    if "seat_depth_threshold_m" in config or "seat_depth_threshold_source" in config:
        raise ValueError("v0_7a_2_geometry_seat_threshold_forbidden")
    expected = _sha256_payload_excluding(
        config,
        "v0_7a_2_trace_native_config_sha256",
        "relabel_config_sha256",
    )
    if config.get("v0_7a_2_trace_native_config_sha256") != expected:
        raise ValueError("v0_7a_2_trace_native_config_hash_mismatch")
    if config.get("relabel_config_sha256") != expected:
        raise ValueError("v0_7a_2_trace_native_config_hash_mismatch")


