def validate_v07b_residual_servo_config_contract(config: dict[str, Any]) -> None:
    if config.get("schema_version") != V07B_RESIDUAL_SERVO_CONFIG_SCHEMA_VERSION:
        raise ValueError("v0_7b_residual_servo_config_required")
    if config.get("policy_slice") != V07B_POLICY_SLICE_ID or config.get("slice_id") != V07B_SLICE_ID:
        raise ValueError("v0_7b_residual_servo_config_required")
    if config.get("base_servo_id") != V07B_BASE_SERVO_ID:
        raise ValueError("v0_7b_residual_servo_config_base_servo_mismatch")
    if config.get("residual_target_definition") != V07B_RESIDUAL_TARGET_DEFINITION:
        raise ValueError("v0_7b_residual_servo_config_target_mismatch")
    base_config = config.get("base_servo_config")
    if not isinstance(base_config, dict) or base_config.get("closing_gate") is not False:
        raise ValueError("v0_7b_residual_servo_config_base_servo_invalid")
    if config.get("base_servo_config_sha256") != _sha256_payload(base_config):
        raise ValueError("v0_7b_residual_servo_config_base_hash_mismatch")
    expected = _sha256_payload_excluding(config, "v0_7b_residual_servo_config_sha256")
    if config.get("v0_7b_residual_servo_config_sha256") != expected:
        raise ValueError("v0_7b_residual_servo_config_hash_mismatch")
    if config.get("heldout_21000_21049_accessed") is not False:
        raise ValueError("v0_7b_residual_servo_config_heldout_access")


