def _v07f_dir(output_dir: Path) -> Path:
    return output_dir / V07F_OUTPUT_DIRNAME


def _v07f_policy_trace_root(output_dir: Path) -> Path:
    return output_dir / V07E_CHILD_OUTPUT_DIRNAME / "isaac_runtime_expressibility_sanity_v0_7e"


def _v07f_expert_trace_root(output_dir: Path) -> Path:
    return output_dir / "isaac_runtime_train_generation_probe" / "isaac_runtime_heldout_rollout_traces"


def build_v07f_diagnostic_config(output_dir: Path) -> dict[str, Any]:
    config: dict[str, Any] = {
        "schema_version": V07F_DIAGNOSTIC_CONFIG_SCHEMA_VERSION,
        "diagnostic_slice": V07F_POLICY_SLICE_ID,
        "diagnosis_slice_id": V07F_DIAGNOSIS_SLICE_ID,
        "scenario_profile": "v0_6",
        "policy_slice_under_test": V07E_POLICY_SLICE_ID,
        "source_policy_trace_dir": str(_v07f_policy_trace_root(output_dir)),
        "source_expert_reference_trace_dir": str(_v07f_expert_trace_root(output_dir)),
        "protected_heldout_seed_range": list(V07A2_PROTECTED_HELDOUT_SEED_RANGE),
        "calibration_opened": False,
        "heldout_21000_21049_accessed": False,
        "heldout_opened": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "phase_e_passed": False,
        "downstream_slice_created": False,
        "proof_authority": "diagnostic_only_not_closure_authority",
        "harness_ids": list(V07F_HARNESS_IDS),
        "classifier_precedence": list(V07F_ROOT_CAUSE_PRECEDENCE),
        "thresholds": V07F_THRESHOLDS,
        "non_claims": {
            "policy_uplift_proven": False,
            "heldout_ab_opened": False,
            "real_robot_success": False,
            "physical_robot_readiness": False,
            "hmd_readiness": False,
            "visual_policy_performance": False,
        },
    }
    config["v0_7f_diagnostic_config_sha256"] = _sha256_payload_excluding(
        config,
        "v0_7f_diagnostic_config_sha256",
    )
    write_json(_v07f_dir(output_dir) / "mvp2e_v07f_diagnostic_config.json", config)
    return config


def validate_v07f_diagnostic_config(config: dict[str, Any]) -> None:
    required = {
        "schema_version",
        "diagnostic_slice",
        "diagnosis_slice_id",
        "scenario_profile",
        "policy_slice_under_test",
        "protected_heldout_seed_range",
        "calibration_opened",
        "heldout_21000_21049_accessed",
        "mvp2_closed",
        "policy_uplift_proven",
        "phase_e_passed",
        "proof_authority",
        "v0_7f_diagnostic_config_sha256",
    }
    if any(key not in config for key in required):
        raise ValueError("v0_7f_diagnostic_config_required")
    if (
        config.get("schema_version") != V07F_DIAGNOSTIC_CONFIG_SCHEMA_VERSION
        or config.get("diagnostic_slice") != V07F_POLICY_SLICE_ID
        or config.get("diagnosis_slice_id") != V07F_DIAGNOSIS_SLICE_ID
        or config.get("scenario_profile") != "v0_6"
        or config.get("policy_slice_under_test") != V07E_POLICY_SLICE_ID
    ):
        raise ValueError("v0_7f_diagnostic_config_mismatch")
    if config.get("protected_heldout_seed_range") != list(V07A2_PROTECTED_HELDOUT_SEED_RANGE):
        raise ValueError("v0_7f_diagnostic_config_heldout_range_mismatch")
    if (
        config.get("calibration_opened") is not False
        or config.get("heldout_21000_21049_accessed") is not False
        or config.get("mvp2_closed") is not False
        or config.get("policy_uplift_proven") is not False
        or config.get("phase_e_passed") is not False
    ):
        raise ValueError("v0_7f_diagnostic_config_claim_boundary_violation")
    expected = _sha256_payload_excluding(config, "v0_7f_diagnostic_config_sha256")
    if config.get("v0_7f_diagnostic_config_sha256") != expected:
        raise ValueError("v0_7f_diagnostic_config_hash_mismatch")


def _discover_v07f_policy_trace_paths(output_dir: Path) -> Any:
    root = _v07f_policy_trace_root(output_dir)
    if not root.exists():
        return iter(())
    return iter(sorted(root.rglob("*isaac_trace.json")))


def _discover_v07f_expert_reference_trace_paths(output_dir: Path) -> Any:
    root = _v07f_expert_trace_root(output_dir)
    if not root.exists():
        return iter(())
    return iter(sorted(root.rglob("*isaac_trace.json")))


def _v07f_seed_from_trace_path(path: Path) -> int:
    name = path.name
    match = re.search(r"(?:train_success|train_failure|held_out|calibration)_(\d{4,6})", name)
    if match is None:
        match = re.search(r"_(\d{4,6})(?:_|\.json$)", name)
    if match is None:
        raise ValueError("v0_7f_trace_seed_missing_before_payload_read")
    return int(match.group(1))


def _v07f_protected_seed_violation(paths: Sequence[Path], trace_set: str) -> dict[str, Any] | None:
    for path in paths:
        seed = _v07f_seed_from_trace_path(path)
        if _protected_heldout_seed_range_accessed(seed):
            return {
                "trace_set": trace_set,
                "seed": seed,
                "path": str(path),
                "reason": "protected_heldout_21000_21049_seed_detected_before_payload_read",
            }
    return None


def _v07f_trace_set_sha256(paths: Sequence[Path]) -> str:
    evidence = [{"path": str(path), "sha256": _sha256_file(path)} for path in sorted(paths)]
    return _sha256_payload(evidence)


def _v07f_rows(payload: dict[str, Any]) -> list[dict[str, Any]]:
    rows = payload.get("trace")
    if not isinstance(rows, list):
        return []
    return [row for row in rows if isinstance(row, dict)]


def _v07f_trace_payload_entries(paths: Sequence[Path], trace_set: str) -> list[dict[str, Any]]:
    entries: list[dict[str, Any]] = []
    for path in sorted(paths):
        payload = read_json(path)
        seed = _seed_from_trace_payload_or_path(payload, path)
        scenario_id = _scenario_id_from_trace_payload_or_path(payload, path)
        entries.append(
            {
                "trace_set": trace_set,
                "path": path,
                "path_string": str(path),
                "sha256": _sha256_file(path),
                "seed": seed,
                "scenario_id": scenario_id,
                "legacy_heldout_path_label_detected": _path_has_legacy_heldout_label(path),
                "payload": payload,
                "rows": _v07f_rows(payload),
            }
        )
    return entries


def _v07f_diag(row: dict[str, Any]) -> dict[str, Any] | None:
    diagnostics = row.get("controller_action_diagnostics")
    return diagnostics if isinstance(diagnostics, dict) else None


def _v07f_action_vector(row: dict[str, Any]) -> list[float] | None:
    diagnostics = _v07f_diag(row)
    candidate = diagnostics.get("post_adapter_action_vector") if diagnostics else None
    if candidate is None:
        candidate = row.get("normalized_action")
    if not isinstance(candidate, list):
        return None
    values: list[float] = []
    for item in candidate[:7]:
        try:
            values.append(float(item))
        except (TypeError, ValueError):
            return None
    return values


def _v07f_action_component(row: dict[str, Any], index: int) -> float | None:
    action = _v07f_action_vector(row)
    if action is None or len(action) <= index:
        return None
    value = action[index]
    if not math.isfinite(value):
        return None
    return value


def _v07f_row_float(row: dict[str, Any], key: str) -> float | None:
    try:
        value = float(row[key])
    except (KeyError, TypeError, ValueError):
        return None
    return value if math.isfinite(value) else None


def _v07f_required_missing_fields(row: dict[str, Any]) -> list[str]:
    missing: list[str] = []
    diagnostics = _v07f_diag(row)
    if diagnostics is None:
        missing.append("controller_action_diagnostics")
        missing.append("post_adapter_action_vector")
    elif not isinstance(diagnostics.get("post_adapter_action_vector"), list):
        missing.append("post_adapter_action_vector")
    for key in ("insertion_depth_m", "lateral_error_m", "relative_x_m", "relative_y_m"):
        if _v07f_row_float(row, key) is None:
            missing.append(key)
    return missing


def _summarize_v07f_trace(rows: list[dict[str, Any]]) -> dict[str, Any]:
    z_open_spans: list[dict[str, int]] = []
    current_start: int | None = None
    current_length = 0
    longest_nonzero_z = 0
    z_open_laterals: list[float] = []
    z_open_xy_saturated = 0
    xy_saturation_count = 0
    max_depth = 0.0
    first_depth_positive_step: int | None = None
    missing_by_row: list[dict[str, Any]] = []
    required_missing_fields: set[str] = set()
    for index, row in enumerate(rows):
        step = int(row.get("step", index))
        depth = _v07f_row_float(row, "insertion_depth_m")
        lateral = _v07f_row_float(row, "lateral_error_m")
        if depth is not None:
            max_depth = max(max_depth, depth)
            if first_depth_positive_step is None and depth > V07F_THRESHOLDS["depth_positive_min_m"]:
                first_depth_positive_step = step
        missing = _v07f_required_missing_fields(row)
        if missing:
            missing_by_row.append({"step": step, "missing_fields": missing})
            required_missing_fields.update(missing)
        action_x = _v07f_action_component(row, 0)
        action_y = _v07f_action_component(row, 1)
        action_z = _v07f_action_component(row, 2)
        xy_saturated = (
            action_x is not None
            and action_y is not None
            and (
                abs(action_x) >= V07F_THRESHOLDS["xy_saturation_abs_action_min"]
                or abs(action_y) >= V07F_THRESHOLDS["xy_saturation_abs_action_min"]
            )
        )
        if xy_saturated:
            xy_saturation_count += 1
        z_open = action_z is not None and action_z < -1e-9
        if z_open:
            if current_start is None:
                current_start = step
                current_length = 0
            current_length += 1
            if lateral is not None:
                z_open_laterals.append(lateral)
            if xy_saturated:
                z_open_xy_saturated += 1
        elif current_start is not None:
            z_open_spans.append(
                {"start_step": current_start, "end_step": step - 1, "length": current_length}
            )
            longest_nonzero_z = max(longest_nonzero_z, current_length)
            current_start = None
            current_length = 0
    if current_start is not None:
        end_step = int(rows[-1].get("step", len(rows) - 1)) if rows else current_start
        z_open_spans.append({"start_step": current_start, "end_step": end_step, "length": current_length})
        longest_nonzero_z = max(longest_nonzero_z, current_length)
    z_open_count = sum(span["length"] for span in z_open_spans)
    start_lateral = z_open_laterals[0] if z_open_laterals else None
    min_lateral = min(z_open_laterals) if z_open_laterals else None
    end_lateral = z_open_laterals[-1] if z_open_laterals else None
    max_lateral = max(z_open_laterals) if z_open_laterals else None
    regression = None
    if end_lateral is not None and min_lateral is not None:
        regression = max(0.0, end_lateral - min_lateral)
    return {
        "row_count": len(rows),
        "longest_nonzero_z": longest_nonzero_z,
        "z_open_spans": z_open_spans,
        "z_open_row_count": z_open_count,
        "max_insertion_depth_m": max_depth,
        "first_depth_positive_step": first_depth_positive_step,
        "xy_saturation_count": xy_saturation_count,
        "xy_saturation_ratio": xy_saturation_count / len(rows) if rows else 0.0,
        "xy_saturation_during_z_open_ratio": z_open_xy_saturated / z_open_count if z_open_count else 0.0,
        "z_open_start_lateral_m": start_lateral,
        "z_open_min_lateral_m": min_lateral,
        "z_open_end_lateral_m": end_lateral,
        "z_open_max_lateral_m": max_lateral,
        "z_open_regression_m": regression,
        "diagnostic_completeness": {
            "complete": not required_missing_fields,
            "missing_required_fields": sorted(required_missing_fields),
            "missing_by_row": missing_by_row[:20],
        },
    }


def _v07f_action_to_state_sign_agreement(rows: list[dict[str, Any]]) -> dict[str, Any]:
    missing_fields: set[str] = set()
    sample_count = 0
    agreement_count = 0
    for row in rows:
        rel_x = _v07f_row_float(row, "relative_x_m")
        rel_y = _v07f_row_float(row, "relative_y_m")
        action_x = _v07f_action_component(row, 0)
        action_y = _v07f_action_component(row, 1)
        if rel_x is None:
            missing_fields.add("relative_x_m")
        if rel_y is None:
            missing_fields.add("relative_y_m")
        if action_x is None or action_y is None:
            missing_fields.add("post_adapter_action_vector")
        if missing_fields:
            continue
        for relative, action in ((rel_x, action_x), (rel_y, action_y)):
            if relative is None or action is None:
                continue
            if abs(relative) < 1e-12 and abs(action) < 1e-12:
                continue
            sample_count += 1
            if relative * action <= 0:
                agreement_count += 1
    if missing_fields:
        return {
            "status": "not_evaluated",
            "missing_fields": sorted(missing_fields),
            "sample_count": sample_count,
            "xy_sign_agreement_ratio": None,
        }
    ratio = agreement_count / sample_count if sample_count else 1.0
    return {
        "status": "evaluated",
        "missing_fields": [],
        "sample_count": sample_count,
        "xy_sign_agreement_ratio": ratio,
    }


def build_v07f_trace_comparison_table(output_dir: Path) -> dict[str, Any]:
    policy_paths = tuple(_discover_v07f_policy_trace_paths(output_dir))
    expert_paths = tuple(_discover_v07f_expert_reference_trace_paths(output_dir))
    policy_violation = _v07f_protected_seed_violation(policy_paths, "policy")
    expert_violation = _v07f_protected_seed_violation(expert_paths, "expert_reference")
    if policy_violation or expert_violation:
        violation = policy_violation or expert_violation
        return {
            "schema_version": V07F_TRACE_COMPARISON_TABLE_SCHEMA_VERSION,
            "policy_slice_under_test": V07E_POLICY_SLICE_ID,
            "expert_reference_source": "isaac_runtime_train_generation_probe",
            "trace_pairs": [],
            "policy_trace_set_sha256": None,
            "expert_reference_trace_set_sha256": None,
            "protected_seed_violation": violation,
            "protected_heldout_21000_21049_accessed": True,
            "legacy_heldout_path_label_interpretation": "directory_name_only_not_protected_seed_split",
        }
    policy_entries = _v07f_trace_payload_entries(policy_paths, "policy")
    expert_entries = _v07f_trace_payload_entries(expert_paths, "expert_reference")
    experts_by_seed = {entry["seed"]: entry for entry in expert_entries}
    trace_pairs: list[dict[str, Any]] = []
    missing_expert_seeds: list[int] = []
    for policy_entry in policy_entries:
        expert_entry = experts_by_seed.get(policy_entry["seed"])
        if expert_entry is None:
            missing_expert_seeds.append(int(policy_entry["seed"]))
            continue
        policy_summary = _summarize_v07f_trace(policy_entry["rows"])
        expert_summary = _summarize_v07f_trace(expert_entry["rows"])
        trace_pairs.append(
            {
                "seed": policy_entry["seed"],
                "scenario_id": policy_entry["scenario_id"],
                "policy_trace_path": policy_entry["path_string"],
                "policy_trace_sha256": policy_entry["sha256"],
                "expert_trace_path": expert_entry["path_string"],
                "expert_trace_sha256": expert_entry["sha256"],
                "policy_summary": policy_summary,
                "expert_reference_summary": expert_summary,
                "policy_sign_agreement": _v07f_action_to_state_sign_agreement(policy_entry["rows"]),
                "expert_sign_agreement": _v07f_action_to_state_sign_agreement(expert_entry["rows"]),
                "legacy_heldout_path_label_detected": bool(
                    policy_entry["legacy_heldout_path_label_detected"]
                    or expert_entry["legacy_heldout_path_label_detected"]
                ),
            }
        )
    table: dict[str, Any] = {
        "schema_version": V07F_TRACE_COMPARISON_TABLE_SCHEMA_VERSION,
        "policy_slice_under_test": V07E_POLICY_SLICE_ID,
        "expert_reference_source": "isaac_runtime_train_generation_probe",
        "policy_trace_count": len(policy_entries),
        "expert_reference_trace_count": len(expert_entries),
        "paired_trace_count": len(trace_pairs),
        "missing_expert_reference_seeds": sorted(missing_expert_seeds),
        "trace_pairs": trace_pairs,
        "policy_trace_set_sha256": _v07f_trace_set_sha256(policy_paths) if policy_paths else None,
        "expert_reference_trace_set_sha256": (
            _v07f_trace_set_sha256(expert_paths) if expert_paths else None
        ),
        "protected_seed_violation": None,
        "protected_heldout_21000_21049_accessed": False,
        "legacy_heldout_path_label_detected": any(
            pair["legacy_heldout_path_label_detected"] for pair in trace_pairs
        ),
        "legacy_heldout_path_label_interpretation": "directory_name_only_not_protected_seed_split",
    }
    table["v0_7f_trace_comparison_table_sha256"] = _sha256_payload_excluding(
        table,
        "v0_7f_trace_comparison_table_sha256",
    )
    return table


def _v07f_harness_record(
    harness_id: str,
    *,
    status: str = "not_evaluated",
    reason: str = "not_evaluated",
    root_cause_candidates: Sequence[str] = (),
    evidence: dict[str, Any] | None = None,
) -> dict[str, Any]:
    return {
        "harness_id": harness_id,
        "status": status,
        "tier": "close_critical_diagnostic",
        "reason": reason,
        "root_cause_candidates": list(root_cause_candidates),
        "evidence": evidence or {},
    }


def _v07f_mean(values: Sequence[float]) -> float:
    return float(sum(values) / len(values)) if values else 0.0


def _v07f_harnesses_from_table(table: dict[str, Any]) -> dict[str, dict[str, Any]]:
    pairs = table.get("trace_pairs")
    if not isinstance(pairs, list) or not pairs:
        return {
            harness_id: _v07f_harness_record(
                harness_id,
                status="missing_evidence",
                reason="missing_paired_policy_and_expert_traces",
                root_cause_candidates=["TRACE_DIAGNOSTICS_INCOMPLETE"],
            )
            for harness_id in V07F_HARNESS_IDS
        }
    policy_summaries = [pair["policy_summary"] for pair in pairs]
    expert_summaries = [pair["expert_reference_summary"] for pair in pairs]
    policy_longest = [float(summary["longest_nonzero_z"]) for summary in policy_summaries]
    expert_longest = [float(summary["longest_nonzero_z"]) for summary in expert_summaries]
    policy_xy = [float(summary["xy_saturation_ratio"]) for summary in policy_summaries]
    expert_xy = [float(summary["xy_saturation_ratio"]) for summary in expert_summaries]
    policy_regression = [
        float(summary["z_open_regression_m"] or 0.0) for summary in policy_summaries
    ]
    policy_z_open_start = [
        float(summary["z_open_start_lateral_m"] or 0.0)
        for summary in policy_summaries
        if summary.get("z_open_start_lateral_m") is not None
    ]
    policy_depths = [float(summary["max_insertion_depth_m"]) for summary in policy_summaries]
    expert_depths = [float(summary["max_insertion_depth_m"]) for summary in expert_summaries]
    missing_fields = sorted(
        {
            field
            for summary in policy_summaries
            for field in summary["diagnostic_completeness"]["missing_required_fields"]
        }
    )
    sign_agreements = [pair["policy_sign_agreement"] for pair in pairs]
    h18 = _v07f_harness_record(
        "H18",
        status="passed" if max(policy_longest, default=0.0) > 0 else "failed",
        reason="policy_z_window_observed" if max(policy_longest, default=0.0) > 0 else "policy_z_window_absent",
        root_cause_candidates=[] if max(policy_longest, default=0.0) > 0 else ["Z_OPEN_WITH_NO_VERTICAL_PROGRESS"],
        evidence={
            "policy_longest_nonzero_z_max": max(policy_longest, default=0.0),
            "expert_longest_nonzero_z_max": max(expert_longest, default=0.0),
        },
    )
    policy_xy_mean = _v07f_mean(policy_xy)
    expert_xy_mean = _v07f_mean(expert_xy)
    h19_failed = (
        policy_xy_mean >= V07F_THRESHOLDS["xy_saturation_ratio_fail_min"]
        and expert_xy_mean <= V07F_THRESHOLDS["xy_saturation_ratio_expert_max"]
    )
    h19 = _v07f_harness_record(
        "H19",
        status="failed" if h19_failed else "passed",
        reason=(
            "policy_xy_saturation_dominates_while_expert_reference_does_not"
            if h19_failed
            else "xy_saturation_not_separated_from_expert_reference"
        ),
        root_cause_candidates=["XY_SATURATION_CENTERING_INSTABILITY"] if h19_failed else [],
        evidence={"policy_xy_saturation_ratio_mean": policy_xy_mean, "expert_xy_saturation_ratio_mean": expert_xy_mean},
    )
    max_regression = max(policy_regression, default=0.0)
    h20_failed = max_regression >= V07F_THRESHOLDS["z_open_lateral_regression_fail_min_m"]
    h20 = _v07f_harness_record(
        "H20",
        status="failed" if h20_failed else "passed",
        reason="lateral_regresses_while_z_open" if h20_failed else "z_open_lateral_regression_not_observed",
        root_cause_candidates=["Z_OPEN_LATERAL_REGRESSION"] if h20_failed else [],
        evidence={"max_z_open_lateral_regression_m": max_regression},
    )
    h21_failed = any(
        lateral > V07F_THRESHOLDS["premature_z_open_lateral_gate_m"]
        for lateral in policy_z_open_start
    )
    h21 = _v07f_harness_record(
        "H21",
        status="failed" if h21_failed else "passed",
        reason="z_opens_before_lateral_gate" if h21_failed else "z_open_context_within_lateral_gate",
        root_cause_candidates=["PREMATURE_Z_OPEN_CONTEXT"] if h21_failed else [],
        evidence={
            "z_open_start_lateral_values_m": policy_z_open_start,
            "lateral_gate_m": V07F_THRESHOLDS["premature_z_open_lateral_gate_m"],
        },
    )
    not_evaluated = [item for item in sign_agreements if item.get("status") != "evaluated"]
    min_ratio = min(
        (
            float(item["xy_sign_agreement_ratio"])
            for item in sign_agreements
            if item.get("xy_sign_agreement_ratio") is not None
        ),
        default=None,
    )
    if not_evaluated:
        h22 = _v07f_harness_record(
            "H22",
            status="not_evaluated",
            reason="missing_relative_or_action_fields_for_xy_sign_check",
            root_cause_candidates=["TRACE_DIAGNOSTICS_INCOMPLETE"],
            evidence={"not_evaluated_count": len(not_evaluated), "examples": not_evaluated[:3]},
        )
    else:
        h22_failed = min_ratio is not None and min_ratio < V07F_THRESHOLDS["xy_sign_agreement_ratio_min"]
        h22 = _v07f_harness_record(
            "H22",
            status="failed" if h22_failed else "passed",
            reason="xy_action_sign_disagrees_with_relative_state" if h22_failed else "xy_action_sign_agreement_ok",
            root_cause_candidates=["XY_ACTION_FRAME_OR_SIGN_MISMATCH"] if h22_failed else [],
            evidence={"min_xy_sign_agreement_ratio": min_ratio},
        )
    policy_depth_max = max(policy_depths, default=0.0)
    expert_depth_max = max(expert_depths, default=0.0)
    h23_failed = (
        max(policy_longest, default=0.0) > 0
        and policy_depth_max <= V07F_THRESHOLDS["depth_positive_min_m"]
        and expert_depth_max >= V07F_THRESHOLDS["expert_reference_depth_min_m"]
    )
    h23 = _v07f_harness_record(
        "H23",
        status="failed" if h23_failed else "passed",
        reason="z_open_without_vertical_depth_response" if h23_failed else "vertical_depth_response_not_depth_zero",
        root_cause_candidates=["Z_OPEN_WITH_NO_VERTICAL_PROGRESS"] if h23_failed else [],
        evidence={"policy_max_insertion_depth_m": policy_depth_max, "expert_max_insertion_depth_m": expert_depth_max},
    )
    h24 = _v07f_harness_record(
        "H24",
        status="failed" if missing_fields else "passed",
        reason="missing_required_trace_diagnostics" if missing_fields else "required_trace_diagnostics_complete",
        root_cause_candidates=["TRACE_DIAGNOSTICS_INCOMPLETE"] if missing_fields else [],
        evidence={
            "missing_required_fields": missing_fields,
            "required_fields": list(V07F_REQUIRED_TRACE_FIELDS),
        },
    )
    return {
        "H18": h18,
        "H19": h19,
        "H20": h20,
        "H21": h21,
        "H22": h22,
        "H23": h23,
        "H24": h24,
    }


def _classify_v07f_depth_zero_harnesses(harnesses: dict[str, dict[str, Any]]) -> dict[str, Any]:
    if harnesses.get("H24", {}).get("status") == "failed" or harnesses.get("H22", {}).get("status") == "not_evaluated":
        return {
            "root_cause_status": "missing_evidence",
            "primary_root_cause_class": "TRACE_DIAGNOSTICS_INCOMPLETE",
            "secondary_root_cause_candidates": [],
            "recommended_downstream_slice": None,
        }
    candidates: list[str] = []
    for record in harnesses.values():
        if record.get("status") == "failed":
            candidates.extend(str(item) for item in record.get("root_cause_candidates", []))
    ordered = [candidate for candidate in V07F_ROOT_CAUSE_PRECEDENCE if candidate in set(candidates)]
    if not ordered:
        return {
            "root_cause_status": "unclassified",
            "primary_root_cause_class": "UNCLASSIFIED_DEPTH_ZERO_FAILURE",
            "secondary_root_cause_candidates": [],
            "recommended_downstream_slice": None,
        }
    primary = ordered[0]
    return {
        "root_cause_status": "classified",
        "primary_root_cause_class": primary,
        "secondary_root_cause_candidates": ordered[1:],
        "recommended_downstream_slice": V07F_ROOT_CAUSE_DOWNSTREAM_SLICE.get(primary),
    }


def _v07f_protected_seed_report(config: dict[str, Any], table: dict[str, Any]) -> dict[str, Any]:
    violation = table.get("protected_seed_violation")
    report: dict[str, Any] = {
        "schema_version": V07F_HARNESS_REPORT_SCHEMA_VERSION,
        "diagnostic_slice": V07F_POLICY_SLICE_ID,
        "diagnosis_slice_id": V07F_DIAGNOSIS_SLICE_ID,
        "policy_slice_under_test": V07E_POLICY_SLICE_ID,
        "proof_authority": "diagnostic_only_not_closure_authority",
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "phase_e_passed": False,
        "calibration_opened": False,
        "heldout_21000_21049_accessed": True,
        "heldout_opened": True,
        "downstream_slice_created": False,
        "config_sha256": config["v0_7f_diagnostic_config_sha256"],
        "trace_comparison_table_sha256": table.get("v0_7f_trace_comparison_table_sha256"),
        "policy_trace_set_sha256": None,
        "expert_reference_trace_set_sha256": None,
        "protected_seed_violation": violation,
        "root_cause_status": "protected_seed_access_detected",
        "primary_root_cause_class": "TRACE_DIAGNOSTICS_INCOMPLETE",
        "secondary_root_cause_candidates": [],
        "recommended_downstream_slice": None,
        "harnesses": {
            harness_id: _v07f_harness_record(
                harness_id,
                status="failed",
                reason="protected_seed_access_detected_before_payload_read",
                root_cause_candidates=["TRACE_DIAGNOSTICS_INCOMPLETE"],
                evidence={"protected_seed_violation": violation},
            )
            for harness_id in V07F_HARNESS_IDS
        },
    }
    report["v0_7f_depth_zero_harness_report_sha256"] = _sha256_payload_excluding(
        report,
        "v0_7f_depth_zero_harness_report_sha256",
    )
    return report


def build_v07f_depth_zero_harness_report(
    output_dir: Path,
    config: dict[str, Any] | None = None,
) -> dict[str, Any]:
    if config is None:
        config = build_v07f_diagnostic_config(output_dir)
    validate_v07f_diagnostic_config(config)
    table = build_v07f_trace_comparison_table(output_dir)
    if table.get("protected_seed_violation") is not None:
        return _v07f_protected_seed_report(config, table)
    harnesses = _v07f_harnesses_from_table(table)
    classification = _classify_v07f_depth_zero_harnesses(harnesses)
    report: dict[str, Any] = {
        "schema_version": V07F_HARNESS_REPORT_SCHEMA_VERSION,
        "diagnostic_slice": V07F_POLICY_SLICE_ID,
        "diagnosis_slice_id": V07F_DIAGNOSIS_SLICE_ID,
        "policy_slice_under_test": V07E_POLICY_SLICE_ID,
        "proof_authority": "diagnostic_only_not_closure_authority",
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "phase_e_passed": False,
        "calibration_opened": False,
        "heldout_21000_21049_accessed": False,
        "heldout_opened": False,
        "downstream_slice_created": False,
        "config_sha256": config["v0_7f_diagnostic_config_sha256"],
        "trace_comparison_table_sha256": table.get("v0_7f_trace_comparison_table_sha256"),
        "policy_trace_set_sha256": table.get("policy_trace_set_sha256"),
        "expert_reference_trace_set_sha256": table.get("expert_reference_trace_set_sha256"),
        "legacy_heldout_path_label_detected": table.get("legacy_heldout_path_label_detected", False),
        "legacy_heldout_path_label_interpretation": table.get(
            "legacy_heldout_path_label_interpretation"
        ),
        "paired_trace_count": table.get("paired_trace_count", 0),
        "missing_expert_reference_seeds": table.get("missing_expert_reference_seeds", []),
        "classifier_precedence": list(V07F_ROOT_CAUSE_PRECEDENCE),
        "harnesses": harnesses,
        **classification,
    }
    report["v0_7f_depth_zero_harness_report_sha256"] = _sha256_payload_excluding(
        report,
        "v0_7f_depth_zero_harness_report_sha256",
    )
    return report


def write_v07f_depth_zero_diagnosis_artifacts(output_dir: Path) -> dict[str, Any]:
    diag_dir = _v07f_dir(output_dir)
    config = build_v07f_diagnostic_config(output_dir)
    table = build_v07f_trace_comparison_table(output_dir)
    write_json(diag_dir / "mvp2e_v07f_trace_comparison_table.json", table)
    report = (
        _v07f_protected_seed_report(config, table)
        if table.get("protected_seed_violation") is not None
        else build_v07f_depth_zero_harness_report(output_dir, config=config)
    )
    write_json(diag_dir / "mvp2e_v07f_depth_zero_harness_report.json", report)
    artifact_paths = {
        "diagnostic_config": diag_dir / "mvp2e_v07f_diagnostic_config.json",
        "depth_zero_harness_report": diag_dir / "mvp2e_v07f_depth_zero_harness_report.json",
        "trace_comparison_table": diag_dir / "mvp2e_v07f_trace_comparison_table.json",
        "gate_manifest": diag_dir / "mvp2e_v07f_gate_manifest.json",
    }
    manifest: dict[str, Any] = {
        "schema_version": V07F_GATE_MANIFEST_SCHEMA_VERSION,
        "diagnostic_slice": V07F_POLICY_SLICE_ID,
        "diagnosis_slice_id": V07F_DIAGNOSIS_SLICE_ID,
        "policy_slice_under_test": V07E_POLICY_SLICE_ID,
        "proof_authority": "diagnostic_only_not_closure_authority",
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "phase_e_passed": False,
        "calibration_opened": False,
        "heldout_21000_21049_accessed": bool(report.get("heldout_21000_21049_accessed")),
        "heldout_opened": bool(report.get("heldout_opened")),
        "downstream_slice_created": False,
        "root_cause_status": report.get("root_cause_status"),
        "primary_root_cause_class": report.get("primary_root_cause_class"),
        "secondary_root_cause_candidates": report.get("secondary_root_cause_candidates", []),
        "recommended_downstream_slice": report.get("recommended_downstream_slice"),
        "artifacts": {
            key: {
                "path": str(path),
                "sha256": _sha256_file(path) if path.exists() else "artifact_not_written_at_manifest_build_time",
            }
            for key, path in artifact_paths.items()
        },
    }
    manifest["v0_7f_gate_manifest_sha256"] = _sha256_payload_excluding(
        manifest,
        "v0_7f_gate_manifest_sha256",
    )
    manifest["artifacts"]["gate_manifest"]["sha256"] = manifest["v0_7f_gate_manifest_sha256"]
    manifest["artifacts"]["gate_manifest"]["sha256_semantics"] = (
        "payload_sha256_excluding_v0_7f_gate_manifest_sha256_before_self_reference"
    )
    write_json(artifact_paths["gate_manifest"], manifest)
    return {"config": config, "table": table, "report": report, "manifest": manifest}


def _mvp2e_harness_dir(output_dir: Path) -> Path:
    return output_dir / MVP2E_HARNESS_OUTPUT_DIRNAME


def build_mvp2e_harness_config(
    *,
    output_dir: Path,
    scenario_profile: str = "v0_6",
    policy_slice_under_test: str = V07C_POLICY_SLICE_ID,
) -> dict[str, Any]:
    source_child_dir = V07D_CHILD_OUTPUT_DIRNAME if policy_slice_under_test == V07D_POLICY_SLICE_ID else V07C_CHILD_OUTPUT_DIRNAME
    config: dict[str, Any] = {
        "schema_version": MVP2E_HARNESS_CONFIG_SCHEMA_VERSION,
        "scenario_profile": scenario_profile,
        "policy_slice_under_test": policy_slice_under_test,
        "source_evidence_dir": str(output_dir / source_child_dir),
        "protected_heldout_seed_range": list(V07A2_PROTECTED_HELDOUT_SEED_RANGE),
        "heldout_21000_21049_accessed": False,
        "calibration_accessed": False,
        "success_authority": {
            "primary": V06_ENV_NATIVE_SUCCESS_AUTHORITY["primary"],
            "stable_steps_required": V06_ENV_NATIVE_SUCCESS_AUTHORITY["stable_steps_required"],
            "success_threshold": V06_ENV_NATIVE_SUCCESS_AUTHORITY["success_threshold"],
            "max_steps": SUCCESS_METRIC["max_steps"],
        },
        "harness_ids": list(MVP2E_HARNESS_IDS),
        "close_critical_harness_ids": list(MVP2E_CLOSE_CRITICAL_HARNESS_IDS),
        "required_evidence_harness_ids": list(MVP2E_REQUIRED_EVIDENCE_HARNESS_IDS),
        "classifier_precedence": list(MVP2E_ROOT_CAUSE_PRECEDENCE),
        "downstream_slice_created": False,
        "mvp2_closed": False,
        "non_claims": {
            "policy_uplift_proven": False,
            "heldout_ab_opened": False,
            "real_robot_success": False,
            "physical_robot_readiness": False,
            "hmd_readiness": False,
            "visual_policy_performance": False,
        },
    }
    config["mvp2e_harness_config_sha256"] = _sha256_payload_excluding(
        config,
        "mvp2e_harness_config_sha256",
    )
    write_json(_mvp2e_harness_dir(output_dir) / "mvp2e_harness_config.json", config)
    return config


def validate_mvp2e_harness_config(config: dict[str, Any]) -> None:
    if config.get("schema_version") != MVP2E_HARNESS_CONFIG_SCHEMA_VERSION:
        raise ValueError("mvp2e_harness_config_required")
    if config.get("scenario_profile") != "v0_6":
        raise ValueError("mvp2e_harness_config_scenario_profile_mismatch")
    if config.get("policy_slice_under_test") not in {V07C_POLICY_SLICE_ID, V07D_POLICY_SLICE_ID}:
        raise ValueError("mvp2e_harness_config_policy_slice_mismatch")
    if config.get("protected_heldout_seed_range") != list(V07A2_PROTECTED_HELDOUT_SEED_RANGE):
        raise ValueError("mvp2e_harness_config_heldout_range_mismatch")
    if config.get("heldout_21000_21049_accessed") is not False:
        raise ValueError("mvp2e_harness_config_heldout_access")
    if config.get("calibration_accessed") is not False:
        raise ValueError("mvp2e_harness_config_calibration_access")
    authority = config.get("success_authority")
    if not isinstance(authority, dict):
        raise ValueError("mvp2e_harness_config_success_authority_required")
    if authority.get("primary") != V06_ENV_NATIVE_SUCCESS_AUTHORITY["primary"]:
        raise ValueError("mvp2e_harness_config_success_authority_mismatch")
    if int(authority.get("stable_steps_required", -1)) != V06_ENV_NATIVE_STABLE_STEPS_REQUIRED:
        raise ValueError("mvp2e_harness_config_stable_steps_mismatch")
    if int(authority.get("max_steps", -1)) != int(SUCCESS_METRIC["max_steps"]):
        raise ValueError("mvp2e_harness_config_max_steps_mismatch")
    expected = _sha256_payload_excluding(config, "mvp2e_harness_config_sha256")
    if config.get("mvp2e_harness_config_sha256") != expected:
        raise ValueError("mvp2e_harness_config_hash_mismatch")


def build_empty_harness_record(
    harness_id: str,
    *,
    status: str = "not_evaluated",
    reason: str = "no_current_evidence_for_first_harness_pass",
    tier: str = "diagnostic",
) -> dict[str, Any]:
    close_critical = harness_id in MVP2E_CLOSE_CRITICAL_HARNESS_IDS
    if close_critical and tier == "diagnostic":
        tier = "close_critical"
    return {
        "harness_id": harness_id,
        "status": status,
        "tier": tier,
        "close_critical": close_critical,
        "reason": reason,
        "root_cause_candidates": [],
        "missing_evidence": [],
        "evidence": {},
    }


def _mvp2e_resolve_trace_path(output_dir: Path, value: Any) -> Path | None:
    if not isinstance(value, str) or not value:
        return None
    path = Path(value)
    candidates = [path]
    if not path.is_absolute():
        candidates.extend((output_dir / path, output_dir / V07C_CHILD_OUTPUT_DIRNAME / path))
    for candidate in candidates:
        if candidate.exists():
            return candidate
    return path if path.exists() else None


def _mvp2e_discover_v07c_trace_paths(output_dir: Path) -> list[Path]:
    child_dir = output_dir / V07C_CHILD_OUTPUT_DIRNAME
    paths: list[Path] = []
    gate_path = child_dir / "expressibility_sanity_gate_v0_7c.json"
    if gate_path.exists():
        gate = read_json(gate_path)
        trace_values = gate.get("trace_paths")
        if isinstance(trace_values, list):
            for value in trace_values:
                resolved = _mvp2e_resolve_trace_path(output_dir, value)
                if resolved is not None:
                    paths.append(resolved)
    runtime_dir = child_dir / "isaac_runtime_expressibility_sanity_v0_7c"
    if runtime_dir.exists():
        paths.extend(sorted(runtime_dir.rglob("*.json")))
    unique: dict[str, Path] = {}
    for path in paths:
        if path.exists() and path.name != "expressibility_sanity_gate_v0_7c.json":
            unique[str(path.resolve())] = path
    return list(unique.values())


def _mvp2e_action_z(value: Any) -> float | None:
    if not isinstance(value, list) and not isinstance(value, tuple):
        return None
    if len(value) < 3:
        return None
    try:
        z = float(value[2])
    except (TypeError, ValueError):
        return None
    return z if math.isfinite(z) else None


def _mvp2e_float(value: Any) -> float | None:
    try:
        number = float(value)
    except (TypeError, ValueError):
        return None
    return number if math.isfinite(number) else None


def _mvp2e_trace_index(output_dir: Path) -> dict[str, Any]:
    entries: list[dict[str, Any]] = []
    protected_accessed = False
    legacy_label_detected = False
    for path in _mvp2e_discover_v07c_trace_paths(output_dir):
        try:
            payload = read_json(path)
        except (OSError, ValueError, json.JSONDecodeError):
            continue
        seed = _seed_from_trace_payload_or_path(payload, path)
        scenario_id = _scenario_id_from_trace_payload_or_path(payload, path)
        protected = _protected_heldout_seed_range_accessed(seed)
        legacy_label = _path_has_legacy_heldout_label(path)
        protected_accessed = protected_accessed or protected
        legacy_label_detected = legacy_label_detected or legacy_label
        trace_rows = payload.get("trace")
        row_count = len(trace_rows) if isinstance(trace_rows, list) else 0
        entries.append(
            {
                "path": str(path),
                "sha256": _sha256_file(path),
                "scenario_id": scenario_id,
                "seed": seed,
                "row_count": row_count,
                "protected_heldout_21000_21049_accessed": protected,
                "legacy_heldout_path_label_detected": legacy_label,
                "legacy_heldout_path_label_interpretation": (
                    "protected_seed_leakage"
                    if protected
                    else "directory_name_only_not_protected_seed_split"
                ),
            }
        )
    index = {
        "schema_version": "rdf_mvp2e_harness_trace_index_v0.1.0",
        "trace_count": len(entries),
        "traces": entries,
        "protected_heldout_21000_21049_accessed": protected_accessed,
        "legacy_heldout_path_label_detected": legacy_label_detected,
        "legacy_heldout_path_label_interpretation": "directory_name_only_not_protected_seed_split",
    }
    index["harness_trace_index_sha256"] = _sha256_payload_excluding(
        index,
        "harness_trace_index_sha256",
    )
    return index


def _mvp2e_trace_rows(output_dir: Path) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    for path in _mvp2e_discover_v07c_trace_paths(output_dir):
        try:
            payload = read_json(path)
        except (OSError, ValueError, json.JSONDecodeError):
            continue
        trace = payload.get("trace")
        if not isinstance(trace, list):
            continue
        for row in trace:
            if isinstance(row, dict):
                rows.append({"trace_path": str(path), "row": row})
    return rows


def _mvp2e_diagnostics_for_row(row: dict[str, Any]) -> dict[str, Any] | None:
    diagnostics = row.get("controller_action_diagnostics")
    return diagnostics if isinstance(diagnostics, dict) else None


def _mvp2e_diag_value(row: dict[str, Any], diagnostics: dict[str, Any], key: str) -> Any:
    if key in diagnostics:
        return diagnostics[key]
    return row.get(key)


def _mvp2e_align_action_records(output_dir: Path) -> tuple[list[dict[str, Any]], list[str]]:
    align_records: list[dict[str, Any]] = []
    missing: list[str] = []
    for item in _mvp2e_trace_rows(output_dir):
        row = item["row"]
        diagnostics = _mvp2e_diagnostics_for_row(row)
        if diagnostics is None:
            missing.append(f"{item['trace_path']}:controller_action_diagnostics")
            continue
        phase = str(diagnostics.get("behavior_state_phase") or row.get("behavior_state_phase") or "").upper()
        if phase != "ALIGN":
            continue
        raw_action_after = _mvp2e_diag_value(row, diagnostics, "raw_action_after_authority")
        post_adapter = _mvp2e_diag_value(row, diagnostics, "post_adapter_action_vector")
        base_servo = _mvp2e_diag_value(row, diagnostics, "base_servo_action")
        residual_z = _mvp2e_float(_mvp2e_diag_value(row, diagnostics, "residual_z_after_authority"))
        raw_z = _mvp2e_action_z(raw_action_after)
        post_z = _mvp2e_action_z(post_adapter)
        base_z = _mvp2e_action_z(base_servo)
        field_values = {
            "raw_action_after_authority": raw_z,
            "post_adapter_action_vector": post_z,
            "base_servo_action": base_z,
            "residual_z_after_authority": residual_z,
        }
        for field, value in field_values.items():
            if value is None:
                missing.append(f"{item['trace_path']}:{field}")
        align_records.append(
            {
                "trace_path": item["trace_path"],
                "step": row.get("step"),
                "raw_z_after_authority": raw_z,
                "post_adapter_z": post_z,
                "base_servo_z": base_z,
                "residual_z_after_authority": residual_z,
                "selected_action_adapter_id": diagnostics.get("selected_action_adapter_id"),
            }
        )
    if not align_records and not missing:
        missing.append("v0_7c_trace:ALIGN_controller_action_diagnostics")
    return align_records, sorted(set(missing))


def _mvp2e_h0_record(config: dict[str, Any], trace_index: dict[str, Any]) -> dict[str, Any]:
    record = build_empty_harness_record("H0", tier="close_critical")
    failures: list[str] = []
    if config.get("scenario_profile") != "v0_6":
        failures.append("scenario_profile_mutated")
    if config.get("heldout_21000_21049_accessed") is not False:
        failures.append("config_heldout_accessed")
    if config.get("calibration_accessed") is not False:
        failures.append("calibration_accessed")
    if trace_index.get("protected_heldout_21000_21049_accessed") is True:
        failures.append("protected_heldout_seed_accessed")
    if failures:
        record.update(
            {
                "status": "failed",
                "reason": ",".join(failures),
                "root_cause_candidates": ["EVALUATOR_OR_SCENARIO_MUTATION"],
            }
        )
    else:
        record.update({"status": "passed", "reason": "scenario_evaluator_and_heldout_seal_intact"})
    record["evidence"] = {
        "scenario_profile": config.get("scenario_profile"),
        "success_authority": config.get("success_authority"),
        "protected_heldout_21000_21049_accessed": trace_index.get(
            "protected_heldout_21000_21049_accessed"
        ),
    }
    return record


def _mvp2e_action_authority_records(output_dir: Path) -> dict[str, dict[str, Any]]:
    align_records, missing = _mvp2e_align_action_records(output_dir)
    if missing:
        return {
            harness_id: {
                **build_empty_harness_record(harness_id, status="missing_evidence", tier="close_critical"),
                "reason": "missing_required_v0_7c_action_diagnostics",
                "missing_evidence": missing,
            }
            for harness_id in ("H1", "H2", "H3")
        }
    residual_violations = [
        item for item in align_records if abs(float(item["residual_z_after_authority"])) > 1e-9
    ]
    post_adapter_violations = [
        item for item in align_records if abs(float(item["post_adapter_z"])) > 1e-9
    ]
    base_descent_violations = [
        item
        for item in align_records
        if abs(float(item["base_servo_z"])) > 1e-9 and abs(float(item["post_adapter_z"])) > 1e-9
    ]
    h1 = build_empty_harness_record("H1", tier="close_critical")
    h2 = build_empty_harness_record("H2", tier="close_critical")
    h3 = build_empty_harness_record("H3", tier="close_critical")
    h1.update(
        {
            "status": "failed" if residual_violations or post_adapter_violations else "passed",
            "reason": (
                "align_residual_or_post_adapter_z_authority_violation"
                if residual_violations or post_adapter_violations
                else "align_z_authority_contract_preserved"
            ),
            "root_cause_candidates": (
                ["ACTION_AUTHORITY_POST_ADAPTER_Z_LEAK"]
                if residual_violations or post_adapter_violations
                else []
            ),
            "evidence": {
                "align_row_count": len(align_records),
                "residual_z_violation_count": len(residual_violations),
                "post_adapter_z_violation_count": len(post_adapter_violations),
                "example_violations": post_adapter_violations[:3],
            },
        }
    )
    h2.update(
        {
            "status": "failed" if post_adapter_violations else "passed",
            "reason": (
                "post_adapter_reintroduced_align_descent"
                if post_adapter_violations
                else "post_adapter_preserved_zero_z_in_align"
            ),
            "root_cause_candidates": (
                ["ACTION_AUTHORITY_POST_ADAPTER_Z_LEAK"] if post_adapter_violations else []
            ),
            "evidence": {
                "align_row_count": len(align_records),
                "post_adapter_z_violation_count": len(post_adapter_violations),
                "example_violations": post_adapter_violations[:3],
            },
        }
    )
    h3.update(
        {
            "status": "failed" if base_descent_violations else "passed",
            "reason": (
                "base_servo_or_adapter_descends_before_centering"
                if base_descent_violations
                else "base_servo_align_descent_not_observed"
            ),
            "root_cause_candidates": (
                ["BASE_SERVO_PREMATURE_DESCENT"] if base_descent_violations else []
            ),
            "evidence": {
                "align_row_count": len(align_records),
                "base_descent_violation_count": len(base_descent_violations),
                "example_violations": base_descent_violations[:3],
            },
        }
    )
    return {"H1": h1, "H2": h2, "H3": h3}


def _mvp2e_h15_record(output_dir: Path) -> dict[str, Any]:
    record = build_empty_harness_record("H15", tier="close_critical")
    child_dir = output_dir / V07C_CHILD_OUTPUT_DIRNAME
    candidate_path = child_dir / "candidate_policy_artifact_v0_7c.json"
    baseline_path = child_dir / "baseline_policy_artifact_v0_7c.json"
    if not candidate_path.exists() or not baseline_path.exists():
        record.update(
            {
                "status": "missing_evidence",
                "reason": "missing_v0_7c_policy_artifact_pair",
                "missing_evidence": [str(candidate_path), str(baseline_path)],
            }
        )
        return record
    candidate = read_json(candidate_path)
    baseline = read_json(baseline_path)
    equality_keys = (
        "selected_action_adapter_id",
        "authority_filter_config_sha256",
        "base_servo_config_sha256",
        "trainer",
        "trainer_family",
        "feature_schema",
        "feature_schema_version",
        "hyperparameters",
        "action_schema",
        "normalization_config_sha256",
    )
    mismatches = [
        key for key in equality_keys if candidate.get(key) != baseline.get(key)
    ]
    if mismatches:
        record.update(
            {
                "status": "failed",
                "reason": "candidate_baseline_adapter_or_schema_mismatch",
                "root_cause_candidates": ["NORMALIZATION_OR_ADAPTER_SCHEMA_MISMATCH"],
                "evidence": {
                    "mismatched_fields": mismatches,
                    "candidate_policy_artifact": str(candidate_path),
                    "baseline_policy_artifact": str(baseline_path),
                },
            }
        )
    else:
        record.update(
            {
                "status": "passed",
                "reason": "candidate_baseline_adapter_schema_and_trainer_shared",
                "evidence": {
                    "checked_fields": list(equality_keys),
                    "candidate_policy_artifact": str(candidate_path),
                    "baseline_policy_artifact": str(baseline_path),
                },
            }
        )
    return record


def _mvp2e_h14_record(trace_index: dict[str, Any]) -> dict[str, Any]:
    record = build_empty_harness_record("H14", tier="close_critical")
    if trace_index.get("protected_heldout_21000_21049_accessed") is True:
        record.update(
            {
                "status": "failed",
                "reason": "protected_heldout_seed_accessed",
                "root_cause_candidates": ["EVALUATOR_OR_SCENARIO_MUTATION"],
            }
        )
    else:
        record.update(
            {
                "status": "passed",
                "reason": "legacy_path_labels_do_not_indicate_protected_seed_access",
            }
        )
    record["evidence"] = {
        "trace_count": trace_index.get("trace_count"),
        "legacy_heldout_path_label_detected": trace_index.get("legacy_heldout_path_label_detected"),
        "legacy_heldout_path_label_interpretation": trace_index.get(
            "legacy_heldout_path_label_interpretation"
        ),
    }
    return record


def _mvp2e_h4_record(output_dir: Path) -> dict[str, Any]:
    record = build_empty_harness_record("H4", tier="close_critical")
    gate_path = output_dir / "train_generation_runtime_gate.json"
    if not gate_path.exists():
        record.update(
            {
                "status": "not_evaluated",
                "reason": "train_generation_runtime_gate_not_present_in_current_harness_context",
            }
        )
        return record
    gate = read_json(gate_path)
    passed = gate.get("passed") is True and int(gate.get("generated_success_count", 0)) >= V06_TRAIN_GATE_SUCCESS_MINIMUM
    record.update(
        {
            "status": "passed" if passed else "failed",
            "reason": "train_generation_gate_passed" if passed else "train_generation_gate_not_passed",
            "root_cause_candidates": [] if passed else ["EXPERT_SOURCE_INVALID"],
            "evidence": {
                "path": str(gate_path),
                "generated_success_count": gate.get("generated_success_count"),
                "required_success_count": V06_TRAIN_GATE_SUCCESS_MINIMUM,
            },
        }
    )
    return record


def _mvp2e_h12_record(output_dir: Path, *, policy_slice_under_test: str = V07C_POLICY_SLICE_ID) -> dict[str, Any]:
    record = build_empty_harness_record("H12", tier="close_critical")
    if policy_slice_under_test == V07D_POLICY_SLICE_ID:
        policy_path = output_dir / V07D_CHILD_OUTPUT_DIRNAME / "candidate_policy_artifact_v0_7d.json"
        if not policy_path.exists():
            record.update(
                {
                    "status": "not_evaluated",
                    "reason": "v0_7d_policy_artifact_not_present_in_current_harness_context",
                    "missing_evidence": [str(policy_path)],
                }
            )
            return record
        policy = read_json(policy_path)
        final_config = policy.get("final_post_adapter_authority_config")
        stable_hold_authority = policy.get("stable_hold_authority")
        config_stable_hold_authority = (
            final_config.get("stable_hold_authority") if isinstance(final_config, dict) else None
        )
        selected_adapter_config = policy.get("selected_action_adapter_config")
        if not isinstance(selected_adapter_config, dict):
            selected_adapter_config = {}
        evidence = {
            "path": str(policy_path),
            "selected_adapter_id": policy.get("selected_action_adapter_id"),
            "stable_hold_authority": stable_hold_authority,
            "final_config_stable_hold_authority": config_stable_hold_authority,
            "required_authority": "env_native_success_mask",
            "legacy_selected_adapter_geometry_thresholds_report_only": {
                key: selected_adapter_config.get(key)
                for key in (
                    "stable_hold_depth_m",
                    "stable_hold_lateral_m",
                    "stable_hold_orientation_deg",
                )
                if key in selected_adapter_config
            },
        }
        if stable_hold_authority == "env_native_success_mask" and config_stable_hold_authority == "env_native_success_mask":
            record.update(
                {
                    "status": "passed",
                    "reason": "stable_hold_uses_env_native_success_mask_authority",
                    "evidence": evidence,
                }
            )
        else:
            record.update(
                {
                    "status": "failed",
                    "reason": "stable_hold_uses_geometry_thresholds_instead_of_env_native_mask",
                    "root_cause_candidates": ["PHASE_LABEL_RUNTIME_MISMATCH"],
                    "evidence": evidence,
                }
            )
        return record

    adapter_path = output_dir / "selected_action_adapter.json"
    if not adapter_path.exists():
        record.update(
            {
                "status": "not_evaluated",
                "reason": "selected_action_adapter_not_present_in_current_harness_context",
                "missing_evidence": [str(adapter_path)],
            }
        )
        return record

    adapter = read_json(adapter_path)
    selected_adapter_config = adapter.get("selected_adapter_config")
    if not isinstance(selected_adapter_config, dict):
        selected_adapter_config = adapter

    stable_hold_authority = selected_adapter_config.get("stable_hold_authority")
    uses_env_native_mask = (
        selected_adapter_config.get("stable_hold_uses_env_native_mask") is True
        or stable_hold_authority == "env_native_success_mask"
    )
    stable_hold_geometry_keys = (
        "stable_hold_depth_m",
        "stable_hold_lateral_m",
        "stable_hold_orientation_deg",
    )
    geometry_thresholds = {
        key: selected_adapter_config.get(key)
        for key in stable_hold_geometry_keys
        if key in selected_adapter_config
    }
    evidence = {
        "path": str(adapter_path),
        "selected_adapter_id": adapter.get("selected_adapter_id"),
        "stable_hold_authority": stable_hold_authority,
        "stable_hold_uses_env_native_mask": selected_adapter_config.get(
            "stable_hold_uses_env_native_mask"
        ),
        "required_authority": "env_native_success_mask",
        "z_action_scale": selected_adapter_config.get("z_action_scale"),
        **geometry_thresholds,
    }
    if geometry_thresholds and not uses_env_native_mask:
        record.update(
            {
                "status": "failed",
                "reason": "stable_hold_uses_geometry_thresholds_instead_of_env_native_mask",
                "root_cause_candidates": ["PHASE_LABEL_RUNTIME_MISMATCH"],
                "evidence": evidence,
            }
        )
    elif uses_env_native_mask:
        record.update(
            {
                "status": "passed",
                "reason": "stable_hold_uses_env_native_success_mask_authority",
                "evidence": evidence,
            }
        )
    else:
        record.update(
            {
                "status": "not_evaluated",
                "reason": "stable_hold_authority_not_declared_in_selected_action_adapter",
                "evidence": evidence,
            }
        )
    return record


def _mvp2e_build_harnesses(
    *,
    output_dir: Path,
    config: dict[str, Any],
    trace_index: dict[str, Any],
) -> dict[str, dict[str, Any]]:
    harnesses = {
        harness_id: build_empty_harness_record(harness_id)
        for harness_id in MVP2E_HARNESS_IDS
    }
    harnesses["H0"] = _mvp2e_h0_record(config, trace_index)
    harnesses.update(_mvp2e_action_authority_records(output_dir))
    harnesses["H4"] = _mvp2e_h4_record(output_dir)
    harnesses["H12"] = _mvp2e_h12_record(output_dir, policy_slice_under_test=str(config.get("policy_slice_under_test")))
    harnesses["H14"] = _mvp2e_h14_record(trace_index)
    harnesses["H15"] = _mvp2e_h15_record(output_dir)
    return harnesses


def _mvp2e_classify_harnesses(harnesses: dict[str, dict[str, Any]]) -> dict[str, Any]:
    unevaluated_close_critical = [
        harness_id
        for harness_id in MVP2E_CLOSE_CRITICAL_HARNESS_IDS
        if harnesses[harness_id].get("status") == "not_evaluated"
    ]
    missing_required = [
        {
            "harness_id": harness_id,
            "missing_evidence": harnesses[harness_id].get("missing_evidence", []),
            "reason": harnesses[harness_id].get("reason"),
        }
        for harness_id in MVP2E_REQUIRED_EVIDENCE_HARNESS_IDS
        if harnesses[harness_id].get("status") == "missing_evidence"
    ]
    if missing_required:
        return {
            "root_cause_status": "missing_evidence",
            "primary_root_cause_class": None,
            "root_cause_class": None,
            "secondary_root_cause_candidates": [],
            "missing_required_evidence": missing_required,
            "recommended_downstream_slice": None,
            "recommended_downstream_repair_requirements": [],
            "unevaluated_close_critical_harnesses": unevaluated_close_critical,
            "close_critical_passed": False,
        }
    candidates: list[str] = []
    for record in harnesses.values():
        if record.get("status") == "failed":
            for candidate in record.get("root_cause_candidates", []):
                if candidate in MVP2E_ROOT_CAUSE_PRECEDENCE:
                    candidates.append(str(candidate))
    ordered = [candidate for candidate in MVP2E_ROOT_CAUSE_PRECEDENCE if candidate in set(candidates)]
    primary = ordered[0] if ordered else None
    close_critical_passed = all(
        harnesses[harness_id].get("status") == "passed"
        for harness_id in MVP2E_CLOSE_CRITICAL_HARNESS_IDS
    )
    recommended_downstream_repair_requirements = [
        MVP2E_ROOT_CAUSE_REPAIR_REQUIREMENTS[candidate]
        for candidate in ordered
        if candidate in MVP2E_ROOT_CAUSE_REPAIR_REQUIREMENTS
    ]
    return {
        "root_cause_status": "classified" if primary else "passed",
        "primary_root_cause_class": primary,
        "root_cause_class": primary,
        "secondary_root_cause_candidates": ordered[1:],
        "missing_required_evidence": [],
        "recommended_downstream_slice": (
            MVP2E_ROOT_CAUSE_DOWNSTREAM_SLICE.get(primary) if primary else None
        ),
        "recommended_downstream_repair_requirements": recommended_downstream_repair_requirements,
        "unevaluated_close_critical_harnesses": unevaluated_close_critical,
        "close_critical_passed": bool(close_critical_passed),
    }


def build_mvp2e_harness_report(
    *,
    output_dir: Path,
    config: dict[str, Any] | None = None,
) -> dict[str, Any]:
    config = config or build_mvp2e_harness_config(output_dir=output_dir)
    validate_mvp2e_harness_config(config)
    trace_index = _mvp2e_trace_index(output_dir)
    harnesses = _mvp2e_build_harnesses(
        output_dir=output_dir,
        config=config,
        trace_index=trace_index,
    )
    classification = _mvp2e_classify_harnesses(harnesses)
    report: dict[str, Any] = {
        "schema_version": MVP2E_HARNESS_REPORT_SCHEMA_VERSION,
        "scenario_profile": config["scenario_profile"],
        "policy_slice_under_test": config["policy_slice_under_test"],
        "harnesses": harnesses,
        "trace_index": {
            "trace_count": trace_index["trace_count"],
            "traces": trace_index["traces"],
            "harness_trace_index_sha256": trace_index["harness_trace_index_sha256"],
        },
        "protected_heldout_21000_21049_accessed": trace_index[
            "protected_heldout_21000_21049_accessed"
        ],
        "legacy_heldout_path_label_detected": trace_index["legacy_heldout_path_label_detected"],
        "legacy_heldout_path_label_interpretation": trace_index[
            "legacy_heldout_path_label_interpretation"
        ],
        "classifier_precedence": list(MVP2E_ROOT_CAUSE_PRECEDENCE),
        "downstream_slice_created": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "heldout_opened": False,
        "calibration_opened": False,
        "proof_authority": "diagnostic_only_not_closure_authority",
        **classification,
    }
    report["mvp2e_harness_report_sha256"] = _sha256_payload_excluding(
        report,
        "mvp2e_harness_report_sha256",
    )
    return report


def write_mvp2e_harness_artifacts(
    output_dir: Path,
    *,
    policy_slice_under_test: str = V07C_POLICY_SLICE_ID,
) -> dict[str, Any]:
    config = build_mvp2e_harness_config(output_dir=output_dir, policy_slice_under_test=policy_slice_under_test)
    trace_index = _mvp2e_trace_index(output_dir)
    report = build_mvp2e_harness_report(output_dir=output_dir, config=config)
    harness_dir = _mvp2e_harness_dir(output_dir)
    trace_index_path = harness_dir / "harness_trace_index.json"
    report_path = harness_dir / "mvp2e_harness_report.json"
    rationale_path = harness_dir / "harness_research_rationale.json"
    manifest_path = harness_dir / "mvp2e_harness_gate_manifest.json"
    write_json(trace_index_path, trace_index)
    write_json(report_path, report)
    rationale = {
        "schema_version": "rdf_mvp2e_harness_research_rationale_v0.1.0",
        "role": "diagnostic_only",
        "adopted_as": "harness_categories_not_new_policy_algorithms",
        "references": [
            "Robot Data Curation with Mutual Information Estimators, 2025",
            "Policy Comparison with Near-Optimal Stopping, 2025",
            "Reactive Diffusion Policy, RSS 2025",
            "Difference-Aware Retrieval Policies for Imitation Learning, 2026",
            "AutoEval, 2025",
            "DAgger, 2011",
        ],
        "non_claims": config["non_claims"],
    }
    rationale["harness_research_rationale_sha256"] = _sha256_payload_excluding(
        rationale,
        "harness_research_rationale_sha256",
    )
    write_json(rationale_path, rationale)
    artifact_paths = {
        "config": harness_dir / "mvp2e_harness_config.json",
        "trace_index": trace_index_path,
        "report": report_path,
        "research_rationale": rationale_path,
    }
    manifest = {
        "schema_version": MVP2E_HARNESS_GATE_MANIFEST_SCHEMA_VERSION,
        "policy_slice_under_test": policy_slice_under_test,
        "harness_output_dir": str(harness_dir),
        "artifacts": {
            key: {"path": str(path), "sha256": _sha256_file(path)}
            for key, path in artifact_paths.items()
        },
        "root_cause_status": report["root_cause_status"],
        "primary_root_cause_class": report["primary_root_cause_class"],
        "secondary_root_cause_candidates": report["secondary_root_cause_candidates"],
        "recommended_downstream_slice": report["recommended_downstream_slice"],
        "recommended_downstream_repair_requirements": report[
            "recommended_downstream_repair_requirements"
        ],
        "unevaluated_close_critical_harnesses": report[
            "unevaluated_close_critical_harnesses"
        ],
        "downstream_slice_created": False,
        "mvp2_closed": False,
        "heldout_opened": False,
        "heldout_21000_21049_accessed": report["protected_heldout_21000_21049_accessed"],
    }
    manifest["mvp2e_harness_gate_manifest_sha256"] = _sha256_payload_excluding(
        manifest,
        "mvp2e_harness_gate_manifest_sha256",
    )
    write_json(manifest_path, manifest)
    return {
        "config": config,
        "trace_index": trace_index,
        "report": report,
        "research_rationale": rationale,
        "manifest": manifest,
    }


def apply_v07c_action_authority_filter(
    *,
    behavior_state_phase: str,
    base_action: np.ndarray,
    residual_prediction: np.ndarray,
    raw_action_before_authority: np.ndarray,
    authority_config: dict[str, Any],
) -> tuple[np.ndarray, dict[str, Any]]:
    base = np.asarray(base_action, dtype=np.float64).copy()
    residual = np.asarray(residual_prediction, dtype=np.float64).copy()
    before = np.asarray(raw_action_before_authority, dtype=np.float64).copy()
    after = before.copy()
    phase = str(behavior_state_phase).upper()
    z_source = "base_plus_residual"
    align_suppressed = False
    if phase == "ALIGN" and authority_config.get("align_z_authority") == "base_servo_z_only":
        after[2] = base[2]
        residual_after = 0.0
        z_source = "base_servo"
        align_suppressed = True
    else:
        residual_after = float(after[2] - base[2])
    diagnostics = {
        "authority_filter_id": authority_config.get("authority_filter_id"),
        "authority_filter_config_sha256": authority_config.get("authority_filter_config_sha256"),
        "behavior_state_phase": phase,
        "residual_z_before_authority": round(float(residual[2]), 12),
        "residual_z_after_authority": round(float(residual_after), 12),
        "align_residual_z_suppressed": bool(align_suppressed),
        "z_authority_source": z_source,
    }
    return np.round(after, 12), diagnostics


def _v07c_fail_gate(reason: str, **extra: Any) -> dict[str, Any]:
    gate = {
        "schema_version": V07C_OFFLINE_ACTION_AUTHORITY_GATE_SCHEMA_VERSION,
        "policy_slice": V07C_POLICY_SLICE_ID,
        "slice_id": V07C_SLICE_ID,
        "passed": False,
        "failure_reason": reason,
        "phase_e_candidate_expressibility_unblocked": False,
        "future_ab_ready": False,
        "heldout_21000_21049_accessed": False,
        "proof_authority": False,
        **extra,
    }
    gate["offline_action_authority_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "offline_action_authority_gate_sha256",
    )
    return gate


def _validate_v07c_policy_artifact_pair(
    *,
    candidate_policy_artifact: dict[str, Any],
    baseline_policy_artifact: dict[str, Any],
    authority_config: dict[str, Any],
) -> str | None:
    for artifact in (candidate_policy_artifact, baseline_policy_artifact):
        if artifact.get("policy_slice") != V07C_POLICY_SLICE_ID:
            return "policy_slice_mismatch"
        if artifact.get("authority_filter_id") != V07C_AUTHORITY_FILTER_ID:
            return "authority_filter_id_mismatch"
        if artifact.get("authority_filter_config_sha256") != authority_config.get("authority_filter_config_sha256"):
            return "authority_filter_config_mismatch"
        if artifact.get("base_servo_id") != V07B_BASE_SERVO_ID:
            return "base_servo_mismatch"
        if artifact.get("residual_target_definition") != V07B_RESIDUAL_TARGET_DEFINITION:
            return "residual_target_definition_mismatch"
        if artifact.get("heldout_21000_21049_accessed") is not False:
            return "heldout_access_detected"
    equality_keys = (
        "authority_filter_id",
        "authority_filter_config_sha256",
        "selected_action_adapter_id",
        "base_servo_config_sha256",
        "trainer",
        "trainer_family",
        "hyperparameters",
    )
    for key in equality_keys:
        if candidate_policy_artifact.get(key) != baseline_policy_artifact.get(key):
            if key == "selected_action_adapter_id":
                return "selected_action_adapter_mismatch"
            if key == "authority_filter_config_sha256":
                return "authority_filter_config_mismatch"
            return f"{key}_mismatch"
    return None


def _v07c_authority_metric_block(
    rows: list[dict[str, Any]],
    predictions: list[list[float]],
    *,
    authority_config: dict[str, Any],
    prefix: str,
) -> dict[str, Any]:
    align_pairs = _phase_rows_with_predictions(rows, predictions, "ALIGN")
    if not align_pairs:
        return {f"{prefix}_align_row_count": 0, f"{prefix}_required_phase_missing": True}
    raw_equals_base = 0
    suppressed = 0
    residual_after_abs: list[float] = []
    for row, prediction in align_pairs:
        base = np.asarray(row["base_servo_action"], dtype=np.float64)
        residual = np.asarray(prediction, dtype=np.float64)
        before = base + residual
        after, diagnostics = apply_v07c_action_authority_filter(
            behavior_state_phase=str(row.get("behavior_state_phase") or ""),
            base_action=base,
            residual_prediction=residual,
            raw_action_before_authority=before,
            authority_config=authority_config,
        )
        if diagnostics["align_residual_z_suppressed"] is True:
            suppressed += 1
        if abs(float(after[2] - base[2])) <= 1e-9:
            raw_equals_base += 1
        residual_after_abs.append(abs(float(after[2] - base[2])))
    count = len(align_pairs)
    return {
        f"{prefix}_align_row_count": count,
        f"{prefix}_align_z_suppression_rate": round(suppressed / count, 6),
        f"{prefix}_align_raw_z_equals_base_z_rate": round(raw_equals_base / count, 6),
        f"{prefix}_align_residual_z_after_authority_abs_max": round(max(residual_after_abs), 12),
    }


def derive_v07c_offline_action_authority_gate(
    *,
    candidate_rows: list[dict[str, Any]],
    baseline_rows: list[dict[str, Any]],
    candidate_policy_artifact: dict[str, Any],
    baseline_policy_artifact: dict[str, Any],
    authority_config: dict[str, Any],
    candidate_predictions: list[list[float]] | None = None,
    baseline_predictions: list[list[float]] | None = None,
) -> dict[str, Any]:
    pair_error = _validate_v07c_policy_artifact_pair(
        candidate_policy_artifact=candidate_policy_artifact,
        baseline_policy_artifact=baseline_policy_artifact,
        authority_config=authority_config,
    )
    if pair_error is not None:
        return _v07c_fail_gate(pair_error)
    candidate_predictions = candidate_predictions or predict_actions_for_rows(candidate_policy_artifact, candidate_rows)
    baseline_predictions = baseline_predictions or predict_actions_for_rows(baseline_policy_artifact, baseline_rows)
    candidate_metrics = _v07c_authority_metric_block(
        candidate_rows,
        candidate_predictions,
        authority_config=authority_config,
        prefix="candidate",
    )
    baseline_metrics = _v07c_authority_metric_block(
        baseline_rows,
        baseline_predictions,
        authority_config=authority_config,
        prefix="baseline",
    )
    gate: dict[str, Any] = {
        "schema_version": V07C_OFFLINE_ACTION_AUTHORITY_GATE_SCHEMA_VERSION,
        "policy_slice": V07C_POLICY_SLICE_ID,
        "slice_id": V07C_SLICE_ID,
        "authority_filter_id": V07C_AUTHORITY_FILTER_ID,
        "candidate_authority_filter_config_sha256": candidate_policy_artifact.get("authority_filter_config_sha256"),
        "baseline_authority_filter_config_sha256": baseline_policy_artifact.get("authority_filter_config_sha256"),
        "candidate_selected_action_adapter_id": candidate_policy_artifact.get("selected_action_adapter_id"),
        "baseline_selected_action_adapter_id": baseline_policy_artifact.get("selected_action_adapter_id"),
        "heldout_21000_21049_accessed": False,
        "proof_authority": False,
        **candidate_metrics,
        **baseline_metrics,
    }
    passed = (
        gate.get("candidate_align_row_count", 0) > 0
        and gate.get("baseline_align_row_count", 0) > 0
        and gate.get("candidate_align_z_suppression_rate") == 1.0
        and gate.get("baseline_align_z_suppression_rate") == 1.0
        and gate.get("candidate_align_raw_z_equals_base_z_rate", 0.0) >= 0.999
        and gate.get("baseline_align_raw_z_equals_base_z_rate", 0.0) >= 0.999
        and gate.get("candidate_align_residual_z_after_authority_abs_max", 1.0) <= 1e-9
        and gate.get("baseline_align_residual_z_after_authority_abs_max", 1.0) <= 1e-9
        and gate["candidate_authority_filter_config_sha256"] == gate["baseline_authority_filter_config_sha256"]
        and gate["candidate_selected_action_adapter_id"] == gate["baseline_selected_action_adapter_id"]
    )
    gate["passed"] = bool(passed)
    gate["phase_e_candidate_expressibility_unblocked"] = bool(passed)
    gate["future_ab_ready"] = bool(passed)
    gate["failure_reason"] = "" if passed else "align_z_authority_violation"
    gate["offline_action_authority_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "offline_action_authority_gate_sha256",
    )
    return gate


def _rounded_action(values: np.ndarray | list[float]) -> list[float]:
    return [round(float(value), 12) for value in np.asarray(values, dtype=np.float64).reshape(-1).tolist()]


def build_v07d_policy_artifact_payload(
    *,
    base_policy_artifact: dict[str, Any],
    final_authority_config: dict[str, Any],
    dataset_view_role: str,
) -> dict[str, Any]:
    validate_v07d_final_action_authority_config_contract(final_authority_config)
    if base_policy_artifact.get("policy_slice") != V07C_POLICY_SLICE_ID:
        raise ValueError("v0_7d_parent_policy_slice_mismatch")
    inherited_authority_sha = final_authority_config["inherited_authority_filter_config_sha256"]
    if base_policy_artifact.get("authority_filter_config_sha256") != inherited_authority_sha:
        raise ValueError("v0_7d_parent_authority_filter_config_mismatch")
    parent_authority_config = base_policy_artifact.get("authority_filter_config")
    if isinstance(parent_authority_config, dict) and (
        parent_authority_config.get("authority_filter_config_sha256") != inherited_authority_sha
    ):
        raise ValueError("v0_7d_parent_authority_filter_config_mismatch")
    selected_config_raw = base_policy_artifact.get("selected_action_adapter_config")
    if not isinstance(selected_config_raw, dict):
        raise ValueError("v0_7d_parent_selected_action_adapter_config_missing")
    selected_config = dict(selected_config_raw)
    parent_adapter_sha = base_policy_artifact.get("selected_action_adapter_config_sha256")
    if not parent_adapter_sha or parent_adapter_sha != _sha256_payload(selected_config):
        raise ValueError("v0_7d_parent_selected_action_adapter_config_hash_mismatch")
    payload = dict(base_policy_artifact)
    payload.update(
        {
            "policy_artifact_schema_version": V07D_POLICY_ARTIFACT_SCHEMA_VERSION,
            "policy_slice": V07D_POLICY_SLICE_ID,
            "slice_id": V07D_SLICE_ID,
            "parent_policy_slice": V07C_POLICY_SLICE_ID,
            "dataset_view_role": dataset_view_role,
            "selected_action_adapter_config": selected_config,
            "selected_action_adapter_config_sha256": parent_adapter_sha,
            "parent_selected_action_adapter_config_sha256": parent_adapter_sha,
            "effective_v07d_adapter_view_sha256": parent_adapter_sha,
            "selected_action_adapter_lineage": "inherited_unchanged_from_v0_7c",
            "stable_hold_authority": "env_native_success_mask",
            "final_post_adapter_authority_id": V07D_FINAL_POST_ADAPTER_AUTHORITY_ID,
            "final_post_adapter_authority_config": dict(final_authority_config),
            "final_post_adapter_authority_config_sha256": final_authority_config[
                "final_post_adapter_authority_config_sha256"
            ],
            "same_final_post_adapter_authority_as_peer": True,
            "same_stable_hold_authority_as_peer": True,
            "future_ab_ready": False,
            "proof_authority": False,
            "heldout_21000_21049_accessed": False,
            "mvp2_closed": False,
        }
    )
    payload["policy_artifact_sha256"] = _sha256_payload_excluding(payload, "policy_artifact_sha256")
    return payload


def build_v07e_policy_artifact_payload(
    *,
    base_policy_artifact: dict[str, Any],
    hysteresis_config: dict[str, Any],
    dataset_view_role: str,
) -> dict[str, Any]:
    validate_v07e_hysteresis_authority_config_contract(hysteresis_config)
    if base_policy_artifact.get("policy_slice") != V07D_POLICY_SLICE_ID:
        raise ValueError("v0_7e_parent_policy_slice_mismatch")
    parent_final_sha = base_policy_artifact.get("final_post_adapter_authority_config_sha256")
    if parent_final_sha != hysteresis_config.get("parent_final_post_adapter_authority_config_sha256"):
        raise ValueError("v0_7e_parent_final_authority_hash_mismatch")
    selected_config = base_policy_artifact.get("selected_action_adapter_config")
    if not isinstance(selected_config, dict):
        raise ValueError("v0_7e_parent_selected_action_adapter_config_missing")
    selected_config_sha = base_policy_artifact.get("selected_action_adapter_config_sha256")
    if not selected_config_sha or selected_config_sha != _sha256_payload(selected_config):
        raise ValueError("v0_7e_parent_selected_action_adapter_config_hash_mismatch")
    payload = dict(base_policy_artifact)
    payload.update(
        {
            "policy_artifact_schema_version": V07E_POLICY_ARTIFACT_SCHEMA_VERSION,
            "policy_slice": V07E_POLICY_SLICE_ID,
            "slice_id": V07E_SLICE_ID,
            "parent_policy_slice": V07D_POLICY_SLICE_ID,
            "dataset_view_role": dataset_view_role,
            "selected_action_adapter_config": dict(selected_config),
            "selected_action_adapter_config_sha256": selected_config_sha,
            "selected_action_adapter_lineage": "inherited_unchanged_from_v0_7d",
            "final_post_adapter_authority_config_sha256": parent_final_sha,
            "shared_hysteresis_authority_id": hysteresis_config["shared_hysteresis_authority_id"],
            "shared_hysteresis_authority_config": dict(hysteresis_config),
            "shared_hysteresis_authority_config_sha256": hysteresis_config[
                "shared_hysteresis_authority_config_sha256"
            ],
            "same_hysteresis_config_as_peer": True,
            "heldout_21000_21049_accessed": False,
            "future_ab_ready": False,
            "proof_authority": False,
            "mvp2_closed": False,
        }
    )
    payload["policy_artifact_sha256"] = _sha256_payload_excluding(payload, "policy_artifact_sha256")
    return payload


def apply_v07d_final_post_adapter_authority(
    *,
    action: np.ndarray,
    behavior_state_phase: str,
    final_authority_config: dict[str, Any],
    current_block_reason: str = "z_motion_allowed",
) -> tuple[np.ndarray, dict[str, Any]]:
    validate_v07d_final_action_authority_config_contract(final_authority_config)
    before = np.asarray(action, dtype=np.float64).copy()
    after = before.copy()
    phase = str(behavior_state_phase or "").upper()
    z_allowed = True
    reason = current_block_reason
    if phase == "ALIGN":
        z_allowed = False
        after[2] = 0.0
        reason = "final_post_adapter_align_z_blocked"
    final_action = np.round(np.clip(after, -1.0, 1.0), 12)
    return final_action, {
        "final_post_adapter_authority_id": final_authority_config["final_post_adapter_authority_id"],
        "final_post_adapter_authority_config_sha256": final_authority_config[
            "final_post_adapter_authority_config_sha256"
        ],
        "pre_final_authority_action_vector": _rounded_action(before),
        "post_adapter_action_vector": _rounded_action(final_action),
        "final_post_adapter_z_motion_allowed": bool(z_allowed),
        "z_motion_block_reason": reason,
    }


def _simulate_selected_action_adapter_for_offline_gate(
    *,
    policy_artifact: dict[str, Any],
    raw_action: np.ndarray,
) -> tuple[np.ndarray, dict[str, Any]]:
    adapter_id = str(policy_artifact.get("selected_action_adapter_id") or "")
    raw_config = policy_artifact.get("selected_action_adapter_config")
    if policy_artifact.get("policy_slice") in {V07D_POLICY_SLICE_ID, V07E_POLICY_SLICE_ID}:
        if not isinstance(raw_config, dict):
            raise ValueError("v0_7d_selected_action_adapter_config_missing")
        config_hash = policy_artifact.get("selected_action_adapter_config_sha256")
        if config_hash != _sha256_payload(raw_config):
            raise ValueError("v0_7d_selected_action_adapter_config_hash_mismatch")
    config = dict(raw_config) if isinstance(raw_config, dict) else {}
    action = np.asarray(raw_action, dtype=np.float64).copy()
    if adapter_id != "isaac_signed_xy_downward_servo_v0":
        final = np.round(np.clip(action, -1.0, 1.0), 12)
        return final, {
            "selected_action_adapter_id": adapter_id,
            "z_motion_block_reason": "no_v06_controller",
            "pre_final_authority_action_vector": _rounded_action(final),
        }
    xy_scale = float(config.get("xy_action_scale", 1.0))
    xy_clip = float(config.get("xy_action_clip", 0.035))
    z_scale = float(config.get("z_action_scale", 1.0))
    z_clip = float(config.get("z_action_clip", 0.12))
    rotation_scale = float(config.get("rotation_action_scale", 0.0))
    action[0:2] = np.clip(action[0:2] * xy_scale, -xy_clip, xy_clip)
    action[2] = np.clip(action[2] * z_scale, -z_clip, z_clip)
    action[3:6] = np.clip(action[3:6] * rotation_scale, -1.0, 1.0)
    if action.shape[0] > 6:
        action[6] = np.clip(action[6], -1.0, 1.0)
    final = np.round(np.clip(action, -1.0, 1.0), 12)
    return final, {
        "selected_action_adapter_id": adapter_id,
        "z_motion_block_reason": "offline_selected_adapter_simulated",
        "pre_final_authority_action_vector": _rounded_action(final),
    }


def _validate_v07d_policy_artifact_pair(
    *,
    candidate_policy_artifact: dict[str, Any],
    baseline_policy_artifact: dict[str, Any],
    final_authority_config: dict[str, Any],
) -> str | None:
    validate_v07d_final_action_authority_config_contract(final_authority_config)
    inherited_authority_sha = final_authority_config["inherited_authority_filter_config_sha256"]
    for role, artifact in (
        ("candidate", candidate_policy_artifact),
        ("baseline", baseline_policy_artifact),
    ):
        if artifact.get("policy_slice") != V07D_POLICY_SLICE_ID:
            return "policy_slice_mismatch"
        if artifact.get("authority_filter_config_sha256") != inherited_authority_sha:
            return "parent_authority_filter_config_mismatch"
        parent_authority_config = artifact.get("authority_filter_config")
        if isinstance(parent_authority_config, dict) and (
            parent_authority_config.get("authority_filter_config_sha256") != inherited_authority_sha
        ):
            return "parent_authority_filter_config_mismatch"
        if artifact.get("stable_hold_authority") != "env_native_success_mask":
            return "stable_hold_authority_mismatch"
        if artifact.get("final_post_adapter_authority_id") != V07D_FINAL_POST_ADAPTER_AUTHORITY_ID:
            return "final_post_adapter_authority_id_mismatch"
        if artifact.get("final_post_adapter_authority_config_sha256") != final_authority_config.get(
            "final_post_adapter_authority_config_sha256"
        ):
            return "final_post_adapter_authority_config_mismatch"
        if artifact.get("heldout_21000_21049_accessed") is not False:
            return "heldout_access_detected"
        selected_config = artifact.get("selected_action_adapter_config")
        if not isinstance(selected_config, dict):
            return f"{role}_selected_action_adapter_config_missing"
        selected_config_sha = artifact.get("selected_action_adapter_config_sha256")
        if not selected_config_sha or selected_config_sha != _sha256_payload(selected_config):
            return f"{role}_selected_action_adapter_config_hash_mismatch"
    equality_keys = (
        "selected_action_adapter_id",
        "selected_action_adapter_config_sha256",
        "authority_filter_config_sha256",
        "parent_selected_action_adapter_config_sha256",
        "effective_v07d_adapter_view_sha256",
        "trainer",
        "trainer_family",
        "hyperparameters",
        "feature_schema_version",
        "base_servo_config_sha256",
    )
    for key in equality_keys:
        if candidate_policy_artifact.get(key) != baseline_policy_artifact.get(key):
            return f"{key}_mismatch"
    return None


def _v07d_final_authority_metric_block(
    rows: list[dict[str, Any]],
    predictions: list[list[float]],
    *,
    policy_artifact: dict[str, Any],
    final_authority_config: dict[str, Any],
    prefix: str,
) -> dict[str, Any]:
    align_pairs = _phase_rows_with_predictions(rows, predictions, "ALIGN")
    if not align_pairs:
        return {
            f"{prefix}_align_row_count": 0,
            f"{prefix}_required_phase_missing": True,
            f"{prefix}_align_final_z_violation_count": 0,
            f"{prefix}_bad_block_reason_count": 0,
        }
    final_z_abs: list[float] = []
    violation_count = 0
    bad_reason_count = 0
    for row, prediction in align_pairs:
        base = np.asarray(row["base_servo_action"], dtype=np.float64)
        residual = np.asarray(prediction, dtype=np.float64)
        raw_action = base + residual
        pre_adapter_action, _pre_diag = apply_v07c_action_authority_filter(
            behavior_state_phase=str(row.get("behavior_state_phase") or ""),
            base_action=base,
            residual_prediction=residual,
            raw_action_before_authority=raw_action,
            authority_config=policy_artifact["authority_filter_config"],
        )
        post_adapter_action, adapter_diagnostics = _simulate_selected_action_adapter_for_offline_gate(
            policy_artifact=policy_artifact,
            raw_action=pre_adapter_action,
        )
        final_action, final_diagnostics = apply_v07d_final_post_adapter_authority(
            action=post_adapter_action,
            behavior_state_phase=str(row.get("behavior_state_phase") or ""),
            final_authority_config=final_authority_config,
            current_block_reason=str(adapter_diagnostics.get("z_motion_block_reason") or ""),
        )
        final_z_abs.append(abs(float(final_action[2])))
        if abs(float(final_action[2])) > 1e-9:
            violation_count += 1
        if final_diagnostics.get("z_motion_block_reason") in {"adapter_not_instrumented", "no_v06_controller"}:
            bad_reason_count += 1
    return {
        f"{prefix}_align_row_count": len(align_pairs),
        f"{prefix}_align_final_z_abs_max": round(max(final_z_abs), 12),
        f"{prefix}_align_final_z_violation_count": violation_count,
        f"{prefix}_bad_block_reason_count": bad_reason_count,
    }


def _v07d_fail_gate(reason: str, **extra: Any) -> dict[str, Any]:
    gate = {
        "schema_version": V07D_OFFLINE_FINAL_ACTION_AUTHORITY_GATE_SCHEMA_VERSION,
        "policy_slice": V07D_POLICY_SLICE_ID,
        "slice_id": V07D_SLICE_ID,
        "passed": False,
        "failure_reason": reason,
        "phase_e_candidate_expressibility_unblocked": False,
        "future_ab_ready": False,
        "heldout_21000_21049_accessed": False,
        "proof_authority": False,
        **extra,
    }
    gate["offline_final_action_authority_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "offline_final_action_authority_gate_sha256",
    )
    return gate


def derive_v07d_offline_final_action_authority_gate(
    *,
    candidate_rows: list[dict[str, Any]],
    baseline_rows: list[dict[str, Any]],
    candidate_policy_artifact: dict[str, Any],
    baseline_policy_artifact: dict[str, Any],
    final_authority_config: dict[str, Any],
    candidate_predictions: list[list[float]] | None = None,
    baseline_predictions: list[list[float]] | None = None,
) -> dict[str, Any]:
    pair_error = _validate_v07d_policy_artifact_pair(
        candidate_policy_artifact=candidate_policy_artifact,
        baseline_policy_artifact=baseline_policy_artifact,
        final_authority_config=final_authority_config,
    )
    if pair_error is not None:
        return _v07d_fail_gate(pair_error)
    candidate_predictions = candidate_predictions or predict_actions_for_rows(candidate_policy_artifact, candidate_rows)
    baseline_predictions = baseline_predictions or predict_actions_for_rows(baseline_policy_artifact, baseline_rows)
    candidate_metrics = _v07d_final_authority_metric_block(
        candidate_rows,
        candidate_predictions,
        policy_artifact=candidate_policy_artifact,
        final_authority_config=final_authority_config,
        prefix="candidate",
    )
    baseline_metrics = _v07d_final_authority_metric_block(
        baseline_rows,
        baseline_predictions,
        policy_artifact=baseline_policy_artifact,
        final_authority_config=final_authority_config,
        prefix="baseline",
    )
    gate: dict[str, Any] = {
        "schema_version": V07D_OFFLINE_FINAL_ACTION_AUTHORITY_GATE_SCHEMA_VERSION,
        "policy_slice": V07D_POLICY_SLICE_ID,
        "slice_id": V07D_SLICE_ID,
        "final_post_adapter_authority_id": V07D_FINAL_POST_ADAPTER_AUTHORITY_ID,
        "candidate_final_post_adapter_authority_config_sha256": candidate_policy_artifact.get(
            "final_post_adapter_authority_config_sha256"
        ),
        "baseline_final_post_adapter_authority_config_sha256": baseline_policy_artifact.get(
            "final_post_adapter_authority_config_sha256"
        ),
        "selected_action_adapter_id": candidate_policy_artifact.get("selected_action_adapter_id"),
        "candidate_parent_selected_action_adapter_config_sha256": candidate_policy_artifact.get(
            "parent_selected_action_adapter_config_sha256"
        ),
        "baseline_parent_selected_action_adapter_config_sha256": baseline_policy_artifact.get(
            "parent_selected_action_adapter_config_sha256"
        ),
        "stable_hold_authority": "env_native_success_mask",
        "heldout_21000_21049_accessed": False,
        "derived_from": "offline_train_row_action_simulation",
        "proof_authority": False,
        **candidate_metrics,
        **baseline_metrics,
    }
    passed = (
        gate.get("candidate_align_row_count", 0) > 0
        and gate.get("baseline_align_row_count", 0) > 0
        and gate.get("candidate_align_final_z_violation_count") == 0
        and gate.get("baseline_align_final_z_violation_count") == 0
        and gate.get("candidate_bad_block_reason_count") == 0
        and gate.get("baseline_bad_block_reason_count") == 0
        and gate["candidate_final_post_adapter_authority_config_sha256"]
        == gate["baseline_final_post_adapter_authority_config_sha256"]
    )
    gate["passed"] = bool(passed)
    gate["phase_e_candidate_expressibility_unblocked"] = bool(passed)
    gate["future_ab_ready"] = False
    gate["future_ab_ready_source"] = "requires_actual_phase_e_pass_and_calibration_freeze"
    gate["failure_reason"] = "" if passed else "final_post_adapter_align_z_authority_violation"
    gate["offline_final_action_authority_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "offline_final_action_authority_gate_sha256",
    )
    return gate


def derive_v07e_offline_hysteresis_parity_gate(
    *,
    counterfactual_windows: list[dict[str, Any]],
    hysteresis_config: dict[str, Any],
) -> dict[str, Any]:
    validate_v07e_hysteresis_authority_config_contract(hysteresis_config)
    protected_access = any(
        bool(item.get("protected_heldout_seed"))
        or (
            item.get("seed") is not None
            and _protected_heldout_seed_range_accessed(int(item["seed"]))
        )
        for item in counterfactual_windows
    )
    min_window = int(hysteresis_config.get("min_descend_window_reference_steps", 28))
    passing = [
        item
        for item in counterfactual_windows
        if int(item.get("v0_7e_counterfactual_max_consecutive_z_descent_steps", 0)) >= min_window
    ]
    passed = not protected_access and len(passing) >= 3
    gate: dict[str, Any] = {
        "schema_version": V07E_OFFLINE_HYSTERESIS_PARITY_GATE_SCHEMA_VERSION,
        "policy_slice": V07E_POLICY_SLICE_ID,
        "slice_id": V07E_SLICE_ID,
        "shared_hysteresis_authority_id": hysteresis_config["shared_hysteresis_authority_id"],
        "shared_hysteresis_authority_config_sha256": hysteresis_config[
            "shared_hysteresis_authority_config_sha256"
        ],
        "passed": bool(passed),
        "failure_reason": ""
        if passed
        else ("protected_heldout_seed_accessed" if protected_access else "insufficient_counterfactual_z_windows"),
        "min_passing_counterfactual_windows": 3,
        "passing_counterfactual_windows": len(passing),
        "counterfactual_window_count": len(counterfactual_windows),
        "heldout_21000_21049_accessed": bool(protected_access),
        "phase_e_candidate_expressibility_unblocked": False,
        "future_ab_ready": False,
        "proof_authority": False,
    }
    gate["offline_hysteresis_parity_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "offline_hysteresis_parity_gate_sha256",
    )
    return gate


def derive_v07e_attribution_preservation_gate(
    *,
    candidate_final_actions: list[list[float]],
    baseline_final_actions: list[list[float]],
    hysteresis_config: dict[str, Any],
    candidate_policy_artifact: dict[str, Any] | None = None,
    baseline_policy_artifact: dict[str, Any] | None = None,
) -> dict[str, Any]:
    validate_v07e_hysteresis_authority_config_contract(hysteresis_config)
    count = min(len(candidate_final_actions), len(baseline_final_actions))
    deltas: list[float] = []
    for index in range(count):
        candidate = np.asarray(candidate_final_actions[index], dtype=np.float64)
        baseline = np.asarray(baseline_final_actions[index], dtype=np.float64)
        deltas.append(float(np.linalg.norm(candidate - baseline)))
    delta_mean = float(np.mean(deltas)) if deltas else 0.0
    nonzero_fraction = (
        sum(1 for delta in deltas if delta > 1.0e-6) / float(count)
        if count
        else 0.0
    )
    equality_keys = (
        "selected_action_adapter_id",
        "selected_action_adapter_config_sha256",
        "authority_filter_config_sha256",
        "trainer",
        "trainer_family",
        "feature_schema_version",
        "base_servo_config_sha256",
        "stable_hold_authority",
        "final_post_adapter_authority_id",
        "final_post_adapter_authority_config_sha256",
        "shared_hysteresis_authority_config_sha256",
    )
    equalities: dict[str, bool] = {}
    if candidate_policy_artifact is not None and baseline_policy_artifact is not None:
        equalities = {
            key: candidate_policy_artifact.get(key) == baseline_policy_artifact.get(key)
            for key in equality_keys
        }
        policy_artifact_sha_differ = (
            candidate_policy_artifact.get("policy_artifact_sha256")
            != baseline_policy_artifact.get("policy_artifact_sha256")
        )
    else:
        equalities = {key: True for key in equality_keys}
        policy_artifact_sha_differ = True
    equalities_all_true = all(equalities.values())
    passed = (
        count > 0
        and delta_mean > 1.0e-6
        and nonzero_fraction >= 0.10
        and equalities_all_true
        and policy_artifact_sha_differ
    )
    gate: dict[str, Any] = {
        "schema_version": V07E_ATTRIBUTION_PRESERVATION_GATE_SCHEMA_VERSION,
        "policy_slice": V07E_POLICY_SLICE_ID,
        "slice_id": V07E_SLICE_ID,
        "shared_hysteresis_authority_id": hysteresis_config["shared_hysteresis_authority_id"],
        "shared_hysteresis_authority_config_sha256": hysteresis_config[
            "shared_hysteresis_authority_config_sha256"
        ],
        "same_hysteresis_config_for_baseline_and_candidate": bool(
            hysteresis_config.get("same_hysteresis_config_as_peer") is True
        ),
        "same_shared_infrastructure_equalities": equalities,
        "same_shared_infrastructure_equalities_all_true": bool(equalities_all_true),
        "candidate_baseline_policy_artifacts_differ": bool(policy_artifact_sha_differ),
        "paired_action_count": count,
        "candidate_baseline_final_action_delta_l2_mean": round(delta_mean, 12),
        "candidate_baseline_final_action_delta_nonzero_fraction": round(nonzero_fraction, 12),
        "candidate_baseline_final_action_delta_l2_threshold": 1.0e-6,
        "candidate_baseline_delta_nonzero_fraction_threshold": 0.10,
        "passed": bool(passed),
        "failure_reason": ""
        if passed
        else (
            "shared_infrastructure_mismatch"
            if not equalities_all_true
            else (
                "candidate_baseline_policy_artifacts_not_distinct"
                if not policy_artifact_sha_differ
                else "candidate_baseline_action_delta_collapsed"
            )
        ),
        "phase_e_candidate_expressibility_unblocked": False,
        "future_ab_ready": False,
        "heldout_21000_21049_accessed": False,
        "calibration_opened": False,
        "proof_authority": False,
    }
    gate["attribution_preservation_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "attribution_preservation_gate_sha256",
    )
    return gate


def _load_v07e_counterfactual_windows_from_autoresearch(
    path: Path = Path(".omx/specs/autoresearch-mvp2e-v07e-hysteresis-parity/result.json"),
) -> list[dict[str, Any]]:
    if not path.exists():
        return []
    result = read_json(path)
    comparisons = {
        int(item["seed"]): item
        for item in result.get("shared_scenario_comparisons", [])
        if isinstance(item, dict) and item.get("seed") is not None
    }
    windows: list[dict[str, Any]] = []
    counterfactual = result.get("offline_hysteresis_counterfactual", {})
    for item in counterfactual.get("trace_summaries", []) if isinstance(counterfactual, dict) else []:
        if not isinstance(item, dict) or item.get("seed") is None:
            continue
        seed = int(item["seed"])
        comparison = comparisons.get(seed, {})
        windows.append(
            {
                "seed": seed,
                "scenario_id": item.get("scenario_id") or comparison.get("scenario_id"),
                "expert_max_consecutive_z_descent_steps": int(
                    comparison.get("expert_longest_z_descent_streak", 0)
                ),
                "v0_7d_policy_max_consecutive_z_descent_steps": int(
                    item.get("actual_longest_z_open_segment", 0)
                ),
                "v0_7e_counterfactual_max_consecutive_z_descent_steps": int(
                    item.get("counterfactual_longest_z_open_segment", 0)
                ),
                "protected_heldout_seed": _protected_heldout_seed_range_accessed(seed),
                "real_rollout_success_claimed": bool(item.get("real_rollout_success_claimed") is True),
            }
        )
    return windows


def _v07e_final_actions_for_rows(
    *,
    rows: list[dict[str, Any]],
    predictions: list[list[float]],
    policy_artifact: dict[str, Any],
) -> tuple[list[list[float]], list[dict[str, Any]]]:
    final_config = policy_artifact.get("final_post_adapter_authority_config")
    if not isinstance(final_config, dict):
        raise ValueError("v0_7e_final_post_adapter_authority_config_missing")
    final_actions: list[list[float]] = []
    align_rows: list[dict[str, Any]] = []
    for row, prediction in zip(rows, predictions, strict=False):
        base = np.asarray(row["base_servo_action"], dtype=np.float64)
        residual = np.asarray(prediction, dtype=np.float64)
        raw_action = base + residual
        pre_adapter_action, _pre_diag = apply_v07c_action_authority_filter(
            behavior_state_phase=str(row.get("behavior_state_phase") or ""),
            base_action=base,
            residual_prediction=residual,
            raw_action_before_authority=raw_action,
            authority_config=policy_artifact["authority_filter_config"],
        )
        post_adapter_action, adapter_diagnostics = _simulate_selected_action_adapter_for_offline_gate(
            policy_artifact=policy_artifact,
            raw_action=pre_adapter_action,
        )
        final_action, _final_diag = apply_v07d_final_post_adapter_authority(
            action=post_adapter_action,
            behavior_state_phase=str(row.get("behavior_state_phase") or ""),
            final_authority_config=final_config,
            current_block_reason=str(adapter_diagnostics.get("z_motion_block_reason") or ""),
        )
        rounded = _rounded_action(final_action)
        final_actions.append(rounded)
        if str(row.get("behavior_state_phase") or "").upper() == "ALIGN":
            align_rows.append(
                {
                    "trajectory_id": row.get("trajectory_id"),
                    "behavior_state_phase": "ALIGN",
                    "final_post_adapter_action": rounded,
                }
            )
    return final_actions, align_rows


def derive_v07e_final_action_authority_regression_gate(
    *,
    final_align_rows: list[dict[str, Any]],
    hysteresis_gate: dict[str, Any],
    attribution_gate: dict[str, Any],
    hysteresis_config: dict[str, Any],
) -> dict[str, Any]:
    validate_v07e_hysteresis_authority_config_contract(hysteresis_config)
    violation_count = 0
    for row in final_align_rows:
        if str(row.get("behavior_state_phase") or "").upper() != "ALIGN":
            continue
        action = row.get("final_post_adapter_action") or row.get("post_adapter_action_vector") or []
        if len(action) > 2 and abs(float(action[2])) > 1.0e-9:
            violation_count += 1
    all_gates_passed = (
        hysteresis_gate.get("passed") is True
        and attribution_gate.get("passed") is True
        and violation_count == 0
        and hysteresis_gate.get("heldout_21000_21049_accessed") is False
        and attribution_gate.get("heldout_21000_21049_accessed") is False
    )
    gate: dict[str, Any] = {
        "schema_version": V07E_FINAL_AUTHORITY_REGRESSION_GATE_SCHEMA_VERSION,
        "policy_slice": V07E_POLICY_SLICE_ID,
        "slice_id": V07E_SLICE_ID,
        "shared_hysteresis_authority_config_sha256": hysteresis_config[
            "shared_hysteresis_authority_config_sha256"
        ],
        "passed": bool(all_gates_passed),
        "failure_reason": "" if all_gates_passed else "v0_7e_offline_gate_regression",
        "all_offline_gates_passed": bool(all_gates_passed),
        "align_final_z_violation_count": violation_count,
        "offline_hysteresis_parity_gate_sha256": hysteresis_gate.get("offline_hysteresis_parity_gate_sha256"),
        "attribution_preservation_gate_sha256": attribution_gate.get("attribution_preservation_gate_sha256"),
        "phase_e_candidate_expressibility_unblocked": bool(all_gates_passed),
        "future_ab_ready": False,
        "heldout_21000_21049_accessed": False,
        "proof_authority": False,
    }
    gate["final_action_authority_regression_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "final_action_authority_regression_gate_sha256",
    )
    return gate


def load_required_v07g_parent_diagnosis_report(output_dir: Path) -> dict[str, Any]:
    report_path = output_dir / V07F_OUTPUT_DIRNAME / "mvp2e_v07f_depth_zero_harness_report.json"
    if not report_path.exists():
        raise ValueError("missing_v0_7f_xy_saturation_parent_report")
    report = read_json(report_path)
    if (
        report.get("root_cause_status") != "classified"
        or report.get("primary_root_cause_class") != "XY_SATURATION_CENTERING_INSTABILITY"
        or report.get("recommended_downstream_slice") != "v0_7g_xy_authority_saturation_repair"
        or report.get("phase_e_passed") is not False
        or report.get("calibration_opened") is not False
        or report.get("heldout_21000_21049_accessed") is not False
    ):
        raise ValueError("invalid_v0_7f_xy_saturation_parent_report")
    return report


