def build_v07g_xy_authority_saturation_repair_slice(*, output_dir: Path) -> dict[str, Any]:
    parent_report = load_required_v07g_parent_diagnosis_report(output_dir)
    child_dir = output_dir / V07G_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    v07e_child_dir = output_dir / V07E_CHILD_OUTPUT_DIRNAME
    candidate_parent_path = v07e_child_dir / "candidate_policy_artifact_v0_7e.json"
    baseline_parent_path = v07e_child_dir / "baseline_policy_artifact_v0_7e.json"
    if not candidate_parent_path.exists() or not baseline_parent_path.exists():
        build_v07e_shared_hysteresis_parity_repair_slice(output_dir=output_dir)
    candidate_parent = read_json(candidate_parent_path)
    baseline_parent = read_json(baseline_parent_path)
    xy_config = build_v07g_xy_authority_config(
        output_dir=child_dir,
        parent_shared_hysteresis_authority_config_sha256=candidate_parent[
            "shared_hysteresis_authority_config_sha256"
        ],
        parent_final_post_adapter_authority_config_sha256=candidate_parent[
            "final_post_adapter_authority_config_sha256"
        ],
    )
    candidate_policy = build_v07g_policy_artifact_payload(
        base_policy_artifact=candidate_parent,
        xy_authority_config=xy_config,
        dataset_view_role="candidate_curated",
    )
    baseline_policy = build_v07g_policy_artifact_payload(
        base_policy_artifact=baseline_parent,
        xy_authority_config=xy_config,
        dataset_view_role="baseline_uncurated",
    )
    write_json(child_dir / "candidate_policy_artifact_v0_7g.json", candidate_policy)
    write_json(child_dir / "baseline_policy_artifact_v0_7g.json", baseline_policy)
    rows, candidate_pre, baseline_pre = _default_v07g_offline_xy_authority_samples()
    offline_gate = derive_v07g_offline_xy_authority_gate(
        rows=rows,
        candidate_pre_xy_authority_actions=candidate_pre,
        baseline_pre_xy_authority_actions=baseline_pre,
        xy_authority_config=xy_config,
    )
    write_json(child_dir / "offline_xy_authority_gate_v0_7g.json", offline_gate)
    parent_report_path = output_dir / V07F_OUTPUT_DIRNAME / "mvp2e_v07f_depth_zero_harness_report.json"
    manifest: dict[str, Any] = {
        "schema_version": V07G_MANIFEST_SCHEMA_VERSION,
        "policy_slice": V07G_POLICY_SLICE_ID,
        "slice_id": V07G_SLICE_ID,
        "parent_policy_slice": V07E_POLICY_SLICE_ID,
        "parent_diagnostic_slice": V07F_POLICY_SLICE_ID,
        "parent_v07f_depth_zero_harness_report_sha256": _sha256_file(parent_report_path),
        "parent_primary_root_cause_class": parent_report["primary_root_cause_class"],
        "final_post_adapter_xy_authority_id": V07G_FINAL_POST_ADAPTER_XY_AUTHORITY_ID,
        "final_post_adapter_xy_authority_config_sha256": xy_config[
            "final_post_adapter_xy_authority_config_sha256"
        ],
        "candidate_policy_artifact_sha256": candidate_policy["policy_artifact_sha256"],
        "baseline_policy_artifact_sha256": baseline_policy["policy_artifact_sha256"],
        "offline_xy_authority_gate_v0_7g": offline_gate,
        "offline_xy_authority_gate_sha256": offline_gate["offline_xy_authority_gate_sha256"],
        "phase_e_candidate_expressibility_unblocked": offline_gate[
            "phase_e_candidate_expressibility_unblocked"
        ],
        "future_ab_ready": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "calibration_opened": False,
        "heldout_21000_21049_accessed": False,
        "artifacts": {
            "xy_authority_config": f"{V07G_CHILD_OUTPUT_DIRNAME}/v0_7g_xy_authority_config.json",
            "candidate_policy_artifact": (
                f"{V07G_CHILD_OUTPUT_DIRNAME}/candidate_policy_artifact_v0_7g.json"
            ),
            "baseline_policy_artifact": (
                f"{V07G_CHILD_OUTPUT_DIRNAME}/baseline_policy_artifact_v0_7g.json"
            ),
            "offline_xy_authority_gate": (
                f"{V07G_CHILD_OUTPUT_DIRNAME}/offline_xy_authority_gate_v0_7g.json"
            ),
        },
    }
    manifest["v0_7g_xy_authority_manifest_sha256"] = _sha256_payload_excluding(
        manifest,
        "v0_7g_xy_authority_manifest_sha256",
    )
    write_json(child_dir / "v0_7g_xy_authority_manifest.json", manifest)
    return manifest


def run_v07g_expressibility_sanity_runtime(
    *,
    output_dir: Path,
    manifest: dict[str, Any] | None = None,
    device: str = DEFAULT_ISAAC_DEVICE,
    headless: bool = True,
    isaac_task: str = DEFAULT_ISAAC_TASK,
    max_steps: int = int(SUCCESS_METRIC["max_steps"]),
    action_scale: float = 1.0,
    backend: Any | None = None,
) -> dict[str, Any]:
    child_dir = output_dir / V07G_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    gate_output_path = child_dir / "expressibility_sanity_gate_v0_7g.json"
    offline_gate_path = child_dir / "offline_xy_authority_gate_v0_7g.json"

    def fail_closed(reason: str, extra: dict[str, Any] | None = None) -> dict[str, Any]:
        gate: dict[str, Any] = {
            "schema_version": V07G_EXPRESSIBILITY_SANITY_GATE_SCHEMA_VERSION,
            "policy_slice": V07G_POLICY_SLICE_ID,
            "slice_id": V07G_SLICE_ID,
            "passed": False,
            "runtime_backend": "isaac_runtime_not_started",
            "proof_runtime": "isaac_candidate_policy_train_split_expressibility_sanity",
            "reason": reason,
            "phase_e_candidate_expressibility_unblocked": False,
            "heldout_opened": False,
            "heldout_21000_21049_accessed": False,
            "calibration_opened": False,
            "proof_authority": False,
            "mvp2_closed": False,
            "policy_uplift_proven": False,
        }
        if extra:
            gate.update(extra)
        write_json(gate_output_path, gate)
        return gate

    if not offline_gate_path.exists():
        return fail_closed("missing_passed_v0_7g_offline_xy_authority_gate")
    offline_gate = read_json(offline_gate_path)
    if (
        offline_gate.get("passed") is not True
        or offline_gate.get("phase_e_candidate_expressibility_unblocked") is not True
    ):
        return fail_closed(
            "missing_passed_v0_7g_offline_xy_authority_gate",
            {"offline_xy_authority_gate_sha256": offline_gate.get("offline_xy_authority_gate_sha256")},
        )
    policy_path = child_dir / "candidate_policy_artifact_v0_7g.json"
    if not policy_path.exists():
        return fail_closed("missing_v0_7g_candidate_policy_artifact")
    policy_artifact = read_json(policy_path)
    xy_config = policy_artifact.get("final_post_adapter_xy_authority_config")
    if policy_artifact.get("policy_slice") != V07G_POLICY_SLICE_ID or not isinstance(xy_config, dict):
        return fail_closed("invalid_v0_7g_candidate_policy_artifact")
    try:
        validate_v07g_xy_authority_config_contract(xy_config)
    except ValueError as exc:
        return fail_closed(str(exc))
    if policy_artifact.get("heldout_21000_21049_accessed") is not False:
        return fail_closed("v0_7g_candidate_policy_artifact_heldout_access_detected")
    if manifest is None:
        return fail_closed("missing_v0_7g_expressibility_manifest")
    train_gate_status = resolve_existing_v06_train_generation_runtime_gate(output_dir=output_dir)
    if train_gate_status.get("reuse_allowed") is not True or not isinstance(train_gate_status.get("gate"), dict):
        return fail_closed(
            str(train_gate_status.get("reason", "missing_passed_v0_6_train_generation_gate")),
            {"offline_xy_authority_gate_sha256": offline_gate.get("offline_xy_authority_gate_sha256")},
        )
    probe_manifest = build_v06_expressibility_sanity_manifest(
        manifest=manifest,
        train_generation_runtime_gate=train_gate_status["gate"],
    )
    write_json(child_dir / "expressibility_sanity_manifest_v0_7g.json", probe_manifest)
    evaluator_backend = backend or IsaacConnectorInsertionEvaluatorBackend(
        task=isaac_task,
        device=device,
        headless=headless,
        action_scale=action_scale,
        max_steps=max_steps,
    )
    probe_result = evaluator_backend.run_single_policy_probe(
        manifest=probe_manifest,
        output_dir=child_dir / "isaac_runtime_expressibility_sanity_v0_7g",
        policy_artifact=policy_artifact,
        role="v0_7g_expressibility_sanity",
        max_rollouts=V06_EXPRESSIBILITY_SANITY_SEED_COUNT,
        stop_after_first_success=False,
    )
    gate = derive_v06_expressibility_sanity_gate_from_probe_result(probe_result)
    gate["schema_version"] = V07G_EXPRESSIBILITY_SANITY_GATE_SCHEMA_VERSION
    gate["policy_slice"] = V07G_POLICY_SLICE_ID
    gate["slice_id"] = V07G_SLICE_ID
    gate["final_post_adapter_xy_authority_id"] = V07G_FINAL_POST_ADAPTER_XY_AUTHORITY_ID
    gate["final_post_adapter_xy_authority_config_sha256"] = xy_config[
        "final_post_adapter_xy_authority_config_sha256"
    ]
    gate["offline_xy_authority_gate_sha256"] = offline_gate["offline_xy_authority_gate_sha256"]
    gate["manifest_sha256"] = probe_manifest["manifest_sha256"]
    gate["phase_e_candidate_expressibility_unblocked"] = gate.get("passed") is True
    gate["future_ab_ready"] = False
    gate["heldout_opened"] = False
    gate["heldout_21000_21049_accessed"] = False
    gate["calibration_opened"] = False
    gate["proof_authority"] = False
    gate["mvp2_closed"] = False
    gate["policy_uplift_proven"] = False
    gate["expressibility_sanity_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "expressibility_sanity_gate_sha256",
    )
    write_json(gate_output_path, gate)
    return gate


def load_required_v07h_parent_expressibility_gate(output_dir: Path) -> dict[str, Any]:
    gate_path = output_dir / V07G_CHILD_OUTPUT_DIRNAME / "expressibility_sanity_gate_v0_7g.json"
    if not gate_path.exists():
        raise ValueError("missing_passed_v0_7g_expressibility_gate")
    gate = read_json(gate_path)
    if (
        gate.get("passed") is not True
        or gate.get("runtime_backend") != "isaac_runtime"
        or gate.get("phase_e_candidate_expressibility_unblocked") is not True
        or gate.get("heldout_21000_21049_accessed") is not False
        or gate.get("calibration_opened") is not False
        or gate.get("mvp2_closed") is not False
        or gate.get("policy_uplift_proven") is not False
    ):
        raise ValueError("missing_passed_v0_7g_expressibility_gate")
    return gate


def build_v07h_calibration_runtime_manifest(*, output_dir: Path, manifest: dict[str, Any]) -> dict[str, Any]:
    child_dir = output_dir / V07H_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    calibration_rows = [
        row
        for row in manifest.get("scenarios", [])
        if isinstance(row, dict) and row.get("split") == "calibration"
    ]
    if len(calibration_rows) != V07H_CALIBRATION_ROLLOUTS_PER_POLICY:
        raise ValueError("v0_7h_calibration_scenario_count_mismatch")
    runtime_rows: list[dict[str, Any]] = []
    protected_access = False
    for row in calibration_rows:
        seed = int(row["seed"])
        protected_access = protected_access or _protected_heldout_seed_range_accessed(seed)
        runtime_row = dict(row)
        runtime_row["split"] = "held_out"
        runtime_row["source_split"] = "calibration"
        runtime_row["semantic_eval_split"] = "calibration"
        runtime_row["calibration_presignal_role"] = "calibration_runtime_backend_compatibility"
        runtime_rows.append(runtime_row)
    if protected_access:
        raise ValueError("v0_7h_calibration_manifest_protected_heldout_access")
    seeds = [int(row["seed"]) for row in runtime_rows]
    runtime_manifest: dict[str, Any] = {
        "schema_version": V07H_CALIBRATION_RUNTIME_MANIFEST_SCHEMA_VERSION,
        "policy_slice": V07H_POLICY_SLICE_ID,
        "slice_id": V07H_SLICE_ID,
        "source_manifest_sha256": manifest.get("manifest_sha256"),
        "scenario_profile": manifest.get("scenario_profile"),
        "task_type": manifest.get("task_type"),
        "success_metric": dict(manifest.get("success_metric") or {}),
        "success_authority": dict(manifest.get("success_authority") or {}),
        "scenarios": runtime_rows,
        "calibration_scenario_ids": [str(row["scenario_id"]) for row in runtime_rows],
        "calibration_seed_range": [min(seeds), max(seeds)],
        "calibration_rollouts_per_policy": V07H_CALIBRATION_ROLLOUTS_PER_POLICY,
        "calibration_opened": True,
        "heldout_opened": False,
        "heldout_21000_21049_accessed": False,
        "semantic_eval_split": "calibration",
        "backend_compatibility_split": "held_out",
        "leakage_policy": {
            "uses_calibration_split_only": True,
            "protected_heldout_21000_21049_excluded": True,
            "heldout_21000_21049_opened": False,
        },
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    runtime_manifest["manifest_sha256"] = _sha256_payload_excluding(
        runtime_manifest,
        "manifest_sha256",
    )
    write_json(child_dir / "calibration_runtime_manifest_v0_7h.json", runtime_manifest)
    return runtime_manifest


def _v07h_rollout_success_rate(rollouts: list[dict[str, Any]]) -> tuple[int, int, float]:
    total = len(rollouts)
    success_count = sum(
        1
        for rollout in rollouts
        if rollout.get("success") is True or rollout.get("env_native_rollout_success") is True
    )
    rate = round(success_count / float(total), 12) if total else 0.0
    return success_count, total, rate


def _v07h_rollouts_access_protected_heldout(rollouts: list[dict[str, Any]]) -> bool:
    for rollout in rollouts:
        seed = rollout.get("seed")
        if seed is not None:
            try:
                if _protected_heldout_seed_range_accessed(int(seed)):
                    return True
            except (TypeError, ValueError):
                return True
        scenario_id = str(rollout.get("scenario_id") or "")
        match = re.search(r"(\d{5})", scenario_id)
        if match and _protected_heldout_seed_range_accessed(int(match.group(1))):
            return True
    return False


def derive_v07h_calibration_presignal_gate(
    *,
    baseline_rollouts: list[dict[str, Any]],
    candidate_rollouts: list[dict[str, Any]],
    runtime_gate: dict[str, Any],
    runtime_metadata: dict[str, Any],
    trace_paths: dict[str, list[str]],
    output_dir: Path,
) -> dict[str, Any]:
    del output_dir
    baseline_success_count, baseline_count, baseline_rate = _v07h_rollout_success_rate(baseline_rollouts)
    candidate_success_count, candidate_count, candidate_rate = _v07h_rollout_success_rate(candidate_rollouts)
    protected_access = _v07h_rollouts_access_protected_heldout(
        list(baseline_rollouts) + list(candidate_rollouts)
    )
    failure_reason = ""
    if protected_access:
        failure_reason = "protected_heldout_seed_accessed"
    elif runtime_gate.get("passed") is not True or runtime_metadata.get("runtime_backend") != "isaac_runtime":
        failure_reason = "calibration_runtime_gate_not_passed"
    elif (
        baseline_count < V07H_CALIBRATION_ROLLOUTS_PER_POLICY
        or candidate_count < V07H_CALIBRATION_ROLLOUTS_PER_POLICY
    ):
        failure_reason = "calibration_rollout_count_below_minimum"
    elif candidate_rate <= baseline_rate:
        failure_reason = "candidate_calibration_not_above_baseline"
    elif candidate_rate < V07H_CALIBRATION_SUCCESS_MINIMUM:
        failure_reason = "candidate_calibration_success_below_minimum"
    passed = failure_reason == ""
    gate: dict[str, Any] = {
        "schema_version": V07H_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
        "policy_slice": V07H_POLICY_SLICE_ID,
        "slice_id": V07H_SLICE_ID,
        "passed": bool(passed),
        "failure_reason": failure_reason,
        "heldout_allowed": bool(passed),
        "runtime_backend": runtime_metadata.get("runtime_backend"),
        "proof_runtime": runtime_gate.get("proof_runtime"),
        "runtime_gate": runtime_gate,
        "runtime_metadata": runtime_metadata,
        "baseline_calibration_success_count": baseline_success_count,
        "candidate_calibration_success_count": candidate_success_count,
        "baseline_calibration_rollout_count": baseline_count,
        "candidate_calibration_rollout_count": candidate_count,
        "calibration_rollouts_per_policy": min(baseline_count, candidate_count),
        "required_calibration_rollouts_per_policy": V07H_CALIBRATION_ROLLOUTS_PER_POLICY,
        "baseline_calibration_success_rate": baseline_rate,
        "candidate_calibration_success_rate": candidate_rate,
        "candidate_calibration_success_minimum": V07H_CALIBRATION_SUCCESS_MINIMUM,
        "curated_vs_uncurated_calibration_uplift": round(candidate_rate - baseline_rate, 12),
        "trace_paths": trace_paths,
        "calibration_opened": True,
        "heldout_opened": False,
        "heldout_21000_21049_accessed": bool(protected_access),
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    gate["calibration_presignal_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "calibration_presignal_gate_sha256",
    )
    return gate


def _write_v07h_calibration_external_rollouts(
    *,
    output_dir: Path,
    baseline_rollouts: list[dict[str, Any]],
    candidate_rollouts: list[dict[str, Any]],
) -> dict[str, str]:
    rollout_dir = output_dir / "calibration_external_rollouts"
    rollout_dir.mkdir(parents=True, exist_ok=True)
    baseline_path = rollout_dir / "baseline_calibration_rollouts_v0_7h.json"
    candidate_path = rollout_dir / "candidate_calibration_rollouts_v0_7h.json"
    write_json(baseline_path, baseline_rollouts)
    write_json(candidate_path, candidate_rollouts)
    return {
        "baseline": str(baseline_path),
        "candidate": str(candidate_path),
    }


def run_v07h_calibration_presignal_runtime(
    *,
    output_dir: Path,
    manifest: dict[str, Any],
    device: str = DEFAULT_ISAAC_DEVICE,
    headless: bool = True,
    isaac_task: str = DEFAULT_ISAAC_TASK,
    max_steps: int = int(SUCCESS_METRIC["max_steps"]),
    action_scale: float = 1.0,
    backend: Any | None = None,
) -> dict[str, Any]:
    child_dir = output_dir / V07H_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    parent_gate = load_required_v07h_parent_expressibility_gate(output_dir)
    v07g_child_dir = output_dir / V07G_CHILD_OUTPUT_DIRNAME
    offline_gate_path = v07g_child_dir / "offline_xy_authority_gate_v0_7g.json"
    if not offline_gate_path.exists():
        raise ValueError("missing_passed_v0_7g_offline_xy_authority_gate")
    offline_gate = read_json(offline_gate_path)
    if offline_gate.get("passed") is not True:
        raise ValueError("missing_passed_v0_7g_offline_xy_authority_gate")
    candidate_policy_path = v07g_child_dir / "candidate_policy_artifact_v0_7g.json"
    baseline_policy_path = v07g_child_dir / "baseline_policy_artifact_v0_7g.json"
    if not candidate_policy_path.exists() or not baseline_policy_path.exists():
        raise ValueError("missing_v0_7g_policy_artifacts")
    candidate_policy = read_json(candidate_policy_path)
    baseline_policy = read_json(baseline_policy_path)
    runtime_manifest = build_v07h_calibration_runtime_manifest(
        output_dir=output_dir,
        manifest=manifest,
    )
    evaluator_backend = backend or IsaacConnectorInsertionEvaluatorBackend(
        task=isaac_task,
        device=device,
        headless=headless,
        action_scale=action_scale,
        max_steps=max_steps,
    )
    backend_result = evaluator_backend.run(
        manifest=runtime_manifest,
        output_dir=child_dir / "isaac_runtime_calibration_presignal_v0_7h",
        min_rollouts_per_policy=V07H_CALIBRATION_ROLLOUTS_PER_POLICY,
        deterministic_profile="candidate_positive",
        policy_artifacts={
            "baseline": baseline_policy,
            "candidate": candidate_policy,
        },
    )
    rollout_paths = _write_v07h_calibration_external_rollouts(
        output_dir=child_dir,
        baseline_rollouts=list(backend_result.baseline_rollouts),
        candidate_rollouts=list(backend_result.candidate_rollouts),
    )
    trace_paths = {
        "baseline": list(backend_result.baseline_trace_paths),
        "candidate": list(backend_result.candidate_trace_paths),
    }
    gate = derive_v07h_calibration_presignal_gate(
        baseline_rollouts=list(backend_result.baseline_rollouts),
        candidate_rollouts=list(backend_result.candidate_rollouts),
        runtime_gate=dict(backend_result.runtime_gate),
        runtime_metadata=dict(backend_result.runtime_metadata),
        trace_paths=trace_paths,
        output_dir=child_dir,
    )
    summary: dict[str, Any] = {
        "schema_version": V07H_CALIBRATION_ROLLOUT_SUMMARY_SCHEMA_VERSION,
        "policy_slice": V07H_POLICY_SLICE_ID,
        "slice_id": V07H_SLICE_ID,
        "runtime_backend": backend_result.runtime_backend,
        "proof_runtime": backend_result.proof_runtime,
        "parent_expressibility_gate_sha256": parent_gate.get("expressibility_sanity_gate_sha256"),
        "offline_xy_authority_gate_sha256": offline_gate.get("offline_xy_authority_gate_sha256"),
        "calibration_runtime_manifest_sha256": runtime_manifest.get("manifest_sha256"),
        "baseline_rollout_path": rollout_paths["baseline"],
        "candidate_rollout_path": rollout_paths["candidate"],
        "baseline_trace_paths": trace_paths["baseline"],
        "candidate_trace_paths": trace_paths["candidate"],
        "baseline_calibration_success_rate": gate["baseline_calibration_success_rate"],
        "candidate_calibration_success_rate": gate["candidate_calibration_success_rate"],
        "passed": gate["passed"],
        "calibration_opened": True,
        "heldout_opened": False,
        "heldout_21000_21049_accessed": gate["heldout_21000_21049_accessed"],
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    summary["calibration_rollout_summary_sha256"] = _sha256_payload_excluding(
        summary,
        "calibration_rollout_summary_sha256",
    )
    write_json(child_dir / "calibration_rollout_summary_v0_7h.json", summary)
    gate["calibration_rollout_summary_sha256"] = summary["calibration_rollout_summary_sha256"]
    gate["calibration_runtime_manifest_sha256"] = runtime_manifest["manifest_sha256"]
    gate["baseline_calibration_rollout_path"] = rollout_paths["baseline"]
    gate["candidate_calibration_rollout_path"] = rollout_paths["candidate"]
    gate["calibration_presignal_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "calibration_presignal_gate_sha256",
    )
    write_json(child_dir / "calibration_presignal_gate_v0_7h.json", gate)
    compatibility_gate = {
        "schema_version": V07H_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
        "policy_slice": V07H_POLICY_SLICE_ID,
        "slice_id": V07H_SLICE_ID,
        "passed": gate["passed"],
        "source_gate_path": f"{V07H_CHILD_OUTPUT_DIRNAME}/calibration_presignal_gate_v0_7h.json",
        "calibration_opened": True,
        "heldout_opened": False,
        "heldout_21000_21049_accessed": gate["heldout_21000_21049_accessed"],
        "heldout_allowed": gate["heldout_allowed"],
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    compatibility_gate["calibration_presignal_gate_sha256"] = _sha256_payload(compatibility_gate)
    write_json(output_dir / "calibration_presignal_gate.json", compatibility_gate)
    return gate


def _v07i_action_vector(row: dict[str, Any]) -> list[float]:
    action = row.get("normalized_action")
    if isinstance(action, list) and len(action) >= 2:
        return [float(value) for value in action]
    diagnostics = row.get("controller_action_diagnostics")
    if isinstance(diagnostics, dict):
        for key in ("post_xy_authority_action_vector", "post_z_pre_xy_authority_action_vector"):
            vector = diagnostics.get(key)
            if isinstance(vector, list) and len(vector) >= 2:
                return [float(value) for value in vector]
    return []


def _v07i_max_consecutive(values: list[bool]) -> int:
    max_run = 0
    current = 0
    for value in values:
        current = current + 1 if value else 0
        max_run = max(max_run, current)
    return max_run


def classify_v07i_calibration_trace(
    payload: dict[str, Any],
    *,
    role: str,
    trace_path: str,
) -> dict[str, Any]:
    trace = [row for row in payload.get("trace", []) if isinstance(row, dict)]
    scenario = payload.get("scenario") if isinstance(payload.get("scenario"), dict) else {}
    summary = payload.get("summary") if isinstance(payload.get("summary"), dict) else {}
    seed = scenario.get("seed")
    if seed is None:
        match = re.search(r"(\d{5})", str(trace_path))
        seed = int(match.group(1)) if match else None
    protected_access = bool(seed is not None and _protected_heldout_seed_range_accessed(int(seed)))
    lateral_values = [float(row.get("lateral_error_m", 0.0) or 0.0) for row in trace]
    depth_values = [float(row.get("insertion_depth_m", 0.0) or 0.0) for row in trace]
    env_native_values = [
        bool(row.get("env_native_success") or row.get("env_native_success_mask")) for row in trace
    ]
    z_motion_values = []
    off_center_xy_saturation_count = 0
    near_center_xy_authority_applied_count = 0
    xy_saturation_threshold = float(V07F_THRESHOLDS["xy_saturation_abs_action_min"])
    xy_near_center_lateral_m = 0.006
    for row in trace:
        action = _v07i_action_vector(row)
        if len(action) >= 3:
            z_motion_values.append(abs(float(action[2])) > 1.0e-8)
            xy_saturated = bool(np.any(np.abs(np.asarray(action[:2], dtype=np.float64)) >= xy_saturation_threshold))
            lateral = float(row.get("lateral_error_m", 0.0) or 0.0)
            if lateral > xy_near_center_lateral_m and xy_saturated:
                off_center_xy_saturation_count += 1
        diagnostics = row.get("controller_action_diagnostics")
        if isinstance(diagnostics, dict) and diagnostics.get("xy_authority_applied") is True:
            lateral = float(row.get("lateral_error_m", 0.0) or 0.0)
            if lateral <= xy_near_center_lateral_m:
                near_center_xy_authority_applied_count += 1
    success = bool(
        summary.get("success") is True
        or summary.get("env_native_rollout_success") is True
        or _v07i_max_consecutive(env_native_values) >= int(V06_ENV_NATIVE_SUCCESS_AUTHORITY["stable_steps_required"])
    )
    initial_lateral = lateral_values[0] if lateral_values else 0.0
    min_lateral = min(lateral_values) if lateral_values else 0.0
    final_lateral = lateral_values[-1] if lateral_values else 0.0
    max_depth = max(depth_values) if depth_values else 0.0
    first_z_motion_step = next((index for index, value in enumerate(z_motion_values) if value), None)
    first_depth_positive_step = next(
        (index for index, value in enumerate(depth_values) if value > 1.0e-6),
        None,
    )
    first_env_native_success_step = next(
        (index for index, value in enumerate(env_native_values) if value),
        None,
    )
    env_native_max_consecutive = _v07i_max_consecutive(env_native_values)
    max_consecutive_z_motion = _v07i_max_consecutive(z_motion_values)
    if success:
        failure_class = "SUCCESS"
    elif (
        max_depth < 1.0e-5
        and off_center_xy_saturation_count > 0
        and initial_lateral > xy_near_center_lateral_m
    ):
        failure_class = "OFF_CENTER_XY_AUTHORITY_GAP_DEPTH_ZERO"
    elif (
        first_env_native_success_step is not None
        and env_native_max_consecutive < int(V06_ENV_NATIVE_SUCCESS_AUTHORITY["stable_steps_required"])
    ):
        failure_class = "UNDER_INSERTION_LATE_SEAT_WINDOW"
    elif max_depth >= 0.015:
        failure_class = "PARTIAL_INSERTION_NO_STABILITY"
    elif final_lateral > max(min_lateral + 0.003, xy_near_center_lateral_m):
        failure_class = "LATERAL_DRIFT_OR_RIM_EJECT"
    else:
        failure_class = "UNCLASSIFIED_CALIBRATION_FAILURE"
    return {
        "schema_version": V07I_TRACE_CLASSIFICATION_SCHEMA_VERSION,
        "role": role,
        "trace_path": trace_path,
        "scenario_id": scenario.get("scenario_id"),
        "seed": seed,
        "success": success,
        "failure_class": failure_class,
        "failure_reason": summary.get("failure_reason", ""),
        "initial_lateral_error_m": round(initial_lateral, 12),
        "min_lateral_error_m": round(min_lateral, 12),
        "final_lateral_error_m": round(final_lateral, 12),
        "max_insertion_depth_m": round(max_depth, 12),
        "first_z_motion_step": first_z_motion_step,
        "first_depth_positive_step": first_depth_positive_step,
        "first_env_native_success_step": first_env_native_success_step,
        "env_native_max_consecutive_success_steps": env_native_max_consecutive,
        "max_consecutive_z_motion_steps": max_consecutive_z_motion,
        "off_center_xy_saturation_count": off_center_xy_saturation_count,
        "near_center_xy_authority_applied_count": near_center_xy_authority_applied_count,
        "xy_near_center_lateral_m": xy_near_center_lateral_m,
        "xy_saturation_threshold_abs": xy_saturation_threshold,
        "heldout_21000_21049_accessed": protected_access,
    }


def _v07i_trace_paths_from_gate_or_disk(output_dir: Path, gate: dict[str, Any]) -> dict[str, list[str]]:
    trace_paths = gate.get("trace_paths") if isinstance(gate.get("trace_paths"), dict) else {}
    baseline_paths = list(trace_paths.get("baseline") or [])
    candidate_paths = list(trace_paths.get("candidate") or [])
    if baseline_paths and candidate_paths:
        return {"baseline": baseline_paths, "candidate": candidate_paths}
    trace_dir = (
        output_dir
        / V07H_CHILD_OUTPUT_DIRNAME
        / "isaac_runtime_calibration_presignal_v0_7h"
        / "isaac_runtime_heldout_rollout_traces"
    )
    return {
        "baseline": [str(path) for path in sorted(trace_dir.glob("baseline_*_calibration_*_isaac_trace.json"))],
        "candidate": [str(path) for path in sorted(trace_dir.glob("candidate_*_calibration_*_isaac_trace.json"))],
    }


def build_v07i_calibration_failure_diagnosis(*, output_dir: Path) -> dict[str, Any]:
    child_dir = output_dir / V07I_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    gate_path = output_dir / V07H_CHILD_OUTPUT_DIRNAME / "calibration_presignal_gate_v0_7h.json"
    if not gate_path.exists():
        raise ValueError("missing_v0_7h_calibration_presignal_gate")
    gate = read_json(gate_path)
    trace_paths_by_role = _v07i_trace_paths_from_gate_or_disk(output_dir, gate)
    classifications: list[dict[str, Any]] = []
    for role, paths in trace_paths_by_role.items():
        for path_text in paths:
            path = Path(path_text)
            payload = read_json(path)
            classifications.append(
                classify_v07i_calibration_trace(payload, role=role, trace_path=str(path))
            )
    protected_access = bool(gate.get("heldout_21000_21049_accessed")) or any(
        item.get("heldout_21000_21049_accessed") is True for item in classifications
    )
    candidate_classes = [
        item["failure_class"] for item in classifications if item.get("role") == "candidate"
    ]
    baseline_classes = [item["failure_class"] for item in classifications if item.get("role") == "baseline"]
    candidate_counts = Counter(candidate_classes)
    baseline_counts = Counter(baseline_classes)
    candidate_failures = sum(count for key, count in candidate_counts.items() if key != "SUCCESS")
    dominant_failure_count = (
        candidate_counts.get("OFF_CENTER_XY_AUTHORITY_GAP_DEPTH_ZERO", 0)
        + candidate_counts.get("UNDER_INSERTION_LATE_SEAT_WINDOW", 0)
    )
    off_center_saturation_total = sum(
        int(item.get("off_center_xy_saturation_count", 0))
        for item in classifications
        if item.get("role") == "candidate"
    )
    near_center_authority_total = sum(
        int(item.get("near_center_xy_authority_applied_count", 0))
        for item in classifications
        if item.get("role") == "candidate"
    )
    diagnosis_confident = (
        gate.get("passed") is False
        and gate.get("failure_reason") == "candidate_calibration_success_below_minimum"
        and gate.get("runtime_backend") == "isaac_runtime"
        and not protected_access
        and candidate_failures > 0
        and dominant_failure_count >= max(1, int(math.ceil(candidate_failures * 0.5)))
        and off_center_saturation_total > 0
        and near_center_authority_total > 0
    )
    report: dict[str, Any] = {
        "schema_version": V07I_DIAGNOSIS_SCHEMA_VERSION,
        "policy_slice": V07I_POLICY_SLICE_ID,
        "slice_id": V07I_SLICE_ID,
        "parent_slice_id": V07H_SLICE_ID,
        "parent_calibration_presignal_gate_sha256": _sha256_file(gate_path),
        "parent_gate_passed": gate.get("passed"),
        "parent_failure_reason": gate.get("failure_reason"),
        "runtime_backend": gate.get("runtime_backend"),
        "baseline_calibration_success_rate": gate.get("baseline_calibration_success_rate"),
        "candidate_calibration_success_rate": gate.get("candidate_calibration_success_rate"),
        "baseline_calibration_success_count": gate.get("baseline_calibration_success_count"),
        "candidate_calibration_success_count": gate.get("candidate_calibration_success_count"),
        "baseline_failure_class_counts": dict(sorted(baseline_counts.items())),
        "candidate_failure_class_counts": dict(sorted(candidate_counts.items())),
        "candidate_failure_count": candidate_failures,
        "candidate_dominant_failure_count": dominant_failure_count,
        "candidate_off_center_xy_saturation_count": off_center_saturation_total,
        "candidate_near_center_xy_authority_applied_count": near_center_authority_total,
        "primary_root_cause_class": (
            "OFF_CENTER_XY_AUTHORITY_GAP_AND_LATE_ALIGNMENT"
            if diagnosis_confident
            else "UNRESOLVED_CALIBRATION_FAILURE"
        ),
        "diagnosis_confident": bool(diagnosis_confident),
        "recommended_downstream_slice": (
            "v0_7j_off_center_xy_authority_repair" if diagnosis_confident else None
        ),
        "calibration_opened": True,
        "heldout_opened": False,
        "heldout_21000_21049_accessed": protected_access,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    report["calibration_failure_diagnosis_sha256"] = _sha256_payload_excluding(
        report,
        "calibration_failure_diagnosis_sha256",
    )
    classification_artifact = {
        "schema_version": V07I_TRACE_CLASSIFICATION_SCHEMA_VERSION,
        "policy_slice": V07I_POLICY_SLICE_ID,
        "slice_id": V07I_SLICE_ID,
        "classifications": classifications,
        "heldout_21000_21049_accessed": protected_access,
    }
    classification_artifact["calibration_trace_classification_sha256"] = _sha256_payload_excluding(
        classification_artifact,
        "calibration_trace_classification_sha256",
    )
    write_json(child_dir / "calibration_trace_classification_v0_7i.json", classification_artifact)
    write_json(child_dir / "calibration_failure_diagnosis_v0_7i.json", report)
    return report


def load_required_v07j_parent_diagnosis(output_dir: Path) -> dict[str, Any]:
    report_path = output_dir / V07I_CHILD_OUTPUT_DIRNAME / "calibration_failure_diagnosis_v0_7i.json"
    if not report_path.exists():
        raise ValueError("missing_confident_v0_7i_calibration_failure_diagnosis")
    report = read_json(report_path)
    if (
        report.get("diagnosis_confident") is not True
        or report.get("recommended_downstream_slice") != "v0_7j_off_center_xy_authority_repair"
        or report.get("heldout_21000_21049_accessed") is not False
        or report.get("mvp2_closed") is not False
        or report.get("policy_uplift_proven") is not False
    ):
        raise ValueError("missing_confident_v0_7i_calibration_failure_diagnosis")
    return report


