def build_v07j_policy_artifact_payload(
    *,
    base_policy_artifact: dict[str, Any],
    xy_authority_config: dict[str, Any],
    dataset_view_role: str,
) -> dict[str, Any]:
    if base_policy_artifact.get("policy_slice") != V07G_POLICY_SLICE_ID:
        raise ValueError("v0_7j_parent_policy_slice_mismatch")
    payload = dict(base_policy_artifact)
    payload.update(
        {
            "policy_artifact_schema_version": V07J_POLICY_ARTIFACT_SCHEMA_VERSION,
            "policy_id": f"{dataset_view_role}_{V07J_SLICE_ID}_policy",
            "policy_slice": V07J_POLICY_SLICE_ID,
            "slice_id": V07J_SLICE_ID,
            "parent_policy_slice": V07G_POLICY_SLICE_ID,
            "dataset_view_role": dataset_view_role,
            "parent_xy_authority_config_sha256": xy_authority_config[
                "parent_xy_authority_config_sha256"
            ],
            "final_post_adapter_xy_authority_id": xy_authority_config[
                "final_post_adapter_xy_authority_id"
            ],
            "final_post_adapter_xy_authority_config": dict(xy_authority_config),
            "final_post_adapter_xy_authority_config_sha256": xy_authority_config[
                "final_post_adapter_xy_authority_config_sha256"
            ],
            "same_xy_authority_config_as_peer": True,
            "stable_hold_authority": "env_native_success_mask",
            "heldout_21000_21049_accessed": False,
            "calibration_opened": True,
            "future_ab_ready": False,
            "proof_authority": False,
            "mvp2_closed": False,
            "policy_uplift_proven": False,
        }
    )
    payload["policy_artifact_sha256"] = _sha256_payload_excluding(payload, "policy_artifact_sha256")
    return payload


def derive_v07j_offline_xy_authority_gate(
    *,
    xy_authority_config: dict[str, Any],
) -> dict[str, Any]:
    rows = [
        {"seed": 20000, "lateral_error_m": 0.018, "relative_x_m": 0.003, "relative_y_m": -0.017},
        {"seed": 20001, "lateral_error_m": 0.017, "relative_x_m": -0.008, "relative_y_m": -0.018},
        {"seed": 20002, "lateral_error_m": 0.0007, "relative_x_m": -0.0005, "relative_y_m": 0.0005},
    ]
    candidate_pre = [
        [-0.05, 0.05, -0.032, 0.0, 0.0, 0.0, 1.0],
        [0.05, 0.05, -0.032, 0.0, 0.0, 0.0, 1.0],
        [0.05, -0.05, -0.032, 0.0, 0.0, 0.0, 1.0],
    ]
    baseline_pre = [
        [-0.04, 0.04, -0.032, 0.0, 0.0, 0.0, 1.0],
        [0.04, 0.04, -0.032, 0.0, 0.0, 0.0, 1.0],
        [0.02, -0.02, -0.032, 0.0, 0.0, 0.0, 1.0],
    ]
    candidate_post: list[list[float]] = []
    baseline_post: list[list[float]] = []
    applied_reasons: list[str] = []
    z_preserved = True
    protected_access = False
    for row, candidate_action, baseline_action in zip(rows, candidate_pre, baseline_pre, strict=True):
        protected_access = protected_access or _protected_heldout_seed_range_accessed(int(row["seed"]))
        candidate_after, candidate_diag = _apply_v07g_final_post_adapter_xy_authority(
            action=np.asarray(candidate_action, dtype=np.float64),
            metric_row=row,
            xy_authority_config=xy_authority_config,
        )
        baseline_after, baseline_diag = _apply_v07g_final_post_adapter_xy_authority(
            action=np.asarray(baseline_action, dtype=np.float64),
            metric_row=row,
            xy_authority_config=xy_authority_config,
        )
        applied_reasons.append(str(candidate_diag.get("xy_authority_reason")))
        applied_reasons.append(str(baseline_diag.get("xy_authority_reason")))
        candidate_post.append(_rounded_action(candidate_after))
        baseline_post.append(_rounded_action(baseline_after))
        z_preserved = z_preserved and bool(np.isclose(candidate_after[2], candidate_action[2]))
        z_preserved = z_preserved and bool(np.isclose(baseline_after[2], baseline_action[2]))
    pre_delta, _pre_nonzero = _xy_delta_stats(candidate_pre, baseline_pre)
    post_delta, post_nonzero_fraction = _xy_delta_stats(candidate_post, baseline_post)
    retention_ratio = post_delta / pre_delta if pre_delta > V07G_XY_ATTRIBUTION_DELTA_EPS else 0.0
    off_center_applied = "xy_saturation_off_center_state_feedback_clamped" in applied_reasons
    near_center_applied = "xy_saturation_near_center_clamped_to_state_feedback" in applied_reasons
    failure_reason = ""
    if protected_access:
        failure_reason = "protected_heldout_seed_accessed"
    elif not off_center_applied:
        failure_reason = "off_center_xy_authority_not_applied"
    elif not near_center_applied:
        failure_reason = "near_center_xy_authority_not_applied"
    elif not z_preserved:
        failure_reason = "xy_authority_mutated_z_authority"
    elif retention_ratio < V07G_XY_ATTRIBUTION_RETENTION_RATIO_MIN:
        failure_reason = "candidate_baseline_xy_delta_retention_too_low"
    elif post_nonzero_fraction < V07G_XY_ATTRIBUTION_NONZERO_FRACTION_MIN:
        failure_reason = "candidate_baseline_post_xy_delta_sparse"
    gate = {
        "schema_version": V07J_OFFLINE_XY_AUTHORITY_GATE_SCHEMA_VERSION,
        "policy_slice": V07J_POLICY_SLICE_ID,
        "slice_id": V07J_SLICE_ID,
        "final_post_adapter_xy_authority_id": xy_authority_config[
            "final_post_adapter_xy_authority_id"
        ],
        "final_post_adapter_xy_authority_config_sha256": xy_authority_config[
            "final_post_adapter_xy_authority_config_sha256"
        ],
        "passed": failure_reason == "",
        "failure_reason": failure_reason,
        "off_center_xy_authority_applied": off_center_applied,
        "near_center_xy_authority_applied": near_center_applied,
        "pre_xy_authority_candidate_baseline_xy_delta_l2_mean": round(pre_delta, 12),
        "post_xy_authority_candidate_baseline_xy_delta_l2_mean": round(post_delta, 12),
        "post_xy_authority_candidate_baseline_xy_delta_nonzero_fraction": round(
            post_nonzero_fraction,
            12,
        ),
        "xy_delta_retention_ratio": round(retention_ratio, 12),
        "z_authority_preserved": z_preserved,
        "heldout_21000_21049_accessed": protected_access,
        "calibration_opened": True,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    gate["offline_xy_authority_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "offline_xy_authority_gate_sha256",
    )
    return gate


def build_v07j_off_center_xy_authority_repair_slice(*, output_dir: Path) -> dict[str, Any]:
    parent_diagnosis = load_required_v07j_parent_diagnosis(output_dir)
    child_dir = output_dir / V07J_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    v07g_child_dir = output_dir / V07G_CHILD_OUTPUT_DIRNAME
    candidate_parent_path = v07g_child_dir / "candidate_policy_artifact_v0_7g.json"
    baseline_parent_path = v07g_child_dir / "baseline_policy_artifact_v0_7g.json"
    if not candidate_parent_path.exists() or not baseline_parent_path.exists():
        raise ValueError("missing_v0_7g_parent_policy_artifacts")
    candidate_parent = read_json(candidate_parent_path)
    baseline_parent = read_json(baseline_parent_path)
    xy_config = build_v07j_off_center_xy_authority_config(
        output_dir=child_dir,
        parent_policy_artifact=candidate_parent,
    )
    candidate_policy = build_v07j_policy_artifact_payload(
        base_policy_artifact=candidate_parent,
        xy_authority_config=xy_config,
        dataset_view_role="candidate_curated",
    )
    baseline_policy = build_v07j_policy_artifact_payload(
        base_policy_artifact=baseline_parent,
        xy_authority_config=xy_config,
        dataset_view_role="baseline_uncurated",
    )
    write_json(child_dir / "candidate_policy_artifact_v0_7j.json", candidate_policy)
    write_json(child_dir / "baseline_policy_artifact_v0_7j.json", baseline_policy)
    offline_gate = derive_v07j_offline_xy_authority_gate(xy_authority_config=xy_config)
    write_json(child_dir / "offline_xy_authority_gate_v0_7j.json", offline_gate)
    manifest = {
        "schema_version": V07J_MANIFEST_SCHEMA_VERSION,
        "policy_slice": V07J_POLICY_SLICE_ID,
        "slice_id": V07J_SLICE_ID,
        "parent_policy_slice": V07G_POLICY_SLICE_ID,
        "parent_diagnostic_slice": V07I_SLICE_ID,
        "parent_calibration_failure_diagnosis_sha256": parent_diagnosis[
            "calibration_failure_diagnosis_sha256"
        ],
        "parent_primary_root_cause_class": parent_diagnosis["primary_root_cause_class"],
        "final_post_adapter_xy_authority_id": V07J_FINAL_POST_ADAPTER_XY_AUTHORITY_ID,
        "final_post_adapter_xy_authority_config_sha256": xy_config[
            "final_post_adapter_xy_authority_config_sha256"
        ],
        "candidate_policy_artifact_sha256": candidate_policy["policy_artifact_sha256"],
        "baseline_policy_artifact_sha256": baseline_policy["policy_artifact_sha256"],
        "offline_xy_authority_gate_v0_7j": offline_gate,
        "offline_xy_authority_gate_sha256": offline_gate["offline_xy_authority_gate_sha256"],
        "future_ab_ready": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "calibration_opened": True,
        "heldout_21000_21049_accessed": False,
        "artifacts": {
            "xy_authority_config": f"{V07J_CHILD_OUTPUT_DIRNAME}/v0_7j_xy_authority_config.json",
            "candidate_policy_artifact": (
                f"{V07J_CHILD_OUTPUT_DIRNAME}/candidate_policy_artifact_v0_7j.json"
            ),
            "baseline_policy_artifact": (
                f"{V07J_CHILD_OUTPUT_DIRNAME}/baseline_policy_artifact_v0_7j.json"
            ),
            "offline_xy_authority_gate": (
                f"{V07J_CHILD_OUTPUT_DIRNAME}/offline_xy_authority_gate_v0_7j.json"
            ),
        },
    }
    manifest["v0_7j_xy_authority_manifest_sha256"] = _sha256_payload_excluding(
        manifest,
        "v0_7j_xy_authority_manifest_sha256",
    )
    write_json(child_dir / "v0_7j_xy_authority_manifest.json", manifest)
    return manifest


def run_v07j_calibration_presignal_runtime(
    *,
    output_dir: Path,
    manifest: dict[str, Any],
    device: str = DEFAULT_ISAAC_DEVICE,
    headless: bool = True,
    isaac_task: str = DEFAULT_ISAAC_TASK,
    max_steps: int = int(SUCCESS_METRIC["max_steps"]),
    action_scale: float = 1.0,
    backend: Any | None = None,
) -> dict[str, Any]:
    child_dir = output_dir / V07J_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    if not (child_dir / "offline_xy_authority_gate_v0_7j.json").exists():
        build_v07j_off_center_xy_authority_repair_slice(output_dir=output_dir)
    offline_gate = read_json(child_dir / "offline_xy_authority_gate_v0_7j.json")
    if offline_gate.get("passed") is not True:
        raise ValueError("missing_passed_v0_7j_offline_xy_authority_gate")
    candidate_policy_path = child_dir / "candidate_policy_artifact_v0_7j.json"
    baseline_policy_path = child_dir / "baseline_policy_artifact_v0_7j.json"
    if not candidate_policy_path.exists() or not baseline_policy_path.exists():
        raise ValueError("missing_v0_7j_policy_artifacts")
    candidate_policy = read_json(candidate_policy_path)
    baseline_policy = read_json(baseline_policy_path)
    runtime_manifest = build_v07h_calibration_runtime_manifest(
        output_dir=output_dir,
        manifest=manifest,
    )
    runtime_manifest["policy_slice"] = V07J_POLICY_SLICE_ID
    runtime_manifest["slice_id"] = V07J_SLICE_ID
    runtime_manifest["manifest_sha256"] = _sha256_payload_excluding(
        runtime_manifest,
        "manifest_sha256",
    )
    write_json(child_dir / "calibration_runtime_manifest_v0_7j.json", runtime_manifest)
    evaluator_backend = backend or IsaacConnectorInsertionEvaluatorBackend(
        task=isaac_task,
        device=device,
        headless=headless,
        action_scale=action_scale,
        max_steps=max_steps,
    )
    backend_result = evaluator_backend.run(
        manifest=runtime_manifest,
        output_dir=child_dir / "isaac_runtime_calibration_presignal_v0_7j",
        min_rollouts_per_policy=V07H_CALIBRATION_ROLLOUTS_PER_POLICY,
        deterministic_profile="candidate_positive",
        policy_artifacts={
            "baseline": baseline_policy,
            "candidate": candidate_policy,
        },
    )
    rollout_paths = _write_v07h_calibration_external_rollouts(
        output_dir=child_dir,
        baseline_rollouts=list(backend_result.baseline_rollouts),
        candidate_rollouts=list(backend_result.candidate_rollouts),
    )
    trace_paths = {
        "baseline": list(backend_result.baseline_trace_paths),
        "candidate": list(backend_result.candidate_trace_paths),
    }
    gate = derive_v07h_calibration_presignal_gate(
        baseline_rollouts=list(backend_result.baseline_rollouts),
        candidate_rollouts=list(backend_result.candidate_rollouts),
        runtime_gate=dict(backend_result.runtime_gate),
        runtime_metadata=dict(backend_result.runtime_metadata),
        trace_paths=trace_paths,
        output_dir=child_dir,
    )
    gate.update(
        {
            "schema_version": V07J_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
            "policy_slice": V07J_POLICY_SLICE_ID,
            "slice_id": V07J_SLICE_ID,
            "offline_xy_authority_gate_sha256": offline_gate["offline_xy_authority_gate_sha256"],
            "calibration_runtime_manifest_sha256": runtime_manifest["manifest_sha256"],
            "baseline_calibration_rollout_path": rollout_paths["baseline"],
            "candidate_calibration_rollout_path": rollout_paths["candidate"],
        }
    )
    gate["calibration_presignal_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "calibration_presignal_gate_sha256",
    )
    summary = {
        "schema_version": V07H_CALIBRATION_ROLLOUT_SUMMARY_SCHEMA_VERSION,
        "policy_slice": V07J_POLICY_SLICE_ID,
        "slice_id": V07J_SLICE_ID,
        "runtime_backend": backend_result.runtime_backend,
        "proof_runtime": backend_result.proof_runtime,
        "calibration_runtime_manifest_sha256": runtime_manifest["manifest_sha256"],
        "baseline_rollout_path": rollout_paths["baseline"],
        "candidate_rollout_path": rollout_paths["candidate"],
        "baseline_trace_paths": trace_paths["baseline"],
        "candidate_trace_paths": trace_paths["candidate"],
        "baseline_calibration_success_rate": gate["baseline_calibration_success_rate"],
        "candidate_calibration_success_rate": gate["candidate_calibration_success_rate"],
        "passed": gate["passed"],
        "calibration_opened": True,
        "heldout_opened": False,
        "heldout_21000_21049_accessed": gate["heldout_21000_21049_accessed"],
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    summary["calibration_rollout_summary_sha256"] = _sha256_payload_excluding(
        summary,
        "calibration_rollout_summary_sha256",
    )
    write_json(child_dir / "calibration_rollout_summary_v0_7j.json", summary)
    write_json(child_dir / "calibration_presignal_gate_v0_7j.json", gate)
    compatibility_gate = {
        "schema_version": V07J_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
        "policy_slice": V07J_POLICY_SLICE_ID,
        "slice_id": V07J_SLICE_ID,
        "passed": gate["passed"],
        "source_gate_path": f"{V07J_CHILD_OUTPUT_DIRNAME}/calibration_presignal_gate_v0_7j.json",
        "calibration_opened": True,
        "heldout_opened": False,
        "heldout_21000_21049_accessed": gate["heldout_21000_21049_accessed"],
        "heldout_allowed": gate["heldout_allowed"],
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    compatibility_gate["calibration_presignal_gate_sha256"] = _sha256_payload(compatibility_gate)
    write_json(output_dir / "calibration_presignal_gate.json", compatibility_gate)
    return gate


def load_required_v07k_parent_calibration_failure(output_dir: Path) -> dict[str, Any]:
    gate_path = output_dir / V07J_CHILD_OUTPUT_DIRNAME / "calibration_presignal_gate_v0_7j.json"
    if not gate_path.exists():
        raise ValueError("missing_failed_v0_7j_calibration_presignal_gate")
    gate = read_json(gate_path)
    if (
        gate.get("policy_slice") != V07J_POLICY_SLICE_ID
        or gate.get("runtime_backend") != "isaac_runtime"
        or gate.get("passed") is not False
        or gate.get("heldout_21000_21049_accessed") is not False
        or gate.get("heldout_opened") is not False
        or gate.get("mvp2_closed") is not False
        or gate.get("policy_uplift_proven") is not False
    ):
        raise ValueError("missing_failed_v0_7j_calibration_presignal_gate")
    return gate


def build_v07k_policy_artifact_payload(
    *,
    base_policy_artifact: dict[str, Any],
    parent_gate: dict[str, Any],
    dataset_view_role: str,
) -> dict[str, Any]:
    if base_policy_artifact.get("policy_slice") != V07J_POLICY_SLICE_ID:
        raise ValueError("v0_7k_parent_policy_slice_mismatch")
    payload = dict(base_policy_artifact)
    payload.update(
        {
            "policy_artifact_schema_version": V07K_POLICY_ARTIFACT_SCHEMA_VERSION,
            "policy_id": f"{dataset_view_role}_{V07K_SLICE_ID}_policy",
            "policy_slice": V07K_POLICY_SLICE_ID,
            "slice_id": V07K_SLICE_ID,
            "parent_policy_slice": V07J_POLICY_SLICE_ID,
            "dataset_view_role": dataset_view_role,
            "runtime_hysteresis_wiring_repair_id": V07K_RUNTIME_HYSTERESIS_WIRING_REPAIR_ID,
            "runtime_hysteresis_wiring_repair": {
                "adds_policy_slice_to_stateful_hysteresis_path": True,
                "adds_policy_slice_to_residual_base_servo_path": True,
                "adds_policy_slice_to_pre_adapter_authority_path": True,
                "success_metric_changed": False,
                "trainer_changed": False,
                "final_xy_authority_changed": False,
            },
            "parent_v0_7j_calibration_presignal_gate_sha256": parent_gate[
                "calibration_presignal_gate_sha256"
            ],
            "heldout_21000_21049_accessed": False,
            "calibration_opened": True,
            "future_ab_ready": False,
            "proof_authority": False,
            "mvp2_closed": False,
            "policy_uplift_proven": False,
        }
    )
    payload["policy_artifact_sha256"] = _sha256_payload_excluding(payload, "policy_artifact_sha256")
    return payload


def derive_v07k_runtime_wiring_gate(
    *,
    candidate_policy: dict[str, Any],
    baseline_policy: dict[str, Any],
    parent_gate: dict[str, Any],
) -> dict[str, Any]:
    failure_reason = ""
    same_shared_hysteresis = (
        candidate_policy.get("shared_hysteresis_authority_config_sha256")
        == baseline_policy.get("shared_hysteresis_authority_config_sha256")
    )
    same_final_z = (
        candidate_policy.get("final_post_adapter_authority_config_sha256")
        == baseline_policy.get("final_post_adapter_authority_config_sha256")
    )
    same_final_xy = (
        candidate_policy.get("final_post_adapter_xy_authority_config_sha256")
        == baseline_policy.get("final_post_adapter_xy_authority_config_sha256")
    )
    same_base_servo = candidate_policy.get("base_servo_config_sha256") == baseline_policy.get(
        "base_servo_config_sha256"
    )
    if parent_gate.get("heldout_21000_21049_accessed") is not False:
        failure_reason = "parent_heldout_accessed"
    elif parent_gate.get("passed") is not False:
        failure_reason = "parent_v0_7j_calibration_not_failed_closed"
    elif candidate_policy.get("policy_slice") != V07K_POLICY_SLICE_ID or baseline_policy.get(
        "policy_slice"
    ) != V07K_POLICY_SLICE_ID:
        failure_reason = "child_policy_slice_mismatch"
    elif candidate_policy.get("runtime_hysteresis_wiring_repair_id") != V07K_RUNTIME_HYSTERESIS_WIRING_REPAIR_ID:
        failure_reason = "missing_runtime_hysteresis_wiring_repair_id"
    elif not same_shared_hysteresis:
        failure_reason = "candidate_baseline_hysteresis_config_mismatch"
    elif not same_final_z:
        failure_reason = "candidate_baseline_final_z_authority_mismatch"
    elif not same_final_xy:
        failure_reason = "candidate_baseline_final_xy_authority_mismatch"
    elif not same_base_servo:
        failure_reason = "candidate_baseline_base_servo_mismatch"
    elif candidate_policy.get("heldout_21000_21049_accessed") is not False or baseline_policy.get(
        "heldout_21000_21049_accessed"
    ) is not False:
        failure_reason = "protected_heldout_seed_accessed"
    gate = {
        "schema_version": V07K_RUNTIME_WIRING_GATE_SCHEMA_VERSION,
        "policy_slice": V07K_POLICY_SLICE_ID,
        "slice_id": V07K_SLICE_ID,
        "runtime_hysteresis_wiring_repair_id": V07K_RUNTIME_HYSTERESIS_WIRING_REPAIR_ID,
        "passed": failure_reason == "",
        "failure_reason": failure_reason,
        "parent_policy_slice": V07J_POLICY_SLICE_ID,
        "parent_v0_7j_calibration_presignal_gate_sha256": parent_gate[
            "calibration_presignal_gate_sha256"
        ],
        "same_shared_hysteresis_config_as_peer": same_shared_hysteresis,
        "same_final_z_authority_config_as_peer": same_final_z,
        "same_final_xy_authority_config_as_peer": same_final_xy,
        "same_base_servo_config_as_peer": same_base_servo,
        "success_metric_changed": False,
        "trainer_changed": False,
        "final_xy_authority_changed": False,
        "calibration_opened": True,
        "heldout_opened": False,
        "heldout_21000_21049_accessed": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    gate["runtime_wiring_gate_sha256"] = _sha256_payload_excluding(gate, "runtime_wiring_gate_sha256")
    return gate


def build_v07k_runtime_hysteresis_wiring_repair_slice(*, output_dir: Path) -> dict[str, Any]:
    parent_gate = load_required_v07k_parent_calibration_failure(output_dir)
    child_dir = output_dir / V07K_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    v07j_child_dir = output_dir / V07J_CHILD_OUTPUT_DIRNAME
    candidate_parent_path = v07j_child_dir / "candidate_policy_artifact_v0_7j.json"
    baseline_parent_path = v07j_child_dir / "baseline_policy_artifact_v0_7j.json"
    if not candidate_parent_path.exists() or not baseline_parent_path.exists():
        raise ValueError("missing_v0_7j_parent_policy_artifacts")
    candidate_policy = build_v07k_policy_artifact_payload(
        base_policy_artifact=read_json(candidate_parent_path),
        parent_gate=parent_gate,
        dataset_view_role="candidate_curated",
    )
    baseline_policy = build_v07k_policy_artifact_payload(
        base_policy_artifact=read_json(baseline_parent_path),
        parent_gate=parent_gate,
        dataset_view_role="baseline_uncurated",
    )
    write_json(child_dir / "candidate_policy_artifact_v0_7k.json", candidate_policy)
    write_json(child_dir / "baseline_policy_artifact_v0_7k.json", baseline_policy)
    gate = derive_v07k_runtime_wiring_gate(
        candidate_policy=candidate_policy,
        baseline_policy=baseline_policy,
        parent_gate=parent_gate,
    )
    write_json(child_dir / "runtime_wiring_gate_v0_7k.json", gate)
    manifest = {
        "schema_version": V07K_MANIFEST_SCHEMA_VERSION,
        "policy_slice": V07K_POLICY_SLICE_ID,
        "slice_id": V07K_SLICE_ID,
        "parent_policy_slice": V07J_POLICY_SLICE_ID,
        "parent_v0_7j_calibration_presignal_gate_sha256": parent_gate[
            "calibration_presignal_gate_sha256"
        ],
        "runtime_hysteresis_wiring_repair_id": V07K_RUNTIME_HYSTERESIS_WIRING_REPAIR_ID,
        "candidate_policy_artifact_sha256": candidate_policy["policy_artifact_sha256"],
        "baseline_policy_artifact_sha256": baseline_policy["policy_artifact_sha256"],
        "runtime_wiring_gate_sha256": gate["runtime_wiring_gate_sha256"],
        "runtime_wiring_gate_v0_7k": gate,
        "future_ab_ready": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "calibration_opened": True,
        "heldout_21000_21049_accessed": False,
        "artifacts": {
            "candidate_policy_artifact": (
                f"{V07K_CHILD_OUTPUT_DIRNAME}/candidate_policy_artifact_v0_7k.json"
            ),
            "baseline_policy_artifact": (
                f"{V07K_CHILD_OUTPUT_DIRNAME}/baseline_policy_artifact_v0_7k.json"
            ),
            "runtime_wiring_gate": f"{V07K_CHILD_OUTPUT_DIRNAME}/runtime_wiring_gate_v0_7k.json",
        },
    }
    manifest["v0_7k_runtime_hysteresis_wiring_manifest_sha256"] = _sha256_payload_excluding(
        manifest,
        "v0_7k_runtime_hysteresis_wiring_manifest_sha256",
    )
    write_json(child_dir / "v0_7k_runtime_hysteresis_wiring_manifest.json", manifest)
    return manifest


def run_v07k_calibration_presignal_runtime(
    *,
    output_dir: Path,
    manifest: dict[str, Any],
    device: str = DEFAULT_ISAAC_DEVICE,
    headless: bool = True,
    isaac_task: str = DEFAULT_ISAAC_TASK,
    max_steps: int = int(SUCCESS_METRIC["max_steps"]),
    action_scale: float = 1.0,
    backend: Any | None = None,
) -> dict[str, Any]:
    child_dir = output_dir / V07K_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    if not (child_dir / "runtime_wiring_gate_v0_7k.json").exists():
        build_v07k_runtime_hysteresis_wiring_repair_slice(output_dir=output_dir)
    runtime_wiring_gate = read_json(child_dir / "runtime_wiring_gate_v0_7k.json")
    if runtime_wiring_gate.get("passed") is not True:
        raise ValueError("missing_passed_v0_7k_runtime_wiring_gate")
    candidate_policy_path = child_dir / "candidate_policy_artifact_v0_7k.json"
    baseline_policy_path = child_dir / "baseline_policy_artifact_v0_7k.json"
    if not candidate_policy_path.exists() or not baseline_policy_path.exists():
        raise ValueError("missing_v0_7k_policy_artifacts")
    candidate_policy = read_json(candidate_policy_path)
    baseline_policy = read_json(baseline_policy_path)
    runtime_manifest = build_v07h_calibration_runtime_manifest(
        output_dir=output_dir,
        manifest=manifest,
    )
    runtime_manifest["policy_slice"] = V07K_POLICY_SLICE_ID
    runtime_manifest["slice_id"] = V07K_SLICE_ID
    runtime_manifest["manifest_sha256"] = _sha256_payload_excluding(
        runtime_manifest,
        "manifest_sha256",
    )
    write_json(child_dir / "calibration_runtime_manifest_v0_7k.json", runtime_manifest)
    evaluator_backend = backend or IsaacConnectorInsertionEvaluatorBackend(
        task=isaac_task,
        device=device,
        headless=headless,
        action_scale=action_scale,
        max_steps=max_steps,
    )
    backend_result = evaluator_backend.run(
        manifest=runtime_manifest,
        output_dir=child_dir / "isaac_runtime_calibration_presignal_v0_7k",
        min_rollouts_per_policy=V07H_CALIBRATION_ROLLOUTS_PER_POLICY,
        deterministic_profile="candidate_positive",
        policy_artifacts={
            "baseline": baseline_policy,
            "candidate": candidate_policy,
        },
    )
    rollout_paths = _write_v07h_calibration_external_rollouts(
        output_dir=child_dir,
        baseline_rollouts=list(backend_result.baseline_rollouts),
        candidate_rollouts=list(backend_result.candidate_rollouts),
    )
    trace_paths = {
        "baseline": list(backend_result.baseline_trace_paths),
        "candidate": list(backend_result.candidate_trace_paths),
    }
    gate = derive_v07h_calibration_presignal_gate(
        baseline_rollouts=list(backend_result.baseline_rollouts),
        candidate_rollouts=list(backend_result.candidate_rollouts),
        runtime_gate=dict(backend_result.runtime_gate),
        runtime_metadata=dict(backend_result.runtime_metadata),
        trace_paths=trace_paths,
        output_dir=child_dir,
    )
    gate.update(
        {
            "schema_version": V07K_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
            "policy_slice": V07K_POLICY_SLICE_ID,
            "slice_id": V07K_SLICE_ID,
            "runtime_wiring_gate_sha256": runtime_wiring_gate["runtime_wiring_gate_sha256"],
            "calibration_runtime_manifest_sha256": runtime_manifest["manifest_sha256"],
            "baseline_calibration_rollout_path": rollout_paths["baseline"],
            "candidate_calibration_rollout_path": rollout_paths["candidate"],
        }
    )
    gate["calibration_presignal_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "calibration_presignal_gate_sha256",
    )
    summary = {
        "schema_version": V07H_CALIBRATION_ROLLOUT_SUMMARY_SCHEMA_VERSION,
        "policy_slice": V07K_POLICY_SLICE_ID,
        "slice_id": V07K_SLICE_ID,
        "runtime_backend": backend_result.runtime_backend,
        "proof_runtime": backend_result.proof_runtime,
        "calibration_runtime_manifest_sha256": runtime_manifest["manifest_sha256"],
        "baseline_rollout_path": rollout_paths["baseline"],
        "candidate_rollout_path": rollout_paths["candidate"],
        "baseline_trace_paths": trace_paths["baseline"],
        "candidate_trace_paths": trace_paths["candidate"],
        "baseline_calibration_success_rate": gate["baseline_calibration_success_rate"],
        "candidate_calibration_success_rate": gate["candidate_calibration_success_rate"],
        "passed": gate["passed"],
        "calibration_opened": True,
        "heldout_opened": False,
        "heldout_21000_21049_accessed": gate["heldout_21000_21049_accessed"],
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    summary["calibration_rollout_summary_sha256"] = _sha256_payload_excluding(
        summary,
        "calibration_rollout_summary_sha256",
    )
    write_json(child_dir / "calibration_rollout_summary_v0_7k.json", summary)
    write_json(child_dir / "calibration_presignal_gate_v0_7k.json", gate)
    compatibility_gate = {
        "schema_version": V07K_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
        "policy_slice": V07K_POLICY_SLICE_ID,
        "slice_id": V07K_SLICE_ID,
        "passed": gate["passed"],
        "source_gate_path": f"{V07K_CHILD_OUTPUT_DIRNAME}/calibration_presignal_gate_v0_7k.json",
        "calibration_opened": True,
        "heldout_opened": False,
        "heldout_21000_21049_accessed": gate["heldout_21000_21049_accessed"],
        "heldout_allowed": gate["heldout_allowed"],
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    compatibility_gate["calibration_presignal_gate_sha256"] = _sha256_payload(compatibility_gate)
    write_json(output_dir / "calibration_presignal_gate.json", compatibility_gate)
    return gate


def _v07l_action_vector(row: dict[str, Any]) -> list[float]:
    action = row.get("normalized_action")
    if isinstance(action, list) and len(action) >= 3:
        return [float(value) for value in action]
    diagnostics = row.get("controller_action_diagnostics")
    if isinstance(diagnostics, dict):
        for key in (
            "post_adapter_action_vector",
            "post_xy_authority_action_vector",
            "post_z_pre_xy_authority_action_vector",
        ):
            vector = diagnostics.get(key)
            if isinstance(vector, list) and len(vector) >= 3:
                return [float(value) for value in vector]
    return []


def _v07l_round_or_none(value: float | None) -> float | None:
    return None if value is None else round(float(value), 12)


def classify_v07l_calibration_trace(
    payload: dict[str, Any],
    *,
    role: str,
    trace_path: str,
) -> dict[str, Any]:
    trace = [row for row in payload.get("trace", []) if isinstance(row, dict)]
    scenario = payload.get("scenario") if isinstance(payload.get("scenario"), dict) else {}
    summary = payload.get("summary") if isinstance(payload.get("summary"), dict) else {}
    seed = scenario.get("seed")
    if seed is None:
        match = re.search(r"(\d{5})", str(trace_path))
        seed = int(match.group(1)) if match else None
    protected_access = bool(seed is not None and _protected_heldout_seed_range_accessed(int(seed)))
    lateral_values = [float(row.get("lateral_error_m", 0.0) or 0.0) for row in trace]
    depth_values = [float(row.get("insertion_depth_m", 0.0) or 0.0) for row in trace]
    env_native_values = [
        bool(row.get("env_native_success") or row.get("env_native_success_mask")) for row in trace
    ]
    action_vectors = [_v07l_action_vector(row) for row in trace]
    z_motion_values = [len(action) >= 3 and float(action[2]) < -1.0e-8 for action in action_vectors]
    z_indices = [index for index, value in enumerate(z_motion_values) if value]
    z_lateral_values = [lateral_values[index] for index in z_indices if index < len(lateral_values)]
    success = bool(
        summary.get("success") is True
        or summary.get("env_native_rollout_success") is True
        or _v07i_max_consecutive(env_native_values) >= int(V06_ENV_NATIVE_SUCCESS_AUTHORITY["stable_steps_required"])
    )
    initial_lateral = lateral_values[0] if lateral_values else 0.0
    min_lateral = min(lateral_values) if lateral_values else 0.0
    final_lateral = lateral_values[-1] if lateral_values else 0.0
    max_depth = max(depth_values) if depth_values else 0.0
    first_z_motion_step = z_indices[0] if z_indices else None
    first_depth_positive_step = next(
        (index for index, value in enumerate(depth_values) if value > V07F_THRESHOLDS["depth_positive_min_m"]),
        None,
    )
    first_env_native_success_step = next(
        (index for index, value in enumerate(env_native_values) if value),
        None,
    )
    env_native_max_consecutive = _v07i_max_consecutive(env_native_values)
    max_consecutive_z_motion = _v07i_max_consecutive(z_motion_values)
    z_window_max_lateral = max(z_lateral_values) if z_lateral_values else None
    z_window_start_lateral = z_lateral_values[0] if z_lateral_values else None
    z_window_end_lateral = z_lateral_values[-1] if z_lateral_values else None
    if success:
        failure_class = "SUCCESS"
    elif (
        max_consecutive_z_motion >= V07L_Z_WINDOW_MIN_STEPS
        and max_depth < V07L_DEPTH_NO_PROGRESS_MAX_M
        and z_window_max_lateral is not None
        and z_window_max_lateral <= V07L_CENTERING_LATERAL_MAX_M
    ):
        failure_class = "Z_WINDOW_NO_VERTICAL_PROGRESS_WITH_CENTERING"
    elif (
        max_consecutive_z_motion >= V07L_Z_WINDOW_MIN_STEPS
        and max_depth < V07L_DEPTH_NO_PROGRESS_MAX_M
        and z_window_max_lateral is not None
        and z_window_max_lateral > V07L_CENTERING_LATERAL_MAX_M
    ):
        failure_class = "Z_WINDOW_LATERAL_ESCAPE_NO_DEPTH"
    elif max_depth >= V07L_SEAT_DEPTH_MIN_M and env_native_max_consecutive < int(
        V06_ENV_NATIVE_SUCCESS_AUTHORITY["stable_steps_required"]
    ):
        failure_class = "SEAT_WINDOW_NOT_HELD"
    elif max_depth >= V07L_PARTIAL_INSERTION_DEPTH_MIN_M:
        failure_class = "PARTIAL_INSERTION_NO_STABILITY"
    elif max_consecutive_z_motion < V07L_Z_WINDOW_MIN_STEPS:
        failure_class = "Z_WINDOW_TOO_SHORT_OR_NEVER_OPENED"
    else:
        failure_class = "UNCLASSIFIED_CALIBRATION_FAILURE"
    return {
        "schema_version": V07L_TRACE_CLASSIFICATION_SCHEMA_VERSION,
        "role": role,
        "trace_path": trace_path,
        "scenario_id": scenario.get("scenario_id"),
        "seed": seed,
        "success": success,
        "failure_class": failure_class,
        "failure_reason": summary.get("failure_reason", ""),
        "initial_lateral_error_m": round(initial_lateral, 12),
        "min_lateral_error_m": round(min_lateral, 12),
        "final_lateral_error_m": round(final_lateral, 12),
        "max_insertion_depth_m": round(max_depth, 12),
        "first_z_motion_step": first_z_motion_step,
        "first_depth_positive_step": first_depth_positive_step,
        "first_env_native_success_step": first_env_native_success_step,
        "env_native_max_consecutive_success_steps": env_native_max_consecutive,
        "z_motion_step_count": sum(1 for value in z_motion_values if value),
        "max_consecutive_z_motion_steps": max_consecutive_z_motion,
        "z_window_start_lateral_error_m": _v07l_round_or_none(z_window_start_lateral),
        "z_window_end_lateral_error_m": _v07l_round_or_none(z_window_end_lateral),
        "z_window_max_lateral_error_m": _v07l_round_or_none(z_window_max_lateral),
        "z_window_min_steps_required": V07L_Z_WINDOW_MIN_STEPS,
        "z_window_centering_lateral_max_m": V07L_CENTERING_LATERAL_MAX_M,
        "depth_no_progress_max_m": V07L_DEPTH_NO_PROGRESS_MAX_M,
        "heldout_21000_21049_accessed": protected_access,
    }


def _v07l_trace_paths_from_gate_or_disk(output_dir: Path, gate: dict[str, Any]) -> dict[str, list[str]]:
    trace_paths = gate.get("trace_paths") if isinstance(gate.get("trace_paths"), dict) else {}
    baseline_paths = list(trace_paths.get("baseline") or [])
    candidate_paths = list(trace_paths.get("candidate") or [])
    if baseline_paths and candidate_paths:
        return {"baseline": baseline_paths, "candidate": candidate_paths}
    trace_dir = (
        output_dir
        / V07K_CHILD_OUTPUT_DIRNAME
        / "isaac_runtime_calibration_presignal_v0_7k"
        / "isaac_runtime_heldout_rollout_traces"
    )
    return {
        "baseline": [str(path) for path in sorted(trace_dir.glob("baseline_*_calibration_*_isaac_trace.json"))],
        "candidate": [str(path) for path in sorted(trace_dir.glob("candidate_*_calibration_*_isaac_trace.json"))],
    }


def build_v07l_calibration_failure_diagnosis(*, output_dir: Path) -> dict[str, Any]:
    child_dir = output_dir / V07L_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    gate_path = output_dir / V07K_CHILD_OUTPUT_DIRNAME / "calibration_presignal_gate_v0_7k.json"
    if not gate_path.exists():
        raise ValueError("missing_v0_7k_calibration_presignal_gate")
    gate = read_json(gate_path)
    if gate.get("policy_slice") != V07K_POLICY_SLICE_ID:
        raise ValueError("v0_7l_parent_policy_slice_mismatch")
    trace_paths_by_role = _v07l_trace_paths_from_gate_or_disk(output_dir, gate)
    classifications: list[dict[str, Any]] = []
    for role, paths in trace_paths_by_role.items():
        for path_text in paths:
            path = Path(path_text)
            payload = read_json(path)
            classifications.append(
                classify_v07l_calibration_trace(payload, role=role, trace_path=str(path))
            )
    protected_access = bool(gate.get("heldout_21000_21049_accessed")) or any(
        item.get("heldout_21000_21049_accessed") is True for item in classifications
    )
    candidate_classes = [
        item["failure_class"] for item in classifications if item.get("role") == "candidate"
    ]
    baseline_classes = [item["failure_class"] for item in classifications if item.get("role") == "baseline"]
    candidate_counts = Counter(candidate_classes)
    baseline_counts = Counter(baseline_classes)
    candidate_failures = sum(count for key, count in candidate_counts.items() if key != "SUCCESS")
    dominant_failure_count = sum(candidate_counts.get(key, 0) for key in V07L_DOMINANT_FAILURE_CLASSES)
    seat_window_failure_count = candidate_counts.get("SEAT_WINDOW_NOT_HELD", 0)
    diagnosis_confident = (
        gate.get("passed") is False
        and gate.get("failure_reason") == "candidate_calibration_success_below_minimum"
        and gate.get("runtime_backend") == "isaac_runtime"
        and not protected_access
        and candidate_failures > 0
        and dominant_failure_count >= max(1, int(math.ceil(candidate_failures * 0.5)))
    )
    report: dict[str, Any] = {
        "schema_version": V07L_DIAGNOSIS_SCHEMA_VERSION,
        "policy_slice": V07L_POLICY_SLICE_ID,
        "slice_id": V07L_SLICE_ID,
        "parent_slice_id": V07K_SLICE_ID,
        "parent_calibration_presignal_gate_sha256": _sha256_file(gate_path),
        "parent_gate_passed": gate.get("passed"),
        "parent_failure_reason": gate.get("failure_reason"),
        "runtime_backend": gate.get("runtime_backend"),
        "baseline_calibration_success_rate": gate.get("baseline_calibration_success_rate"),
        "candidate_calibration_success_rate": gate.get("candidate_calibration_success_rate"),
        "baseline_calibration_success_count": gate.get("baseline_calibration_success_count"),
        "candidate_calibration_success_count": gate.get("candidate_calibration_success_count"),
        "baseline_failure_class_counts": dict(sorted(baseline_counts.items())),
        "candidate_failure_class_counts": dict(sorted(candidate_counts.items())),
        "candidate_failure_count": candidate_failures,
        "candidate_dominant_z_window_failure_count": dominant_failure_count,
        "candidate_seat_window_failure_count": seat_window_failure_count,
        "dominant_failure_classes": list(V07L_DOMINANT_FAILURE_CLASSES),
        "primary_root_cause_class": (
            "Z_DESCENT_WINDOW_INSUFFICIENT_AND_CENTERING_ESCAPE"
            if diagnosis_confident
            else "UNRESOLVED_CALIBRATION_FAILURE"
        ),
        "diagnosis_confident": bool(diagnosis_confident),
        "recommended_downstream_slice": (
            V07L_RECOMMENDED_DOWNSTREAM_SLICE if diagnosis_confident else None
        ),
        "calibration_opened": True,
        "heldout_opened": False,
        "heldout_21000_21049_accessed": protected_access,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    report["calibration_failure_diagnosis_sha256"] = _sha256_payload_excluding(
        report,
        "calibration_failure_diagnosis_sha256",
    )
    classification_artifact = {
        "schema_version": V07L_TRACE_CLASSIFICATION_SCHEMA_VERSION,
        "policy_slice": V07L_POLICY_SLICE_ID,
        "slice_id": V07L_SLICE_ID,
        "classifications": classifications,
        "heldout_21000_21049_accessed": protected_access,
    }
    classification_artifact["calibration_trace_classification_sha256"] = _sha256_payload_excluding(
        classification_artifact,
        "calibration_trace_classification_sha256",
    )
    write_json(child_dir / "calibration_trace_classification_v0_7l.json", classification_artifact)
    write_json(child_dir / "calibration_failure_diagnosis_v0_7l.json", report)
    return report


def load_required_v07m_parent_diagnosis(output_dir: Path) -> dict[str, Any]:
    diagnosis_path = output_dir / V07L_CHILD_OUTPUT_DIRNAME / "calibration_failure_diagnosis_v0_7l.json"
    if not diagnosis_path.exists():
        raise ValueError("missing_v0_7l_calibration_failure_diagnosis")
    diagnosis = read_json(diagnosis_path)
    if (
        diagnosis.get("schema_version") != V07L_DIAGNOSIS_SCHEMA_VERSION
        or diagnosis.get("slice_id") != V07L_SLICE_ID
        or diagnosis.get("diagnosis_confident") is not True
        or diagnosis.get("recommended_downstream_slice") != V07L_RECOMMENDED_DOWNSTREAM_SLICE
        or diagnosis.get("primary_root_cause_class")
        != "Z_DESCENT_WINDOW_INSUFFICIENT_AND_CENTERING_ESCAPE"
        or diagnosis.get("heldout_21000_21049_accessed") is not False
        or diagnosis.get("mvp2_closed") is not False
        or diagnosis.get("policy_uplift_proven") is not False
    ):
        raise ValueError("v0_7l_parent_diagnosis_not_confident")
    return diagnosis


def build_v07m_hysteresis_authority_config(
    *,
    output_dir: Path,
    parent_policy_artifact: dict[str, Any],
    parent_diagnosis: dict[str, Any],
) -> dict[str, Any]:
    if parent_policy_artifact.get("policy_slice") != V07K_POLICY_SLICE_ID:
        raise ValueError("v0_7m_parent_policy_slice_mismatch")
    parent_config = parent_policy_artifact.get("shared_hysteresis_authority_config")
    if not isinstance(parent_config, dict):
        raise ValueError("missing_v0_7k_parent_hysteresis_config")
    parent_diagnosis_sha = parent_diagnosis.get("calibration_failure_diagnosis_sha256")
    if not parent_diagnosis_sha:
        raise ValueError("missing_v0_7l_parent_diagnosis_sha256")
    config = {
        "schema_version": V07M_SHARED_HYSTERESIS_AUTHORITY_CONFIG_SCHEMA_VERSION,
        "policy_slice": V07M_POLICY_SLICE_ID,
        "slice_id": V07M_SLICE_ID,
        "parent_policy_slice": V07K_POLICY_SLICE_ID,
        "shared_hysteresis_authority_id": V07E_SHARED_HYSTERESIS_AUTHORITY_ID,
        "parent_shared_hysteresis_authority_config_sha256": parent_policy_artifact[
            "shared_hysteresis_authority_config_sha256"
        ],
        "parent_final_post_adapter_authority_config_sha256": parent_policy_artifact[
            "final_post_adapter_authority_config_sha256"
        ],
        "parent_v0_7l_calibration_failure_diagnosis_sha256": parent_diagnosis_sha,
        "parent_z_window_hold_steps": int(parent_config.get("z_window_hold_steps", 28)),
        "min_descend_window_reference_steps": int(parent_config.get("min_descend_window_reference_steps", 28)),
        "z_window_hold_steps": V07M_Z_WINDOW_HOLD_STEPS,
        "z_window_realign_lateral_m": V07M_Z_WINDOW_REALIGN_LATERAL_M,
        "approach_lateral_gate_m": float(
            parent_config.get("approach_lateral_gate_m", V07A_BEHAVIOR_PHASE_LATERAL_GATE_M)
        ),
        "align_orientation_gate_rad": float(parent_config.get("align_orientation_gate_rad", 0.25)),
        "hard_safety_escape_lateral_m": float(parent_config.get("hard_safety_escape_lateral_m", 0.03)),
        "repair_rule": "hold_longer_z_window_and_soft_realign_before_depth_progress",
        "success_metric_changed": False,
        "trainer_changed": False,
        "selected_action_adapter_changed": False,
        "final_post_adapter_z_authority_changed": False,
        "final_post_adapter_xy_authority_changed": False,
        "same_hysteresis_config_as_peer": True,
        "candidate_specific": False,
        "baseline_specific": False,
        "calibration_opened": True,
        "heldout_opened": False,
        "heldout_21000_21049_accessed": False,
    }
    config["shared_hysteresis_authority_config_sha256"] = _sha256_payload_excluding(
        config,
        "shared_hysteresis_authority_config_sha256",
    )
    child_dir = output_dir / V07M_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    write_json(child_dir / "v0_7m_hysteresis_authority_config.json", config)
    return config


def build_v07m_policy_artifact_payload(
    *,
    base_policy_artifact: dict[str, Any],
    hysteresis_config: dict[str, Any],
    parent_diagnosis: dict[str, Any],
    dataset_view_role: str,
) -> dict[str, Any]:
    if base_policy_artifact.get("policy_slice") != V07K_POLICY_SLICE_ID:
        raise ValueError("v0_7m_parent_policy_slice_mismatch")
    if hysteresis_config.get("policy_slice") != V07M_POLICY_SLICE_ID:
        raise ValueError("v0_7m_hysteresis_config_mismatch")
    payload = dict(base_policy_artifact)
    payload.update(
        {
            "policy_artifact_schema_version": V07M_POLICY_ARTIFACT_SCHEMA_VERSION,
            "policy_id": f"{dataset_view_role}_{V07M_SLICE_ID}_policy",
            "policy_slice": V07M_POLICY_SLICE_ID,
            "slice_id": V07M_SLICE_ID,
            "parent_policy_slice": V07K_POLICY_SLICE_ID,
            "dataset_view_role": dataset_view_role,
            "z_window_progress_authority_repair_id": V07M_Z_WINDOW_PROGRESS_REPAIR_ID,
            "z_window_progress_authority_repair": {
                "parent_diagnosis": parent_diagnosis["primary_root_cause_class"],
                "z_window_hold_steps": V07M_Z_WINDOW_HOLD_STEPS,
                "z_window_realign_lateral_m": V07M_Z_WINDOW_REALIGN_LATERAL_M,
                "soft_realign_is_not_hard_escape": True,
                "success_metric_changed": False,
                "trainer_changed": False,
                "selected_action_adapter_changed": False,
            },
            "parent_policy_artifact_sha256": base_policy_artifact["policy_artifact_sha256"],
            "parent_shared_hysteresis_authority_config_sha256": base_policy_artifact[
                "shared_hysteresis_authority_config_sha256"
            ],
            "parent_v0_7l_calibration_failure_diagnosis_sha256": parent_diagnosis[
                "calibration_failure_diagnosis_sha256"
            ],
            "shared_hysteresis_authority_id": hysteresis_config["shared_hysteresis_authority_id"],
            "shared_hysteresis_authority_config": dict(hysteresis_config),
            "shared_hysteresis_authority_config_sha256": hysteresis_config[
                "shared_hysteresis_authority_config_sha256"
            ],
            "same_hysteresis_config_as_peer": True,
            "heldout_21000_21049_accessed": False,
            "calibration_opened": True,
            "future_ab_ready": False,
            "proof_authority": False,
            "mvp2_closed": False,
            "policy_uplift_proven": False,
        }
    )
    payload["policy_artifact_sha256"] = _sha256_payload_excluding(payload, "policy_artifact_sha256")
    return payload


def derive_v07m_z_window_progress_authority_gate(
    *,
    candidate_policy: dict[str, Any],
    baseline_policy: dict[str, Any],
    parent_diagnosis: dict[str, Any],
    hysteresis_config: dict[str, Any],
) -> dict[str, Any]:
    failure_reason = ""
    same_shared_hysteresis = (
        candidate_policy.get("shared_hysteresis_authority_config_sha256")
        == baseline_policy.get("shared_hysteresis_authority_config_sha256")
        == hysteresis_config.get("shared_hysteresis_authority_config_sha256")
    )
    same_final_z = (
        candidate_policy.get("final_post_adapter_authority_config_sha256")
        == baseline_policy.get("final_post_adapter_authority_config_sha256")
    )
    same_final_xy = (
        candidate_policy.get("final_post_adapter_xy_authority_config_sha256")
        == baseline_policy.get("final_post_adapter_xy_authority_config_sha256")
    )
    same_base_servo = candidate_policy.get("base_servo_config_sha256") == baseline_policy.get(
        "base_servo_config_sha256"
    )
    same_trainer = (
        candidate_policy.get("trainer_family") == baseline_policy.get("trainer_family")
        and candidate_policy.get("trainer") == baseline_policy.get("trainer")
    )
    if parent_diagnosis.get("diagnosis_confident") is not True:
        failure_reason = "parent_v0_7l_diagnosis_not_confident"
    elif parent_diagnosis.get("recommended_downstream_slice") != V07L_RECOMMENDED_DOWNSTREAM_SLICE:
        failure_reason = "parent_v0_7l_downstream_slice_mismatch"
    elif parent_diagnosis.get("heldout_21000_21049_accessed") is not False:
        failure_reason = "parent_heldout_accessed"
    elif candidate_policy.get("policy_slice") != V07M_POLICY_SLICE_ID or baseline_policy.get(
        "policy_slice"
    ) != V07M_POLICY_SLICE_ID:
        failure_reason = "child_policy_slice_mismatch"
    elif candidate_policy.get("z_window_progress_authority_repair_id") != V07M_Z_WINDOW_PROGRESS_REPAIR_ID:
        failure_reason = "missing_z_window_progress_authority_repair_id"
    elif not same_shared_hysteresis:
        failure_reason = "candidate_baseline_hysteresis_config_mismatch"
    elif not same_final_z:
        failure_reason = "candidate_baseline_final_z_authority_mismatch"
    elif not same_final_xy:
        failure_reason = "candidate_baseline_final_xy_authority_mismatch"
    elif not same_base_servo:
        failure_reason = "candidate_baseline_base_servo_mismatch"
    elif not same_trainer:
        failure_reason = "candidate_baseline_trainer_mismatch"
    elif int(hysteresis_config.get("z_window_hold_steps", 0)) != V07M_Z_WINDOW_HOLD_STEPS:
        failure_reason = "z_window_hold_steps_not_frozen"
    elif float(hysteresis_config.get("z_window_realign_lateral_m", 0.0)) != V07M_Z_WINDOW_REALIGN_LATERAL_M:
        failure_reason = "z_window_realign_lateral_not_frozen"
    elif int(hysteresis_config.get("z_window_hold_steps", 0)) <= int(
        hysteresis_config.get("parent_z_window_hold_steps", 0)
    ):
        failure_reason = "z_window_hold_steps_not_increased"
    elif candidate_policy.get("heldout_21000_21049_accessed") is not False or baseline_policy.get(
        "heldout_21000_21049_accessed"
    ) is not False:
        failure_reason = "protected_heldout_seed_accessed"
    gate = {
        "schema_version": V07M_Z_WINDOW_PROGRESS_GATE_SCHEMA_VERSION,
        "policy_slice": V07M_POLICY_SLICE_ID,
        "slice_id": V07M_SLICE_ID,
        "parent_policy_slice": V07K_POLICY_SLICE_ID,
        "z_window_progress_authority_repair_id": V07M_Z_WINDOW_PROGRESS_REPAIR_ID,
        "passed": failure_reason == "",
        "failure_reason": failure_reason,
        "parent_diagnosis_confident": parent_diagnosis.get("diagnosis_confident") is True,
        "parent_v0_7l_calibration_failure_diagnosis_sha256": parent_diagnosis[
            "calibration_failure_diagnosis_sha256"
        ],
        "shared_hysteresis_authority_config_sha256": hysteresis_config[
            "shared_hysteresis_authority_config_sha256"
        ],
        "same_shared_hysteresis_config_as_peer": same_shared_hysteresis,
        "same_final_z_authority_config_as_peer": same_final_z,
        "same_final_xy_authority_config_as_peer": same_final_xy,
        "same_base_servo_config_as_peer": same_base_servo,
        "same_trainer_as_peer": same_trainer,
        "z_window_hold_steps": V07M_Z_WINDOW_HOLD_STEPS,
        "z_window_realign_lateral_m": V07M_Z_WINDOW_REALIGN_LATERAL_M,
        "success_metric_changed": False,
        "trainer_changed": False,
        "selected_action_adapter_changed": False,
        "final_post_adapter_z_authority_changed": False,
        "final_post_adapter_xy_authority_changed": False,
        "calibration_opened": True,
        "heldout_opened": False,
        "heldout_21000_21049_accessed": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    gate["z_window_progress_authority_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "z_window_progress_authority_gate_sha256",
    )
    return gate


def build_v07m_z_window_progress_authority_repair_slice(*, output_dir: Path) -> dict[str, Any]:
    parent_diagnosis = load_required_v07m_parent_diagnosis(output_dir)
    v07k_child_dir = output_dir / V07K_CHILD_OUTPUT_DIRNAME
    if not (
        (v07k_child_dir / "candidate_policy_artifact_v0_7k.json").exists()
        and (v07k_child_dir / "baseline_policy_artifact_v0_7k.json").exists()
    ):
        build_v07k_runtime_hysteresis_wiring_repair_slice(output_dir=output_dir)
    candidate_parent = read_json(v07k_child_dir / "candidate_policy_artifact_v0_7k.json")
    baseline_parent = read_json(v07k_child_dir / "baseline_policy_artifact_v0_7k.json")
    child_dir = output_dir / V07M_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    hysteresis_config = build_v07m_hysteresis_authority_config(
        output_dir=output_dir,
        parent_policy_artifact=candidate_parent,
        parent_diagnosis=parent_diagnosis,
    )
    candidate_policy = build_v07m_policy_artifact_payload(
        base_policy_artifact=candidate_parent,
        hysteresis_config=hysteresis_config,
        parent_diagnosis=parent_diagnosis,
        dataset_view_role="candidate_curated",
    )
    baseline_policy = build_v07m_policy_artifact_payload(
        base_policy_artifact=baseline_parent,
        hysteresis_config=hysteresis_config,
        parent_diagnosis=parent_diagnosis,
        dataset_view_role="baseline_uncurated",
    )
    write_json(child_dir / "candidate_policy_artifact_v0_7m.json", candidate_policy)
    write_json(child_dir / "baseline_policy_artifact_v0_7m.json", baseline_policy)
    gate = derive_v07m_z_window_progress_authority_gate(
        candidate_policy=candidate_policy,
        baseline_policy=baseline_policy,
        parent_diagnosis=parent_diagnosis,
        hysteresis_config=hysteresis_config,
    )
    write_json(child_dir / "z_window_progress_authority_gate_v0_7m.json", gate)
    manifest = {
        "schema_version": V07M_MANIFEST_SCHEMA_VERSION,
        "policy_slice": V07M_POLICY_SLICE_ID,
        "slice_id": V07M_SLICE_ID,
        "parent_policy_slice": V07K_POLICY_SLICE_ID,
        "parent_v0_7l_calibration_failure_diagnosis_sha256": parent_diagnosis[
            "calibration_failure_diagnosis_sha256"
        ],
        "z_window_progress_authority_repair_id": V07M_Z_WINDOW_PROGRESS_REPAIR_ID,
        "candidate_policy_artifact_sha256": candidate_policy["policy_artifact_sha256"],
        "baseline_policy_artifact_sha256": baseline_policy["policy_artifact_sha256"],
        "shared_hysteresis_authority_config_sha256": hysteresis_config[
            "shared_hysteresis_authority_config_sha256"
        ],
        "z_window_progress_authority_gate_sha256": gate["z_window_progress_authority_gate_sha256"],
        "z_window_progress_authority_gate_v0_7m": gate,
        "future_ab_ready": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "calibration_opened": True,
        "heldout_21000_21049_accessed": False,
        "artifacts": {
            "hysteresis_authority_config": (
                f"{V07M_CHILD_OUTPUT_DIRNAME}/v0_7m_hysteresis_authority_config.json"
            ),
            "candidate_policy_artifact": (
                f"{V07M_CHILD_OUTPUT_DIRNAME}/candidate_policy_artifact_v0_7m.json"
            ),
            "baseline_policy_artifact": (
                f"{V07M_CHILD_OUTPUT_DIRNAME}/baseline_policy_artifact_v0_7m.json"
            ),
            "z_window_progress_authority_gate": (
                f"{V07M_CHILD_OUTPUT_DIRNAME}/z_window_progress_authority_gate_v0_7m.json"
            ),
        },
    }
    manifest["v0_7m_z_window_progress_authority_manifest_sha256"] = _sha256_payload_excluding(
        manifest,
        "v0_7m_z_window_progress_authority_manifest_sha256",
    )
    write_json(child_dir / "v0_7m_z_window_progress_authority_manifest.json", manifest)
    return manifest


def run_v07m_calibration_presignal_runtime(
    *,
    output_dir: Path,
    manifest: dict[str, Any],
    device: str = DEFAULT_ISAAC_DEVICE,
    headless: bool = True,
    isaac_task: str = DEFAULT_ISAAC_TASK,
    max_steps: int = int(SUCCESS_METRIC["max_steps"]),
    action_scale: float = 1.0,
    backend: Any | None = None,
) -> dict[str, Any]:
    child_dir = output_dir / V07M_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    if not (child_dir / "z_window_progress_authority_gate_v0_7m.json").exists():
        build_v07m_z_window_progress_authority_repair_slice(output_dir=output_dir)
    repair_gate = read_json(child_dir / "z_window_progress_authority_gate_v0_7m.json")
    if repair_gate.get("passed") is not True:
        raise ValueError("missing_passed_v0_7m_z_window_progress_authority_gate")
    candidate_policy_path = child_dir / "candidate_policy_artifact_v0_7m.json"
    baseline_policy_path = child_dir / "baseline_policy_artifact_v0_7m.json"
    if not candidate_policy_path.exists() or not baseline_policy_path.exists():
        raise ValueError("missing_v0_7m_policy_artifacts")
    candidate_policy = read_json(candidate_policy_path)
    baseline_policy = read_json(baseline_policy_path)
    runtime_manifest = build_v07h_calibration_runtime_manifest(
        output_dir=output_dir,
        manifest=manifest,
    )
    runtime_manifest["policy_slice"] = V07M_POLICY_SLICE_ID
    runtime_manifest["slice_id"] = V07M_SLICE_ID
    runtime_manifest["manifest_sha256"] = _sha256_payload_excluding(
        runtime_manifest,
        "manifest_sha256",
    )
    write_json(child_dir / "calibration_runtime_manifest_v0_7m.json", runtime_manifest)
    evaluator_backend = backend or IsaacConnectorInsertionEvaluatorBackend(
        task=isaac_task,
        device=device,
        headless=headless,
        action_scale=action_scale,
        max_steps=max_steps,
    )
    backend_result = evaluator_backend.run(
        manifest=runtime_manifest,
        output_dir=child_dir / "isaac_runtime_calibration_presignal_v0_7m",
        min_rollouts_per_policy=V07H_CALIBRATION_ROLLOUTS_PER_POLICY,
        deterministic_profile="candidate_positive",
        policy_artifacts={
            "baseline": baseline_policy,
            "candidate": candidate_policy,
        },
    )
    rollout_paths = _write_v07h_calibration_external_rollouts(
        output_dir=child_dir,
        baseline_rollouts=list(backend_result.baseline_rollouts),
        candidate_rollouts=list(backend_result.candidate_rollouts),
    )
    trace_paths = {
        "baseline": list(backend_result.baseline_trace_paths),
        "candidate": list(backend_result.candidate_trace_paths),
    }
    gate = derive_v07h_calibration_presignal_gate(
        baseline_rollouts=list(backend_result.baseline_rollouts),
        candidate_rollouts=list(backend_result.candidate_rollouts),
        runtime_gate=dict(backend_result.runtime_gate),
        runtime_metadata=dict(backend_result.runtime_metadata),
        trace_paths=trace_paths,
        output_dir=child_dir,
    )
    gate.update(
        {
            "schema_version": V07M_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
            "policy_slice": V07M_POLICY_SLICE_ID,
            "slice_id": V07M_SLICE_ID,
            "z_window_progress_authority_gate_sha256": repair_gate[
                "z_window_progress_authority_gate_sha256"
            ],
            "calibration_runtime_manifest_sha256": runtime_manifest["manifest_sha256"],
            "baseline_calibration_rollout_path": rollout_paths["baseline"],
            "candidate_calibration_rollout_path": rollout_paths["candidate"],
        }
    )
    gate["calibration_presignal_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "calibration_presignal_gate_sha256",
    )
    summary = {
        "schema_version": V07H_CALIBRATION_ROLLOUT_SUMMARY_SCHEMA_VERSION,
        "policy_slice": V07M_POLICY_SLICE_ID,
        "slice_id": V07M_SLICE_ID,
        "runtime_backend": backend_result.runtime_backend,
        "proof_runtime": backend_result.proof_runtime,
        "calibration_runtime_manifest_sha256": runtime_manifest["manifest_sha256"],
        "baseline_rollout_path": rollout_paths["baseline"],
        "candidate_rollout_path": rollout_paths["candidate"],
        "baseline_trace_paths": trace_paths["baseline"],
        "candidate_trace_paths": trace_paths["candidate"],
        "baseline_calibration_success_rate": gate["baseline_calibration_success_rate"],
        "candidate_calibration_success_rate": gate["candidate_calibration_success_rate"],
        "passed": gate["passed"],
        "calibration_opened": True,
        "heldout_opened": False,
        "heldout_21000_21049_accessed": gate["heldout_21000_21049_accessed"],
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    summary["calibration_rollout_summary_sha256"] = _sha256_payload_excluding(
        summary,
        "calibration_rollout_summary_sha256",
    )
    write_json(child_dir / "calibration_rollout_summary_v0_7m.json", summary)
    write_json(child_dir / "calibration_presignal_gate_v0_7m.json", gate)
    compatibility_gate = {
        "schema_version": V07M_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
        "policy_slice": V07M_POLICY_SLICE_ID,
        "slice_id": V07M_SLICE_ID,
        "passed": gate["passed"],
        "source_gate_path": f"{V07M_CHILD_OUTPUT_DIRNAME}/calibration_presignal_gate_v0_7m.json",
        "calibration_opened": True,
        "heldout_opened": False,
        "heldout_21000_21049_accessed": gate["heldout_21000_21049_accessed"],
        "heldout_allowed": gate["heldout_allowed"],
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    compatibility_gate["calibration_presignal_gate_sha256"] = _sha256_payload(compatibility_gate)
    write_json(output_dir / "calibration_presignal_gate.json", compatibility_gate)
    return gate


def load_required_v07n_parent_calibration_failure(output_dir: Path) -> dict[str, Any]:
    gate_path = output_dir / V07M_CHILD_OUTPUT_DIRNAME / "calibration_presignal_gate_v0_7m.json"
    if not gate_path.exists():
        raise ValueError("missing_failed_v0_7m_calibration_presignal_gate")
    gate = read_json(gate_path)
    if (
        gate.get("schema_version") != V07M_CALIBRATION_PRESIGNAL_SCHEMA_VERSION
        or gate.get("policy_slice") != V07M_POLICY_SLICE_ID
        or gate.get("runtime_backend") != "isaac_runtime"
        or gate.get("passed") is not False
        or gate.get("failure_reason") != "candidate_calibration_success_below_minimum"
        or gate.get("heldout_21000_21049_accessed") is not False
        or gate.get("heldout_opened") is not False
        or gate.get("mvp2_closed") is not False
        or gate.get("policy_uplift_proven") is not False
    ):
        raise ValueError("missing_failed_v0_7m_calibration_presignal_gate")
    return gate


def build_v07n_final_xy_authority_config(
    *,
    output_dir: Path,
    parent_policy_artifact: dict[str, Any],
    parent_gate: dict[str, Any],
) -> dict[str, Any]:
    if parent_policy_artifact.get("policy_slice") != V07M_POLICY_SLICE_ID:
        raise ValueError("v0_7n_parent_policy_slice_mismatch")
    parent_config = parent_policy_artifact.get("final_post_adapter_xy_authority_config")
    if not isinstance(parent_config, dict):
        raise ValueError("missing_v0_7m_parent_xy_authority_config")
    if parent_gate.get("policy_slice") != V07M_POLICY_SLICE_ID or parent_gate.get("passed") is not False:
        raise ValueError("v0_7n_parent_calibration_gate_mismatch")
    config = dict(parent_config)
    config.update(
        {
            "schema_version": V07N_FINAL_XY_AUTHORITY_CONFIG_SCHEMA_VERSION,
            "policy_slice": V07N_POLICY_SLICE_ID,
            "slice_id": V07N_SLICE_ID,
            "parent_policy_slice": V07M_POLICY_SLICE_ID,
            "final_post_adapter_xy_authority_id": V07N_FINAL_POST_ADAPTER_XY_AUTHORITY_ID,
            "parent_xy_authority_config_sha256": parent_policy_artifact[
                "final_post_adapter_xy_authority_config_sha256"
            ],
            "parent_shared_hysteresis_authority_config_sha256": parent_policy_artifact[
                "shared_hysteresis_authority_config_sha256"
            ],
            "parent_final_post_adapter_authority_config_sha256": parent_policy_artifact[
                "final_post_adapter_authority_config_sha256"
            ],
            "parent_v0_7m_calibration_presignal_gate_sha256": parent_gate[
                "calibration_presignal_gate_sha256"
            ],
            "xy_authority_axis_scope": ["x", "y"],
            "xy_authority_strategy": "z_open_center_maintenance_state_feedback_clip",
            "z_open_centering_depth_max_m": V07N_Z_OPEN_CENTERING_DEPTH_MAX_M,
            "z_open_centering_lateral_m": V07N_Z_OPEN_CENTERING_LATERAL_M,
            "z_open_xy_authority_gain": V07N_Z_OPEN_XY_AUTHORITY_GAIN,
            "z_open_xy_clip_abs": V07N_Z_OPEN_XY_CLIP_ABS,
            "allow_sign_flip_during_z_open_low_depth": True,
            "success_metric_changed": False,
            "trainer_changed": False,
            "selected_action_adapter_changed": False,
            "final_post_adapter_z_authority_changed": False,
            "final_post_adapter_xy_authority_changed": True,
            "same_xy_authority_config_as_peer": True,
            "candidate_specific": False,
            "baseline_specific": False,
            "calibration_opened": True,
            "heldout_opened": False,
            "heldout_21000_21049_accessed": False,
            "proof_authority": False,
        }
    )
    config["final_post_adapter_xy_authority_config_sha256"] = _sha256_payload_excluding(
        config,
        "final_post_adapter_xy_authority_config_sha256",
    )
    child_dir = output_dir / V07N_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    write_json(child_dir / "v0_7n_xy_authority_config.json", config)
    return config


def build_v07n_policy_artifact_payload(
    *,
    base_policy_artifact: dict[str, Any],
    xy_authority_config: dict[str, Any],
    parent_gate: dict[str, Any],
    dataset_view_role: str,
) -> dict[str, Any]:
    if base_policy_artifact.get("policy_slice") != V07M_POLICY_SLICE_ID:
        raise ValueError("v0_7n_parent_policy_slice_mismatch")
    if xy_authority_config.get("policy_slice") != V07N_POLICY_SLICE_ID:
        raise ValueError("v0_7n_xy_authority_config_mismatch")
    payload = dict(base_policy_artifact)
    payload.update(
        {
            "policy_artifact_schema_version": V07N_POLICY_ARTIFACT_SCHEMA_VERSION,
            "policy_id": f"{dataset_view_role}_{V07N_SLICE_ID}_policy",
            "policy_slice": V07N_POLICY_SLICE_ID,
            "slice_id": V07N_SLICE_ID,
            "parent_policy_slice": V07M_POLICY_SLICE_ID,
            "dataset_view_role": dataset_view_role,
            "z_open_xy_center_maintenance_repair_id": V07N_Z_OPEN_XY_CENTER_MAINTENANCE_REPAIR_ID,
            "z_open_xy_center_maintenance_repair": {
                "parent_failure_reason": parent_gate["failure_reason"],
                "strategy": "z_open_center_maintenance_state_feedback_clip",
                "z_open_centering_depth_max_m": V07N_Z_OPEN_CENTERING_DEPTH_MAX_M,
                "z_open_centering_lateral_m": V07N_Z_OPEN_CENTERING_LATERAL_M,
                "allow_sign_flip_during_z_open_low_depth": True,
                "success_metric_changed": False,
                "trainer_changed": False,
                "selected_action_adapter_changed": False,
            },
            "parent_policy_artifact_sha256": base_policy_artifact["policy_artifact_sha256"],
            "parent_xy_authority_config_sha256": xy_authority_config["parent_xy_authority_config_sha256"],
            "parent_v0_7m_calibration_presignal_gate_sha256": parent_gate[
                "calibration_presignal_gate_sha256"
            ],
            "final_post_adapter_xy_authority_id": xy_authority_config[
                "final_post_adapter_xy_authority_id"
            ],
            "final_post_adapter_xy_authority_config": dict(xy_authority_config),
            "final_post_adapter_xy_authority_config_sha256": xy_authority_config[
                "final_post_adapter_xy_authority_config_sha256"
            ],
            "same_xy_authority_config_as_peer": True,
            "stable_hold_authority": "env_native_success_mask",
            "heldout_21000_21049_accessed": False,
            "calibration_opened": True,
            "future_ab_ready": False,
            "proof_authority": False,
            "mvp2_closed": False,
            "policy_uplift_proven": False,
        }
    )
    payload["policy_artifact_sha256"] = _sha256_payload_excluding(payload, "policy_artifact_sha256")
    return payload


def derive_v07n_z_open_xy_centering_gate(
    *,
    candidate_policy: dict[str, Any],
    baseline_policy: dict[str, Any],
    parent_gate: dict[str, Any],
    xy_authority_config: dict[str, Any],
) -> dict[str, Any]:
    failure_reason = ""
    same_shared_hysteresis = (
        candidate_policy.get("shared_hysteresis_authority_config_sha256")
        == baseline_policy.get("shared_hysteresis_authority_config_sha256")
    )
    same_final_z = (
        candidate_policy.get("final_post_adapter_authority_config_sha256")
        == baseline_policy.get("final_post_adapter_authority_config_sha256")
    )
    same_final_xy = (
        candidate_policy.get("final_post_adapter_xy_authority_config_sha256")
        == baseline_policy.get("final_post_adapter_xy_authority_config_sha256")
        == xy_authority_config.get("final_post_adapter_xy_authority_config_sha256")
    )
    same_base_servo = candidate_policy.get("base_servo_config_sha256") == baseline_policy.get(
        "base_servo_config_sha256"
    )
    same_trainer = (
        candidate_policy.get("trainer_family") == baseline_policy.get("trainer_family")
        and candidate_policy.get("trainer") == baseline_policy.get("trainer")
    )
    if parent_gate.get("heldout_21000_21049_accessed") is not False:
        failure_reason = "parent_heldout_accessed"
    elif parent_gate.get("passed") is not False:
        failure_reason = "parent_v0_7m_calibration_not_failed_closed"
    elif candidate_policy.get("policy_slice") != V07N_POLICY_SLICE_ID or baseline_policy.get(
        "policy_slice"
    ) != V07N_POLICY_SLICE_ID:
        failure_reason = "child_policy_slice_mismatch"
    elif (
        candidate_policy.get("z_open_xy_center_maintenance_repair_id")
        != V07N_Z_OPEN_XY_CENTER_MAINTENANCE_REPAIR_ID
    ):
        failure_reason = "missing_z_open_xy_center_maintenance_repair_id"
    elif not same_shared_hysteresis:
        failure_reason = "candidate_baseline_hysteresis_config_mismatch"
    elif not same_final_z:
        failure_reason = "candidate_baseline_final_z_authority_mismatch"
    elif not same_final_xy:
        failure_reason = "candidate_baseline_final_xy_authority_mismatch"
    elif not same_base_servo:
        failure_reason = "candidate_baseline_base_servo_mismatch"
    elif not same_trainer:
        failure_reason = "candidate_baseline_trainer_mismatch"
    elif xy_authority_config.get("allow_sign_flip_during_z_open_low_depth") is not True:
        failure_reason = "z_open_sign_flip_override_not_frozen"
    elif float(xy_authority_config.get("z_open_centering_depth_max_m", 0.0)) != V07N_Z_OPEN_CENTERING_DEPTH_MAX_M:
        failure_reason = "z_open_centering_depth_threshold_not_frozen"
    elif float(xy_authority_config.get("z_open_centering_lateral_m", 0.0)) != V07N_Z_OPEN_CENTERING_LATERAL_M:
        failure_reason = "z_open_centering_lateral_threshold_not_frozen"
    elif candidate_policy.get("heldout_21000_21049_accessed") is not False or baseline_policy.get(
        "heldout_21000_21049_accessed"
    ) is not False:
        failure_reason = "protected_heldout_seed_accessed"
    gate = {
        "schema_version": V07N_Z_OPEN_XY_GATE_SCHEMA_VERSION,
        "policy_slice": V07N_POLICY_SLICE_ID,
        "slice_id": V07N_SLICE_ID,
        "parent_policy_slice": V07M_POLICY_SLICE_ID,
        "z_open_xy_center_maintenance_repair_id": V07N_Z_OPEN_XY_CENTER_MAINTENANCE_REPAIR_ID,
        "passed": failure_reason == "",
        "failure_reason": failure_reason,
        "parent_v0_7m_calibration_presignal_gate_sha256": parent_gate[
            "calibration_presignal_gate_sha256"
        ],
        "final_post_adapter_xy_authority_id": xy_authority_config[
            "final_post_adapter_xy_authority_id"
        ],
        "final_post_adapter_xy_authority_config_sha256": xy_authority_config[
            "final_post_adapter_xy_authority_config_sha256"
        ],
        "same_shared_hysteresis_config_as_peer": same_shared_hysteresis,
        "same_final_z_authority_config_as_peer": same_final_z,
        "same_final_xy_authority_config_as_peer": same_final_xy,
        "same_base_servo_config_as_peer": same_base_servo,
        "same_trainer_as_peer": same_trainer,
        "z_open_centering_depth_max_m": V07N_Z_OPEN_CENTERING_DEPTH_MAX_M,
        "z_open_centering_lateral_m": V07N_Z_OPEN_CENTERING_LATERAL_M,
        "z_open_xy_authority_gain": V07N_Z_OPEN_XY_AUTHORITY_GAIN,
        "z_open_xy_clip_abs": V07N_Z_OPEN_XY_CLIP_ABS,
        "success_metric_changed": False,
        "trainer_changed": False,
        "selected_action_adapter_changed": False,
        "final_post_adapter_z_authority_changed": False,
        "final_post_adapter_xy_authority_changed": True,
        "calibration_opened": True,
        "heldout_opened": False,
        "heldout_21000_21049_accessed": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    gate["z_open_xy_center_maintenance_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "z_open_xy_center_maintenance_gate_sha256",
    )
    return gate


def build_v07n_z_open_xy_center_maintenance_slice(*, output_dir: Path) -> dict[str, Any]:
    parent_gate = load_required_v07n_parent_calibration_failure(output_dir)
    v07m_child_dir = output_dir / V07M_CHILD_OUTPUT_DIRNAME
    candidate_parent_path = v07m_child_dir / "candidate_policy_artifact_v0_7m.json"
    baseline_parent_path = v07m_child_dir / "baseline_policy_artifact_v0_7m.json"
    if not candidate_parent_path.exists() or not baseline_parent_path.exists():
        build_v07m_z_window_progress_authority_repair_slice(output_dir=output_dir)
    candidate_parent = read_json(candidate_parent_path)
    baseline_parent = read_json(baseline_parent_path)
    child_dir = output_dir / V07N_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    xy_config = build_v07n_final_xy_authority_config(
        output_dir=output_dir,
        parent_policy_artifact=candidate_parent,
        parent_gate=parent_gate,
    )
    candidate_policy = build_v07n_policy_artifact_payload(
        base_policy_artifact=candidate_parent,
        xy_authority_config=xy_config,
        parent_gate=parent_gate,
        dataset_view_role="candidate_curated",
    )
    baseline_policy = build_v07n_policy_artifact_payload(
        base_policy_artifact=baseline_parent,
        xy_authority_config=xy_config,
        parent_gate=parent_gate,
        dataset_view_role="baseline_uncurated",
    )
    write_json(child_dir / "candidate_policy_artifact_v0_7n.json", candidate_policy)
    write_json(child_dir / "baseline_policy_artifact_v0_7n.json", baseline_policy)
    gate = derive_v07n_z_open_xy_centering_gate(
        candidate_policy=candidate_policy,
        baseline_policy=baseline_policy,
        parent_gate=parent_gate,
        xy_authority_config=xy_config,
    )
    write_json(child_dir / "z_open_xy_center_maintenance_gate_v0_7n.json", gate)
    manifest = {
        "schema_version": V07N_MANIFEST_SCHEMA_VERSION,
        "policy_slice": V07N_POLICY_SLICE_ID,
        "slice_id": V07N_SLICE_ID,
        "parent_policy_slice": V07M_POLICY_SLICE_ID,
        "parent_v0_7m_calibration_presignal_gate_sha256": parent_gate[
            "calibration_presignal_gate_sha256"
        ],
        "z_open_xy_center_maintenance_repair_id": V07N_Z_OPEN_XY_CENTER_MAINTENANCE_REPAIR_ID,
        "candidate_policy_artifact_sha256": candidate_policy["policy_artifact_sha256"],
        "baseline_policy_artifact_sha256": baseline_policy["policy_artifact_sha256"],
        "final_post_adapter_xy_authority_config_sha256": xy_config[
            "final_post_adapter_xy_authority_config_sha256"
        ],
        "z_open_xy_center_maintenance_gate_sha256": gate[
            "z_open_xy_center_maintenance_gate_sha256"
        ],
        "z_open_xy_center_maintenance_gate_v0_7n": gate,
        "future_ab_ready": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "calibration_opened": True,
        "heldout_21000_21049_accessed": False,
        "artifacts": {
            "xy_authority_config": f"{V07N_CHILD_OUTPUT_DIRNAME}/v0_7n_xy_authority_config.json",
            "candidate_policy_artifact": (
                f"{V07N_CHILD_OUTPUT_DIRNAME}/candidate_policy_artifact_v0_7n.json"
            ),
            "baseline_policy_artifact": (
                f"{V07N_CHILD_OUTPUT_DIRNAME}/baseline_policy_artifact_v0_7n.json"
            ),
            "z_open_xy_center_maintenance_gate": (
                f"{V07N_CHILD_OUTPUT_DIRNAME}/z_open_xy_center_maintenance_gate_v0_7n.json"
            ),
        },
    }
    manifest["v0_7n_z_open_xy_center_maintenance_manifest_sha256"] = _sha256_payload_excluding(
        manifest,
        "v0_7n_z_open_xy_center_maintenance_manifest_sha256",
    )
    write_json(child_dir / "v0_7n_z_open_xy_center_maintenance_manifest.json", manifest)
    return manifest


def run_v07n_calibration_presignal_runtime(
    *,
    output_dir: Path,
    manifest: dict[str, Any],
    device: str = DEFAULT_ISAAC_DEVICE,
    headless: bool = True,
    isaac_task: str = DEFAULT_ISAAC_TASK,
    max_steps: int = int(SUCCESS_METRIC["max_steps"]),
    action_scale: float = 1.0,
    backend: Any | None = None,
) -> dict[str, Any]:
    child_dir = output_dir / V07N_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    if not (child_dir / "z_open_xy_center_maintenance_gate_v0_7n.json").exists():
        build_v07n_z_open_xy_center_maintenance_slice(output_dir=output_dir)
    repair_gate = read_json(child_dir / "z_open_xy_center_maintenance_gate_v0_7n.json")
    if repair_gate.get("passed") is not True:
        raise ValueError("missing_passed_v0_7n_z_open_xy_center_maintenance_gate")
    candidate_policy_path = child_dir / "candidate_policy_artifact_v0_7n.json"
    baseline_policy_path = child_dir / "baseline_policy_artifact_v0_7n.json"
    if not candidate_policy_path.exists() or not baseline_policy_path.exists():
        raise ValueError("missing_v0_7n_policy_artifacts")
    candidate_policy = read_json(candidate_policy_path)
    baseline_policy = read_json(baseline_policy_path)
    runtime_manifest = build_v07h_calibration_runtime_manifest(
        output_dir=output_dir,
        manifest=manifest,
    )
    runtime_manifest["policy_slice"] = V07N_POLICY_SLICE_ID
    runtime_manifest["slice_id"] = V07N_SLICE_ID
    runtime_manifest["manifest_sha256"] = _sha256_payload_excluding(
        runtime_manifest,
        "manifest_sha256",
    )
    write_json(child_dir / "calibration_runtime_manifest_v0_7n.json", runtime_manifest)
    evaluator_backend = backend or IsaacConnectorInsertionEvaluatorBackend(
        task=isaac_task,
        device=device,
        headless=headless,
        action_scale=action_scale,
        max_steps=max_steps,
    )
    backend_result = evaluator_backend.run(
        manifest=runtime_manifest,
        output_dir=child_dir / "isaac_runtime_calibration_presignal_v0_7n",
        min_rollouts_per_policy=V07H_CALIBRATION_ROLLOUTS_PER_POLICY,
        deterministic_profile="candidate_positive",
        policy_artifacts={
            "baseline": baseline_policy,
            "candidate": candidate_policy,
        },
    )
    rollout_paths = _write_v07h_calibration_external_rollouts(
        output_dir=child_dir,
        baseline_rollouts=list(backend_result.baseline_rollouts),
        candidate_rollouts=list(backend_result.candidate_rollouts),
    )
    trace_paths = {
        "baseline": list(backend_result.baseline_trace_paths),
        "candidate": list(backend_result.candidate_trace_paths),
    }
    gate = derive_v07h_calibration_presignal_gate(
        baseline_rollouts=list(backend_result.baseline_rollouts),
        candidate_rollouts=list(backend_result.candidate_rollouts),
        runtime_gate=dict(backend_result.runtime_gate),
        runtime_metadata=dict(backend_result.runtime_metadata),
        trace_paths=trace_paths,
        output_dir=child_dir,
    )
    gate.update(
        {
            "schema_version": V07N_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
            "policy_slice": V07N_POLICY_SLICE_ID,
            "slice_id": V07N_SLICE_ID,
            "z_open_xy_center_maintenance_gate_sha256": repair_gate[
                "z_open_xy_center_maintenance_gate_sha256"
            ],
            "calibration_runtime_manifest_sha256": runtime_manifest["manifest_sha256"],
            "baseline_calibration_rollout_path": rollout_paths["baseline"],
            "candidate_calibration_rollout_path": rollout_paths["candidate"],
        }
    )
    gate["calibration_presignal_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "calibration_presignal_gate_sha256",
    )
    summary = {
        "schema_version": V07H_CALIBRATION_ROLLOUT_SUMMARY_SCHEMA_VERSION,
        "policy_slice": V07N_POLICY_SLICE_ID,
        "slice_id": V07N_SLICE_ID,
        "runtime_backend": backend_result.runtime_backend,
        "proof_runtime": backend_result.proof_runtime,
        "calibration_runtime_manifest_sha256": runtime_manifest["manifest_sha256"],
        "baseline_rollout_path": rollout_paths["baseline"],
        "candidate_rollout_path": rollout_paths["candidate"],
        "baseline_trace_paths": trace_paths["baseline"],
        "candidate_trace_paths": trace_paths["candidate"],
        "baseline_calibration_success_rate": gate["baseline_calibration_success_rate"],
        "candidate_calibration_success_rate": gate["candidate_calibration_success_rate"],
        "passed": gate["passed"],
        "calibration_opened": True,
        "heldout_opened": False,
        "heldout_21000_21049_accessed": gate["heldout_21000_21049_accessed"],
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    summary["calibration_rollout_summary_sha256"] = _sha256_payload_excluding(
        summary,
        "calibration_rollout_summary_sha256",
    )
    write_json(child_dir / "calibration_rollout_summary_v0_7n.json", summary)
    write_json(child_dir / "calibration_presignal_gate_v0_7n.json", gate)
    compatibility_gate = {
        "schema_version": V07N_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
        "policy_slice": V07N_POLICY_SLICE_ID,
        "slice_id": V07N_SLICE_ID,
        "passed": gate["passed"],
        "source_gate_path": f"{V07N_CHILD_OUTPUT_DIRNAME}/calibration_presignal_gate_v0_7n.json",
        "calibration_opened": True,
        "heldout_opened": False,
        "heldout_21000_21049_accessed": gate["heldout_21000_21049_accessed"],
        "heldout_allowed": gate["heldout_allowed"],
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    compatibility_gate["calibration_presignal_gate_sha256"] = _sha256_payload(compatibility_gate)
    write_json(output_dir / "calibration_presignal_gate.json", compatibility_gate)
    return gate


def load_required_v07o_parent_calibration_failure(output_dir: Path) -> dict[str, Any]:
    gate_path = output_dir / V07N_CHILD_OUTPUT_DIRNAME / "calibration_presignal_gate_v0_7n.json"
    if not gate_path.exists():
        raise ValueError("missing_failed_v0_7n_calibration_presignal_gate")
    gate = read_json(gate_path)
    if (
        gate.get("schema_version") != V07N_CALIBRATION_PRESIGNAL_SCHEMA_VERSION
        or gate.get("policy_slice") != V07N_POLICY_SLICE_ID
        or gate.get("runtime_backend") != "isaac_runtime"
        or gate.get("passed") is not False
        or gate.get("failure_reason") != "candidate_calibration_not_above_baseline"
        or gate.get("heldout_21000_21049_accessed") is not False
        or gate.get("heldout_opened") is not False
        or gate.get("mvp2_closed") is not False
        or gate.get("policy_uplift_proven") is not False
    ):
        raise ValueError("missing_failed_v0_7n_calibration_presignal_gate")
    return gate


def build_v07o_final_xy_authority_config(
    *,
    output_dir: Path,
    parent_policy_artifact: dict[str, Any],
    parent_gate: dict[str, Any],
) -> dict[str, Any]:
    if parent_policy_artifact.get("policy_slice") != V07N_POLICY_SLICE_ID:
        raise ValueError("v0_7o_parent_policy_slice_mismatch")
    parent_config = parent_policy_artifact.get("final_post_adapter_xy_authority_config")
    if not isinstance(parent_config, dict):
        raise ValueError("missing_v0_7n_parent_xy_authority_config")
    if parent_gate.get("policy_slice") != V07N_POLICY_SLICE_ID or parent_gate.get("passed") is not False:
        raise ValueError("v0_7o_parent_calibration_gate_mismatch")
    required_piecewise_fields = (
        "xy_authority_gain",
        "xy_near_center_clip_abs",
        "xy_off_center_clip_abs",
        "xy_saturation_threshold_abs",
        "xy_near_center_lateral_m",
    )
    if any(float(parent_config.get(field, 0.0)) <= 0.0 for field in required_piecewise_fields):
        raise ValueError("v0_7o_parent_piecewise_xy_fields_missing")
    config = dict(parent_config)
    config.update(
        {
            "schema_version": V07O_FINAL_XY_AUTHORITY_CONFIG_SCHEMA_VERSION,
            "policy_slice": V07O_POLICY_SLICE_ID,
            "slice_id": V07O_SLICE_ID,
            "parent_policy_slice": V07N_POLICY_SLICE_ID,
            "final_post_adapter_xy_authority_id": V07O_FINAL_POST_ADAPTER_XY_AUTHORITY_ID,
            "parent_xy_authority_config_sha256": parent_policy_artifact[
                "final_post_adapter_xy_authority_config_sha256"
            ],
            "parent_shared_hysteresis_authority_config_sha256": parent_policy_artifact[
                "shared_hysteresis_authority_config_sha256"
            ],
            "parent_final_post_adapter_authority_config_sha256": parent_policy_artifact[
                "final_post_adapter_authority_config_sha256"
            ],
            "parent_v0_7n_calibration_presignal_gate_sha256": parent_gate[
                "calibration_presignal_gate_sha256"
            ],
            "xy_authority_axis_scope": ["x", "y"],
            "xy_authority_strategy": "composed_piecewise_plus_z_open_center_maintenance",
            "z_open_centering_depth_max_m": V07N_Z_OPEN_CENTERING_DEPTH_MAX_M,
            "z_open_centering_lateral_m": V07N_Z_OPEN_CENTERING_LATERAL_M,
            "z_open_xy_authority_gain": V07N_Z_OPEN_XY_AUTHORITY_GAIN,
            "z_open_xy_clip_abs": V07N_Z_OPEN_XY_CLIP_ABS,
            "allow_sign_flip_during_z_open_low_depth": True,
            "parent_piecewise_xy_authority_preserved": True,
            "z_open_override_added": True,
            "success_metric_changed": False,
            "trainer_changed": False,
            "selected_action_adapter_changed": False,
            "final_post_adapter_z_authority_changed": False,
            "final_post_adapter_xy_authority_changed": True,
            "same_xy_authority_config_as_peer": True,
            "candidate_specific": False,
            "baseline_specific": False,
            "calibration_opened": True,
            "heldout_opened": False,
            "heldout_21000_21049_accessed": False,
            "proof_authority": False,
        }
    )
    config["final_post_adapter_xy_authority_config_sha256"] = _sha256_payload_excluding(
        config,
        "final_post_adapter_xy_authority_config_sha256",
    )
    child_dir = output_dir / V07O_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    write_json(child_dir / "v0_7o_xy_authority_config.json", config)
    return config


def build_v07o_policy_artifact_payload(
    *,
    base_policy_artifact: dict[str, Any],
    xy_authority_config: dict[str, Any],
    parent_gate: dict[str, Any],
    dataset_view_role: str,
) -> dict[str, Any]:
    if base_policy_artifact.get("policy_slice") != V07N_POLICY_SLICE_ID:
        raise ValueError("v0_7o_parent_policy_slice_mismatch")
    if xy_authority_config.get("policy_slice") != V07O_POLICY_SLICE_ID:
        raise ValueError("v0_7o_xy_authority_config_mismatch")
    payload = dict(base_policy_artifact)
    payload.update(
        {
            "policy_artifact_schema_version": V07O_POLICY_ARTIFACT_SCHEMA_VERSION,
            "policy_id": f"{dataset_view_role}_{V07O_SLICE_ID}_policy",
            "policy_slice": V07O_POLICY_SLICE_ID,
            "slice_id": V07O_SLICE_ID,
            "parent_policy_slice": V07N_POLICY_SLICE_ID,
            "dataset_view_role": dataset_view_role,
            "composed_xy_authority_repair_id": V07O_COMPOSED_XY_AUTHORITY_REPAIR_ID,
            "composed_xy_authority_repair": {
                "parent_failure_reason": parent_gate["failure_reason"],
                "strategy": "composed_piecewise_plus_z_open_center_maintenance",
                "parent_piecewise_xy_authority_preserved": True,
                "z_open_override_added": True,
                "z_open_centering_depth_max_m": V07N_Z_OPEN_CENTERING_DEPTH_MAX_M,
                "z_open_centering_lateral_m": V07N_Z_OPEN_CENTERING_LATERAL_M,
                "allow_sign_flip_during_z_open_low_depth": True,
                "success_metric_changed": False,
                "trainer_changed": False,
                "selected_action_adapter_changed": False,
            },
            "parent_policy_artifact_sha256": base_policy_artifact["policy_artifact_sha256"],
            "parent_xy_authority_config_sha256": xy_authority_config["parent_xy_authority_config_sha256"],
            "parent_v0_7n_calibration_presignal_gate_sha256": parent_gate[
                "calibration_presignal_gate_sha256"
            ],
            "final_post_adapter_xy_authority_id": xy_authority_config[
                "final_post_adapter_xy_authority_id"
            ],
            "final_post_adapter_xy_authority_config": dict(xy_authority_config),
            "final_post_adapter_xy_authority_config_sha256": xy_authority_config[
                "final_post_adapter_xy_authority_config_sha256"
            ],
            "same_xy_authority_config_as_peer": True,
            "stable_hold_authority": "env_native_success_mask",
            "heldout_21000_21049_accessed": False,
            "calibration_opened": True,
            "future_ab_ready": False,
            "proof_authority": False,
            "mvp2_closed": False,
            "policy_uplift_proven": False,
        }
    )
    payload["policy_artifact_sha256"] = _sha256_payload_excluding(payload, "policy_artifact_sha256")
    return payload


def derive_v07o_composed_xy_authority_gate(
    *,
    candidate_policy: dict[str, Any],
    baseline_policy: dict[str, Any],
    parent_gate: dict[str, Any],
    xy_authority_config: dict[str, Any],
) -> dict[str, Any]:
    failure_reason = ""
    same_shared_hysteresis = (
        candidate_policy.get("shared_hysteresis_authority_config_sha256")
        == baseline_policy.get("shared_hysteresis_authority_config_sha256")
    )
    same_final_z = (
        candidate_policy.get("final_post_adapter_authority_config_sha256")
        == baseline_policy.get("final_post_adapter_authority_config_sha256")
    )
    same_final_xy = (
        candidate_policy.get("final_post_adapter_xy_authority_config_sha256")
        == baseline_policy.get("final_post_adapter_xy_authority_config_sha256")
        == xy_authority_config.get("final_post_adapter_xy_authority_config_sha256")
    )
    same_base_servo = candidate_policy.get("base_servo_config_sha256") == baseline_policy.get(
        "base_servo_config_sha256"
    )
    same_trainer = (
        candidate_policy.get("trainer_family") == baseline_policy.get("trainer_family")
        and candidate_policy.get("trainer") == baseline_policy.get("trainer")
    )
    parent_piecewise_preserved = all(
        float(xy_authority_config.get(field, 0.0)) > 0.0
        for field in (
            "xy_authority_gain",
            "xy_near_center_clip_abs",
            "xy_off_center_clip_abs",
            "xy_saturation_threshold_abs",
            "xy_near_center_lateral_m",
        )
    )
    if parent_gate.get("heldout_21000_21049_accessed") is not False:
        failure_reason = "parent_heldout_accessed"
    elif parent_gate.get("passed") is not False:
        failure_reason = "parent_v0_7n_calibration_not_failed_closed"
    elif candidate_policy.get("policy_slice") != V07O_POLICY_SLICE_ID or baseline_policy.get(
        "policy_slice"
    ) != V07O_POLICY_SLICE_ID:
        failure_reason = "child_policy_slice_mismatch"
    elif (
        candidate_policy.get("composed_xy_authority_repair_id")
        != V07O_COMPOSED_XY_AUTHORITY_REPAIR_ID
    ):
        failure_reason = "missing_composed_xy_authority_repair_id"
    elif not same_shared_hysteresis:
        failure_reason = "candidate_baseline_hysteresis_config_mismatch"
    elif not same_final_z:
        failure_reason = "candidate_baseline_final_z_authority_mismatch"
    elif not same_final_xy:
        failure_reason = "candidate_baseline_final_xy_authority_mismatch"
    elif not same_base_servo:
        failure_reason = "candidate_baseline_base_servo_mismatch"
    elif not same_trainer:
        failure_reason = "candidate_baseline_trainer_mismatch"
    elif not parent_piecewise_preserved:
        failure_reason = "parent_piecewise_xy_authority_not_preserved"
    elif xy_authority_config.get("allow_sign_flip_during_z_open_low_depth") is not True:
        failure_reason = "z_open_sign_flip_override_not_frozen"
    elif float(xy_authority_config.get("z_open_centering_depth_max_m", 0.0)) != V07N_Z_OPEN_CENTERING_DEPTH_MAX_M:
        failure_reason = "z_open_centering_depth_threshold_not_frozen"
    elif float(xy_authority_config.get("z_open_centering_lateral_m", 0.0)) != V07N_Z_OPEN_CENTERING_LATERAL_M:
        failure_reason = "z_open_centering_lateral_threshold_not_frozen"
    elif candidate_policy.get("heldout_21000_21049_accessed") is not False or baseline_policy.get(
        "heldout_21000_21049_accessed"
    ) is not False:
        failure_reason = "protected_heldout_seed_accessed"
    gate = {
        "schema_version": V07O_COMPOSED_XY_GATE_SCHEMA_VERSION,
        "policy_slice": V07O_POLICY_SLICE_ID,
        "slice_id": V07O_SLICE_ID,
        "parent_policy_slice": V07N_POLICY_SLICE_ID,
        "composed_xy_authority_repair_id": V07O_COMPOSED_XY_AUTHORITY_REPAIR_ID,
        "passed": failure_reason == "",
        "failure_reason": failure_reason,
        "parent_v0_7n_calibration_presignal_gate_sha256": parent_gate[
            "calibration_presignal_gate_sha256"
        ],
        "final_post_adapter_xy_authority_id": xy_authority_config[
            "final_post_adapter_xy_authority_id"
        ],
        "final_post_adapter_xy_authority_config_sha256": xy_authority_config[
            "final_post_adapter_xy_authority_config_sha256"
        ],
        "same_shared_hysteresis_config_as_peer": same_shared_hysteresis,
        "same_final_z_authority_config_as_peer": same_final_z,
        "same_final_xy_authority_config_as_peer": same_final_xy,
        "same_base_servo_config_as_peer": same_base_servo,
        "same_trainer_as_peer": same_trainer,
        "parent_piecewise_xy_authority_preserved": parent_piecewise_preserved,
        "z_open_override_added": True,
        "z_open_centering_depth_max_m": V07N_Z_OPEN_CENTERING_DEPTH_MAX_M,
        "z_open_centering_lateral_m": V07N_Z_OPEN_CENTERING_LATERAL_M,
        "z_open_xy_authority_gain": V07N_Z_OPEN_XY_AUTHORITY_GAIN,
        "z_open_xy_clip_abs": V07N_Z_OPEN_XY_CLIP_ABS,
        "success_metric_changed": False,
        "trainer_changed": False,
        "selected_action_adapter_changed": False,
        "final_post_adapter_z_authority_changed": False,
        "final_post_adapter_xy_authority_changed": True,
        "calibration_opened": True,
        "heldout_opened": False,
        "heldout_21000_21049_accessed": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    gate["composed_xy_authority_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "composed_xy_authority_gate_sha256",
    )
    return gate


def build_v07o_composed_xy_authority_slice(*, output_dir: Path) -> dict[str, Any]:
    parent_gate = load_required_v07o_parent_calibration_failure(output_dir)
    v07n_child_dir = output_dir / V07N_CHILD_OUTPUT_DIRNAME
    candidate_parent_path = v07n_child_dir / "candidate_policy_artifact_v0_7n.json"
    baseline_parent_path = v07n_child_dir / "baseline_policy_artifact_v0_7n.json"
    if not candidate_parent_path.exists() or not baseline_parent_path.exists():
        build_v07n_z_open_xy_center_maintenance_slice(output_dir=output_dir)
    candidate_parent = read_json(candidate_parent_path)
    baseline_parent = read_json(baseline_parent_path)
    child_dir = output_dir / V07O_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    xy_config = build_v07o_final_xy_authority_config(
        output_dir=output_dir,
        parent_policy_artifact=candidate_parent,
        parent_gate=parent_gate,
    )
    candidate_policy = build_v07o_policy_artifact_payload(
        base_policy_artifact=candidate_parent,
        xy_authority_config=xy_config,
        parent_gate=parent_gate,
        dataset_view_role="candidate_curated",
    )
    baseline_policy = build_v07o_policy_artifact_payload(
        base_policy_artifact=baseline_parent,
        xy_authority_config=xy_config,
        parent_gate=parent_gate,
        dataset_view_role="baseline_uncurated",
    )
    write_json(child_dir / "candidate_policy_artifact_v0_7o.json", candidate_policy)
    write_json(child_dir / "baseline_policy_artifact_v0_7o.json", baseline_policy)
    gate = derive_v07o_composed_xy_authority_gate(
        candidate_policy=candidate_policy,
        baseline_policy=baseline_policy,
        parent_gate=parent_gate,
        xy_authority_config=xy_config,
    )
    write_json(child_dir / "composed_xy_authority_gate_v0_7o.json", gate)
    manifest = {
        "schema_version": V07O_MANIFEST_SCHEMA_VERSION,
        "policy_slice": V07O_POLICY_SLICE_ID,
        "slice_id": V07O_SLICE_ID,
        "parent_policy_slice": V07N_POLICY_SLICE_ID,
        "parent_v0_7n_calibration_presignal_gate_sha256": parent_gate[
            "calibration_presignal_gate_sha256"
        ],
        "composed_xy_authority_repair_id": V07O_COMPOSED_XY_AUTHORITY_REPAIR_ID,
        "candidate_policy_artifact_sha256": candidate_policy["policy_artifact_sha256"],
        "baseline_policy_artifact_sha256": baseline_policy["policy_artifact_sha256"],
        "final_post_adapter_xy_authority_config_sha256": xy_config[
            "final_post_adapter_xy_authority_config_sha256"
        ],
        "composed_xy_authority_gate_sha256": gate["composed_xy_authority_gate_sha256"],
        "composed_xy_authority_gate_v0_7o": gate,
        "future_ab_ready": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "calibration_opened": True,
        "heldout_21000_21049_accessed": False,
        "artifacts": {
            "xy_authority_config": f"{V07O_CHILD_OUTPUT_DIRNAME}/v0_7o_xy_authority_config.json",
            "candidate_policy_artifact": (
                f"{V07O_CHILD_OUTPUT_DIRNAME}/candidate_policy_artifact_v0_7o.json"
            ),
            "baseline_policy_artifact": (
                f"{V07O_CHILD_OUTPUT_DIRNAME}/baseline_policy_artifact_v0_7o.json"
            ),
            "composed_xy_authority_gate": (
                f"{V07O_CHILD_OUTPUT_DIRNAME}/composed_xy_authority_gate_v0_7o.json"
            ),
        },
    }
    manifest["v0_7o_composed_xy_authority_manifest_sha256"] = _sha256_payload_excluding(
        manifest,
        "v0_7o_composed_xy_authority_manifest_sha256",
    )
    write_json(child_dir / "v0_7o_composed_xy_authority_manifest.json", manifest)
    return manifest


def run_v07o_calibration_presignal_runtime(
    *,
    output_dir: Path,
    manifest: dict[str, Any],
    device: str = DEFAULT_ISAAC_DEVICE,
    headless: bool = True,
    isaac_task: str = DEFAULT_ISAAC_TASK,
    max_steps: int = int(SUCCESS_METRIC["max_steps"]),
    action_scale: float = 1.0,
    backend: Any | None = None,
) -> dict[str, Any]:
    child_dir = output_dir / V07O_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    if not (child_dir / "composed_xy_authority_gate_v0_7o.json").exists():
        build_v07o_composed_xy_authority_slice(output_dir=output_dir)
    repair_gate = read_json(child_dir / "composed_xy_authority_gate_v0_7o.json")
    if repair_gate.get("passed") is not True:
        raise ValueError("missing_passed_v0_7o_composed_xy_authority_gate")
    candidate_policy_path = child_dir / "candidate_policy_artifact_v0_7o.json"
    baseline_policy_path = child_dir / "baseline_policy_artifact_v0_7o.json"
    if not candidate_policy_path.exists() or not baseline_policy_path.exists():
        raise ValueError("missing_v0_7o_policy_artifacts")
    candidate_policy = read_json(candidate_policy_path)
    baseline_policy = read_json(baseline_policy_path)
    runtime_manifest = build_v07h_calibration_runtime_manifest(
        output_dir=output_dir,
        manifest=manifest,
    )
    runtime_manifest["policy_slice"] = V07O_POLICY_SLICE_ID
    runtime_manifest["slice_id"] = V07O_SLICE_ID
    runtime_manifest["manifest_sha256"] = _sha256_payload_excluding(
        runtime_manifest,
        "manifest_sha256",
    )
    write_json(child_dir / "calibration_runtime_manifest_v0_7o.json", runtime_manifest)
    evaluator_backend = backend or IsaacConnectorInsertionEvaluatorBackend(
        task=isaac_task,
        device=device,
        headless=headless,
        action_scale=action_scale,
        max_steps=max_steps,
    )
    backend_result = evaluator_backend.run(
        manifest=runtime_manifest,
        output_dir=child_dir / "isaac_runtime_calibration_presignal_v0_7o",
        min_rollouts_per_policy=V07H_CALIBRATION_ROLLOUTS_PER_POLICY,
        deterministic_profile="candidate_positive",
        policy_artifacts={
            "baseline": baseline_policy,
            "candidate": candidate_policy,
        },
    )
    rollout_paths = _write_v07h_calibration_external_rollouts(
        output_dir=child_dir,
        baseline_rollouts=list(backend_result.baseline_rollouts),
        candidate_rollouts=list(backend_result.candidate_rollouts),
    )
    trace_paths = {
        "baseline": list(backend_result.baseline_trace_paths),
        "candidate": list(backend_result.candidate_trace_paths),
    }
    gate = derive_v07h_calibration_presignal_gate(
        baseline_rollouts=list(backend_result.baseline_rollouts),
        candidate_rollouts=list(backend_result.candidate_rollouts),
        runtime_gate=dict(backend_result.runtime_gate),
        runtime_metadata=dict(backend_result.runtime_metadata),
        trace_paths=trace_paths,
        output_dir=child_dir,
    )
    gate.update(
        {
            "schema_version": V07O_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
            "policy_slice": V07O_POLICY_SLICE_ID,
            "slice_id": V07O_SLICE_ID,
            "composed_xy_authority_gate_sha256": repair_gate["composed_xy_authority_gate_sha256"],
            "calibration_runtime_manifest_sha256": runtime_manifest["manifest_sha256"],
            "baseline_calibration_rollout_path": rollout_paths["baseline"],
            "candidate_calibration_rollout_path": rollout_paths["candidate"],
        }
    )
    gate["calibration_presignal_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "calibration_presignal_gate_sha256",
    )
    summary = {
        "schema_version": V07H_CALIBRATION_ROLLOUT_SUMMARY_SCHEMA_VERSION,
        "policy_slice": V07O_POLICY_SLICE_ID,
        "slice_id": V07O_SLICE_ID,
        "runtime_backend": backend_result.runtime_backend,
        "proof_runtime": backend_result.proof_runtime,
        "calibration_runtime_manifest_sha256": runtime_manifest["manifest_sha256"],
        "baseline_rollout_path": rollout_paths["baseline"],
        "candidate_rollout_path": rollout_paths["candidate"],
        "baseline_trace_paths": trace_paths["baseline"],
        "candidate_trace_paths": trace_paths["candidate"],
        "baseline_calibration_success_rate": gate["baseline_calibration_success_rate"],
        "candidate_calibration_success_rate": gate["candidate_calibration_success_rate"],
        "passed": gate["passed"],
        "calibration_opened": True,
        "heldout_opened": False,
        "heldout_21000_21049_accessed": gate["heldout_21000_21049_accessed"],
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    summary["calibration_rollout_summary_sha256"] = _sha256_payload_excluding(
        summary,
        "calibration_rollout_summary_sha256",
    )
    write_json(child_dir / "calibration_rollout_summary_v0_7o.json", summary)
    write_json(child_dir / "calibration_presignal_gate_v0_7o.json", gate)
    compatibility_gate = {
        "schema_version": V07O_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
        "policy_slice": V07O_POLICY_SLICE_ID,
        "slice_id": V07O_SLICE_ID,
        "passed": gate["passed"],
        "source_gate_path": f"{V07O_CHILD_OUTPUT_DIRNAME}/calibration_presignal_gate_v0_7o.json",
        "calibration_opened": True,
        "heldout_opened": False,
        "heldout_21000_21049_accessed": gate["heldout_21000_21049_accessed"],
        "heldout_allowed": gate["heldout_allowed"],
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    compatibility_gate["calibration_presignal_gate_sha256"] = _sha256_payload(compatibility_gate)
    write_json(output_dir / "calibration_presignal_gate.json", compatibility_gate)
    return gate


def load_required_v07o_calibration_pass(output_dir: Path) -> dict[str, Any]:
    gate_path = output_dir / V07O_CHILD_OUTPUT_DIRNAME / "calibration_presignal_gate_v0_7o.json"
    if not gate_path.exists():
        raise ValueError("missing_passed_v0_7o_calibration_presignal_gate")
    gate = read_json(gate_path)
    reasons: list[str] = []
    if gate.get("schema_version") != V07O_CALIBRATION_PRESIGNAL_SCHEMA_VERSION:
        reasons.append("schema_version_mismatch")
    if gate.get("policy_slice") != V07O_POLICY_SLICE_ID:
        reasons.append("policy_slice_mismatch")
    if gate.get("slice_id") != V07O_SLICE_ID:
        reasons.append("slice_id_mismatch")
    if gate.get("passed") is not True:
        reasons.append("gate_not_passed")
    if gate.get("heldout_allowed") is not True:
        reasons.append("heldout_not_allowed")
    if gate.get("runtime_backend") != "isaac_runtime":
        reasons.append("runtime_backend_not_isaac")
    if gate.get("proof_runtime") != ISAAC_PROOF_RUNTIME:
        reasons.append("proof_runtime_mismatch")
    if gate.get("heldout_opened") is not False:
        reasons.append("heldout_already_opened")
    if gate.get("heldout_21000_21049_accessed") is not False:
        reasons.append("heldout_access_detected_before_closure")
    expected_hash = _sha256_payload_excluding(gate, "calibration_presignal_gate_sha256")
    if gate.get("calibration_presignal_gate_sha256") != expected_hash:
        reasons.append("calibration_gate_hash_mismatch")
    if reasons:
        raise ValueError("missing_passed_v0_7o_calibration_presignal_gate: " + ",".join(reasons))
    return gate


def _load_v07p_policy_artifacts(output_dir: Path) -> dict[str, dict[str, Any]]:
    child_dir = output_dir / V07O_CHILD_OUTPUT_DIRNAME
    candidate_path = child_dir / "candidate_policy_artifact_v0_7o.json"
    baseline_path = child_dir / "baseline_policy_artifact_v0_7o.json"
    if not candidate_path.exists() or not baseline_path.exists():
        raise ValueError("missing_v0_7o_policy_artifacts")
    baseline = read_json(baseline_path)
    candidate = read_json(candidate_path)
    validate_v07p_policy_peer_fairness(baseline_policy=baseline, candidate_policy=candidate)
    return {
        "baseline": {**baseline, "path": str(baseline_path)},
        "candidate": {**candidate, "path": str(candidate_path)},
    }


def validate_v07p_policy_peer_fairness(
    *,
    baseline_policy: dict[str, Any],
    candidate_policy: dict[str, Any],
) -> None:
    reasons: list[str] = []
    for role, policy in (("baseline", baseline_policy), ("candidate", candidate_policy)):
        if policy.get("policy_slice") != V07O_POLICY_SLICE_ID:
            reasons.append(f"{role}_policy_slice_mismatch")
        if policy.get("heldout_21000_21049_accessed") is not False:
            reasons.append(f"{role}_heldout_accessed_before_v07p")
        if policy.get("mvp2_closed") is not False:
            reasons.append(f"{role}_already_closed")
    equality_keys = (
        "selected_action_adapter_id",
        "trainer",
        "trainer_family",
        "policy_class",
        "feature_schema",
        "feature_schema_version",
        "phase_schema",
        "final_post_adapter_authority_config_sha256",
        "final_post_adapter_xy_authority_config_sha256",
        "base_servo_config_sha256",
        "shared_hysteresis_authority_config_sha256",
    )
    for key in equality_keys:
        if baseline_policy.get(key) != candidate_policy.get(key):
            reasons.append(f"peer_{key}_mismatch")
    if reasons:
        raise ValueError("v0_7p_policy_peer_fairness_failed: " + ",".join(reasons))


def _existing_train_view(path: Path, *, view_id: str) -> dict[str, Any]:
    if not path.exists():
        raise ValueError(f"missing_train_view_hdf5:{path}")
    return {
        "view_id": view_id,
        "path": str(path),
        "sha256": _sha256_file(path),
    }


def _heldout_seed_access_from_rollouts(rollouts: Sequence[dict[str, Any]]) -> bool:
    for rollout in rollouts:
        seed = rollout.get("seed")
        if seed is None:
            match = re.search(r"held_out_(\d+)", str(rollout.get("scenario_id") or ""))
            seed = int(match.group(1)) if match else None
        if seed is not None and _protected_heldout_seed_range_accessed(int(seed)):
            return True
    return False


def run_v07p_heldout_closure_runtime(
    *,
    output_dir: Path,
    manifest: dict[str, Any],
    device: str = DEFAULT_ISAAC_DEVICE,
    headless: bool = True,
    isaac_task: str = DEFAULT_ISAAC_TASK,
    max_steps: int = int(SUCCESS_METRIC["max_steps"]),
    action_scale: float = 1.0,
    min_rollouts_per_policy: int = MIN_PROOF_ROLLOUTS_PER_POLICY,
    bootstrap_iterations: int = 2000,
    bootstrap_seed: int = 23,
    backend: Any | None = None,
) -> dict[str, Any]:
    if manifest.get("scenario_profile") != "v0_6":
        raise ValueError("v0_7p_heldout_closure_requires_v0_6_manifest")
    calibration_gate = load_required_v07o_calibration_pass(output_dir)
    train_gate_status = resolve_existing_v06_train_generation_runtime_gate(output_dir=output_dir)
    if train_gate_status.get("reuse_allowed") is not True or not isinstance(train_gate_status.get("gate"), dict):
        raise ValueError("missing_passed_v0_6_train_generation_runtime_gate")
    train_generation_runtime_gate = train_gate_status["gate"]
    policy_artifacts = _load_v07p_policy_artifacts(output_dir)
    baseline_policy = policy_artifacts["baseline"]
    candidate_policy = policy_artifacts["candidate"]
    child_dir = output_dir / V07P_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)

    selection_path = output_dir / "calibration_selection_report.json"
    if not selection_path.exists():
        raise ValueError("missing_calibration_selection_report")
    selection = read_json(selection_path)
    selected_adapter_id = str(candidate_policy["selected_action_adapter_id"])
    if selection.get("same_adapter_used_for_baseline_and_candidate") is not True:
        raise ValueError("v0_7p_calibration_selection_not_peer_fair")
    if selection.get("heldout_excluded") is not True:
        raise ValueError("v0_7p_calibration_selection_heldout_not_excluded")

    curation_path = output_dir / "curation_manifest.json"
    if not curation_path.exists():
        raise ValueError("missing_curation_manifest")
    curation_manifest = read_json(curation_path)
    training_scenario_ids = sorted(
        {
            str(item["scenario_id"])
            for item in curation_manifest.get("items", [])
            if isinstance(item, dict) and item.get("scenario_id")
        }
    )
    heldout_leakage_guard = validate_no_heldout_leakage(
        manifest=manifest,
        training_scenario_ids=training_scenario_ids,
        curation_tuning_scenario_ids=[],
        threshold_tuning_scenario_ids=[],
        hyperparameter_scenario_ids=[],
        calibration_selector_scenario_ids=[str(item) for item in selection.get("calibration_scenario_ids", [])],
    )
    if heldout_leakage_guard["passed"] is not True:
        raise ValueError("v0_7p_heldout_leakage_guard_failed")

    baseline_view = _existing_train_view(
        output_dir / "baseline_uncurated_train.hdf5",
        view_id="baseline_uncurated_mvp2c_train_view",
    )
    candidate_view = _existing_train_view(
        output_dir / "candidate_curated_train.hdf5",
        view_id="candidate_curated_mvp2c_train_view",
    )
    policy_class = str(candidate_policy["policy_class"])
    trainer = str(candidate_policy["trainer"])
    bridge_dir = _write_learning_harness_bridge(
        output_dir=child_dir,
        manifest=manifest,
        baseline_view=baseline_view,
        candidate_view=candidate_view,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )

    evaluator_backend = backend or IsaacConnectorInsertionEvaluatorBackend(
        task=isaac_task,
        device=device,
        headless=headless,
        action_scale=action_scale,
        max_steps=max_steps,
    )
    backend_result = evaluator_backend.run(
        manifest=manifest,
        output_dir=child_dir,
        min_rollouts_per_policy=min_rollouts_per_policy,
        deterministic_profile="candidate_positive",
        policy_artifacts=policy_artifacts,
    )
    runtime_gate = dict(backend_result.runtime_gate)
    actual_rollouts_per_policy = min(
        len(backend_result.baseline_rollouts),
        len(backend_result.candidate_rollouts),
    )
    runtime_gate["actual_baseline_rollouts"] = len(backend_result.baseline_rollouts)
    runtime_gate["actual_candidate_rollouts"] = len(backend_result.candidate_rollouts)
    runtime_gate["actual_rollouts_per_policy"] = actual_rollouts_per_policy
    heldout_accessed = _heldout_seed_access_from_rollouts(
        list(backend_result.baseline_rollouts) + list(backend_result.candidate_rollouts)
    )
    heldout_suite = _heldout_suite(manifest)
    baseline_rollouts_path = _write_external_rollout_json(
        output_dir=child_dir,
        role="baseline",
        policy_artifact=baseline_policy,
        train_view=baseline_view,
        heldout_suite=heldout_suite,
        backend_result=backend_result,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    candidate_rollouts_path = _write_external_rollout_json(
        output_dir=child_dir,
        role="candidate",
        policy_artifact=candidate_policy,
        train_view=candidate_view,
        heldout_suite=heldout_suite,
        backend_result=backend_result,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    learning_report = _run_learning_validator(
        output_dir=child_dir,
        bridge_dir=bridge_dir,
        baseline_rollouts_path=baseline_rollouts_path,
        candidate_rollouts_path=candidate_rollouts_path,
        min_rollouts_per_policy=min_rollouts_per_policy,
        bootstrap_iterations=bootstrap_iterations,
        bootstrap_seed=bootstrap_seed,
        policy_class=policy_class,
        trainer=trainer,
    )
    closure = derive_mvp2c_closure(
        learning_report=learning_report,
        runtime_gate=runtime_gate,
        train_generation_runtime_gate=train_generation_runtime_gate,
        calibration_selection_report=selection,
        heldout_leakage_guard=heldout_leakage_guard,
        actual_rollouts_per_policy=actual_rollouts_per_policy,
    )
    confidence_interval_report = _bootstrap_uplift_ci(
        baseline_rollouts=list(backend_result.baseline_rollouts),
        candidate_rollouts=list(backend_result.candidate_rollouts),
        iterations=bootstrap_iterations,
        seed=bootstrap_seed,
    )
    gate = {
        "schema_version": V07P_HELDOUT_CLOSURE_SCHEMA_VERSION,
        "policy_slice": V07P_POLICY_SLICE_ID,
        "slice_id": V07P_SLICE_ID,
        "parent_policy_slice": V07O_POLICY_SLICE_ID,
        "parent_calibration_presignal_gate_sha256": calibration_gate["calibration_presignal_gate_sha256"],
        "runtime_backend": backend_result.runtime_backend,
        "proof_runtime": backend_result.proof_runtime,
        "runtime_gate": runtime_gate,
        "actual_rollouts_per_policy": actual_rollouts_per_policy,
        "baseline_success_rate": learning_report.get("baseline_success_rate"),
        "candidate_success_rate": learning_report.get("candidate_success_rate"),
        "curated_vs_uncurated_uplift": learning_report.get("curated_vs_uncurated_uplift"),
        "learning_report_path": str(
            child_dir / "mvp2_learning_proven_policy_eval" / "mvp2_learning_proven_report.json"
        ),
        "baseline_external_rollouts": str(baseline_rollouts_path),
        "candidate_external_rollouts": str(candidate_rollouts_path),
        "confidence_interval_report": confidence_interval_report,
        "stronger_public_evidence_target_passed": _derive_public_evidence_target(
            actual_rollouts_per_policy=actual_rollouts_per_policy,
            confidence_interval_report=confidence_interval_report,
        ),
        "heldout_opened": True,
        "heldout_21000_21049_accessed": heldout_accessed,
        "heldout_leakage_guard": heldout_leakage_guard,
        "calibration_selection_report_sha256": _sha256_file(selection_path),
        "selected_action_adapter_id": selected_adapter_id,
        "same_adapter_used_for_baseline_and_candidate": True,
        "same_policy_class": baseline_policy.get("policy_class") == candidate_policy.get("policy_class"),
        "same_trainer": baseline_policy.get("trainer") == candidate_policy.get("trainer"),
        "same_feature_schema": baseline_policy.get("feature_schema") == candidate_policy.get("feature_schema"),
        "mvp2_closed": closure["mvp2_closed"],
        "mvp2c_close_minimum_passed": closure["mvp2c_close_minimum_passed"],
        "policy_uplift_proven": closure["learning_proven"],
        "proof_eligible": closure["proof_eligible"],
        "blockers": closure["blockers"] + list(learning_report.get("blockers") or []),
        "non_claims": {
            "deployable_real_robot_policy": False,
            "visual_policy_performance": False,
            "real_robot_success": False,
            "physical_robot_readiness": False,
            "universal_robot_support": False,
            "hmd_openxr_readiness": False,
        },
    }
    gate["heldout_closure_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "heldout_closure_gate_sha256",
    )
    write_json(child_dir / "heldout_closure_gate_v0_7p.json", gate)
    write_json(output_dir / "heldout_closure_gate.json", gate)
    return gate


def _rollout_success_from_summary(summary: dict[str, Any]) -> bool:
    return summary.get("env_native_rollout_success") is True or summary.get("success") is True


def _longest_env_native_success_window(trace: list[dict[str, Any]]) -> int:
    longest = 0
    current = 0
    for row in trace:
        if row.get("env_native_success") is True or row.get("env_native_success_mask") is True:
            current += 1
            longest = max(longest, current)
        else:
            current = 0
    return longest


def _longest_negative_z_window(trace: list[dict[str, Any]]) -> int:
    longest = 0
    current = 0
    for row in trace:
        diagnostics = row.get("controller_action_diagnostics")
        action = None
        if isinstance(diagnostics, dict):
            action = diagnostics.get("post_adapter_action_vector") or diagnostics.get(
                "post_xy_authority_action_vector"
            )
        if action is None:
            action = row.get("normalized_action")
        z_value = float(action[2]) if isinstance(action, list) and len(action) >= 3 else 0.0
        if z_value < -0.01:
            current += 1
            longest = max(longest, current)
        else:
            current = 0
    return longest


def _trace_float_values(trace: list[dict[str, Any]], key: str) -> list[float]:
    values = []
    for row in trace:
        value = row.get(key)
        if isinstance(value, (int, float)) and not isinstance(value, bool):
            values.append(float(value))
    return values


def classify_v07q_candidate_failure(summary: dict[str, Any], trace: list[dict[str, Any]]) -> dict[str, Any]:
    depths = _trace_float_values(trace, "insertion_depth_m")
    laterals = _trace_float_values(trace, "lateral_error_m")
    max_depth = max(depths) if depths else 0.0
    min_lateral = min(laterals) if laterals else None
    env_window = summary.get("env_native_max_consecutive_success_steps")
    if not isinstance(env_window, int):
        env_window = _longest_env_native_success_window(trace)
    z_window = _longest_negative_z_window(trace)
    if max_depth == 0.0 and z_window == 0:
        failure_class = "ALIGNMENT_STALL_NO_DESCENT"
    elif max_depth >= 0.0245 and env_window > 0:
        failure_class = "NEAR_SEAT_HOLD_WINDOW_SHORT"
    elif max_depth < 0.0245 and min_lateral is not None and min_lateral <= 0.001:
        failure_class = "UNDER_INSERTION_WITH_GOOD_CENTERING"
    else:
        failure_class = "OTHER_CANDIDATE_FAILURE"
    return {
        "failure_class": failure_class,
        "max_insertion_depth_m": round(max_depth, 6),
        "min_lateral_error_m": round(min_lateral, 6) if min_lateral is not None else None,
        "env_native_max_consecutive_success_steps": env_window,
        "longest_z_descent_steps": z_window,
        "failure_reason": summary.get("failure_reason") or "UNKNOWN",
    }


def _load_v07p_trace_rows(output_dir: Path) -> list[dict[str, Any]]:
    trace_dir = output_dir / V07P_CHILD_OUTPUT_DIRNAME / "isaac_runtime_heldout_rollout_traces"
    if not trace_dir.exists():
        raise ValueError("missing_v0_7p_heldout_trace_dir")
    rows = []
    for path in sorted(trace_dir.glob("*.json")):
        payload = read_json(path)
        scenario = payload.get("scenario") if isinstance(payload.get("scenario"), dict) else {}
        summary = payload.get("summary") if isinstance(payload.get("summary"), dict) else {}
        trace = payload.get("trace") if isinstance(payload.get("trace"), list) else []
        role = str(payload.get("policy_role") or payload.get("role") or path.name.split("_")[0])
        seed = scenario.get("seed")
        if not isinstance(seed, int):
            scenario_id = str(scenario.get("scenario_id") or "")
            match = re.search(r"(\d+)$", scenario_id)
            if match:
                seed = int(match.group(1))
        if role not in {"baseline", "candidate"} or not isinstance(seed, int):
            continue
        rows.append(
            {
                "role": role,
                "seed": seed,
                "scenario_id": str(scenario.get("scenario_id") or f"held_out_{seed}"),
                "summary": summary,
                "trace": trace,
                "trace_path": str(path),
                "success": _rollout_success_from_summary(summary),
            }
        )
    return rows


def build_v07q_heldout_shortfall_diagnosis(*, output_dir: Path) -> dict[str, Any]:
    gate_path = output_dir / V07P_CHILD_OUTPUT_DIRNAME / "heldout_closure_gate_v0_7p.json"
    if not gate_path.exists():
        raise ValueError("missing_v0_7p_heldout_closure_gate")
    gate = read_json(gate_path)
    if gate.get("heldout_opened") is not True or gate.get("heldout_21000_21049_accessed") is not True:
        raise ValueError("v0_7q_requires_opened_v0_7p_heldout_gate")
    rows = _load_v07p_trace_rows(output_dir)
    if len(rows) != 100:
        raise ValueError(f"v0_7q_requires_100_v0_7p_heldout_traces_got_{len(rows)}")

    paired: dict[int, dict[str, dict[str, Any]]] = {}
    for row in rows:
        paired.setdefault(int(row["seed"]), {})[str(row["role"])] = row
    paired_table = []
    paired_outcome_counts = {"B1_C1": 0, "B0_C1": 0, "B1_C0": 0, "B0_C0": 0}
    candidate_failure_rows = []
    for seed in sorted(paired):
        baseline = paired[seed].get("baseline")
        candidate = paired[seed].get("candidate")
        if baseline is None or candidate is None:
            raise ValueError(f"v0_7q_missing_paired_rollout_for_seed_{seed}")
        baseline_success = bool(baseline["success"])
        candidate_success = bool(candidate["success"])
        outcome = ("B1" if baseline_success else "B0") + "_" + ("C1" if candidate_success else "C0")
        paired_outcome_counts[outcome] += 1
        row = {
            "seed": seed,
            "scenario_id": candidate["scenario_id"],
            "baseline_success": baseline_success,
            "candidate_success": candidate_success,
            "paired_outcome": outcome,
            "baseline_trace_path": baseline["trace_path"],
            "candidate_trace_path": candidate["trace_path"],
        }
        paired_table.append(row)
        if not candidate_success:
            classification = classify_v07q_candidate_failure(candidate["summary"], candidate["trace"])
            candidate_failure_rows.append({**row, **classification})

    baseline_success_count = paired_outcome_counts["B1_C1"] + paired_outcome_counts["B1_C0"]
    candidate_success_count = paired_outcome_counts["B1_C1"] + paired_outcome_counts["B0_C1"]
    actual_rollouts_per_policy = int(gate.get("actual_rollouts_per_policy") or len(paired))
    required_candidate_success_count = math.ceil(
        baseline_success_count + 0.20 * actual_rollouts_per_policy - 1e-9
    )
    close_shortfall_success_count = max(0, required_candidate_success_count - candidate_success_count)
    if round(float(gate.get("baseline_success_rate", 0.0)) * actual_rollouts_per_policy) != baseline_success_count:
        raise ValueError("v0_7q_baseline_success_count_mismatch")
    if round(float(gate.get("candidate_success_rate", 0.0)) * actual_rollouts_per_policy) != candidate_success_count:
        raise ValueError("v0_7q_candidate_success_count_mismatch")

    failure_class_counts = {
        "NEAR_SEAT_HOLD_WINDOW_SHORT": 0,
        "UNDER_INSERTION_WITH_GOOD_CENTERING": 0,
        "ALIGNMENT_STALL_NO_DESCENT": 0,
        "OTHER_CANDIDATE_FAILURE": 0,
    }
    for row in candidate_failure_rows:
        failure_class_counts[str(row["failure_class"])] += 1
    near_seat_recoverable_count = failure_class_counts["NEAR_SEAT_HOLD_WINDOW_SHORT"]
    under_insertion_count = failure_class_counts["UNDER_INSERTION_WITH_GOOD_CENTERING"]
    alignment_stall_count = failure_class_counts["ALIGNMENT_STALL_NO_DESCENT"]
    if near_seat_recoverable_count >= close_shortfall_success_count:
        recommendation = "v0_8a_fresh_seat_window_authority_slice"
        dominant = "NEAR_SEAT_HOLD_WINDOW_SHORT"
    elif under_insertion_count >= close_shortfall_success_count:
        recommendation = "v0_8a_fresh_z_progress_authority_slice"
        dominant = "UNDER_INSERTION_WITH_GOOD_CENTERING"
    else:
        recommendation = "v0_8a_fresh_policy_class_rebase"
        dominant = "MIXED_OR_UNRESOLVED"

    child_dir = output_dir / V07Q_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    write_json(child_dir / "paired_seed_outcome_table_v0_7q.json", paired_table)
    write_json(child_dir / "candidate_failure_classification_v0_7q.json", candidate_failure_rows)
    marker = {
        "schema_version": "rdf_mvp2e_post_heldout_integrity_marker_v0.1.0",
        "source_slice_id": V07P_SLICE_ID,
        "source_gate_path": str(gate_path),
        "source_gate_sha256": _sha256_file(gate_path),
        "heldout_opened": True,
        "heldout_21000_21049_accessed": True,
        "fresh_slice_required": True,
        "same_heldout_reuse_allowed_for_closure": False,
        "recommended_downstream_slice": recommendation,
        "reason": "v0_7p actual held-out was opened and failed close minimum; tuning must move to a fresh sealed split.",
    }
    marker["post_heldout_integrity_marker_sha256"] = _sha256_payload_excluding(
        marker,
        "post_heldout_integrity_marker_sha256",
    )
    write_json(child_dir / "post_heldout_integrity_marker_v0_7q.json", marker)
    write_json(output_dir / "post_heldout_tuning_marker.json", marker)
    diagnosis = {
        "schema_version": V07Q_DIAGNOSIS_SCHEMA_VERSION,
        "policy_slice": V07Q_POLICY_SLICE_ID,
        "slice_id": V07Q_SLICE_ID,
        "source_slice_id": V07P_SLICE_ID,
        "source_heldout_closure_gate_sha256": _sha256_file(gate_path),
        "runtime_backend": "offline_artifact_diagnosis",
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "heldout_opened": True,
        "heldout_21000_21049_accessed": True,
        "same_heldout_reuse_allowed_for_closure": False,
        "fresh_slice_required": True,
        "actual_rollouts_per_policy": actual_rollouts_per_policy,
        "baseline_success_count": baseline_success_count,
        "candidate_success_count": candidate_success_count,
        "required_candidate_success_count": required_candidate_success_count,
        "close_shortfall_success_count": close_shortfall_success_count,
        "paired_outcome_counts": paired_outcome_counts,
        "candidate_failure_class_counts": failure_class_counts,
        "near_seat_recoverable_count": near_seat_recoverable_count,
        "under_insertion_count": under_insertion_count,
        "alignment_stall_count": alignment_stall_count,
        "dominant_shortfall_class": dominant,
        "recommended_downstream_slice": recommendation,
        "artifact_paths": {
            "paired_seed_outcome_table": str(child_dir / "paired_seed_outcome_table_v0_7q.json"),
            "candidate_failure_classification": str(
                child_dir / "candidate_failure_classification_v0_7q.json"
            ),
            "post_heldout_integrity_marker": str(
                child_dir / "post_heldout_integrity_marker_v0_7q.json"
            ),
        },
        "non_claims": {
            "closure_authority": False,
            "same_heldout_reuse_for_closure": False,
            "policy_uplift_proven": False,
        },
    }
    diagnosis["heldout_shortfall_diagnosis_sha256"] = _sha256_payload_excluding(
        diagnosis,
        "heldout_shortfall_diagnosis_sha256",
    )
    write_json(child_dir / "heldout_shortfall_diagnosis_v0_7q.json", diagnosis)
    write_json(output_dir / "heldout_shortfall_diagnosis.json", diagnosis)
    return diagnosis


def load_required_v07q_post_heldout_marker(output_dir: Path) -> dict[str, Any]:
    candidates = [
        output_dir / "post_heldout_tuning_marker.json",
        output_dir / V07Q_CHILD_OUTPUT_DIRNAME / "post_heldout_integrity_marker_v0_7q.json",
    ]
    marker_path = next((path for path in candidates if path.exists()), None)
    if marker_path is None:
        raise ValueError("missing_v0_7q_post_heldout_marker")
    marker = read_json(marker_path)
    if (
        marker.get("fresh_slice_required") is not True
        or marker.get("same_heldout_reuse_allowed_for_closure") is not False
        or marker.get("recommended_downstream_slice") != "v0_8a_fresh_seat_window_authority_slice"
        or marker.get("heldout_21000_21049_accessed") is not True
    ):
        raise ValueError("invalid_v0_7q_post_heldout_marker")
    marker["path"] = str(marker_path)
    marker["sha256"] = _sha256_file(marker_path)
    return marker


def _v08a_trace_rows_from_path(path: Path) -> tuple[int, list[dict[str, Any]]]:
    if not path.exists():
        raise ValueError("v0_8a_train_success_trace_missing")
    payload = read_json(path)
    seed = _seed_from_trace_payload_or_path(payload, path)
    if _protected_heldout_seed_range_accessed(seed):
        raise ValueError("v0_8a_train_success_trace_protected_heldout_access")
    trace = payload.get("trace")
    if not isinstance(trace, list) or not trace:
        raise ValueError("v0_8a_train_success_trace_invalid")
    return seed, [row for row in trace if isinstance(row, dict)]


def _v08a_first_negative_z_step(rows: list[dict[str, Any]]) -> int | None:
    for index, row in enumerate(rows):
        action = row.get("normalized_action")
        if not (isinstance(action, list) and len(action) >= 3):
            diagnostics = row.get("controller_action_diagnostics")
            if isinstance(diagnostics, dict):
                action = diagnostics.get("post_adapter_action_vector")
        if isinstance(action, list) and len(action) >= 3 and float(action[2]) < -1.0e-8:
            return int(row.get("step", index))
    return None


def _v08a_first_env_native_success_step(rows: list[dict[str, Any]]) -> int | None:
    for index, row in enumerate(rows):
        if bool(row.get("env_native_success") or row.get("env_native_success_mask")):
            return int(row.get("step", index))
    return None


def derive_v08a_seat_window_authority_config(*, output_dir: Path) -> dict[str, Any]:
    train_gate, train_gate_sha256 = load_v07a2_parent_train_generation_gate(output_dir)
    trace_paths = [Path(str(path)) for path in train_gate.get("generated_success_trace_paths") or []]
    if not trace_paths:
        raise ValueError("v0_8a_train_success_trace_paths_missing")
    stats: list[dict[str, Any]] = []
    for path in trace_paths:
        seed, rows = _v08a_trace_rows_from_path(path)
        first_z = _v08a_first_negative_z_step(rows)
        first_env = _v08a_first_env_native_success_step(rows)
        if first_z is None or first_env is None:
            raise ValueError("v0_8a_train_success_trace_lacks_z_or_env_success")
        stats.append(
            {
                "seed": seed,
                "trace_path": str(path),
                "trace_sha256": _sha256_file(path),
                "first_z_step": first_z,
                "first_env_native_success_step": first_env,
            }
        )
    first_z_steps = [int(row["first_z_step"]) for row in stats]
    first_env_steps = [int(row["first_env_native_success_step"]) for row in stats]
    config: dict[str, Any] = {
        "schema_version": V08A_SEAT_WINDOW_AUTHORITY_CONFIG_SCHEMA_VERSION,
        "seat_window_authority_id": V08A_SEAT_WINDOW_AUTHORITY_ID,
        "policy_slice": V08A_POLICY_SLICE_ID,
        "parent_policy_slice": V07O_POLICY_SLICE_ID,
        "slice_id": V08A_SLICE_ID,
        "source": "train_generation_success_traces_only",
        "parent_train_generation_runtime_gate_sha256": train_gate_sha256,
        "train_success_trace_stats": stats,
        "train_success_first_z_steps": first_z_steps,
        "train_success_first_env_success_steps": first_env_steps,
        "train_success_first_z_step_max": max(first_z_steps),
        "train_success_first_env_success_step_max": max(first_env_steps),
        "latest_z_open_step": max(first_z_steps),
        "z_open_centering_lateral_m": V07N_Z_OPEN_CENTERING_LATERAL_M,
        "seat_region_depth_m": V08A_SEAT_REGION_DEPTH_M,
        "z_progress_action": V08A_Z_PROGRESS_ACTION,
        "candidate_specific": False,
        "baseline_specific": False,
        "proof_authority": False,
        "fresh_calibration_seed_range": [min(V08A_FRESH_CALIBRATION_RANGE), max(V08A_FRESH_CALIBRATION_RANGE)],
        "fresh_heldout_seed_range": [min(V08A_FRESH_HELDOUT_RANGE), max(V08A_FRESH_HELDOUT_RANGE)],
        "burned_heldout_seed_range": list(V07A2_PROTECTED_HELDOUT_SEED_RANGE),
        "heldout_21000_21049_used_for_parameter_derivation": False,
        "source_diagnostic_heldout_21000_21049_accessed": True,
    }
    config["seat_window_authority_config_sha256"] = _sha256_payload_excluding(
        config,
        "seat_window_authority_config_sha256",
    )
    return config


def build_v08a_fresh_manifest(*, output_dir: Path, marker: dict[str, Any]) -> dict[str, Any]:
    calibration_rows = [_scenario_row(split="calibration", seed=seed) for seed in V08A_FRESH_CALIBRATION_RANGE]
    heldout_rows = [_scenario_row(split="held_out", seed=seed) for seed in V08A_FRESH_HELDOUT_RANGE]
    for row in calibration_rows + heldout_rows:
        seed = int(row["seed"])
        if _protected_heldout_seed_range_accessed(seed):
            raise ValueError("v0_8a_fresh_manifest_reuses_burned_heldout")
    manifest = {
        "schema_version": V08A_MANIFEST_SCHEMA_VERSION,
        "policy_slice": V08A_POLICY_SLICE_ID,
        "slice_id": V08A_SLICE_ID,
        "parent_policy_slice": V07O_POLICY_SLICE_ID,
        "scenario_profile": "v0_8a",
        "task_type": "connector_insertion",
        "success_metric": SUCCESS_METRIC,
        "success_authority": V06_ENV_NATIVE_SUCCESS_AUTHORITY,
        "source_post_heldout_marker_sha256": marker["sha256"],
        "scenarios": calibration_rows + heldout_rows,
        "fresh_split_manifest": {
            "calibration": {
                "seed_range": [min(V08A_FRESH_CALIBRATION_RANGE), max(V08A_FRESH_CALIBRATION_RANGE)],
                "scenario_ids": [row["scenario_id"] for row in calibration_rows],
                "count": len(calibration_rows),
            },
            "held_out": {
                "seed_range": [min(V08A_FRESH_HELDOUT_RANGE), max(V08A_FRESH_HELDOUT_RANGE)],
                "scenario_ids": [row["scenario_id"] for row in heldout_rows],
                "count": len(heldout_rows),
            },
        },
        "burned_heldout_seed_range": list(V07A2_PROTECTED_HELDOUT_SEED_RANGE),
        "heldout_21000_21049_accessed": True,
        "heldout_21000_21049_reuse_allowed_for_closure": False,
        "fresh_heldout_24000_24049_accessed": False,
        "calibration_opened": False,
        "heldout_opened": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    manifest["manifest_sha256"] = _sha256_payload_excluding(manifest, "manifest_sha256")
    return manifest


def build_v08a_policy_artifact_payload(
    *,
    base_policy_artifact: dict[str, Any],
    seat_window_authority_config: dict[str, Any],
    dataset_view_role: str,
) -> dict[str, Any]:
    role = "candidate" if dataset_view_role == "candidate_curated" else "baseline"
    payload = {
        key: value
        for key, value in base_policy_artifact.items()
        if key not in {"path", "policy_artifact_sha256"}
    }
    payload.update(
        {
            "schema_version": V08A_POLICY_ARTIFACT_SCHEMA_VERSION,
            "policy_id": f"{role}_mvp2e_v08a_fresh_seat_window_authority_policy",
            "policy_slice": V08A_POLICY_SLICE_ID,
            "slice_id": V08A_SLICE_ID,
            "parent_policy_slice": V07O_POLICY_SLICE_ID,
            "parent_policy_artifact_sha256": base_policy_artifact.get("policy_artifact_sha256"),
            "dataset_view_role": dataset_view_role,
            "seat_window_authority_id": V08A_SEAT_WINDOW_AUTHORITY_ID,
            "seat_window_authority_config": seat_window_authority_config,
            "seat_window_authority_config_sha256": seat_window_authority_config[
                "seat_window_authority_config_sha256"
            ],
            "same_seat_window_authority_config_as_peer": True,
            "source_diagnostic_heldout_21000_21049_accessed": True,
            "heldout_21000_21049_accessed": False,
            "fresh_calibration_23000_23029_accessed": False,
            "fresh_heldout_24000_24049_accessed": False,
            "mvp2_closed": False,
            "policy_uplift_proven": False,
        }
    )
    payload["policy_artifact_sha256"] = _sha256_payload_excluding(payload, "policy_artifact_sha256")
    return payload


def build_v08a_fresh_seat_window_authority_slice(*, output_dir: Path) -> dict[str, Any]:
    marker = load_required_v07q_post_heldout_marker(output_dir)
    policy_artifacts = _load_v07p_policy_artifacts(output_dir)
    child_dir = output_dir / V08A_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    seat_window_config = derive_v08a_seat_window_authority_config(output_dir=output_dir)
    write_json(child_dir / "v0_8a_seat_window_authority_config.json", seat_window_config)
    candidate_policy = build_v08a_policy_artifact_payload(
        base_policy_artifact=policy_artifacts["candidate"],
        seat_window_authority_config=seat_window_config,
        dataset_view_role="candidate_curated",
    )
    baseline_policy = build_v08a_policy_artifact_payload(
        base_policy_artifact=policy_artifacts["baseline"],
        seat_window_authority_config=seat_window_config,
        dataset_view_role="baseline_uncurated",
    )
    write_json(child_dir / "candidate_policy_artifact_v0_8a.json", candidate_policy)
    write_json(child_dir / "baseline_policy_artifact_v0_8a.json", baseline_policy)
    manifest = build_v08a_fresh_manifest(output_dir=output_dir, marker=marker)
    manifest.update(
        {
            "seat_window_authority_id": V08A_SEAT_WINDOW_AUTHORITY_ID,
            "seat_window_authority_config_sha256": seat_window_config[
                "seat_window_authority_config_sha256"
            ],
            "candidate_policy_artifact_sha256": candidate_policy["policy_artifact_sha256"],
            "baseline_policy_artifact_sha256": baseline_policy["policy_artifact_sha256"],
            "same_seat_window_authority_config_as_peer": (
                candidate_policy["seat_window_authority_config_sha256"]
                == baseline_policy["seat_window_authority_config_sha256"]
            ),
            "artifacts": {
                "seat_window_authority_config": (
                    f"{V08A_CHILD_OUTPUT_DIRNAME}/v0_8a_seat_window_authority_config.json"
                ),
                "candidate_policy_artifact": (
                    f"{V08A_CHILD_OUTPUT_DIRNAME}/candidate_policy_artifact_v0_8a.json"
                ),
                "baseline_policy_artifact": (
                    f"{V08A_CHILD_OUTPUT_DIRNAME}/baseline_policy_artifact_v0_8a.json"
                ),
            },
        }
    )
    manifest["manifest_sha256"] = _sha256_payload_excluding(manifest, "manifest_sha256")
    write_json(child_dir / "v0_8a_fresh_manifest.json", manifest)
    return manifest


def _load_v08a_policy_artifacts(output_dir: Path) -> dict[str, dict[str, Any]]:
    child_dir = output_dir / V08A_CHILD_OUTPUT_DIRNAME
    candidate_path = child_dir / "candidate_policy_artifact_v0_8a.json"
    baseline_path = child_dir / "baseline_policy_artifact_v0_8a.json"
    if not candidate_path.exists() or not baseline_path.exists():
        raise ValueError("missing_v0_8a_policy_artifacts")
    baseline = read_json(baseline_path)
    candidate = read_json(candidate_path)
    reasons: list[str] = []
    for role, policy in (("baseline", baseline), ("candidate", candidate)):
        if policy.get("policy_slice") != V08A_POLICY_SLICE_ID:
            reasons.append(f"{role}_policy_slice_mismatch")
        if policy.get("parent_policy_slice") != V07O_POLICY_SLICE_ID:
            reasons.append(f"{role}_parent_policy_slice_mismatch")
        if policy.get("heldout_21000_21049_accessed") is not False:
            reasons.append(f"{role}_burned_heldout_accessed")
        if policy.get("fresh_heldout_24000_24049_accessed") is not False:
            reasons.append(f"{role}_fresh_heldout_accessed_before_closure")
        expected_hash = _sha256_payload_excluding(policy, "policy_artifact_sha256")
        if policy.get("policy_artifact_sha256") != expected_hash:
            reasons.append(f"{role}_policy_hash_mismatch")
    equality_keys = (
        "selected_action_adapter_id",
        "trainer",
        "trainer_family",
        "policy_class",
        "feature_schema",
        "feature_schema_version",
        "phase_schema",
        "final_post_adapter_authority_config_sha256",
        "final_post_adapter_xy_authority_config_sha256",
        "base_servo_config_sha256",
        "shared_hysteresis_authority_config_sha256",
        "seat_window_authority_config_sha256",
    )
    for key in equality_keys:
        if baseline.get(key) != candidate.get(key):
            reasons.append(f"peer_{key}_mismatch")
    if reasons:
        raise ValueError("v0_8a_policy_peer_fairness_failed: " + ",".join(reasons))
    return {
        "baseline": {**baseline, "path": str(baseline_path)},
        "candidate": {**candidate, "path": str(candidate_path)},
    }


def _v08a_runtime_manifest_for_split(*, fresh_manifest: dict[str, Any], split: str) -> dict[str, Any]:
    if split not in {"calibration", "held_out"}:
        raise ValueError("v0_8a_runtime_manifest_unknown_split")
    rows = [
        {**row, "source_split": split, "semantic_eval_split": split, "split": "held_out"}
        for row in fresh_manifest.get("scenarios", [])
        if isinstance(row, dict) and row.get("split") == split
    ]
    if not rows:
        raise ValueError(f"v0_8a_runtime_manifest_missing_{split}_rows")
    seeds = [int(row["seed"]) for row in rows]
    if any(_protected_heldout_seed_range_accessed(seed) for seed in seeds):
        raise ValueError("v0_8a_runtime_manifest_reuses_burned_heldout")
    if split == "calibration" and seeds != list(V08A_FRESH_CALIBRATION_RANGE):
        raise ValueError("v0_8a_calibration_seed_range_mismatch")
    if split == "held_out" and seeds != list(V08A_FRESH_HELDOUT_RANGE):
        raise ValueError("v0_8a_heldout_seed_range_mismatch")
    manifest = {
        "schema_version": fresh_manifest["schema_version"],
        "policy_slice": V08A_POLICY_SLICE_ID,
        "slice_id": V08A_SLICE_ID,
        "parent_policy_slice": V07O_POLICY_SLICE_ID,
        "scenario_profile": "v0_8a",
        "runtime_split": split,
        "task_type": fresh_manifest["task_type"],
        "success_metric": fresh_manifest["success_metric"],
        "success_authority": fresh_manifest["success_authority"],
        "source_fresh_manifest_sha256": fresh_manifest["manifest_sha256"],
        "scenarios": rows,
        "burned_heldout_seed_range": list(V07A2_PROTECTED_HELDOUT_SEED_RANGE),
        "heldout_21000_21049_accessed": False,
        "fresh_calibration_23000_23029_accessed": split == "calibration",
        "fresh_heldout_24000_24049_accessed": split == "held_out",
        "calibration_opened": split == "calibration",
        "heldout_opened": split == "held_out",
        "proof_authority": split == "held_out",
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    manifest["manifest_sha256"] = _sha256_payload_excluding(manifest, "manifest_sha256")
    return manifest


def _write_v08a_calibration_external_rollouts(
    *,
    output_dir: Path,
    baseline_rollouts: list[dict[str, Any]],
    candidate_rollouts: list[dict[str, Any]],
) -> dict[str, str]:
    rollout_dir = output_dir / "calibration_external_rollouts"
    rollout_dir.mkdir(parents=True, exist_ok=True)
    baseline_path = rollout_dir / "baseline_calibration_rollouts_v0_8a.json"
    candidate_path = rollout_dir / "candidate_calibration_rollouts_v0_8a.json"
    write_json(baseline_path, baseline_rollouts)
    write_json(candidate_path, candidate_rollouts)
    return {
        "baseline": str(baseline_path),
        "candidate": str(candidate_path),
    }


def derive_v08a_calibration_presignal_gate(
    *,
    baseline_rollouts: list[dict[str, Any]],
    candidate_rollouts: list[dict[str, Any]],
    runtime_gate: dict[str, Any],
    runtime_metadata: dict[str, Any],
    trace_paths: dict[str, list[str]],
) -> dict[str, Any]:
    gate = derive_v07h_calibration_presignal_gate(
        baseline_rollouts=baseline_rollouts,
        candidate_rollouts=candidate_rollouts,
        runtime_gate=runtime_gate,
        runtime_metadata=runtime_metadata,
        trace_paths=trace_paths,
        output_dir=Path("."),
    )
    gate.update(
        {
            "schema_version": V08A_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
            "policy_slice": V08A_POLICY_SLICE_ID,
            "slice_id": V08A_SLICE_ID,
            "parent_policy_slice": V07O_POLICY_SLICE_ID,
            "fresh_calibration_23000_23029_accessed": True,
            "fresh_heldout_24000_24049_accessed": False,
            "source": "v0_8a_fresh_calibration_runtime",
        }
    )
    gate["calibration_presignal_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "calibration_presignal_gate_sha256",
    )
    return gate


def _v08a_calibration_selection_report(output_dir: Path) -> dict[str, Any]:
    selection_path = output_dir / "calibration_selection_report.json"
    if not selection_path.exists():
        raise ValueError("missing_calibration_selection_report")
    selection = read_json(selection_path)
    if selection.get("same_adapter_used_for_baseline_and_candidate") is not True:
        raise ValueError("v0_8a_calibration_selection_not_peer_fair")
    if selection.get("heldout_excluded") is not True:
        raise ValueError("v0_8a_calibration_selection_heldout_not_excluded")
    return selection


def _v08a_training_scenario_ids(output_dir: Path) -> list[str]:
    curation_path = output_dir / "curation_manifest.json"
    if not curation_path.exists():
        raise ValueError("missing_curation_manifest")
    curation_manifest = read_json(curation_path)
    return sorted(
        {
            str(item["scenario_id"])
            for item in curation_manifest.get("items", [])
            if isinstance(item, dict) and item.get("scenario_id")
        }
    )


def _run_v08a_manifest_with_existing_isaac(
    *,
    evaluator_backend: Any,
    env: Any,
    simulation_app: Any,
    torch_module: Any,
    manifest: dict[str, Any],
    output_dir: Path,
    min_rollouts_per_policy: int,
    policy_artifacts: dict[str, Any],
) -> BackendResult:
    trace_dir = output_dir / "isaac_runtime_heldout_rollout_traces"
    trace_dir.mkdir(parents=True, exist_ok=True)
    heldout = [row for row in manifest["scenarios"] if row["split"] == "held_out"]
    rollout_count = max(int(min_rollouts_per_policy), len(heldout))
    baseline_rollouts: list[dict[str, Any]] = []
    candidate_rollouts: list[dict[str, Any]] = []
    baseline_paths: list[str] = []
    candidate_paths: list[str] = []
    try:
        for role, policy in (
            ("baseline", policy_artifacts["baseline"]),
            ("candidate", policy_artifacts["candidate"]),
        ):
            rollouts = baseline_rollouts if role == "baseline" else candidate_rollouts
            trace_paths = baseline_paths if role == "baseline" else candidate_paths
            for index in range(rollout_count):
                scenario = heldout[index % len(heldout)]
                trace_path, rollout = evaluator_backend._run_one_rollout(
                    env=env,
                    simulation_app=simulation_app,
                    torch=torch_module,
                    policy_artifact=policy,
                    scenario=scenario,
                    role=role,
                    rollout_index=index,
                    trace_dir=trace_dir,
                    manifest=manifest,
                )
                trace_paths.append(str(trace_path))
                rollouts.append(rollout)
    except Exception as exc:
        error_path = trace_dir / "isaac_runtime_error.json"
        write_json(
            error_path,
            {
                "schema_version": "rdf_mvp2b_isaac_runtime_error_v0.1.0",
                "runtime_backend": evaluator_backend.runtime_backend,
                "proof_runtime": evaluator_backend.proof_runtime,
                "scenario_manifest_sha256": manifest["manifest_sha256"],
                "isaac_task_or_scene_id": evaluator_backend.task,
                "headless": evaluator_backend.headless,
                "device": evaluator_backend.device,
                "error": f"{type(exc).__name__}: {exc}",
            },
        )
        return BackendResult(
            runtime_backend=evaluator_backend.runtime_backend,
            proof_runtime=evaluator_backend.proof_runtime,
            runtime_gate={
                "passed": False,
                "runtime_backend": evaluator_backend.runtime_backend,
                "proof_runtime": evaluator_backend.proof_runtime,
                "reason": f"Isaac runtime rollout failed: {type(exc).__name__}: {exc}",
                "error_artifact": str(error_path),
            },
            baseline_rollouts=baseline_rollouts,
            candidate_rollouts=candidate_rollouts,
            baseline_trace_paths=baseline_paths + [str(error_path)],
            candidate_trace_paths=candidate_paths + [str(error_path)],
            runtime_metadata={
                "runtime_backend": evaluator_backend.runtime_backend,
                "proof_runtime": evaluator_backend.proof_runtime,
                "scenario_manifest_sha256": manifest["manifest_sha256"],
                "isaac_task_or_scene_id": evaluator_backend.task,
                "headless": evaluator_backend.headless,
                "device": evaluator_backend.device,
                "runtime_error_artifact": str(error_path),
            },
        )
    runtime_gate = {
        "passed": bool(baseline_rollouts and candidate_rollouts),
        "runtime_backend": evaluator_backend.runtime_backend,
        "proof_runtime": evaluator_backend.proof_runtime,
        "isaac_task_or_scene_id": evaluator_backend.task,
        "headless": evaluator_backend.headless,
        "device": evaluator_backend.device,
    }
    return BackendResult(
        runtime_backend=evaluator_backend.runtime_backend,
        proof_runtime=evaluator_backend.proof_runtime,
        runtime_gate=runtime_gate,
        baseline_rollouts=baseline_rollouts,
        candidate_rollouts=candidate_rollouts,
        baseline_trace_paths=baseline_paths,
        candidate_trace_paths=candidate_paths,
        runtime_metadata={
            "runtime_backend": evaluator_backend.runtime_backend,
            "proof_runtime": evaluator_backend.proof_runtime,
            "scenario_manifest_sha256": manifest["manifest_sha256"],
            "isaac_task_or_scene_id": evaluator_backend.task,
            "headless": evaluator_backend.headless,
            "device": evaluator_backend.device,
            "max_steps": evaluator_backend.max_steps,
            "action_scale": evaluator_backend.action_scale,
        },
    )


def run_v08a_fresh_seat_window_authority_runtime(
    *,
    output_dir: Path,
    device: str = DEFAULT_ISAAC_DEVICE,
    headless: bool = True,
    isaac_task: str = DEFAULT_ISAAC_TASK,
    max_steps: int = int(SUCCESS_METRIC["max_steps"]),
    action_scale: float = 1.0,
    min_rollouts_per_policy: int = MIN_PROOF_ROLLOUTS_PER_POLICY,
    bootstrap_iterations: int = 2000,
    bootstrap_seed: int = 23,
    backend: Any | None = None,
) -> dict[str, Any]:
    child_dir = output_dir / V08A_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    fresh_manifest = build_v08a_fresh_seat_window_authority_slice(output_dir=output_dir)
    policy_artifacts = _load_v08a_policy_artifacts(output_dir)
    baseline_policy = policy_artifacts["baseline"]
    candidate_policy = policy_artifacts["candidate"]
    selected_adapter_id = str(candidate_policy["selected_action_adapter_id"])
    policy_class = str(candidate_policy["policy_class"])
    trainer = str(candidate_policy["trainer"])
    use_single_app_actual_backend = (
        backend is None
        and getattr(IsaacConnectorInsertionEvaluatorBackend, "__name__", "")
        == "IsaacConnectorInsertionEvaluatorBackend"
    )
    evaluator_backend = backend or IsaacConnectorInsertionEvaluatorBackend(
        task=isaac_task,
        device=device,
        headless=headless,
        action_scale=action_scale,
        max_steps=max_steps,
    )
    actual_env = None
    actual_simulation_app = None
    actual_torch = None
    if use_single_app_actual_backend:
        from isaaclab.app import AppLauncher

        app_launcher = AppLauncher(
            {
                "headless": headless,
                "device": device,
                "enable_cameras": False,
            }
        )
        actual_simulation_app = app_launcher.app

        import gymnasium as gym
        import torch as torch_module

        import isaaclab_tasks  # noqa: F401
        from isaaclab_tasks.utils import parse_env_cfg

        env_cfg = parse_env_cfg(isaac_task, device=device, num_envs=1)
        actual_env = gym.make(isaac_task, cfg=env_cfg).unwrapped
        actual_torch = torch_module

    def run_runtime_manifest(
        *,
        manifest: dict[str, Any],
        runtime_output_dir: Path,
        rollouts_per_policy: int,
    ) -> BackendResult:
        if actual_env is not None:
            return _run_v08a_manifest_with_existing_isaac(
                evaluator_backend=evaluator_backend,
                env=actual_env,
                simulation_app=actual_simulation_app,
                torch_module=actual_torch,
                manifest=manifest,
                output_dir=runtime_output_dir,
                min_rollouts_per_policy=rollouts_per_policy,
                policy_artifacts=policy_artifacts,
            )
        return evaluator_backend.run(
            manifest=manifest,
            output_dir=runtime_output_dir,
            min_rollouts_per_policy=rollouts_per_policy,
            deterministic_profile="candidate_positive",
            policy_artifacts=policy_artifacts,
        )

    calibration_manifest = _v08a_runtime_manifest_for_split(
        fresh_manifest=fresh_manifest,
        split="calibration",
    )
    write_json(child_dir / "calibration_runtime_manifest_v0_8a.json", calibration_manifest)
    calibration_result = run_runtime_manifest(
        manifest=calibration_manifest,
        runtime_output_dir=child_dir / "isaac_runtime_fresh_calibration_v0_8a",
        rollouts_per_policy=V07H_CALIBRATION_ROLLOUTS_PER_POLICY,
    )
    calibration_rollout_paths = _write_v08a_calibration_external_rollouts(
        output_dir=child_dir,
        baseline_rollouts=list(calibration_result.baseline_rollouts),
        candidate_rollouts=list(calibration_result.candidate_rollouts),
    )
    calibration_trace_paths = {
        "baseline": list(calibration_result.baseline_trace_paths),
        "candidate": list(calibration_result.candidate_trace_paths),
    }
    calibration_gate = derive_v08a_calibration_presignal_gate(
        baseline_rollouts=list(calibration_result.baseline_rollouts),
        candidate_rollouts=list(calibration_result.candidate_rollouts),
        runtime_gate=dict(calibration_result.runtime_gate),
        runtime_metadata=dict(calibration_result.runtime_metadata),
        trace_paths=calibration_trace_paths,
    )
    calibration_gate["calibration_runtime_manifest_sha256"] = calibration_manifest["manifest_sha256"]
    calibration_gate["baseline_calibration_rollout_path"] = calibration_rollout_paths["baseline"]
    calibration_gate["candidate_calibration_rollout_path"] = calibration_rollout_paths["candidate"]
    calibration_gate["calibration_presignal_gate_sha256"] = _sha256_payload_excluding(
        calibration_gate,
        "calibration_presignal_gate_sha256",
    )
    write_json(child_dir / "calibration_presignal_gate_v0_8a.json", calibration_gate)
    write_json(
        output_dir / "calibration_presignal_gate.json",
        {
            "schema_version": V08A_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
            "policy_slice": V08A_POLICY_SLICE_ID,
            "slice_id": V08A_SLICE_ID,
            "passed": calibration_gate["passed"],
            "source_gate_path": f"{V08A_CHILD_OUTPUT_DIRNAME}/calibration_presignal_gate_v0_8a.json",
            "calibration_opened": True,
            "heldout_opened": False,
            "heldout_21000_21049_accessed": False,
            "fresh_heldout_24000_24049_accessed": False,
            "heldout_allowed": calibration_gate["heldout_allowed"],
            "mvp2_closed": False,
            "policy_uplift_proven": False,
        },
    )
    if calibration_gate.get("passed") is not True:
        calibration_gate["mvp2_closed"] = False
        calibration_gate["policy_uplift_proven"] = False
        if actual_env is not None:
            actual_env.close()
        return calibration_gate

    selection = _v08a_calibration_selection_report(output_dir)
    training_scenario_ids = _v08a_training_scenario_ids(output_dir)
    heldout_manifest = _v08a_runtime_manifest_for_split(
        fresh_manifest=fresh_manifest,
        split="held_out",
    )
    write_json(child_dir / "heldout_runtime_manifest_v0_8a.json", heldout_manifest)
    heldout_leakage_guard = validate_no_heldout_leakage(
        manifest=heldout_manifest,
        training_scenario_ids=training_scenario_ids,
        curation_tuning_scenario_ids=[],
        threshold_tuning_scenario_ids=[],
        hyperparameter_scenario_ids=[],
        calibration_selector_scenario_ids=[str(item) for item in selection.get("calibration_scenario_ids", [])],
    )
    if heldout_leakage_guard["passed"] is not True:
        raise ValueError("v0_8a_fresh_heldout_leakage_guard_failed")

    baseline_view = _existing_train_view(
        output_dir / "baseline_uncurated_train.hdf5",
        view_id="baseline_uncurated_mvp2c_train_view",
    )
    candidate_view = _existing_train_view(
        output_dir / "candidate_curated_train.hdf5",
        view_id="candidate_curated_mvp2c_train_view",
    )
    bridge_dir = _write_learning_harness_bridge(
        output_dir=child_dir,
        manifest=heldout_manifest,
        baseline_view=baseline_view,
        candidate_view=candidate_view,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    heldout_rollouts_per_policy = max(
        int(min_rollouts_per_policy),
        STRONGER_PUBLIC_ROLLOUTS_PER_POLICY,
        len(V08A_FRESH_HELDOUT_RANGE),
    )
    heldout_result = run_runtime_manifest(
        manifest=heldout_manifest,
        runtime_output_dir=child_dir / "isaac_runtime_fresh_heldout_v0_8a",
        rollouts_per_policy=heldout_rollouts_per_policy,
    )
    runtime_gate = dict(heldout_result.runtime_gate)
    actual_rollouts_per_policy = min(
        len(heldout_result.baseline_rollouts),
        len(heldout_result.candidate_rollouts),
    )
    runtime_gate["actual_baseline_rollouts"] = len(heldout_result.baseline_rollouts)
    runtime_gate["actual_candidate_rollouts"] = len(heldout_result.candidate_rollouts)
    runtime_gate["actual_rollouts_per_policy"] = actual_rollouts_per_policy
    if _heldout_seed_access_from_rollouts(
        list(heldout_result.baseline_rollouts) + list(heldout_result.candidate_rollouts)
    ):
        raise ValueError("v0_8a_burned_heldout_seed_accessed")
    heldout_suite = _heldout_suite(heldout_manifest)
    baseline_rollouts_path = _write_external_rollout_json(
        output_dir=child_dir,
        role="baseline",
        policy_artifact=baseline_policy,
        train_view=baseline_view,
        heldout_suite=heldout_suite,
        backend_result=heldout_result,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    candidate_rollouts_path = _write_external_rollout_json(
        output_dir=child_dir,
        role="candidate",
        policy_artifact=candidate_policy,
        train_view=candidate_view,
        heldout_suite=heldout_suite,
        backend_result=heldout_result,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    learning_report = _run_learning_validator(
        output_dir=child_dir,
        bridge_dir=bridge_dir,
        baseline_rollouts_path=baseline_rollouts_path,
        candidate_rollouts_path=candidate_rollouts_path,
        min_rollouts_per_policy=MIN_PROOF_ROLLOUTS_PER_POLICY,
        bootstrap_iterations=bootstrap_iterations,
        bootstrap_seed=bootstrap_seed,
        policy_class=policy_class,
        trainer=trainer,
    )
    train_generation_runtime_gate, train_gate_sha256 = load_v07a2_parent_train_generation_gate(output_dir)
    closure = derive_mvp2c_closure(
        learning_report=learning_report,
        runtime_gate=runtime_gate,
        train_generation_runtime_gate=train_generation_runtime_gate,
        calibration_selection_report=selection,
        heldout_leakage_guard=heldout_leakage_guard,
        actual_rollouts_per_policy=actual_rollouts_per_policy,
    )
    confidence_interval_report = _bootstrap_uplift_ci(
        baseline_rollouts=list(heldout_result.baseline_rollouts),
        candidate_rollouts=list(heldout_result.candidate_rollouts),
        iterations=bootstrap_iterations,
        seed=bootstrap_seed,
    )
    gate = {
        "schema_version": V08A_HELDOUT_CLOSURE_SCHEMA_VERSION,
        "policy_slice": V08A_POLICY_SLICE_ID,
        "slice_id": V08A_SLICE_ID,
        "parent_policy_slice": V07O_POLICY_SLICE_ID,
        "source_fresh_manifest_sha256": fresh_manifest["manifest_sha256"],
        "seat_window_authority_config_sha256": candidate_policy["seat_window_authority_config_sha256"],
        "parent_train_generation_runtime_gate_sha256": train_gate_sha256,
        "fresh_calibration_presignal_gate_sha256": calibration_gate["calibration_presignal_gate_sha256"],
        "runtime_backend": heldout_result.runtime_backend,
        "proof_runtime": heldout_result.proof_runtime,
        "runtime_gate": runtime_gate,
        "actual_rollouts_per_policy": actual_rollouts_per_policy,
        "baseline_success_rate": learning_report.get("baseline_success_rate"),
        "candidate_success_rate": learning_report.get("candidate_success_rate"),
        "curated_vs_uncurated_uplift": learning_report.get("curated_vs_uncurated_uplift"),
        "learning_report_path": str(
            child_dir / "mvp2_learning_proven_policy_eval" / "mvp2_learning_proven_report.json"
        ),
        "baseline_external_rollouts": str(baseline_rollouts_path),
        "candidate_external_rollouts": str(candidate_rollouts_path),
        "confidence_interval_report": confidence_interval_report,
        "stronger_public_evidence_target_passed": _derive_public_evidence_target(
            actual_rollouts_per_policy=actual_rollouts_per_policy,
            confidence_interval_report=confidence_interval_report,
        ),
        "calibration_opened": True,
        "heldout_opened": True,
        "heldout_21000_21049_accessed": False,
        "fresh_calibration_23000_23029_accessed": True,
        "fresh_heldout_24000_24049_accessed": True,
        "same_heldout_reuse_allowed_for_closure": False,
        "heldout_leakage_guard": heldout_leakage_guard,
        "calibration_selection_report_sha256": _sha256_file(output_dir / "calibration_selection_report.json"),
        "selected_action_adapter_id": selected_adapter_id,
        "same_adapter_used_for_baseline_and_candidate": True,
        "same_policy_class": baseline_policy.get("policy_class") == candidate_policy.get("policy_class"),
        "same_trainer": baseline_policy.get("trainer") == candidate_policy.get("trainer"),
        "same_feature_schema": baseline_policy.get("feature_schema") == candidate_policy.get("feature_schema"),
        "mvp2_closed": closure["mvp2_closed"],
        "mvp2c_close_minimum_passed": closure["mvp2c_close_minimum_passed"],
        "policy_uplift_proven": closure["learning_proven"],
        "proof_eligible": closure["proof_eligible"],
        "blockers": closure["blockers"] + list(learning_report.get("blockers") or []),
        "non_claims": {
            "deployable_real_robot_policy": False,
            "visual_policy_performance": False,
            "real_robot_success": False,
            "physical_robot_readiness": False,
            "universal_robot_support": False,
            "hmd_openxr_readiness": False,
        },
    }
    gate["heldout_closure_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "heldout_closure_gate_sha256",
    )
    write_json(child_dir / "heldout_closure_gate_v0_8a.json", gate)
    write_json(output_dir / "heldout_closure_gate.json", gate)
    if actual_env is not None:
        actual_env.close()
    return gate


def _v08b_burned_heldout_seed_range_accessed(seed: int) -> bool:
    return _protected_heldout_seed_range_accessed(seed) or int(seed) in V08A_FRESH_HELDOUT_RANGE


def load_required_v08a_failed_heldout_gate(output_dir: Path) -> tuple[dict[str, Any], str]:
    gate_path = output_dir / V08A_CHILD_OUTPUT_DIRNAME / "heldout_closure_gate_v0_8a.json"
    if not gate_path.exists():
        raise ValueError("missing_v0_8a_failed_heldout_gate")
    gate = read_json(gate_path)
    if (
        gate.get("policy_slice") != V08A_POLICY_SLICE_ID
        or gate.get("slice_id") != V08A_SLICE_ID
        or gate.get("runtime_backend") != "isaac_runtime"
        or gate.get("heldout_opened") is not True
        or gate.get("fresh_heldout_24000_24049_accessed") is not True
        or gate.get("same_heldout_reuse_allowed_for_closure") is not False
        or gate.get("mvp2_closed") is not False
        or gate.get("policy_uplift_proven") is not False
    ):
        raise ValueError("invalid_v0_8a_failed_heldout_gate")
    gate["path"] = str(gate_path)
    gate["sha256"] = _sha256_file(gate_path)
    return gate, gate["sha256"]


def derive_v08b_scenario_aware_seat_window_authority_config(*, output_dir: Path) -> dict[str, Any]:
    failed_gate, failed_gate_sha256 = load_required_v08a_failed_heldout_gate(output_dir)
    parent_config_path = output_dir / V08A_CHILD_OUTPUT_DIRNAME / "v0_8a_seat_window_authority_config.json"
    if not parent_config_path.exists():
        raise ValueError("missing_v0_8a_seat_window_authority_config")
    parent_config = read_json(parent_config_path)
    if parent_config.get("policy_slice") != V08A_POLICY_SLICE_ID:
        raise ValueError("invalid_v0_8a_seat_window_authority_config")
    latest_z_open_step = int(parent_config["latest_z_open_step"])
    config: dict[str, Any] = {
        "schema_version": V08B_SEAT_WINDOW_AUTHORITY_CONFIG_SCHEMA_VERSION,
        "seat_window_authority_id": V08B_SEAT_WINDOW_AUTHORITY_ID,
        "policy_slice": V08B_POLICY_SLICE_ID,
        "parent_policy_slice": V08A_POLICY_SLICE_ID,
        "slice_id": V08B_SLICE_ID,
        "source": "v0_8a_failed_heldout_diagnosis_plus_train_generation_success_traces",
        "parent_v08a_seat_window_authority_config_sha256": parent_config[
            "seat_window_authority_config_sha256"
        ],
        "source_v08a_failed_heldout_gate_sha256": failed_gate_sha256,
        "source_v08a_curated_vs_uncurated_uplift": failed_gate.get("curated_vs_uncurated_uplift"),
        "latest_z_open_step_train_max": latest_z_open_step,
        "scenario_aware_deadline_step": V08B_SCENARIO_AWARE_DEADLINE_STEP,
        "seat_window_required_steps": int(V06_ENV_NATIVE_SUCCESS_AUTHORITY["stable_steps_required"]),
        "terminal_guard_steps": V08B_TERMINAL_GUARD_STEPS,
        "descent_latency_steps_p95": V08B_DESCENT_LATENCY_STEPS_P95,
        "scenario_aware_deadline_formula": (
            "max_steps_minus_stable_window_minus_terminal_guard_minus_descent_latency_p95"
        ),
        "z_open_centering_lateral_m": V07N_Z_OPEN_CENTERING_LATERAL_M,
        "seat_region_depth_m": V08A_SEAT_REGION_DEPTH_M,
        "z_progress_action": V08A_Z_PROGRESS_ACTION,
        "candidate_specific": False,
        "baseline_specific": False,
        "proof_authority": False,
        "fresh_calibration_seed_range": [min(V08B_FRESH_CALIBRATION_RANGE), max(V08B_FRESH_CALIBRATION_RANGE)],
        "fresh_heldout_seed_range": [min(V08B_FRESH_HELDOUT_RANGE), max(V08B_FRESH_HELDOUT_RANGE)],
        "burned_heldout_seed_ranges": [
            list(V07A2_PROTECTED_HELDOUT_SEED_RANGE),
            [min(V08A_FRESH_HELDOUT_RANGE), max(V08A_FRESH_HELDOUT_RANGE)],
        ],
        "heldout_21000_21049_used_for_parameter_derivation": False,
        "heldout_24000_24049_used_for_parameter_derivation": False,
        "source_diagnostic_heldout_21000_21049_accessed": True,
        "source_diagnostic_heldout_24000_24049_accessed": True,
    }
    config["seat_window_authority_config_sha256"] = _sha256_payload_excluding(
        config,
        "seat_window_authority_config_sha256",
    )
    return config


def build_v08b_fresh_manifest(*, output_dir: Path, failed_gate: dict[str, Any]) -> dict[str, Any]:
    calibration_rows = [_scenario_row(split="calibration", seed=seed) for seed in V08B_FRESH_CALIBRATION_RANGE]
    heldout_rows = [_scenario_row(split="held_out", seed=seed) for seed in V08B_FRESH_HELDOUT_RANGE]
    for row in calibration_rows + heldout_rows:
        if _v08b_burned_heldout_seed_range_accessed(int(row["seed"])):
            raise ValueError("v0_8b_fresh_manifest_reuses_burned_heldout")
    manifest = {
        "schema_version": V08B_MANIFEST_SCHEMA_VERSION,
        "policy_slice": V08B_POLICY_SLICE_ID,
        "slice_id": V08B_SLICE_ID,
        "parent_policy_slice": V08A_POLICY_SLICE_ID,
        "scenario_profile": "v0_8b",
        "task_type": "connector_insertion",
        "success_metric": SUCCESS_METRIC,
        "success_authority": V06_ENV_NATIVE_SUCCESS_AUTHORITY,
        "source_v08a_failed_heldout_gate_sha256": failed_gate["sha256"],
        "scenarios": calibration_rows + heldout_rows,
        "fresh_split_manifest": {
            "calibration": {
                "seed_range": [min(V08B_FRESH_CALIBRATION_RANGE), max(V08B_FRESH_CALIBRATION_RANGE)],
                "scenario_ids": [row["scenario_id"] for row in calibration_rows],
                "count": len(calibration_rows),
            },
            "held_out": {
                "seed_range": [min(V08B_FRESH_HELDOUT_RANGE), max(V08B_FRESH_HELDOUT_RANGE)],
                "scenario_ids": [row["scenario_id"] for row in heldout_rows],
                "count": len(heldout_rows),
            },
        },
        "burned_heldout_seed_ranges": [
            list(V07A2_PROTECTED_HELDOUT_SEED_RANGE),
            [min(V08A_FRESH_HELDOUT_RANGE), max(V08A_FRESH_HELDOUT_RANGE)],
        ],
        "heldout_21000_21049_accessed": False,
        "fresh_heldout_24000_24049_accessed": False,
        "fresh_heldout_24000_24049_reuse_allowed_for_closure": False,
        "fresh_heldout_26000_26049_accessed": False,
        "calibration_opened": False,
        "heldout_opened": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    manifest["manifest_sha256"] = _sha256_payload_excluding(manifest, "manifest_sha256")
    return manifest


def build_v08b_policy_artifact_payload(
    *,
    base_policy_artifact: dict[str, Any],
    seat_window_authority_config: dict[str, Any],
    dataset_view_role: str,
) -> dict[str, Any]:
    role = "candidate" if dataset_view_role == "candidate_curated" else "baseline"
    payload = {
        key: value
        for key, value in base_policy_artifact.items()
        if key not in {"path", "policy_artifact_sha256"}
    }
    payload.update(
        {
            "schema_version": V08B_POLICY_ARTIFACT_SCHEMA_VERSION,
            "policy_id": f"{role}_mvp2e_v08b_scenario_aware_seat_window_authority_policy",
            "policy_slice": V08B_POLICY_SLICE_ID,
            "slice_id": V08B_SLICE_ID,
            "parent_policy_slice": V08A_POLICY_SLICE_ID,
            "parent_policy_artifact_sha256": base_policy_artifact.get("policy_artifact_sha256"),
            "dataset_view_role": dataset_view_role,
            "seat_window_authority_id": V08B_SEAT_WINDOW_AUTHORITY_ID,
            "seat_window_authority_config": seat_window_authority_config,
            "seat_window_authority_config_sha256": seat_window_authority_config[
                "seat_window_authority_config_sha256"
            ],
            "same_seat_window_authority_config_as_peer": True,
            "source_diagnostic_heldout_21000_21049_accessed": True,
            "source_diagnostic_heldout_24000_24049_accessed": True,
            "heldout_21000_21049_accessed": False,
            "fresh_heldout_24000_24049_accessed": False,
            "fresh_calibration_25000_25029_accessed": False,
            "fresh_heldout_26000_26049_accessed": False,
            "mvp2_closed": False,
            "policy_uplift_proven": False,
        }
    )
    payload["policy_artifact_sha256"] = _sha256_payload_excluding(payload, "policy_artifact_sha256")
    return payload


def build_v08b_scenario_aware_seat_window_authority_slice(*, output_dir: Path) -> dict[str, Any]:
    failed_gate, _failed_gate_sha256 = load_required_v08a_failed_heldout_gate(output_dir)
    policy_artifacts = _load_v08a_policy_artifacts(output_dir)
    child_dir = output_dir / V08B_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    seat_window_config = derive_v08b_scenario_aware_seat_window_authority_config(output_dir=output_dir)
    write_json(child_dir / "v0_8b_seat_window_authority_config.json", seat_window_config)
    candidate_policy = build_v08b_policy_artifact_payload(
        base_policy_artifact=policy_artifacts["candidate"],
        seat_window_authority_config=seat_window_config,
        dataset_view_role="candidate_curated",
    )
    baseline_policy = build_v08b_policy_artifact_payload(
        base_policy_artifact=policy_artifacts["baseline"],
        seat_window_authority_config=seat_window_config,
        dataset_view_role="baseline_uncurated",
    )
    write_json(child_dir / "candidate_policy_artifact_v0_8b.json", candidate_policy)
    write_json(child_dir / "baseline_policy_artifact_v0_8b.json", baseline_policy)
    manifest = build_v08b_fresh_manifest(output_dir=output_dir, failed_gate=failed_gate)
    manifest.update(
        {
            "seat_window_authority_id": V08B_SEAT_WINDOW_AUTHORITY_ID,
            "seat_window_authority_config_sha256": seat_window_config[
                "seat_window_authority_config_sha256"
            ],
            "candidate_policy_artifact_sha256": candidate_policy["policy_artifact_sha256"],
            "baseline_policy_artifact_sha256": baseline_policy["policy_artifact_sha256"],
            "same_seat_window_authority_config_as_peer": (
                candidate_policy["seat_window_authority_config_sha256"]
                == baseline_policy["seat_window_authority_config_sha256"]
            ),
            "artifacts": {
                "seat_window_authority_config": (
                    f"{V08B_CHILD_OUTPUT_DIRNAME}/v0_8b_seat_window_authority_config.json"
                ),
                "candidate_policy_artifact": (
                    f"{V08B_CHILD_OUTPUT_DIRNAME}/candidate_policy_artifact_v0_8b.json"
                ),
                "baseline_policy_artifact": (
                    f"{V08B_CHILD_OUTPUT_DIRNAME}/baseline_policy_artifact_v0_8b.json"
                ),
            },
        }
    )
    manifest["manifest_sha256"] = _sha256_payload_excluding(manifest, "manifest_sha256")
    write_json(child_dir / "v0_8b_fresh_manifest.json", manifest)
    return manifest


def _load_v08b_policy_artifacts(output_dir: Path) -> dict[str, dict[str, Any]]:
    child_dir = output_dir / V08B_CHILD_OUTPUT_DIRNAME
    candidate_path = child_dir / "candidate_policy_artifact_v0_8b.json"
    baseline_path = child_dir / "baseline_policy_artifact_v0_8b.json"
    if not candidate_path.exists() or not baseline_path.exists():
        raise ValueError("missing_v0_8b_policy_artifacts")
    baseline = read_json(baseline_path)
    candidate = read_json(candidate_path)
    reasons: list[str] = []
    for role, policy in (("baseline", baseline), ("candidate", candidate)):
        if policy.get("policy_slice") != V08B_POLICY_SLICE_ID:
            reasons.append(f"{role}_policy_slice_mismatch")
        if policy.get("parent_policy_slice") != V08A_POLICY_SLICE_ID:
            reasons.append(f"{role}_parent_policy_slice_mismatch")
        if policy.get("heldout_21000_21049_accessed") is not False:
            reasons.append(f"{role}_burned_heldout_accessed")
        if policy.get("fresh_heldout_24000_24049_accessed") is not False:
            reasons.append(f"{role}_v08a_fresh_heldout_reused")
        if policy.get("fresh_heldout_26000_26049_accessed") is not False:
            reasons.append(f"{role}_fresh_heldout_accessed_before_closure")
        expected_hash = _sha256_payload_excluding(policy, "policy_artifact_sha256")
        if policy.get("policy_artifact_sha256") != expected_hash:
            reasons.append(f"{role}_policy_hash_mismatch")
    equality_keys = (
        "selected_action_adapter_id",
        "trainer",
        "trainer_family",
        "policy_class",
        "feature_schema",
        "feature_schema_version",
        "phase_schema",
        "final_post_adapter_authority_config_sha256",
        "final_post_adapter_xy_authority_config_sha256",
        "base_servo_config_sha256",
        "shared_hysteresis_authority_config_sha256",
        "seat_window_authority_config_sha256",
    )
    for key in equality_keys:
        if baseline.get(key) != candidate.get(key):
            reasons.append(f"peer_{key}_mismatch")
    if reasons:
        raise ValueError("v0_8b_policy_peer_fairness_failed: " + ",".join(reasons))
    return {
        "baseline": {**baseline, "path": str(baseline_path)},
        "candidate": {**candidate, "path": str(candidate_path)},
    }


def _v08b_runtime_manifest_for_split(*, fresh_manifest: dict[str, Any], split: str) -> dict[str, Any]:
    if split not in {"calibration", "held_out"}:
        raise ValueError("v0_8b_runtime_manifest_unknown_split")
    rows = [
        {**row, "source_split": split, "semantic_eval_split": split, "split": "held_out"}
        for row in fresh_manifest.get("scenarios", [])
        if isinstance(row, dict) and row.get("split") == split
    ]
    if not rows:
        raise ValueError(f"v0_8b_runtime_manifest_missing_{split}_rows")
    seeds = [int(row["seed"]) for row in rows]
    if any(_v08b_burned_heldout_seed_range_accessed(seed) for seed in seeds):
        raise ValueError("v0_8b_runtime_manifest_reuses_burned_heldout")
    if split == "calibration" and seeds != list(V08B_FRESH_CALIBRATION_RANGE):
        raise ValueError("v0_8b_calibration_seed_range_mismatch")
    if split == "held_out" and seeds != list(V08B_FRESH_HELDOUT_RANGE):
        raise ValueError("v0_8b_heldout_seed_range_mismatch")
    manifest = {
        "schema_version": fresh_manifest["schema_version"],
        "policy_slice": V08B_POLICY_SLICE_ID,
        "slice_id": V08B_SLICE_ID,
        "parent_policy_slice": V08A_POLICY_SLICE_ID,
        "scenario_profile": "v0_8b",
        "runtime_split": split,
        "task_type": fresh_manifest["task_type"],
        "success_metric": fresh_manifest["success_metric"],
        "success_authority": fresh_manifest["success_authority"],
        "source_fresh_manifest_sha256": fresh_manifest["manifest_sha256"],
        "scenarios": rows,
        "burned_heldout_seed_ranges": fresh_manifest["burned_heldout_seed_ranges"],
        "heldout_21000_21049_accessed": False,
        "fresh_heldout_24000_24049_accessed": False,
        "fresh_calibration_25000_25029_accessed": split == "calibration",
        "fresh_heldout_26000_26049_accessed": split == "held_out",
        "calibration_opened": split == "calibration",
        "heldout_opened": split == "held_out",
        "proof_authority": split == "held_out",
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    manifest["manifest_sha256"] = _sha256_payload_excluding(manifest, "manifest_sha256")
    return manifest


def _write_v08b_calibration_external_rollouts(
    *,
    output_dir: Path,
    baseline_rollouts: list[dict[str, Any]],
    candidate_rollouts: list[dict[str, Any]],
) -> dict[str, str]:
    rollout_dir = output_dir / "calibration_external_rollouts"
    rollout_dir.mkdir(parents=True, exist_ok=True)
    baseline_path = rollout_dir / "baseline_calibration_rollouts_v0_8b.json"
    candidate_path = rollout_dir / "candidate_calibration_rollouts_v0_8b.json"
    write_json(baseline_path, baseline_rollouts)
    write_json(candidate_path, candidate_rollouts)
    return {
        "baseline": str(baseline_path),
        "candidate": str(candidate_path),
    }


def derive_v08b_calibration_presignal_gate(
    *,
    baseline_rollouts: list[dict[str, Any]],
    candidate_rollouts: list[dict[str, Any]],
    runtime_gate: dict[str, Any],
    runtime_metadata: dict[str, Any],
    trace_paths: dict[str, list[str]],
) -> dict[str, Any]:
    gate = derive_v07h_calibration_presignal_gate(
        baseline_rollouts=baseline_rollouts,
        candidate_rollouts=candidate_rollouts,
        runtime_gate=runtime_gate,
        runtime_metadata=runtime_metadata,
        trace_paths=trace_paths,
        output_dir=Path("."),
    )
    gate.update(
        {
            "schema_version": V08B_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
            "policy_slice": V08B_POLICY_SLICE_ID,
            "slice_id": V08B_SLICE_ID,
            "parent_policy_slice": V08A_POLICY_SLICE_ID,
            "fresh_calibration_25000_25029_accessed": True,
            "fresh_heldout_26000_26049_accessed": False,
            "fresh_heldout_24000_24049_accessed": False,
            "source": "v0_8b_fresh_calibration_runtime",
        }
    )
    gate["calibration_presignal_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "calibration_presignal_gate_sha256",
    )
    return gate


def run_v08b_scenario_aware_seat_window_authority_runtime(
    *,
    output_dir: Path,
    device: str = DEFAULT_ISAAC_DEVICE,
    headless: bool = True,
    isaac_task: str = DEFAULT_ISAAC_TASK,
    max_steps: int = int(SUCCESS_METRIC["max_steps"]),
    action_scale: float = 1.0,
    min_rollouts_per_policy: int = MIN_PROOF_ROLLOUTS_PER_POLICY,
    bootstrap_iterations: int = 2000,
    bootstrap_seed: int = 23,
    backend: Any | None = None,
) -> dict[str, Any]:
    child_dir = output_dir / V08B_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    fresh_manifest = build_v08b_scenario_aware_seat_window_authority_slice(output_dir=output_dir)
    policy_artifacts = _load_v08b_policy_artifacts(output_dir)
    baseline_policy = policy_artifacts["baseline"]
    candidate_policy = policy_artifacts["candidate"]
    selected_adapter_id = str(candidate_policy["selected_action_adapter_id"])
    policy_class = str(candidate_policy["policy_class"])
    trainer = str(candidate_policy["trainer"])
    use_single_app_actual_backend = (
        backend is None
        and getattr(IsaacConnectorInsertionEvaluatorBackend, "__name__", "")
        == "IsaacConnectorInsertionEvaluatorBackend"
    )
    evaluator_backend = backend or IsaacConnectorInsertionEvaluatorBackend(
        task=isaac_task,
        device=device,
        headless=headless,
        action_scale=action_scale,
        max_steps=max_steps,
    )
    actual_env = None
    actual_simulation_app = None
    actual_torch = None
    if use_single_app_actual_backend:
        from isaaclab.app import AppLauncher

        app_launcher = AppLauncher(
            {
                "headless": headless,
                "device": device,
                "enable_cameras": False,
            }
        )
        actual_simulation_app = app_launcher.app

        import gymnasium as gym
        import torch as torch_module

        import isaaclab_tasks  # noqa: F401
        from isaaclab_tasks.utils import parse_env_cfg

        env_cfg = parse_env_cfg(isaac_task, device=device, num_envs=1)
        actual_env = gym.make(isaac_task, cfg=env_cfg).unwrapped
        actual_torch = torch_module

    def run_runtime_manifest(
        *,
        manifest: dict[str, Any],
        runtime_output_dir: Path,
        rollouts_per_policy: int,
    ) -> BackendResult:
        if actual_env is not None:
            return _run_v08a_manifest_with_existing_isaac(
                evaluator_backend=evaluator_backend,
                env=actual_env,
                simulation_app=actual_simulation_app,
                torch_module=actual_torch,
                manifest=manifest,
                output_dir=runtime_output_dir,
                min_rollouts_per_policy=rollouts_per_policy,
                policy_artifacts=policy_artifacts,
            )
        return evaluator_backend.run(
            manifest=manifest,
            output_dir=runtime_output_dir,
            min_rollouts_per_policy=rollouts_per_policy,
            deterministic_profile="candidate_positive",
            policy_artifacts=policy_artifacts,
        )

    calibration_manifest = _v08b_runtime_manifest_for_split(
        fresh_manifest=fresh_manifest,
        split="calibration",
    )
    write_json(child_dir / "calibration_runtime_manifest_v0_8b.json", calibration_manifest)
    calibration_result = run_runtime_manifest(
        manifest=calibration_manifest,
        runtime_output_dir=child_dir / "isaac_runtime_fresh_calibration_v0_8b",
        rollouts_per_policy=V07H_CALIBRATION_ROLLOUTS_PER_POLICY,
    )
    calibration_rollout_paths = _write_v08b_calibration_external_rollouts(
        output_dir=child_dir,
        baseline_rollouts=list(calibration_result.baseline_rollouts),
        candidate_rollouts=list(calibration_result.candidate_rollouts),
    )
    calibration_trace_paths = {
        "baseline": list(calibration_result.baseline_trace_paths),
        "candidate": list(calibration_result.candidate_trace_paths),
    }
    calibration_gate = derive_v08b_calibration_presignal_gate(
        baseline_rollouts=list(calibration_result.baseline_rollouts),
        candidate_rollouts=list(calibration_result.candidate_rollouts),
        runtime_gate=dict(calibration_result.runtime_gate),
        runtime_metadata=dict(calibration_result.runtime_metadata),
        trace_paths=calibration_trace_paths,
    )
    calibration_gate["calibration_runtime_manifest_sha256"] = calibration_manifest["manifest_sha256"]
    calibration_gate["baseline_calibration_rollout_path"] = calibration_rollout_paths["baseline"]
    calibration_gate["candidate_calibration_rollout_path"] = calibration_rollout_paths["candidate"]
    calibration_gate["calibration_presignal_gate_sha256"] = _sha256_payload_excluding(
        calibration_gate,
        "calibration_presignal_gate_sha256",
    )
    write_json(child_dir / "calibration_presignal_gate_v0_8b.json", calibration_gate)
    write_json(
        output_dir / "calibration_presignal_gate.json",
        {
            "schema_version": V08B_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
            "policy_slice": V08B_POLICY_SLICE_ID,
            "slice_id": V08B_SLICE_ID,
            "passed": calibration_gate["passed"],
            "source_gate_path": f"{V08B_CHILD_OUTPUT_DIRNAME}/calibration_presignal_gate_v0_8b.json",
            "calibration_opened": True,
            "heldout_opened": False,
            "heldout_21000_21049_accessed": False,
            "fresh_heldout_24000_24049_accessed": False,
            "fresh_heldout_26000_26049_accessed": False,
            "heldout_allowed": calibration_gate["heldout_allowed"],
            "mvp2_closed": False,
            "policy_uplift_proven": False,
        },
    )
    if calibration_gate.get("passed") is not True:
        calibration_gate["mvp2_closed"] = False
        calibration_gate["policy_uplift_proven"] = False
        if actual_env is not None:
            actual_env.close()
        return calibration_gate

    selection = _v08a_calibration_selection_report(output_dir)
    training_scenario_ids = _v08a_training_scenario_ids(output_dir)
    heldout_manifest = _v08b_runtime_manifest_for_split(
        fresh_manifest=fresh_manifest,
        split="held_out",
    )
    write_json(child_dir / "heldout_runtime_manifest_v0_8b.json", heldout_manifest)
    heldout_leakage_guard = validate_no_heldout_leakage(
        manifest=heldout_manifest,
        training_scenario_ids=training_scenario_ids,
        curation_tuning_scenario_ids=[],
        threshold_tuning_scenario_ids=[],
        hyperparameter_scenario_ids=[],
        calibration_selector_scenario_ids=[str(item) for item in selection.get("calibration_scenario_ids", [])],
    )
    if heldout_leakage_guard["passed"] is not True:
        raise ValueError("v0_8b_fresh_heldout_leakage_guard_failed")

    baseline_view = _existing_train_view(
        output_dir / "baseline_uncurated_train.hdf5",
        view_id="baseline_uncurated_mvp2c_train_view",
    )
    candidate_view = _existing_train_view(
        output_dir / "candidate_curated_train.hdf5",
        view_id="candidate_curated_mvp2c_train_view",
    )
    bridge_dir = _write_learning_harness_bridge(
        output_dir=child_dir,
        manifest=heldout_manifest,
        baseline_view=baseline_view,
        candidate_view=candidate_view,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    heldout_rollouts_per_policy = max(
        int(min_rollouts_per_policy),
        STRONGER_PUBLIC_ROLLOUTS_PER_POLICY,
        len(V08B_FRESH_HELDOUT_RANGE),
    )
    heldout_result = run_runtime_manifest(
        manifest=heldout_manifest,
        runtime_output_dir=child_dir / "isaac_runtime_fresh_heldout_v0_8b",
        rollouts_per_policy=heldout_rollouts_per_policy,
    )
    runtime_gate = dict(heldout_result.runtime_gate)
    actual_rollouts_per_policy = min(
        len(heldout_result.baseline_rollouts),
        len(heldout_result.candidate_rollouts),
    )
    runtime_gate["actual_baseline_rollouts"] = len(heldout_result.baseline_rollouts)
    runtime_gate["actual_candidate_rollouts"] = len(heldout_result.candidate_rollouts)
    runtime_gate["actual_rollouts_per_policy"] = actual_rollouts_per_policy
    if _heldout_seed_access_from_rollouts(
        list(heldout_result.baseline_rollouts) + list(heldout_result.candidate_rollouts)
    ):
        raise ValueError("v0_8b_burned_heldout_seed_accessed")
    if any(
        int(rollout.get("seed", -1)) in V08A_FRESH_HELDOUT_RANGE
        for rollout in list(heldout_result.baseline_rollouts) + list(heldout_result.candidate_rollouts)
    ):
        raise ValueError("v0_8b_reused_v08a_fresh_heldout_seed")
    heldout_suite = _heldout_suite(heldout_manifest)
    baseline_rollouts_path = _write_external_rollout_json(
        output_dir=child_dir,
        role="baseline",
        policy_artifact=baseline_policy,
        train_view=baseline_view,
        heldout_suite=heldout_suite,
        backend_result=heldout_result,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    candidate_rollouts_path = _write_external_rollout_json(
        output_dir=child_dir,
        role="candidate",
        policy_artifact=candidate_policy,
        train_view=candidate_view,
        heldout_suite=heldout_suite,
        backend_result=heldout_result,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    learning_report = _run_learning_validator(
        output_dir=child_dir,
        bridge_dir=bridge_dir,
        baseline_rollouts_path=baseline_rollouts_path,
        candidate_rollouts_path=candidate_rollouts_path,
        min_rollouts_per_policy=MIN_PROOF_ROLLOUTS_PER_POLICY,
        bootstrap_iterations=bootstrap_iterations,
        bootstrap_seed=bootstrap_seed,
        policy_class=policy_class,
        trainer=trainer,
    )
    train_generation_runtime_gate, train_gate_sha256 = load_v07a2_parent_train_generation_gate(output_dir)
    closure = derive_mvp2c_closure(
        learning_report=learning_report,
        runtime_gate=runtime_gate,
        train_generation_runtime_gate=train_generation_runtime_gate,
        calibration_selection_report=selection,
        heldout_leakage_guard=heldout_leakage_guard,
        actual_rollouts_per_policy=actual_rollouts_per_policy,
    )
    confidence_interval_report = _bootstrap_uplift_ci(
        baseline_rollouts=list(heldout_result.baseline_rollouts),
        candidate_rollouts=list(heldout_result.candidate_rollouts),
        iterations=bootstrap_iterations,
        seed=bootstrap_seed,
    )
    gate = {
        "schema_version": V08B_HELDOUT_CLOSURE_SCHEMA_VERSION,
        "policy_slice": V08B_POLICY_SLICE_ID,
        "slice_id": V08B_SLICE_ID,
        "parent_policy_slice": V08A_POLICY_SLICE_ID,
        "source_fresh_manifest_sha256": fresh_manifest["manifest_sha256"],
        "seat_window_authority_config_sha256": candidate_policy["seat_window_authority_config_sha256"],
        "parent_train_generation_runtime_gate_sha256": train_gate_sha256,
        "fresh_calibration_presignal_gate_sha256": calibration_gate["calibration_presignal_gate_sha256"],
        "runtime_backend": heldout_result.runtime_backend,
        "proof_runtime": heldout_result.proof_runtime,
        "runtime_gate": runtime_gate,
        "actual_rollouts_per_policy": actual_rollouts_per_policy,
        "baseline_success_rate": learning_report.get("baseline_success_rate"),
        "candidate_success_rate": learning_report.get("candidate_success_rate"),
        "curated_vs_uncurated_uplift": learning_report.get("curated_vs_uncurated_uplift"),
        "learning_report_path": str(
            child_dir / "mvp2_learning_proven_policy_eval" / "mvp2_learning_proven_report.json"
        ),
        "baseline_external_rollouts": str(baseline_rollouts_path),
        "candidate_external_rollouts": str(candidate_rollouts_path),
        "confidence_interval_report": confidence_interval_report,
        "stronger_public_evidence_target_passed": _derive_public_evidence_target(
            actual_rollouts_per_policy=actual_rollouts_per_policy,
            confidence_interval_report=confidence_interval_report,
        ),
        "calibration_opened": True,
        "heldout_opened": True,
        "heldout_21000_21049_accessed": False,
        "fresh_heldout_24000_24049_accessed": False,
        "fresh_calibration_25000_25029_accessed": True,
        "fresh_heldout_26000_26049_accessed": True,
        "same_heldout_reuse_allowed_for_closure": False,
        "heldout_leakage_guard": heldout_leakage_guard,
        "calibration_selection_report_sha256": _sha256_file(output_dir / "calibration_selection_report.json"),
        "selected_action_adapter_id": selected_adapter_id,
        "same_adapter_used_for_baseline_and_candidate": True,
        "same_policy_class": baseline_policy.get("policy_class") == candidate_policy.get("policy_class"),
        "same_trainer": baseline_policy.get("trainer") == candidate_policy.get("trainer"),
        "same_feature_schema": baseline_policy.get("feature_schema") == candidate_policy.get("feature_schema"),
        "mvp2_closed": closure["mvp2_closed"],
        "mvp2c_close_minimum_passed": closure["mvp2c_close_minimum_passed"],
        "policy_uplift_proven": closure["learning_proven"],
        "proof_eligible": closure["proof_eligible"],
        "blockers": closure["blockers"] + list(learning_report.get("blockers") or []),
        "non_claims": {
            "deployable_real_robot_policy": False,
            "visual_policy_performance": False,
            "real_robot_success": False,
            "physical_robot_readiness": False,
            "universal_robot_support": False,
            "hmd_openxr_readiness": False,
        },
    }
    gate["heldout_closure_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "heldout_closure_gate_sha256",
    )
    write_json(child_dir / "heldout_closure_gate_v0_8b.json", gate)
    write_json(output_dir / "heldout_closure_gate.json", gate)
    if actual_env is not None:
        actual_env.close()
    return gate


def load_required_v08b_failed_heldout_gate(output_dir: Path) -> tuple[dict[str, Any], str]:
    gate_path = output_dir / V08B_CHILD_OUTPUT_DIRNAME / "heldout_closure_gate_v0_8b.json"
    if not gate_path.exists():
        raise ValueError("missing_v0_8b_heldout_closure_gate")
    gate = read_json(gate_path)
    if (
        gate.get("policy_slice") != V08B_POLICY_SLICE_ID
        or gate.get("slice_id") != V08B_SLICE_ID
        or gate.get("runtime_backend") != "isaac_runtime"
        or gate.get("heldout_opened") is not True
        or gate.get("fresh_heldout_26000_26049_accessed") is not True
        or gate.get("mvp2_closed") is not False
        or gate.get("policy_uplift_proven") is not False
        or int(gate.get("actual_rollouts_per_policy") or 0) != 50
    ):
        raise ValueError("invalid_v0_8b_failed_heldout_gate")
    gate["path"] = str(gate_path)
    gate["sha256"] = _sha256_file(gate_path)
    return gate, gate["sha256"]


def load_required_v08b_seat_window_config(output_dir: Path) -> tuple[dict[str, Any], str]:
    config_path = output_dir / V08B_CHILD_OUTPUT_DIRNAME / "v0_8b_seat_window_authority_config.json"
    if not config_path.exists():
        raise ValueError("missing_v0_8b_seat_window_authority_config")
    config = read_json(config_path)
    if (
        config.get("policy_slice") != V08B_POLICY_SLICE_ID
        or config.get("slice_id") != V08B_SLICE_ID
        or config.get("seat_window_authority_id") != V08B_SEAT_WINDOW_AUTHORITY_ID
    ):
        raise ValueError("invalid_v0_8b_seat_window_authority_config")
    config["path"] = str(config_path)
    config["sha256"] = _sha256_file(config_path)
    return config, config["sha256"]


def _load_v08b_heldout_trace_rows(output_dir: Path) -> list[dict[str, Any]]:
    trace_dir = (
        output_dir
        / V08B_CHILD_OUTPUT_DIRNAME
        / "isaac_runtime_fresh_heldout_v0_8b"
        / "isaac_runtime_heldout_rollout_traces"
    )
    if not trace_dir.exists():
        raise ValueError("missing_v0_8b_heldout_trace_dir")
    rows: list[dict[str, Any]] = []
    for path in sorted(trace_dir.glob("*.json")):
        payload = read_json(path)
        scenario = payload.get("scenario") if isinstance(payload.get("scenario"), dict) else {}
        summary = payload.get("summary") if isinstance(payload.get("summary"), dict) else {}
        trace = payload.get("trace") if isinstance(payload.get("trace"), list) else []
        role = str(payload.get("policy_role") or payload.get("role") or path.name.split("_")[0])
        seed = scenario.get("seed")
        if seed is None:
            scenario_id = str(scenario.get("scenario_id") or path.name)
            match = re.search(r"held_out_(\d+)", scenario_id)
            seed = int(match.group(1)) if match else None
        if role not in {"baseline", "candidate"} or seed is None:
            continue
        rows.append(
            {
                "role": role,
                "seed": int(seed),
                "scenario_id": str(scenario.get("scenario_id") or f"held_out_{int(seed)}"),
                "summary": summary,
                "trace": trace,
                "trace_path": str(path),
                "success": _rollout_success_from_summary(summary),
            }
        )
    if len(rows) != 100:
        raise ValueError(f"v0_8c_requires_100_v0_8b_heldout_traces_got_{len(rows)}")
    return rows


def _v08c_trace_metrics(summary: dict[str, Any], trace: list[dict[str, Any]]) -> dict[str, Any]:
    z_count = 0
    z_first: int | None = None
    z_last: int | None = None
    z_longest = 0
    current_z = 0
    forced_count = 0
    max_depth = 0.0
    min_lateral = math.inf
    final_depth = 0.0
    final_lateral = math.inf
    for row in trace:
        step = int(row.get("step") or 0)
        action = row.get("normalized_action") if isinstance(row.get("normalized_action"), list) else []
        z_action = float(action[2]) if len(action) > 2 else 0.0
        if z_action < -1e-6:
            z_count += 1
            z_first = step if z_first is None else z_first
            z_last = step
            current_z += 1
            z_longest = max(z_longest, current_z)
        else:
            current_z = 0
        diagnostics = row.get("controller_action_diagnostics")
        if isinstance(diagnostics, dict) and diagnostics.get("seat_window_authority_applied") is True:
            forced_count += 1
        depth = float(row.get("insertion_depth_m") or 0.0)
        lateral_value = row.get("lateral_error_m")
        lateral = float(lateral_value) if lateral_value is not None else math.inf
        max_depth = max(max_depth, depth)
        min_lateral = min(min_lateral, lateral)
        final_depth = depth
        final_lateral = lateral
    if min_lateral == math.inf:
        min_lateral = 0.0
    if final_lateral == math.inf:
        final_lateral = 0.0
    return {
        "env_native_first_success_step": summary.get("env_native_first_success_step"),
        "env_native_max_consecutive_success_steps": int(
            summary.get("env_native_max_consecutive_success_steps") or 0
        ),
        "z_first_step": z_first,
        "z_last_step": z_last,
        "z_count": z_count,
        "z_longest_consecutive_steps": z_longest,
        "seat_window_authority_forced_count": forced_count,
        "max_insertion_depth_m": round(max_depth, 6),
        "min_lateral_error_m": round(min_lateral, 6),
        "final_insertion_depth_m": round(final_depth, 6),
        "final_lateral_error_m": round(final_lateral, 6),
    }


def classify_v08c_candidate_failure(summary: dict[str, Any], trace: list[dict[str, Any]]) -> dict[str, Any]:
    metrics = _v08c_trace_metrics(summary, trace)
    first_success = metrics["env_native_first_success_step"]
    max_consecutive = metrics["env_native_max_consecutive_success_steps"]
    max_depth = float(metrics["max_insertion_depth_m"])
    min_lateral = float(metrics["min_lateral_error_m"])
    z_count = int(metrics["z_count"])
    if first_success is not None and max_consecutive < 10 and max_depth >= 0.0248:
        failure_class = "late_seat_window_shortfall"
    elif min_lateral <= 0.0006 and max_depth < 0.024 and z_count >= 60:
        failure_class = "centered_under_depth_progress"
    elif max_depth <= 0.001 and min_lateral >= 0.002 and z_count >= 60:
        failure_class = "off_center_no_capture"
    else:
        failure_class = "unclassified"
    return {
        "failure_class": failure_class,
        "failure_reason": summary.get("failure_reason") or "UNKNOWN",
        **metrics,
    }


def build_v08c_heldout_shortfall_diagnosis(*, output_dir: Path) -> dict[str, Any]:
    gate, gate_sha256 = load_required_v08b_failed_heldout_gate(output_dir)
    config, config_sha256 = load_required_v08b_seat_window_config(output_dir)
    rows = _load_v08b_heldout_trace_rows(output_dir)
    paired: dict[int, dict[str, dict[str, Any]]] = {}
    for row in rows:
        paired.setdefault(int(row["seed"]), {})[str(row["role"])] = row
    if sorted(paired) != list(V08B_FRESH_HELDOUT_RANGE):
        raise ValueError("v0_8c_v08b_heldout_seed_range_mismatch")

    candidate_failures: list[dict[str, Any]] = []
    baseline_success_count = 0
    candidate_success_count = 0
    paired_outcome_counts = {"B1_C1": 0, "B0_C1": 0, "B1_C0": 0, "B0_C0": 0}
    for seed in sorted(paired):
        baseline = paired[seed].get("baseline")
        candidate = paired[seed].get("candidate")
        if baseline is None or candidate is None:
            raise ValueError(f"v0_8c_missing_paired_rollout_for_seed_{seed}")
        baseline_success = bool(baseline["success"])
        candidate_success = bool(candidate["success"])
        baseline_success_count += int(baseline_success)
        candidate_success_count += int(candidate_success)
        outcome = ("B1" if baseline_success else "B0") + "_" + ("C1" if candidate_success else "C0")
        paired_outcome_counts[outcome] += 1
        if not candidate_success:
            classification = classify_v08c_candidate_failure(candidate["summary"], candidate["trace"])
            candidate_failures.append(
                {
                    "seed": seed,
                    "scenario_id": candidate["scenario_id"],
                    "baseline_success": baseline_success,
                    "candidate_success": candidate_success,
                    "paired_outcome": outcome,
                    "baseline_trace_path": baseline["trace_path"],
                    "candidate_trace_path": candidate["trace_path"],
                    **classification,
                }
            )

    actual_rollouts_per_policy = int(gate.get("actual_rollouts_per_policy") or 0)
    if actual_rollouts_per_policy != 50:
        raise ValueError("v0_8c_requires_50_rollouts_per_policy")
    if round(float(gate.get("baseline_success_rate", 0.0)) * actual_rollouts_per_policy) != baseline_success_count:
        raise ValueError("v0_8c_baseline_success_count_mismatch")
    if round(float(gate.get("candidate_success_rate", 0.0)) * actual_rollouts_per_policy) != candidate_success_count:
        raise ValueError("v0_8c_candidate_success_count_mismatch")

    taxonomy: dict[str, dict[str, Any]] = {
        "late_seat_window_shortfall": {"count": 0, "seeds": []},
        "centered_under_depth_progress": {"count": 0, "seeds": []},
        "off_center_no_capture": {"count": 0, "seeds": []},
        "unclassified": {"count": 0, "seeds": []},
    }
    for row in candidate_failures:
        failure_class = str(row["failure_class"])
        taxonomy[failure_class]["count"] += 1
        taxonomy[failure_class]["seeds"].append(int(row["seed"]))
    if taxonomy["unclassified"]["count"]:
        raise ValueError("v0_8c_unclassified_candidate_failures_present")

    child_dir = output_dir / V08C_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    write_json(child_dir / "candidate_failure_taxonomy_v0_8c.json", candidate_failures)

    burned_ranges = [
        list(V07A2_PROTECTED_HELDOUT_SEED_RANGE),
        [min(V08A_FRESH_HELDOUT_RANGE), max(V08A_FRESH_HELDOUT_RANGE)],
        [min(V08B_FRESH_HELDOUT_RANGE), max(V08B_FRESH_HELDOUT_RANGE)],
    ]
    recommended_constraints = {
        "earlier_z_deadline_step_lte": 68,
        "pre_z_capture_conditioning_required": True,
        "z_open_progress_monitor_required": True,
        "same_shared_authority_for_baseline_and_candidate": True,
        "attribution_preservation_gate_required": True,
        "forbidden_mechanisms": ["retry", "withdraw", "search", "force_control"],
        "fresh_heldout_seed_range": [
            min(V08C_FRESH_HELDOUT_RANGE),
            max(V08C_FRESH_HELDOUT_RANGE),
        ],
    }
    diagnosis = {
        "schema_version": V08C_SHORTFALL_DIAGNOSIS_SCHEMA_VERSION,
        "policy_slice": V08C_POLICY_SLICE_ID,
        "source_policy_slice": V08B_POLICY_SLICE_ID,
        "slice_id": V08C_SLICE_ID,
        "source_slice_id": V08B_SLICE_ID,
        "runtime_backend": "offline_artifact_diagnosis",
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "proof_eligible": False,
        "heldout_opened": False,
        "fresh_heldout_27000_27049_accessed": False,
        "source_v08b_gate_path": str(gate["path"]),
        "source_v08b_gate_sha256": gate_sha256,
        "source_v08b_config_path": str(config["path"]),
        "source_v08b_config_sha256": config_sha256,
        "actual_rollouts_per_policy": actual_rollouts_per_policy,
        "baseline_success_count": baseline_success_count,
        "candidate_success_count": candidate_success_count,
        "baseline_success_rate": gate.get("baseline_success_rate"),
        "candidate_success_rate": gate.get("candidate_success_rate"),
        "curated_vs_uncurated_uplift": gate.get("curated_vs_uncurated_uplift"),
        "paired_outcome_counts": paired_outcome_counts,
        "candidate_failures_total": len(candidate_failures),
        "failure_taxonomy": taxonomy,
        "burned_heldout_seed_ranges": burned_ranges,
        "recommended_downstream_slice": V08C_RECOMMENDED_DOWNSTREAM_SLICE,
        "recommended_downstream_constraints": recommended_constraints,
        "artifact_paths": {
            "candidate_failure_taxonomy": str(child_dir / "candidate_failure_taxonomy_v0_8c.json"),
        },
        "source_config_summary": {
            "scenario_aware_deadline_step": config.get("scenario_aware_deadline_step"),
            "z_open_centering_lateral_m": config.get("z_open_centering_lateral_m"),
        },
        "non_claims": {
            "closure_authority": False,
            "policy_uplift_proven": False,
            "same_heldout_reuse_for_closure": False,
        },
    }
    diagnosis["v0_8c_shortfall_diagnosis_sha256"] = _sha256_payload_excluding(
        diagnosis,
        "v0_8c_shortfall_diagnosis_sha256",
    )
    write_json(child_dir / "v0_8c_shortfall_diagnosis.json", diagnosis)
    write_json(output_dir / "heldout_shortfall_diagnosis_v0_8c.json", diagnosis)
    return diagnosis


def _v08d_burned_heldout_seed_range_accessed(seed: int) -> bool:
    return (
        _protected_heldout_seed_range_accessed(seed)
        or int(seed) in V08A_FRESH_HELDOUT_RANGE
        or int(seed) in V08B_FRESH_HELDOUT_RANGE
    )


def load_required_v08c_shortfall_diagnosis(output_dir: Path) -> tuple[dict[str, Any], str]:
    diagnosis_path = output_dir / V08C_CHILD_OUTPUT_DIRNAME / "v0_8c_shortfall_diagnosis.json"
    if not diagnosis_path.exists():
        raise ValueError("missing_v0_8c_shortfall_diagnosis")
    diagnosis = read_json(diagnosis_path)
    taxonomy = diagnosis.get("failure_taxonomy") if isinstance(diagnosis.get("failure_taxonomy"), dict) else {}
    if (
        diagnosis.get("policy_slice") != V08C_POLICY_SLICE_ID
        or diagnosis.get("source_policy_slice") != V08B_POLICY_SLICE_ID
        or diagnosis.get("recommended_downstream_slice") != V08C_RECOMMENDED_DOWNSTREAM_SLICE
        or diagnosis.get("mvp2_closed") is not False
        or diagnosis.get("policy_uplift_proven") is not False
        or diagnosis.get("fresh_heldout_27000_27049_accessed") is not False
        or int(taxonomy.get("unclassified", {}).get("count", 0)) != 0
    ):
        raise ValueError("invalid_v0_8c_shortfall_diagnosis")
    diagnosis["path"] = str(diagnosis_path)
    diagnosis["sha256"] = _sha256_file(diagnosis_path)
    return diagnosis, diagnosis["sha256"]


def derive_v08d_capture_conditioned_progress_authority_config(*, output_dir: Path) -> dict[str, Any]:
    diagnosis, diagnosis_sha256 = load_required_v08c_shortfall_diagnosis(output_dir)
    parent_config, parent_config_sha256 = load_required_v08b_seat_window_config(output_dir)
    config: dict[str, Any] = {
        "schema_version": V08D_CAPTURE_CONDITIONED_PROGRESS_AUTHORITY_CONFIG_SCHEMA_VERSION,
        "capture_conditioned_progress_authority_id": V08D_CAPTURE_CONDITIONED_PROGRESS_AUTHORITY_ID,
        "policy_slice": V08D_POLICY_SLICE_ID,
        "parent_policy_slice": V08B_POLICY_SLICE_ID,
        "slice_id": V08D_SLICE_ID,
        "source": "v0_8c_heldout_shortfall_diagnosis",
        "source_v08c_shortfall_diagnosis_sha256": diagnosis_sha256,
        "source_v08b_seat_window_authority_config_sha256": parent_config_sha256,
        "source_curated_vs_uncurated_uplift": diagnosis.get("curated_vs_uncurated_uplift"),
        "source_candidate_failure_taxonomy": diagnosis.get("failure_taxonomy"),
        "source_paired_outcome_counts": diagnosis.get("paired_outcome_counts"),
        "early_z_deadline_step": V08D_EARLY_Z_DEADLINE_STEP,
        "capture_prepare_start_step": V08D_CAPTURE_PREPARE_START_STEP,
        "capture_lateral_gate_m": V08D_CAPTURE_LATERAL_GATE_M,
        "depth_progress_window_steps": V08D_DEPTH_PROGRESS_WINDOW_STEPS,
        "minimum_depth_progress_m": V08D_MINIMUM_DEPTH_PROGRESS_M,
        "under_depth_progress_threshold_m": V08D_UNDER_DEPTH_PROGRESS_THRESHOLD_M,
        "seat_region_depth_m": V08A_SEAT_REGION_DEPTH_M,
        "z_progress_action": V08A_Z_PROGRESS_ACTION,
        "parent_scenario_aware_deadline_step": parent_config.get("scenario_aware_deadline_step"),
        "candidate_specific": False,
        "baseline_specific": False,
        "proof_authority": False,
        "forbidden_mechanisms": ["retry", "withdraw", "search", "force_control"],
        "fresh_calibration_seed_range": [
            min(V08D_FRESH_CALIBRATION_RANGE),
            max(V08D_FRESH_CALIBRATION_RANGE),
        ],
        "fresh_heldout_seed_range": [
            min(V08D_FRESH_HELDOUT_RANGE),
            max(V08D_FRESH_HELDOUT_RANGE),
        ],
        "burned_heldout_seed_ranges": [
            list(V07A2_PROTECTED_HELDOUT_SEED_RANGE),
            [min(V08A_FRESH_HELDOUT_RANGE), max(V08A_FRESH_HELDOUT_RANGE)],
            [min(V08B_FRESH_HELDOUT_RANGE), max(V08B_FRESH_HELDOUT_RANGE)],
        ],
        "heldout_21000_21049_used_for_parameter_derivation": False,
        "heldout_24000_24049_used_for_parameter_derivation": False,
        "heldout_26000_26049_used_for_parameter_derivation": True,
        "fresh_heldout_27000_27049_used_for_parameter_derivation": False,
        "fresh_heldout_27000_27049_accessed": False,
    }
    config["capture_conditioned_progress_authority_config_sha256"] = _sha256_payload_excluding(
        config,
        "capture_conditioned_progress_authority_config_sha256",
    )
    return config


def build_v08d_fresh_manifest(*, output_dir: Path, diagnosis: dict[str, Any]) -> dict[str, Any]:
    calibration_rows = [_scenario_row(split="calibration", seed=seed) for seed in V08D_FRESH_CALIBRATION_RANGE]
    heldout_rows = [_scenario_row(split="held_out", seed=seed) for seed in V08D_FRESH_HELDOUT_RANGE]
    for row in calibration_rows + heldout_rows:
        if _v08d_burned_heldout_seed_range_accessed(int(row["seed"])):
            raise ValueError("v0_8d_fresh_manifest_reuses_burned_heldout")
    manifest = {
        "schema_version": V08D_MANIFEST_SCHEMA_VERSION,
        "policy_slice": V08D_POLICY_SLICE_ID,
        "slice_id": V08D_SLICE_ID,
        "parent_policy_slice": V08B_POLICY_SLICE_ID,
        "scenario_profile": "v0_8d",
        "task_type": "connector_insertion",
        "success_metric": SUCCESS_METRIC,
        "success_authority": V06_ENV_NATIVE_SUCCESS_AUTHORITY,
        "source_v08c_shortfall_diagnosis_sha256": diagnosis["sha256"],
        "scenarios": calibration_rows + heldout_rows,
        "fresh_split_manifest": {
            "calibration": {
                "seed_range": [
                    min(V08D_FRESH_CALIBRATION_RANGE),
                    max(V08D_FRESH_CALIBRATION_RANGE),
                ],
                "scenario_ids": [row["scenario_id"] for row in calibration_rows],
                "count": len(calibration_rows),
            },
            "held_out": {
                "seed_range": [min(V08D_FRESH_HELDOUT_RANGE), max(V08D_FRESH_HELDOUT_RANGE)],
                "scenario_ids": [row["scenario_id"] for row in heldout_rows],
                "count": len(heldout_rows),
            },
        },
        "burned_heldout_seed_ranges": [
            list(V07A2_PROTECTED_HELDOUT_SEED_RANGE),
            [min(V08A_FRESH_HELDOUT_RANGE), max(V08A_FRESH_HELDOUT_RANGE)],
            [min(V08B_FRESH_HELDOUT_RANGE), max(V08B_FRESH_HELDOUT_RANGE)],
        ],
        "heldout_21000_21049_accessed": False,
        "fresh_heldout_24000_24049_accessed": False,
        "fresh_heldout_26000_26049_accessed": False,
        "fresh_heldout_27000_27049_accessed": False,
        "calibration_opened": False,
        "heldout_opened": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    manifest["manifest_sha256"] = _sha256_payload_excluding(manifest, "manifest_sha256")
    return manifest


def build_v08d_policy_artifact_payload(
    *,
    base_policy_artifact: dict[str, Any],
    capture_conditioned_progress_authority_config: dict[str, Any],
    dataset_view_role: str,
) -> dict[str, Any]:
    role = "candidate" if dataset_view_role == "candidate_curated" else "baseline"
    payload = {
        key: value
        for key, value in base_policy_artifact.items()
        if key not in {"path", "policy_artifact_sha256"}
    }
    payload.update(
        {
            "schema_version": V08D_POLICY_ARTIFACT_SCHEMA_VERSION,
            "policy_id": f"{role}_mvp2e_v08d_capture_conditioned_progress_authority_policy",
            "policy_slice": V08D_POLICY_SLICE_ID,
            "slice_id": V08D_SLICE_ID,
            "parent_policy_slice": V08B_POLICY_SLICE_ID,
            "parent_policy_artifact_sha256": base_policy_artifact.get("policy_artifact_sha256"),
            "dataset_view_role": dataset_view_role,
            "capture_conditioned_progress_authority_id": V08D_CAPTURE_CONDITIONED_PROGRESS_AUTHORITY_ID,
            "capture_conditioned_progress_authority_config": capture_conditioned_progress_authority_config,
            "capture_conditioned_progress_authority_config_sha256": (
                capture_conditioned_progress_authority_config[
                    "capture_conditioned_progress_authority_config_sha256"
                ]
            ),
            "same_capture_conditioned_progress_authority_config_as_peer": True,
            "source_diagnostic_heldout_21000_21049_accessed": True,
            "source_diagnostic_heldout_24000_24049_accessed": True,
            "source_diagnostic_heldout_26000_26049_accessed": True,
            "heldout_21000_21049_accessed": False,
            "fresh_heldout_24000_24049_accessed": False,
            "fresh_heldout_26000_26049_accessed": False,
            "fresh_calibration_26500_26529_accessed": False,
            "fresh_heldout_27000_27049_accessed": False,
            "mvp2_closed": False,
            "policy_uplift_proven": False,
        }
    )
    payload["policy_artifact_sha256"] = _sha256_payload_excluding(payload, "policy_artifact_sha256")
    return payload


def build_v08d_capture_conditioned_progress_authority_slice(*, output_dir: Path) -> dict[str, Any]:
    diagnosis, _diagnosis_sha256 = load_required_v08c_shortfall_diagnosis(output_dir)
    policy_artifacts = _load_v08b_policy_artifacts(output_dir)
    child_dir = output_dir / V08D_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    capture_config = derive_v08d_capture_conditioned_progress_authority_config(output_dir=output_dir)
    write_json(child_dir / "v0_8d_capture_conditioned_progress_authority_config.json", capture_config)
    candidate_policy = build_v08d_policy_artifact_payload(
        base_policy_artifact=policy_artifacts["candidate"],
        capture_conditioned_progress_authority_config=capture_config,
        dataset_view_role="candidate_curated",
    )
    baseline_policy = build_v08d_policy_artifact_payload(
        base_policy_artifact=policy_artifacts["baseline"],
        capture_conditioned_progress_authority_config=capture_config,
        dataset_view_role="baseline_uncurated",
    )
    write_json(child_dir / "candidate_policy_artifact_v0_8d.json", candidate_policy)
    write_json(child_dir / "baseline_policy_artifact_v0_8d.json", baseline_policy)
    manifest = build_v08d_fresh_manifest(output_dir=output_dir, diagnosis=diagnosis)
    manifest.update(
        {
            "capture_conditioned_progress_authority_id": V08D_CAPTURE_CONDITIONED_PROGRESS_AUTHORITY_ID,
            "capture_conditioned_progress_authority_config_sha256": capture_config[
                "capture_conditioned_progress_authority_config_sha256"
            ],
            "candidate_policy_artifact_sha256": candidate_policy["policy_artifact_sha256"],
            "baseline_policy_artifact_sha256": baseline_policy["policy_artifact_sha256"],
            "same_capture_conditioned_progress_authority_config_as_peer": (
                candidate_policy["capture_conditioned_progress_authority_config_sha256"]
                == baseline_policy["capture_conditioned_progress_authority_config_sha256"]
            ),
            "artifacts": {
                "capture_conditioned_progress_authority_config": (
                    f"{V08D_CHILD_OUTPUT_DIRNAME}/"
                    "v0_8d_capture_conditioned_progress_authority_config.json"
                ),
                "candidate_policy_artifact": (
                    f"{V08D_CHILD_OUTPUT_DIRNAME}/candidate_policy_artifact_v0_8d.json"
                ),
                "baseline_policy_artifact": (
                    f"{V08D_CHILD_OUTPUT_DIRNAME}/baseline_policy_artifact_v0_8d.json"
                ),
            },
        }
    )
    manifest["manifest_sha256"] = _sha256_payload_excluding(manifest, "manifest_sha256")
    write_json(child_dir / "v0_8d_fresh_manifest.json", manifest)
    return manifest


def _load_v08d_policy_artifacts(output_dir: Path) -> dict[str, dict[str, Any]]:
    child_dir = output_dir / V08D_CHILD_OUTPUT_DIRNAME
    candidate_path = child_dir / "candidate_policy_artifact_v0_8d.json"
    baseline_path = child_dir / "baseline_policy_artifact_v0_8d.json"
    if not candidate_path.exists() or not baseline_path.exists():
        raise ValueError("missing_v0_8d_policy_artifacts")
    baseline = read_json(baseline_path)
    candidate = read_json(candidate_path)
    reasons: list[str] = []
    for role, policy in (("baseline", baseline), ("candidate", candidate)):
        if policy.get("policy_slice") != V08D_POLICY_SLICE_ID:
            reasons.append(f"{role}_policy_slice_mismatch")
        if policy.get("parent_policy_slice") != V08B_POLICY_SLICE_ID:
            reasons.append(f"{role}_parent_policy_slice_mismatch")
        if policy.get("heldout_21000_21049_accessed") is not False:
            reasons.append(f"{role}_burned_heldout_accessed")
        if policy.get("fresh_heldout_24000_24049_accessed") is not False:
            reasons.append(f"{role}_v08a_fresh_heldout_reused")
        if policy.get("fresh_heldout_26000_26049_accessed") is not False:
            reasons.append(f"{role}_v08b_fresh_heldout_reused")
        if policy.get("fresh_heldout_27000_27049_accessed") is not False:
            reasons.append(f"{role}_fresh_heldout_accessed_before_closure")
        expected_hash = _sha256_payload_excluding(policy, "policy_artifact_sha256")
        if policy.get("policy_artifact_sha256") != expected_hash:
            reasons.append(f"{role}_policy_hash_mismatch")
    equality_keys = (
        "selected_action_adapter_id",
        "trainer",
        "trainer_family",
        "policy_class",
        "feature_schema",
        "feature_schema_version",
        "phase_schema",
        "final_post_adapter_authority_config_sha256",
        "final_post_adapter_xy_authority_config_sha256",
        "base_servo_config_sha256",
        "shared_hysteresis_authority_config_sha256",
        "capture_conditioned_progress_authority_config_sha256",
    )
    for key in equality_keys:
        if baseline.get(key) != candidate.get(key):
            reasons.append(f"peer_{key}_mismatch")
    if reasons:
        raise ValueError("v0_8d_policy_peer_fairness_failed: " + ",".join(reasons))
    return {
        "baseline": {**baseline, "path": str(baseline_path)},
        "candidate": {**candidate, "path": str(candidate_path)},
    }


def _v08d_runtime_manifest_for_split(*, fresh_manifest: dict[str, Any], split: str) -> dict[str, Any]:
    if split not in {"calibration", "held_out"}:
        raise ValueError("v0_8d_runtime_manifest_unknown_split")
    rows = [
        {**row, "source_split": split, "semantic_eval_split": split, "split": "held_out"}
        for row in fresh_manifest.get("scenarios", [])
        if isinstance(row, dict) and row.get("split") == split
    ]
    if not rows:
        raise ValueError(f"v0_8d_runtime_manifest_missing_{split}_rows")
    seeds = [int(row["seed"]) for row in rows]
    if any(_v08d_burned_heldout_seed_range_accessed(seed) for seed in seeds):
        raise ValueError("v0_8d_runtime_manifest_reuses_burned_heldout")
    if split == "calibration" and seeds != list(V08D_FRESH_CALIBRATION_RANGE):
        raise ValueError("v0_8d_calibration_seed_range_mismatch")
    if split == "held_out" and seeds != list(V08D_FRESH_HELDOUT_RANGE):
        raise ValueError("v0_8d_heldout_seed_range_mismatch")
    manifest = {
        "schema_version": fresh_manifest["schema_version"],
        "policy_slice": V08D_POLICY_SLICE_ID,
        "slice_id": V08D_SLICE_ID,
        "parent_policy_slice": V08B_POLICY_SLICE_ID,
        "scenario_profile": "v0_8d",
        "runtime_split": split,
        "task_type": fresh_manifest["task_type"],
        "success_metric": fresh_manifest["success_metric"],
        "success_authority": fresh_manifest["success_authority"],
        "source_fresh_manifest_sha256": fresh_manifest["manifest_sha256"],
        "scenarios": rows,
        "burned_heldout_seed_ranges": fresh_manifest["burned_heldout_seed_ranges"],
        "heldout_21000_21049_accessed": False,
        "fresh_heldout_24000_24049_accessed": False,
        "fresh_heldout_26000_26049_accessed": False,
        "fresh_calibration_26500_26529_accessed": split == "calibration",
        "fresh_heldout_27000_27049_accessed": split == "held_out",
        "calibration_opened": split == "calibration",
        "heldout_opened": split == "held_out",
        "proof_authority": split == "held_out",
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    manifest["manifest_sha256"] = _sha256_payload_excluding(manifest, "manifest_sha256")
    return manifest


def _write_v08d_calibration_external_rollouts(
    *,
    output_dir: Path,
    baseline_rollouts: list[dict[str, Any]],
    candidate_rollouts: list[dict[str, Any]],
) -> dict[str, str]:
    rollout_dir = output_dir / "calibration_external_rollouts"
    rollout_dir.mkdir(parents=True, exist_ok=True)
    baseline_path = rollout_dir / "baseline_calibration_rollouts_v0_8d.json"
    candidate_path = rollout_dir / "candidate_calibration_rollouts_v0_8d.json"
    write_json(baseline_path, baseline_rollouts)
    write_json(candidate_path, candidate_rollouts)
    return {"baseline": str(baseline_path), "candidate": str(candidate_path)}


def _v08d_attribution_preservation_metrics(trace_paths: dict[str, list[str]]) -> dict[str, Any]:
    role_vectors: dict[str, list[list[float]]] = {"baseline": [], "candidate": []}
    for role in ("baseline", "candidate"):
        for path_value in trace_paths.get(role, []):
            path = Path(path_value)
            if not path.exists():
                continue
            payload = read_json(path)
            trace = payload.get("trace") if isinstance(payload.get("trace"), list) else []
            for row in trace:
                diagnostics = row.get("controller_action_diagnostics")
                vector = None
                if isinstance(diagnostics, dict) and isinstance(
                    diagnostics.get("post_adapter_action_vector"),
                    list,
                ):
                    vector = diagnostics["post_adapter_action_vector"]
                elif isinstance(row.get("normalized_action"), list):
                    vector = row["normalized_action"]
                if isinstance(vector, list) and len(vector) >= 3:
                    role_vectors[role].append([float(value) for value in vector[:3]])
    paired_count = min(len(role_vectors["baseline"]), len(role_vectors["candidate"]))
    if paired_count <= 0:
        return {
            "paired_action_rows": 0,
            "mean_l2_action_delta": 0.0,
            "attribution_preservation_gate_passed": False,
            "failure_reason": "missing_paired_trace_actions",
        }
    deltas = []
    for index in range(paired_count):
        baseline = np.asarray(role_vectors["baseline"][index], dtype=np.float64)
        candidate = np.asarray(role_vectors["candidate"][index], dtype=np.float64)
        deltas.append(float(np.linalg.norm(candidate - baseline)))
    mean_delta = float(np.mean(deltas)) if deltas else 0.0
    return {
        "paired_action_rows": paired_count,
        "mean_l2_action_delta": round(mean_delta, 12),
        "attribution_preservation_gate_passed": bool(mean_delta > 1.0e-6),
        "failure_reason": "" if mean_delta > 1.0e-6 else "candidate_baseline_actions_collapsed",
    }


def derive_v08d_calibration_presignal_gate(
    *,
    baseline_rollouts: list[dict[str, Any]],
    candidate_rollouts: list[dict[str, Any]],
    runtime_gate: dict[str, Any],
    runtime_metadata: dict[str, Any],
    trace_paths: dict[str, list[str]],
) -> dict[str, Any]:
    gate = derive_v07h_calibration_presignal_gate(
        baseline_rollouts=baseline_rollouts,
        candidate_rollouts=candidate_rollouts,
        runtime_gate=runtime_gate,
        runtime_metadata=runtime_metadata,
        trace_paths=trace_paths,
        output_dir=Path("."),
    )
    candidate_count = int(gate["candidate_calibration_rollout_count"])
    candidate_success_count = int(gate["candidate_calibration_success_count"])
    candidate_failures_total = candidate_count - candidate_success_count
    baseline_rate = float(gate["baseline_calibration_success_rate"])
    candidate_rate = float(gate["candidate_calibration_success_rate"])
    success_gap = round(candidate_rate - baseline_rate, 12)
    attribution = _v08d_attribution_preservation_metrics(trace_paths)
    failure_reason = ""
    if gate.get("heldout_21000_21049_accessed") is True:
        failure_reason = "protected_heldout_seed_accessed"
    elif runtime_gate.get("passed") is not True or runtime_metadata.get("runtime_backend") != "isaac_runtime":
        failure_reason = "calibration_runtime_gate_not_passed"
    elif min(int(gate["baseline_calibration_rollout_count"]), candidate_count) < V07H_CALIBRATION_ROLLOUTS_PER_POLICY:
        failure_reason = "calibration_rollout_count_below_minimum"
    elif candidate_rate <= baseline_rate:
        failure_reason = "candidate_calibration_not_above_baseline"
    elif success_gap < 0.10:
        failure_reason = "candidate_baseline_success_gap_below_minimum"
    elif candidate_failures_total > 3:
        failure_reason = "candidate_failures_above_maximum"
    elif attribution["attribution_preservation_gate_passed"] is not True:
        failure_reason = "attribution_preservation_failed"
    passed = failure_reason == ""
    gate.update(
        {
            "schema_version": V08D_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
            "policy_slice": V08D_POLICY_SLICE_ID,
            "slice_id": V08D_SLICE_ID,
            "parent_policy_slice": V08B_POLICY_SLICE_ID,
            "passed": bool(passed),
            "failure_reason": failure_reason,
            "heldout_allowed": bool(passed),
            "fresh_calibration_26500_26529_accessed": True,
            "fresh_heldout_27000_27049_accessed": False,
            "fresh_heldout_24000_24049_accessed": False,
            "fresh_heldout_26000_26049_accessed": False,
            "candidate_baseline_success_gap": success_gap,
            "candidate_success_gap_minimum": 0.10,
            "candidate_failures_total": candidate_failures_total,
            "candidate_failures_maximum": 3,
            "attribution_preservation": attribution,
            "attribution_preservation_gate_passed": bool(
                attribution["attribution_preservation_gate_passed"]
            ),
            "source": "v0_8d_fresh_calibration_runtime",
            "mvp2_closed": False,
            "policy_uplift_proven": False,
        }
    )
    gate["calibration_presignal_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "calibration_presignal_gate_sha256",
    )
    return gate


def run_v08d_capture_conditioned_progress_authority_runtime(
    *,
    output_dir: Path,
    device: str = DEFAULT_ISAAC_DEVICE,
    headless: bool = True,
    isaac_task: str = DEFAULT_ISAAC_TASK,
    max_steps: int = int(SUCCESS_METRIC["max_steps"]),
    action_scale: float = 1.0,
    min_rollouts_per_policy: int = MIN_PROOF_ROLLOUTS_PER_POLICY,
    bootstrap_iterations: int = 2000,
    bootstrap_seed: int = 23,
    backend: Any | None = None,
) -> dict[str, Any]:
    child_dir = output_dir / V08D_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    fresh_manifest = build_v08d_capture_conditioned_progress_authority_slice(output_dir=output_dir)
    policy_artifacts = _load_v08d_policy_artifacts(output_dir)
    baseline_policy = policy_artifacts["baseline"]
    candidate_policy = policy_artifacts["candidate"]
    selected_adapter_id = str(candidate_policy["selected_action_adapter_id"])
    policy_class = str(candidate_policy["policy_class"])
    trainer = str(candidate_policy["trainer"])
    use_single_app_actual_backend = (
        backend is None
        and getattr(IsaacConnectorInsertionEvaluatorBackend, "__name__", "")
        == "IsaacConnectorInsertionEvaluatorBackend"
    )
    evaluator_backend = backend or IsaacConnectorInsertionEvaluatorBackend(
        task=isaac_task,
        device=device,
        headless=headless,
        action_scale=action_scale,
        max_steps=max_steps,
    )
    actual_env = None
    actual_simulation_app = None
    actual_torch = None
    if use_single_app_actual_backend:
        from isaaclab.app import AppLauncher

        app_launcher = AppLauncher(
            {
                "headless": headless,
                "device": device,
                "enable_cameras": False,
            }
        )
        actual_simulation_app = app_launcher.app

        import gymnasium as gym
        import torch as torch_module

        import isaaclab_tasks  # noqa: F401
        from isaaclab_tasks.utils import parse_env_cfg

        env_cfg = parse_env_cfg(isaac_task, device=device, num_envs=1)
        actual_env = gym.make(isaac_task, cfg=env_cfg).unwrapped
        actual_torch = torch_module

    def run_runtime_manifest(
        *,
        manifest: dict[str, Any],
        runtime_output_dir: Path,
        rollouts_per_policy: int,
    ) -> BackendResult:
        if actual_env is not None:
            return _run_v08a_manifest_with_existing_isaac(
                evaluator_backend=evaluator_backend,
                env=actual_env,
                simulation_app=actual_simulation_app,
                torch_module=actual_torch,
                manifest=manifest,
                output_dir=runtime_output_dir,
                min_rollouts_per_policy=rollouts_per_policy,
                policy_artifacts=policy_artifacts,
            )
        return evaluator_backend.run(
            manifest=manifest,
            output_dir=runtime_output_dir,
            min_rollouts_per_policy=rollouts_per_policy,
            deterministic_profile="candidate_positive",
            policy_artifacts=policy_artifacts,
        )

    calibration_manifest = _v08d_runtime_manifest_for_split(
        fresh_manifest=fresh_manifest,
        split="calibration",
    )
    write_json(child_dir / "calibration_runtime_manifest_v0_8d.json", calibration_manifest)
    calibration_result = run_runtime_manifest(
        manifest=calibration_manifest,
        runtime_output_dir=child_dir / "isaac_runtime_fresh_calibration_v0_8d",
        rollouts_per_policy=V07H_CALIBRATION_ROLLOUTS_PER_POLICY,
    )
    calibration_rollout_paths = _write_v08d_calibration_external_rollouts(
        output_dir=child_dir,
        baseline_rollouts=list(calibration_result.baseline_rollouts),
        candidate_rollouts=list(calibration_result.candidate_rollouts),
    )
    calibration_trace_paths = {
        "baseline": list(calibration_result.baseline_trace_paths),
        "candidate": list(calibration_result.candidate_trace_paths),
    }
    calibration_gate = derive_v08d_calibration_presignal_gate(
        baseline_rollouts=list(calibration_result.baseline_rollouts),
        candidate_rollouts=list(calibration_result.candidate_rollouts),
        runtime_gate=dict(calibration_result.runtime_gate),
        runtime_metadata=dict(calibration_result.runtime_metadata),
        trace_paths=calibration_trace_paths,
    )
    calibration_gate["calibration_runtime_manifest_sha256"] = calibration_manifest["manifest_sha256"]
    calibration_gate["baseline_calibration_rollout_path"] = calibration_rollout_paths["baseline"]
    calibration_gate["candidate_calibration_rollout_path"] = calibration_rollout_paths["candidate"]
    calibration_gate["calibration_presignal_gate_sha256"] = _sha256_payload_excluding(
        calibration_gate,
        "calibration_presignal_gate_sha256",
    )
    write_json(child_dir / "calibration_presignal_gate_v0_8d.json", calibration_gate)
    write_json(
        output_dir / "calibration_presignal_gate.json",
        {
            "schema_version": V08D_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
            "policy_slice": V08D_POLICY_SLICE_ID,
            "slice_id": V08D_SLICE_ID,
            "passed": calibration_gate["passed"],
            "source_gate_path": f"{V08D_CHILD_OUTPUT_DIRNAME}/calibration_presignal_gate_v0_8d.json",
            "calibration_opened": True,
            "heldout_opened": False,
            "heldout_21000_21049_accessed": False,
            "fresh_heldout_24000_24049_accessed": False,
            "fresh_heldout_26000_26049_accessed": False,
            "fresh_heldout_27000_27049_accessed": False,
            "heldout_allowed": calibration_gate["heldout_allowed"],
            "mvp2_closed": False,
            "policy_uplift_proven": False,
        },
    )
    if calibration_gate.get("passed") is not True:
        calibration_gate["mvp2_closed"] = False
        calibration_gate["policy_uplift_proven"] = False
        if actual_env is not None:
            actual_env.close()
        return calibration_gate

    selection = _v08a_calibration_selection_report(output_dir)
    training_scenario_ids = _v08a_training_scenario_ids(output_dir)
    heldout_manifest = _v08d_runtime_manifest_for_split(
        fresh_manifest=fresh_manifest,
        split="held_out",
    )
    write_json(child_dir / "heldout_runtime_manifest_v0_8d.json", heldout_manifest)
    heldout_leakage_guard = validate_no_heldout_leakage(
        manifest=heldout_manifest,
        training_scenario_ids=training_scenario_ids,
        curation_tuning_scenario_ids=[],
        threshold_tuning_scenario_ids=[],
        hyperparameter_scenario_ids=[],
        calibration_selector_scenario_ids=[str(item) for item in selection.get("calibration_scenario_ids", [])],
    )
    if heldout_leakage_guard["passed"] is not True:
        raise ValueError("v0_8d_fresh_heldout_leakage_guard_failed")

    baseline_view = _existing_train_view(
        output_dir / "baseline_uncurated_train.hdf5",
        view_id="baseline_uncurated_mvp2c_train_view",
    )
    candidate_view = _existing_train_view(
        output_dir / "candidate_curated_train.hdf5",
        view_id="candidate_curated_mvp2c_train_view",
    )
    bridge_dir = _write_learning_harness_bridge(
        output_dir=child_dir,
        manifest=heldout_manifest,
        baseline_view=baseline_view,
        candidate_view=candidate_view,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    heldout_rollouts_per_policy = max(
        int(min_rollouts_per_policy),
        STRONGER_PUBLIC_ROLLOUTS_PER_POLICY,
        len(V08D_FRESH_HELDOUT_RANGE),
    )
    heldout_result = run_runtime_manifest(
        manifest=heldout_manifest,
        runtime_output_dir=child_dir / "isaac_runtime_fresh_heldout_v0_8d",
        rollouts_per_policy=heldout_rollouts_per_policy,
    )
    runtime_gate = dict(heldout_result.runtime_gate)
    actual_rollouts_per_policy = min(
        len(heldout_result.baseline_rollouts),
        len(heldout_result.candidate_rollouts),
    )
    runtime_gate["actual_baseline_rollouts"] = len(heldout_result.baseline_rollouts)
    runtime_gate["actual_candidate_rollouts"] = len(heldout_result.candidate_rollouts)
    runtime_gate["actual_rollouts_per_policy"] = actual_rollouts_per_policy
    combined_rollouts = list(heldout_result.baseline_rollouts) + list(heldout_result.candidate_rollouts)
    if any(_v08d_burned_heldout_seed_range_accessed(int(rollout.get("seed", -1))) for rollout in combined_rollouts):
        raise ValueError("v0_8d_burned_heldout_seed_accessed")
    heldout_suite = _heldout_suite(heldout_manifest)
    baseline_rollouts_path = _write_external_rollout_json(
        output_dir=child_dir,
        role="baseline",
        policy_artifact=baseline_policy,
        train_view=baseline_view,
        heldout_suite=heldout_suite,
        backend_result=heldout_result,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    candidate_rollouts_path = _write_external_rollout_json(
        output_dir=child_dir,
        role="candidate",
        policy_artifact=candidate_policy,
        train_view=candidate_view,
        heldout_suite=heldout_suite,
        backend_result=heldout_result,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    learning_report = _run_learning_validator(
        output_dir=child_dir,
        bridge_dir=bridge_dir,
        baseline_rollouts_path=baseline_rollouts_path,
        candidate_rollouts_path=candidate_rollouts_path,
        min_rollouts_per_policy=MIN_PROOF_ROLLOUTS_PER_POLICY,
        bootstrap_iterations=bootstrap_iterations,
        bootstrap_seed=bootstrap_seed,
        policy_class=policy_class,
        trainer=trainer,
    )
    train_generation_runtime_gate, train_gate_sha256 = load_v07a2_parent_train_generation_gate(output_dir)
    closure = derive_mvp2c_closure(
        learning_report=learning_report,
        runtime_gate=runtime_gate,
        train_generation_runtime_gate=train_generation_runtime_gate,
        calibration_selection_report=selection,
        heldout_leakage_guard=heldout_leakage_guard,
        actual_rollouts_per_policy=actual_rollouts_per_policy,
    )
    confidence_interval_report = _bootstrap_uplift_ci(
        baseline_rollouts=list(heldout_result.baseline_rollouts),
        candidate_rollouts=list(heldout_result.candidate_rollouts),
        iterations=bootstrap_iterations,
        seed=bootstrap_seed,
    )
    gate = {
        "schema_version": V08D_HELDOUT_CLOSURE_SCHEMA_VERSION,
        "policy_slice": V08D_POLICY_SLICE_ID,
        "slice_id": V08D_SLICE_ID,
        "parent_policy_slice": V08B_POLICY_SLICE_ID,
        "source_fresh_manifest_sha256": fresh_manifest["manifest_sha256"],
        "capture_conditioned_progress_authority_config_sha256": candidate_policy[
            "capture_conditioned_progress_authority_config_sha256"
        ],
        "parent_train_generation_runtime_gate_sha256": train_gate_sha256,
        "fresh_calibration_presignal_gate_sha256": calibration_gate["calibration_presignal_gate_sha256"],
        "runtime_backend": heldout_result.runtime_backend,
        "proof_runtime": heldout_result.proof_runtime,
        "runtime_gate": runtime_gate,
        "actual_rollouts_per_policy": actual_rollouts_per_policy,
        "baseline_success_rate": learning_report.get("baseline_success_rate"),
        "candidate_success_rate": learning_report.get("candidate_success_rate"),
        "curated_vs_uncurated_uplift": learning_report.get("curated_vs_uncurated_uplift"),
        "learning_report_path": str(
            child_dir / "mvp2_learning_proven_policy_eval" / "mvp2_learning_proven_report.json"
        ),
        "baseline_external_rollouts": str(baseline_rollouts_path),
        "candidate_external_rollouts": str(candidate_rollouts_path),
        "confidence_interval_report": confidence_interval_report,
        "stronger_public_evidence_target_passed": _derive_public_evidence_target(
            actual_rollouts_per_policy=actual_rollouts_per_policy,
            confidence_interval_report=confidence_interval_report,
        ),
        "calibration_opened": True,
        "heldout_opened": True,
        "heldout_21000_21049_accessed": False,
        "fresh_heldout_24000_24049_accessed": False,
        "fresh_heldout_26000_26049_accessed": False,
        "fresh_calibration_26500_26529_accessed": True,
        "fresh_heldout_27000_27049_accessed": True,
        "same_heldout_reuse_allowed_for_closure": False,
        "heldout_leakage_guard": heldout_leakage_guard,
        "calibration_selection_report_sha256": _sha256_file(output_dir / "calibration_selection_report.json"),
        "selected_action_adapter_id": selected_adapter_id,
        "same_adapter_used_for_baseline_and_candidate": True,
        "same_policy_class": baseline_policy.get("policy_class") == candidate_policy.get("policy_class"),
        "same_trainer": baseline_policy.get("trainer") == candidate_policy.get("trainer"),
        "same_feature_schema": baseline_policy.get("feature_schema") == candidate_policy.get("feature_schema"),
        "mvp2_closed": closure["mvp2_closed"],
        "mvp2c_close_minimum_passed": closure["mvp2c_close_minimum_passed"],
        "policy_uplift_proven": closure["learning_proven"],
        "proof_eligible": closure["proof_eligible"],
        "blockers": closure["blockers"] + list(learning_report.get("blockers") or []),
        "non_claims": {
            "deployable_real_robot_policy": False,
            "visual_policy_performance": False,
            "real_robot_success": False,
            "physical_robot_readiness": False,
            "universal_robot_support": False,
            "hmd_openxr_readiness": False,
        },
    }
    gate["heldout_closure_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "heldout_closure_gate_sha256",
    )
    write_json(child_dir / "heldout_closure_gate_v0_8d.json", gate)
    write_json(output_dir / "heldout_closure_gate.json", gate)
    if actual_env is not None:
        actual_env.close()
    return gate


def load_required_v08d_failed_calibration_gate(output_dir: Path) -> tuple[dict[str, Any], str]:
    gate_path = output_dir / V08D_CHILD_OUTPUT_DIRNAME / "calibration_presignal_gate_v0_8d.json"
    if not gate_path.exists():
        raise ValueError("missing_v0_8d_calibration_presignal_gate")
    gate = read_json(gate_path)
    if (
        gate.get("policy_slice") != V08D_POLICY_SLICE_ID
        or gate.get("slice_id") != V08D_SLICE_ID
        or gate.get("runtime_backend") != "isaac_runtime"
        or gate.get("passed") is not False
        or gate.get("heldout_opened") is not False
        or gate.get("fresh_heldout_27000_27049_accessed") is not False
        or gate.get("mvp2_closed") is not False
        or gate.get("policy_uplift_proven") is not False
        or int(gate.get("baseline_calibration_rollout_count") or 0) != 30
        or int(gate.get("candidate_calibration_rollout_count") or 0) != 30
        or int(gate.get("candidate_failures_total") or 0) <= int(
            gate.get("candidate_failures_maximum") or 3
        )
    ):
        raise ValueError("invalid_v0_8d_failed_calibration_gate")
    gate["path"] = str(gate_path)
    gate["sha256"] = _sha256_file(gate_path)
    return gate, gate["sha256"]


def _load_v08d_calibration_trace_rows(output_dir: Path) -> list[dict[str, Any]]:
    trace_dir = (
        output_dir
        / V08D_CHILD_OUTPUT_DIRNAME
        / "isaac_runtime_fresh_calibration_v0_8d"
        / "isaac_runtime_heldout_rollout_traces"
    )
    if not trace_dir.exists():
        raise ValueError("missing_v0_8d_calibration_trace_dir")
    rows: list[dict[str, Any]] = []
    for path in sorted(trace_dir.glob("*.json")):
        payload = read_json(path)
        summary = payload.get("summary") if isinstance(payload.get("summary"), dict) else {}
        trace = payload.get("trace") if isinstance(payload.get("trace"), list) else []
        role = str(payload.get("policy_role") or payload.get("role") or path.name.split("_")[0])
        if role not in {"baseline", "candidate"}:
            continue
        seed = _seed_from_trace_payload_or_path(payload, path)
        rows.append(
            {
                "role": role,
                "seed": seed,
                "scenario_id": _scenario_id_from_trace_payload_or_path(payload, path),
                "summary": summary,
                "trace": trace,
                "trace_path": str(path),
                "trace_sha256": _sha256_file(path),
                "success": _rollout_success_from_summary(summary),
            }
        )
    if len(rows) != 60:
        raise ValueError("v0_8e_requires_60_v0_8d_calibration_traces")
    seeds_by_role: dict[str, list[int]] = {"baseline": [], "candidate": []}
    for row in rows:
        seeds_by_role[str(row["role"])].append(int(row["seed"]))
    expected = list(V08D_FRESH_CALIBRATION_RANGE)
    if sorted(seeds_by_role["baseline"]) != expected or sorted(seeds_by_role["candidate"]) != expected:
        raise ValueError("v0_8e_v08d_calibration_seed_range_mismatch")
    return rows


def _v08e_trace_metrics(summary: dict[str, Any], trace: list[dict[str, Any]]) -> dict[str, Any]:
    z_open_step: int | None = None
    z_count = 0
    z_longest = 0
    current_z = 0
    first_depth_positive_step: int | None = None
    max_depth = 0.0
    min_lateral = math.inf
    final_lateral = math.inf
    forced_capture_count = 0
    wait_count = 0
    for row in trace:
        step = int(row.get("step") or 0)
        action = row.get("normalized_action") if isinstance(row.get("normalized_action"), list) else []
        z_action = float(action[2]) if len(action) > 2 else 0.0
        diagnostics = row.get("controller_action_diagnostics")
        if isinstance(diagnostics, dict):
            if z_open_step is None and diagnostics.get("z_open_step") is not None:
                try:
                    z_open_step = int(diagnostics["z_open_step"])
                except (TypeError, ValueError):
                    z_open_step = None
            reason = diagnostics.get("capture_conditioning_reason")
            if reason == "forced_capture_conditioned_progress_z":
                forced_capture_count += 1
            elif reason == "capture_conditioning_wait":
                wait_count += 1
        if z_action < -1e-6:
            z_count += 1
            if z_open_step is None:
                z_open_step = step
            current_z += 1
            z_longest = max(z_longest, current_z)
        else:
            current_z = 0
        depth = float(row.get("insertion_depth_m") or 0.0)
        max_depth = max(max_depth, depth)
        if first_depth_positive_step is None and depth > 0.0:
            first_depth_positive_step = step
        lateral_value = row.get("lateral_error_m")
        lateral = float(lateral_value) if lateral_value is not None else math.inf
        min_lateral = min(min_lateral, lateral)
        final_lateral = lateral
    if min_lateral == math.inf:
        min_lateral = 0.0
    if final_lateral == math.inf:
        final_lateral = 0.0
    return {
        "env_native_first_success_step": summary.get("env_native_first_success_step"),
        "env_native_max_consecutive_success_steps": int(
            summary.get("env_native_max_consecutive_success_steps") or 0
        ),
        "z_open_step": z_open_step,
        "z_open_row_count": z_count,
        "z_longest_consecutive_steps": z_longest,
        "first_depth_positive_step": first_depth_positive_step,
        "max_insertion_depth_m": round(max_depth, 6),
        "min_lateral_error_m": round(min_lateral, 6),
        "final_lateral_error_m": round(final_lateral, 6),
        "forced_capture_conditioning_count": forced_capture_count,
        "capture_conditioning_wait_count": wait_count,
    }


def classify_v08e_candidate_failure(summary: dict[str, Any], trace: list[dict[str, Any]]) -> dict[str, Any]:
    metrics = _v08e_trace_metrics(summary, trace)
    first_success = metrics["env_native_first_success_step"]
    max_consecutive = int(metrics["env_native_max_consecutive_success_steps"])
    max_depth = float(metrics["max_insertion_depth_m"])
    min_lateral = float(metrics["min_lateral_error_m"])
    z_open_step = metrics["z_open_step"]
    first_depth_step = metrics["first_depth_positive_step"]
    z_count = int(metrics["z_open_row_count"])
    if first_success is not None and max_consecutive < 10 and max_depth >= 0.024:
        failure_class = "late_seat_window_shortfall"
    elif max_depth <= 0.001 and min_lateral >= 0.002 and z_count >= 50:
        failure_class = "off_center_no_capture"
    elif (
        first_success is None
        and max_depth < 0.024
        and min_lateral <= 0.0006
        and z_count > 0
        and (
            (z_open_step is not None and int(z_open_step) >= 84)
            or (first_depth_step is not None and int(first_depth_step) >= 119)
        )
    ):
        failure_class = "late_z_open_depth_shortfall"
    else:
        failure_class = "unclassified"
    return {
        "failure_class": failure_class,
        "failure_reason": summary.get("failure_reason") or "UNKNOWN",
        **metrics,
    }


def build_v08e_calibration_shortfall_diagnosis(*, output_dir: Path) -> dict[str, Any]:
    gate, gate_sha256 = load_required_v08d_failed_calibration_gate(output_dir)
    rows = _load_v08d_calibration_trace_rows(output_dir)
    paired: dict[int, dict[str, dict[str, Any]]] = {}
    for row in rows:
        paired.setdefault(int(row["seed"]), {})[str(row["role"])] = row
    if sorted(paired) != list(V08D_FRESH_CALIBRATION_RANGE):
        raise ValueError("v0_8e_v08d_calibration_pair_seed_range_mismatch")

    baseline_success_count = 0
    candidate_success_count = 0
    candidate_failures: list[dict[str, Any]] = []
    paired_outcome_counts = {"B1_C1": 0, "B0_C1": 0, "B1_C0": 0, "B0_C0": 0}
    for seed in sorted(paired):
        baseline = paired[seed].get("baseline")
        candidate = paired[seed].get("candidate")
        if baseline is None or candidate is None:
            raise ValueError(f"v0_8e_missing_paired_calibration_rollout_for_seed_{seed}")
        baseline_success = bool(baseline["success"])
        candidate_success = bool(candidate["success"])
        baseline_success_count += int(baseline_success)
        candidate_success_count += int(candidate_success)
        outcome = ("B1" if baseline_success else "B0") + "_" + ("C1" if candidate_success else "C0")
        paired_outcome_counts[outcome] += 1
        if not candidate_success:
            classification = classify_v08e_candidate_failure(candidate["summary"], candidate["trace"])
            candidate_failures.append(
                {
                    "seed": seed,
                    "scenario_id": candidate["scenario_id"],
                    "baseline_success": baseline_success,
                    "candidate_success": candidate_success,
                    "paired_outcome": outcome,
                    "baseline_trace_path": baseline["trace_path"],
                    "candidate_trace_path": candidate["trace_path"],
                    **classification,
                }
            )

    if int(gate.get("baseline_calibration_success_count") or 0) != baseline_success_count:
        raise ValueError("v0_8e_baseline_success_count_mismatch")
    if int(gate.get("candidate_calibration_success_count") or 0) != candidate_success_count:
        raise ValueError("v0_8e_candidate_success_count_mismatch")
    if int(gate.get("candidate_failures_total") or 0) != len(candidate_failures):
        raise ValueError("v0_8e_candidate_failure_count_mismatch")

    taxonomy: dict[str, dict[str, Any]] = {
        "late_z_open_depth_shortfall": {"count": 0, "seeds": []},
        "late_seat_window_shortfall": {"count": 0, "seeds": []},
        "off_center_no_capture": {"count": 0, "seeds": []},
        "unclassified": {"count": 0, "seeds": []},
    }
    for row in candidate_failures:
        failure_class = str(row["failure_class"])
        taxonomy[failure_class]["count"] += 1
        taxonomy[failure_class]["seeds"].append(int(row["seed"]))
    if taxonomy["unclassified"]["count"]:
        raise ValueError("v0_8e_unclassified_candidate_failures_present")

    child_dir = output_dir / V08E_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    write_json(child_dir / "candidate_failure_taxonomy_v0_8e.json", candidate_failures)

    candidate_failures_maximum = int(gate.get("candidate_failures_maximum") or 3)
    candidate_failures_to_recover = max(0, len(candidate_failures) - candidate_failures_maximum)
    diagnosis = {
        "schema_version": V08E_CALIBRATION_SHORTFALL_DIAGNOSIS_SCHEMA_VERSION,
        "policy_slice": V08E_POLICY_SLICE_ID,
        "source_policy_slice": V08D_POLICY_SLICE_ID,
        "slice_id": V08E_SLICE_ID,
        "source_slice_id": V08D_SLICE_ID,
        "runtime_backend": "offline_artifact_diagnosis",
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "proof_eligible": False,
        "calibration_opened": True,
        "heldout_opened": False,
        "fresh_heldout_27000_27049_accessed": False,
        "source_v08d_gate_path": str(gate["path"]),
        "source_v08d_gate_sha256": gate_sha256,
        "baseline_success_count": baseline_success_count,
        "candidate_success_count": candidate_success_count,
        "baseline_success_rate": gate.get("baseline_calibration_success_rate"),
        "candidate_success_rate": gate.get("candidate_calibration_success_rate"),
        "candidate_baseline_success_gap": gate.get("candidate_baseline_success_gap"),
        "paired_outcome_counts": paired_outcome_counts,
        "candidate_failures_total": len(candidate_failures),
        "candidate_failures_maximum": candidate_failures_maximum,
        "candidate_failures_to_recover_for_calibration_gate": candidate_failures_to_recover,
        "failure_taxonomy": taxonomy,
        "recommended_downstream_slice": V08E_RECOMMENDED_DOWNSTREAM_SLICE,
        "recommended_downstream_constraints": {
            "fresh_calibration_required": True,
            "do_not_reuse_calibration_seed_range": [
                min(V08D_FRESH_CALIBRATION_RANGE),
                max(V08D_FRESH_CALIBRATION_RANGE),
            ],
            "keep_fresh_heldout_27000_27049_sealed": True,
            "env_native_10_consecutive_success_authority_unchanged": True,
            "same_shared_authority_for_baseline_and_candidate": True,
            "attribution_preservation_gate_required": True,
            "target_failure_reduction_minimum": candidate_failures_to_recover,
            "dominant_repair_targets": [
                "earlier_z_open_with_horizon_reserve",
                "late_seat_hold_window_margin",
                "off_center_no_capture_guard",
            ],
            "forbidden_mechanisms": ["retry", "withdraw", "search", "force_control"],
        },
        "artifact_paths": {
            "candidate_failure_taxonomy": str(child_dir / "candidate_failure_taxonomy_v0_8e.json"),
        },
        "non_claims": {
            "closure_authority": False,
            "policy_uplift_proven": False,
            "heldout_ab_opened": False,
            "real_robot_success": False,
        },
    }
    diagnosis["v0_8e_calibration_shortfall_diagnosis_sha256"] = _sha256_payload_excluding(
        diagnosis,
        "v0_8e_calibration_shortfall_diagnosis_sha256",
    )
    write_json(child_dir / "v0_8e_calibration_shortfall_diagnosis.json", diagnosis)
    write_json(output_dir / "calibration_shortfall_diagnosis_v0_8e.json", diagnosis)
    return diagnosis


def _v08f_burned_seed_range_accessed(seed: int) -> bool:
    return _v08d_burned_heldout_seed_range_accessed(seed) or int(seed) in V08D_FRESH_CALIBRATION_RANGE


def load_required_v08e_calibration_shortfall_diagnosis(output_dir: Path) -> tuple[dict[str, Any], str]:
    diagnosis_path = (
        output_dir
        / V08E_CHILD_OUTPUT_DIRNAME
        / "v0_8e_calibration_shortfall_diagnosis.json"
    )
    if not diagnosis_path.exists():
        raise ValueError("missing_v0_8e_calibration_shortfall_diagnosis")
    diagnosis = read_json(diagnosis_path)
    taxonomy = diagnosis.get("failure_taxonomy") if isinstance(diagnosis.get("failure_taxonomy"), dict) else {}
    if (
        diagnosis.get("policy_slice") != V08E_POLICY_SLICE_ID
        or diagnosis.get("source_policy_slice") != V08D_POLICY_SLICE_ID
        or diagnosis.get("recommended_downstream_slice") != V08E_RECOMMENDED_DOWNSTREAM_SLICE
        or diagnosis.get("mvp2_closed") is not False
        or diagnosis.get("policy_uplift_proven") is not False
        or diagnosis.get("fresh_heldout_27000_27049_accessed") is not False
        or int(taxonomy.get("unclassified", {}).get("count", 0)) != 0
    ):
        raise ValueError("invalid_v0_8e_calibration_shortfall_diagnosis")
    diagnosis["path"] = str(diagnosis_path)
    diagnosis["sha256"] = _sha256_file(diagnosis_path)
    return diagnosis, diagnosis["sha256"]


