def build_v08h_fresh_manifest(*, output_dir: Path, failed_gate: dict[str, Any]) -> dict[str, Any]:
    calibration_rows = [_scenario_row(split="calibration", seed=seed) for seed in V08H_FRESH_CALIBRATION_RANGE]
    heldout_rows = [_scenario_row(split="held_out", seed=seed) for seed in V08H_FRESH_HELDOUT_RANGE]
    for row in calibration_rows + heldout_rows:
        if _v08h_burned_seed_range_accessed(int(row["seed"])):
            raise ValueError("v0_8h_fresh_manifest_reuses_burned_seed_range")
    manifest = {
        "schema_version": V08H_MANIFEST_SCHEMA_VERSION,
        "policy_slice": V08H_POLICY_SLICE_ID,
        "slice_id": V08H_SLICE_ID,
        "parent_policy_slice": V08G_POLICY_SLICE_ID,
        "source_policy_slice": V08G_POLICY_SLICE_ID,
        "scenario_profile": "v0_8h",
        "task_type": "connector_insertion",
        "success_metric": SUCCESS_METRIC,
        "success_authority": V06_ENV_NATIVE_SUCCESS_AUTHORITY,
        "source_v08g_calibration_presignal_gate_sha256": failed_gate["sha256"],
        "source_v08g_failure_reason": failed_gate.get("failure_reason"),
        "scenarios": calibration_rows + heldout_rows,
        "fresh_split_manifest": {
            "calibration": {
                "seed_range": [min(V08H_FRESH_CALIBRATION_RANGE), max(V08H_FRESH_CALIBRATION_RANGE)],
                "scenario_ids": [row["scenario_id"] for row in calibration_rows],
                "count": len(calibration_rows),
            },
            "held_out": {
                "seed_range": [min(V08H_FRESH_HELDOUT_RANGE), max(V08H_FRESH_HELDOUT_RANGE)],
                "scenario_ids": [row["scenario_id"] for row in heldout_rows],
                "count": len(heldout_rows),
            },
        },
        "burned_heldout_seed_ranges": [
            list(V07A2_PROTECTED_HELDOUT_SEED_RANGE),
            [min(V08A_FRESH_HELDOUT_RANGE), max(V08A_FRESH_HELDOUT_RANGE)],
            [min(V08B_FRESH_HELDOUT_RANGE), max(V08B_FRESH_HELDOUT_RANGE)],
        ],
        "burned_calibration_seed_ranges": [
            [min(V08D_FRESH_CALIBRATION_RANGE), max(V08D_FRESH_CALIBRATION_RANGE)],
            [min(V08F_FRESH_CALIBRATION_RANGE), max(V08F_FRESH_CALIBRATION_RANGE)],
            [min(V08G_FRESH_CALIBRATION_RANGE), max(V08G_FRESH_CALIBRATION_RANGE)],
        ],
        "fresh_calibration_26500_26529_accessed": True,
        "fresh_calibration_27500_27529_accessed": True,
        "fresh_calibration_28000_28029_accessed": True,
        "fresh_calibration_28500_28529_accessed": False,
        "fresh_heldout_27000_27049_accessed": False,
        "heldout_21000_21049_accessed": False,
        "fresh_heldout_24000_24049_accessed": False,
        "fresh_heldout_26000_26049_accessed": False,
        "calibration_opened": False,
        "heldout_opened": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    manifest["manifest_sha256"] = _sha256_payload_excluding(manifest, "manifest_sha256")
    return manifest


def build_v08h_policy_artifact_payload(
    *,
    base_policy_artifact: dict[str, Any],
    early_centered_config: dict[str, Any],
    dataset_view_role: str,
) -> dict[str, Any]:
    role = "candidate" if dataset_view_role == "candidate_curated" else "baseline"
    payload = {
        key: value
        for key, value in base_policy_artifact.items()
        if key not in {"path", "policy_artifact_sha256"}
    }
    payload.update(
        {
            "schema_version": V08H_POLICY_ARTIFACT_SCHEMA_VERSION,
            "policy_id": f"{role}_mvp2e_v08h_early_centered_z_open_safe_entry_policy",
            "policy_slice": V08H_POLICY_SLICE_ID,
            "slice_id": V08H_SLICE_ID,
            "parent_policy_slice": V08G_POLICY_SLICE_ID,
            "source_policy_slice": V08G_POLICY_SLICE_ID,
            "parent_policy_artifact_sha256": base_policy_artifact.get("policy_artifact_sha256"),
            "dataset_view_role": dataset_view_role,
            "early_centered_z_open_safe_entry_authority_id": (
                V08H_EARLY_CENTERED_Z_OPEN_SAFE_ENTRY_AUTHORITY_ID
            ),
            "early_centered_z_open_safe_entry_config": early_centered_config,
            "early_centered_z_open_safe_entry_config_sha256": early_centered_config[
                "early_centered_z_open_safe_entry_config_sha256"
            ],
            "same_early_centered_z_open_safe_entry_config_as_peer": True,
            "source_failed_fresh_calibration_28000_28029_accessed": True,
            "fresh_calibration_26500_26529_accessed": True,
            "fresh_calibration_27500_27529_accessed": True,
            "fresh_calibration_28000_28029_accessed": True,
            "fresh_calibration_28500_28529_accessed": False,
            "heldout_21000_21049_accessed": False,
            "fresh_heldout_24000_24049_accessed": False,
            "fresh_heldout_26000_26049_accessed": False,
            "fresh_heldout_27000_27049_accessed": False,
            "mvp2_closed": False,
            "policy_uplift_proven": False,
        }
    )
    payload["policy_artifact_sha256"] = _sha256_payload_excluding(payload, "policy_artifact_sha256")
    return payload


def build_v08h_early_centered_z_open_safe_entry_slice(*, output_dir: Path) -> dict[str, Any]:
    failed_gate, _failed_gate_sha256 = load_required_v08g_failed_calibration_presignal_gate(output_dir)
    parent_policy_artifacts = _load_v08g_policy_artifacts(output_dir)
    child_dir = output_dir / V08H_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    early_centered_config = derive_v08h_early_centered_z_open_safe_entry_config(output_dir=output_dir)
    write_json(child_dir / "v0_8h_early_centered_z_open_safe_entry_config.json", early_centered_config)
    candidate_policy = build_v08h_policy_artifact_payload(
        base_policy_artifact=parent_policy_artifacts["candidate"],
        early_centered_config=early_centered_config,
        dataset_view_role="candidate_curated",
    )
    baseline_policy = build_v08h_policy_artifact_payload(
        base_policy_artifact=parent_policy_artifacts["baseline"],
        early_centered_config=early_centered_config,
        dataset_view_role="baseline_uncurated",
    )
    write_json(child_dir / "candidate_policy_artifact_v0_8h.json", candidate_policy)
    write_json(child_dir / "baseline_policy_artifact_v0_8h.json", baseline_policy)
    manifest = build_v08h_fresh_manifest(output_dir=output_dir, failed_gate=failed_gate)
    manifest.update(
        {
            "early_centered_z_open_safe_entry_authority_id": V08H_EARLY_CENTERED_Z_OPEN_SAFE_ENTRY_AUTHORITY_ID,
            "early_centered_z_open_safe_entry_config_sha256": early_centered_config[
                "early_centered_z_open_safe_entry_config_sha256"
            ],
            "candidate_policy_artifact_sha256": candidate_policy["policy_artifact_sha256"],
            "baseline_policy_artifact_sha256": baseline_policy["policy_artifact_sha256"],
            "same_early_centered_z_open_safe_entry_config_as_peer": (
                candidate_policy["early_centered_z_open_safe_entry_config_sha256"]
                == baseline_policy["early_centered_z_open_safe_entry_config_sha256"]
            ),
            "artifacts": {
                "early_centered_z_open_safe_entry_config": (
                    f"{V08H_CHILD_OUTPUT_DIRNAME}/"
                    "v0_8h_early_centered_z_open_safe_entry_config.json"
                ),
                "candidate_policy_artifact": (
                    f"{V08H_CHILD_OUTPUT_DIRNAME}/candidate_policy_artifact_v0_8h.json"
                ),
                "baseline_policy_artifact": f"{V08H_CHILD_OUTPUT_DIRNAME}/baseline_policy_artifact_v0_8h.json",
            },
        }
    )
    manifest["manifest_sha256"] = _sha256_payload_excluding(manifest, "manifest_sha256")
    write_json(child_dir / "v0_8h_fresh_manifest.json", manifest)
    return manifest


def _load_v08h_policy_artifacts(output_dir: Path) -> dict[str, dict[str, Any]]:
    child_dir = output_dir / V08H_CHILD_OUTPUT_DIRNAME
    candidate_path = child_dir / "candidate_policy_artifact_v0_8h.json"
    baseline_path = child_dir / "baseline_policy_artifact_v0_8h.json"
    if not candidate_path.exists() or not baseline_path.exists():
        raise ValueError("missing_v0_8h_policy_artifacts")
    baseline = read_json(baseline_path)
    candidate = read_json(candidate_path)
    reasons: list[str] = []
    for role, policy in (("baseline", baseline), ("candidate", candidate)):
        if policy.get("policy_slice") != V08H_POLICY_SLICE_ID:
            reasons.append(f"{role}_policy_slice_mismatch")
        if policy.get("parent_policy_slice") != V08G_POLICY_SLICE_ID:
            reasons.append(f"{role}_parent_policy_slice_mismatch")
        if policy.get("fresh_calibration_28500_28529_accessed") is not False:
            reasons.append(f"{role}_fresh_calibration_accessed_before_runtime")
        if policy.get("fresh_heldout_27000_27049_accessed") is not False:
            reasons.append(f"{role}_fresh_heldout_accessed_before_closure")
        expected_hash = _sha256_payload_excluding(policy, "policy_artifact_sha256")
        if policy.get("policy_artifact_sha256") != expected_hash:
            reasons.append(f"{role}_policy_hash_mismatch")
    equality_keys = (
        "selected_action_adapter_id",
        "trainer",
        "trainer_family",
        "policy_class",
        "feature_schema",
        "feature_schema_version",
        "phase_schema",
        "final_post_adapter_authority_config_sha256",
        "final_post_adapter_xy_authority_config_sha256",
        "base_servo_config_sha256",
        "shared_hysteresis_authority_config_sha256",
        "capture_conditioned_progress_authority_config_sha256",
        "horizon_reserved_capture_authority_config_sha256",
        "deadline_precedence_horizon_authority_config_sha256",
        "early_centered_z_open_safe_entry_config_sha256",
    )
    for key in equality_keys:
        if baseline.get(key) != candidate.get(key):
            reasons.append(f"peer_{key}_mismatch")
    if reasons:
        raise ValueError("v0_8h_policy_peer_fairness_failed: " + ",".join(reasons))
    return {
        "baseline": {**baseline, "path": str(baseline_path)},
        "candidate": {**candidate, "path": str(candidate_path)},
    }


def _v08h_runtime_manifest_for_split(*, fresh_manifest: dict[str, Any], split: str) -> dict[str, Any]:
    if split not in {"calibration", "held_out"}:
        raise ValueError("v0_8h_runtime_manifest_unknown_split")
    rows = [
        {**row, "source_split": split, "semantic_eval_split": split, "split": "held_out"}
        for row in fresh_manifest.get("scenarios", [])
        if isinstance(row, dict) and row.get("split") == split
    ]
    if not rows:
        raise ValueError(f"v0_8h_runtime_manifest_missing_{split}_rows")
    seeds = [int(row["seed"]) for row in rows]
    if any(_v08h_burned_seed_range_accessed(seed) for seed in seeds):
        raise ValueError("v0_8h_runtime_manifest_reuses_burned_seed_range")
    if split == "calibration" and seeds != list(V08H_FRESH_CALIBRATION_RANGE):
        raise ValueError("v0_8h_calibration_seed_range_mismatch")
    if split == "held_out" and seeds != list(V08H_FRESH_HELDOUT_RANGE):
        raise ValueError("v0_8h_heldout_seed_range_mismatch")
    manifest = {
        "schema_version": fresh_manifest["schema_version"],
        "policy_slice": V08H_POLICY_SLICE_ID,
        "slice_id": V08H_SLICE_ID,
        "parent_policy_slice": V08G_POLICY_SLICE_ID,
        "scenario_profile": "v0_8h",
        "runtime_split": split,
        "task_type": fresh_manifest["task_type"],
        "success_metric": fresh_manifest["success_metric"],
        "success_authority": fresh_manifest["success_authority"],
        "source_fresh_manifest_sha256": fresh_manifest["manifest_sha256"],
        "scenarios": rows,
        "burned_heldout_seed_ranges": fresh_manifest["burned_heldout_seed_ranges"],
        "burned_calibration_seed_ranges": fresh_manifest["burned_calibration_seed_ranges"],
        "heldout_21000_21049_accessed": False,
        "fresh_heldout_24000_24049_accessed": False,
        "fresh_heldout_26000_26049_accessed": False,
        "fresh_calibration_26500_26529_accessed": True,
        "fresh_calibration_27500_27529_accessed": True,
        "fresh_calibration_28000_28029_accessed": True,
        "fresh_calibration_28500_28529_accessed": split == "calibration",
        "fresh_heldout_27000_27049_accessed": split == "held_out",
        "calibration_opened": split == "calibration",
        "heldout_opened": split == "held_out",
        "proof_authority": split == "held_out",
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    manifest["manifest_sha256"] = _sha256_payload_excluding(manifest, "manifest_sha256")
    return manifest


def _write_v08h_calibration_external_rollouts(
    *,
    output_dir: Path,
    baseline_rollouts: list[dict[str, Any]],
    candidate_rollouts: list[dict[str, Any]],
) -> dict[str, str]:
    rollout_dir = output_dir / "calibration_external_rollouts"
    rollout_dir.mkdir(parents=True, exist_ok=True)
    baseline_path = rollout_dir / "baseline_calibration_rollouts_v0_8h.json"
    candidate_path = rollout_dir / "candidate_calibration_rollouts_v0_8h.json"
    write_json(baseline_path, baseline_rollouts)
    write_json(candidate_path, candidate_rollouts)
    return {"baseline": str(baseline_path), "candidate": str(candidate_path)}


def derive_v08h_calibration_presignal_gate(
    *,
    baseline_rollouts: list[dict[str, Any]],
    candidate_rollouts: list[dict[str, Any]],
    runtime_gate: dict[str, Any],
    runtime_metadata: dict[str, Any],
    trace_paths: dict[str, list[str]],
) -> dict[str, Any]:
    gate = derive_v08d_calibration_presignal_gate(
        baseline_rollouts=baseline_rollouts,
        candidate_rollouts=candidate_rollouts,
        runtime_gate=runtime_gate,
        runtime_metadata=runtime_metadata,
        trace_paths=trace_paths,
    )
    gate.update(
        {
            "schema_version": V08H_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
            "policy_slice": V08H_POLICY_SLICE_ID,
            "slice_id": V08H_SLICE_ID,
            "parent_policy_slice": V08G_POLICY_SLICE_ID,
            "fresh_calibration_26500_26529_accessed": True,
            "fresh_calibration_27500_27529_accessed": True,
            "fresh_calibration_28000_28029_accessed": True,
            "fresh_calibration_28500_28529_accessed": True,
            "fresh_heldout_27000_27049_accessed": False,
            "fresh_heldout_24000_24049_accessed": False,
            "fresh_heldout_26000_26049_accessed": False,
            "source": "v0_8h_fresh_calibration_runtime",
        }
    )
    gate["calibration_presignal_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "calibration_presignal_gate_sha256",
    )
    return gate


def run_v08h_early_centered_z_open_safe_entry_runtime(
    *,
    output_dir: Path,
    device: str = DEFAULT_ISAAC_DEVICE,
    headless: bool = True,
    isaac_task: str = DEFAULT_ISAAC_TASK,
    max_steps: int = int(SUCCESS_METRIC["max_steps"]),
    action_scale: float = 1.0,
    min_rollouts_per_policy: int = MIN_PROOF_ROLLOUTS_PER_POLICY,
    bootstrap_iterations: int = 2000,
    bootstrap_seed: int = 23,
    backend: Any | None = None,
) -> dict[str, Any]:
    child_dir = output_dir / V08H_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    fresh_manifest = build_v08h_early_centered_z_open_safe_entry_slice(output_dir=output_dir)
    policy_artifacts = _load_v08h_policy_artifacts(output_dir)
    baseline_policy = policy_artifacts["baseline"]
    candidate_policy = policy_artifacts["candidate"]
    selected_adapter_id = str(candidate_policy["selected_action_adapter_id"])
    policy_class = str(candidate_policy["policy_class"])
    trainer = str(candidate_policy["trainer"])
    use_single_app_actual_backend = (
        backend is None
        and getattr(IsaacConnectorInsertionEvaluatorBackend, "__name__", "")
        == "IsaacConnectorInsertionEvaluatorBackend"
    )
    evaluator_backend = backend or IsaacConnectorInsertionEvaluatorBackend(
        task=isaac_task,
        device=device,
        headless=headless,
        action_scale=action_scale,
        max_steps=max_steps,
    )
    actual_env = None
    actual_simulation_app = None
    actual_torch = None
    if use_single_app_actual_backend:
        from isaaclab.app import AppLauncher

        app_launcher = AppLauncher(
            {
                "headless": headless,
                "device": device,
                "enable_cameras": False,
            }
        )
        actual_simulation_app = app_launcher.app

        import gymnasium as gym
        import torch as torch_module

        import isaaclab_tasks  # noqa: F401
        from isaaclab_tasks.utils import parse_env_cfg

        env_cfg = parse_env_cfg(isaac_task, device=device, num_envs=1)
        actual_env = gym.make(isaac_task, cfg=env_cfg).unwrapped
        actual_torch = torch_module

    def run_runtime_manifest(
        *,
        manifest: dict[str, Any],
        runtime_output_dir: Path,
        rollouts_per_policy: int,
    ) -> BackendResult:
        if actual_env is not None:
            return _run_v08a_manifest_with_existing_isaac(
                evaluator_backend=evaluator_backend,
                env=actual_env,
                simulation_app=actual_simulation_app,
                torch_module=actual_torch,
                manifest=manifest,
                output_dir=runtime_output_dir,
                min_rollouts_per_policy=rollouts_per_policy,
                policy_artifacts=policy_artifacts,
            )
        return evaluator_backend.run(
            manifest=manifest,
            output_dir=runtime_output_dir,
            min_rollouts_per_policy=rollouts_per_policy,
            deterministic_profile="candidate_positive",
            policy_artifacts=policy_artifacts,
        )

    calibration_manifest = _v08h_runtime_manifest_for_split(
        fresh_manifest=fresh_manifest,
        split="calibration",
    )
    write_json(child_dir / "calibration_runtime_manifest_v0_8h.json", calibration_manifest)
    calibration_result = run_runtime_manifest(
        manifest=calibration_manifest,
        runtime_output_dir=child_dir / "isaac_runtime_fresh_calibration_v0_8h",
        rollouts_per_policy=V07H_CALIBRATION_ROLLOUTS_PER_POLICY,
    )
    calibration_rollout_paths = _write_v08h_calibration_external_rollouts(
        output_dir=child_dir,
        baseline_rollouts=list(calibration_result.baseline_rollouts),
        candidate_rollouts=list(calibration_result.candidate_rollouts),
    )
    calibration_trace_paths = {
        "baseline": list(calibration_result.baseline_trace_paths),
        "candidate": list(calibration_result.candidate_trace_paths),
    }
    calibration_gate = derive_v08h_calibration_presignal_gate(
        baseline_rollouts=list(calibration_result.baseline_rollouts),
        candidate_rollouts=list(calibration_result.candidate_rollouts),
        runtime_gate=dict(calibration_result.runtime_gate),
        runtime_metadata=dict(calibration_result.runtime_metadata),
        trace_paths=calibration_trace_paths,
    )
    calibration_gate["calibration_runtime_manifest_sha256"] = calibration_manifest["manifest_sha256"]
    calibration_gate["baseline_calibration_rollout_path"] = calibration_rollout_paths["baseline"]
    calibration_gate["candidate_calibration_rollout_path"] = calibration_rollout_paths["candidate"]
    calibration_gate["calibration_presignal_gate_sha256"] = _sha256_payload_excluding(
        calibration_gate,
        "calibration_presignal_gate_sha256",
    )
    write_json(child_dir / "calibration_presignal_gate_v0_8h.json", calibration_gate)
    write_json(
        output_dir / "calibration_presignal_gate.json",
        {
            "schema_version": V08H_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
            "policy_slice": V08H_POLICY_SLICE_ID,
            "slice_id": V08H_SLICE_ID,
            "passed": calibration_gate["passed"],
            "source_gate_path": f"{V08H_CHILD_OUTPUT_DIRNAME}/calibration_presignal_gate_v0_8h.json",
            "calibration_opened": True,
            "heldout_opened": False,
            "heldout_21000_21049_accessed": False,
            "fresh_heldout_24000_24049_accessed": False,
            "fresh_heldout_26000_26049_accessed": False,
            "fresh_calibration_26500_26529_accessed": True,
            "fresh_calibration_27500_27529_accessed": True,
            "fresh_calibration_28000_28029_accessed": True,
            "fresh_calibration_28500_28529_accessed": True,
            "fresh_heldout_27000_27049_accessed": False,
            "heldout_allowed": calibration_gate["heldout_allowed"],
            "mvp2_closed": False,
            "policy_uplift_proven": False,
        },
    )
    if calibration_gate.get("passed") is not True:
        calibration_gate["mvp2_closed"] = False
        calibration_gate["policy_uplift_proven"] = False
        if actual_env is not None:
            actual_env.close()
        return calibration_gate

    selection = _v08a_calibration_selection_report(output_dir)
    training_scenario_ids = _v08a_training_scenario_ids(output_dir)
    heldout_manifest = _v08h_runtime_manifest_for_split(
        fresh_manifest=fresh_manifest,
        split="held_out",
    )
    write_json(child_dir / "heldout_runtime_manifest_v0_8h.json", heldout_manifest)
    heldout_leakage_guard = validate_no_heldout_leakage(
        manifest=heldout_manifest,
        training_scenario_ids=training_scenario_ids,
        curation_tuning_scenario_ids=[],
        threshold_tuning_scenario_ids=[],
        hyperparameter_scenario_ids=[],
        calibration_selector_scenario_ids=[str(item) for item in selection.get("calibration_scenario_ids", [])],
    )
    if heldout_leakage_guard["passed"] is not True:
        raise ValueError("v0_8h_fresh_heldout_leakage_guard_failed")

    baseline_view = _existing_train_view(
        output_dir / "baseline_uncurated_train.hdf5",
        view_id="baseline_uncurated_mvp2c_train_view",
    )
    candidate_view = _existing_train_view(
        output_dir / "candidate_curated_train.hdf5",
        view_id="candidate_curated_mvp2c_train_view",
    )
    bridge_dir = _write_learning_harness_bridge(
        output_dir=child_dir,
        manifest=heldout_manifest,
        baseline_view=baseline_view,
        candidate_view=candidate_view,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    heldout_rollouts_per_policy = max(
        int(min_rollouts_per_policy),
        STRONGER_PUBLIC_ROLLOUTS_PER_POLICY,
        len(V08H_FRESH_HELDOUT_RANGE),
    )
    heldout_result = run_runtime_manifest(
        manifest=heldout_manifest,
        runtime_output_dir=child_dir / "isaac_runtime_fresh_heldout_v0_8h",
        rollouts_per_policy=heldout_rollouts_per_policy,
    )
    runtime_gate = dict(heldout_result.runtime_gate)
    actual_rollouts_per_policy = min(
        len(heldout_result.baseline_rollouts),
        len(heldout_result.candidate_rollouts),
    )
    runtime_gate["actual_baseline_rollouts"] = len(heldout_result.baseline_rollouts)
    runtime_gate["actual_candidate_rollouts"] = len(heldout_result.candidate_rollouts)
    runtime_gate["actual_rollouts_per_policy"] = actual_rollouts_per_policy
    combined_rollouts = list(heldout_result.baseline_rollouts) + list(heldout_result.candidate_rollouts)
    if any(_v08h_burned_seed_range_accessed(int(rollout.get("seed", -1))) for rollout in combined_rollouts):
        raise ValueError("v0_8h_burned_seed_accessed")
    heldout_suite = _heldout_suite(heldout_manifest)
    baseline_rollouts_path = _write_external_rollout_json(
        output_dir=child_dir,
        role="baseline",
        policy_artifact=baseline_policy,
        train_view=baseline_view,
        heldout_suite=heldout_suite,
        backend_result=heldout_result,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    candidate_rollouts_path = _write_external_rollout_json(
        output_dir=child_dir,
        role="candidate",
        policy_artifact=candidate_policy,
        train_view=candidate_view,
        heldout_suite=heldout_suite,
        backend_result=heldout_result,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    learning_report = _run_learning_validator(
        output_dir=child_dir,
        bridge_dir=bridge_dir,
        baseline_rollouts_path=baseline_rollouts_path,
        candidate_rollouts_path=candidate_rollouts_path,
        min_rollouts_per_policy=MIN_PROOF_ROLLOUTS_PER_POLICY,
        bootstrap_iterations=bootstrap_iterations,
        bootstrap_seed=bootstrap_seed,
        policy_class=policy_class,
        trainer=trainer,
    )
    train_generation_runtime_gate, train_gate_sha256 = load_v07a2_parent_train_generation_gate(output_dir)
    closure = derive_mvp2c_closure(
        learning_report=learning_report,
        runtime_gate=runtime_gate,
        train_generation_runtime_gate=train_generation_runtime_gate,
        calibration_selection_report=selection,
        heldout_leakage_guard=heldout_leakage_guard,
        actual_rollouts_per_policy=actual_rollouts_per_policy,
    )
    confidence_interval_report = _bootstrap_uplift_ci(
        baseline_rollouts=list(heldout_result.baseline_rollouts),
        candidate_rollouts=list(heldout_result.candidate_rollouts),
        iterations=bootstrap_iterations,
        seed=bootstrap_seed,
    )
    gate = {
        "schema_version": V08H_HELDOUT_CLOSURE_SCHEMA_VERSION,
        "policy_slice": V08H_POLICY_SLICE_ID,
        "slice_id": V08H_SLICE_ID,
        "parent_policy_slice": V08G_POLICY_SLICE_ID,
        "source_fresh_manifest_sha256": fresh_manifest["manifest_sha256"],
        "early_centered_z_open_safe_entry_config_sha256": candidate_policy[
            "early_centered_z_open_safe_entry_config_sha256"
        ],
        "parent_train_generation_runtime_gate_sha256": train_gate_sha256,
        "fresh_calibration_presignal_gate_sha256": calibration_gate["calibration_presignal_gate_sha256"],
        "runtime_backend": heldout_result.runtime_backend,
        "proof_runtime": heldout_result.proof_runtime,
        "runtime_gate": runtime_gate,
        "actual_rollouts_per_policy": actual_rollouts_per_policy,
        "baseline_success_rate": learning_report.get("baseline_success_rate"),
        "candidate_success_rate": learning_report.get("candidate_success_rate"),
        "curated_vs_uncurated_uplift": learning_report.get("curated_vs_uncurated_uplift"),
        "learning_report_path": str(
            child_dir / "mvp2_learning_proven_policy_eval" / "mvp2_learning_proven_report.json"
        ),
        "baseline_external_rollouts": str(baseline_rollouts_path),
        "candidate_external_rollouts": str(candidate_rollouts_path),
        "confidence_interval_report": confidence_interval_report,
        "stronger_public_evidence_target_passed": _derive_public_evidence_target(
            actual_rollouts_per_policy=actual_rollouts_per_policy,
            confidence_interval_report=confidence_interval_report,
        ),
        "calibration_opened": True,
        "heldout_opened": True,
        "heldout_21000_21049_accessed": False,
        "fresh_heldout_24000_24049_accessed": False,
        "fresh_heldout_26000_26049_accessed": False,
        "fresh_calibration_26500_26529_accessed": True,
        "fresh_calibration_27500_27529_accessed": True,
        "fresh_calibration_28000_28029_accessed": True,
        "fresh_calibration_28500_28529_accessed": True,
        "fresh_heldout_27000_27049_accessed": True,
        "same_heldout_reuse_allowed_for_closure": False,
        "heldout_leakage_guard": heldout_leakage_guard,
        "calibration_selection_report_sha256": _sha256_file(output_dir / "calibration_selection_report.json"),
        "selected_action_adapter_id": selected_adapter_id,
        "same_adapter_used_for_baseline_and_candidate": True,
        "same_policy_class": baseline_policy.get("policy_class") == candidate_policy.get("policy_class"),
        "same_trainer": baseline_policy.get("trainer") == candidate_policy.get("trainer"),
        "same_feature_schema": baseline_policy.get("feature_schema") == candidate_policy.get("feature_schema"),
        "mvp2_closed": closure["mvp2_closed"],
        "mvp2c_close_minimum_passed": closure["mvp2c_close_minimum_passed"],
        "policy_uplift_proven": closure["learning_proven"],
        "proof_eligible": closure["proof_eligible"],
        "blockers": closure["blockers"] + list(learning_report.get("blockers") or []),
        "non_claims": {
            "deployable_real_robot_policy": False,
            "visual_policy_performance": False,
            "real_robot_success": False,
            "physical_robot_readiness": False,
            "universal_robot_support": False,
            "hmd_openxr_readiness": False,
        },
    }
    gate["heldout_closure_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "heldout_closure_gate_sha256",
    )
    write_json(child_dir / "heldout_closure_gate_v0_8h.json", gate)
    write_json(output_dir / "heldout_closure_gate.json", gate)
    if actual_env is not None:
        actual_env.close()
    return gate


def load_required_v08h_failed_calibration_gate(output_dir: Path) -> tuple[dict[str, Any], str]:
    gate_path = output_dir / V08H_CHILD_OUTPUT_DIRNAME / "calibration_presignal_gate_v0_8h.json"
    if not gate_path.exists():
        raise ValueError("missing_v0_8h_failed_calibration_presignal_gate")
    gate = read_json(gate_path)
    if (
        gate.get("schema_version") != V08H_CALIBRATION_PRESIGNAL_SCHEMA_VERSION
        or gate.get("policy_slice") != V08H_POLICY_SLICE_ID
        or gate.get("slice_id") != V08H_SLICE_ID
        or gate.get("runtime_backend") != "isaac_runtime"
        or gate.get("passed") is not False
        or gate.get("heldout_opened") is not False
        or gate.get("fresh_heldout_27000_27049_accessed") is not False
        or int(gate.get("candidate_failures_total", 0)) <= 0
    ):
        raise ValueError("invalid_v0_8h_failed_calibration_gate")
    gate["path"] = str(gate_path)
    gate["sha256"] = _sha256_file(gate_path)
    return gate, gate["sha256"]


def _load_v08h_calibration_trace_rows(output_dir: Path) -> list[dict[str, Any]]:
    trace_dir = (
        output_dir
        / V08H_CHILD_OUTPUT_DIRNAME
        / "isaac_runtime_fresh_calibration_v0_8h"
        / "isaac_runtime_heldout_rollout_traces"
    )
    if not trace_dir.exists():
        raise ValueError("missing_v0_8h_calibration_trace_dir")
    rows: list[dict[str, Any]] = []
    for path in sorted(trace_dir.glob("*.json")):
        payload = read_json(path)
        role = "candidate" if path.name.startswith("candidate_") else "baseline" if path.name.startswith("baseline_") else ""
        if role not in {"baseline", "candidate"}:
            continue
        summary = payload.get("summary") if isinstance(payload.get("summary"), dict) else {}
        trace = payload.get("trace")
        if not isinstance(trace, list) or not trace:
            raise ValueError("v0_8i_v08h_trace_invalid")
        rows.append(
            {
                "role": role,
                "seed": _seed_from_trace_payload_or_path(payload, path),
                "scenario_id": _scenario_id_from_trace_payload_or_path(payload, path),
                "summary": summary,
                "trace": trace,
                "trace_path": str(path),
                "trace_sha256": _sha256_file(path),
                "success": _rollout_success_from_summary(summary),
            }
        )
    if len(rows) != 60:
        raise ValueError("v0_8i_requires_60_v0_8h_calibration_traces")
    seeds_by_role: dict[str, list[int]] = {"baseline": [], "candidate": []}
    for row in rows:
        seeds_by_role[str(row["role"])].append(int(row["seed"]))
    expected = list(V08H_FRESH_CALIBRATION_RANGE)
    if sorted(seeds_by_role["baseline"]) != expected or sorted(seeds_by_role["candidate"]) != expected:
        raise ValueError("v0_8i_v08h_calibration_seed_range_mismatch")
    return rows


def classify_v08i_candidate_failure(summary: dict[str, Any], trace: list[dict[str, Any]]) -> dict[str, Any]:
    metrics = _v08e_trace_metrics(summary, trace)
    first_success = metrics["env_native_first_success_step"]
    max_consecutive = int(metrics["env_native_max_consecutive_success_steps"])
    max_depth = float(metrics["max_insertion_depth_m"])
    min_lateral = float(metrics["min_lateral_error_m"])
    z_open_step = metrics["z_open_step"]
    first_depth_step = metrics["first_depth_positive_step"]
    z_count = int(metrics["z_open_row_count"])
    if first_success is not None and max_consecutive < 10 and max_depth >= 0.024:
        failure_class = "late_seat_window_shortfall"
    elif first_success is None and max_depth <= 0.001 and min_lateral <= 0.003 and z_count >= 50:
        failure_class = "centered_no_depth_contact_miss"
    elif (
        first_success is None
        and max_depth < 0.024
        and min_lateral <= 0.0015
        and z_count > 0
        and (
            (first_depth_step is not None and int(first_depth_step) >= 110)
            or (z_open_step is not None and int(z_open_step) >= 80)
        )
    ):
        failure_class = "under_depth_late_entry"
    else:
        failure_class = "unclassified"
    return {
        "failure_class": failure_class,
        "failure_reason": summary.get("failure_reason") or "UNKNOWN",
        **metrics,
    }


def build_v08i_calibration_uplift_compression_diagnosis(*, output_dir: Path) -> dict[str, Any]:
    gate, gate_sha256 = load_required_v08h_failed_calibration_gate(output_dir)
    rows = _load_v08h_calibration_trace_rows(output_dir)
    paired: dict[int, dict[str, dict[str, Any]]] = {}
    for row in rows:
        paired.setdefault(int(row["seed"]), {})[str(row["role"])] = row
    if sorted(paired) != list(V08H_FRESH_CALIBRATION_RANGE):
        raise ValueError("v0_8i_v08h_calibration_pair_seed_range_mismatch")

    baseline_success_count = 0
    candidate_success_count = 0
    candidate_failures: list[dict[str, Any]] = []
    paired_outcome_counts = {"B1_C1": 0, "B0_C1": 0, "B1_C0": 0, "B0_C0": 0}
    for seed in sorted(paired):
        baseline = paired[seed].get("baseline")
        candidate = paired[seed].get("candidate")
        if baseline is None or candidate is None:
            raise ValueError(f"v0_8i_missing_paired_calibration_rollout_for_seed_{seed}")
        baseline_success = bool(baseline["success"])
        candidate_success = bool(candidate["success"])
        baseline_success_count += int(baseline_success)
        candidate_success_count += int(candidate_success)
        outcome = ("B1" if baseline_success else "B0") + "_" + ("C1" if candidate_success else "C0")
        paired_outcome_counts[outcome] += 1
        if not candidate_success:
            classification = classify_v08i_candidate_failure(candidate["summary"], candidate["trace"])
            candidate_failures.append(
                {
                    "seed": seed,
                    "scenario_id": candidate["scenario_id"],
                    "baseline_success": baseline_success,
                    "candidate_success": candidate_success,
                    "paired_outcome": outcome,
                    "baseline_trace_path": baseline["trace_path"],
                    "candidate_trace_path": candidate["trace_path"],
                    **classification,
                }
            )

    if int(gate.get("baseline_calibration_success_count") or 0) != baseline_success_count:
        raise ValueError("v0_8i_baseline_success_count_mismatch")
    if int(gate.get("candidate_calibration_success_count") or 0) != candidate_success_count:
        raise ValueError("v0_8i_candidate_success_count_mismatch")
    if int(gate.get("candidate_failures_total") or 0) != len(candidate_failures):
        raise ValueError("v0_8i_candidate_failure_count_mismatch")

    taxonomy: dict[str, dict[str, Any]] = {
        "late_seat_window_shortfall": {"count": 0, "seeds": []},
        "under_depth_late_entry": {"count": 0, "seeds": []},
        "centered_no_depth_contact_miss": {"count": 0, "seeds": []},
        "unclassified": {"count": 0, "seeds": []},
    }
    for row in candidate_failures:
        failure_class = str(row["failure_class"])
        taxonomy[failure_class]["count"] += 1
        taxonomy[failure_class]["seeds"].append(int(row["seed"]))
    if taxonomy["unclassified"]["count"]:
        raise ValueError("v0_8i_unclassified_candidate_failures_present")

    child_dir = output_dir / V08I_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    write_json(child_dir / "candidate_failure_taxonomy_v0_8i.json", candidate_failures)

    candidate_failures_maximum = int(gate.get("candidate_failures_maximum") or 3)
    candidate_failures_to_recover = max(0, len(candidate_failures) - candidate_failures_maximum)
    candidate_only_success_count = int(paired_outcome_counts["B0_C1"])
    baseline_success_compression = (
        baseline_success_count >= 20
        and candidate_only_success_count <= 3
        and float(gate.get("candidate_baseline_success_gap") or 0.0) < 0.10
    )
    diagnosis = {
        "schema_version": V08I_CALIBRATION_UPLIFT_COMPRESSION_DIAGNOSIS_SCHEMA_VERSION,
        "policy_slice": V08I_POLICY_SLICE_ID,
        "source_policy_slice": V08H_POLICY_SLICE_ID,
        "slice_id": V08I_SLICE_ID,
        "source_slice_id": V08H_SLICE_ID,
        "runtime_backend": "offline_artifact_diagnosis",
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "proof_eligible": False,
        "calibration_opened": True,
        "heldout_opened": False,
        "fresh_heldout_27000_27049_accessed": False,
        "source_v08h_gate_path": str(gate["path"]),
        "source_v08h_gate_sha256": gate_sha256,
        "baseline_success_count": baseline_success_count,
        "candidate_success_count": candidate_success_count,
        "baseline_success_rate": gate.get("baseline_calibration_success_rate"),
        "candidate_success_rate": gate.get("candidate_calibration_success_rate"),
        "candidate_baseline_success_gap": gate.get("candidate_baseline_success_gap"),
        "paired_outcome_counts": paired_outcome_counts,
        "candidate_only_success_count": candidate_only_success_count,
        "baseline_success_compression": baseline_success_compression,
        "candidate_failures_total": len(candidate_failures),
        "candidate_failures_maximum": candidate_failures_maximum,
        "candidate_failures_to_recover_for_calibration_gate": candidate_failures_to_recover,
        "failure_taxonomy": taxonomy,
        "recommended_downstream_slice": V08I_RECOMMENDED_DOWNSTREAM_SLICE,
        "recommended_downstream_constraints": {
            "fresh_calibration_required": True,
            "do_not_reuse_calibration_seed_range": [
                min(V08H_FRESH_CALIBRATION_RANGE),
                max(V08H_FRESH_CALIBRATION_RANGE),
            ],
            "keep_fresh_heldout_27000_27049_sealed": True,
            "env_native_10_consecutive_success_authority_unchanged": True,
            "same_shared_safety_authority_for_baseline_and_candidate": True,
            "avoid_further_shared_authority_strengthening": baseline_success_compression,
            "candidate_specific_learned_residual_margin_required": True,
            "attribution_preservation_gate_required": True,
            "target_failure_reduction_minimum": candidate_failures_to_recover,
            "dominant_repair_targets": [
                "candidate_hard_seed_margin",
                "under_depth_late_entry",
                "late_seat_hold_window_margin",
                "baseline_success_compression",
            ],
            "forbidden_mechanisms": ["retry", "withdraw", "search", "force_control"],
        },
        "artifact_paths": {
            "candidate_failure_taxonomy": str(child_dir / "candidate_failure_taxonomy_v0_8i.json"),
        },
        "non_claims": {
            "closure_authority": False,
            "policy_uplift_proven": False,
            "heldout_ab_opened": False,
            "real_robot_success": False,
        },
    }
    diagnosis["v0_8i_calibration_uplift_compression_diagnosis_sha256"] = _sha256_payload_excluding(
        diagnosis,
        "v0_8i_calibration_uplift_compression_diagnosis_sha256",
    )
    write_json(child_dir / "v0_8i_calibration_uplift_compression_diagnosis.json", diagnosis)
    write_json(output_dir / "calibration_uplift_compression_diagnosis_v0_8i.json", diagnosis)
    return diagnosis


def load_required_v08i_uplift_compression_diagnosis(output_dir: Path) -> tuple[dict[str, Any], str]:
    diagnosis_path = output_dir / V08I_CHILD_OUTPUT_DIRNAME / "v0_8i_calibration_uplift_compression_diagnosis.json"
    if not diagnosis_path.exists():
        raise ValueError("missing_v0_8i_uplift_compression_diagnosis")
    diagnosis = read_json(diagnosis_path)
    if (
        diagnosis.get("schema_version") != V08I_CALIBRATION_UPLIFT_COMPRESSION_DIAGNOSIS_SCHEMA_VERSION
        or diagnosis.get("policy_slice") != V08I_POLICY_SLICE_ID
        or diagnosis.get("source_policy_slice") != V08H_POLICY_SLICE_ID
        or diagnosis.get("mvp2_closed") is not False
        or diagnosis.get("policy_uplift_proven") is not False
        or diagnosis.get("heldout_opened") is not False
        or diagnosis.get("fresh_heldout_27000_27049_accessed") is not False
        or diagnosis.get("baseline_success_compression") is not True
        or int(diagnosis.get("candidate_failures_total") or 0) <= 0
    ):
        raise ValueError("invalid_v0_8i_uplift_compression_diagnosis")
    diagnosis["path"] = str(diagnosis_path)
    diagnosis["sha256"] = _sha256_file(diagnosis_path)
    return diagnosis, diagnosis["sha256"]


def _v08j_median(values: list[float]) -> float | None:
    if not values:
        return None
    return round(float(statistics.median(values)), 12)


def _v08j_delta(candidate_value: Any, baseline_value: Any) -> float | None:
    if candidate_value is None or baseline_value is None:
        return None
    return round(float(candidate_value) - float(baseline_value), 12)


def _v08j_trace_residual_margin_metrics(trace: list[dict[str, Any]]) -> dict[str, Any]:
    z_open_rows: list[int] = []
    z_open_lateral: list[float] = []
    z_open_residual_z: list[float] = []
    z_open_residual_xy: list[float] = []
    lateral_values: list[float] = []
    depth_values: list[float] = []
    first_depth_positive_step: int | None = None
    first_env_native_success_step: int | None = None
    current_success_run = 0
    max_success_run = 0
    for index, row in enumerate(trace):
        action = row.get("normalized_action") if isinstance(row.get("normalized_action"), list) else []
        action_z = float(action[2]) if len(action) > 2 else 0.0
        lateral = float(row.get("lateral_error_m") or 0.0)
        depth = float(row.get("insertion_depth_m") or 0.0)
        lateral_values.append(lateral)
        depth_values.append(depth)
        if first_depth_positive_step is None and depth > 1e-6:
            first_depth_positive_step = int(index)
        env_success = bool(row.get("env_native_success_mask") or row.get("env_native_success"))
        if env_success:
            if first_env_native_success_step is None:
                first_env_native_success_step = int(index)
            current_success_run += 1
            max_success_run = max(max_success_run, current_success_run)
        else:
            current_success_run = 0
        if action_z < -1e-9:
            z_open_rows.append(int(index))
            z_open_lateral.append(lateral)
            diagnostics = row.get("controller_action_diagnostics")
            residual = diagnostics.get("residual_prediction") if isinstance(diagnostics, dict) else None
            if isinstance(residual, list) and len(residual) >= 3:
                residual_x = float(residual[0])
                residual_y = float(residual[1])
                residual_z = float(residual[2])
                z_open_residual_z.append(residual_z)
                z_open_residual_xy.append(float((residual_x * residual_x + residual_y * residual_y) ** 0.5))
    return {
        "first_z_open_step": z_open_rows[0] if z_open_rows else None,
        "first_depth_positive_step": first_depth_positive_step,
        "first_env_native_success_step": first_env_native_success_step,
        "env_native_max_consecutive_success_steps": int(max_success_run),
        "z_open_row_count": len(z_open_rows),
        "max_insertion_depth_m": round(max(depth_values) if depth_values else 0.0, 12),
        "min_lateral_error_m": round(min(lateral_values) if lateral_values else 0.0, 12),
        "z_open_lateral_median": _v08j_median(z_open_lateral),
        "z_open_residual_z_median": _v08j_median(z_open_residual_z),
        "z_open_residual_z_min": round(min(z_open_residual_z), 12) if z_open_residual_z else None,
        "z_open_residual_xy_median": _v08j_median(z_open_residual_xy),
    }


def build_v08j_residual_margin_table(*, output_dir: Path) -> dict[str, Any]:
    rows = _load_v08h_calibration_trace_rows(output_dir)
    paired: dict[int, dict[str, dict[str, Any]]] = {}
    for row in rows:
        paired.setdefault(int(row["seed"]), {})[str(row["role"])] = row
    if sorted(paired) != list(V08H_FRESH_CALIBRATION_RANGE):
        raise ValueError("v0_8j_v08h_calibration_pair_seed_range_mismatch")
    paired_outcome_counts = {"B1_C1": 0, "B0_C1": 0, "B1_C0": 0, "B0_C0": 0}
    pairs: list[dict[str, Any]] = []
    for seed in sorted(paired):
        baseline = paired[seed].get("baseline")
        candidate = paired[seed].get("candidate")
        if baseline is None or candidate is None:
            raise ValueError(f"v0_8j_missing_paired_calibration_rollout_for_seed_{seed}")
        baseline_success = bool(baseline["success"])
        candidate_success = bool(candidate["success"])
        paired_outcome = ("B1" if baseline_success else "B0") + "_" + ("C1" if candidate_success else "C0")
        paired_outcome_counts[paired_outcome] += 1
        baseline_metrics = _v08j_trace_residual_margin_metrics(baseline["trace"])
        candidate_metrics = _v08j_trace_residual_margin_metrics(candidate["trace"])
        pairs.append(
            {
                "seed": seed,
                "scenario_id": candidate["scenario_id"],
                "paired_outcome": paired_outcome,
                "baseline_success": baseline_success,
                "candidate_success": candidate_success,
                "baseline": baseline_metrics,
                "candidate": candidate_metrics,
                "candidate_minus_baseline": {
                    "first_z_open_step_delta": _v08j_delta(
                        candidate_metrics["first_z_open_step"],
                        baseline_metrics["first_z_open_step"],
                    ),
                    "first_depth_positive_step_delta": _v08j_delta(
                        candidate_metrics["first_depth_positive_step"],
                        baseline_metrics["first_depth_positive_step"],
                    ),
                    "z_open_residual_z_median_delta": _v08j_delta(
                        candidate_metrics["z_open_residual_z_median"],
                        baseline_metrics["z_open_residual_z_median"],
                    ),
                    "z_open_lateral_median_delta": _v08j_delta(
                        candidate_metrics["z_open_lateral_median"],
                        baseline_metrics["z_open_lateral_median"],
                    ),
                },
                "baseline_trace_path": baseline["trace_path"],
                "candidate_trace_path": candidate["trace_path"],
            }
        )
    return {
        "schema_version": "rdf_mvp2e_v08j_residual_margin_table_v0.1.0",
        "policy_slice": V08J_POLICY_SLICE_ID,
        "source_policy_slice": V08H_POLICY_SLICE_ID,
        "paired_outcome_counts": paired_outcome_counts,
        "pairs": pairs,
    }


def classify_v08j_candidate_failure_recoverability(
    pair_row: dict[str, Any],
    v08i_failure_row: dict[str, Any],
) -> dict[str, Any]:
    if pair_row.get("paired_outcome") != "B0_C0":
        return {
            "seed": int(pair_row["seed"]),
            "recoverability_class": "not_candidate_failure_target",
            "source_v08i_failure_class": v08i_failure_row.get("failure_class"),
        }
    delta = pair_row["candidate_minus_baseline"]
    residual_delta = delta.get("z_open_residual_z_median_delta")
    lateral_delta = delta.get("z_open_lateral_median_delta")
    residual_margin_present = residual_delta is not None and float(residual_delta) <= -0.03
    lateral_margin_present = lateral_delta is not None and float(lateral_delta) <= -0.0005
    if residual_margin_present and lateral_margin_present:
        recoverability_class = "candidate_margin_present"
    elif (
        residual_delta is not None
        and lateral_delta is not None
        and abs(float(residual_delta)) <= 0.005
        and abs(float(lateral_delta)) <= 0.0005
    ):
        recoverability_class = "shared_failure_no_candidate_margin"
    elif residual_delta is not None and lateral_delta is not None:
        recoverability_class = "insufficient_margin_signal"
    else:
        recoverability_class = "unclassified"
    return {
        "seed": int(pair_row["seed"]),
        "scenario_id": pair_row.get("scenario_id"),
        "paired_outcome": pair_row.get("paired_outcome"),
        "recoverability_class": recoverability_class,
        "source_v08i_failure_class": v08i_failure_row.get("failure_class"),
        "candidate_minus_baseline": dict(delta),
        "candidate_metrics": dict(pair_row["candidate"]),
        "baseline_metrics": dict(pair_row["baseline"]),
    }


def build_v08j_attribution_preserving_candidate_margin_diagnosis(*, output_dir: Path) -> dict[str, Any]:
    parent_diagnosis, parent_sha256 = load_required_v08i_uplift_compression_diagnosis(output_dir)
    parent_failures_path = output_dir / V08I_CHILD_OUTPUT_DIRNAME / "candidate_failure_taxonomy_v0_8i.json"
    if not parent_failures_path.exists():
        raise ValueError("missing_v0_8i_candidate_failure_taxonomy")
    parent_failures = json.loads(parent_failures_path.read_text(encoding="utf-8"))
    if not isinstance(parent_failures, list):
        raise ValueError("invalid_v0_8i_candidate_failure_taxonomy")
    parent_failures_by_seed = {int(row["seed"]): row for row in parent_failures}
    table = build_v08j_residual_margin_table(output_dir=output_dir)
    if table["paired_outcome_counts"] != parent_diagnosis.get("paired_outcome_counts"):
        raise ValueError("v0_8j_parent_paired_outcome_mismatch")
    recoverability: list[dict[str, Any]] = []
    pairs_by_seed = {int(row["seed"]): row for row in table["pairs"]}
    for seed in sorted(parent_failures_by_seed):
        if seed not in pairs_by_seed:
            raise ValueError(f"v0_8j_missing_pair_for_parent_failure_seed_{seed}")
        recoverability.append(
            classify_v08j_candidate_failure_recoverability(
                pairs_by_seed[seed],
                parent_failures_by_seed[seed],
            )
        )
    unclassified_count = sum(1 for row in recoverability if row["recoverability_class"] == "unclassified")
    if unclassified_count:
        raise ValueError("v0_8j_unclassified_recoverability_present")

    candidate_margin_positive_failures = [
        row for row in recoverability if row["recoverability_class"] == "candidate_margin_present"
    ]
    candidate_failures_to_recover = int(
        parent_diagnosis.get("candidate_failures_to_recover_for_calibration_gate") or 0
    )
    candidate_margin_repair_feasible = len(candidate_margin_positive_failures) >= candidate_failures_to_recover
    recommended_downstream_slice = (
        V08J_REPAIR_SLICE_IF_MARGIN_PRESENT
        if candidate_margin_repair_feasible
        else V08J_REBALANCE_SLICE_IF_MARGIN_ABSENT
    )

    child_dir = output_dir / V08J_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    write_json(child_dir / "residual_margin_table_v0_8j.json", table)
    write_json(child_dir / "candidate_failure_recoverability_v0_8j.json", recoverability)
    diagnosis = {
        "schema_version": V08J_DIAGNOSIS_SCHEMA_VERSION,
        "policy_slice": V08J_POLICY_SLICE_ID,
        "source_policy_slice": V08H_POLICY_SLICE_ID,
        "parent_diagnosis_policy_slice": V08I_POLICY_SLICE_ID,
        "slice_id": V08J_SLICE_ID,
        "runtime_backend": "offline_artifact_diagnosis",
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "proof_eligible": False,
        "calibration_opened": True,
        "heldout_opened": False,
        "fresh_heldout_27000_27049_accessed": False,
        "source_v08i_diagnosis_path": str(parent_diagnosis["path"]),
        "source_v08i_diagnosis_sha256": parent_sha256,
        "paired_outcome_counts": table["paired_outcome_counts"],
        "baseline_success_compression": parent_diagnosis["baseline_success_compression"],
        "candidate_failures_total": int(parent_diagnosis["candidate_failures_total"]),
        "candidate_failures_to_recover_for_calibration_gate": candidate_failures_to_recover,
        "candidate_margin_positive_failure_count": len(candidate_margin_positive_failures),
        "unclassified_recoverability_count": unclassified_count,
        "candidate_margin_repair_feasible": candidate_margin_repair_feasible,
        "recoverability_class_counts": {
            "candidate_margin_present": sum(
                1 for row in recoverability if row["recoverability_class"] == "candidate_margin_present"
            ),
            "shared_failure_no_candidate_margin": sum(
                1 for row in recoverability if row["recoverability_class"] == "shared_failure_no_candidate_margin"
            ),
            "insufficient_margin_signal": sum(
                1 for row in recoverability if row["recoverability_class"] == "insufficient_margin_signal"
            ),
            "unclassified": unclassified_count,
        },
        "recommended_downstream_slice": recommended_downstream_slice,
        "recommended_downstream_constraints": {
            "fresh_calibration_required": True,
            "keep_fresh_heldout_27000_27049_sealed": True,
            "same_success_metric_required": True,
            "same_shared_safety_authority_for_baseline_and_candidate": True,
            "no_candidate_only_hand_coded_controller": True,
            "avoid_further_shared_authority_strengthening": True,
            "candidate_specific_effect_must_come_from_learned_residual": True,
        },
        "artifact_paths": {
            "residual_margin_table": str(child_dir / "residual_margin_table_v0_8j.json"),
            "candidate_failure_recoverability": str(
                child_dir / "candidate_failure_recoverability_v0_8j.json"
            ),
        },
        "non_claims": {
            "closure_authority": False,
            "policy_uplift_proven": False,
            "heldout_ab_opened": False,
            "real_robot_success": False,
        },
    }
    diagnosis["v0_8j_attribution_preserving_candidate_margin_diagnosis_sha256"] = _sha256_payload_excluding(
        diagnosis,
        "v0_8j_attribution_preserving_candidate_margin_diagnosis_sha256",
    )
    write_json(child_dir / "v0_8j_attribution_preserving_candidate_margin_diagnosis.json", diagnosis)
    write_json(output_dir / "attribution_preserving_candidate_margin_diagnosis_v0_8j.json", diagnosis)
    return diagnosis


def load_required_v08j_candidate_margin_diagnosis(output_dir: Path) -> dict[str, Any]:
    diagnosis_path = (
        output_dir
        / V08J_CHILD_OUTPUT_DIRNAME
        / "v0_8j_attribution_preserving_candidate_margin_diagnosis.json"
    )
    if not diagnosis_path.exists():
        raise ValueError("missing_v0_8j_candidate_margin_diagnosis")
    diagnosis = read_json(diagnosis_path)
    if (
        diagnosis.get("schema_version") != V08J_DIAGNOSIS_SCHEMA_VERSION
        or diagnosis.get("policy_slice") != V08J_POLICY_SLICE_ID
        or diagnosis.get("source_policy_slice") != V08H_POLICY_SLICE_ID
        or diagnosis.get("recommended_downstream_slice") != V08J_REBALANCE_SLICE_IF_MARGIN_ABSENT
        or diagnosis.get("candidate_margin_repair_feasible") is not False
        or diagnosis.get("heldout_opened") is not False
        or diagnosis.get("fresh_heldout_27000_27049_accessed") is not False
        or diagnosis.get("mvp2_closed") is not False
        or diagnosis.get("policy_uplift_proven") is not False
    ):
        raise ValueError("invalid_v0_8j_candidate_margin_diagnosis")
    diagnosis["path"] = str(diagnosis_path)
    diagnosis["sha256"] = _sha256_file(diagnosis_path)
    return diagnosis


def _v08k_row_sha256(row: dict[str, Any]) -> str:
    return _sha256_payload(row)


def _v08k_action_z(row: dict[str, Any]) -> float:
    action = row.get("normalized_action")
    if isinstance(action, list) and len(action) > 2:
        return float(action[2])
    return 0.0


def _v08k_rebalance_reasons(row: dict[str, Any]) -> list[str]:
    action_z = _v08k_action_z(row)
    phase = row.get("behavior_state_phase")
    lateral = float(row.get("lateral_error_m") or 0.0)
    depth = float(row.get("insertion_depth_m") or 0.0)
    reasons: list[str] = []
    if phase == "HOLD" or row.get("env_native_success_mask") is True:
        reasons.extend(["seat_hold_rows", "seat_hold_rows", "seat_hold_rows"])
    if phase == "DESCEND" and lateral <= 0.006 and action_z <= -0.08:
        reasons.append("centered_descent_rows")
        if depth < 0.024:
            reasons.append("under_depth_progress_rows")
    return reasons[:4]


def rebalance_v08k_candidate_rows(
    rows: list[dict[str, Any]],
) -> tuple[list[dict[str, Any]], dict[str, int]]:
    rebalanced: list[dict[str, Any]] = []
    counts: dict[str, int] = {
        "seat_hold_rows": 0,
        "centered_descent_rows": 0,
        "under_depth_progress_rows": 0,
    }
    for row in rows:
        source_hash = _v08k_row_sha256(row)
        base = dict(row)
        base.update(
            {
                "rebalance_policy_slice": V08K_POLICY_SLICE_ID,
                "rebalance_is_duplicate": False,
                "rebalance_reason": "base_source_row",
                "rebalance_source_row_sha256": source_hash,
                "rebalance_copy_index": 0,
            }
        )
        rebalanced.append(base)
        for index, reason in enumerate(_v08k_rebalance_reasons(row), start=1):
            duplicate = dict(row)
            duplicate.update(
                {
                    "rebalance_policy_slice": V08K_POLICY_SLICE_ID,
                    "rebalance_is_duplicate": True,
                    "rebalance_reason": reason,
                    "rebalance_source_row_sha256": source_hash,
                    "rebalance_copy_index": index,
                }
            )
            counts[reason] = counts.get(reason, 0) + 1
            rebalanced.append(duplicate)
    return rebalanced, counts


def _v08k_l2(values: Sequence[float]) -> float:
    return round(float(np.linalg.norm(np.asarray(list(values), dtype=np.float64))), 12)


def _v08k_matrix_l2_delta(left: Any, right: Any) -> float:
    left_arr = np.asarray(left, dtype=np.float64)
    right_arr = np.asarray(right, dtype=np.float64)
    if left_arr.shape != right_arr.shape:
        return float("inf")
    return round(float(np.linalg.norm(left_arr - right_arr)), 12)


def _v08k_any_calibration_or_heldout_training_rows(rows: list[dict[str, Any]]) -> bool:
    protected_seed_ranges = (
        range(21000, 21050),
        range(23000, 23030),
        range(24000, 24050),
        range(25000, 25030),
        range(26000, 26050),
        range(26500, 26530),
        range(27000, 27050),
        range(27500, 27530),
        range(28000, 28030),
        range(28500, 28530),
        range(29000, 29030),
    )
    for row in rows:
        if any(
            row.get(flag) is True
            for flag in (
                "heldout_21000_21049_accessed",
                "fresh_heldout_24000_24049_accessed",
                "fresh_heldout_26000_26049_accessed",
                "fresh_heldout_27000_27049_accessed",
                "fresh_calibration_23000_23029_accessed",
                "fresh_calibration_25000_25029_accessed",
                "fresh_calibration_26500_26529_accessed",
                "fresh_calibration_27500_27529_accessed",
                "fresh_calibration_28000_28029_accessed",
                "fresh_calibration_28500_28529_accessed",
                "fresh_calibration_29000_29029_accessed",
            )
        ):
            return True
        text = " ".join(
            str(row.get(key) or "")
            for key in ("source_trace_path", "runtime_trace_path", "trajectory_id", "scenario_id")
        ).lower()
        seed_match = re.search(
            r"(?:train_success|train_failure|held_out|heldout|calibration|seed)[_-](\d{4,6})",
            text,
        )
        if seed_match is None:
            seed_match = re.search(r"_(\d{5})(?:_|\.|$)", text)
        if seed_match is not None:
            seed = int(seed_match.group(1))
            if any(seed in seed_range for seed_range in protected_seed_ranges):
                return True
            continue
        if "calibration" in text or "heldout" in text or "held_out" in text:
            return True
    return False


def _v08k_source_authority_config(output_dir: Path, parent_policy: dict[str, Any]) -> dict[str, Any]:
    v07c_manifest = output_dir / V07C_CHILD_OUTPUT_DIRNAME / "v0_7c_residual_action_authority_manifest.json"
    if v07c_manifest.exists():
        manifest = read_json(v07c_manifest)
        config = manifest.get("authority_filter_config")
        if isinstance(config, dict):
            validate_v07c_action_authority_config_contract(config)
            return config
    fake_or_child_config = output_dir / V07D_CHILD_OUTPUT_DIRNAME / "v0_7c_action_authority_config.json"
    if fake_or_child_config.exists():
        config = read_json(fake_or_child_config)
        validate_v07c_action_authority_config_contract(config)
        return config
    config = parent_policy.get("authority_filter_config")
    if isinstance(config, dict):
        validate_v07c_action_authority_config_contract(config)
        return config
    raise ValueError("missing_v0_8k_source_authority_config")


def build_v08k_policy_artifact_payload(
    *,
    parent_policy_artifact: dict[str, Any],
    base_policy_artifact: dict[str, Any],
    dataset_view_role: str,
    training_view: dict[str, Any],
    parent_diagnosis_sha256: str,
) -> dict[str, Any]:
    role = "candidate" if dataset_view_role == "candidate_curated" else "baseline"
    payload = {
        key: value
        for key, value in parent_policy_artifact.items()
        if key not in {"path", "policy_artifact_sha256"}
    }
    for key in (
        "weights",
        "bias",
        "train_sample_count",
        "hyperparameters",
        "feature_schema",
        "feature_schema_version",
        "phase_schema",
        "action_schema",
    ):
        payload[key] = base_policy_artifact[key]
    payload.update(
        {
            "schema_version": V08K_POLICY_ARTIFACT_SCHEMA_VERSION,
            "policy_artifact_schema_version": V08K_POLICY_ARTIFACT_SCHEMA_VERSION,
            "policy_id": f"{role}_mvp2e_v08k_candidate_training_signal_rebalance_policy",
            "policy_slice": V08K_POLICY_SLICE_ID,
            "slice_id": V08K_SLICE_ID,
            "parent_policy_slice": V08H_POLICY_SLICE_ID,
            "source_policy_slice": V08H_POLICY_SLICE_ID,
            "parent_policy_artifact_sha256": parent_policy_artifact.get("policy_artifact_sha256"),
            "source_v08j_diagnosis_sha256": parent_diagnosis_sha256,
            "dataset_view_role": dataset_view_role,
            "policy_class": RESIDUAL_POLICY_CLASS,
            "trainer": RESIDUAL_TRAINER,
            "trainer_family": RESIDUAL_TRAINER_FAMILY,
            "candidate_training_signal_rebalance_enabled": dataset_view_role == "candidate_curated",
            "training_view_sha256": training_view["sha256"],
            "training_view_path": training_view["path"],
            "same_shared_authority_as_peer": True,
            "fresh_calibration_29000_29029_accessed": False,
            "fresh_heldout_27000_27049_accessed": False,
            "heldout_opened": False,
            "mvp2_closed": False,
            "policy_uplift_proven": False,
            "proof_authority": False,
        }
    )
    payload["policy_artifact_sha256"] = _sha256_payload_excluding(payload, "policy_artifact_sha256")
    return payload


def derive_v08k_training_signal_rebalance_gate(
    *,
    parent_policies: dict[str, dict[str, Any]],
    candidate_policy: dict[str, Any],
    baseline_policy: dict[str, Any],
    candidate_source_rows: list[dict[str, Any]],
    candidate_rows: list[dict[str, Any]],
    baseline_source_rows: list[dict[str, Any]],
    baseline_rows: list[dict[str, Any]],
    duplicate_counts: dict[str, int],
    source_v08j_diagnosis_sha256: str,
) -> dict[str, Any]:
    candidate_parent_predictions = predict_actions_for_rows(parent_policies["candidate"], candidate_source_rows)
    candidate_predictions = predict_actions_for_rows(candidate_policy, candidate_source_rows)
    deltas = np.asarray(candidate_predictions, dtype=np.float64) - np.asarray(
        candidate_parent_predictions,
        dtype=np.float64,
    )
    row_delta_norms = np.linalg.norm(deltas, axis=1) if len(deltas) else np.asarray([], dtype=np.float64)
    descent_indices = [
        index
        for index, row in enumerate(candidate_source_rows)
        if "centered_descent_rows" in _v08k_rebalance_reasons(row)
    ]
    descent_z_delta_mean = (
        round(float(np.mean(deltas[descent_indices, 2])), 12)
        if descent_indices and len(deltas)
        else 0.0
    )
    equality_keys = (
        "selected_action_adapter_id",
        "trainer",
        "trainer_family",
        "policy_class",
        "feature_schema",
        "feature_schema_version",
        "phase_schema",
        "action_schema",
        "base_servo_config_sha256",
        "authority_filter_config_sha256",
        "final_post_adapter_authority_config_sha256",
        "final_post_adapter_xy_authority_config_sha256",
        "shared_hysteresis_authority_config_sha256",
        "capture_conditioned_progress_authority_config_sha256",
        "horizon_reserved_capture_authority_config_sha256",
        "deadline_precedence_horizon_authority_config_sha256",
        "early_centered_z_open_safe_entry_config_sha256",
    )
    peer_mismatches = [key for key in equality_keys if candidate_policy.get(key) != baseline_policy.get(key)]
    candidate_weight_delta_l2 = _v08k_matrix_l2_delta(
        candidate_policy.get("weights"),
        parent_policies["candidate"].get("weights"),
    )
    baseline_weight_delta_l2 = _v08k_matrix_l2_delta(
        baseline_policy.get("weights"),
        parent_policies["baseline"].get("weights"),
    )
    candidate_duplicate_rows = len(candidate_rows) - len(candidate_source_rows)
    calibration_or_heldout_rows_used = _v08k_any_calibration_or_heldout_training_rows(
        candidate_rows + baseline_rows
    )
    candidate_delta_nonzero_fraction = (
        round(float(np.mean(row_delta_norms > 1e-9)), 12) if len(row_delta_norms) else 0.0
    )
    reasons: list[str] = []
    if candidate_duplicate_rows <= 0:
        reasons.append("candidate_duplicate_rows_absent")
    if duplicate_counts.get("seat_hold_rows", 0) <= 0:
        reasons.append("seat_hold_rebalance_absent")
    if duplicate_counts.get("centered_descent_rows", 0) <= 0:
        reasons.append("centered_descent_rebalance_absent")
    if len(baseline_rows) != len(baseline_source_rows):
        reasons.append("baseline_rows_changed")
    if calibration_or_heldout_rows_used:
        reasons.append("calibration_or_heldout_rows_used_for_training")
    if peer_mismatches:
        reasons.append("peer_fairness_mismatch")
    if candidate_weight_delta_l2 <= 1e-6:
        reasons.append("candidate_weight_delta_absent")
    if candidate_delta_nonzero_fraction < 0.10:
        reasons.append("candidate_prediction_delta_too_sparse")
    if descent_z_delta_mean >= -1e-6:
        reasons.append("candidate_descent_z_delta_not_stronger")
    gate = {
        "schema_version": V08K_REBALANCE_GATE_SCHEMA_VERSION,
        "policy_slice": V08K_POLICY_SLICE_ID,
        "slice_id": V08K_SLICE_ID,
        "source_policy_slice": V08H_POLICY_SLICE_ID,
        "source_v08j_diagnosis_sha256": source_v08j_diagnosis_sha256,
        "candidate_source_rows": len(candidate_source_rows),
        "candidate_rebalanced_rows": len(candidate_rows),
        "candidate_duplicate_rows": candidate_duplicate_rows,
        "candidate_duplicate_rows_by_reason": dict(duplicate_counts),
        "baseline_source_rows": len(baseline_source_rows),
        "baseline_rebalanced_rows": len(baseline_rows),
        "baseline_training_view_unchanged": len(baseline_rows) == len(baseline_source_rows),
        "candidate_weight_delta_l2": candidate_weight_delta_l2,
        "baseline_weight_delta_l2": baseline_weight_delta_l2,
        "candidate_prediction_delta_nonzero_fraction": candidate_delta_nonzero_fraction,
        "candidate_descent_target_rows_mean_z_delta": descent_z_delta_mean,
        "peer_fairness_mismatch_keys": peer_mismatches,
        "calibration_or_heldout_rows_used_for_training": calibration_or_heldout_rows_used,
        "fresh_heldout_27000_27049_accessed": False,
        "heldout_opened": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "passed": not reasons,
        "failure_reasons": reasons,
        "failure_reason": ",".join(reasons),
    }
    gate["training_signal_rebalance_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "training_signal_rebalance_gate_sha256",
    )
    return gate


def build_v08k_candidate_training_signal_rebalance_slice(*, output_dir: Path) -> dict[str, Any]:
    diagnosis = load_required_v08j_candidate_margin_diagnosis(output_dir)
    parent_policies = _load_v08h_policy_artifacts(output_dir)
    source_dir = output_dir / V07D_CHILD_OUTPUT_DIRNAME
    candidate_source_rows = _rows_from_hdf5_metadata(source_dir / "candidate_curated_train_v0_7d.hdf5")
    baseline_source_rows = _rows_from_hdf5_metadata(source_dir / "baseline_uncurated_train_v0_7d.hdf5")
    candidate_rows, duplicate_counts = rebalance_v08k_candidate_rows(candidate_source_rows)
    baseline_rows = []
    for row in baseline_source_rows:
        payload = dict(row)
        payload.update(
            {
                "rebalance_policy_slice": V08K_POLICY_SLICE_ID,
                "rebalance_is_duplicate": False,
                "rebalance_reason": "baseline_source_row_unchanged",
            }
        )
        baseline_rows.append(payload)
    child_dir = output_dir / V08K_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    authority_config = _v08k_source_authority_config(output_dir, parent_policies["candidate"])
    config = {
        "schema_version": "rdf_mvp2e_v08k_candidate_training_signal_rebalance_config_v0.1.0",
        "policy_slice": V08K_POLICY_SLICE_ID,
        "slice_id": V08K_SLICE_ID,
        "source_policy_slice": V08H_POLICY_SLICE_ID,
        "source_v08j_diagnosis_sha256": diagnosis["sha256"],
        "candidate_rebalance_rule": {
            "seat_hold_extra_copies": 3,
            "centered_descent_extra_copies": 1,
            "under_depth_progress_extra_copies": 1,
            "max_total_copies_per_source_row": 5,
        },
        "fresh_calibration_seed_range": [min(V08K_FRESH_CALIBRATION_RANGE), max(V08K_FRESH_CALIBRATION_RANGE)],
        "fresh_heldout_seed_range": [min(V08K_FRESH_HELDOUT_RANGE), max(V08K_FRESH_HELDOUT_RANGE)],
        "fresh_heldout_27000_27049_accessed": False,
        "heldout_opened": False,
        "proof_authority": False,
    }
    config["candidate_training_signal_rebalance_config_sha256"] = _sha256_payload_excluding(
        config,
        "candidate_training_signal_rebalance_config_sha256",
    )
    write_json(child_dir / "v0_8k_candidate_training_signal_rebalance_config.json", config)
    candidate_view = write_v07c_residual_train_view_hdf5(
        path=child_dir / "candidate_curated_train_v0_8k.hdf5",
        rows=candidate_rows,
        view_id="candidate_curated_v0_8k_training_signal_rebalance",
        authority_config=authority_config,
        schema_version=V08K_MANIFEST_SCHEMA_VERSION,
        extra_hdf5_attrs={
            "policy_slice": V08K_POLICY_SLICE_ID,
            "candidate_training_signal_rebalance_config_sha256": config[
                "candidate_training_signal_rebalance_config_sha256"
            ],
        },
        extra_view_fields={
            "policy_slice": V08K_POLICY_SLICE_ID,
            "candidate_training_signal_rebalance_config_sha256": config[
                "candidate_training_signal_rebalance_config_sha256"
            ],
            "candidate_duplicate_rows_by_reason": dict(duplicate_counts),
        },
    )
    baseline_view = write_v07c_residual_train_view_hdf5(
        path=child_dir / "baseline_uncurated_train_v0_8k.hdf5",
        rows=baseline_rows,
        view_id="baseline_uncurated_v0_8k_training_signal_rebalance_control",
        authority_config=authority_config,
        schema_version=V08K_MANIFEST_SCHEMA_VERSION,
        extra_hdf5_attrs={
            "policy_slice": V08K_POLICY_SLICE_ID,
            "candidate_training_signal_rebalance_config_sha256": config[
                "candidate_training_signal_rebalance_config_sha256"
            ],
        },
        extra_view_fields={
            "policy_slice": V08K_POLICY_SLICE_ID,
            "candidate_training_signal_rebalance_config_sha256": config[
                "candidate_training_signal_rebalance_config_sha256"
            ],
        },
    )
    hyperparameters = dict(parent_policies["candidate"].get("hyperparameters") or {})
    hyperparameters.update(
        {
            "trainer_family": RESIDUAL_TRAINER_FAMILY,
            "candidate_training_signal_rebalance_config_sha256": config[
                "candidate_training_signal_rebalance_config_sha256"
            ],
        }
    )
    candidate_base = fit_phase_conditioned_bc_policy(
        policy_id="candidate_curated_mvp2e_v08k_candidate_training_signal_rebalance_bc",
        train_rows=candidate_rows,
        hyperparameters=hyperparameters,
        feature_schema=FEATURE_SCHEMA_V07A,
        phase_schema=BEHAVIOR_STATE_PHASES,
        feature_schema_version=FEATURE_SCHEMA_V07A_VERSION,
    )
    baseline_base = fit_phase_conditioned_bc_policy(
        policy_id="baseline_uncurated_mvp2e_v08k_candidate_training_signal_rebalance_bc",
        train_rows=baseline_rows,
        hyperparameters=hyperparameters,
        feature_schema=FEATURE_SCHEMA_V07A,
        phase_schema=BEHAVIOR_STATE_PHASES,
        feature_schema_version=FEATURE_SCHEMA_V07A_VERSION,
    )
    candidate_policy = build_v08k_policy_artifact_payload(
        parent_policy_artifact=parent_policies["candidate"],
        base_policy_artifact=candidate_base,
        dataset_view_role="candidate_curated",
        training_view=candidate_view,
        parent_diagnosis_sha256=diagnosis["sha256"],
    )
    baseline_policy = build_v08k_policy_artifact_payload(
        parent_policy_artifact=parent_policies["baseline"],
        base_policy_artifact=baseline_base,
        dataset_view_role="baseline_uncurated",
        training_view=baseline_view,
        parent_diagnosis_sha256=diagnosis["sha256"],
    )
    write_json(child_dir / "candidate_policy_artifact_v0_8k.json", candidate_policy)
    write_json(child_dir / "baseline_policy_artifact_v0_8k.json", baseline_policy)
    gate = derive_v08k_training_signal_rebalance_gate(
        parent_policies=parent_policies,
        candidate_policy=candidate_policy,
        baseline_policy=baseline_policy,
        candidate_source_rows=candidate_source_rows,
        candidate_rows=candidate_rows,
        baseline_source_rows=baseline_source_rows,
        baseline_rows=baseline_rows,
        duplicate_counts=duplicate_counts,
        source_v08j_diagnosis_sha256=diagnosis["sha256"],
    )
    write_json(child_dir / "training_signal_rebalance_gate_v0_8k.json", gate)
    manifest = {
        "schema_version": V08K_MANIFEST_SCHEMA_VERSION,
        "policy_slice": V08K_POLICY_SLICE_ID,
        "slice_id": V08K_SLICE_ID,
        "parent_policy_slice": V08H_POLICY_SLICE_ID,
        "source_policy_slice": V08H_POLICY_SLICE_ID,
        "source_v08j_diagnosis_sha256": diagnosis["sha256"],
        "candidate_training_signal_rebalance_config": config,
        "candidate_training_signal_rebalance_config_sha256": config[
            "candidate_training_signal_rebalance_config_sha256"
        ],
        "training_views": {"candidate": candidate_view, "baseline": baseline_view},
        "policy_artifacts": {
            "candidate": {**candidate_policy, "path": str(child_dir / "candidate_policy_artifact_v0_8k.json")},
            "baseline": {**baseline_policy, "path": str(child_dir / "baseline_policy_artifact_v0_8k.json")},
        },
        "training_signal_rebalance_gate": gate,
        "failed_closed": gate.get("passed") is not True,
        "failure_reason": "" if gate.get("passed") is True else gate.get("failure_reason"),
        "calibration_opened": False,
        "heldout_opened": False,
        "fresh_heldout_27000_27049_accessed": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "non_claims": {
            "policy_uplift_proven": False,
            "real_robot_success": False,
            "physical_robot_readiness": False,
            "hmd_openxr_readiness": False,
            "visual_policy_performance": False,
        },
    }
    manifest["v0_8k_candidate_training_signal_rebalance_manifest_sha256"] = _sha256_payload_excluding(
        manifest,
        "v0_8k_candidate_training_signal_rebalance_manifest_sha256",
    )
    write_json(child_dir / "v0_8k_candidate_training_signal_rebalance_manifest.json", manifest)
    return manifest


def _v08k_burned_seed_range_accessed(seed: int) -> bool:
    return _v08h_burned_seed_range_accessed(seed) or int(seed) in V08H_FRESH_CALIBRATION_RANGE


def _load_v08k_policy_artifacts(output_dir: Path) -> dict[str, dict[str, Any]]:
    child_dir = output_dir / V08K_CHILD_OUTPUT_DIRNAME
    candidate_path = child_dir / "candidate_policy_artifact_v0_8k.json"
    baseline_path = child_dir / "baseline_policy_artifact_v0_8k.json"
    if not candidate_path.exists() or not baseline_path.exists():
        raise ValueError("missing_v0_8k_policy_artifacts")
    baseline = read_json(baseline_path)
    candidate = read_json(candidate_path)
    reasons: list[str] = []
    for role, policy in (("baseline", baseline), ("candidate", candidate)):
        if policy.get("policy_slice") != V08K_POLICY_SLICE_ID:
            reasons.append(f"{role}_policy_slice_mismatch")
        if policy.get("parent_policy_slice") != V08H_POLICY_SLICE_ID:
            reasons.append(f"{role}_parent_policy_slice_mismatch")
        if policy.get("fresh_calibration_29000_29029_accessed") is not False:
            reasons.append(f"{role}_fresh_calibration_accessed_before_runtime")
        if policy.get("fresh_heldout_27000_27049_accessed") is not False:
            reasons.append(f"{role}_fresh_heldout_accessed_before_closure")
        expected_hash = _sha256_payload_excluding(policy, "policy_artifact_sha256")
        if policy.get("policy_artifact_sha256") != expected_hash:
            reasons.append(f"{role}_policy_hash_mismatch")
    equality_keys = (
        "selected_action_adapter_id",
        "trainer",
        "trainer_family",
        "policy_class",
        "feature_schema",
        "feature_schema_version",
        "phase_schema",
        "final_post_adapter_authority_config_sha256",
        "final_post_adapter_xy_authority_config_sha256",
        "base_servo_config_sha256",
        "shared_hysteresis_authority_config_sha256",
        "capture_conditioned_progress_authority_config_sha256",
        "horizon_reserved_capture_authority_config_sha256",
        "deadline_precedence_horizon_authority_config_sha256",
        "early_centered_z_open_safe_entry_config_sha256",
    )
    for key in equality_keys:
        if baseline.get(key) != candidate.get(key):
            reasons.append(f"peer_{key}_mismatch")
    if reasons:
        raise ValueError("v0_8k_policy_peer_fairness_failed: " + ",".join(reasons))
    return {
        "baseline": {**baseline, "path": str(baseline_path)},
        "candidate": {**candidate, "path": str(candidate_path)},
    }


def build_v08k_fresh_manifest(*, output_dir: Path, rebalance_manifest: dict[str, Any]) -> dict[str, Any]:
    calibration_rows = [_scenario_row(split="calibration", seed=seed) for seed in V08K_FRESH_CALIBRATION_RANGE]
    heldout_rows = [_scenario_row(split="held_out", seed=seed) for seed in V08K_FRESH_HELDOUT_RANGE]
    for row in calibration_rows:
        if _v08k_burned_seed_range_accessed(int(row["seed"])):
            raise ValueError("v0_8k_fresh_manifest_reuses_burned_calibration_seed_range")
    heldout_seeds = [int(row["seed"]) for row in heldout_rows]
    if any(seed in V08A_FRESH_HELDOUT_RANGE or seed in V08B_FRESH_HELDOUT_RANGE for seed in heldout_seeds):
        raise ValueError("v0_8k_fresh_manifest_reuses_burned_heldout_seed_range")
    manifest = {
        "schema_version": V08K_MANIFEST_SCHEMA_VERSION,
        "policy_slice": V08K_POLICY_SLICE_ID,
        "slice_id": V08K_SLICE_ID,
        "parent_policy_slice": V08H_POLICY_SLICE_ID,
        "source_policy_slice": V08H_POLICY_SLICE_ID,
        "scenario_profile": "v0_8k",
        "task_type": "connector_insertion",
        "success_metric": SUCCESS_METRIC,
        "success_authority": V06_ENV_NATIVE_SUCCESS_AUTHORITY,
        "source_v08k_rebalance_manifest_sha256": rebalance_manifest[
            "v0_8k_candidate_training_signal_rebalance_manifest_sha256"
        ],
        "source_v08k_rebalance_gate_sha256": rebalance_manifest["training_signal_rebalance_gate"][
            "training_signal_rebalance_gate_sha256"
        ],
        "scenarios": calibration_rows + heldout_rows,
        "fresh_split_manifest": {
            "calibration": {
                "seed_range": [min(V08K_FRESH_CALIBRATION_RANGE), max(V08K_FRESH_CALIBRATION_RANGE)],
                "scenario_ids": [row["scenario_id"] for row in calibration_rows],
                "count": len(calibration_rows),
            },
            "held_out": {
                "seed_range": [min(V08K_FRESH_HELDOUT_RANGE), max(V08K_FRESH_HELDOUT_RANGE)],
                "scenario_ids": [row["scenario_id"] for row in heldout_rows],
                "count": len(heldout_rows),
            },
        },
        "burned_heldout_seed_ranges": [
            list(V07A2_PROTECTED_HELDOUT_SEED_RANGE),
            [min(V08A_FRESH_HELDOUT_RANGE), max(V08A_FRESH_HELDOUT_RANGE)],
            [min(V08B_FRESH_HELDOUT_RANGE), max(V08B_FRESH_HELDOUT_RANGE)],
        ],
        "burned_calibration_seed_ranges": [
            [min(V08D_FRESH_CALIBRATION_RANGE), max(V08D_FRESH_CALIBRATION_RANGE)],
            [min(V08F_FRESH_CALIBRATION_RANGE), max(V08F_FRESH_CALIBRATION_RANGE)],
            [min(V08G_FRESH_CALIBRATION_RANGE), max(V08G_FRESH_CALIBRATION_RANGE)],
            [min(V08H_FRESH_CALIBRATION_RANGE), max(V08H_FRESH_CALIBRATION_RANGE)],
        ],
        "fresh_calibration_26500_26529_accessed": True,
        "fresh_calibration_27500_27529_accessed": True,
        "fresh_calibration_28000_28029_accessed": True,
        "fresh_calibration_28500_28529_accessed": True,
        "fresh_calibration_29000_29029_accessed": False,
        "fresh_heldout_27000_27049_accessed": False,
        "heldout_21000_21049_accessed": False,
        "fresh_heldout_24000_24049_accessed": False,
        "fresh_heldout_26000_26049_accessed": False,
        "calibration_opened": False,
        "heldout_opened": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    manifest["manifest_sha256"] = _sha256_payload_excluding(manifest, "manifest_sha256")
    return manifest


def _v08k_runtime_manifest_for_split(*, fresh_manifest: dict[str, Any], split: str) -> dict[str, Any]:
    if split not in {"calibration", "held_out"}:
        raise ValueError("v0_8k_runtime_manifest_unknown_split")
    rows = [
        {**row, "source_split": split, "semantic_eval_split": split, "split": "held_out"}
        for row in fresh_manifest.get("scenarios", [])
        if isinstance(row, dict) and row.get("split") == split
    ]
    if not rows:
        raise ValueError(f"v0_8k_runtime_manifest_missing_{split}_rows")
    seeds = [int(row["seed"]) for row in rows]
    if split == "calibration":
        if seeds != list(V08K_FRESH_CALIBRATION_RANGE):
            raise ValueError("v0_8k_calibration_seed_range_mismatch")
        if any(_v08k_burned_seed_range_accessed(seed) for seed in seeds):
            raise ValueError("v0_8k_runtime_manifest_reuses_burned_calibration_seed_range")
    if split == "held_out":
        if seeds != list(V08K_FRESH_HELDOUT_RANGE):
            raise ValueError("v0_8k_heldout_seed_range_mismatch")
        if any(seed in V08A_FRESH_HELDOUT_RANGE or seed in V08B_FRESH_HELDOUT_RANGE for seed in seeds):
            raise ValueError("v0_8k_runtime_manifest_reuses_burned_heldout_seed_range")
    manifest = {
        "schema_version": fresh_manifest["schema_version"],
        "policy_slice": V08K_POLICY_SLICE_ID,
        "slice_id": V08K_SLICE_ID,
        "parent_policy_slice": V08H_POLICY_SLICE_ID,
        "scenario_profile": "v0_8k",
        "runtime_split": split,
        "task_type": fresh_manifest["task_type"],
        "success_metric": fresh_manifest["success_metric"],
        "success_authority": fresh_manifest["success_authority"],
        "source_fresh_manifest_sha256": fresh_manifest["manifest_sha256"],
        "scenarios": rows,
        "burned_heldout_seed_ranges": fresh_manifest["burned_heldout_seed_ranges"],
        "burned_calibration_seed_ranges": fresh_manifest["burned_calibration_seed_ranges"],
        "heldout_21000_21049_accessed": False,
        "fresh_heldout_24000_24049_accessed": False,
        "fresh_heldout_26000_26049_accessed": False,
        "fresh_calibration_26500_26529_accessed": True,
        "fresh_calibration_27500_27529_accessed": True,
        "fresh_calibration_28000_28029_accessed": True,
        "fresh_calibration_28500_28529_accessed": True,
        "fresh_calibration_29000_29029_accessed": split == "calibration",
        "fresh_heldout_27000_27049_accessed": split == "held_out",
        "calibration_opened": split == "calibration",
        "heldout_opened": split == "held_out",
        "proof_authority": split == "held_out",
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    manifest["manifest_sha256"] = _sha256_payload_excluding(manifest, "manifest_sha256")
    return manifest


def _write_v08k_calibration_external_rollouts(
    *,
    output_dir: Path,
    baseline_rollouts: list[dict[str, Any]],
    candidate_rollouts: list[dict[str, Any]],
) -> dict[str, str]:
    rollout_dir = output_dir / "calibration_external_rollouts"
    rollout_dir.mkdir(parents=True, exist_ok=True)
    baseline_path = rollout_dir / "baseline_calibration_rollouts_v0_8k.json"
    candidate_path = rollout_dir / "candidate_calibration_rollouts_v0_8k.json"
    write_json(baseline_path, baseline_rollouts)
    write_json(candidate_path, candidate_rollouts)
    return {"baseline": str(baseline_path), "candidate": str(candidate_path)}


def derive_v08k_calibration_presignal_gate(
    *,
    baseline_rollouts: list[dict[str, Any]],
    candidate_rollouts: list[dict[str, Any]],
    runtime_gate: dict[str, Any],
    runtime_metadata: dict[str, Any],
    trace_paths: dict[str, list[str]],
) -> dict[str, Any]:
    gate = derive_v08d_calibration_presignal_gate(
        baseline_rollouts=baseline_rollouts,
        candidate_rollouts=candidate_rollouts,
        runtime_gate=runtime_gate,
        runtime_metadata=runtime_metadata,
        trace_paths=trace_paths,
    )
    gate.update(
        {
            "schema_version": V08K_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
            "policy_slice": V08K_POLICY_SLICE_ID,
            "slice_id": V08K_SLICE_ID,
            "parent_policy_slice": V08H_POLICY_SLICE_ID,
            "fresh_calibration_26500_26529_accessed": True,
            "fresh_calibration_27500_27529_accessed": True,
            "fresh_calibration_28000_28029_accessed": True,
            "fresh_calibration_28500_28529_accessed": True,
            "fresh_calibration_29000_29029_accessed": True,
            "fresh_heldout_27000_27049_accessed": False,
            "fresh_heldout_24000_24049_accessed": False,
            "fresh_heldout_26000_26049_accessed": False,
            "source": "v0_8k_fresh_calibration_runtime",
        }
    )
    gate["calibration_presignal_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "calibration_presignal_gate_sha256",
    )
    return gate


def run_v08k_candidate_training_signal_rebalance_runtime(
    *,
    output_dir: Path,
    device: str = DEFAULT_ISAAC_DEVICE,
    headless: bool = True,
    isaac_task: str = DEFAULT_ISAAC_TASK,
    max_steps: int = int(SUCCESS_METRIC["max_steps"]),
    action_scale: float = 1.0,
    min_rollouts_per_policy: int = MIN_PROOF_ROLLOUTS_PER_POLICY,
    bootstrap_iterations: int = 2000,
    bootstrap_seed: int = 23,
    backend: Any | None = None,
) -> dict[str, Any]:
    child_dir = output_dir / V08K_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    rebalance_manifest = build_v08k_candidate_training_signal_rebalance_slice(output_dir=output_dir)
    if rebalance_manifest["training_signal_rebalance_gate"].get("passed") is not True:
        return rebalance_manifest["training_signal_rebalance_gate"]
    fresh_manifest = build_v08k_fresh_manifest(
        output_dir=output_dir,
        rebalance_manifest=rebalance_manifest,
    )
    write_json(child_dir / "v0_8k_fresh_manifest.json", fresh_manifest)
    policy_artifacts = _load_v08k_policy_artifacts(output_dir)
    baseline_policy = policy_artifacts["baseline"]
    candidate_policy = policy_artifacts["candidate"]
    selected_adapter_id = str(candidate_policy["selected_action_adapter_id"])
    policy_class = str(candidate_policy["policy_class"])
    trainer = str(candidate_policy["trainer"])
    use_single_app_actual_backend = (
        backend is None
        and getattr(IsaacConnectorInsertionEvaluatorBackend, "__name__", "")
        == "IsaacConnectorInsertionEvaluatorBackend"
    )
    evaluator_backend = backend or IsaacConnectorInsertionEvaluatorBackend(
        task=isaac_task,
        device=device,
        headless=headless,
        action_scale=action_scale,
        max_steps=max_steps,
    )
    actual_env = None
    actual_simulation_app = None
    actual_torch = None
    if use_single_app_actual_backend:
        from isaaclab.app import AppLauncher

        app_launcher = AppLauncher(
            {
                "headless": headless,
                "device": device,
                "enable_cameras": False,
            }
        )
        actual_simulation_app = app_launcher.app

        import gymnasium as gym
        import torch as torch_module

        import isaaclab_tasks  # noqa: F401
        from isaaclab_tasks.utils import parse_env_cfg

        env_cfg = parse_env_cfg(isaac_task, device=device, num_envs=1)
        actual_env = gym.make(isaac_task, cfg=env_cfg).unwrapped
        actual_torch = torch_module

    def run_runtime_manifest(
        *,
        manifest: dict[str, Any],
        runtime_output_dir: Path,
        rollouts_per_policy: int,
    ) -> BackendResult:
        if actual_env is not None:
            return _run_v08a_manifest_with_existing_isaac(
                evaluator_backend=evaluator_backend,
                env=actual_env,
                simulation_app=actual_simulation_app,
                torch_module=actual_torch,
                manifest=manifest,
                output_dir=runtime_output_dir,
                min_rollouts_per_policy=rollouts_per_policy,
                policy_artifacts=policy_artifacts,
            )
        return evaluator_backend.run(
            manifest=manifest,
            output_dir=runtime_output_dir,
            min_rollouts_per_policy=rollouts_per_policy,
            deterministic_profile="candidate_positive",
            policy_artifacts=policy_artifacts,
        )

    calibration_manifest = _v08k_runtime_manifest_for_split(
        fresh_manifest=fresh_manifest,
        split="calibration",
    )
    write_json(child_dir / "calibration_runtime_manifest_v0_8k.json", calibration_manifest)
    calibration_result = run_runtime_manifest(
        manifest=calibration_manifest,
        runtime_output_dir=child_dir / "isaac_runtime_fresh_calibration_v0_8k",
        rollouts_per_policy=V07H_CALIBRATION_ROLLOUTS_PER_POLICY,
    )
    calibration_rollout_paths = _write_v08k_calibration_external_rollouts(
        output_dir=child_dir,
        baseline_rollouts=list(calibration_result.baseline_rollouts),
        candidate_rollouts=list(calibration_result.candidate_rollouts),
    )
    calibration_trace_paths = {
        "baseline": list(calibration_result.baseline_trace_paths),
        "candidate": list(calibration_result.candidate_trace_paths),
    }
    calibration_gate = derive_v08k_calibration_presignal_gate(
        baseline_rollouts=list(calibration_result.baseline_rollouts),
        candidate_rollouts=list(calibration_result.candidate_rollouts),
        runtime_gate=dict(calibration_result.runtime_gate),
        runtime_metadata=dict(calibration_result.runtime_metadata),
        trace_paths=calibration_trace_paths,
    )
    calibration_gate["calibration_runtime_manifest_sha256"] = calibration_manifest["manifest_sha256"]
    calibration_gate["baseline_calibration_rollout_path"] = calibration_rollout_paths["baseline"]
    calibration_gate["candidate_calibration_rollout_path"] = calibration_rollout_paths["candidate"]
    calibration_gate["calibration_presignal_gate_sha256"] = _sha256_payload_excluding(
        calibration_gate,
        "calibration_presignal_gate_sha256",
    )
    write_json(child_dir / "calibration_presignal_gate_v0_8k.json", calibration_gate)
    write_json(
        output_dir / "calibration_presignal_gate.json",
        {
            "schema_version": V08K_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
            "policy_slice": V08K_POLICY_SLICE_ID,
            "slice_id": V08K_SLICE_ID,
            "passed": calibration_gate["passed"],
            "source_gate_path": f"{V08K_CHILD_OUTPUT_DIRNAME}/calibration_presignal_gate_v0_8k.json",
            "calibration_opened": True,
            "heldout_opened": False,
            "heldout_21000_21049_accessed": False,
            "fresh_heldout_24000_24049_accessed": False,
            "fresh_heldout_26000_26049_accessed": False,
            "fresh_calibration_26500_26529_accessed": True,
            "fresh_calibration_27500_27529_accessed": True,
            "fresh_calibration_28000_28029_accessed": True,
            "fresh_calibration_28500_28529_accessed": True,
            "fresh_calibration_29000_29029_accessed": True,
            "fresh_heldout_27000_27049_accessed": False,
            "heldout_allowed": calibration_gate["heldout_allowed"],
            "mvp2_closed": False,
            "policy_uplift_proven": False,
        },
    )
    if calibration_gate.get("passed") is not True:
        calibration_gate["mvp2_closed"] = False
        calibration_gate["policy_uplift_proven"] = False
        if actual_env is not None:
            actual_env.close()
        return calibration_gate

    selection = _v08a_calibration_selection_report(output_dir)
    training_scenario_ids = _v08a_training_scenario_ids(output_dir)
    heldout_manifest = _v08k_runtime_manifest_for_split(
        fresh_manifest=fresh_manifest,
        split="held_out",
    )
    write_json(child_dir / "heldout_runtime_manifest_v0_8k.json", heldout_manifest)
    heldout_leakage_guard = validate_no_heldout_leakage(
        manifest=heldout_manifest,
        training_scenario_ids=training_scenario_ids,
        curation_tuning_scenario_ids=[],
        threshold_tuning_scenario_ids=[],
        hyperparameter_scenario_ids=[],
        calibration_selector_scenario_ids=[str(item) for item in selection.get("calibration_scenario_ids", [])],
    )
    if heldout_leakage_guard["passed"] is not True:
        raise ValueError("v0_8k_fresh_heldout_leakage_guard_failed")

    baseline_view = _existing_train_view(
        child_dir / "baseline_uncurated_train_v0_8k.hdf5",
        view_id="baseline_uncurated_v0_8k_training_signal_rebalance_control",
    )
    candidate_view = _existing_train_view(
        child_dir / "candidate_curated_train_v0_8k.hdf5",
        view_id="candidate_curated_v0_8k_training_signal_rebalance",
    )
    bridge_dir = _write_learning_harness_bridge(
        output_dir=child_dir,
        manifest=heldout_manifest,
        baseline_view=baseline_view,
        candidate_view=candidate_view,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    heldout_rollouts_per_policy = max(
        int(min_rollouts_per_policy),
        STRONGER_PUBLIC_ROLLOUTS_PER_POLICY,
        len(V08K_FRESH_HELDOUT_RANGE),
    )
    heldout_result = run_runtime_manifest(
        manifest=heldout_manifest,
        runtime_output_dir=child_dir / "isaac_runtime_fresh_heldout_v0_8k",
        rollouts_per_policy=heldout_rollouts_per_policy,
    )
    runtime_gate = dict(heldout_result.runtime_gate)
    actual_rollouts_per_policy = min(
        len(heldout_result.baseline_rollouts),
        len(heldout_result.candidate_rollouts),
    )
    runtime_gate["actual_baseline_rollouts"] = len(heldout_result.baseline_rollouts)
    runtime_gate["actual_candidate_rollouts"] = len(heldout_result.candidate_rollouts)
    runtime_gate["actual_rollouts_per_policy"] = actual_rollouts_per_policy
    combined_rollouts = list(heldout_result.baseline_rollouts) + list(heldout_result.candidate_rollouts)
    if any(_v08k_burned_seed_range_accessed(int(rollout.get("seed", -1))) for rollout in combined_rollouts):
        raise ValueError("v0_8k_burned_seed_accessed")
    heldout_suite = _heldout_suite(heldout_manifest)
    baseline_rollouts_path = _write_external_rollout_json(
        output_dir=child_dir,
        role="baseline",
        policy_artifact=baseline_policy,
        train_view=baseline_view,
        heldout_suite=heldout_suite,
        backend_result=heldout_result,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    candidate_rollouts_path = _write_external_rollout_json(
        output_dir=child_dir,
        role="candidate",
        policy_artifact=candidate_policy,
        train_view=candidate_view,
        heldout_suite=heldout_suite,
        backend_result=heldout_result,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    learning_report = _run_learning_validator(
        output_dir=child_dir,
        bridge_dir=bridge_dir,
        baseline_rollouts_path=baseline_rollouts_path,
        candidate_rollouts_path=candidate_rollouts_path,
        min_rollouts_per_policy=MIN_PROOF_ROLLOUTS_PER_POLICY,
        bootstrap_iterations=bootstrap_iterations,
        bootstrap_seed=bootstrap_seed,
        policy_class=policy_class,
        trainer=trainer,
    )
    train_generation_runtime_gate, train_gate_sha256 = load_v07a2_parent_train_generation_gate(output_dir)
    closure = derive_mvp2c_closure(
        learning_report=learning_report,
        runtime_gate=runtime_gate,
        train_generation_runtime_gate=train_generation_runtime_gate,
        calibration_selection_report=selection,
        heldout_leakage_guard=heldout_leakage_guard,
        actual_rollouts_per_policy=actual_rollouts_per_policy,
    )
    confidence_interval_report = _bootstrap_uplift_ci(
        baseline_rollouts=list(heldout_result.baseline_rollouts),
        candidate_rollouts=list(heldout_result.candidate_rollouts),
        iterations=bootstrap_iterations,
        seed=bootstrap_seed,
    )
    gate = {
        "schema_version": V08K_HELDOUT_CLOSURE_SCHEMA_VERSION,
        "policy_slice": V08K_POLICY_SLICE_ID,
        "slice_id": V08K_SLICE_ID,
        "parent_policy_slice": V08H_POLICY_SLICE_ID,
        "source_fresh_manifest_sha256": fresh_manifest["manifest_sha256"],
        "candidate_training_signal_rebalance_config_sha256": rebalance_manifest[
            "candidate_training_signal_rebalance_config_sha256"
        ],
        "training_signal_rebalance_gate_sha256": rebalance_manifest["training_signal_rebalance_gate"][
            "training_signal_rebalance_gate_sha256"
        ],
        "parent_train_generation_runtime_gate_sha256": train_gate_sha256,
        "fresh_calibration_presignal_gate_sha256": calibration_gate["calibration_presignal_gate_sha256"],
        "runtime_backend": heldout_result.runtime_backend,
        "proof_runtime": heldout_result.proof_runtime,
        "runtime_gate": runtime_gate,
        "actual_rollouts_per_policy": actual_rollouts_per_policy,
        "baseline_success_rate": learning_report.get("baseline_success_rate"),
        "candidate_success_rate": learning_report.get("candidate_success_rate"),
        "curated_vs_uncurated_uplift": learning_report.get("curated_vs_uncurated_uplift"),
        "learning_report_path": str(
            child_dir / "mvp2_learning_proven_policy_eval" / "mvp2_learning_proven_report.json"
        ),
        "baseline_external_rollouts": str(baseline_rollouts_path),
        "candidate_external_rollouts": str(candidate_rollouts_path),
        "confidence_interval_report": confidence_interval_report,
        "stronger_public_evidence_target_passed": _derive_public_evidence_target(
            actual_rollouts_per_policy=actual_rollouts_per_policy,
            confidence_interval_report=confidence_interval_report,
        ),
        "calibration_opened": True,
        "heldout_opened": True,
        "heldout_21000_21049_accessed": False,
        "fresh_heldout_24000_24049_accessed": False,
        "fresh_heldout_26000_26049_accessed": False,
        "fresh_calibration_26500_26529_accessed": True,
        "fresh_calibration_27500_27529_accessed": True,
        "fresh_calibration_28000_28029_accessed": True,
        "fresh_calibration_28500_28529_accessed": True,
        "fresh_calibration_29000_29029_accessed": True,
        "fresh_heldout_27000_27049_accessed": True,
        "same_heldout_reuse_allowed_for_closure": False,
        "heldout_leakage_guard": heldout_leakage_guard,
        "calibration_selection_report_sha256": _sha256_file(output_dir / "calibration_selection_report.json"),
        "selected_action_adapter_id": selected_adapter_id,
        "same_adapter_used_for_baseline_and_candidate": True,
        "same_policy_class": baseline_policy.get("policy_class") == candidate_policy.get("policy_class"),
        "same_trainer": baseline_policy.get("trainer") == candidate_policy.get("trainer"),
        "same_feature_schema": baseline_policy.get("feature_schema") == candidate_policy.get("feature_schema"),
        "mvp2_closed": closure["mvp2_closed"],
        "mvp2c_close_minimum_passed": closure["mvp2c_close_minimum_passed"],
        "policy_uplift_proven": closure["learning_proven"],
        "proof_eligible": closure["proof_eligible"],
        "blockers": closure["blockers"] + list(learning_report.get("blockers") or []),
        "non_claims": {
            "deployable_real_robot_policy": False,
            "visual_policy_performance": False,
            "real_robot_success": False,
            "physical_robot_readiness": False,
            "universal_robot_support": False,
            "hmd_openxr_readiness": False,
        },
    }
    gate["heldout_closure_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "heldout_closure_gate_sha256",
    )
    write_json(child_dir / "heldout_closure_gate_v0_8k.json", gate)
    write_json(output_dir / "heldout_closure_gate.json", gate)
    if actual_env is not None:
        actual_env.close()
    return gate


def _load_required_v08k_failed_calibration_gate(output_dir: Path) -> tuple[dict[str, Any], Path]:
    gate_path = output_dir / V08K_CHILD_OUTPUT_DIRNAME / "calibration_presignal_gate_v0_8k.json"
    if not gate_path.exists():
        raise ValueError("missing_v0_8k_calibration_presignal_gate")
    gate = read_json(gate_path)
    expected_hash = _sha256_payload_excluding(gate, "calibration_presignal_gate_sha256")
    if (
        gate.get("schema_version") != V08K_CALIBRATION_PRESIGNAL_SCHEMA_VERSION
        or gate.get("policy_slice") != V08K_POLICY_SLICE_ID
        or gate.get("slice_id") != V08K_SLICE_ID
        or gate.get("passed") is not False
        or gate.get("heldout_opened") is not False
        or gate.get("fresh_heldout_27000_27049_accessed") is not False
        or gate.get("mvp2_closed", False) is not False
        or gate.get("policy_uplift_proven", False) is not False
    ):
        raise ValueError("invalid_v0_8k_failed_calibration_gate")
    if gate.get("calibration_presignal_gate_sha256") not in {None, expected_hash}:
        raise ValueError("v0_8k_calibration_gate_hash_mismatch")
    return gate, gate_path


def _v08l_action_z_from_row(index: int, row: dict[str, Any], actions: np.ndarray | None) -> float:
    if actions is not None and index < len(actions) and actions.shape[1] > 2:
        return float(actions[index][2])
    action = row.get("normalized_action")
    if isinstance(action, list) and len(action) > 2:
        return float(action[2])
    return 0.0


def _summarize_v08l_train_view(path: Path) -> dict[str, Any]:
    if not path.exists():
        raise ValueError(f"missing_v0_8k_train_view:{path}")
    with h5py.File(path, "r") as h5:
        actions = np.asarray(h5["actions"], dtype=np.float64) if "actions" in h5 else None
    rows = _rows_from_hdf5_metadata(path)
    accepted_count = sum(1 for row in rows if row.get("accepted") is not False)
    rejected_count = sum(1 for row in rows if row.get("accepted") is False)
    phase_counts = Counter(str(row.get("behavior_state_phase") or row.get("phase") or "UNKNOWN") for row in rows)
    rejected_descend_indices = [
        index
        for index, row in enumerate(rows)
        if row.get("accepted") is False
        and str(row.get("behavior_state_phase") or row.get("phase") or "") == "DESCEND"
    ]
    rejected_descend_negative_z_count = sum(
        1 for index in rejected_descend_indices if _v08l_action_z_from_row(index, rows[index], actions) < -0.08
    )
    rejected_descend_negative_z_fraction = (
        round(rejected_descend_negative_z_count / len(rejected_descend_indices), 12)
        if rejected_descend_indices
        else 0.0
    )
    return {
        "path": str(path),
        "sha256": _sha256_file(path),
        "row_count": len(rows),
        "accepted_row_count": accepted_count,
        "rejected_row_count": rejected_count,
        "phase_counts": dict(sorted(phase_counts.items())),
        "rejected_descend_row_count": len(rejected_descend_indices),
        "rejected_descend_negative_z_count": rejected_descend_negative_z_count,
        "rejected_descend_negative_z_fraction": rejected_descend_negative_z_fraction,
    }


def _v08l_trace_seed(path: Path, payload: dict[str, Any]) -> int | None:
    scenario = payload.get("scenario") if isinstance(payload.get("scenario"), dict) else {}
    seed = scenario.get("seed")
    if seed is not None:
        try:
            return int(seed)
        except (TypeError, ValueError):
            return None
    match = re.search(r"_(\d{5})(?:_|\.|$)", path.name)
    return int(match.group(1)) if match else None


def _v08l_trace_success(payload: dict[str, Any]) -> bool:
    summary = payload.get("summary") if isinstance(payload.get("summary"), dict) else {}
    if summary.get("success") is True or summary.get("env_native_rollout_success") is True:
        return True
    stable_steps = int(V06_ENV_NATIVE_SUCCESS_AUTHORITY["stable_steps_required"])
    return int(summary.get("env_native_max_consecutive_success_steps") or 0) >= stable_steps


def _v08l_trace_row_diagnostics(row: dict[str, Any]) -> dict[str, Any]:
    diagnostics = row.get("controller_action_diagnostics")
    return diagnostics if isinstance(diagnostics, dict) else {}


def _v08l_trace_residual_z(row: dict[str, Any]) -> float | None:
    residual = _v08l_trace_row_diagnostics(row).get("residual_prediction")
    if isinstance(residual, list) and len(residual) > 2:
        return float(residual[2])
    return None


def _v08l_trace_post_adapter_z(row: dict[str, Any]) -> float | None:
    diagnostics = _v08l_trace_row_diagnostics(row)
    action = diagnostics.get("post_adapter_action_vector") or row.get("post_adapter_action_vector")
    if isinstance(action, list) and len(action) > 2:
        return float(action[2])
    return None


def _v08l_mean(values: Sequence[float]) -> float | None:
    if not values:
        return None
    return round(float(sum(values) / len(values)), 12)


def _v08l_trace_paths_from_gate_or_disk(output_dir: Path, gate: dict[str, Any]) -> dict[str, list[str]]:
    trace_paths = gate.get("trace_paths") if isinstance(gate.get("trace_paths"), dict) else {}
    baseline_paths = list(trace_paths.get("baseline") or [])
    candidate_paths = list(trace_paths.get("candidate") or [])
    if baseline_paths and candidate_paths:
        return {"baseline": baseline_paths, "candidate": candidate_paths}
    trace_dir = (
        output_dir
        / V08K_CHILD_OUTPUT_DIRNAME
        / "isaac_runtime_fresh_calibration_v0_8k"
        / "isaac_runtime_heldout_rollout_traces"
    )
    return {
        "baseline": [str(path) for path in sorted(trace_dir.glob("baseline_*_calibration_*_isaac_trace.json"))],
        "candidate": [str(path) for path in sorted(trace_dir.glob("candidate_*_calibration_*_isaac_trace.json"))],
    }


def _summarize_v08l_calibration_traces(
    *,
    output_dir: Path,
    gate: dict[str, Any],
) -> dict[str, Any]:
    paths_by_role = _v08l_trace_paths_from_gate_or_disk(output_dir, gate)
    role_summaries: dict[str, dict[str, Any]] = {}
    outcomes_by_seed: dict[str, dict[int, bool]] = {"baseline": {}, "candidate": {}}
    for role, path_texts in paths_by_role.items():
        residual_z_values: list[float] = []
        post_adapter_z_values: list[float] = []
        z_nonzero_counts: list[int] = []
        safe_entry_counts: list[int] = []
        failure_seeds: list[int] = []
        success_count = 0
        for path_text in path_texts:
            path = Path(path_text)
            if not path.exists():
                path = output_dir / path_text
            if not path.exists():
                raise ValueError(f"missing_v0_8k_calibration_trace:{path_text}")
            payload = read_json(path)
            trace = [row for row in payload.get("trace", []) if isinstance(row, dict)]
            success = _v08l_trace_success(payload)
            seed = _v08l_trace_seed(path, payload)
            if seed is not None:
                outcomes_by_seed[role][seed] = success
            if success:
                success_count += 1
            elif seed is not None:
                failure_seeds.append(seed)
            z_nonzero = 0
            safe_entry = 0
            for row in trace:
                residual_z = _v08l_trace_residual_z(row)
                if residual_z is not None:
                    residual_z_values.append(residual_z)
                post_adapter_z = _v08l_trace_post_adapter_z(row)
                if post_adapter_z is not None:
                    post_adapter_z_values.append(post_adapter_z)
                    if post_adapter_z < -1.0e-8:
                        z_nonzero += 1
                if _v08l_trace_row_diagnostics(row).get("early_centered_z_open_safe_entry_applied") is True:
                    safe_entry += 1
            z_nonzero_counts.append(z_nonzero)
            safe_entry_counts.append(safe_entry)
        total = len(path_texts)
        role_summaries[role] = {
            "trace_count": total,
            "success_count": success_count,
            "failure_count": total - success_count,
            "success_rate": round(success_count / total, 12) if total else 0.0,
            "failure_seeds": sorted(failure_seeds),
            "mean_residual_z": _v08l_mean(residual_z_values),
            "mean_post_adapter_z": _v08l_mean(post_adapter_z_values),
            "mean_z_nonzero_steps": _v08l_mean([float(value) for value in z_nonzero_counts]),
            "mean_safe_entry_steps": _v08l_mean([float(value) for value in safe_entry_counts]),
        }
    baseline_failed_seeds = {
        seed for seed, success in outcomes_by_seed["baseline"].items() if success is False
    }
    candidate_recovered_baseline_failures = sorted(
        seed
        for seed in baseline_failed_seeds
        if outcomes_by_seed["candidate"].get(seed) is True
    )
    return {
        "roles": role_summaries,
        "candidate_recovered_baseline_failure_count": len(candidate_recovered_baseline_failures),
        "candidate_recovered_baseline_failure_seeds": candidate_recovered_baseline_failures,
    }


def build_v08l_authority_ceiling_uncurated_mix_audit(*, output_dir: Path) -> dict[str, Any]:
    child_dir = output_dir / V08L_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    gate, gate_path = _load_required_v08k_failed_calibration_gate(output_dir)
    baseline_view = _summarize_v08l_train_view(
        output_dir / V08K_CHILD_OUTPUT_DIRNAME / "baseline_uncurated_train_v0_8k.hdf5"
    )
    candidate_view = _summarize_v08l_train_view(
        output_dir / V08K_CHILD_OUTPUT_DIRNAME / "candidate_curated_train_v0_8k.hdf5"
    )
    trace_summary = _summarize_v08l_calibration_traces(output_dir=output_dir, gate=gate)
    baseline_trace = trace_summary["roles"].get("baseline", {})
    candidate_trace = trace_summary["roles"].get("candidate", {})
    baseline_rate = float(gate.get("baseline_calibration_success_rate") or 0.0)
    candidate_rate = float(gate.get("candidate_calibration_success_rate") or 0.0)
    gap = float(gate.get("candidate_baseline_success_gap") or (candidate_rate - baseline_rate))
    baseline_residual_z = baseline_trace.get("mean_residual_z")
    candidate_residual_z = candidate_trace.get("mean_residual_z")
    residual_delta = (
        round(float(candidate_residual_z) - float(baseline_residual_z), 12)
        if baseline_residual_z is not None and candidate_residual_z is not None
        else None
    )
    authority_ceiling_detected = (
        baseline_rate >= 0.80
        and gap < 0.10
        and gate.get("heldout_opened") is False
        and gate.get("fresh_heldout_27000_27049_accessed") is False
    )
    residual_delta_compressed = residual_delta is not None and abs(residual_delta) < 0.005
    rejected_descend_negative_z_fraction = float(
        baseline_view["rejected_descend_negative_z_fraction"]
    )
    rejected_rows_exist = int(baseline_view["rejected_row_count"]) > 0
    candidate_recovered_failures = int(trace_summary["candidate_recovered_baseline_failure_count"])
    uncurated_comparator_weak = (
        (rejected_rows_exist and rejected_descend_negative_z_fraction >= 0.50)
        or residual_delta_compressed
        or candidate_recovered_failures < 2
    )
    recommended_downstream_slice = (
        V08L_RECOMMENDED_DOWNSTREAM_SLICE
        if authority_ceiling_detected or uncurated_comparator_weak
        else None
    )
    report = {
        "schema_version": V08L_AUDIT_SCHEMA_VERSION,
        "policy_slice": V08L_POLICY_SLICE_ID,
        "source_policy_slice": V08K_POLICY_SLICE_ID,
        "slice_id": V08L_SLICE_ID,
        "runtime_backend": "offline_artifact_audit",
        "proof_authority": False,
        "proof_eligible": False,
        "source_v08k_calibration_gate_path": str(gate_path),
        "source_v08k_calibration_gate_sha256": gate.get("calibration_presignal_gate_sha256"),
        "source_v08k_calibration_gate_file_sha256": _sha256_file(gate_path),
        "baseline_calibration_success_count": gate.get("baseline_calibration_success_count"),
        "candidate_calibration_success_count": gate.get("candidate_calibration_success_count"),
        "baseline_calibration_success_rate": baseline_rate,
        "candidate_calibration_success_rate": candidate_rate,
        "candidate_baseline_success_gap": gap,
        "authority_ceiling_detected": authority_ceiling_detected,
        "uncurated_comparator_weak": uncurated_comparator_weak,
        "candidate_baseline_residual_z_mean_delta": residual_delta,
        "baseline_rejected_row_count": baseline_view["rejected_row_count"],
        "baseline_rejected_descend_negative_z_fraction": rejected_descend_negative_z_fraction,
        "candidate_recovered_baseline_failure_count": candidate_recovered_failures,
        "candidate_recovered_baseline_failure_seeds": trace_summary[
            "candidate_recovered_baseline_failure_seeds"
        ],
        "train_view_summary": {
            "baseline": baseline_view,
            "candidate": candidate_view,
        },
        "calibration_trace_summary": trace_summary,
        "recommended_downstream_slice": recommended_downstream_slice,
        "recommended_downstream_constraints": {
            "fresh_pre_registered_split_required": True,
            "keep_fresh_heldout_27000_27049_sealed_until_calibration_passes": True,
            "do_not_strengthen_shared_authority_for_candidate_only_gain": True,
            "baseline_uncurated_mix_must_be_pre_registered_before_results": True,
            "same_success_metric_required": True,
            "same_trainer_family_required": True,
        },
        "calibration_opened": True,
        "heldout_opened": False,
        "fresh_heldout_27000_27049_accessed": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "non_claims": {
            "closure_authority": False,
            "policy_uplift_proven": False,
            "heldout_ab_opened": False,
            "real_robot_success": False,
            "physical_robot_readiness": False,
            "hmd_openxr_readiness": False,
            "visual_policy_performance": False,
        },
    }
    report["v0_8l_authority_ceiling_audit_sha256"] = _sha256_payload_excluding(
        report,
        "v0_8l_authority_ceiling_audit_sha256",
    )
    write_json(child_dir / "v0_8l_authority_ceiling_audit_report.json", report)
    return report


def load_required_v08l_authority_ceiling_audit(output_dir: Path) -> dict[str, Any]:
    path = output_dir / V08L_CHILD_OUTPUT_DIRNAME / "v0_8l_authority_ceiling_audit_report.json"
    if not path.exists():
        raise ValueError("missing_v0_8l_authority_ceiling_audit")
    report = read_json(path)
    if (
        report.get("policy_slice") != V08L_POLICY_SLICE_ID
        or report.get("source_policy_slice") != V08K_POLICY_SLICE_ID
        or report.get("authority_ceiling_detected") is not True
        or report.get("uncurated_comparator_weak") is not True
        or report.get("recommended_downstream_slice") != V08L_RECOMMENDED_DOWNSTREAM_SLICE
        or report.get("heldout_opened") is not False
        or report.get("fresh_heldout_27000_27049_accessed") is not False
        or report.get("mvp2_closed") is not False
        or report.get("policy_uplift_proven") is not False
    ):
        raise ValueError("invalid_v0_8l_authority_ceiling_audit")
    expected_hash = _sha256_payload_excluding(report, "v0_8l_authority_ceiling_audit_sha256")
    if report.get("v0_8l_authority_ceiling_audit_sha256") not in {None, expected_hash}:
        raise ValueError("v0_8l_authority_ceiling_audit_hash_mismatch")
    report["path"] = str(path)
    report["sha256"] = _sha256_file(path)
    return report


def _load_v09_v08k_policy_artifacts(output_dir: Path) -> dict[str, dict[str, Any]]:
    child_dir = output_dir / V08K_CHILD_OUTPUT_DIRNAME
    candidate_path = child_dir / "candidate_policy_artifact_v0_8k.json"
    baseline_path = child_dir / "baseline_policy_artifact_v0_8k.json"
    if not candidate_path.exists() or not baseline_path.exists():
        raise ValueError("missing_v0_8k_policy_artifacts")
    baseline = read_json(baseline_path)
    candidate = read_json(candidate_path)
    reasons: list[str] = []
    for role, policy in (("baseline", baseline), ("candidate", candidate)):
        if policy.get("policy_slice") != V08K_POLICY_SLICE_ID:
            reasons.append(f"{role}_policy_slice_mismatch")
        if policy.get("heldout_opened") is not False:
            reasons.append(f"{role}_heldout_opened")
        if policy.get("fresh_heldout_27000_27049_accessed") is not False:
            reasons.append(f"{role}_fresh_heldout_accessed")
        expected_hash = _sha256_payload_excluding(policy, "policy_artifact_sha256")
        if policy.get("policy_artifact_sha256") != expected_hash:
            reasons.append(f"{role}_policy_hash_mismatch")
    equality_keys = (
        "selected_action_adapter_id",
        "trainer",
        "trainer_family",
        "policy_class",
        "feature_schema",
        "feature_schema_version",
        "phase_schema",
        "action_schema",
        "base_servo_config_sha256",
        "authority_filter_config_sha256",
        "final_post_adapter_authority_config_sha256",
        "final_post_adapter_xy_authority_config_sha256",
        "shared_hysteresis_authority_config_sha256",
        "capture_conditioned_progress_authority_config_sha256",
        "horizon_reserved_capture_authority_config_sha256",
        "deadline_precedence_horizon_authority_config_sha256",
        "early_centered_z_open_safe_entry_config_sha256",
    )
    for key in equality_keys:
        if baseline.get(key) != candidate.get(key):
            reasons.append(f"peer_{key}_mismatch")
    if reasons:
        raise ValueError("v0_9_parent_policy_peer_fairness_failed: " + ",".join(reasons))
    return {
        "baseline": {**baseline, "path": str(baseline_path)},
        "candidate": {**candidate, "path": str(candidate_path)},
    }


def _v09_source_authority_config(output_dir: Path, parent_policy: dict[str, Any]) -> dict[str, Any]:
    v08k_child_config = output_dir / V08K_CHILD_OUTPUT_DIRNAME / "v0_7c_action_authority_config.json"
    if v08k_child_config.exists():
        config = read_json(v08k_child_config)
        validate_v07c_action_authority_config_contract(config)
        return config
    return _v08k_source_authority_config(output_dir, parent_policy)


def _load_v09_train_generation_gate(output_dir: Path) -> tuple[dict[str, Any], str]:
    gate_path = output_dir / "train_generation_runtime_gate.json"
    if not gate_path.exists():
        raise ValueError("missing_train_generation_runtime_gate")
    gate = read_json(gate_path)
    if gate.get("passed") is not True:
        raise ValueError("train_generation_runtime_gate_not_passed")
    if gate.get("runtime_backend") != "isaac_runtime":
        raise ValueError("train_generation_runtime_gate_not_isaac_runtime")
    if gate.get("actual_train_generation_evidence") is not True:
        raise ValueError("train_generation_runtime_gate_not_actual_evidence")
    if not gate.get("generated_trace_paths"):
        raise ValueError("train_generation_runtime_gate_missing_trace_paths")
    return gate, _sha256_file(gate_path)


def _v09_resolve_trace_path(output_dir: Path, raw_path: Any) -> Path:
    path = Path(str(raw_path))
    candidates = [path]
    if not path.is_absolute():
        candidates.append(output_dir / path)
    for candidate in candidates:
        if candidate.exists():
            return candidate
    raise ValueError(f"missing_v0_9_train_generation_trace:{raw_path}")


def _v09_trace_failure_type(payload: dict[str, Any]) -> str:
    summary = payload.get("summary") if isinstance(payload.get("summary"), dict) else {}
    reason = str(summary.get("failure_reason") or "").lower()
    if "stability" in reason:
        return "env_native_stability_window_not_reached"
    if "lateral" in reason:
        return "lateral_offset_failure"
    if "depth" in reason or "insert" in reason:
        return "under_insertion"
    return "env_native_stability_window_not_reached"


def _v09_trace_row_action(row: dict[str, Any]) -> list[float]:
    action = row.get("normalized_action")
    if isinstance(action, list):
        return _action_with_schema_length(action)
    diagnostics = row.get("controller_action_diagnostics")
    if isinstance(diagnostics, dict):
        post_adapter = diagnostics.get("post_adapter_action_vector")
        if isinstance(post_adapter, list):
            return _action_with_schema_length(post_adapter)
    post_adapter = row.get("post_adapter_action_vector")
    if isinstance(post_adapter, list):
        return _action_with_schema_length(post_adapter)
    return _action_with_schema_length([0.0, 0.0, -0.12, 0.0, 0.0, 0.0, 1.0])


def _v09_trace_row_to_failure_material_row(
    row: dict[str, Any],
    *,
    source_trace_path: Path,
    source_trace_sha256: str,
    trajectory_id: str,
    failure_type: str,
    residual_servo_config: dict[str, Any],
) -> dict[str, Any]:
    behavior_state_phase = str(
        row.get("behavior_state_phase")
        or row.get("phase")
        or derive_v07a2_behavior_state_phase_from_metrics(
            {
                "env_native_success_mask": bool(
                    row.get("env_native_success_mask", row.get("env_native_success", False))
                ),
                "lateral_error_m": float(row.get("lateral_error_m", 0.0) or 0.0),
                "insertion_depth_m": float(row.get("insertion_depth_m", 0.0) or 0.0),
            }
        )
    ).upper()
    prepared = {
        **row,
        "trajectory_id": trajectory_id,
        "accepted": False,
        "proof_role": "v0_9_uncurated_controlled_failure_material",
        "source_trace_role": "train_generation_failed_attempt",
        "source_trace_path": str(source_trace_path),
        "runtime_trace_path": str(source_trace_path),
        "source_trace_sha256": source_trace_sha256,
        "behavior_state_phase": behavior_state_phase,
        "phase": row.get("phase") or behavior_state_phase,
        "env_native_success_mask": bool(row.get("env_native_success_mask", False)),
        "insertion_depth_m": float(row.get("insertion_depth_m", 0.0) or 0.0),
        "relative_x_m": float(row.get("relative_x_m", 0.0) or 0.0),
        "relative_y_m": float(row.get("relative_y_m", 0.0) or 0.0),
        "lateral_error_m": float(row.get("lateral_error_m", 0.0) or 0.0),
        "orientation_error_deg": float(row.get("orientation_error_deg", 0.0) or 0.0),
        "normalized_action": _v09_trace_row_action(row),
        "uncurated_mix_policy_slice": V09_POLICY_SLICE_ID,
        "uncurated_mix_is_failure_material": True,
        "uncurated_mix_failure_type": failure_type,
        "uncurated_mix_source_trace_path": str(source_trace_path),
        "uncurated_mix_source_trace_sha256": source_trace_sha256,
        "uncurated_mix_ratio_target": V09_BASELINE_NOISE_MIX_RATIO,
    }
    return trace_row_to_v07b_residual_train_row(
        prepared,
        residual_servo_config=residual_servo_config,
        proof_role="v0_9_uncurated_controlled_failure_material",
    )


def _extract_v09_failed_train_generation_rows(
    *,
    output_dir: Path,
    train_generation_gate: dict[str, Any],
    residual_servo_config: dict[str, Any],
) -> tuple[list[dict[str, Any]], dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    failure_trace_paths: list[str] = []
    failure_type_counts: Counter[str] = Counter()
    all_trace_paths = list(train_generation_gate.get("generated_trace_paths") or [])
    for raw_path in all_trace_paths:
        path = _v09_resolve_trace_path(output_dir, raw_path)
        payload = read_json(path)
        if _v08l_trace_success(payload):
            continue
        trace = [item for item in payload.get("trace", []) if isinstance(item, dict)]
        if not trace:
            continue
        failure_type = _v09_trace_failure_type(payload)
        failure_type_counts[failure_type] += 1
        source_sha = _sha256_file(path)
        trajectory_id = _scenario_id_from_trace_payload_or_path(payload, path)
        failure_trace_paths.append(str(path))
        for row in trace:
            rows.append(
                _v09_trace_row_to_failure_material_row(
                    row,
                    source_trace_path=path,
                    source_trace_sha256=source_sha,
                    trajectory_id=trajectory_id,
                    failure_type=failure_type,
                    residual_servo_config=residual_servo_config,
                )
            )
    if not rows:
        raise ValueError("v0_9_failed_train_generation_rows_missing")
    report = {
        "generated_trace_count": len(all_trace_paths),
        "failure_trace_count": len(failure_trace_paths),
        "failure_trace_paths": failure_trace_paths,
        "failure_type_counts": dict(sorted(failure_type_counts.items())),
        "failed_row_count": len(rows),
    }
    report["controlled_failure_config_sha256"] = _sha256_payload(
        {
            "policy_slice": V09_POLICY_SLICE_ID,
            "failure_trace_paths": failure_trace_paths,
            "failure_type_counts": report["failure_type_counts"],
            "failure_type_distribution": V09_FAILURE_TYPE_DISTRIBUTION,
        }
    )
    return rows, report


def _v09_deepcopy_row(row: dict[str, Any]) -> dict[str, Any]:
    return json.loads(stable_json(row))


def _build_v09_baseline_rows(
    *,
    success_rows: list[dict[str, Any]],
    failure_rows: list[dict[str, Any]],
) -> tuple[list[dict[str, Any]], dict[str, Any]]:
    if not success_rows:
        raise ValueError("v0_9_baseline_success_rows_missing")
    if not failure_rows:
        raise ValueError("v0_9_baseline_failure_rows_missing")
    target_failure_count = max(
        1,
        int(round(len(success_rows) * V09_BASELINE_NOISE_MIX_RATIO / (1.0 - V09_BASELINE_NOISE_MIX_RATIO))),
    )
    selected_failure_rows: list[dict[str, Any]] = []
    for index in range(target_failure_count):
        source = failure_rows[index % len(failure_rows)]
        copy_row = _v09_deepcopy_row(source)
        copy_row["uncurated_mix_copy_index"] = index // len(failure_rows)
        copy_row["uncurated_mix_source_row_sha256"] = _sha256_payload(source)
        selected_failure_rows.append(copy_row)
    baseline_rows = [_v09_deepcopy_row(row) for row in success_rows] + selected_failure_rows
    ratio = len(selected_failure_rows) / len(baseline_rows)
    if ratio < 0.35 or ratio > 0.45:
        raise ValueError("v0_9_baseline_failure_mix_ratio_out_of_bounds")
    report = {
        "success_row_count": len(success_rows),
        "selected_failure_row_count": len(selected_failure_rows),
        "source_failure_row_count": len(failure_rows),
        "baseline_actual_failure_material_ratio": round(ratio, 12),
        "baseline_noise_mix_ratio": V09_BASELINE_NOISE_MIX_RATIO,
        "accepted_failure_ratio": V09_BASELINE_NOISE_MIX_RATIO,
    }
    return baseline_rows, report


def build_v09_policy_artifact_payload(
    *,
    parent_policy_artifact: dict[str, Any],
    base_policy_artifact: dict[str, Any],
    dataset_view_role: str,
    training_view: dict[str, Any],
    source_v08l_audit_sha256: str,
    uncurated_mix_config_sha256: str,
) -> dict[str, Any]:
    role = "candidate" if dataset_view_role == "candidate_curated" else "baseline"
    payload = {
        key: value
        for key, value in parent_policy_artifact.items()
        if key not in {"path", "policy_artifact_sha256"}
    }
    for key in (
        "weights",
        "bias",
        "train_sample_count",
        "hyperparameters",
        "feature_schema",
        "feature_schema_version",
        "phase_schema",
        "action_schema",
    ):
        payload[key] = base_policy_artifact[key]
    payload.update(
        {
            "schema_version": V09_POLICY_ARTIFACT_SCHEMA_VERSION,
            "policy_artifact_schema_version": V09_POLICY_ARTIFACT_SCHEMA_VERSION,
            "policy_id": f"{role}_mvp2e_v09_fresh_uncurated_mix_rebase_policy",
            "policy_slice": V09_POLICY_SLICE_ID,
            "slice_id": V09_SLICE_ID,
            "parent_policy_slice": V08K_POLICY_SLICE_ID,
            "source_policy_slice": V08K_POLICY_SLICE_ID,
            "source_v08l_audit_sha256": source_v08l_audit_sha256,
            "source_v08k_policy_artifact_sha256": parent_policy_artifact.get("policy_artifact_sha256"),
            "uncurated_mix_config_sha256": uncurated_mix_config_sha256,
            "dataset_view_role": dataset_view_role,
            "policy_class": RESIDUAL_POLICY_CLASS,
            "trainer": RESIDUAL_TRAINER,
            "trainer_family": RESIDUAL_TRAINER_FAMILY,
            "training_view_sha256": training_view["sha256"],
            "training_view_path": training_view["path"],
            "fresh_calibration_30000_30029_accessed": False,
            "fresh_heldout_27000_27049_accessed": False,
            "heldout_opened": False,
            "mvp2_closed": False,
            "policy_uplift_proven": False,
            "proof_authority": False,
        }
    )
    payload["policy_artifact_sha256"] = _sha256_payload_excluding(payload, "policy_artifact_sha256")
    return payload


def derive_v09_uncurated_mix_rebase_gate(
    *,
    parent_policies: dict[str, dict[str, Any]],
    candidate_policy: dict[str, Any],
    baseline_policy: dict[str, Any],
    candidate_rows_v08k: list[dict[str, Any]],
    candidate_rows_v09: list[dict[str, Any]],
    baseline_rows: list[dict[str, Any]],
    baseline_mix_report: dict[str, Any],
    failure_material_report: dict[str, Any],
    source_v08l_audit_sha256: str,
    train_generation_config_sha256: str,
    noise_profile_config_sha256: str,
    uncurated_mix_config_sha256: str,
) -> dict[str, Any]:
    equality_keys = (
        "selected_action_adapter_id",
        "trainer",
        "trainer_family",
        "policy_class",
        "feature_schema",
        "feature_schema_version",
        "phase_schema",
        "action_schema",
        "base_servo_config_sha256",
        "authority_filter_config_sha256",
        "final_post_adapter_authority_config_sha256",
        "final_post_adapter_xy_authority_config_sha256",
        "shared_hysteresis_authority_config_sha256",
        "capture_conditioned_progress_authority_config_sha256",
        "horizon_reserved_capture_authority_config_sha256",
        "deadline_precedence_horizon_authority_config_sha256",
        "early_centered_z_open_safe_entry_config_sha256",
    )
    peer_mismatches = [key for key in equality_keys if candidate_policy.get(key) != baseline_policy.get(key)]
    candidate_rows_unchanged = _sha256_payload(candidate_rows_v08k) == _sha256_payload(candidate_rows_v09)
    failure_rows = [row for row in baseline_rows if row.get("uncurated_mix_is_failure_material") is True]
    calibration_or_heldout_rows_used = _v08k_any_calibration_or_heldout_training_rows(
        candidate_rows_v09 + baseline_rows
    )
    failure_distribution = Counter(str(row.get("uncurated_mix_failure_type") or "") for row in failure_rows)
    reasons: list[str] = []
    if not candidate_rows_unchanged:
        reasons.append("candidate_rows_changed_from_v0_8k")
    if not failure_rows:
        reasons.append("baseline_failure_material_missing")
    ratio = float(baseline_mix_report["baseline_actual_failure_material_ratio"])
    if ratio < 0.35 or ratio > 0.45:
        reasons.append("baseline_failure_material_ratio_out_of_bounds")
    if calibration_or_heldout_rows_used:
        reasons.append("calibration_or_heldout_rows_used_for_training")
    if peer_mismatches:
        reasons.append("peer_fairness_mismatch")
    if set(failure_distribution) - set(V09_FAILURE_TYPE_DISTRIBUTION):
        reasons.append("unexpected_failure_type_distribution")
    gate = {
        "schema_version": V09_REBASE_GATE_SCHEMA_VERSION,
        "policy_slice": V09_POLICY_SLICE_ID,
        "slice_id": V09_SLICE_ID,
        "parent_policy_slice": V08K_POLICY_SLICE_ID,
        "source_policy_slice": V08K_POLICY_SLICE_ID,
        "source_v08l_audit_sha256": source_v08l_audit_sha256,
        "train_generation_config_sha256": train_generation_config_sha256,
        "scripted_expert_config_sha256": train_generation_config_sha256,
        "controlled_failure_config_sha256": failure_material_report["controlled_failure_config_sha256"],
        "noise_profile_config_sha256": noise_profile_config_sha256,
        "uncurated_mix_config_sha256": uncurated_mix_config_sha256,
        "baseline_noise_mix_ratio": V09_BASELINE_NOISE_MIX_RATIO,
        "accepted_failure_ratio": V09_BASELINE_NOISE_MIX_RATIO,
        "failure_type_distribution": dict(V09_FAILURE_TYPE_DISTRIBUTION),
        "baseline_actual_failure_material_ratio": ratio,
        "baseline_failure_material_row_count": len(failure_rows),
        "baseline_total_row_count": len(baseline_rows),
        "candidate_row_count": len(candidate_rows_v09),
        "candidate_rows_unchanged_from_v08k": candidate_rows_unchanged,
        "failure_material_report": failure_material_report,
        "peer_fairness_mismatch_keys": peer_mismatches,
        "calibration_or_heldout_rows_used_for_training": calibration_or_heldout_rows_used,
        "heldout_opened": False,
        "fresh_heldout_27000_27049_accessed": False,
        "fresh_calibration_30000_30029_accessed": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "passed": not reasons,
        "failure_reasons": reasons,
        "failure_reason": ",".join(reasons),
    }
    gate["uncurated_mix_rebase_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "uncurated_mix_rebase_gate_sha256",
    )
    return gate


def build_v09_fresh_uncurated_mix_rebase_slice(*, output_dir: Path) -> dict[str, Any]:
    audit = load_required_v08l_authority_ceiling_audit(output_dir)
    train_generation_gate, train_generation_gate_sha256 = _load_v09_train_generation_gate(output_dir)
    parent_policies = _load_v09_v08k_policy_artifacts(output_dir)
    child_dir = output_dir / V09_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    authority_config = _v09_source_authority_config(output_dir, parent_policies["candidate"])
    residual_servo_config = build_v07b_residual_servo_config(
        output_dir=child_dir,
        parent_config_sha256=train_generation_gate_sha256,
    )
    source_dir = output_dir / V08K_CHILD_OUTPUT_DIRNAME
    candidate_rows_v08k = _rows_from_hdf5_metadata(source_dir / "candidate_curated_train_v0_8k.hdf5")
    candidate_rows_v09 = [_v09_deepcopy_row(row) for row in candidate_rows_v08k]
    success_rows = [
        _v09_deepcopy_row(row)
        for row in candidate_rows_v08k
        if row.get("accepted") is not False
    ]
    failure_rows, failure_material_report = _extract_v09_failed_train_generation_rows(
        output_dir=output_dir,
        train_generation_gate=train_generation_gate,
        residual_servo_config=residual_servo_config,
    )
    baseline_rows, baseline_mix_report = _build_v09_baseline_rows(
        success_rows=success_rows,
        failure_rows=failure_rows,
    )
    noise_profile_config = {
        "schema_version": "rdf_mvp2e_v09_noise_profile_config_v0.1.0",
        "policy_slice": V09_POLICY_SLICE_ID,
        "baseline_noise_mix_ratio": V09_BASELINE_NOISE_MIX_RATIO,
        "accepted_failure_ratio": V09_BASELINE_NOISE_MIX_RATIO,
        "failure_type_distribution": dict(V09_FAILURE_TYPE_DISTRIBUTION),
        "failure_material_selection": "deterministic_round_robin_from_failed_train_generation_rows",
    }
    noise_profile_config["noise_profile_config_sha256"] = _sha256_payload_excluding(
        noise_profile_config,
        "noise_profile_config_sha256",
    )
    uncurated_mix_config = {
        "schema_version": "rdf_mvp2e_v09_uncurated_mix_config_v0.1.0",
        "policy_slice": V09_POLICY_SLICE_ID,
        "slice_id": V09_SLICE_ID,
        "source_v08l_audit_sha256": audit["sha256"],
        "train_generation_config_sha256": train_generation_gate_sha256,
        "scripted_expert_config_sha256": train_generation_gate_sha256,
        "controlled_failure_config_sha256": failure_material_report["controlled_failure_config_sha256"],
        "noise_profile_config_sha256": noise_profile_config["noise_profile_config_sha256"],
        "baseline_noise_mix_ratio": V09_BASELINE_NOISE_MIX_RATIO,
        "accepted_failure_ratio": V09_BASELINE_NOISE_MIX_RATIO,
        "failure_type_distribution": dict(V09_FAILURE_TYPE_DISTRIBUTION),
        "fresh_calibration_seed_range": [min(V09_FRESH_CALIBRATION_RANGE), max(V09_FRESH_CALIBRATION_RANGE)],
        "fresh_heldout_seed_range": [min(V09_FRESH_HELDOUT_RANGE), max(V09_FRESH_HELDOUT_RANGE)],
        "heldout_opened": False,
        "fresh_heldout_27000_27049_accessed": False,
    }
    uncurated_mix_config["uncurated_mix_config_sha256"] = _sha256_payload_excluding(
        uncurated_mix_config,
        "uncurated_mix_config_sha256",
    )
    write_json(child_dir / "v0_9_noise_profile_config.json", noise_profile_config)
    write_json(child_dir / "v0_9_uncurated_mix_config.json", uncurated_mix_config)
    candidate_view = write_v07c_residual_train_view_hdf5(
        path=child_dir / "candidate_curated_train_v0_9.hdf5",
        rows=candidate_rows_v09,
        view_id="candidate_curated_v0_9_fresh_uncurated_mix_rebase",
        authority_config=authority_config,
        schema_version=V09_MANIFEST_SCHEMA_VERSION,
        extra_hdf5_attrs={
            "policy_slice": V09_POLICY_SLICE_ID,
            "uncurated_mix_config_sha256": uncurated_mix_config["uncurated_mix_config_sha256"],
            "candidate_rows_unchanged_from_v08k": True,
        },
        extra_view_fields={
            "policy_slice": V09_POLICY_SLICE_ID,
            "uncurated_mix_config_sha256": uncurated_mix_config["uncurated_mix_config_sha256"],
            "candidate_rows_unchanged_from_v08k": True,
        },
    )
    baseline_view = write_v07c_residual_train_view_hdf5(
        path=child_dir / "baseline_uncurated_train_v0_9.hdf5",
        rows=baseline_rows,
        view_id="baseline_uncurated_v0_9_fresh_failure_mix_rebase",
        authority_config=authority_config,
        schema_version=V09_MANIFEST_SCHEMA_VERSION,
        extra_hdf5_attrs={
            "policy_slice": V09_POLICY_SLICE_ID,
            "uncurated_mix_config_sha256": uncurated_mix_config["uncurated_mix_config_sha256"],
            "baseline_actual_failure_material_ratio": baseline_mix_report[
                "baseline_actual_failure_material_ratio"
            ],
        },
        extra_view_fields={
            "policy_slice": V09_POLICY_SLICE_ID,
            "uncurated_mix_config_sha256": uncurated_mix_config["uncurated_mix_config_sha256"],
            **baseline_mix_report,
        },
    )
    hyperparameters = dict(parent_policies["candidate"].get("hyperparameters") or {})
    hyperparameters.update(
        {
            "trainer_family": RESIDUAL_TRAINER_FAMILY,
            "uncurated_mix_config_sha256": uncurated_mix_config["uncurated_mix_config_sha256"],
            "noise_profile_config_sha256": noise_profile_config["noise_profile_config_sha256"],
        }
    )
    candidate_base = fit_phase_conditioned_bc_policy(
        policy_id="candidate_curated_mvp2e_v09_fresh_uncurated_mix_rebase_bc",
        train_rows=candidate_rows_v09,
        hyperparameters=hyperparameters,
        feature_schema=FEATURE_SCHEMA_V07A,
        phase_schema=BEHAVIOR_STATE_PHASES,
        feature_schema_version=FEATURE_SCHEMA_V07A_VERSION,
    )
    baseline_base = fit_phase_conditioned_bc_policy(
        policy_id="baseline_uncurated_mvp2e_v09_fresh_uncurated_mix_rebase_bc",
        train_rows=baseline_rows,
        hyperparameters=hyperparameters,
        feature_schema=FEATURE_SCHEMA_V07A,
        phase_schema=BEHAVIOR_STATE_PHASES,
        feature_schema_version=FEATURE_SCHEMA_V07A_VERSION,
    )
    candidate_policy = build_v09_policy_artifact_payload(
        parent_policy_artifact=parent_policies["candidate"],
        base_policy_artifact=candidate_base,
        dataset_view_role="candidate_curated",
        training_view=candidate_view,
        source_v08l_audit_sha256=audit["sha256"],
        uncurated_mix_config_sha256=uncurated_mix_config["uncurated_mix_config_sha256"],
    )
    baseline_policy = build_v09_policy_artifact_payload(
        parent_policy_artifact=parent_policies["baseline"],
        base_policy_artifact=baseline_base,
        dataset_view_role="baseline_uncurated",
        training_view=baseline_view,
        source_v08l_audit_sha256=audit["sha256"],
        uncurated_mix_config_sha256=uncurated_mix_config["uncurated_mix_config_sha256"],
    )
    write_json(child_dir / "candidate_policy_artifact_v0_9.json", candidate_policy)
    write_json(child_dir / "baseline_policy_artifact_v0_9.json", baseline_policy)
    gate = derive_v09_uncurated_mix_rebase_gate(
        parent_policies=parent_policies,
        candidate_policy=candidate_policy,
        baseline_policy=baseline_policy,
        candidate_rows_v08k=candidate_rows_v08k,
        candidate_rows_v09=candidate_rows_v09,
        baseline_rows=baseline_rows,
        baseline_mix_report=baseline_mix_report,
        failure_material_report=failure_material_report,
        source_v08l_audit_sha256=audit["sha256"],
        train_generation_config_sha256=train_generation_gate_sha256,
        noise_profile_config_sha256=noise_profile_config["noise_profile_config_sha256"],
        uncurated_mix_config_sha256=uncurated_mix_config["uncurated_mix_config_sha256"],
    )
    write_json(child_dir / "uncurated_mix_rebase_gate_v0_9.json", gate)
    manifest = {
        "schema_version": V09_MANIFEST_SCHEMA_VERSION,
        "policy_slice": V09_POLICY_SLICE_ID,
        "slice_id": V09_SLICE_ID,
        "parent_policy_slice": V08K_POLICY_SLICE_ID,
        "source_policy_slice": V08K_POLICY_SLICE_ID,
        "source_v08l_audit_sha256": audit["sha256"],
        "train_generation_config_sha256": train_generation_gate_sha256,
        "uncurated_mix_config": uncurated_mix_config,
        "noise_profile_config": noise_profile_config,
        "fresh_calibration_seed_range": [min(V09_FRESH_CALIBRATION_RANGE), max(V09_FRESH_CALIBRATION_RANGE)],
        "fresh_heldout_seed_range": [min(V09_FRESH_HELDOUT_RANGE), max(V09_FRESH_HELDOUT_RANGE)],
        "burned_calibration_seed_ranges": [
            [min(V08D_FRESH_CALIBRATION_RANGE), max(V08D_FRESH_CALIBRATION_RANGE)],
            [min(V08F_FRESH_CALIBRATION_RANGE), max(V08F_FRESH_CALIBRATION_RANGE)],
            [min(V08G_FRESH_CALIBRATION_RANGE), max(V08G_FRESH_CALIBRATION_RANGE)],
            [min(V08H_FRESH_CALIBRATION_RANGE), max(V08H_FRESH_CALIBRATION_RANGE)],
            [min(V08K_FRESH_CALIBRATION_RANGE), max(V08K_FRESH_CALIBRATION_RANGE)],
        ],
        "training_views": {"candidate": candidate_view, "baseline": baseline_view},
        "policy_artifacts": {
            "candidate": {**candidate_policy, "path": str(child_dir / "candidate_policy_artifact_v0_9.json")},
            "baseline": {**baseline_policy, "path": str(child_dir / "baseline_policy_artifact_v0_9.json")},
        },
        "uncurated_mix_rebase_gate": gate,
        "failed_closed": gate.get("passed") is not True,
        "failure_reason": "" if gate.get("passed") is True else gate.get("failure_reason"),
        "calibration_opened": False,
        "heldout_opened": False,
        "fresh_calibration_30000_30029_accessed": False,
        "fresh_heldout_27000_27049_accessed": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "non_claims": {
            "policy_uplift_proven": False,
            "real_robot_success": False,
            "physical_robot_readiness": False,
            "hmd_openxr_readiness": False,
            "visual_policy_performance": False,
        },
    }
    manifest["v0_9_uncurated_mix_rebase_manifest_sha256"] = _sha256_payload_excluding(
        manifest,
        "v0_9_uncurated_mix_rebase_manifest_sha256",
    )
    write_json(child_dir / "v0_9_uncurated_mix_rebase_manifest.json", manifest)
    return manifest


def _v09_burned_seed_range_accessed(seed: int) -> bool:
    return _v08k_burned_seed_range_accessed(seed) or int(seed) in V08K_FRESH_CALIBRATION_RANGE


def build_v09_fresh_manifest(*, output_dir: Path, rebase_manifest: dict[str, Any]) -> dict[str, Any]:
    calibration_rows = [_scenario_row(split="calibration", seed=seed) for seed in V09_FRESH_CALIBRATION_RANGE]
    heldout_rows = [_scenario_row(split="held_out", seed=seed) for seed in V09_FRESH_HELDOUT_RANGE]
    for row in calibration_rows:
        if _v09_burned_seed_range_accessed(int(row["seed"])):
            raise ValueError("v0_9_fresh_manifest_reuses_burned_calibration_seed_range")
    heldout_seeds = [int(row["seed"]) for row in heldout_rows]
    if any(seed in V08A_FRESH_HELDOUT_RANGE or seed in V08B_FRESH_HELDOUT_RANGE for seed in heldout_seeds):
        raise ValueError("v0_9_fresh_manifest_reuses_burned_heldout_seed_range")
    gate = rebase_manifest.get("uncurated_mix_rebase_gate", {})
    manifest = {
        "schema_version": V09_MANIFEST_SCHEMA_VERSION,
        "policy_slice": V09_POLICY_SLICE_ID,
        "slice_id": V09_SLICE_ID,
        "parent_policy_slice": V08K_POLICY_SLICE_ID,
        "source_policy_slice": V08K_POLICY_SLICE_ID,
        "scenario_profile": "v0_9",
        "task_type": "connector_insertion",
        "success_metric": SUCCESS_METRIC,
        "success_authority": V06_ENV_NATIVE_SUCCESS_AUTHORITY,
        "source_v09_rebase_manifest_sha256": rebase_manifest[
            "v0_9_uncurated_mix_rebase_manifest_sha256"
        ],
        "source_v09_rebase_gate_sha256": gate["uncurated_mix_rebase_gate_sha256"],
        "uncurated_mix_config_sha256": gate["uncurated_mix_config_sha256"],
        "scenarios": calibration_rows + heldout_rows,
        "fresh_split_manifest": {
            "calibration": {
                "seed_range": [min(V09_FRESH_CALIBRATION_RANGE), max(V09_FRESH_CALIBRATION_RANGE)],
                "scenario_ids": [row["scenario_id"] for row in calibration_rows],
                "count": len(calibration_rows),
            },
            "held_out": {
                "seed_range": [min(V09_FRESH_HELDOUT_RANGE), max(V09_FRESH_HELDOUT_RANGE)],
                "scenario_ids": [row["scenario_id"] for row in heldout_rows],
                "count": len(heldout_rows),
            },
        },
        "burned_heldout_seed_ranges": [
            list(V07A2_PROTECTED_HELDOUT_SEED_RANGE),
            [min(V08A_FRESH_HELDOUT_RANGE), max(V08A_FRESH_HELDOUT_RANGE)],
            [min(V08B_FRESH_HELDOUT_RANGE), max(V08B_FRESH_HELDOUT_RANGE)],
        ],
        "burned_calibration_seed_ranges": [
            [min(V08D_FRESH_CALIBRATION_RANGE), max(V08D_FRESH_CALIBRATION_RANGE)],
            [min(V08F_FRESH_CALIBRATION_RANGE), max(V08F_FRESH_CALIBRATION_RANGE)],
            [min(V08G_FRESH_CALIBRATION_RANGE), max(V08G_FRESH_CALIBRATION_RANGE)],
            [min(V08H_FRESH_CALIBRATION_RANGE), max(V08H_FRESH_CALIBRATION_RANGE)],
            [min(V08K_FRESH_CALIBRATION_RANGE), max(V08K_FRESH_CALIBRATION_RANGE)],
        ],
        "fresh_calibration_26500_26529_accessed": True,
        "fresh_calibration_27500_27529_accessed": True,
        "fresh_calibration_28000_28029_accessed": True,
        "fresh_calibration_28500_28529_accessed": True,
        "fresh_calibration_29000_29029_accessed": True,
        "fresh_calibration_30000_30029_accessed": False,
        "heldout_21000_21049_accessed": False,
        "fresh_heldout_24000_24049_accessed": False,
        "fresh_heldout_26000_26049_accessed": False,
        "fresh_heldout_27000_27049_accessed": False,
        "calibration_opened": False,
        "heldout_opened": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    manifest["manifest_sha256"] = _sha256_payload_excluding(manifest, "manifest_sha256")
    return manifest


def _v09_runtime_manifest_for_split(*, fresh_manifest: dict[str, Any], split: str) -> dict[str, Any]:
    if split not in {"calibration", "held_out"}:
        raise ValueError("v0_9_runtime_manifest_unknown_split")
    rows = [
        {**row, "source_split": split, "semantic_eval_split": split, "split": "held_out"}
        for row in fresh_manifest.get("scenarios", [])
        if isinstance(row, dict) and row.get("split") == split
    ]
    if not rows:
        raise ValueError(f"v0_9_runtime_manifest_missing_{split}_rows")
    seeds = [int(row["seed"]) for row in rows]
    if split == "calibration":
        if seeds != list(V09_FRESH_CALIBRATION_RANGE):
            raise ValueError("v0_9_calibration_seed_range_mismatch")
        if any(_v09_burned_seed_range_accessed(seed) for seed in seeds):
            raise ValueError("v0_9_runtime_manifest_reuses_burned_calibration_seed_range")
    if split == "held_out":
        if seeds != list(V09_FRESH_HELDOUT_RANGE):
            raise ValueError("v0_9_heldout_seed_range_mismatch")
        if any(seed in V08A_FRESH_HELDOUT_RANGE or seed in V08B_FRESH_HELDOUT_RANGE for seed in seeds):
            raise ValueError("v0_9_runtime_manifest_reuses_burned_heldout_seed_range")
    manifest = {
        "schema_version": fresh_manifest["schema_version"],
        "policy_slice": V09_POLICY_SLICE_ID,
        "slice_id": V09_SLICE_ID,
        "parent_policy_slice": V08K_POLICY_SLICE_ID,
        "scenario_profile": "v0_9",
        "runtime_split": split,
        "task_type": fresh_manifest["task_type"],
        "success_metric": fresh_manifest["success_metric"],
        "success_authority": fresh_manifest["success_authority"],
        "source_fresh_manifest_sha256": fresh_manifest["manifest_sha256"],
        "scenarios": rows,
        "burned_heldout_seed_ranges": fresh_manifest["burned_heldout_seed_ranges"],
        "burned_calibration_seed_ranges": fresh_manifest["burned_calibration_seed_ranges"],
        "heldout_21000_21049_accessed": False,
        "fresh_heldout_24000_24049_accessed": False,
        "fresh_heldout_26000_26049_accessed": False,
        "fresh_heldout_27000_27049_accessed": split == "held_out",
        "fresh_calibration_26500_26529_accessed": True,
        "fresh_calibration_27500_27529_accessed": True,
        "fresh_calibration_28000_28029_accessed": True,
        "fresh_calibration_28500_28529_accessed": True,
        "fresh_calibration_29000_29029_accessed": True,
        "fresh_calibration_30000_30029_accessed": True,
        "calibration_opened": True,
        "heldout_opened": split == "held_out",
        "proof_authority": split == "held_out",
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    manifest["manifest_sha256"] = _sha256_payload_excluding(manifest, "manifest_sha256")
    return manifest


def _load_v09_policy_artifacts(output_dir: Path) -> dict[str, dict[str, Any]]:
    child_dir = output_dir / V09_CHILD_OUTPUT_DIRNAME
    candidate_path = child_dir / "candidate_policy_artifact_v0_9.json"
    baseline_path = child_dir / "baseline_policy_artifact_v0_9.json"
    if not candidate_path.exists() or not baseline_path.exists():
        raise ValueError("missing_v0_9_policy_artifacts")
    baseline = read_json(baseline_path)
    candidate = read_json(candidate_path)
    reasons: list[str] = []
    for role, policy in (("baseline", baseline), ("candidate", candidate)):
        if policy.get("policy_slice") != V09_POLICY_SLICE_ID:
            reasons.append(f"{role}_policy_slice_mismatch")
        if policy.get("parent_policy_slice") != V08K_POLICY_SLICE_ID:
            reasons.append(f"{role}_parent_policy_slice_mismatch")
        if policy.get("fresh_calibration_30000_30029_accessed") is not False:
            reasons.append(f"{role}_fresh_calibration_accessed_before_runtime")
        if policy.get("fresh_heldout_27000_27049_accessed") is not False:
            reasons.append(f"{role}_fresh_heldout_accessed_before_closure")
        expected_hash = _sha256_payload_excluding(policy, "policy_artifact_sha256")
        if policy.get("policy_artifact_sha256") != expected_hash:
            reasons.append(f"{role}_policy_hash_mismatch")
    equality_keys = (
        "selected_action_adapter_id",
        "trainer",
        "trainer_family",
        "policy_class",
        "feature_schema",
        "feature_schema_version",
        "phase_schema",
        "action_schema",
        "base_servo_config_sha256",
        "authority_filter_config_sha256",
        "final_post_adapter_authority_config_sha256",
        "final_post_adapter_xy_authority_config_sha256",
        "shared_hysteresis_authority_config_sha256",
        "capture_conditioned_progress_authority_config_sha256",
        "horizon_reserved_capture_authority_config_sha256",
        "deadline_precedence_horizon_authority_config_sha256",
        "early_centered_z_open_safe_entry_config_sha256",
    )
    for key in equality_keys:
        if baseline.get(key) != candidate.get(key):
            reasons.append(f"peer_{key}_mismatch")
    if reasons:
        raise ValueError("v0_9_policy_peer_fairness_failed: " + ",".join(reasons))
    return {
        "baseline": {**baseline, "path": str(baseline_path)},
        "candidate": {**candidate, "path": str(candidate_path)},
    }


def _write_v09_calibration_external_rollouts(
    *,
    output_dir: Path,
    baseline_rollouts: list[dict[str, Any]],
    candidate_rollouts: list[dict[str, Any]],
) -> dict[str, str]:
    rollout_dir = output_dir / "calibration_external_rollouts"
    rollout_dir.mkdir(parents=True, exist_ok=True)
    baseline_path = rollout_dir / "baseline_calibration_rollouts_v0_9.json"
    candidate_path = rollout_dir / "candidate_calibration_rollouts_v0_9.json"
    write_json(baseline_path, baseline_rollouts)
    write_json(candidate_path, candidate_rollouts)
    return {"baseline": str(baseline_path), "candidate": str(candidate_path)}


def derive_v09_calibration_presignal_gate(
    *,
    baseline_rollouts: list[dict[str, Any]],
    candidate_rollouts: list[dict[str, Any]],
    runtime_gate: dict[str, Any],
    runtime_metadata: dict[str, Any],
    trace_paths: dict[str, list[str]],
) -> dict[str, Any]:
    gate = derive_v08d_calibration_presignal_gate(
        baseline_rollouts=baseline_rollouts,
        candidate_rollouts=candidate_rollouts,
        runtime_gate=runtime_gate,
        runtime_metadata=runtime_metadata,
        trace_paths=trace_paths,
    )
    gate.update(
        {
            "schema_version": V09_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
            "policy_slice": V09_POLICY_SLICE_ID,
            "slice_id": V09_SLICE_ID,
            "parent_policy_slice": V08K_POLICY_SLICE_ID,
            "fresh_calibration_26500_26529_accessed": True,
            "fresh_calibration_27500_27529_accessed": True,
            "fresh_calibration_28000_28029_accessed": True,
            "fresh_calibration_28500_28529_accessed": True,
            "fresh_calibration_29000_29029_accessed": True,
            "fresh_calibration_30000_30029_accessed": True,
            "fresh_heldout_24000_24049_accessed": False,
            "fresh_heldout_26000_26049_accessed": False,
            "fresh_heldout_27000_27049_accessed": False,
            "source": "v0_9_fresh_uncurated_mix_rebase_calibration_runtime",
        }
    )
    gate["calibration_presignal_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "calibration_presignal_gate_sha256",
    )
    return gate


def run_v09_fresh_uncurated_mix_rebase_runtime(
    *,
    output_dir: Path,
    device: str = DEFAULT_ISAAC_DEVICE,
    headless: bool = True,
    isaac_task: str = DEFAULT_ISAAC_TASK,
    max_steps: int = int(SUCCESS_METRIC["max_steps"]),
    action_scale: float = 1.0,
    min_rollouts_per_policy: int = MIN_PROOF_ROLLOUTS_PER_POLICY,
    bootstrap_iterations: int = 2000,
    bootstrap_seed: int = 23,
    backend: Any | None = None,
) -> dict[str, Any]:
    child_dir = output_dir / V09_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    rebase_manifest = build_v09_fresh_uncurated_mix_rebase_slice(output_dir=output_dir)
    if rebase_manifest["uncurated_mix_rebase_gate"].get("passed") is not True:
        return rebase_manifest["uncurated_mix_rebase_gate"]
    fresh_manifest = build_v09_fresh_manifest(output_dir=output_dir, rebase_manifest=rebase_manifest)
    write_json(child_dir / "v0_9_fresh_manifest.json", fresh_manifest)
    policy_artifacts = _load_v09_policy_artifacts(output_dir)
    baseline_policy = policy_artifacts["baseline"]
    candidate_policy = policy_artifacts["candidate"]
    selected_adapter_id = str(candidate_policy["selected_action_adapter_id"])
    policy_class = str(candidate_policy["policy_class"])
    trainer = str(candidate_policy["trainer"])
    use_single_app_actual_backend = (
        backend is None
        and getattr(IsaacConnectorInsertionEvaluatorBackend, "__name__", "")
        == "IsaacConnectorInsertionEvaluatorBackend"
    )
    evaluator_backend = backend or IsaacConnectorInsertionEvaluatorBackend(
        task=isaac_task,
        device=device,
        headless=headless,
        action_scale=action_scale,
        max_steps=max_steps,
    )
    actual_env = None
    actual_simulation_app = None
    actual_torch = None
    if use_single_app_actual_backend:
        from isaaclab.app import AppLauncher

        app_launcher = AppLauncher(
            {
                "headless": headless,
                "device": device,
                "enable_cameras": False,
            }
        )
        actual_simulation_app = app_launcher.app

        import gymnasium as gym
        import torch as torch_module

        import isaaclab_tasks  # noqa: F401
        from isaaclab_tasks.utils import parse_env_cfg

        env_cfg = parse_env_cfg(isaac_task, device=device, num_envs=1)
        actual_env = gym.make(isaac_task, cfg=env_cfg).unwrapped
        actual_torch = torch_module

    def run_runtime_manifest(
        *,
        manifest: dict[str, Any],
        runtime_output_dir: Path,
        rollouts_per_policy: int,
    ) -> BackendResult:
        if actual_env is not None:
            return _run_v08a_manifest_with_existing_isaac(
                evaluator_backend=evaluator_backend,
                env=actual_env,
                simulation_app=actual_simulation_app,
                torch_module=actual_torch,
                manifest=manifest,
                output_dir=runtime_output_dir,
                min_rollouts_per_policy=rollouts_per_policy,
                policy_artifacts=policy_artifacts,
            )
        return evaluator_backend.run(
            manifest=manifest,
            output_dir=runtime_output_dir,
            min_rollouts_per_policy=rollouts_per_policy,
            deterministic_profile="candidate_positive",
            policy_artifacts=policy_artifacts,
        )

    calibration_manifest = _v09_runtime_manifest_for_split(
        fresh_manifest=fresh_manifest,
        split="calibration",
    )
    write_json(child_dir / "calibration_runtime_manifest_v0_9.json", calibration_manifest)
    calibration_result = run_runtime_manifest(
        manifest=calibration_manifest,
        runtime_output_dir=child_dir / "isaac_runtime_fresh_calibration_v0_9",
        rollouts_per_policy=V07H_CALIBRATION_ROLLOUTS_PER_POLICY,
    )
    calibration_rollout_paths = _write_v09_calibration_external_rollouts(
        output_dir=child_dir,
        baseline_rollouts=list(calibration_result.baseline_rollouts),
        candidate_rollouts=list(calibration_result.candidate_rollouts),
    )
    calibration_trace_paths = {
        "baseline": list(calibration_result.baseline_trace_paths),
        "candidate": list(calibration_result.candidate_trace_paths),
    }
    calibration_gate = derive_v09_calibration_presignal_gate(
        baseline_rollouts=list(calibration_result.baseline_rollouts),
        candidate_rollouts=list(calibration_result.candidate_rollouts),
        runtime_gate=dict(calibration_result.runtime_gate),
        runtime_metadata=dict(calibration_result.runtime_metadata),
        trace_paths=calibration_trace_paths,
    )
    calibration_gate["calibration_runtime_manifest_sha256"] = calibration_manifest["manifest_sha256"]
    calibration_gate["baseline_calibration_rollout_path"] = calibration_rollout_paths["baseline"]
    calibration_gate["candidate_calibration_rollout_path"] = calibration_rollout_paths["candidate"]
    calibration_gate["calibration_presignal_gate_sha256"] = _sha256_payload_excluding(
        calibration_gate,
        "calibration_presignal_gate_sha256",
    )
    write_json(child_dir / "calibration_presignal_gate_v0_9.json", calibration_gate)
    write_json(
        output_dir / "calibration_presignal_gate.json",
        {
            "schema_version": V09_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
            "policy_slice": V09_POLICY_SLICE_ID,
            "slice_id": V09_SLICE_ID,
            "passed": calibration_gate["passed"],
            "source_gate_path": f"{V09_CHILD_OUTPUT_DIRNAME}/calibration_presignal_gate_v0_9.json",
            "calibration_opened": True,
            "heldout_opened": False,
            "heldout_21000_21049_accessed": False,
            "fresh_heldout_24000_24049_accessed": False,
            "fresh_heldout_26000_26049_accessed": False,
            "fresh_heldout_27000_27049_accessed": False,
            "fresh_calibration_26500_26529_accessed": True,
            "fresh_calibration_27500_27529_accessed": True,
            "fresh_calibration_28000_28029_accessed": True,
            "fresh_calibration_28500_28529_accessed": True,
            "fresh_calibration_29000_29029_accessed": True,
            "fresh_calibration_30000_30029_accessed": True,
            "heldout_allowed": calibration_gate["heldout_allowed"],
            "mvp2_closed": False,
            "policy_uplift_proven": False,
        },
    )
    if calibration_gate.get("passed") is not True:
        calibration_gate["mvp2_closed"] = False
        calibration_gate["policy_uplift_proven"] = False
        if actual_env is not None:
            actual_env.close()
        return calibration_gate

    selection = _v08a_calibration_selection_report(output_dir)
    training_scenario_ids = _v08a_training_scenario_ids(output_dir)
    heldout_manifest = _v09_runtime_manifest_for_split(
        fresh_manifest=fresh_manifest,
        split="held_out",
    )
    write_json(child_dir / "heldout_runtime_manifest_v0_9.json", heldout_manifest)
    heldout_leakage_guard = validate_no_heldout_leakage(
        manifest=heldout_manifest,
        training_scenario_ids=training_scenario_ids,
        curation_tuning_scenario_ids=[],
        threshold_tuning_scenario_ids=[],
        hyperparameter_scenario_ids=[],
        calibration_selector_scenario_ids=[str(item) for item in selection.get("calibration_scenario_ids", [])],
    )
    if heldout_leakage_guard["passed"] is not True:
        raise ValueError("v0_9_fresh_heldout_leakage_guard_failed")
    baseline_view = _existing_train_view(
        child_dir / "baseline_uncurated_train_v0_9.hdf5",
        view_id="baseline_uncurated_v0_9_fresh_failure_mix_rebase",
    )
    candidate_view = _existing_train_view(
        child_dir / "candidate_curated_train_v0_9.hdf5",
        view_id="candidate_curated_v0_9_fresh_uncurated_mix_rebase",
    )
    bridge_dir = _write_learning_harness_bridge(
        output_dir=child_dir,
        manifest=heldout_manifest,
        baseline_view=baseline_view,
        candidate_view=candidate_view,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    heldout_rollouts_per_policy = max(
        int(min_rollouts_per_policy),
        STRONGER_PUBLIC_ROLLOUTS_PER_POLICY,
        len(V09_FRESH_HELDOUT_RANGE),
    )
    heldout_result = run_runtime_manifest(
        manifest=heldout_manifest,
        runtime_output_dir=child_dir / "isaac_runtime_fresh_heldout_v0_9",
        rollouts_per_policy=heldout_rollouts_per_policy,
    )
    runtime_gate = dict(heldout_result.runtime_gate)
    actual_rollouts_per_policy = min(
        len(heldout_result.baseline_rollouts),
        len(heldout_result.candidate_rollouts),
    )
    runtime_gate["actual_baseline_rollouts"] = len(heldout_result.baseline_rollouts)
    runtime_gate["actual_candidate_rollouts"] = len(heldout_result.candidate_rollouts)
    runtime_gate["actual_rollouts_per_policy"] = actual_rollouts_per_policy
    combined_rollouts = list(heldout_result.baseline_rollouts) + list(heldout_result.candidate_rollouts)
    if any(_v09_burned_seed_range_accessed(int(rollout.get("seed", -1))) for rollout in combined_rollouts):
        raise ValueError("v0_9_burned_seed_accessed")
    heldout_suite = _heldout_suite(heldout_manifest)
    baseline_rollouts_path = _write_external_rollout_json(
        output_dir=child_dir,
        role="baseline",
        policy_artifact=baseline_policy,
        train_view=baseline_view,
        heldout_suite=heldout_suite,
        backend_result=heldout_result,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    candidate_rollouts_path = _write_external_rollout_json(
        output_dir=child_dir,
        role="candidate",
        policy_artifact=candidate_policy,
        train_view=candidate_view,
        heldout_suite=heldout_suite,
        backend_result=heldout_result,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    learning_report = _run_learning_validator(
        output_dir=child_dir,
        bridge_dir=bridge_dir,
        baseline_rollouts_path=baseline_rollouts_path,
        candidate_rollouts_path=candidate_rollouts_path,
        min_rollouts_per_policy=MIN_PROOF_ROLLOUTS_PER_POLICY,
        bootstrap_iterations=bootstrap_iterations,
        bootstrap_seed=bootstrap_seed,
        policy_class=policy_class,
        trainer=trainer,
    )
    train_generation_runtime_gate, train_gate_sha256 = load_v07a2_parent_train_generation_gate(output_dir)
    closure = derive_mvp2c_closure(
        learning_report=learning_report,
        runtime_gate=runtime_gate,
        train_generation_runtime_gate=train_generation_runtime_gate,
        calibration_selection_report=selection,
        heldout_leakage_guard=heldout_leakage_guard,
        actual_rollouts_per_policy=actual_rollouts_per_policy,
    )
    confidence_interval_report = _bootstrap_uplift_ci(
        baseline_rollouts=list(heldout_result.baseline_rollouts),
        candidate_rollouts=list(heldout_result.candidate_rollouts),
        iterations=bootstrap_iterations,
        seed=bootstrap_seed,
    )
    gate = {
        "schema_version": V09_HELDOUT_CLOSURE_SCHEMA_VERSION,
        "policy_slice": V09_POLICY_SLICE_ID,
        "slice_id": V09_SLICE_ID,
        "parent_policy_slice": V08K_POLICY_SLICE_ID,
        "source_fresh_manifest_sha256": fresh_manifest["manifest_sha256"],
        "uncurated_mix_config_sha256": rebase_manifest["uncurated_mix_config"][
            "uncurated_mix_config_sha256"
        ],
        "uncurated_mix_rebase_gate_sha256": rebase_manifest["uncurated_mix_rebase_gate"][
            "uncurated_mix_rebase_gate_sha256"
        ],
        "parent_train_generation_runtime_gate_sha256": train_gate_sha256,
        "fresh_calibration_presignal_gate_sha256": calibration_gate["calibration_presignal_gate_sha256"],
        "runtime_backend": heldout_result.runtime_backend,
        "proof_runtime": heldout_result.proof_runtime,
        "runtime_gate": runtime_gate,
        "actual_rollouts_per_policy": actual_rollouts_per_policy,
        "baseline_success_rate": learning_report.get("baseline_success_rate"),
        "candidate_success_rate": learning_report.get("candidate_success_rate"),
        "curated_vs_uncurated_uplift": learning_report.get("curated_vs_uncurated_uplift"),
        "learning_report_path": str(
            child_dir / "mvp2_learning_proven_policy_eval" / "mvp2_learning_proven_report.json"
        ),
        "baseline_external_rollouts": str(baseline_rollouts_path),
        "candidate_external_rollouts": str(candidate_rollouts_path),
        "confidence_interval_report": confidence_interval_report,
        "stronger_public_evidence_target_passed": _derive_public_evidence_target(
            actual_rollouts_per_policy=actual_rollouts_per_policy,
            confidence_interval_report=confidence_interval_report,
        ),
        "calibration_opened": True,
        "heldout_opened": True,
        "heldout_21000_21049_accessed": False,
        "fresh_heldout_24000_24049_accessed": False,
        "fresh_heldout_26000_26049_accessed": False,
        "fresh_heldout_27000_27049_accessed": True,
        "fresh_calibration_26500_26529_accessed": True,
        "fresh_calibration_27500_27529_accessed": True,
        "fresh_calibration_28000_28029_accessed": True,
        "fresh_calibration_28500_28529_accessed": True,
        "fresh_calibration_29000_29029_accessed": True,
        "fresh_calibration_30000_30029_accessed": True,
        "same_heldout_reuse_allowed_for_closure": False,
        "heldout_leakage_guard": heldout_leakage_guard,
        "calibration_selection_report_sha256": _sha256_file(output_dir / "calibration_selection_report.json"),
        "selected_action_adapter_id": selected_adapter_id,
        "same_adapter_used_for_baseline_and_candidate": True,
        "same_policy_class": baseline_policy.get("policy_class") == candidate_policy.get("policy_class"),
        "same_trainer": baseline_policy.get("trainer") == candidate_policy.get("trainer"),
        "same_feature_schema": baseline_policy.get("feature_schema") == candidate_policy.get("feature_schema"),
        "mvp2_closed": closure["mvp2_closed"],
        "mvp2c_close_minimum_passed": closure["mvp2c_close_minimum_passed"],
        "policy_uplift_proven": closure["learning_proven"],
        "proof_eligible": closure["proof_eligible"],
        "blockers": closure["blockers"] + list(learning_report.get("blockers") or []),
        "non_claims": {
            "deployable_real_robot_policy": False,
            "visual_policy_performance": False,
            "real_robot_success": False,
            "physical_robot_readiness": False,
            "universal_robot_support": False,
            "hmd_openxr_readiness": False,
        },
    }
    gate["heldout_closure_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "heldout_closure_gate_sha256",
    )
    write_json(child_dir / "heldout_closure_gate_v0_9.json", gate)
    write_json(output_dir / "heldout_closure_gate.json", gate)
    if actual_env is not None:
        actual_env.close()
    return gate


def _load_required_failed_v09_heldout_closure_gate(output_dir: Path) -> tuple[dict[str, Any], Path, str]:
    gate_path = output_dir / V09_CHILD_OUTPUT_DIRNAME / "heldout_closure_gate_v0_9.json"
    if not gate_path.exists():
        raise ValueError("missing_v0_9_heldout_closure_gate")
    gate = read_json(gate_path)
    uplift = gate.get("curated_vs_uncurated_uplift")
    if gate.get("schema_version") != V09_HELDOUT_CLOSURE_SCHEMA_VERSION:
        raise ValueError("invalid_v0_9_heldout_closure_gate_schema")
    if gate.get("policy_slice") != V09_POLICY_SLICE_ID:
        raise ValueError("invalid_v0_9_heldout_closure_gate_policy_slice")
    if gate.get("heldout_opened") is not True:
        raise ValueError("v0_9_heldout_gate_not_opened")
    if gate.get("fresh_heldout_27000_27049_accessed") is not True:
        raise ValueError("v0_9_fresh_heldout_27000_27049_not_accessed")
    if int(gate.get("actual_rollouts_per_policy", 0)) < STRONGER_PUBLIC_ROLLOUTS_PER_POLICY:
        raise ValueError("v0_9_heldout_gate_insufficient_rollouts")
    if gate.get("mvp2_closed") is not False:
        raise ValueError("v0_9_heldout_gate_not_failed_closed")
    if gate.get("policy_uplift_proven") is not False:
        raise ValueError("v0_9_heldout_gate_policy_uplift_not_failed")
    if not isinstance(uplift, (int, float)) or isinstance(uplift, bool):
        raise ValueError("v0_9_heldout_gate_uplift_missing")
    if float(uplift) >= V09A_REQUIRED_MINIMUM_UPLIFT:
        raise ValueError("v0_9_heldout_gate_not_shortfall")
    return gate, gate_path, _sha256_file(gate_path)


def _v09a_resolve_artifact_path(output_dir: Path, raw_path: Any) -> Path:
    path = Path(str(raw_path))
    candidates = [path]
    if not path.is_absolute():
        candidates.append(output_dir / path)
        candidates.append(output_dir / V09_CHILD_OUTPUT_DIRNAME / path)
    for candidate in candidates:
        if candidate.exists():
            return candidate
    raise ValueError(f"missing_v0_9a_artifact_path:{raw_path}")


def _load_v09a_rollout_payload(output_dir: Path, raw_path: Any, *, role: str) -> tuple[dict[str, Any], Path, str]:
    path = _v09a_resolve_artifact_path(output_dir, raw_path)
    payload = read_json(path)
    if payload.get("schema_version") != ROLLOUT_SCHEMA_VERSION:
        raise ValueError(f"invalid_v0_9a_{role}_rollout_schema")
    if payload.get("policy_role") not in {None, role}:
        raise ValueError(f"invalid_v0_9a_{role}_rollout_role")
    rollouts = payload.get("rollout_results")
    if not isinstance(rollouts, list) or not rollouts:
        raise ValueError(f"missing_v0_9a_{role}_rollout_results")
    return payload, path, _sha256_file(path)


def _v09a_rollout_seed(rollout: dict[str, Any]) -> int | None:
    seed = rollout.get("seed")
    if isinstance(seed, int) and not isinstance(seed, bool):
        return seed
    scenario_id = str(rollout.get("scenario_id") or "")
    match = re.search(r"(\d+)$", scenario_id)
    if match:
        return int(match.group(1))
    return None


def _v09a_rollout_succeeded(rollout: dict[str, Any]) -> bool:
    if isinstance(rollout.get("success"), bool):
        return bool(rollout["success"])
    if isinstance(rollout.get("env_native_rollout_success"), bool):
        return bool(rollout["env_native_rollout_success"])
    return False


def _v09a_rollouts_by_scenario(rollouts: list[dict[str, Any]], *, role: str) -> dict[str, dict[str, Any]]:
    indexed: dict[str, dict[str, Any]] = {}
    for rollout in rollouts:
        scenario_id = str(rollout.get("scenario_id") or "")
        if not scenario_id:
            raise ValueError(f"v0_9a_{role}_rollout_missing_scenario_id")
        if scenario_id in indexed:
            raise ValueError(f"v0_9a_{role}_duplicate_scenario_id:{scenario_id}")
        indexed[scenario_id] = rollout
    return indexed


def _v09a_trace_action_z(row: dict[str, Any]) -> float:
    action = row.get("normalized_action")
    if isinstance(action, list) and len(action) >= 3:
        try:
            return float(action[2])
        except (TypeError, ValueError):
            return 0.0
    diagnostics = row.get("controller_action_diagnostics")
    if isinstance(diagnostics, dict):
        post_adapter = diagnostics.get("post_adapter_action_vector")
        if isinstance(post_adapter, list) and len(post_adapter) >= 3:
            try:
                return float(post_adapter[2])
            except (TypeError, ValueError):
                return 0.0
    post_adapter = row.get("post_adapter_action_vector")
    if isinstance(post_adapter, list) and len(post_adapter) >= 3:
        try:
            return float(post_adapter[2])
        except (TypeError, ValueError):
            return 0.0
    return 0.0


def _v09a_longest_true_run(values: list[bool]) -> int:
    longest = 0
    current = 0
    for value in values:
        if value:
            current += 1
            longest = max(longest, current)
        else:
            current = 0
    return longest


def _summarize_v09a_trace(output_dir: Path, rollout: dict[str, Any]) -> dict[str, Any]:
    raw_ref = rollout.get("rollout_log_ref")
    if not raw_ref:
        return {"trace_summary_available": False, "missing_reason": "rollout_log_ref_missing"}
    try:
        path = _v09a_resolve_artifact_path(output_dir, raw_ref)
    except ValueError:
        return {
            "trace_summary_available": False,
            "missing_reason": "rollout_log_ref_unresolved",
            "rollout_log_ref": str(raw_ref),
        }
    payload = read_json(path)
    trace = [row for row in payload.get("trace", []) if isinstance(row, dict)]
    if not trace:
        return {
            "trace_summary_available": False,
            "missing_reason": "trace_rows_missing",
            "trace_path": str(path),
            "trace_sha256": _sha256_file(path),
        }
    depths = [float(row.get("insertion_depth_m", 0.0) or 0.0) for row in trace]
    laterals = [float(row.get("lateral_error_m", 0.0) or 0.0) for row in trace]
    z_values = [_v09a_trace_action_z(row) for row in trace]
    masks = [bool(row.get("env_native_success_mask", row.get("env_native_success", False))) for row in trace]
    summary = payload.get("summary") if isinstance(payload.get("summary"), dict) else {}
    max_consecutive = summary.get("env_native_max_consecutive_success_steps")
    if not isinstance(max_consecutive, int) or isinstance(max_consecutive, bool):
        max_consecutive = _v09a_longest_true_run(masks)
    max_depth = max(depths)
    min_lateral = min(laterals)
    if max_depth < 0.0245:
        failure_mode = "under_depth_or_seat_window_shortfall"
    elif int(max_consecutive) < 10:
        failure_mode = "env_native_stability_window_shortfall"
    elif min_lateral > 0.002:
        failure_mode = "lateral_alignment_shortfall"
    else:
        failure_mode = "unclassified"
    return {
        "trace_summary_available": True,
        "trace_path": str(path),
        "trace_sha256": _sha256_file(path),
        "max_insertion_depth_m": round(max_depth, 9),
        "min_lateral_error_m": round(min_lateral, 9),
        "final_insertion_depth_m": round(depths[-1], 9),
        "final_lateral_error_m": round(laterals[-1], 9),
        "z_nonzero_steps": sum(1 for value in z_values if abs(value) > 1e-9),
        "env_native_max_consecutive_success_steps": int(max_consecutive),
        "failure_mode": failure_mode,
    }


def _v09a_seed_list(rollouts: list[dict[str, Any]]) -> list[int]:
    seeds = [_v09a_rollout_seed(rollout) for rollout in rollouts]
    return sorted(seed for seed in seeds if seed is not None)


def build_v09a_heldout_uplift_shortfall_diagnosis(*, output_dir: Path) -> dict[str, Any]:
    gate, gate_path, gate_sha = _load_required_failed_v09_heldout_closure_gate(output_dir)
    baseline_payload, baseline_path, baseline_sha = _load_v09a_rollout_payload(
        output_dir,
        gate.get("baseline_external_rollouts"),
        role="baseline",
    )
    candidate_payload, candidate_path, candidate_sha = _load_v09a_rollout_payload(
        output_dir,
        gate.get("candidate_external_rollouts"),
        role="candidate",
    )
    baseline_rollouts = [row for row in baseline_payload["rollout_results"] if isinstance(row, dict)]
    candidate_rollouts = [row for row in candidate_payload["rollout_results"] if isinstance(row, dict)]
    baseline_by_scenario = _v09a_rollouts_by_scenario(baseline_rollouts, role="baseline")
    candidate_by_scenario = _v09a_rollouts_by_scenario(candidate_rollouts, role="candidate")
    scenario_ids = sorted(set(baseline_by_scenario) & set(candidate_by_scenario))
    if len(scenario_ids) != int(gate.get("actual_rollouts_per_policy", 0)):
        raise ValueError("v0_9a_rollout_pair_count_mismatch")
    paired_counts = {"B1_C1": 0, "B1_C0": 0, "B0_C1": 0, "B0_C0": 0}
    baseline_failures: list[dict[str, Any]] = []
    candidate_failures: list[dict[str, Any]] = []
    recovered: list[int] = []
    common_failures: list[int] = []
    degraded: list[int] = []
    common_failure_trace_summaries: dict[str, dict[str, Any]] = {}
    baseline_failure_trace_summaries: dict[str, dict[str, Any]] = {}
    for scenario_id in scenario_ids:
        baseline_rollout = baseline_by_scenario[scenario_id]
        candidate_rollout = candidate_by_scenario[scenario_id]
        baseline_success = _v09a_rollout_succeeded(baseline_rollout)
        candidate_success = _v09a_rollout_succeeded(candidate_rollout)
        key = f"B{int(baseline_success)}_C{int(candidate_success)}"
        paired_counts[key] += 1
        seed = _v09a_rollout_seed(baseline_rollout) or _v09a_rollout_seed(candidate_rollout)
        if not baseline_success:
            baseline_failures.append(baseline_rollout)
            if seed is not None:
                baseline_failure_trace_summaries[str(seed)] = _summarize_v09a_trace(output_dir, baseline_rollout)
        if not candidate_success:
            candidate_failures.append(candidate_rollout)
        if not baseline_success and candidate_success and seed is not None:
            recovered.append(seed)
        if baseline_success and not candidate_success and seed is not None:
            degraded.append(seed)
        if not baseline_success and not candidate_success and seed is not None:
            common_failures.append(seed)
            common_failure_trace_summaries[str(seed)] = {
                "baseline": _summarize_v09a_trace(output_dir, baseline_rollout),
                "candidate": _summarize_v09a_trace(output_dir, candidate_rollout),
            }
    baseline_rate = float(gate["baseline_success_rate"])
    candidate_rate = float(gate["candidate_success_rate"])
    uplift = float(gate["curated_vs_uncurated_uplift"])
    max_possible_uplift = round(1.0 - baseline_rate, 12)
    report = {
        "schema_version": V09A_DIAGNOSIS_SCHEMA_VERSION,
        "policy_slice": V09A_POLICY_SLICE_ID,
        "slice_id": V09A_SLICE_ID,
        "source_policy_slice": V09_POLICY_SLICE_ID,
        "source_slice_id": V09_SLICE_ID,
        "source_heldout_closure_gate_path": str(gate_path),
        "source_heldout_closure_gate_sha256": gate_sha,
        "baseline_external_rollouts": str(baseline_path),
        "baseline_external_rollouts_sha256": baseline_sha,
        "candidate_external_rollouts": str(candidate_path),
        "candidate_external_rollouts_sha256": candidate_sha,
        "runtime_backend": "offline_artifact_diagnosis",
        "proof_runtime": V09A_SLICE_ID,
        "actual_rollouts_per_policy": int(gate["actual_rollouts_per_policy"]),
        "baseline_success_rate": baseline_rate,
        "candidate_success_rate": candidate_rate,
        "curated_vs_uncurated_uplift": uplift,
        "required_minimum_uplift": V09A_REQUIRED_MINIMUM_UPLIFT,
        "max_possible_uplift_on_opened_heldout": max_possible_uplift,
        "opened_heldout_can_no_longer_close_minimum": (
            max_possible_uplift < V09A_REQUIRED_MINIMUM_UPLIFT
        ),
        "paired_outcome_counts": paired_counts,
        "baseline_failure_seeds": _v09a_seed_list(baseline_failures),
        "candidate_failure_seeds": _v09a_seed_list(candidate_failures),
        "candidate_recovered_baseline_failure_seeds": sorted(recovered),
        "candidate_degraded_baseline_success_seeds": sorted(degraded),
        "common_failure_seeds": sorted(common_failures),
        "baseline_ceiling_compression": baseline_rate >= 0.85,
        "candidate_non_regression": paired_counts["B1_C0"] == 0,
        "failure_mix_did_not_create_sufficient_uncurated_heldout_gap": (
            baseline_rate > 1.0 - V09A_REQUIRED_MINIMUM_UPLIFT
        ),
        "baseline_failure_trace_summaries": baseline_failure_trace_summaries,
        "common_failure_trace_summaries": common_failure_trace_summaries,
        "heldout_opened": True,
        "fresh_heldout_27000_27049_accessed": True,
        "same_heldout_reuse_allowed_for_closure": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "recommended_downstream_slice": V09A_RECOMMENDED_DOWNSTREAM_SLICE,
        "recommended_next_valid_step": (
            "Pre-register a fresh v0.10 comparator-stress proof slice with a new "
            "sealed held-out range; do not reuse 27000-27049 for closure."
        ),
        "blockers": [
            "Opened v0.9 held-out baseline success rate is too high for +0.20 uplift closure.",
            "Even a perfect candidate on opened v0.9 held-out could only reach "
            f"{max_possible_uplift:.2f} uplift.",
        ],
        "non_claims": {
            "mvp2_closed": False,
            "policy_uplift_proven": False,
            "deployable_real_robot_policy": False,
            "visual_policy_performance": False,
            "real_robot_success": False,
            "physical_robot_readiness": False,
            "universal_robot_support": False,
            "hmd_openxr_readiness": False,
        },
    }
    report["v0_9a_heldout_uplift_shortfall_diagnosis_sha256"] = _sha256_payload_excluding(
        report,
        "v0_9a_heldout_uplift_shortfall_diagnosis_sha256",
    )
    child_dir = output_dir / V09A_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    write_json(child_dir / "v0_9a_heldout_uplift_shortfall_diagnosis_report.json", report)
    return report


def load_required_v09a_heldout_uplift_shortfall_diagnosis(output_dir: Path) -> tuple[dict[str, Any], str]:
    path = (
        output_dir
        / V09A_CHILD_OUTPUT_DIRNAME
        / "v0_9a_heldout_uplift_shortfall_diagnosis_report.json"
    )
    if not path.exists():
        raise ValueError("missing_v0_9a_heldout_uplift_shortfall_diagnosis")
    report = read_json(path)
    if report.get("schema_version") != V09A_DIAGNOSIS_SCHEMA_VERSION:
        raise ValueError("invalid_v0_9a_shortfall_diagnosis_schema")
    if report.get("policy_slice") != V09A_POLICY_SLICE_ID:
        raise ValueError("invalid_v0_9a_shortfall_diagnosis_policy_slice")
    if report.get("source_policy_slice") != V09_POLICY_SLICE_ID:
        raise ValueError("invalid_v0_9a_shortfall_source_policy_slice")
    if report.get("opened_heldout_can_no_longer_close_minimum") is not True:
        raise ValueError("v0_9a_shortfall_diagnosis_not_binding")
    if report.get("recommended_downstream_slice") != V09A_RECOMMENDED_DOWNSTREAM_SLICE:
        raise ValueError("v0_9a_downstream_recommendation_mismatch")
    if report.get("mvp2_closed") is not False or report.get("policy_uplift_proven") is not False:
        raise ValueError("v0_9a_shortfall_diagnosis_not_failed_closed")
    return report, _sha256_file(path)


V10A_POLICY_AUTHORITY_HASH_KEYS = (
    "selected_action_adapter_config_sha256",
    "parent_selected_action_adapter_config_sha256",
    "shared_hysteresis_authority_config_sha256",
    "parent_shared_hysteresis_authority_config_sha256",
    "final_post_adapter_authority_config_sha256",
    "final_post_adapter_xy_authority_config_sha256",
    "capture_conditioned_progress_authority_config_sha256",
    "horizon_reserved_capture_authority_config_sha256",
    "deadline_precedence_horizon_authority_config_sha256",
    "early_centered_z_open_safe_entry_config_sha256",
)


def _v10a_resolve_artifact_path(output_dir: Path, raw_path: Any) -> Path:
    path = Path(str(raw_path))
    candidates = [path]
    if not path.is_absolute():
        candidates.extend(
            [
                Path.cwd() / path,
                output_dir / path,
                output_dir / V10_CHILD_OUTPUT_DIRNAME / path,
                output_dir / V09_CHILD_OUTPUT_DIRNAME / path,
            ]
        )
    for candidate in candidates:
        if candidate.exists():
            return candidate
    raise ValueError(f"missing_v0_10a_artifact_path:{raw_path}")


def _v10a_load_rollouts(path: Path) -> list[dict[str, Any]]:
    payload = json.loads(path.read_text(encoding="utf-8"))
    if isinstance(payload, list):
        rollouts = payload
    elif isinstance(payload, dict):
        rollouts = payload.get("rollout_results")
    else:
        rollouts = None
    if not isinstance(rollouts, list):
        raise ValueError(f"invalid_v0_10a_rollout_payload:{path}")
    return [row for row in rollouts if isinstance(row, dict)]


def _v10a_rollout_success_count(rollouts: list[dict[str, Any]]) -> int:
    count = 0
    for rollout in rollouts:
        if bool(rollout.get("success", rollout.get("env_native_rollout_success", False))):
            count += 1
    return count


def _v10a_policy_vectors_equal(left: dict[str, Any], right: dict[str, Any]) -> bool:
    return left.get("weights") == right.get("weights") and left.get("bias") == right.get("bias")


def _v10a_policy_authority_hashes(policy: dict[str, Any]) -> dict[str, Any]:
    return {key: policy.get(key) for key in V10A_POLICY_AUTHORITY_HASH_KEYS if key in policy}


def _v10a_shared_authority_hashes_unchanged(
    *,
    parent_policy: dict[str, Any],
    child_policy: dict[str, Any],
) -> bool:
    for key in (
        "selected_action_adapter_config_sha256",
        "shared_hysteresis_authority_config_sha256",
        "final_post_adapter_authority_config_sha256",
        "final_post_adapter_xy_authority_config_sha256",
        "capture_conditioned_progress_authority_config_sha256",
        "horizon_reserved_capture_authority_config_sha256",
        "deadline_precedence_horizon_authority_config_sha256",
        "early_centered_z_open_safe_entry_config_sha256",
    ):
        if parent_policy.get(key) != child_policy.get(key):
            return False
    return True


def _v10a_trace_paths_from_rollouts(
    *,
    output_dir: Path,
    rollouts: list[dict[str, Any]],
) -> list[Path]:
    paths: list[Path] = []
    for rollout in rollouts:
        raw_ref = rollout.get("rollout_log_ref")
        if not raw_ref:
            continue
        paths.append(_v10a_resolve_artifact_path(output_dir, raw_ref))
    return paths


def _v10a_summarize_authority_diagnostics(trace_paths: list[Path]) -> dict[str, Any]:
    summary = {
        "trace_count": len(trace_paths),
        "row_count": 0,
        "policy_slices_observed": [],
        "diagnostic_absent_count": 0,
        "no_v06_controller_count": 0,
        "shared_hysteresis_authority_count": 0,
        "final_post_adapter_authority_count": 0,
        "final_post_adapter_xy_authority_count": 0,
        "safe_entry_authority_count": 0,
        "no_mutation_after_final_post_adapter_authority_count": 0,
        "z_motion_block_reasons": {},
    }
    policy_slices: set[str] = set()
    reasons: dict[str, int] = {}
    for trace_path in trace_paths:
        payload = read_json(trace_path)
        rows = payload.get("trace") if isinstance(payload, dict) else None
        if not isinstance(rows, list):
            continue
        for row in rows:
            if not isinstance(row, dict):
                continue
            summary["row_count"] += 1
            diagnostics = row.get("controller_action_diagnostics")
            if not isinstance(diagnostics, dict):
                summary["diagnostic_absent_count"] += 1
                continue
            policy_slice = diagnostics.get("policy_slice")
            if policy_slice:
                policy_slices.add(str(policy_slice))
            reason = diagnostics.get("z_motion_block_reason")
            if reason:
                reasons[str(reason)] = reasons.get(str(reason), 0) + 1
            if diagnostics.get("z_motion_block_reason") == "no_v06_controller":
                summary["no_v06_controller_count"] += 1
            if diagnostics.get("shared_hysteresis_authority_id"):
                summary["shared_hysteresis_authority_count"] += 1
            if diagnostics.get("final_post_adapter_authority_id"):
                summary["final_post_adapter_authority_count"] += 1
            if diagnostics.get("final_post_adapter_xy_authority_id"):
                summary["final_post_adapter_xy_authority_count"] += 1
            if "early_centered_z_open_safe_entry_applied" in diagnostics:
                summary["safe_entry_authority_count"] += 1
            if diagnostics.get("no_mutation_after_final_post_adapter_authority") is True:
                summary["no_mutation_after_final_post_adapter_authority_count"] += 1
    summary["policy_slices_observed"] = sorted(policy_slices)
    summary["z_motion_block_reasons"] = dict(sorted(reasons.items()))
    return summary


def _v10a_load_required_failed_calibration_gate(output_dir: Path) -> tuple[dict[str, Any], Path, str]:
    gate_path = output_dir / V10_CHILD_OUTPUT_DIRNAME / "calibration_presignal_gate_v0_10.json"
    if not gate_path.exists():
        raise ValueError("missing_v0_10_calibration_presignal_gate")
    gate = read_json(gate_path)
    if gate.get("schema_version") != V10_CALIBRATION_PRESIGNAL_SCHEMA_VERSION:
        raise ValueError("invalid_v0_10_calibration_presignal_schema")
    if gate.get("policy_slice") != V10_POLICY_SLICE_ID:
        raise ValueError("invalid_v0_10_calibration_policy_slice")
    if gate.get("runtime_backend") != "isaac_runtime":
        raise ValueError("v0_10_calibration_not_actual_isaac_runtime")
    if gate.get("passed") is not False:
        raise ValueError("v0_10_calibration_gate_not_failed")
    if gate.get("heldout_opened") is True:
        raise ValueError("v0_10_heldout_already_opened")
    if gate.get("fresh_heldout_32000_32049_accessed") is True:
        raise ValueError("v0_10_fresh_heldout_32000_32049_already_accessed")
    return gate, gate_path, _sha256_file(gate_path)


def build_v10a_calibration_collapse_diagnosis(*, output_dir: Path) -> dict[str, Any]:
    gate, gate_path, gate_sha = _v10a_load_required_failed_calibration_gate(output_dir)
    v09_child = output_dir / V09_CHILD_OUTPUT_DIRNAME
    v10_child = output_dir / V10_CHILD_OUTPUT_DIRNAME
    v09_candidate_path = v09_child / "candidate_policy_artifact_v0_9.json"
    v10_candidate_path = v10_child / "candidate_policy_artifact_v0_10.json"
    v10_baseline_path = v10_child / "baseline_policy_artifact_v0_10.json"
    for path in (v09_candidate_path, v10_candidate_path, v10_baseline_path):
        if not path.exists():
            raise ValueError(f"missing_v0_10a_policy_artifact:{path.name}")
    v09_candidate_policy = read_json(v09_candidate_path)
    v10_candidate_policy = read_json(v10_candidate_path)
    v10_baseline_policy = read_json(v10_baseline_path)
    if v09_candidate_policy.get("policy_slice") != V09_POLICY_SLICE_ID:
        raise ValueError("invalid_v0_10a_v09_candidate_policy_slice")
    if v10_candidate_policy.get("policy_slice") != V10_POLICY_SLICE_ID:
        raise ValueError("invalid_v0_10a_v10_candidate_policy_slice")
    if v10_baseline_policy.get("policy_slice") != V10_POLICY_SLICE_ID:
        raise ValueError("invalid_v0_10a_v10_baseline_policy_slice")

    candidate_rollout_path = _v10a_resolve_artifact_path(
        output_dir,
        gate.get("candidate_calibration_rollout_path")
        or v10_child / "calibration_external_rollouts" / "candidate_calibration_rollouts_v0_10.json",
    )
    baseline_rollout_path = _v10a_resolve_artifact_path(
        output_dir,
        gate.get("baseline_calibration_rollout_path")
        or v10_child / "calibration_external_rollouts" / "baseline_calibration_rollouts_v0_10.json",
    )
    v09_candidate_rollout_path = _v10a_resolve_artifact_path(
        output_dir,
        v09_child / "calibration_external_rollouts" / "candidate_calibration_rollouts_v0_9.json",
    )
    v10_candidate_rollouts = _v10a_load_rollouts(candidate_rollout_path)
    v10_baseline_rollouts = _v10a_load_rollouts(baseline_rollout_path)
    v09_candidate_rollouts = _v10a_load_rollouts(v09_candidate_rollout_path)
    v10_candidate_trace_paths = _v10a_trace_paths_from_rollouts(
        output_dir=output_dir,
        rollouts=v10_candidate_rollouts,
    )
    v09_candidate_trace_paths = _v10a_trace_paths_from_rollouts(
        output_dir=output_dir,
        rollouts=v09_candidate_rollouts,
    )
    v10_diagnostics = _v10a_summarize_authority_diagnostics(v10_candidate_trace_paths)
    v09_diagnostics = _v10a_summarize_authority_diagnostics(v09_candidate_trace_paths)
    weights_unchanged = _v10a_policy_vectors_equal(v09_candidate_policy, v10_candidate_policy)
    authority_hashes_unchanged = _v10a_shared_authority_hashes_unchanged(
        parent_policy=v09_candidate_policy,
        child_policy=v10_candidate_policy,
    )
    lineage_missing = (
        weights_unchanged
        and authority_hashes_unchanged
        and v10_diagnostics["row_count"] > 0
        and v10_diagnostics["shared_hysteresis_authority_count"] == 0
        and v10_diagnostics["final_post_adapter_authority_count"] == 0
        and v10_diagnostics["final_post_adapter_xy_authority_count"] == 0
        and v10_diagnostics["no_v06_controller_count"] > 0
        and v09_diagnostics["shared_hysteresis_authority_count"] > 0
        and v09_diagnostics["final_post_adapter_authority_count"] > 0
        and v09_diagnostics["final_post_adapter_xy_authority_count"] > 0
    )
    root_cause = (
        "RUNTIME_POLICY_SLICE_AUTHORITY_LINEAGE_MISSING"
        if lineage_missing
        else "UNCLASSIFIED_V0_10_CALIBRATION_COLLAPSE"
    )
    recommended_downstream_slice = V10A_RECOMMENDED_DOWNSTREAM_SLICE if lineage_missing else None
    report = {
        "schema_version": V10A_DIAGNOSIS_SCHEMA_VERSION,
        "policy_slice": V10A_POLICY_SLICE_ID,
        "slice_id": V10A_SLICE_ID,
        "source_policy_slice": V10_POLICY_SLICE_ID,
        "source_slice_id": V10_SLICE_ID,
        "parent_policy_slice": V09_POLICY_SLICE_ID,
        "source_calibration_presignal_gate_path": str(gate_path),
        "source_calibration_presignal_gate_sha256": gate_sha,
        "v09_candidate_policy_artifact": str(v09_candidate_path),
        "v09_candidate_policy_artifact_sha256": _sha256_file(v09_candidate_path),
        "v10_candidate_policy_artifact": str(v10_candidate_path),
        "v10_candidate_policy_artifact_sha256": _sha256_file(v10_candidate_path),
        "v10_baseline_policy_artifact": str(v10_baseline_path),
        "v10_baseline_policy_artifact_sha256": _sha256_file(v10_baseline_path),
        "v10_candidate_calibration_rollouts": str(candidate_rollout_path),
        "v10_candidate_calibration_rollouts_sha256": _sha256_file(candidate_rollout_path),
        "v10_baseline_calibration_rollouts": str(baseline_rollout_path),
        "v10_baseline_calibration_rollouts_sha256": _sha256_file(baseline_rollout_path),
        "v09_candidate_calibration_rollouts": str(v09_candidate_rollout_path),
        "v09_candidate_calibration_rollouts_sha256": _sha256_file(v09_candidate_rollout_path),
        "runtime_backend": "offline_artifact_diagnosis",
        "proof_runtime": V10A_SLICE_ID,
        "v0_10_calibration_success": {
            "baseline": _v10a_rollout_success_count(v10_baseline_rollouts),
            "candidate": _v10a_rollout_success_count(v10_candidate_rollouts),
            "total": len(v10_candidate_rollouts),
        },
        "v0_9_candidate_calibration_success": {
            "candidate": _v10a_rollout_success_count(v09_candidate_rollouts),
            "total": len(v09_candidate_rollouts),
        },
        "candidate_weights_unchanged_from_v09": weights_unchanged,
        "candidate_authority_hashes_unchanged_from_v09": authority_hashes_unchanged,
        "v0_9_candidate_authority_hashes": _v10a_policy_authority_hashes(v09_candidate_policy),
        "v0_10_candidate_authority_hashes": _v10a_policy_authority_hashes(v10_candidate_policy),
        "v0_10_authority_diagnostics": v10_diagnostics,
        "v0_9_authority_diagnostics": v09_diagnostics,
        "primary_root_cause_class": root_cause,
        "recommended_downstream_slice": recommended_downstream_slice,
        "recommended_next_valid_step": (
            "Add v0_10 to the evaluator runtime derived-policy authority lineage allowlist, "
            "then rerun the actual v0.10 fresh comparator stress runtime."
            if lineage_missing
            else "Inspect v0.10 calibration traces for a non-lineage runtime regression before "
            "opening held-out 32000-32049."
        ),
        "calibration_opened": True,
        "heldout_opened": False,
        "fresh_calibration_31000_31029_accessed": True,
        "fresh_heldout_32000_32049_accessed": False,
        "same_heldout_reuse_allowed_for_closure": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "non_claims": {
            "mvp2_closed": False,
            "policy_uplift_proven": False,
            "deployable_real_robot_policy": False,
            "visual_policy_performance": False,
            "real_robot_success": False,
            "physical_robot_readiness": False,
            "universal_robot_support": False,
            "hmd_openxr_readiness": False,
        },
    }
    report["v0_10a_calibration_collapse_diagnosis_sha256"] = _sha256_payload_excluding(
        report,
        "v0_10a_calibration_collapse_diagnosis_sha256",
    )
    child_dir = output_dir / V10A_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    write_json(child_dir / "v0_10a_calibration_collapse_diagnosis_report.json", report)
    return report


def _v10c_load_required_gap_failed_calibration_gate(output_dir: Path) -> tuple[dict[str, Any], Path, str]:
    gate_path = output_dir / V10_CHILD_OUTPUT_DIRNAME / "calibration_presignal_gate_v0_10.json"
    if not gate_path.exists():
        raise ValueError("missing_v0_10_calibration_presignal_gate")
    gate = read_json(gate_path)
    if gate.get("schema_version") != V10_CALIBRATION_PRESIGNAL_SCHEMA_VERSION:
        raise ValueError("invalid_v0_10_calibration_presignal_schema")
    if gate.get("policy_slice") != V10_POLICY_SLICE_ID:
        raise ValueError("invalid_v0_10_calibration_policy_slice")
    if gate.get("runtime_backend") != "isaac_runtime":
        raise ValueError("v0_10_calibration_not_actual_isaac_runtime")
    if gate.get("passed") is not False:
        raise ValueError("v0_10_calibration_gate_not_failed")
    if gate.get("failure_reason") != "candidate_baseline_success_gap_below_v0_10_minimum":
        raise ValueError("v0_10_calibration_failure_not_gap_compression")
    if gate.get("heldout_opened") is True or gate.get("fresh_heldout_32000_32049_accessed") is True:
        raise ValueError("v0_10_heldout_already_opened")
    return gate, gate_path, _sha256_file(gate_path)


def _v10c_rollouts_by_scenario(rollouts: list[dict[str, Any]], *, role: str) -> dict[str, dict[str, Any]]:
    indexed: dict[str, dict[str, Any]] = {}
    for rollout in rollouts:
        scenario_id = str(rollout.get("scenario_id") or "")
        if not scenario_id:
            raise ValueError(f"v0_10c_{role}_rollout_missing_scenario_id")
        if scenario_id in indexed:
            raise ValueError(f"v0_10c_{role}_duplicate_scenario_id:{scenario_id}")
        indexed[scenario_id] = rollout
    return indexed


def _v10c_rollout_seed(rollout: dict[str, Any]) -> int | None:
    return _v09a_rollout_seed(rollout)


def _v10c_trace_summary(output_dir: Path, rollout: dict[str, Any]) -> dict[str, Any]:
    raw_ref = rollout.get("rollout_log_ref")
    if not raw_ref:
        return {"trace_summary_available": False, "missing_reason": "rollout_log_ref_missing"}
    try:
        path = _v10a_resolve_artifact_path(output_dir, raw_ref)
    except ValueError:
        return {
            "trace_summary_available": False,
            "missing_reason": "rollout_log_ref_unresolved",
            "rollout_log_ref": str(raw_ref),
        }
    payload = read_json(path)
    rows = [row for row in payload.get("trace", []) if isinstance(row, dict)]
    if not rows:
        return {
            "trace_summary_available": False,
            "missing_reason": "trace_rows_missing",
            "trace_path": str(path),
            "trace_sha256": _sha256_file(path),
        }
    depths = [float(row.get("insertion_depth_m", 0.0) or 0.0) for row in rows]
    laterals = [float(row.get("lateral_error_m", 0.0) or 0.0) for row in rows]
    summary = payload.get("summary") if isinstance(payload.get("summary"), dict) else {}
    max_consecutive = summary.get("env_native_max_consecutive_success_steps")
    if not isinstance(max_consecutive, int) or isinstance(max_consecutive, bool):
        max_consecutive = _v09a_longest_true_run(
            [bool(row.get("env_native_success_mask", row.get("env_native_success", False))) for row in rows]
        )
    return {
        "trace_summary_available": True,
        "trace_path": str(path),
        "trace_sha256": _sha256_file(path),
        "max_insertion_depth_m": round(max(depths), 9),
        "min_lateral_error_m": round(min(laterals), 9),
        "final_insertion_depth_m": round(depths[-1], 9),
        "final_lateral_error_m": round(laterals[-1], 9),
        "env_native_max_consecutive_success_steps": int(max_consecutive),
        "failure_reason": summary.get("failure_reason") or rollout.get("failure_reason"),
    }


def build_v10c_calibration_gap_compression_diagnosis(*, output_dir: Path) -> dict[str, Any]:
    gate, gate_path, gate_sha = _v10c_load_required_gap_failed_calibration_gate(output_dir)
    baseline_rollout_path = _v10a_resolve_artifact_path(
        output_dir,
        gate.get("baseline_calibration_rollout_path")
        or output_dir
        / V10_CHILD_OUTPUT_DIRNAME
        / "calibration_external_rollouts"
        / "baseline_calibration_rollouts_v0_10.json",
    )
    candidate_rollout_path = _v10a_resolve_artifact_path(
        output_dir,
        gate.get("candidate_calibration_rollout_path")
        or output_dir
        / V10_CHILD_OUTPUT_DIRNAME
        / "calibration_external_rollouts"
        / "candidate_calibration_rollouts_v0_10.json",
    )
    baseline_rollouts = _v10a_load_rollouts(baseline_rollout_path)
    candidate_rollouts = _v10a_load_rollouts(candidate_rollout_path)
    baseline_by_scenario = _v10c_rollouts_by_scenario(baseline_rollouts, role="baseline")
    candidate_by_scenario = _v10c_rollouts_by_scenario(candidate_rollouts, role="candidate")
    scenario_ids = sorted(set(baseline_by_scenario) & set(candidate_by_scenario))
    if len(scenario_ids) != int(gate.get("baseline_calibration_rollout_count", 0)):
        raise ValueError("v0_10c_rollout_pair_count_mismatch")

    paired_counts = {"B1_C1": 0, "B1_C0": 0, "B0_C1": 0, "B0_C0": 0}
    baseline_failures: list[dict[str, Any]] = []
    candidate_failures: list[dict[str, Any]] = []
    recovered: list[int] = []
    degraded: list[int] = []
    common_failures: list[int] = []
    common_failure_trace_summaries: dict[str, dict[str, Any]] = {}
    recovered_trace_summaries: dict[str, dict[str, Any]] = {}
    for scenario_id in scenario_ids:
        baseline_rollout = baseline_by_scenario[scenario_id]
        candidate_rollout = candidate_by_scenario[scenario_id]
        baseline_success = _v09a_rollout_succeeded(baseline_rollout)
        candidate_success = _v09a_rollout_succeeded(candidate_rollout)
        paired_counts[f"B{int(baseline_success)}_C{int(candidate_success)}"] += 1
        seed = _v10c_rollout_seed(baseline_rollout) or _v10c_rollout_seed(candidate_rollout)
        if not baseline_success:
            baseline_failures.append(baseline_rollout)
        if not candidate_success:
            candidate_failures.append(candidate_rollout)
        if baseline_success and not candidate_success and seed is not None:
            degraded.append(seed)
        if not baseline_success and candidate_success and seed is not None:
            recovered.append(seed)
            recovered_trace_summaries[str(seed)] = {
                "baseline": _v10c_trace_summary(output_dir, baseline_rollout),
                "candidate": _v10c_trace_summary(output_dir, candidate_rollout),
            }
        if not baseline_success and not candidate_success and seed is not None:
            common_failures.append(seed)
            common_failure_trace_summaries[str(seed)] = {
                "baseline": _v10c_trace_summary(output_dir, baseline_rollout),
                "candidate": _v10c_trace_summary(output_dir, candidate_rollout),
            }

    baseline_success_count = _v10a_rollout_success_count(baseline_rollouts)
    candidate_success_count = _v10a_rollout_success_count(candidate_rollouts)
    rollout_count = len(scenario_ids)
    baseline_rate = baseline_success_count / rollout_count if rollout_count else 0.0
    candidate_rate = candidate_success_count / rollout_count if rollout_count else 0.0
    gap = round(candidate_rate - baseline_rate, 12)
    recovered_count_required_for_min_gap = int(math.ceil(V10_CALIBRATION_UPLIFT_MINIMUM * rollout_count))
    baseline_ceiling_compression = baseline_rate >= 0.70
    candidate_non_regression = paired_counts["B1_C0"] == 0
    shared_authority_success_floor_detected = (
        baseline_ceiling_compression
        and candidate_non_regression
        and candidate_rate >= V10_CALIBRATION_SUCCESS_MINIMUM
        and paired_counts["B0_C1"] < recovered_count_required_for_min_gap
    )
    primary_root_cause = (
        "CALIBRATION_GAP_COMPRESSED_BY_BASELINE_SUCCESS_FLOOR"
        if shared_authority_success_floor_detected
        else "UNCLASSIFIED_V0_10_CALIBRATION_GAP_COMPRESSION"
    )
    recommended_downstream_slice = (
        V10C_RECOMMENDED_DOWNSTREAM_SLICE if shared_authority_success_floor_detected else None
    )
    report = {
        "schema_version": V10C_DIAGNOSIS_SCHEMA_VERSION,
        "policy_slice": V10C_POLICY_SLICE_ID,
        "slice_id": V10C_SLICE_ID,
        "source_policy_slice": V10_POLICY_SLICE_ID,
        "source_slice_id": V10_SLICE_ID,
        "source_calibration_presignal_gate_path": str(gate_path),
        "source_calibration_presignal_gate_sha256": gate_sha,
        "baseline_calibration_rollouts": str(baseline_rollout_path),
        "baseline_calibration_rollouts_sha256": _sha256_file(baseline_rollout_path),
        "candidate_calibration_rollouts": str(candidate_rollout_path),
        "candidate_calibration_rollouts_sha256": _sha256_file(candidate_rollout_path),
        "runtime_backend": "offline_artifact_diagnosis",
        "proof_runtime": V10C_SLICE_ID,
        "baseline_calibration_success_count": baseline_success_count,
        "candidate_calibration_success_count": candidate_success_count,
        "calibration_rollouts_per_policy": rollout_count,
        "baseline_calibration_success_rate": round(baseline_rate, 12),
        "candidate_calibration_success_rate": round(candidate_rate, 12),
        "candidate_baseline_success_gap": gap,
        "required_candidate_baseline_success_gap": V10_CALIBRATION_UPLIFT_MINIMUM,
        "candidate_success_minimum": V10_CALIBRATION_SUCCESS_MINIMUM,
        "paired_outcome_counts": paired_counts,
        "candidate_degraded_baseline_success_seeds": sorted(degraded),
        "candidate_recovered_baseline_failure_seeds": sorted(recovered),
        "common_failure_seeds": sorted(common_failures),
        "baseline_failure_seeds": _v09a_seed_list(baseline_failures),
        "candidate_failure_seeds": _v09a_seed_list(candidate_failures),
        "baseline_ceiling_compression": baseline_ceiling_compression,
        "candidate_non_regression": candidate_non_regression,
        "shared_authority_success_floor_detected": shared_authority_success_floor_detected,
        "baseline_success_floor_threshold": 0.70,
        "candidate_recoveries_required_for_minimum_gap": recovered_count_required_for_min_gap,
        "candidate_recoveries_observed": paired_counts["B0_C1"],
        "primary_root_cause_class": primary_root_cause,
        "recommended_downstream_slice": recommended_downstream_slice,
        "recommended_next_valid_step": (
            "Pre-register v0.11 with a fresh calibration/held-out split and an "
            "attribution-preserving comparator that audits and limits shared-authority "
            "success floor before held-out."
            if shared_authority_success_floor_detected
            else "Inspect paired calibration traces before opening held-out 32000-32049."
        ),
        "common_failure_trace_summaries": common_failure_trace_summaries,
        "recovered_trace_summaries": recovered_trace_summaries,
        "calibration_opened": True,
        "heldout_opened": False,
        "fresh_calibration_31000_31029_accessed": True,
        "fresh_heldout_32000_32049_accessed": False,
        "same_heldout_reuse_allowed_for_closure": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "non_claims": {
            "mvp2_closed": False,
            "policy_uplift_proven": False,
            "deployable_real_robot_policy": False,
            "visual_policy_performance": False,
            "real_robot_success": False,
            "physical_robot_readiness": False,
            "universal_robot_support": False,
            "hmd_openxr_readiness": False,
        },
    }
    report["v0_10c_calibration_gap_compression_diagnosis_sha256"] = _sha256_payload_excluding(
        report,
        "v0_10c_calibration_gap_compression_diagnosis_sha256",
    )
    child_dir = output_dir / V10C_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    write_json(child_dir / "v0_10c_calibration_gap_compression_diagnosis_report.json", report)
    return report


def load_required_v10c_calibration_gap_compression_diagnosis(
    output_dir: Path,
) -> tuple[dict[str, Any], str]:
    path = (
        output_dir
        / V10C_CHILD_OUTPUT_DIRNAME
        / "v0_10c_calibration_gap_compression_diagnosis_report.json"
    )
    if not path.exists():
        raise ValueError("missing_v0_10c_calibration_gap_compression_diagnosis")
    report = read_json(path)
    if report.get("policy_slice") != V10C_POLICY_SLICE_ID:
        raise ValueError("invalid_v0_10c_gap_compression_policy_slice")
    if report.get("source_policy_slice") != V10_POLICY_SLICE_ID:
        raise ValueError("invalid_v0_10c_gap_compression_source_policy_slice")
    if (
        report.get("primary_root_cause_class")
        != "CALIBRATION_GAP_COMPRESSED_BY_BASELINE_SUCCESS_FLOOR"
    ):
        raise ValueError("v0_10c_gap_compression_not_baseline_floor")
    if report.get("recommended_downstream_slice") != V10C_RECOMMENDED_DOWNSTREAM_SLICE:
        raise ValueError("v0_10c_downstream_recommendation_mismatch")
    if (
        report.get("heldout_opened") is not False
        or report.get("fresh_heldout_32000_32049_accessed") is not False
        or report.get("mvp2_closed") is not False
        or report.get("policy_uplift_proven") is not False
    ):
        raise ValueError("v0_10c_gap_compression_claim_boundary_violation")
    report["path"] = str(path)
    report["sha256"] = _sha256_file(path)
    return report, report["sha256"]


def _v11_failure_material_row(row: dict[str, Any], *, copy_index: int) -> dict[str, Any]:
    copy_row = _v09_deepcopy_row(row)
    copy_row.update(
        {
            "proof_role": "v0_11_low_floor_uncurated_failure_material",
            "uncurated_mix_policy_slice": V11_POLICY_SLICE_ID,
            "uncurated_mix_is_failure_material": True,
            "uncurated_low_floor_policy_slice": V11_POLICY_SLICE_ID,
            "uncurated_low_floor_is_failure_material": True,
            "uncurated_low_floor_ratio_target": V11_BASELINE_FAILURE_MATERIAL_RATIO,
            "uncurated_low_floor_copy_index": copy_index,
            "uncurated_low_floor_source_row_sha256": _sha256_payload(row),
        }
    )
    return copy_row


def _build_v11_baseline_rows(
    *,
    success_rows: list[dict[str, Any]],
    failure_rows: list[dict[str, Any]],
) -> tuple[list[dict[str, Any]], dict[str, Any]]:
    if not success_rows:
        raise ValueError("v0_11_baseline_success_rows_missing")
    if not failure_rows:
        raise ValueError("v0_11_baseline_failure_rows_missing")
    target_failure_count = max(
        1,
        int(
            round(
                len(success_rows)
                * V11_BASELINE_FAILURE_MATERIAL_RATIO
                / (1.0 - V11_BASELINE_FAILURE_MATERIAL_RATIO)
            )
        ),
    )
    selected_failure_rows = [
        _v11_failure_material_row(
            failure_rows[index % len(failure_rows)],
            copy_index=index // len(failure_rows),
        )
        for index in range(target_failure_count)
    ]
    baseline_success_rows = [_v09_deepcopy_row(row) for row in success_rows]
    for row in baseline_success_rows:
        row["uncurated_low_floor_policy_slice"] = V11_POLICY_SLICE_ID
        row["uncurated_low_floor_is_failure_material"] = False
        row["uncurated_low_floor_ratio_target"] = V11_BASELINE_FAILURE_MATERIAL_RATIO
    baseline_rows = baseline_success_rows + selected_failure_rows
    ratio = len(selected_failure_rows) / len(baseline_rows)
    if ratio < 0.85 or ratio > 0.95:
        raise ValueError("v0_11_baseline_failure_mix_ratio_out_of_bounds")
    return baseline_rows, {
        "success_row_count": len(success_rows),
        "selected_failure_row_count": len(selected_failure_rows),
        "source_failure_row_count": len(failure_rows),
        "baseline_actual_failure_material_ratio": round(ratio, 12),
        "baseline_failure_material_ratio_target": V11_BASELINE_FAILURE_MATERIAL_RATIO,
    }


def build_v11_policy_artifact_payload(
    *,
    parent_policy_artifact: dict[str, Any],
    base_policy_artifact: dict[str, Any],
    dataset_view_role: str,
    training_view: dict[str, Any],
    source_v10c_diagnosis_sha256: str,
    low_floor_comparator_config_sha256: str,
) -> dict[str, Any]:
    role = "candidate" if dataset_view_role == "candidate_curated" else "baseline"
    payload = {
        key: value
        for key, value in parent_policy_artifact.items()
        if key not in {"path", "policy_artifact_sha256"}
    }
    for key in (
        "weights",
        "bias",
        "train_sample_count",
        "hyperparameters",
        "feature_schema",
        "feature_schema_version",
        "phase_schema",
        "action_schema",
    ):
        payload[key] = base_policy_artifact[key]
    payload.update(
        {
            "schema_version": V11_POLICY_ARTIFACT_SCHEMA_VERSION,
            "policy_artifact_schema_version": V11_POLICY_ARTIFACT_SCHEMA_VERSION,
            "policy_id": f"{role}_mvp2e_v11_low_floor_comparator_policy",
            "policy_slice": V11_POLICY_SLICE_ID,
            "slice_id": V11_SLICE_ID,
            "parent_policy_slice": V10_POLICY_SLICE_ID,
            "source_policy_slice": V10C_POLICY_SLICE_ID,
            "source_v10c_diagnosis_sha256": source_v10c_diagnosis_sha256,
            "source_v10_policy_artifact_sha256": parent_policy_artifact.get(
                "policy_artifact_sha256"
            ),
            "low_floor_comparator_config_sha256": low_floor_comparator_config_sha256,
            "dataset_view_role": dataset_view_role,
            "policy_class": RESIDUAL_POLICY_CLASS,
            "trainer": RESIDUAL_TRAINER,
            "trainer_family": RESIDUAL_TRAINER_FAMILY,
            "training_view_sha256": training_view["sha256"],
            "training_view_path": training_view["path"],
            "fresh_calibration_33000_33029_accessed": False,
            "fresh_heldout_34000_34049_accessed": False,
            "heldout_opened": False,
            "mvp2_closed": False,
            "policy_uplift_proven": False,
            "proof_authority": False,
        }
    )
    payload["policy_artifact_sha256"] = _sha256_payload_excluding(payload, "policy_artifact_sha256")
    return payload


def derive_v11_low_floor_comparator_gate(
    *,
    candidate_policy: dict[str, Any],
    baseline_policy: dict[str, Any],
    candidate_rows_v10: list[dict[str, Any]],
    candidate_rows_v11: list[dict[str, Any]],
    baseline_rows: list[dict[str, Any]],
    baseline_mix_report: dict[str, Any],
    source_v10c_diagnosis_sha256: str,
    low_floor_comparator_config_sha256: str,
    failure_material_report: dict[str, Any],
) -> dict[str, Any]:
    equality_keys = (
        "selected_action_adapter_id",
        "trainer",
        "trainer_family",
        "policy_class",
        "feature_schema",
        "feature_schema_version",
        "phase_schema",
        "action_schema",
        "base_servo_config_sha256",
        "authority_filter_config_sha256",
        "final_post_adapter_authority_config_sha256",
        "final_post_adapter_xy_authority_config_sha256",
        "shared_hysteresis_authority_config_sha256",
        "capture_conditioned_progress_authority_config_sha256",
        "horizon_reserved_capture_authority_config_sha256",
        "deadline_precedence_horizon_authority_config_sha256",
        "early_centered_z_open_safe_entry_config_sha256",
    )
    peer_mismatches = [key for key in equality_keys if candidate_policy.get(key) != baseline_policy.get(key)]
    candidate_rows_unchanged = _sha256_payload(candidate_rows_v10) == _sha256_payload(candidate_rows_v11)
    failure_rows = [row for row in baseline_rows if row.get("uncurated_low_floor_is_failure_material") is True]
    calibration_or_heldout_rows_used = _v08k_any_calibration_or_heldout_training_rows(
        candidate_rows_v11 + baseline_rows
    )
    ratio = float(baseline_mix_report["baseline_actual_failure_material_ratio"])
    reasons: list[str] = []
    if not candidate_rows_unchanged:
        reasons.append("candidate_rows_changed_from_v0_10")
    if ratio < 0.85 or ratio > 0.95:
        reasons.append("baseline_failure_material_ratio_out_of_bounds")
    if not failure_rows:
        reasons.append("baseline_failure_material_missing")
    if calibration_or_heldout_rows_used:
        reasons.append("calibration_or_heldout_rows_used_for_training")
    if peer_mismatches:
        reasons.append("peer_fairness_mismatch")
    gate = {
        "schema_version": V11_COMPARATOR_GATE_SCHEMA_VERSION,
        "policy_slice": V11_POLICY_SLICE_ID,
        "slice_id": V11_SLICE_ID,
        "parent_policy_slice": V10_POLICY_SLICE_ID,
        "source_policy_slice": V10C_POLICY_SLICE_ID,
        "source_v10c_diagnosis_sha256": source_v10c_diagnosis_sha256,
        "low_floor_comparator_config_sha256": low_floor_comparator_config_sha256,
        "failure_material_report": failure_material_report,
        "baseline_failure_material_ratio_target": V11_BASELINE_FAILURE_MATERIAL_RATIO,
        "baseline_actual_failure_material_ratio": ratio,
        "baseline_failure_material_row_count": len(failure_rows),
        "baseline_total_row_count": len(baseline_rows),
        "candidate_row_count": len(candidate_rows_v11),
        "candidate_rows_unchanged_from_v10": candidate_rows_unchanged,
        "peer_fairness_mismatch_keys": peer_mismatches,
        "calibration_or_heldout_rows_used_for_training": calibration_or_heldout_rows_used,
        "heldout_opened": False,
        "fresh_calibration_33000_33029_accessed": False,
        "fresh_heldout_34000_34049_accessed": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "passed": not reasons,
        "failure_reasons": reasons,
        "failure_reason": ",".join(reasons),
    }
    gate["low_floor_comparator_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "low_floor_comparator_gate_sha256",
    )
    return gate


def build_v11_low_floor_comparator_slice(*, output_dir: Path) -> dict[str, Any]:
    diagnosis, diagnosis_sha = load_required_v10c_calibration_gap_compression_diagnosis(output_dir)
    train_generation_gate, train_generation_gate_sha256 = _load_v09_train_generation_gate(output_dir)
    parent_policies = _load_v10_policy_artifacts(output_dir)
    child_dir = output_dir / V11_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    authority_config = _v09_source_authority_config(output_dir, parent_policies["candidate"])
    residual_servo_config = build_v07b_residual_servo_config(
        output_dir=child_dir,
        parent_config_sha256=train_generation_gate_sha256,
    )
    source_dir = output_dir / V10_CHILD_OUTPUT_DIRNAME
    candidate_rows_v10 = _rows_from_hdf5_metadata(source_dir / "candidate_curated_train_v0_10.hdf5")
    candidate_rows_v11 = [_v09_deepcopy_row(row) for row in candidate_rows_v10]
    success_rows = [_v09_deepcopy_row(row) for row in candidate_rows_v10 if row.get("accepted") is not False]
    failure_rows, failure_material_report = _extract_v09_failed_train_generation_rows(
        output_dir=output_dir,
        train_generation_gate=train_generation_gate,
        residual_servo_config=residual_servo_config,
    )
    baseline_rows, baseline_mix_report = _build_v11_baseline_rows(
        success_rows=success_rows,
        failure_rows=failure_rows,
    )
    low_floor_comparator_config = {
        "schema_version": "rdf_mvp2e_v11_low_floor_comparator_config_v0.1.0",
        "policy_slice": V11_POLICY_SLICE_ID,
        "slice_id": V11_SLICE_ID,
        "source_v10c_diagnosis_sha256": diagnosis_sha,
        "source_v10c_baseline_success_rate": diagnosis["baseline_calibration_success_rate"],
        "source_v10c_candidate_success_rate": diagnosis["candidate_calibration_success_rate"],
        "source_v10c_candidate_baseline_success_gap": diagnosis[
            "candidate_baseline_success_gap"
        ],
        "train_generation_config_sha256": train_generation_gate_sha256,
        "baseline_failure_material_ratio_target": V11_BASELINE_FAILURE_MATERIAL_RATIO,
        "baseline_floor_success_maximum": V11_BASELINE_FLOOR_SUCCESS_MAXIMUM,
        "failure_material_selection": "deterministic_round_robin_from_failed_train_generation_rows",
        "fresh_calibration_seed_range": [min(V11_FRESH_CALIBRATION_RANGE), max(V11_FRESH_CALIBRATION_RANGE)],
        "fresh_heldout_seed_range": [min(V11_FRESH_HELDOUT_RANGE), max(V11_FRESH_HELDOUT_RANGE)],
        "burned_heldout_seed_ranges": [
            [21000, 21049],
            [24000, 24049],
            [26000, 26049],
            [27000, 27049],
            [32000, 32049],
        ],
        "burned_calibration_seed_ranges": [
            [30000, 30029],
            [31000, 31029],
        ],
        "heldout_opened": False,
        "fresh_heldout_34000_34049_accessed": False,
    }
    low_floor_comparator_config["low_floor_comparator_config_sha256"] = _sha256_payload_excluding(
        low_floor_comparator_config,
        "low_floor_comparator_config_sha256",
    )
    write_json(child_dir / "v0_11_low_floor_comparator_config.json", low_floor_comparator_config)
    candidate_view = write_v07c_residual_train_view_hdf5(
        path=child_dir / "candidate_curated_train_v0_11.hdf5",
        rows=candidate_rows_v11,
        view_id="candidate_curated_v0_11_low_floor_comparator",
        authority_config=authority_config,
        schema_version=V11_MANIFEST_SCHEMA_VERSION,
        extra_hdf5_attrs={
            "policy_slice": V11_POLICY_SLICE_ID,
            "low_floor_comparator_config_sha256": low_floor_comparator_config[
                "low_floor_comparator_config_sha256"
            ],
            "candidate_rows_unchanged_from_v10": True,
        },
        extra_view_fields={
            "policy_slice": V11_POLICY_SLICE_ID,
            "low_floor_comparator_config_sha256": low_floor_comparator_config[
                "low_floor_comparator_config_sha256"
            ],
            "candidate_rows_unchanged_from_v10": True,
        },
    )
    baseline_view = write_v07c_residual_train_view_hdf5(
        path=child_dir / "baseline_uncurated_low_floor_train_v0_11.hdf5",
        rows=baseline_rows,
        view_id="baseline_uncurated_low_floor_v0_11",
        authority_config=authority_config,
        schema_version=V11_MANIFEST_SCHEMA_VERSION,
        extra_hdf5_attrs={
            "policy_slice": V11_POLICY_SLICE_ID,
            "low_floor_comparator_config_sha256": low_floor_comparator_config[
                "low_floor_comparator_config_sha256"
            ],
            "baseline_actual_failure_material_ratio": baseline_mix_report[
                "baseline_actual_failure_material_ratio"
            ],
        },
        extra_view_fields={
            "policy_slice": V11_POLICY_SLICE_ID,
            "low_floor_comparator_config_sha256": low_floor_comparator_config[
                "low_floor_comparator_config_sha256"
            ],
            **baseline_mix_report,
        },
    )
    hyperparameters = dict(parent_policies["candidate"].get("hyperparameters") or {})
    hyperparameters.update(
        {
            "trainer_family": RESIDUAL_TRAINER_FAMILY,
            "low_floor_comparator_config_sha256": low_floor_comparator_config[
                "low_floor_comparator_config_sha256"
            ],
            "baseline_failure_material_ratio_target": V11_BASELINE_FAILURE_MATERIAL_RATIO,
            "baseline_floor_success_maximum": V11_BASELINE_FLOOR_SUCCESS_MAXIMUM,
        }
    )
    candidate_base = fit_phase_conditioned_bc_policy(
        policy_id="candidate_curated_mvp2e_v11_low_floor_comparator_bc",
        train_rows=candidate_rows_v11,
        hyperparameters=hyperparameters,
        feature_schema=FEATURE_SCHEMA_V07A,
        phase_schema=BEHAVIOR_STATE_PHASES,
        feature_schema_version=FEATURE_SCHEMA_V07A_VERSION,
    )
    baseline_base = fit_phase_conditioned_bc_policy(
        policy_id="baseline_uncurated_low_floor_mvp2e_v11_bc",
        train_rows=baseline_rows,
        hyperparameters=hyperparameters,
        feature_schema=FEATURE_SCHEMA_V07A,
        phase_schema=BEHAVIOR_STATE_PHASES,
        feature_schema_version=FEATURE_SCHEMA_V07A_VERSION,
    )
    candidate_policy = build_v11_policy_artifact_payload(
        parent_policy_artifact=parent_policies["candidate"],
        base_policy_artifact=candidate_base,
        dataset_view_role="candidate_curated",
        training_view=candidate_view,
        source_v10c_diagnosis_sha256=diagnosis_sha,
        low_floor_comparator_config_sha256=low_floor_comparator_config[
            "low_floor_comparator_config_sha256"
        ],
    )
    baseline_policy = build_v11_policy_artifact_payload(
        parent_policy_artifact=parent_policies["baseline"],
        base_policy_artifact=baseline_base,
        dataset_view_role="baseline_uncurated_low_floor",
        training_view=baseline_view,
        source_v10c_diagnosis_sha256=diagnosis_sha,
        low_floor_comparator_config_sha256=low_floor_comparator_config[
            "low_floor_comparator_config_sha256"
        ],
    )
    write_json(child_dir / "candidate_policy_artifact_v0_11.json", candidate_policy)
    write_json(child_dir / "baseline_policy_artifact_v0_11.json", baseline_policy)
    gate = derive_v11_low_floor_comparator_gate(
        candidate_policy=candidate_policy,
        baseline_policy=baseline_policy,
        candidate_rows_v10=candidate_rows_v10,
        candidate_rows_v11=candidate_rows_v11,
        baseline_rows=baseline_rows,
        baseline_mix_report=baseline_mix_report,
        source_v10c_diagnosis_sha256=diagnosis_sha,
        low_floor_comparator_config_sha256=low_floor_comparator_config[
            "low_floor_comparator_config_sha256"
        ],
        failure_material_report=failure_material_report,
    )
    write_json(child_dir / "low_floor_comparator_gate_v0_11.json", gate)
    manifest = {
        "schema_version": V11_MANIFEST_SCHEMA_VERSION,
        "policy_slice": V11_POLICY_SLICE_ID,
        "slice_id": V11_SLICE_ID,
        "parent_policy_slice": V10_POLICY_SLICE_ID,
        "source_policy_slice": V10C_POLICY_SLICE_ID,
        "source_v10c_diagnosis_sha256": diagnosis_sha,
        "train_generation_config_sha256": train_generation_gate_sha256,
        "low_floor_comparator_config": low_floor_comparator_config,
        "fresh_calibration_seed_range": [min(V11_FRESH_CALIBRATION_RANGE), max(V11_FRESH_CALIBRATION_RANGE)],
        "fresh_heldout_seed_range": [min(V11_FRESH_HELDOUT_RANGE), max(V11_FRESH_HELDOUT_RANGE)],
        "burned_heldout_seed_ranges": low_floor_comparator_config["burned_heldout_seed_ranges"],
        "training_views": {"candidate": candidate_view, "baseline": baseline_view},
        "policy_artifacts": {
            "candidate": {**candidate_policy, "path": str(child_dir / "candidate_policy_artifact_v0_11.json")},
            "baseline": {**baseline_policy, "path": str(child_dir / "baseline_policy_artifact_v0_11.json")},
        },
        "low_floor_comparator_gate": gate,
        "failed_closed": gate.get("passed") is not True,
        "failure_reason": "" if gate.get("passed") is True else gate.get("failure_reason"),
        "calibration_opened": False,
        "heldout_opened": False,
        "fresh_calibration_33000_33029_accessed": False,
        "fresh_heldout_34000_34049_accessed": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "non_claims": {
            "policy_uplift_proven": False,
            "real_robot_success": False,
            "physical_robot_readiness": False,
            "hmd_openxr_readiness": False,
            "visual_policy_performance": False,
        },
    }
    manifest["v0_11_low_floor_comparator_manifest_sha256"] = _sha256_payload_excluding(
        manifest,
        "v0_11_low_floor_comparator_manifest_sha256",
    )
    write_json(child_dir / "v0_11_low_floor_comparator_manifest.json", manifest)
    return manifest


def _load_v10_v09_policy_artifacts(output_dir: Path) -> dict[str, dict[str, Any]]:
    child_dir = output_dir / V09_CHILD_OUTPUT_DIRNAME
    baseline_path = child_dir / "baseline_policy_artifact_v0_9.json"
    candidate_path = child_dir / "candidate_policy_artifact_v0_9.json"
    if not baseline_path.exists() or not candidate_path.exists():
        raise ValueError("missing_v0_9_policy_artifacts_for_v0_10")
    baseline = read_json(baseline_path)
    candidate = read_json(candidate_path)
    for role, payload in (("baseline", baseline), ("candidate", candidate)):
        if payload.get("policy_slice") != V09_POLICY_SLICE_ID:
            raise ValueError(f"invalid_v0_10_parent_{role}_policy_slice")
        if payload.get("policy_artifact_sha256") != _sha256_payload_excluding(
            payload,
            "policy_artifact_sha256",
        ):
            raise ValueError(f"invalid_v0_10_parent_{role}_policy_sha")
    return {
        "baseline": {**baseline, "path": str(baseline_path)},
        "candidate": {**candidate, "path": str(candidate_path)},
    }


def _v10_failure_material_row(row: dict[str, Any], *, copy_index: int) -> dict[str, Any]:
    copy_row = _v09_deepcopy_row(row)
    copy_row.update(
        {
            "proof_role": "v0_10_controlled_uncurated_stress_failure_material",
            "uncurated_mix_policy_slice": V10_POLICY_SLICE_ID,
            "uncurated_mix_is_failure_material": True,
            "uncurated_stress_policy_slice": V10_POLICY_SLICE_ID,
            "uncurated_stress_is_failure_material": True,
            "uncurated_stress_ratio_target": V10_BASELINE_FAILURE_MATERIAL_RATIO,
            "uncurated_stress_copy_index": copy_index,
            "uncurated_stress_source_row_sha256": _sha256_payload(row),
        }
    )
    return copy_row


def _build_v10_baseline_rows(
    *,
    success_rows: list[dict[str, Any]],
    failure_rows: list[dict[str, Any]],
) -> tuple[list[dict[str, Any]], dict[str, Any]]:
    if not success_rows:
        raise ValueError("v0_10_baseline_success_rows_missing")
    if not failure_rows:
        raise ValueError("v0_10_baseline_failure_rows_missing")
    target_failure_count = max(
        1,
        int(
            round(
                len(success_rows)
                * V10_BASELINE_FAILURE_MATERIAL_RATIO
                / (1.0 - V10_BASELINE_FAILURE_MATERIAL_RATIO)
            )
        ),
    )
    selected_failure_rows = [
        _v10_failure_material_row(
            failure_rows[index % len(failure_rows)],
            copy_index=index // len(failure_rows),
        )
        for index in range(target_failure_count)
    ]
    baseline_success_rows = [_v09_deepcopy_row(row) for row in success_rows]
    for row in baseline_success_rows:
        row["uncurated_stress_policy_slice"] = V10_POLICY_SLICE_ID
        row["uncurated_stress_is_failure_material"] = False
        row["uncurated_stress_ratio_target"] = V10_BASELINE_FAILURE_MATERIAL_RATIO
    baseline_rows = baseline_success_rows + selected_failure_rows
    ratio = len(selected_failure_rows) / len(baseline_rows)
    if ratio < 0.65 or ratio > 0.75:
        raise ValueError("v0_10_baseline_failure_mix_ratio_out_of_bounds")
    report = {
        "success_row_count": len(success_rows),
        "selected_failure_row_count": len(selected_failure_rows),
        "source_failure_row_count": len(failure_rows),
        "baseline_actual_failure_material_ratio": round(ratio, 12),
        "baseline_failure_material_ratio_target": V10_BASELINE_FAILURE_MATERIAL_RATIO,
    }
    return baseline_rows, report


def build_v10_policy_artifact_payload(
    *,
    parent_policy_artifact: dict[str, Any],
    base_policy_artifact: dict[str, Any],
    dataset_view_role: str,
    training_view: dict[str, Any],
    source_v09a_diagnosis_sha256: str,
    comparator_stress_config_sha256: str,
) -> dict[str, Any]:
    role = "candidate" if dataset_view_role == "candidate_curated" else "baseline"
    payload = {
        key: value
        for key, value in parent_policy_artifact.items()
        if key not in {"path", "policy_artifact_sha256"}
    }
    for key in (
        "weights",
        "bias",
        "train_sample_count",
        "hyperparameters",
        "feature_schema",
        "feature_schema_version",
        "phase_schema",
        "action_schema",
    ):
        payload[key] = base_policy_artifact[key]
    payload.update(
        {
            "schema_version": V10_POLICY_ARTIFACT_SCHEMA_VERSION,
            "policy_artifact_schema_version": V10_POLICY_ARTIFACT_SCHEMA_VERSION,
            "policy_id": f"{role}_mvp2e_v10_fresh_comparator_stress_policy",
            "policy_slice": V10_POLICY_SLICE_ID,
            "slice_id": V10_SLICE_ID,
            "parent_policy_slice": V09_POLICY_SLICE_ID,
            "source_policy_slice": V09_POLICY_SLICE_ID,
            "source_v09a_diagnosis_sha256": source_v09a_diagnosis_sha256,
            "source_v09_policy_artifact_sha256": parent_policy_artifact.get("policy_artifact_sha256"),
            "comparator_stress_config_sha256": comparator_stress_config_sha256,
            "dataset_view_role": dataset_view_role,
            "policy_class": RESIDUAL_POLICY_CLASS,
            "trainer": RESIDUAL_TRAINER,
            "trainer_family": RESIDUAL_TRAINER_FAMILY,
            "training_view_sha256": training_view["sha256"],
            "training_view_path": training_view["path"],
            "fresh_calibration_31000_31029_accessed": False,
            "fresh_heldout_32000_32049_accessed": False,
            "heldout_opened": False,
            "mvp2_closed": False,
            "policy_uplift_proven": False,
            "proof_authority": False,
        }
    )
    payload["policy_artifact_sha256"] = _sha256_payload_excluding(payload, "policy_artifact_sha256")
    return payload


def derive_v10_comparator_stress_gate(
    *,
    candidate_policy: dict[str, Any],
    baseline_policy: dict[str, Any],
    candidate_rows_v09: list[dict[str, Any]],
    candidate_rows_v10: list[dict[str, Any]],
    baseline_rows: list[dict[str, Any]],
    baseline_mix_report: dict[str, Any],
    source_v09a_diagnosis_sha256: str,
    comparator_stress_config_sha256: str,
    failure_material_report: dict[str, Any],
) -> dict[str, Any]:
    equality_keys = (
        "selected_action_adapter_id",
        "trainer",
        "trainer_family",
        "policy_class",
        "feature_schema",
        "feature_schema_version",
        "phase_schema",
        "action_schema",
        "base_servo_config_sha256",
        "authority_filter_config_sha256",
        "final_post_adapter_authority_config_sha256",
        "final_post_adapter_xy_authority_config_sha256",
        "shared_hysteresis_authority_config_sha256",
        "capture_conditioned_progress_authority_config_sha256",
        "horizon_reserved_capture_authority_config_sha256",
        "deadline_precedence_horizon_authority_config_sha256",
        "early_centered_z_open_safe_entry_config_sha256",
    )
    peer_mismatches = [key for key in equality_keys if candidate_policy.get(key) != baseline_policy.get(key)]
    candidate_rows_unchanged = _sha256_payload(candidate_rows_v09) == _sha256_payload(candidate_rows_v10)
    failure_rows = [row for row in baseline_rows if row.get("uncurated_stress_is_failure_material") is True]
    calibration_or_heldout_rows_used = _v08k_any_calibration_or_heldout_training_rows(
        candidate_rows_v10 + baseline_rows
    )
    reasons: list[str] = []
    ratio = float(baseline_mix_report["baseline_actual_failure_material_ratio"])
    if not candidate_rows_unchanged:
        reasons.append("candidate_rows_changed_from_v0_9")
    if ratio < 0.65 or ratio > 0.75:
        reasons.append("baseline_failure_material_ratio_out_of_bounds")
    if not failure_rows:
        reasons.append("baseline_failure_material_missing")
    if calibration_or_heldout_rows_used:
        reasons.append("calibration_or_heldout_rows_used_for_training")
    if peer_mismatches:
        reasons.append("peer_fairness_mismatch")
    gate = {
        "schema_version": V10_COMPARATOR_STRESS_GATE_SCHEMA_VERSION,
        "policy_slice": V10_POLICY_SLICE_ID,
        "slice_id": V10_SLICE_ID,
        "parent_policy_slice": V09_POLICY_SLICE_ID,
        "source_policy_slice": V09_POLICY_SLICE_ID,
        "source_v09a_diagnosis_sha256": source_v09a_diagnosis_sha256,
        "comparator_stress_config_sha256": comparator_stress_config_sha256,
        "failure_material_report": failure_material_report,
        "baseline_failure_material_ratio_target": V10_BASELINE_FAILURE_MATERIAL_RATIO,
        "baseline_actual_failure_material_ratio": ratio,
        "baseline_failure_material_row_count": len(failure_rows),
        "baseline_total_row_count": len(baseline_rows),
        "candidate_row_count": len(candidate_rows_v10),
        "candidate_rows_unchanged_from_v09": candidate_rows_unchanged,
        "peer_fairness_mismatch_keys": peer_mismatches,
        "calibration_or_heldout_rows_used_for_training": calibration_or_heldout_rows_used,
        "heldout_opened": False,
        "fresh_heldout_32000_32049_accessed": False,
        "fresh_calibration_31000_31029_accessed": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "passed": not reasons,
        "failure_reasons": reasons,
        "failure_reason": ",".join(reasons),
    }
    gate["comparator_stress_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "comparator_stress_gate_sha256",
    )
    return gate


def build_v10_fresh_comparator_stress_slice(*, output_dir: Path) -> dict[str, Any]:
    diagnosis, diagnosis_sha = load_required_v09a_heldout_uplift_shortfall_diagnosis(output_dir)
    train_generation_gate, train_generation_gate_sha256 = _load_v09_train_generation_gate(output_dir)
    parent_policies = _load_v10_v09_policy_artifacts(output_dir)
    child_dir = output_dir / V10_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    authority_config = _v09_source_authority_config(output_dir, parent_policies["candidate"])
    residual_servo_config = build_v07b_residual_servo_config(
        output_dir=child_dir,
        parent_config_sha256=train_generation_gate_sha256,
    )
    source_dir = output_dir / V09_CHILD_OUTPUT_DIRNAME
    candidate_rows_v09 = _rows_from_hdf5_metadata(source_dir / "candidate_curated_train_v0_9.hdf5")
    candidate_rows_v10 = [_v09_deepcopy_row(row) for row in candidate_rows_v09]
    success_rows = [_v09_deepcopy_row(row) for row in candidate_rows_v09 if row.get("accepted") is not False]
    failure_rows, failure_material_report = _extract_v09_failed_train_generation_rows(
        output_dir=output_dir,
        train_generation_gate=train_generation_gate,
        residual_servo_config=residual_servo_config,
    )
    baseline_rows, baseline_mix_report = _build_v10_baseline_rows(
        success_rows=success_rows,
        failure_rows=failure_rows,
    )
    comparator_stress_config = {
        "schema_version": "rdf_mvp2e_v10_comparator_stress_config_v0.1.0",
        "policy_slice": V10_POLICY_SLICE_ID,
        "slice_id": V10_SLICE_ID,
        "source_v09a_diagnosis_sha256": diagnosis_sha,
        "source_v09a_max_possible_uplift_on_opened_heldout": diagnosis[
            "max_possible_uplift_on_opened_heldout"
        ],
        "train_generation_config_sha256": train_generation_gate_sha256,
        "baseline_failure_material_ratio_target": V10_BASELINE_FAILURE_MATERIAL_RATIO,
        "failure_material_selection": "deterministic_round_robin_from_failed_train_generation_rows",
        "fresh_calibration_seed_range": [min(V10_FRESH_CALIBRATION_RANGE), max(V10_FRESH_CALIBRATION_RANGE)],
        "fresh_heldout_seed_range": [min(V10_FRESH_HELDOUT_RANGE), max(V10_FRESH_HELDOUT_RANGE)],
        "burned_heldout_seed_ranges": [
            [21000, 21049],
            [24000, 24049],
            [26000, 26049],
            [27000, 27049],
        ],
        "heldout_opened": False,
        "fresh_heldout_32000_32049_accessed": False,
    }
    comparator_stress_config["comparator_stress_config_sha256"] = _sha256_payload_excluding(
        comparator_stress_config,
        "comparator_stress_config_sha256",
    )
    write_json(child_dir / "v0_10_comparator_stress_config.json", comparator_stress_config)
    candidate_view = write_v07c_residual_train_view_hdf5(
        path=child_dir / "candidate_curated_train_v0_10.hdf5",
        rows=candidate_rows_v10,
        view_id="candidate_curated_v0_10_fresh_comparator_stress",
        authority_config=authority_config,
        schema_version=V10_MANIFEST_SCHEMA_VERSION,
        extra_hdf5_attrs={
            "policy_slice": V10_POLICY_SLICE_ID,
            "comparator_stress_config_sha256": comparator_stress_config[
                "comparator_stress_config_sha256"
            ],
            "candidate_rows_unchanged_from_v09": True,
        },
        extra_view_fields={
            "policy_slice": V10_POLICY_SLICE_ID,
            "comparator_stress_config_sha256": comparator_stress_config[
                "comparator_stress_config_sha256"
            ],
            "candidate_rows_unchanged_from_v09": True,
        },
    )
    baseline_view = write_v07c_residual_train_view_hdf5(
        path=child_dir / "baseline_uncurated_stress_train_v0_10.hdf5",
        rows=baseline_rows,
        view_id="baseline_uncurated_stress_v0_10",
        authority_config=authority_config,
        schema_version=V10_MANIFEST_SCHEMA_VERSION,
        extra_hdf5_attrs={
            "policy_slice": V10_POLICY_SLICE_ID,
            "comparator_stress_config_sha256": comparator_stress_config[
                "comparator_stress_config_sha256"
            ],
            "baseline_actual_failure_material_ratio": baseline_mix_report[
                "baseline_actual_failure_material_ratio"
            ],
        },
        extra_view_fields={
            "policy_slice": V10_POLICY_SLICE_ID,
            "comparator_stress_config_sha256": comparator_stress_config[
                "comparator_stress_config_sha256"
            ],
            **baseline_mix_report,
        },
    )
    hyperparameters = dict(parent_policies["candidate"].get("hyperparameters") or {})
    hyperparameters.update(
        {
            "trainer_family": RESIDUAL_TRAINER_FAMILY,
            "comparator_stress_config_sha256": comparator_stress_config[
                "comparator_stress_config_sha256"
            ],
            "baseline_failure_material_ratio_target": V10_BASELINE_FAILURE_MATERIAL_RATIO,
        }
    )
    candidate_base = fit_phase_conditioned_bc_policy(
        policy_id="candidate_curated_mvp2e_v10_fresh_comparator_stress_bc",
        train_rows=candidate_rows_v10,
        hyperparameters=hyperparameters,
        feature_schema=FEATURE_SCHEMA_V07A,
        phase_schema=BEHAVIOR_STATE_PHASES,
        feature_schema_version=FEATURE_SCHEMA_V07A_VERSION,
    )
    baseline_base = fit_phase_conditioned_bc_policy(
        policy_id="baseline_uncurated_stress_mvp2e_v10_bc",
        train_rows=baseline_rows,
        hyperparameters=hyperparameters,
        feature_schema=FEATURE_SCHEMA_V07A,
        phase_schema=BEHAVIOR_STATE_PHASES,
        feature_schema_version=FEATURE_SCHEMA_V07A_VERSION,
    )
    candidate_policy = build_v10_policy_artifact_payload(
        parent_policy_artifact=parent_policies["candidate"],
        base_policy_artifact=candidate_base,
        dataset_view_role="candidate_curated",
        training_view=candidate_view,
        source_v09a_diagnosis_sha256=diagnosis_sha,
        comparator_stress_config_sha256=comparator_stress_config["comparator_stress_config_sha256"],
    )
    baseline_policy = build_v10_policy_artifact_payload(
        parent_policy_artifact=parent_policies["baseline"],
        base_policy_artifact=baseline_base,
        dataset_view_role="baseline_uncurated_stress",
        training_view=baseline_view,
        source_v09a_diagnosis_sha256=diagnosis_sha,
        comparator_stress_config_sha256=comparator_stress_config["comparator_stress_config_sha256"],
    )
    write_json(child_dir / "candidate_policy_artifact_v0_10.json", candidate_policy)
    write_json(child_dir / "baseline_policy_artifact_v0_10.json", baseline_policy)
    gate = derive_v10_comparator_stress_gate(
        candidate_policy=candidate_policy,
        baseline_policy=baseline_policy,
        candidate_rows_v09=candidate_rows_v09,
        candidate_rows_v10=candidate_rows_v10,
        baseline_rows=baseline_rows,
        baseline_mix_report=baseline_mix_report,
        source_v09a_diagnosis_sha256=diagnosis_sha,
        comparator_stress_config_sha256=comparator_stress_config["comparator_stress_config_sha256"],
        failure_material_report=failure_material_report,
    )
    write_json(child_dir / "comparator_stress_gate_v0_10.json", gate)
    manifest = {
        "schema_version": V10_MANIFEST_SCHEMA_VERSION,
        "policy_slice": V10_POLICY_SLICE_ID,
        "slice_id": V10_SLICE_ID,
        "parent_policy_slice": V09_POLICY_SLICE_ID,
        "source_policy_slice": V09_POLICY_SLICE_ID,
        "source_v09a_diagnosis_sha256": diagnosis_sha,
        "train_generation_config_sha256": train_generation_gate_sha256,
        "comparator_stress_config": comparator_stress_config,
        "fresh_calibration_seed_range": [min(V10_FRESH_CALIBRATION_RANGE), max(V10_FRESH_CALIBRATION_RANGE)],
        "fresh_heldout_seed_range": [min(V10_FRESH_HELDOUT_RANGE), max(V10_FRESH_HELDOUT_RANGE)],
        "burned_heldout_seed_ranges": comparator_stress_config["burned_heldout_seed_ranges"],
        "training_views": {"candidate": candidate_view, "baseline": baseline_view},
        "policy_artifacts": {
            "candidate": {**candidate_policy, "path": str(child_dir / "candidate_policy_artifact_v0_10.json")},
            "baseline": {**baseline_policy, "path": str(child_dir / "baseline_policy_artifact_v0_10.json")},
        },
        "comparator_stress_gate": gate,
        "failed_closed": gate.get("passed") is not True,
        "failure_reason": "" if gate.get("passed") is True else gate.get("failure_reason"),
        "calibration_opened": False,
        "heldout_opened": False,
        "fresh_calibration_31000_31029_accessed": False,
        "fresh_heldout_32000_32049_accessed": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "non_claims": {
            "policy_uplift_proven": False,
            "real_robot_success": False,
            "physical_robot_readiness": False,
            "hmd_openxr_readiness": False,
            "visual_policy_performance": False,
        },
    }
    manifest["v0_10_comparator_stress_manifest_sha256"] = _sha256_payload_excluding(
        manifest,
        "v0_10_comparator_stress_manifest_sha256",
    )
    write_json(child_dir / "v0_10_comparator_stress_manifest.json", manifest)
    return manifest


def _v10_burned_seed_range_accessed(seed: int) -> bool:
    seed_int = int(seed)
    return (
        _v09_burned_seed_range_accessed(seed_int)
        or seed_int in V09_FRESH_CALIBRATION_RANGE
        or seed_int in V09_FRESH_HELDOUT_RANGE
        or seed_int in V08A_FRESH_HELDOUT_RANGE
        or seed_int in V08B_FRESH_HELDOUT_RANGE
    )


def build_v10_fresh_manifest(*, output_dir: Path, stress_manifest: dict[str, Any]) -> dict[str, Any]:
    gate = stress_manifest.get("comparator_stress_gate", {})
    if gate.get("passed") is not True:
        raise ValueError("v0_10_comparator_stress_gate_not_passed")
    calibration_rows = [_scenario_row(split="calibration", seed=seed) for seed in V10_FRESH_CALIBRATION_RANGE]
    heldout_rows = [_scenario_row(split="held_out", seed=seed) for seed in V10_FRESH_HELDOUT_RANGE]
    if any(_v10_burned_seed_range_accessed(int(row["seed"])) for row in calibration_rows):
        raise ValueError("v0_10_fresh_manifest_reuses_burned_calibration_seed_range")
    if any(_v10_burned_seed_range_accessed(int(row["seed"])) for row in heldout_rows):
        raise ValueError("v0_10_fresh_manifest_reuses_burned_heldout_seed_range")
    manifest = {
        "schema_version": V10_MANIFEST_SCHEMA_VERSION,
        "policy_slice": V10_POLICY_SLICE_ID,
        "slice_id": V10_SLICE_ID,
        "parent_policy_slice": V09_POLICY_SLICE_ID,
        "source_policy_slice": V09_POLICY_SLICE_ID,
        "scenario_profile": "v0_10",
        "task_type": "connector_insertion",
        "success_metric": SUCCESS_METRIC,
        "success_authority": V06_ENV_NATIVE_SUCCESS_AUTHORITY,
        "source_v10_comparator_stress_manifest_sha256": stress_manifest[
            "v0_10_comparator_stress_manifest_sha256"
        ],
        "source_v10_comparator_stress_gate_sha256": gate["comparator_stress_gate_sha256"],
        "comparator_stress_config_sha256": gate["comparator_stress_config_sha256"],
        "scenarios": calibration_rows + heldout_rows,
        "fresh_split_manifest": {
            "calibration": {
                "seed_range": [min(V10_FRESH_CALIBRATION_RANGE), max(V10_FRESH_CALIBRATION_RANGE)],
                "scenario_ids": [row["scenario_id"] for row in calibration_rows],
                "count": len(calibration_rows),
            },
            "held_out": {
                "seed_range": [min(V10_FRESH_HELDOUT_RANGE), max(V10_FRESH_HELDOUT_RANGE)],
                "scenario_ids": [row["scenario_id"] for row in heldout_rows],
                "count": len(heldout_rows),
            },
        },
        "burned_heldout_seed_ranges": [
            list(V07A2_PROTECTED_HELDOUT_SEED_RANGE),
            [min(V08A_FRESH_HELDOUT_RANGE), max(V08A_FRESH_HELDOUT_RANGE)],
            [min(V08B_FRESH_HELDOUT_RANGE), max(V08B_FRESH_HELDOUT_RANGE)],
            [min(V09_FRESH_HELDOUT_RANGE), max(V09_FRESH_HELDOUT_RANGE)],
        ],
        "burned_calibration_seed_ranges": [
            [min(V08D_FRESH_CALIBRATION_RANGE), max(V08D_FRESH_CALIBRATION_RANGE)],
            [min(V08F_FRESH_CALIBRATION_RANGE), max(V08F_FRESH_CALIBRATION_RANGE)],
            [min(V08G_FRESH_CALIBRATION_RANGE), max(V08G_FRESH_CALIBRATION_RANGE)],
            [min(V08H_FRESH_CALIBRATION_RANGE), max(V08H_FRESH_CALIBRATION_RANGE)],
            [min(V08K_FRESH_CALIBRATION_RANGE), max(V08K_FRESH_CALIBRATION_RANGE)],
            [min(V09_FRESH_CALIBRATION_RANGE), max(V09_FRESH_CALIBRATION_RANGE)],
        ],
        "fresh_calibration_26500_26529_accessed": True,
        "fresh_calibration_27500_27529_accessed": True,
        "fresh_calibration_28000_28029_accessed": True,
        "fresh_calibration_28500_28529_accessed": True,
        "fresh_calibration_29000_29029_accessed": True,
        "fresh_calibration_30000_30029_accessed": True,
        "fresh_calibration_31000_31029_accessed": False,
        "heldout_21000_21049_accessed": False,
        "fresh_heldout_24000_24049_accessed": False,
        "fresh_heldout_26000_26049_accessed": False,
        "fresh_heldout_27000_27049_accessed": False,
        "fresh_heldout_32000_32049_accessed": False,
        "calibration_opened": False,
        "heldout_opened": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    manifest["manifest_sha256"] = _sha256_payload_excluding(manifest, "manifest_sha256")
    return manifest


def _v10_runtime_manifest_for_split(*, fresh_manifest: dict[str, Any], split: str) -> dict[str, Any]:
    if split not in {"calibration", "held_out"}:
        raise ValueError("v0_10_runtime_manifest_unknown_split")
    rows = [
        {**row, "source_split": split, "semantic_eval_split": split, "split": "held_out"}
        for row in fresh_manifest.get("scenarios", [])
        if isinstance(row, dict) and row.get("split") == split
    ]
    if not rows:
        raise ValueError(f"v0_10_runtime_manifest_missing_{split}_rows")
    seeds = [int(row["seed"]) for row in rows]
    if split == "calibration":
        if seeds != list(V10_FRESH_CALIBRATION_RANGE):
            raise ValueError("v0_10_calibration_seed_range_mismatch")
        if any(_v10_burned_seed_range_accessed(seed) for seed in seeds):
            raise ValueError("v0_10_runtime_manifest_reuses_burned_calibration_seed_range")
    if split == "held_out":
        if seeds != list(V10_FRESH_HELDOUT_RANGE):
            raise ValueError("v0_10_heldout_seed_range_mismatch")
        if any(_v10_burned_seed_range_accessed(seed) for seed in seeds):
            raise ValueError("v0_10_runtime_manifest_reuses_burned_heldout_seed_range")
    manifest = {
        "schema_version": fresh_manifest["schema_version"],
        "policy_slice": V10_POLICY_SLICE_ID,
        "slice_id": V10_SLICE_ID,
        "parent_policy_slice": V09_POLICY_SLICE_ID,
        "scenario_profile": "v0_10",
        "runtime_split": split,
        "task_type": fresh_manifest["task_type"],
        "success_metric": fresh_manifest["success_metric"],
        "success_authority": fresh_manifest["success_authority"],
        "source_fresh_manifest_sha256": fresh_manifest["manifest_sha256"],
        "scenarios": rows,
        "burned_heldout_seed_ranges": fresh_manifest["burned_heldout_seed_ranges"],
        "burned_calibration_seed_ranges": fresh_manifest["burned_calibration_seed_ranges"],
        "heldout_21000_21049_accessed": False,
        "fresh_heldout_24000_24049_accessed": False,
        "fresh_heldout_26000_26049_accessed": False,
        "fresh_heldout_27000_27049_accessed": False,
        "fresh_heldout_32000_32049_accessed": split == "held_out",
        "fresh_calibration_26500_26529_accessed": True,
        "fresh_calibration_27500_27529_accessed": True,
        "fresh_calibration_28000_28029_accessed": True,
        "fresh_calibration_28500_28529_accessed": True,
        "fresh_calibration_29000_29029_accessed": True,
        "fresh_calibration_30000_30029_accessed": True,
        "fresh_calibration_31000_31029_accessed": True,
        "calibration_opened": True,
        "heldout_opened": split == "held_out",
        "proof_authority": split == "held_out",
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    manifest["manifest_sha256"] = _sha256_payload_excluding(manifest, "manifest_sha256")
    return manifest


def _load_v10_policy_artifacts(output_dir: Path) -> dict[str, dict[str, Any]]:
    child_dir = output_dir / V10_CHILD_OUTPUT_DIRNAME
    candidate_path = child_dir / "candidate_policy_artifact_v0_10.json"
    baseline_path = child_dir / "baseline_policy_artifact_v0_10.json"
    if not candidate_path.exists() or not baseline_path.exists():
        raise ValueError("missing_v0_10_policy_artifacts")
    baseline = read_json(baseline_path)
    candidate = read_json(candidate_path)
    reasons: list[str] = []
    for role, policy in (("baseline", baseline), ("candidate", candidate)):
        if policy.get("policy_slice") != V10_POLICY_SLICE_ID:
            reasons.append(f"{role}_policy_slice_mismatch")
        if policy.get("parent_policy_slice") != V09_POLICY_SLICE_ID:
            reasons.append(f"{role}_parent_policy_slice_mismatch")
        if policy.get("fresh_calibration_31000_31029_accessed") is not False:
            reasons.append(f"{role}_fresh_calibration_accessed_before_runtime")
        if policy.get("fresh_heldout_32000_32049_accessed") is not False:
            reasons.append(f"{role}_fresh_heldout_accessed_before_closure")
        expected_hash = _sha256_payload_excluding(policy, "policy_artifact_sha256")
        if policy.get("policy_artifact_sha256") != expected_hash:
            reasons.append(f"{role}_policy_hash_mismatch")
    equality_keys = (
        "selected_action_adapter_id",
        "trainer",
        "trainer_family",
        "policy_class",
        "feature_schema",
        "feature_schema_version",
        "phase_schema",
        "action_schema",
        "base_servo_config_sha256",
        "authority_filter_config_sha256",
        "final_post_adapter_authority_config_sha256",
        "final_post_adapter_xy_authority_config_sha256",
        "shared_hysteresis_authority_config_sha256",
        "capture_conditioned_progress_authority_config_sha256",
        "horizon_reserved_capture_authority_config_sha256",
        "deadline_precedence_horizon_authority_config_sha256",
        "early_centered_z_open_safe_entry_config_sha256",
        "comparator_stress_config_sha256",
    )
    for key in equality_keys:
        if baseline.get(key) != candidate.get(key):
            reasons.append(f"peer_{key}_mismatch")
    if reasons:
        raise ValueError("v0_10_policy_peer_fairness_failed: " + ",".join(reasons))
    return {
        "baseline": {**baseline, "path": str(baseline_path)},
        "candidate": {**candidate, "path": str(candidate_path)},
    }


def _write_v10_calibration_external_rollouts(
    *,
    output_dir: Path,
    baseline_rollouts: list[dict[str, Any]],
    candidate_rollouts: list[dict[str, Any]],
) -> dict[str, str]:
    rollout_dir = output_dir / "calibration_external_rollouts"
    rollout_dir.mkdir(parents=True, exist_ok=True)
    baseline_path = rollout_dir / "baseline_calibration_rollouts_v0_10.json"
    candidate_path = rollout_dir / "candidate_calibration_rollouts_v0_10.json"
    write_json(baseline_path, baseline_rollouts)
    write_json(candidate_path, candidate_rollouts)
    return {"baseline": str(baseline_path), "candidate": str(candidate_path)}


def derive_v10_calibration_presignal_gate(
    *,
    baseline_rollouts: list[dict[str, Any]],
    candidate_rollouts: list[dict[str, Any]],
    runtime_gate: dict[str, Any],
    runtime_metadata: dict[str, Any],
    trace_paths: dict[str, list[str]],
) -> dict[str, Any]:
    gate = derive_v07h_calibration_presignal_gate(
        baseline_rollouts=baseline_rollouts,
        candidate_rollouts=candidate_rollouts,
        runtime_gate=runtime_gate,
        runtime_metadata=runtime_metadata,
        trace_paths=trace_paths,
        output_dir=Path("."),
    )
    baseline_rate = float(gate["baseline_calibration_success_rate"])
    candidate_rate = float(gate["candidate_calibration_success_rate"])
    success_gap = round(candidate_rate - baseline_rate, 12)
    attribution = _v08d_attribution_preservation_metrics(trace_paths)
    failure_reason = ""
    if gate.get("heldout_21000_21049_accessed") is True:
        failure_reason = "protected_heldout_seed_accessed"
    elif runtime_gate.get("passed") is not True or runtime_metadata.get("runtime_backend") != "isaac_runtime":
        failure_reason = "calibration_runtime_gate_not_passed"
    elif (
        int(gate["baseline_calibration_rollout_count"]) < V07H_CALIBRATION_ROLLOUTS_PER_POLICY
        or int(gate["candidate_calibration_rollout_count"]) < V07H_CALIBRATION_ROLLOUTS_PER_POLICY
    ):
        failure_reason = "calibration_rollout_count_below_minimum"
    elif candidate_rate < V10_CALIBRATION_SUCCESS_MINIMUM:
        failure_reason = "candidate_calibration_success_below_v0_10_minimum"
    elif candidate_rate <= baseline_rate:
        failure_reason = "candidate_calibration_not_above_baseline"
    elif success_gap < V10_CALIBRATION_UPLIFT_MINIMUM:
        failure_reason = "candidate_baseline_success_gap_below_v0_10_minimum"
    elif attribution["attribution_preservation_gate_passed"] is not True:
        failure_reason = "attribution_preservation_failed"
    passed = failure_reason == ""
    gate.update(
        {
            "schema_version": V10_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
            "policy_slice": V10_POLICY_SLICE_ID,
            "slice_id": V10_SLICE_ID,
            "parent_policy_slice": V09_POLICY_SLICE_ID,
            "passed": bool(passed),
            "failure_reason": failure_reason,
            "heldout_allowed": bool(passed),
            "candidate_baseline_success_gap": success_gap,
            "candidate_success_gap_minimum": V10_CALIBRATION_UPLIFT_MINIMUM,
            "candidate_calibration_success_minimum": V10_CALIBRATION_SUCCESS_MINIMUM,
            "attribution_preservation": attribution,
            "attribution_preservation_gate_passed": bool(
                attribution["attribution_preservation_gate_passed"]
            ),
            "fresh_calibration_26500_26529_accessed": True,
            "fresh_calibration_27500_27529_accessed": True,
            "fresh_calibration_28000_28029_accessed": True,
            "fresh_calibration_28500_28529_accessed": True,
            "fresh_calibration_29000_29029_accessed": True,
            "fresh_calibration_30000_30029_accessed": True,
            "fresh_calibration_31000_31029_accessed": True,
            "fresh_heldout_24000_24049_accessed": False,
            "fresh_heldout_26000_26049_accessed": False,
            "fresh_heldout_27000_27049_accessed": False,
            "fresh_heldout_32000_32049_accessed": False,
            "source": "v0_10_fresh_comparator_stress_calibration_runtime",
            "mvp2_closed": False,
            "policy_uplift_proven": False,
        }
    )
    gate["calibration_presignal_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "calibration_presignal_gate_sha256",
    )
    return gate


def run_v10_fresh_comparator_stress_runtime(
    *,
    output_dir: Path,
    device: str = DEFAULT_ISAAC_DEVICE,
    headless: bool = True,
    isaac_task: str = DEFAULT_ISAAC_TASK,
    max_steps: int = int(SUCCESS_METRIC["max_steps"]),
    action_scale: float = 1.0,
    min_rollouts_per_policy: int = MIN_PROOF_ROLLOUTS_PER_POLICY,
    bootstrap_iterations: int = 2000,
    bootstrap_seed: int = 23,
    backend: Any | None = None,
) -> dict[str, Any]:
    child_dir = output_dir / V10_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    stress_manifest = build_v10_fresh_comparator_stress_slice(output_dir=output_dir)
    if stress_manifest["comparator_stress_gate"].get("passed") is not True:
        return stress_manifest["comparator_stress_gate"]
    fresh_manifest = build_v10_fresh_manifest(output_dir=output_dir, stress_manifest=stress_manifest)
    write_json(child_dir / "v0_10_fresh_manifest.json", fresh_manifest)
    policy_artifacts = _load_v10_policy_artifacts(output_dir)
    baseline_policy = policy_artifacts["baseline"]
    candidate_policy = policy_artifacts["candidate"]
    selected_adapter_id = str(candidate_policy["selected_action_adapter_id"])
    policy_class = str(candidate_policy["policy_class"])
    trainer = str(candidate_policy["trainer"])
    use_single_app_actual_backend = (
        backend is None
        and getattr(IsaacConnectorInsertionEvaluatorBackend, "__name__", "")
        == "IsaacConnectorInsertionEvaluatorBackend"
    )
    evaluator_backend = backend or IsaacConnectorInsertionEvaluatorBackend(
        task=isaac_task,
        device=device,
        headless=headless,
        action_scale=action_scale,
        max_steps=max_steps,
    )
    actual_env = None
    actual_simulation_app = None
    actual_torch = None
    if use_single_app_actual_backend:
        from isaaclab.app import AppLauncher

        app_launcher = AppLauncher(
            {
                "headless": headless,
                "device": device,
                "enable_cameras": False,
            }
        )
        actual_simulation_app = app_launcher.app

        import gymnasium as gym
        import torch as torch_module

        import isaaclab_tasks  # noqa: F401
        from isaaclab_tasks.utils import parse_env_cfg

        env_cfg = parse_env_cfg(isaac_task, device=device, num_envs=1)
        actual_env = gym.make(isaac_task, cfg=env_cfg).unwrapped
        actual_torch = torch_module

    def run_runtime_manifest(
        *,
        manifest: dict[str, Any],
        runtime_output_dir: Path,
        rollouts_per_policy: int,
    ) -> BackendResult:
        if actual_env is not None:
            return _run_v08a_manifest_with_existing_isaac(
                evaluator_backend=evaluator_backend,
                env=actual_env,
                simulation_app=actual_simulation_app,
                torch_module=actual_torch,
                manifest=manifest,
                output_dir=runtime_output_dir,
                min_rollouts_per_policy=rollouts_per_policy,
                policy_artifacts=policy_artifacts,
            )
        return evaluator_backend.run(
            manifest=manifest,
            output_dir=runtime_output_dir,
            min_rollouts_per_policy=rollouts_per_policy,
            deterministic_profile="candidate_positive",
            policy_artifacts=policy_artifacts,
        )

    calibration_manifest = _v10_runtime_manifest_for_split(
        fresh_manifest=fresh_manifest,
        split="calibration",
    )
    write_json(child_dir / "calibration_runtime_manifest_v0_10.json", calibration_manifest)
    calibration_result = run_runtime_manifest(
        manifest=calibration_manifest,
        runtime_output_dir=child_dir / "isaac_runtime_fresh_calibration_v0_10",
        rollouts_per_policy=V07H_CALIBRATION_ROLLOUTS_PER_POLICY,
    )
    calibration_rollout_paths = _write_v10_calibration_external_rollouts(
        output_dir=child_dir,
        baseline_rollouts=list(calibration_result.baseline_rollouts),
        candidate_rollouts=list(calibration_result.candidate_rollouts),
    )
    calibration_trace_paths = {
        "baseline": list(calibration_result.baseline_trace_paths),
        "candidate": list(calibration_result.candidate_trace_paths),
    }
    calibration_gate = derive_v10_calibration_presignal_gate(
        baseline_rollouts=list(calibration_result.baseline_rollouts),
        candidate_rollouts=list(calibration_result.candidate_rollouts),
        runtime_gate=dict(calibration_result.runtime_gate),
        runtime_metadata=dict(calibration_result.runtime_metadata),
        trace_paths=calibration_trace_paths,
    )
    calibration_gate["calibration_runtime_manifest_sha256"] = calibration_manifest["manifest_sha256"]
    calibration_gate["baseline_calibration_rollout_path"] = calibration_rollout_paths["baseline"]
    calibration_gate["candidate_calibration_rollout_path"] = calibration_rollout_paths["candidate"]
    calibration_gate["calibration_presignal_gate_sha256"] = _sha256_payload_excluding(
        calibration_gate,
        "calibration_presignal_gate_sha256",
    )
    write_json(child_dir / "calibration_presignal_gate_v0_10.json", calibration_gate)
    write_json(
        output_dir / "calibration_presignal_gate.json",
        {
            "schema_version": V10_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
            "policy_slice": V10_POLICY_SLICE_ID,
            "slice_id": V10_SLICE_ID,
            "passed": calibration_gate["passed"],
            "source_gate_path": f"{V10_CHILD_OUTPUT_DIRNAME}/calibration_presignal_gate_v0_10.json",
            "calibration_opened": True,
            "heldout_opened": False,
            "heldout_21000_21049_accessed": False,
            "fresh_heldout_24000_24049_accessed": False,
            "fresh_heldout_26000_26049_accessed": False,
            "fresh_heldout_27000_27049_accessed": False,
            "fresh_heldout_32000_32049_accessed": False,
            "fresh_calibration_26500_26529_accessed": True,
            "fresh_calibration_27500_27529_accessed": True,
            "fresh_calibration_28000_28029_accessed": True,
            "fresh_calibration_28500_28529_accessed": True,
            "fresh_calibration_29000_29029_accessed": True,
            "fresh_calibration_30000_30029_accessed": True,
            "fresh_calibration_31000_31029_accessed": True,
            "heldout_allowed": calibration_gate["heldout_allowed"],
            "mvp2_closed": False,
            "policy_uplift_proven": False,
        },
    )
    if calibration_gate.get("passed") is not True:
        calibration_gate["mvp2_closed"] = False
        calibration_gate["policy_uplift_proven"] = False
        if actual_env is not None:
            actual_env.close()
        return calibration_gate

    selection = _v08a_calibration_selection_report(output_dir)
    training_scenario_ids = _v08a_training_scenario_ids(output_dir)
    heldout_manifest = _v10_runtime_manifest_for_split(
        fresh_manifest=fresh_manifest,
        split="held_out",
    )
    write_json(child_dir / "heldout_runtime_manifest_v0_10.json", heldout_manifest)
    heldout_leakage_guard = validate_no_heldout_leakage(
        manifest=heldout_manifest,
        training_scenario_ids=training_scenario_ids,
        curation_tuning_scenario_ids=[],
        threshold_tuning_scenario_ids=[],
        hyperparameter_scenario_ids=[],
        calibration_selector_scenario_ids=[str(item) for item in selection.get("calibration_scenario_ids", [])],
    )
    if heldout_leakage_guard["passed"] is not True:
        raise ValueError("v0_10_fresh_heldout_leakage_guard_failed")
    baseline_view = _existing_train_view(
        child_dir / "baseline_uncurated_stress_train_v0_10.hdf5",
        view_id="baseline_uncurated_stress_v0_10",
    )
    candidate_view = _existing_train_view(
        child_dir / "candidate_curated_train_v0_10.hdf5",
        view_id="candidate_curated_v0_10_fresh_comparator_stress",
    )
    bridge_dir = _write_learning_harness_bridge(
        output_dir=child_dir,
        manifest=heldout_manifest,
        baseline_view=baseline_view,
        candidate_view=candidate_view,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    heldout_rollouts_per_policy = max(
        int(min_rollouts_per_policy),
        STRONGER_PUBLIC_ROLLOUTS_PER_POLICY,
        len(V10_FRESH_HELDOUT_RANGE),
    )
    heldout_result = run_runtime_manifest(
        manifest=heldout_manifest,
        runtime_output_dir=child_dir / "isaac_runtime_fresh_heldout_v0_10",
        rollouts_per_policy=heldout_rollouts_per_policy,
    )
    runtime_gate = dict(heldout_result.runtime_gate)
    actual_rollouts_per_policy = min(
        len(heldout_result.baseline_rollouts),
        len(heldout_result.candidate_rollouts),
    )
    runtime_gate["actual_baseline_rollouts"] = len(heldout_result.baseline_rollouts)
    runtime_gate["actual_candidate_rollouts"] = len(heldout_result.candidate_rollouts)
    runtime_gate["actual_rollouts_per_policy"] = actual_rollouts_per_policy
    combined_rollouts = list(heldout_result.baseline_rollouts) + list(heldout_result.candidate_rollouts)
    if any(_v10_burned_seed_range_accessed(int(rollout.get("seed", -1))) for rollout in combined_rollouts):
        raise ValueError("v0_10_burned_seed_accessed")
    heldout_suite = _heldout_suite(heldout_manifest)
    baseline_rollouts_path = _write_external_rollout_json(
        output_dir=child_dir,
        role="baseline",
        policy_artifact=baseline_policy,
        train_view=baseline_view,
        heldout_suite=heldout_suite,
        backend_result=heldout_result,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    candidate_rollouts_path = _write_external_rollout_json(
        output_dir=child_dir,
        role="candidate",
        policy_artifact=candidate_policy,
        train_view=candidate_view,
        heldout_suite=heldout_suite,
        backend_result=heldout_result,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    learning_report = _run_learning_validator(
        output_dir=child_dir,
        bridge_dir=bridge_dir,
        baseline_rollouts_path=baseline_rollouts_path,
        candidate_rollouts_path=candidate_rollouts_path,
        min_rollouts_per_policy=MIN_PROOF_ROLLOUTS_PER_POLICY,
        bootstrap_iterations=bootstrap_iterations,
        bootstrap_seed=bootstrap_seed,
        policy_class=policy_class,
        trainer=trainer,
    )
    train_generation_runtime_gate, train_gate_sha256 = load_v07a2_parent_train_generation_gate(output_dir)
    closure = derive_mvp2c_closure(
        learning_report=learning_report,
        runtime_gate=runtime_gate,
        train_generation_runtime_gate=train_generation_runtime_gate,
        calibration_selection_report=selection,
        heldout_leakage_guard=heldout_leakage_guard,
        actual_rollouts_per_policy=actual_rollouts_per_policy,
    )
    confidence_interval_report = _bootstrap_uplift_ci(
        baseline_rollouts=list(heldout_result.baseline_rollouts),
        candidate_rollouts=list(heldout_result.candidate_rollouts),
        iterations=bootstrap_iterations,
        seed=bootstrap_seed,
    )
    gate = {
        "schema_version": V10_HELDOUT_CLOSURE_SCHEMA_VERSION,
        "policy_slice": V10_POLICY_SLICE_ID,
        "slice_id": V10_SLICE_ID,
        "parent_policy_slice": V09_POLICY_SLICE_ID,
        "source_fresh_manifest_sha256": fresh_manifest["manifest_sha256"],
        "comparator_stress_config_sha256": stress_manifest["comparator_stress_config"][
            "comparator_stress_config_sha256"
        ],
        "comparator_stress_gate_sha256": stress_manifest["comparator_stress_gate"][
            "comparator_stress_gate_sha256"
        ],
        "parent_train_generation_runtime_gate_sha256": train_gate_sha256,
        "fresh_calibration_presignal_gate_sha256": calibration_gate["calibration_presignal_gate_sha256"],
        "runtime_backend": heldout_result.runtime_backend,
        "proof_runtime": heldout_result.proof_runtime,
        "runtime_gate": runtime_gate,
        "actual_rollouts_per_policy": actual_rollouts_per_policy,
        "baseline_success_rate": learning_report.get("baseline_success_rate"),
        "candidate_success_rate": learning_report.get("candidate_success_rate"),
        "curated_vs_uncurated_uplift": learning_report.get("curated_vs_uncurated_uplift"),
        "learning_report_path": str(
            child_dir / "mvp2_learning_proven_policy_eval" / "mvp2_learning_proven_report.json"
        ),
        "baseline_external_rollouts": str(baseline_rollouts_path),
        "candidate_external_rollouts": str(candidate_rollouts_path),
        "confidence_interval_report": confidence_interval_report,
        "stronger_public_evidence_target_passed": _derive_public_evidence_target(
            actual_rollouts_per_policy=actual_rollouts_per_policy,
            confidence_interval_report=confidence_interval_report,
        ),
        "calibration_opened": True,
        "heldout_opened": True,
        "heldout_21000_21049_accessed": False,
        "fresh_heldout_24000_24049_accessed": False,
        "fresh_heldout_26000_26049_accessed": False,
        "fresh_heldout_27000_27049_accessed": False,
        "fresh_heldout_32000_32049_accessed": True,
        "fresh_calibration_26500_26529_accessed": True,
        "fresh_calibration_27500_27529_accessed": True,
        "fresh_calibration_28000_28029_accessed": True,
        "fresh_calibration_28500_28529_accessed": True,
        "fresh_calibration_29000_29029_accessed": True,
        "fresh_calibration_30000_30029_accessed": True,
        "fresh_calibration_31000_31029_accessed": True,
        "same_heldout_reuse_allowed_for_closure": False,
        "heldout_leakage_guard": heldout_leakage_guard,
        "calibration_selection_report_sha256": _sha256_file(output_dir / "calibration_selection_report.json"),
        "selected_action_adapter_id": selected_adapter_id,
        "same_adapter_used_for_baseline_and_candidate": True,
        "same_policy_class": baseline_policy.get("policy_class") == candidate_policy.get("policy_class"),
        "same_trainer": baseline_policy.get("trainer") == candidate_policy.get("trainer"),
        "same_feature_schema": baseline_policy.get("feature_schema") == candidate_policy.get("feature_schema"),
        "mvp2_closed": closure["mvp2_closed"],
        "mvp2c_close_minimum_passed": closure["mvp2c_close_minimum_passed"],
        "policy_uplift_proven": closure["learning_proven"],
        "proof_eligible": closure["proof_eligible"],
        "blockers": closure["blockers"] + list(learning_report.get("blockers") or []),
        "non_claims": {
            "deployable_real_robot_policy": False,
            "visual_policy_performance": False,
            "real_robot_success": False,
            "physical_robot_readiness": False,
            "universal_robot_support": False,
            "hmd_openxr_readiness": False,
        },
    }
    gate["heldout_closure_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "heldout_closure_gate_sha256",
    )
    write_json(child_dir / "heldout_closure_gate_v0_10.json", gate)
    write_json(output_dir / "heldout_closure_gate.json", gate)
    if actual_env is not None:
        actual_env.close()
    return gate


def _v11_burned_seed_range_accessed(seed: int) -> bool:
    seed_int = int(seed)
    return (
        _v10_burned_seed_range_accessed(seed_int)
        or seed_int in V10_FRESH_CALIBRATION_RANGE
        or seed_int in V10_FRESH_HELDOUT_RANGE
    )


def build_v11_fresh_manifest(*, output_dir: Path, low_floor_manifest: dict[str, Any]) -> dict[str, Any]:
    gate = low_floor_manifest.get("low_floor_comparator_gate", {})
    if gate.get("passed") is not True:
        raise ValueError("v0_11_low_floor_comparator_gate_not_passed")
    calibration_rows = [_scenario_row(split="calibration", seed=seed) for seed in V11_FRESH_CALIBRATION_RANGE]
    heldout_rows = [_scenario_row(split="held_out", seed=seed) for seed in V11_FRESH_HELDOUT_RANGE]
    if any(_v11_burned_seed_range_accessed(int(row["seed"])) for row in calibration_rows):
        raise ValueError("v0_11_fresh_manifest_reuses_burned_calibration_seed_range")
    if any(_v11_burned_seed_range_accessed(int(row["seed"])) for row in heldout_rows):
        raise ValueError("v0_11_fresh_manifest_reuses_burned_heldout_seed_range")
    manifest = {
        "schema_version": V11_MANIFEST_SCHEMA_VERSION,
        "policy_slice": V11_POLICY_SLICE_ID,
        "slice_id": V11_SLICE_ID,
        "parent_policy_slice": V10_POLICY_SLICE_ID,
        "source_policy_slice": V10C_POLICY_SLICE_ID,
        "scenario_profile": "v0_11",
        "task_type": "connector_insertion",
        "success_metric": SUCCESS_METRIC,
        "success_authority": V06_ENV_NATIVE_SUCCESS_AUTHORITY,
        "source_v11_low_floor_manifest_sha256": low_floor_manifest[
            "v0_11_low_floor_comparator_manifest_sha256"
        ],
        "source_v11_low_floor_gate_sha256": gate["low_floor_comparator_gate_sha256"],
        "low_floor_comparator_config_sha256": gate["low_floor_comparator_config_sha256"],
        "scenarios": calibration_rows + heldout_rows,
        "fresh_split_manifest": {
            "calibration": {
                "seed_range": [min(V11_FRESH_CALIBRATION_RANGE), max(V11_FRESH_CALIBRATION_RANGE)],
                "scenario_ids": [row["scenario_id"] for row in calibration_rows],
                "count": len(calibration_rows),
            },
            "held_out": {
                "seed_range": [min(V11_FRESH_HELDOUT_RANGE), max(V11_FRESH_HELDOUT_RANGE)],
                "scenario_ids": [row["scenario_id"] for row in heldout_rows],
                "count": len(heldout_rows),
            },
        },
        "burned_heldout_seed_ranges": [
            list(V07A2_PROTECTED_HELDOUT_SEED_RANGE),
            [min(V08A_FRESH_HELDOUT_RANGE), max(V08A_FRESH_HELDOUT_RANGE)],
            [min(V08B_FRESH_HELDOUT_RANGE), max(V08B_FRESH_HELDOUT_RANGE)],
            [min(V09_FRESH_HELDOUT_RANGE), max(V09_FRESH_HELDOUT_RANGE)],
            [min(V10_FRESH_HELDOUT_RANGE), max(V10_FRESH_HELDOUT_RANGE)],
        ],
        "burned_calibration_seed_ranges": [
            [min(V08D_FRESH_CALIBRATION_RANGE), max(V08D_FRESH_CALIBRATION_RANGE)],
            [min(V08F_FRESH_CALIBRATION_RANGE), max(V08F_FRESH_CALIBRATION_RANGE)],
            [min(V08G_FRESH_CALIBRATION_RANGE), max(V08G_FRESH_CALIBRATION_RANGE)],
            [min(V08H_FRESH_CALIBRATION_RANGE), max(V08H_FRESH_CALIBRATION_RANGE)],
            [min(V08K_FRESH_CALIBRATION_RANGE), max(V08K_FRESH_CALIBRATION_RANGE)],
            [min(V09_FRESH_CALIBRATION_RANGE), max(V09_FRESH_CALIBRATION_RANGE)],
            [min(V10_FRESH_CALIBRATION_RANGE), max(V10_FRESH_CALIBRATION_RANGE)],
        ],
        "fresh_calibration_30000_30029_accessed": True,
        "fresh_calibration_31000_31029_accessed": True,
        "fresh_calibration_33000_33029_accessed": False,
        "fresh_heldout_32000_32049_accessed": False,
        "fresh_heldout_34000_34049_accessed": False,
        "calibration_opened": False,
        "heldout_opened": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    manifest["manifest_sha256"] = _sha256_payload_excluding(manifest, "manifest_sha256")
    return manifest


def _v11_runtime_manifest_for_split(*, fresh_manifest: dict[str, Any], split: str) -> dict[str, Any]:
    if split not in {"calibration", "held_out"}:
        raise ValueError("v0_11_runtime_manifest_unknown_split")
    rows = [
        {**row, "source_split": split, "semantic_eval_split": split, "split": "held_out"}
        for row in fresh_manifest.get("scenarios", [])
        if isinstance(row, dict) and row.get("split") == split
    ]
    if not rows:
        raise ValueError(f"v0_11_runtime_manifest_missing_{split}_rows")
    seeds = [int(row["seed"]) for row in rows]
    if split == "calibration":
        if seeds != list(V11_FRESH_CALIBRATION_RANGE):
            raise ValueError("v0_11_calibration_seed_range_mismatch")
        if any(_v11_burned_seed_range_accessed(seed) for seed in seeds):
            raise ValueError("v0_11_runtime_manifest_reuses_burned_calibration_seed_range")
    if split == "held_out":
        if seeds != list(V11_FRESH_HELDOUT_RANGE):
            raise ValueError("v0_11_heldout_seed_range_mismatch")
        if any(_v11_burned_seed_range_accessed(seed) for seed in seeds):
            raise ValueError("v0_11_runtime_manifest_reuses_burned_heldout_seed_range")
    manifest = {
        "schema_version": fresh_manifest["schema_version"],
        "policy_slice": V11_POLICY_SLICE_ID,
        "slice_id": V11_SLICE_ID,
        "parent_policy_slice": V10_POLICY_SLICE_ID,
        "scenario_profile": "v0_11",
        "runtime_split": split,
        "task_type": fresh_manifest["task_type"],
        "success_metric": fresh_manifest["success_metric"],
        "success_authority": fresh_manifest["success_authority"],
        "source_fresh_manifest_sha256": fresh_manifest["manifest_sha256"],
        "scenarios": rows,
        "burned_heldout_seed_ranges": fresh_manifest["burned_heldout_seed_ranges"],
        "burned_calibration_seed_ranges": fresh_manifest["burned_calibration_seed_ranges"],
        "fresh_calibration_30000_30029_accessed": True,
        "fresh_calibration_31000_31029_accessed": True,
        "fresh_calibration_33000_33029_accessed": True,
        "fresh_heldout_32000_32049_accessed": False,
        "fresh_heldout_34000_34049_accessed": split == "held_out",
        "calibration_opened": True,
        "heldout_opened": split == "held_out",
        "proof_authority": split == "held_out",
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    manifest["manifest_sha256"] = _sha256_payload_excluding(manifest, "manifest_sha256")
    return manifest


def _load_v11_policy_artifacts(output_dir: Path) -> dict[str, dict[str, Any]]:
    child_dir = output_dir / V11_CHILD_OUTPUT_DIRNAME
    candidate_path = child_dir / "candidate_policy_artifact_v0_11.json"
    baseline_path = child_dir / "baseline_policy_artifact_v0_11.json"
    if not candidate_path.exists() or not baseline_path.exists():
        raise ValueError("missing_v0_11_policy_artifacts")
    baseline = read_json(baseline_path)
    candidate = read_json(candidate_path)
    reasons: list[str] = []
    for role, policy in (("baseline", baseline), ("candidate", candidate)):
        if policy.get("policy_slice") != V11_POLICY_SLICE_ID:
            reasons.append(f"{role}_policy_slice_mismatch")
        if policy.get("parent_policy_slice") != V10_POLICY_SLICE_ID:
            reasons.append(f"{role}_parent_policy_slice_mismatch")
        if policy.get("fresh_calibration_33000_33029_accessed") is not False:
            reasons.append(f"{role}_fresh_calibration_accessed_before_runtime")
        if policy.get("fresh_heldout_34000_34049_accessed") is not False:
            reasons.append(f"{role}_fresh_heldout_accessed_before_closure")
        expected_hash = _sha256_payload_excluding(policy, "policy_artifact_sha256")
        if policy.get("policy_artifact_sha256") != expected_hash:
            reasons.append(f"{role}_policy_hash_mismatch")
    equality_keys = (
        "selected_action_adapter_id",
        "trainer",
        "trainer_family",
        "policy_class",
        "feature_schema",
        "feature_schema_version",
        "phase_schema",
        "action_schema",
        "base_servo_config_sha256",
        "authority_filter_config_sha256",
        "final_post_adapter_authority_config_sha256",
        "final_post_adapter_xy_authority_config_sha256",
        "shared_hysteresis_authority_config_sha256",
        "capture_conditioned_progress_authority_config_sha256",
        "horizon_reserved_capture_authority_config_sha256",
        "deadline_precedence_horizon_authority_config_sha256",
        "early_centered_z_open_safe_entry_config_sha256",
        "low_floor_comparator_config_sha256",
    )
    for key in equality_keys:
        if baseline.get(key) != candidate.get(key):
            reasons.append(f"peer_{key}_mismatch")
    if reasons:
        raise ValueError("v0_11_policy_peer_fairness_failed: " + ",".join(reasons))
    return {
        "baseline": {**baseline, "path": str(baseline_path)},
        "candidate": {**candidate, "path": str(candidate_path)},
    }


def _write_v11_calibration_external_rollouts(
    *,
    output_dir: Path,
    baseline_rollouts: list[dict[str, Any]],
    candidate_rollouts: list[dict[str, Any]],
) -> dict[str, str]:
    rollout_dir = output_dir / "calibration_external_rollouts"
    rollout_dir.mkdir(parents=True, exist_ok=True)
    baseline_path = rollout_dir / "baseline_calibration_rollouts_v0_11.json"
    candidate_path = rollout_dir / "candidate_calibration_rollouts_v0_11.json"
    write_json(baseline_path, baseline_rollouts)
    write_json(candidate_path, candidate_rollouts)
    return {"baseline": str(baseline_path), "candidate": str(candidate_path)}


def derive_v11_calibration_presignal_gate(
    *,
    baseline_rollouts: list[dict[str, Any]],
    candidate_rollouts: list[dict[str, Any]],
    runtime_gate: dict[str, Any],
    runtime_metadata: dict[str, Any],
    trace_paths: dict[str, list[str]],
) -> dict[str, Any]:
    gate = derive_v07h_calibration_presignal_gate(
        baseline_rollouts=baseline_rollouts,
        candidate_rollouts=candidate_rollouts,
        runtime_gate=runtime_gate,
        runtime_metadata=runtime_metadata,
        trace_paths=trace_paths,
        output_dir=Path("."),
    )
    baseline_rate = float(gate["baseline_calibration_success_rate"])
    candidate_rate = float(gate["candidate_calibration_success_rate"])
    success_gap = round(candidate_rate - baseline_rate, 12)
    attribution = _v08d_attribution_preservation_metrics(trace_paths)
    failure_reason = ""
    if runtime_gate.get("passed") is not True or runtime_metadata.get("runtime_backend") != "isaac_runtime":
        failure_reason = "calibration_runtime_gate_not_passed"
    elif (
        int(gate["baseline_calibration_rollout_count"]) < V07H_CALIBRATION_ROLLOUTS_PER_POLICY
        or int(gate["candidate_calibration_rollout_count"]) < V07H_CALIBRATION_ROLLOUTS_PER_POLICY
    ):
        failure_reason = "calibration_rollout_count_below_minimum"
    elif baseline_rate > V11_BASELINE_FLOOR_SUCCESS_MAXIMUM:
        failure_reason = "baseline_calibration_success_floor_above_v0_11_maximum"
    elif candidate_rate < V11_CALIBRATION_SUCCESS_MINIMUM:
        failure_reason = "candidate_calibration_success_below_v0_11_minimum"
    elif candidate_rate <= baseline_rate:
        failure_reason = "candidate_calibration_not_above_baseline"
    elif success_gap < V11_CALIBRATION_UPLIFT_MINIMUM:
        failure_reason = "candidate_baseline_success_gap_below_v0_11_minimum"
    elif attribution["attribution_preservation_gate_passed"] is not True:
        failure_reason = "attribution_preservation_failed"
    passed = failure_reason == ""
    gate.update(
        {
            "schema_version": V11_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
            "policy_slice": V11_POLICY_SLICE_ID,
            "slice_id": V11_SLICE_ID,
            "parent_policy_slice": V10_POLICY_SLICE_ID,
            "passed": bool(passed),
            "failure_reason": failure_reason,
            "heldout_allowed": bool(passed),
            "candidate_baseline_success_gap": success_gap,
            "candidate_success_gap_minimum": V11_CALIBRATION_UPLIFT_MINIMUM,
            "candidate_calibration_success_minimum": V11_CALIBRATION_SUCCESS_MINIMUM,
            "baseline_calibration_success_floor_maximum": V11_BASELINE_FLOOR_SUCCESS_MAXIMUM,
            "attribution_preservation": attribution,
            "attribution_preservation_gate_passed": bool(
                attribution["attribution_preservation_gate_passed"]
            ),
            "fresh_calibration_33000_33029_accessed": True,
            "fresh_heldout_32000_32049_accessed": False,
            "fresh_heldout_34000_34049_accessed": False,
            "source": "v0_11_low_floor_comparator_calibration_runtime",
            "mvp2_closed": False,
            "policy_uplift_proven": False,
        }
    )
    gate["calibration_presignal_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "calibration_presignal_gate_sha256",
    )
    return gate


def run_v11_low_floor_comparator_runtime(
    *,
    output_dir: Path,
    device: str = DEFAULT_ISAAC_DEVICE,
    headless: bool = True,
    isaac_task: str = DEFAULT_ISAAC_TASK,
    max_steps: int = int(SUCCESS_METRIC["max_steps"]),
    action_scale: float = 1.0,
    min_rollouts_per_policy: int = MIN_PROOF_ROLLOUTS_PER_POLICY,
    bootstrap_iterations: int = 2000,
    bootstrap_seed: int = 23,
    backend: Any | None = None,
) -> dict[str, Any]:
    child_dir = output_dir / V11_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    low_floor_manifest = build_v11_low_floor_comparator_slice(output_dir=output_dir)
    if low_floor_manifest["low_floor_comparator_gate"].get("passed") is not True:
        return low_floor_manifest["low_floor_comparator_gate"]
    fresh_manifest = build_v11_fresh_manifest(
        output_dir=output_dir,
        low_floor_manifest=low_floor_manifest,
    )
    write_json(child_dir / "v0_11_fresh_manifest.json", fresh_manifest)
    policy_artifacts = _load_v11_policy_artifacts(output_dir)
    baseline_policy = policy_artifacts["baseline"]
    candidate_policy = policy_artifacts["candidate"]
    selected_adapter_id = str(candidate_policy["selected_action_adapter_id"])
    policy_class = str(candidate_policy["policy_class"])
    trainer = str(candidate_policy["trainer"])
    use_single_app_actual_backend = (
        backend is None
        and getattr(IsaacConnectorInsertionEvaluatorBackend, "__name__", "")
        == "IsaacConnectorInsertionEvaluatorBackend"
    )
    evaluator_backend = backend or IsaacConnectorInsertionEvaluatorBackend(
        task=isaac_task,
        device=device,
        headless=headless,
        action_scale=action_scale,
        max_steps=max_steps,
    )
    actual_env = None
    actual_simulation_app = None
    actual_torch = None
    if use_single_app_actual_backend:
        from isaaclab.app import AppLauncher

        app_launcher = AppLauncher(
            {
                "headless": headless,
                "device": device,
                "enable_cameras": False,
            }
        )
        actual_simulation_app = app_launcher.app

        import gymnasium as gym
        import torch as torch_module

        import isaaclab_tasks  # noqa: F401
        from isaaclab_tasks.utils import parse_env_cfg

        env_cfg = parse_env_cfg(isaac_task, device=device, num_envs=1)
        actual_env = gym.make(isaac_task, cfg=env_cfg).unwrapped
        actual_torch = torch_module

    def run_runtime_manifest(
        *,
        manifest: dict[str, Any],
        runtime_output_dir: Path,
        rollouts_per_policy: int,
    ) -> BackendResult:
        if actual_env is not None:
            return _run_v08a_manifest_with_existing_isaac(
                evaluator_backend=evaluator_backend,
                env=actual_env,
                simulation_app=actual_simulation_app,
                torch_module=actual_torch,
                manifest=manifest,
                output_dir=runtime_output_dir,
                min_rollouts_per_policy=rollouts_per_policy,
                policy_artifacts=policy_artifacts,
            )
        return evaluator_backend.run(
            manifest=manifest,
            output_dir=runtime_output_dir,
            min_rollouts_per_policy=rollouts_per_policy,
            deterministic_profile="candidate_positive",
            policy_artifacts=policy_artifacts,
        )

    calibration_manifest = _v11_runtime_manifest_for_split(
        fresh_manifest=fresh_manifest,
        split="calibration",
    )
    write_json(child_dir / "calibration_runtime_manifest_v0_11.json", calibration_manifest)
    calibration_result = run_runtime_manifest(
        manifest=calibration_manifest,
        runtime_output_dir=child_dir / "isaac_runtime_fresh_calibration_v0_11",
        rollouts_per_policy=V07H_CALIBRATION_ROLLOUTS_PER_POLICY,
    )
    calibration_rollout_paths = _write_v11_calibration_external_rollouts(
        output_dir=child_dir,
        baseline_rollouts=list(calibration_result.baseline_rollouts),
        candidate_rollouts=list(calibration_result.candidate_rollouts),
    )
    calibration_trace_paths = {
        "baseline": list(calibration_result.baseline_trace_paths),
        "candidate": list(calibration_result.candidate_trace_paths),
    }
    calibration_gate = derive_v11_calibration_presignal_gate(
        baseline_rollouts=list(calibration_result.baseline_rollouts),
        candidate_rollouts=list(calibration_result.candidate_rollouts),
        runtime_gate=dict(calibration_result.runtime_gate),
        runtime_metadata=dict(calibration_result.runtime_metadata),
        trace_paths=calibration_trace_paths,
    )
    calibration_gate["calibration_runtime_manifest_sha256"] = calibration_manifest["manifest_sha256"]
    calibration_gate["baseline_calibration_rollout_path"] = calibration_rollout_paths["baseline"]
    calibration_gate["candidate_calibration_rollout_path"] = calibration_rollout_paths["candidate"]
    calibration_gate["calibration_presignal_gate_sha256"] = _sha256_payload_excluding(
        calibration_gate,
        "calibration_presignal_gate_sha256",
    )
    write_json(child_dir / "calibration_presignal_gate_v0_11.json", calibration_gate)
    write_json(output_dir / "calibration_presignal_gate.json", calibration_gate)
    if calibration_gate.get("passed") is not True:
        calibration_gate["mvp2_closed"] = False
        calibration_gate["policy_uplift_proven"] = False
        if actual_env is not None:
            actual_env.close()
        return calibration_gate

    selection = _v08a_calibration_selection_report(output_dir)
    training_scenario_ids = _v08a_training_scenario_ids(output_dir)
    heldout_manifest = _v11_runtime_manifest_for_split(
        fresh_manifest=fresh_manifest,
        split="held_out",
    )
    write_json(child_dir / "heldout_runtime_manifest_v0_11.json", heldout_manifest)
    heldout_leakage_guard = validate_no_heldout_leakage(
        manifest=heldout_manifest,
        training_scenario_ids=training_scenario_ids,
        curation_tuning_scenario_ids=[],
        threshold_tuning_scenario_ids=[],
        hyperparameter_scenario_ids=[],
        calibration_selector_scenario_ids=[str(item) for item in selection.get("calibration_scenario_ids", [])],
    )
    if heldout_leakage_guard["passed"] is not True:
        raise ValueError("v0_11_fresh_heldout_leakage_guard_failed")
    baseline_view = _existing_train_view(
        child_dir / "baseline_uncurated_low_floor_train_v0_11.hdf5",
        view_id="baseline_uncurated_low_floor_v0_11",
    )
    candidate_view = _existing_train_view(
        child_dir / "candidate_curated_train_v0_11.hdf5",
        view_id="candidate_curated_v0_11_low_floor_comparator",
    )
    bridge_dir = _write_learning_harness_bridge(
        output_dir=child_dir,
        manifest=heldout_manifest,
        baseline_view=baseline_view,
        candidate_view=candidate_view,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    heldout_rollouts_per_policy = max(
        int(min_rollouts_per_policy),
        STRONGER_PUBLIC_ROLLOUTS_PER_POLICY,
        len(V11_FRESH_HELDOUT_RANGE),
    )
    heldout_result = run_runtime_manifest(
        manifest=heldout_manifest,
        runtime_output_dir=child_dir / "isaac_runtime_fresh_heldout_v0_11",
        rollouts_per_policy=heldout_rollouts_per_policy,
    )
    runtime_gate = dict(heldout_result.runtime_gate)
    actual_rollouts_per_policy = min(
        len(heldout_result.baseline_rollouts),
        len(heldout_result.candidate_rollouts),
    )
    runtime_gate["actual_baseline_rollouts"] = len(heldout_result.baseline_rollouts)
    runtime_gate["actual_candidate_rollouts"] = len(heldout_result.candidate_rollouts)
    runtime_gate["actual_rollouts_per_policy"] = actual_rollouts_per_policy
    combined_rollouts = list(heldout_result.baseline_rollouts) + list(heldout_result.candidate_rollouts)
    if any(_v11_burned_seed_range_accessed(int(rollout.get("seed", -1))) for rollout in combined_rollouts):
        raise ValueError("v0_11_burned_seed_accessed")
    heldout_suite = _heldout_suite(heldout_manifest)
    baseline_rollouts_path = _write_external_rollout_json(
        output_dir=child_dir,
        role="baseline",
        policy_artifact=baseline_policy,
        train_view=baseline_view,
        heldout_suite=heldout_suite,
        backend_result=heldout_result,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    candidate_rollouts_path = _write_external_rollout_json(
        output_dir=child_dir,
        role="candidate",
        policy_artifact=candidate_policy,
        train_view=candidate_view,
        heldout_suite=heldout_suite,
        backend_result=heldout_result,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    learning_report = _run_learning_validator(
        output_dir=child_dir,
        bridge_dir=bridge_dir,
        baseline_rollouts_path=baseline_rollouts_path,
        candidate_rollouts_path=candidate_rollouts_path,
        min_rollouts_per_policy=MIN_PROOF_ROLLOUTS_PER_POLICY,
        bootstrap_iterations=bootstrap_iterations,
        bootstrap_seed=bootstrap_seed,
        policy_class=policy_class,
        trainer=trainer,
    )
    train_generation_runtime_gate, train_gate_sha256 = load_v07a2_parent_train_generation_gate(output_dir)
    closure = derive_mvp2c_closure(
        learning_report=learning_report,
        runtime_gate=runtime_gate,
        train_generation_runtime_gate=train_generation_runtime_gate,
        calibration_selection_report=selection,
        heldout_leakage_guard=heldout_leakage_guard,
        actual_rollouts_per_policy=actual_rollouts_per_policy,
    )
    confidence_interval_report = _bootstrap_uplift_ci(
        baseline_rollouts=list(heldout_result.baseline_rollouts),
        candidate_rollouts=list(heldout_result.candidate_rollouts),
        iterations=bootstrap_iterations,
        seed=bootstrap_seed,
    )
    gate = {
        "schema_version": V11_HELDOUT_CLOSURE_SCHEMA_VERSION,
        "policy_slice": V11_POLICY_SLICE_ID,
        "slice_id": V11_SLICE_ID,
        "parent_policy_slice": V10_POLICY_SLICE_ID,
        "source_fresh_manifest_sha256": fresh_manifest["manifest_sha256"],
        "low_floor_comparator_config_sha256": low_floor_manifest["low_floor_comparator_config"][
            "low_floor_comparator_config_sha256"
        ],
        "low_floor_comparator_gate_sha256": low_floor_manifest["low_floor_comparator_gate"][
            "low_floor_comparator_gate_sha256"
        ],
        "parent_train_generation_runtime_gate_sha256": train_gate_sha256,
        "fresh_calibration_presignal_gate_sha256": calibration_gate["calibration_presignal_gate_sha256"],
        "runtime_backend": heldout_result.runtime_backend,
        "proof_runtime": heldout_result.proof_runtime,
        "runtime_gate": runtime_gate,
        "actual_rollouts_per_policy": actual_rollouts_per_policy,
        "baseline_success_rate": learning_report.get("baseline_success_rate"),
        "candidate_success_rate": learning_report.get("candidate_success_rate"),
        "curated_vs_uncurated_uplift": learning_report.get("curated_vs_uncurated_uplift"),
        "learning_report_path": str(
            child_dir / "mvp2_learning_proven_policy_eval" / "mvp2_learning_proven_report.json"
        ),
        "baseline_external_rollouts": str(baseline_rollouts_path),
        "candidate_external_rollouts": str(candidate_rollouts_path),
        "confidence_interval_report": confidence_interval_report,
        "stronger_public_evidence_target_passed": _derive_public_evidence_target(
            actual_rollouts_per_policy=actual_rollouts_per_policy,
            confidence_interval_report=confidence_interval_report,
        ),
        "calibration_opened": True,
        "heldout_opened": True,
        "fresh_heldout_32000_32049_accessed": False,
        "fresh_heldout_34000_34049_accessed": False,
        "fresh_calibration_33000_33029_accessed": True,
        "same_heldout_reuse_allowed_for_closure": False,
        "heldout_leakage_guard": heldout_leakage_guard,
        "calibration_selection_report_sha256": _sha256_file(output_dir / "calibration_selection_report.json"),
        "selected_action_adapter_id": selected_adapter_id,
        "same_adapter_used_for_baseline_and_candidate": True,
        "same_policy_class": baseline_policy.get("policy_class") == candidate_policy.get("policy_class"),
        "same_trainer": baseline_policy.get("trainer") == candidate_policy.get("trainer"),
        "same_feature_schema": baseline_policy.get("feature_schema") == candidate_policy.get("feature_schema"),
        "mvp2_closed": closure["mvp2_closed"],
        "mvp2c_close_minimum_passed": closure["mvp2c_close_minimum_passed"],
        "policy_uplift_proven": closure["learning_proven"],
        "proof_eligible": closure["proof_eligible"],
        "blockers": closure["blockers"] + list(learning_report.get("blockers") or []),
        "non_claims": {
            "deployable_real_robot_policy": False,
            "visual_policy_performance": False,
            "real_robot_success": False,
            "physical_robot_readiness": False,
            "universal_robot_support": False,
            "hmd_openxr_readiness": False,
        },
    }
    gate["heldout_closure_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "heldout_closure_gate_sha256",
    )
    write_json(child_dir / "heldout_closure_gate_v0_11.json", gate)
    write_json(output_dir / "heldout_closure_gate.json", gate)
    if actual_env is not None:
        actual_env.close()
    return gate


def _v11a_calibration_gate_path(output_dir: Path) -> Path:
    return output_dir / V11_CHILD_OUTPUT_DIRNAME / "calibration_presignal_gate_v0_11.json"


def _v11a_rollout_path(output_dir: Path, role: str) -> Path:
    return (
        output_dir
        / V11_CHILD_OUTPUT_DIRNAME
        / "calibration_external_rollouts"
        / f"{role}_calibration_rollouts_v0_11.json"
    )


def _scenario_seed(scenario_id: str) -> int:
    match = re.search(r"(\d+)$", str(scenario_id))
    if match is None:
        raise ValueError(f"scenario_id_missing_seed:{scenario_id}")
    return int(match.group(1))


def _v11a_paired_outcomes(
    *,
    baseline_rollouts: list[dict[str, Any]],
    candidate_rollouts: list[dict[str, Any]],
) -> tuple[dict[str, int], dict[str, list[int]], list[dict[str, Any]]]:
    baseline_by_id = {str(row["scenario_id"]): row for row in baseline_rollouts}
    candidate_by_id = {str(row["scenario_id"]): row for row in candidate_rollouts}
    if set(baseline_by_id) != set(candidate_by_id):
        raise ValueError("v0_11a_calibration_scenario_mismatch")
    counts = {"B1_C1": 0, "B1_C0": 0, "B0_C1": 0, "B0_C0": 0}
    seed_lists = {key: [] for key in counts}
    rows: list[dict[str, Any]] = []
    for scenario_id in sorted(baseline_by_id, key=_scenario_seed):
        baseline = baseline_by_id[scenario_id]
        candidate = candidate_by_id[scenario_id]
        baseline_success = bool(baseline.get("success"))
        candidate_success = bool(candidate.get("success"))
        key = f"B{1 if baseline_success else 0}_C{1 if candidate_success else 0}"
        counts[key] += 1
        seed = _scenario_seed(scenario_id)
        seed_lists[key].append(seed)
        rows.append(
            {
                "scenario_id": scenario_id,
                "seed": seed,
                "baseline_success": baseline_success,
                "candidate_success": candidate_success,
                "paired_outcome": key,
                "baseline_env_native_max_consecutive_success_steps": baseline.get(
                    "env_native_max_consecutive_success_steps"
                ),
                "candidate_env_native_max_consecutive_success_steps": candidate.get(
                    "env_native_max_consecutive_success_steps"
                ),
                "baseline_failure_reason": baseline.get("failure_reason", ""),
                "candidate_failure_reason": candidate.get("failure_reason", ""),
            }
        )
    return counts, seed_lists, rows


def _v11a_policy_delta_report(output_dir: Path) -> dict[str, Any]:
    v10_baseline_path = output_dir / V10_CHILD_OUTPUT_DIRNAME / "baseline_policy_artifact_v0_10.json"
    v11_child = output_dir / V11_CHILD_OUTPUT_DIRNAME
    v11_baseline_path = v11_child / "baseline_policy_artifact_v0_11.json"
    v11_candidate_path = v11_child / "candidate_policy_artifact_v0_11.json"
    for path in (v10_baseline_path, v11_baseline_path, v11_candidate_path):
        if not path.exists():
            raise ValueError(f"missing_policy_artifact:{path}")
    v10_baseline = read_json(v10_baseline_path)
    v11_baseline = read_json(v11_baseline_path)
    v11_candidate = read_json(v11_candidate_path)

    def delta(left: dict[str, Any], right: dict[str, Any]) -> dict[str, float]:
        left_weights = np.asarray(left.get("weights", []), dtype=np.float64)
        right_weights = np.asarray(right.get("weights", []), dtype=np.float64)
        left_bias = np.asarray(left.get("bias", []), dtype=np.float64)
        right_bias = np.asarray(right.get("bias", []), dtype=np.float64)
        return {
            "weight_l2_delta": round(float(np.linalg.norm(left_weights - right_weights)), 12),
            "weight_max_abs_delta": round(float(np.max(np.abs(left_weights - right_weights))), 12),
            "bias_l2_delta": round(float(np.linalg.norm(left_bias - right_bias)), 12),
            "bias_max_abs_delta": round(float(np.max(np.abs(left_bias - right_bias))), 12),
        }

    report = {
        "schema_version": "rdf_mvp2e_v11a_policy_delta_report_v0.1.0",
        "policy_slice": V11A_POLICY_SLICE_ID,
        "source_policy_slice": V11_POLICY_SLICE_ID,
        "v10_baseline_policy_artifact_sha256": v10_baseline.get("policy_artifact_sha256"),
        "v11_baseline_policy_artifact_sha256": v11_baseline.get("policy_artifact_sha256"),
        "v11_candidate_policy_artifact_sha256": v11_candidate.get("policy_artifact_sha256"),
        "v10_baseline_to_v11_baseline": delta(v10_baseline, v11_baseline),
        "v11_baseline_to_v11_candidate": delta(v11_baseline, v11_candidate),
        "v11_baseline_training_view_sha256": v11_baseline.get("training_view_sha256"),
        "v11_candidate_training_view_sha256": v11_candidate.get("training_view_sha256"),
    }
    report["policy_delta_report_sha256"] = _sha256_payload_excluding(
        report,
        "policy_delta_report_sha256",
    )
    return report


def build_v11a_low_floor_baseline_persistence_diagnosis(*, output_dir: Path) -> dict[str, Any]:
    gate_path = _v11a_calibration_gate_path(output_dir)
    if not gate_path.exists():
        raise ValueError("missing_v0_11_calibration_presignal_gate")
    gate = read_json(gate_path)
    if gate.get("runtime_backend") != "isaac_runtime":
        raise ValueError("v0_11_calibration_not_actual_isaac_runtime")
    if gate.get("heldout_opened") is not False or gate.get("fresh_heldout_34000_34049_accessed") is not False:
        raise ValueError("v0_11a_heldout_claim_boundary_violation")

    baseline_rollouts = json.loads(
        _v11a_rollout_path(output_dir, "baseline").read_text(encoding="utf-8")
    )
    candidate_rollouts = json.loads(
        _v11a_rollout_path(output_dir, "candidate").read_text(encoding="utf-8")
    )
    if not isinstance(baseline_rollouts, list) or not isinstance(candidate_rollouts, list):
        raise ValueError("v0_11a_calibration_rollouts_must_be_lists")
    counts, seed_lists, paired_rows = _v11a_paired_outcomes(
        baseline_rollouts=baseline_rollouts,
        candidate_rollouts=candidate_rollouts,
    )
    baseline_rate = float(gate["baseline_calibration_success_rate"])
    candidate_rate = float(gate["candidate_calibration_success_rate"])
    success_gap = round(candidate_rate - baseline_rate, 12)
    baseline_success_count = int(gate["baseline_calibration_success_count"])
    candidate_success_count = int(gate["candidate_calibration_success_count"])
    required_baseline_success_max_count = math.floor(
        len(baseline_rollouts) * V11_BASELINE_FLOOR_SUCCESS_MAXIMUM
    )
    required_candidate_success_min_count = math.ceil(
        len(candidate_rollouts) * V11_CALIBRATION_SUCCESS_MINIMUM
    )
    success_gap_required_count_delta = math.ceil(
        len(candidate_rollouts) * V11_CALIBRATION_UPLIFT_MINIMUM
    )
    current_count_delta = candidate_success_count - baseline_success_count

    if baseline_rate > V11_BASELINE_FLOOR_SUCCESS_MAXIMUM and candidate_rate >= V11_CALIBRATION_SUCCESS_MINIMUM:
        primary_root_cause_class = "LOW_FLOOR_BASELINE_RUNTIME_FLOOR_PERSISTENCE"
        recommended_downstream_slice = V11A_RECOMMENDED_DOWNSTREAM_SLICE
    elif candidate_rate < V11_CALIBRATION_SUCCESS_MINIMUM:
        primary_root_cause_class = "CANDIDATE_RUNTIME_SUCCESS_BELOW_MINIMUM"
        recommended_downstream_slice = "v0_12_candidate_success_recovery_slice"
    elif success_gap < V11_CALIBRATION_UPLIFT_MINIMUM:
        primary_root_cause_class = "CALIBRATION_GAP_STILL_BELOW_MINIMUM"
        recommended_downstream_slice = "v0_12_candidate_baseline_gap_repair_slice"
    else:
        primary_root_cause_class = "UNCLASSIFIED_V11_CALIBRATION_FAILURE"
        recommended_downstream_slice = None

    policy_delta_report = _v11a_policy_delta_report(output_dir)
    child_dir = output_dir / V11A_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    write_json(child_dir / "v0_11a_paired_outcome_table.json", paired_rows)
    write_json(child_dir / "v0_11a_policy_delta_report.json", policy_delta_report)
    report = {
        "schema_version": V11A_DIAGNOSIS_SCHEMA_VERSION,
        "policy_slice": V11A_POLICY_SLICE_ID,
        "source_policy_slice": V11_POLICY_SLICE_ID,
        "slice_id": V11A_SLICE_ID,
        "runtime_backend": "offline_artifact_diagnosis",
        "source_v11_calibration_gate_sha256": _sha256_file(gate_path),
        "baseline_calibration_success_count": baseline_success_count,
        "candidate_calibration_success_count": candidate_success_count,
        "baseline_calibration_success_rate": baseline_rate,
        "candidate_calibration_success_rate": candidate_rate,
        "candidate_baseline_success_gap": success_gap,
        "baseline_success_floor_maximum": V11_BASELINE_FLOOR_SUCCESS_MAXIMUM,
        "candidate_success_minimum": V11_CALIBRATION_SUCCESS_MINIMUM,
        "candidate_success_gap_minimum": V11_CALIBRATION_UPLIFT_MINIMUM,
        "required_baseline_success_max_count": required_baseline_success_max_count,
        "required_candidate_success_min_count": required_candidate_success_min_count,
        "success_gap_required_count_delta": success_gap_required_count_delta,
        "current_count_delta": current_count_delta,
        "additional_baseline_failures_needed_for_floor": max(
            0,
            baseline_success_count - required_baseline_success_max_count,
        ),
        "additional_candidate_successes_needed_for_gap": max(
            0,
            success_gap_required_count_delta - current_count_delta,
        ),
        "paired_outcome_counts": counts,
        "candidate_recovered_baseline_failure_seeds": seed_lists["B0_C1"],
        "candidate_degraded_baseline_success_seeds": seed_lists["B1_C0"],
        "joint_failure_seeds": seed_lists["B0_C0"],
        "joint_success_seeds": seed_lists["B1_C1"],
        "candidate_non_regression": counts["B1_C0"] <= 1,
        "baseline_floor_exceeded": baseline_rate > V11_BASELINE_FLOOR_SUCCESS_MAXIMUM,
        "candidate_success_requirement_met": candidate_rate >= V11_CALIBRATION_SUCCESS_MINIMUM,
        "calibration_gap_requirement_met": success_gap >= V11_CALIBRATION_UPLIFT_MINIMUM,
        "primary_root_cause_class": primary_root_cause_class,
        "recommended_downstream_slice": recommended_downstream_slice,
        "policy_delta_report_sha256": policy_delta_report["policy_delta_report_sha256"],
        "policy_delta_report": "v0_11a_policy_delta_report.json",
        "paired_outcome_table": "v0_11a_paired_outcome_table.json",
        "calibration_opened": True,
        "heldout_opened": False,
        "fresh_heldout_32000_32049_accessed": False,
        "fresh_heldout_34000_34049_accessed": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "proof_authority": False,
        "non_claims": {
            "deployable_real_robot_policy": False,
            "visual_policy_performance": False,
            "real_robot_success": False,
            "physical_robot_readiness": False,
            "hmd_openxr_readiness": False,
        },
    }
    report["v0_11a_diagnosis_sha256"] = _sha256_payload_excluding(
        report,
        "v0_11a_diagnosis_sha256",
    )
    write_json(child_dir / "v0_11a_low_floor_baseline_persistence_diagnosis.json", report)
    return report


def load_required_v11a_low_floor_baseline_persistence_diagnosis(
    output_dir: Path,
) -> tuple[dict[str, Any], str]:
    path = (
        output_dir
        / V11A_CHILD_OUTPUT_DIRNAME
        / "v0_11a_low_floor_baseline_persistence_diagnosis.json"
    )
    if not path.exists():
        raise ValueError("missing_v0_11a_low_floor_baseline_persistence_diagnosis")
    report = read_json(path)
    if report.get("policy_slice") != V11A_POLICY_SLICE_ID:
        raise ValueError("v0_11a_policy_slice_mismatch")
    if report.get("primary_root_cause_class") != "LOW_FLOOR_BASELINE_RUNTIME_FLOOR_PERSISTENCE":
        raise ValueError("v0_11a_not_baseline_floor_persistence")
    if report.get("recommended_downstream_slice") != V11A_RECOMMENDED_DOWNSTREAM_SLICE:
        raise ValueError("v0_11a_downstream_recommendation_mismatch")
    if report.get("heldout_opened") is not False or report.get("fresh_heldout_34000_34049_accessed") is not False:
        raise ValueError("v0_11a_claim_boundary_violation")
    report["path"] = str(path)
    report["sha256"] = _sha256_file(path)
    return report, report["sha256"]


def _v12_terminal_failure_rows(failure_rows: list[dict[str, Any]]) -> tuple[list[dict[str, Any]], dict[str, Any]]:
    grouped: dict[str, list[dict[str, Any]]] = {}
    for row in failure_rows:
        trace_path = str(row.get("source_trace_path") or row.get("runtime_trace_path") or "")
        if not trace_path:
            raise ValueError("v0_12_failure_row_missing_trace_path")
        grouped.setdefault(trace_path, []).append(row)
    terminal_rows: list[dict[str, Any]] = []
    rows_per_trace: dict[str, int] = {}
    for trace_path, rows in sorted(grouped.items()):
        sorted_rows = sorted(rows, key=lambda item: int(item.get("step", 0)))
        selected = sorted_rows[-V12_FAILURE_TAIL_WINDOW_ROWS:]
        terminal_rows.extend(_v09_deepcopy_row(row) for row in selected)
        rows_per_trace[trace_path] = len(selected)
    report = {
        "failure_material_selection": "terminal_failure_window_rows",
        "terminal_window_rows_per_trace": V12_FAILURE_TAIL_WINDOW_ROWS,
        "source_failure_row_count": len(failure_rows),
        "source_failure_trace_count": len(grouped),
        "terminal_failure_row_count": len(terminal_rows),
        "rows_per_trace": rows_per_trace,
    }
    return terminal_rows, report


def _v12_failure_material_row(row: dict[str, Any], *, copy_index: int) -> dict[str, Any]:
    copy_row = _v09_deepcopy_row(row)
    copy_row.update(
        {
            "proof_role": "v0_12_terminal_low_floor_uncurated_failure_material",
            "uncurated_mix_policy_slice": V12_POLICY_SLICE_ID,
            "uncurated_mix_is_failure_material": True,
            "uncurated_low_floor_policy_slice": V12_POLICY_SLICE_ID,
            "uncurated_low_floor_is_failure_material": True,
            "uncurated_low_floor_ratio_target": V12_BASELINE_FAILURE_MATERIAL_RATIO,
            "uncurated_low_floor_terminal_window_rows": V12_FAILURE_TAIL_WINDOW_ROWS,
            "uncurated_low_floor_copy_index": copy_index,
            "uncurated_low_floor_source_row_sha256": _sha256_payload(row),
        }
    )
    return copy_row


def _build_v12_baseline_rows(
    *,
    success_rows: list[dict[str, Any]],
    failure_rows: list[dict[str, Any]],
) -> tuple[list[dict[str, Any]], dict[str, Any]]:
    if not success_rows:
        raise ValueError("v0_12_baseline_success_rows_missing")
    if not failure_rows:
        raise ValueError("v0_12_baseline_failure_rows_missing")
    terminal_rows, terminal_report = _v12_terminal_failure_rows(failure_rows)
    if not terminal_rows:
        raise ValueError("v0_12_terminal_failure_rows_missing")
    target_failure_count = max(
        1,
        int(
            round(
                len(success_rows)
                * V12_BASELINE_FAILURE_MATERIAL_RATIO
                / (1.0 - V12_BASELINE_FAILURE_MATERIAL_RATIO)
            )
        ),
    )
    selected_failure_rows = [
        _v12_failure_material_row(
            terminal_rows[index % len(terminal_rows)],
            copy_index=index // len(terminal_rows),
        )
        for index in range(target_failure_count)
    ]
    baseline_success_rows = [_v09_deepcopy_row(row) for row in success_rows]
    for row in baseline_success_rows:
        row["uncurated_low_floor_policy_slice"] = V12_POLICY_SLICE_ID
        row["uncurated_low_floor_is_failure_material"] = False
        row["uncurated_low_floor_ratio_target"] = V12_BASELINE_FAILURE_MATERIAL_RATIO
    baseline_rows = baseline_success_rows + selected_failure_rows
    ratio = len(selected_failure_rows) / len(baseline_rows)
    if ratio < 0.85 or ratio > 0.95:
        raise ValueError("v0_12_baseline_failure_mix_ratio_out_of_bounds")
    return baseline_rows, {
        "success_row_count": len(success_rows),
        "selected_failure_row_count": len(selected_failure_rows),
        "source_failure_row_count": len(failure_rows),
        "terminal_failure_row_count": len(terminal_rows),
        "baseline_actual_failure_material_ratio": round(ratio, 12),
        "baseline_failure_material_ratio_target": V12_BASELINE_FAILURE_MATERIAL_RATIO,
        **terminal_report,
    }


def build_v12_policy_artifact_payload(
    *,
    parent_policy_artifact: dict[str, Any],
    base_policy_artifact: dict[str, Any],
    dataset_view_role: str,
    training_view: dict[str, Any],
    source_v11a_diagnosis_sha256: str,
    baseline_floor_suppression_config_sha256: str,
) -> dict[str, Any]:
    role = "candidate" if dataset_view_role == "candidate_curated" else "baseline"
    payload = {
        key: value
        for key, value in parent_policy_artifact.items()
        if key not in {"path", "policy_artifact_sha256"}
    }
    for key in (
        "weights",
        "bias",
        "train_sample_count",
        "hyperparameters",
        "feature_schema",
        "feature_schema_version",
        "phase_schema",
        "action_schema",
    ):
        payload[key] = base_policy_artifact[key]
    hyperparameters = dict(payload.get("hyperparameters") or {})
    hyperparameters["baseline_floor_suppression_config_sha256"] = (
        baseline_floor_suppression_config_sha256
    )
    payload.update(
        {
            "schema_version": V12_POLICY_ARTIFACT_SCHEMA_VERSION,
            "policy_artifact_schema_version": V12_POLICY_ARTIFACT_SCHEMA_VERSION,
            "policy_id": f"{role}_mvp2e_v12_baseline_floor_suppression_policy",
            "policy_slice": V12_POLICY_SLICE_ID,
            "slice_id": V12_SLICE_ID,
            "parent_policy_slice": V11_POLICY_SLICE_ID,
            "source_policy_slice": V11A_POLICY_SLICE_ID,
            "source_v11a_diagnosis_sha256": source_v11a_diagnosis_sha256,
            "source_v11_policy_artifact_sha256": parent_policy_artifact.get(
                "policy_artifact_sha256"
            ),
            "baseline_floor_suppression_config_sha256": baseline_floor_suppression_config_sha256,
            "dataset_view_role": dataset_view_role,
            "policy_class": RESIDUAL_POLICY_CLASS,
            "trainer": RESIDUAL_TRAINER,
            "trainer_family": RESIDUAL_TRAINER_FAMILY,
            "hyperparameters": hyperparameters,
            "training_view_sha256": training_view["sha256"],
            "training_view_path": training_view["path"],
            "fresh_calibration_35000_35029_accessed": False,
            "fresh_heldout_36000_36049_accessed": False,
            "heldout_opened": False,
            "mvp2_closed": False,
            "policy_uplift_proven": False,
            "proof_authority": False,
        }
    )
    payload["policy_artifact_sha256"] = _sha256_payload_excluding(payload, "policy_artifact_sha256")
    return payload


def derive_v12_baseline_floor_suppression_gate(
    *,
    candidate_policy: dict[str, Any],
    baseline_policy: dict[str, Any],
    candidate_rows_v11: list[dict[str, Any]],
    candidate_rows_v12: list[dict[str, Any]],
    baseline_rows: list[dict[str, Any]],
    baseline_mix_report: dict[str, Any],
    source_v11a_diagnosis_sha256: str,
    baseline_floor_suppression_config_sha256: str,
    failure_material_report: dict[str, Any],
) -> dict[str, Any]:
    equality_keys = (
        "selected_action_adapter_id",
        "trainer",
        "trainer_family",
        "policy_class",
        "feature_schema",
        "feature_schema_version",
        "phase_schema",
        "action_schema",
        "base_servo_config_sha256",
        "authority_filter_config_sha256",
        "final_post_adapter_authority_config_sha256",
        "final_post_adapter_xy_authority_config_sha256",
        "shared_hysteresis_authority_config_sha256",
        "capture_conditioned_progress_authority_config_sha256",
        "horizon_reserved_capture_authority_config_sha256",
        "deadline_precedence_horizon_authority_config_sha256",
        "early_centered_z_open_safe_entry_config_sha256",
    )
    peer_mismatches = [
        key for key in equality_keys if candidate_policy.get(key) != baseline_policy.get(key)
    ]
    candidate_rows_unchanged = (
        _sha256_payload(candidate_rows_v11) == _sha256_payload(candidate_rows_v12)
    )
    calibration_or_heldout_rows_used = any(
        str(row.get("split") or "").startswith("calibration")
        or str(row.get("split") or "") == "held_out"
        for row in baseline_rows + candidate_rows_v12
    )
    reasons: list[str] = []
    ratio = float(baseline_mix_report["baseline_actual_failure_material_ratio"])
    if ratio < 0.85 or ratio > 0.95:
        reasons.append("baseline_failure_material_ratio_out_of_bounds")
    if baseline_mix_report.get("failure_material_selection") != "terminal_failure_window_rows":
        reasons.append("terminal_failure_window_material_not_used")
    if baseline_mix_report.get("terminal_window_rows_per_trace") != V12_FAILURE_TAIL_WINDOW_ROWS:
        reasons.append("terminal_failure_window_size_mismatch")
    if not candidate_rows_unchanged:
        reasons.append("candidate_rows_changed_from_v11")
    if peer_mismatches:
        reasons.append("peer_fairness_mismatch")
    if calibration_or_heldout_rows_used:
        reasons.append("calibration_or_heldout_rows_used_for_training")
    gate = {
        "schema_version": V12_COMPARATOR_GATE_SCHEMA_VERSION,
        "policy_slice": V12_POLICY_SLICE_ID,
        "slice_id": V12_SLICE_ID,
        "parent_policy_slice": V11_POLICY_SLICE_ID,
        "source_policy_slice": V11A_POLICY_SLICE_ID,
        "source_v11a_diagnosis_sha256": source_v11a_diagnosis_sha256,
        "baseline_floor_suppression_config_sha256": baseline_floor_suppression_config_sha256,
        "baseline_failure_material_ratio_target": V12_BASELINE_FAILURE_MATERIAL_RATIO,
        "baseline_actual_failure_material_ratio": ratio,
        "baseline_success_row_count": baseline_mix_report["success_row_count"],
        "baseline_failure_material_row_count": baseline_mix_report[
            "selected_failure_row_count"
        ],
        "baseline_terminal_failure_row_count": baseline_mix_report["terminal_failure_row_count"],
        "baseline_total_row_count": len(baseline_rows),
        "candidate_row_count": len(candidate_rows_v12),
        "candidate_rows_unchanged_from_v11": candidate_rows_unchanged,
        "failure_material_report": failure_material_report,
        "terminal_failure_window_report": baseline_mix_report,
        "peer_fairness_mismatch_keys": peer_mismatches,
        "calibration_or_heldout_rows_used_for_training": calibration_or_heldout_rows_used,
        "heldout_opened": False,
        "fresh_calibration_35000_35029_accessed": False,
        "fresh_heldout_36000_36049_accessed": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "passed": not reasons,
        "failure_reasons": reasons,
        "failure_reason": ",".join(reasons),
    }
    gate["baseline_floor_suppression_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "baseline_floor_suppression_gate_sha256",
    )
    return gate


def build_v12_baseline_floor_suppression_slice(*, output_dir: Path) -> dict[str, Any]:
    diagnosis, diagnosis_sha = load_required_v11a_low_floor_baseline_persistence_diagnosis(
        output_dir
    )
    train_generation_gate, train_generation_gate_sha256 = _load_v09_train_generation_gate(output_dir)
    parent_policies = _load_v11_policy_artifacts(output_dir)
    child_dir = output_dir / V12_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    authority_config = _v09_source_authority_config(output_dir, parent_policies["candidate"])
    residual_servo_config = build_v07b_residual_servo_config(
        output_dir=child_dir,
        parent_config_sha256=train_generation_gate_sha256,
    )
    source_dir = output_dir / V11_CHILD_OUTPUT_DIRNAME
    candidate_rows_v11 = _rows_from_hdf5_metadata(source_dir / "candidate_curated_train_v0_11.hdf5")
    candidate_rows_v12 = [_v09_deepcopy_row(row) for row in candidate_rows_v11]
    success_rows = [_v09_deepcopy_row(row) for row in candidate_rows_v11 if row.get("accepted") is not False]
    failure_rows, failure_material_report = _extract_v09_failed_train_generation_rows(
        output_dir=output_dir,
        train_generation_gate=train_generation_gate,
        residual_servo_config=residual_servo_config,
    )
    baseline_rows, baseline_mix_report = _build_v12_baseline_rows(
        success_rows=success_rows,
        failure_rows=failure_rows,
    )
    config = {
        "schema_version": "rdf_mvp2e_v12_baseline_floor_suppression_config_v0.1.0",
        "policy_slice": V12_POLICY_SLICE_ID,
        "slice_id": V12_SLICE_ID,
        "source_v11a_diagnosis_sha256": diagnosis_sha,
        "source_v11a_baseline_success_rate": diagnosis["baseline_calibration_success_rate"],
        "source_v11a_candidate_success_rate": diagnosis["candidate_calibration_success_rate"],
        "source_v11a_candidate_baseline_success_gap": diagnosis[
            "candidate_baseline_success_gap"
        ],
        "train_generation_config_sha256": train_generation_gate_sha256,
        "baseline_failure_material_ratio_target": V12_BASELINE_FAILURE_MATERIAL_RATIO,
        "baseline_floor_success_maximum": V12_BASELINE_FLOOR_SUCCESS_MAXIMUM,
        "failure_material_selection": "terminal_failure_window_rows",
        "terminal_failure_window_rows": V12_FAILURE_TAIL_WINDOW_ROWS,
        "fresh_calibration_seed_range": [min(V12_FRESH_CALIBRATION_RANGE), max(V12_FRESH_CALIBRATION_RANGE)],
        "fresh_heldout_seed_range": [min(V12_FRESH_HELDOUT_RANGE), max(V12_FRESH_HELDOUT_RANGE)],
        "burned_heldout_seed_ranges": [
            [21000, 21049],
            [24000, 24049],
            [26000, 26049],
            [27000, 27049],
            [32000, 32049],
            [34000, 34049],
        ],
        "burned_calibration_seed_ranges": [
            [30000, 30029],
            [31000, 31029],
            [33000, 33029],
        ],
        "heldout_opened": False,
        "fresh_heldout_36000_36049_accessed": False,
    }
    config["baseline_floor_suppression_config_sha256"] = _sha256_payload_excluding(
        config,
        "baseline_floor_suppression_config_sha256",
    )
    write_json(child_dir / "v0_12_baseline_floor_suppression_config.json", config)
    candidate_view = write_v07c_residual_train_view_hdf5(
        path=child_dir / "candidate_curated_train_v0_12.hdf5",
        rows=candidate_rows_v12,
        view_id="candidate_curated_v0_12_baseline_floor_suppression",
        authority_config=authority_config,
        schema_version=V12_MANIFEST_SCHEMA_VERSION,
        extra_hdf5_attrs={
            "policy_slice": V12_POLICY_SLICE_ID,
            "baseline_floor_suppression_config_sha256": config[
                "baseline_floor_suppression_config_sha256"
            ],
            "candidate_rows_unchanged_from_v11": True,
        },
        extra_view_fields={
            "policy_slice": V12_POLICY_SLICE_ID,
            "baseline_floor_suppression_config_sha256": config[
                "baseline_floor_suppression_config_sha256"
            ],
            "candidate_rows_unchanged_from_v11": True,
        },
    )
    baseline_view = write_v07c_residual_train_view_hdf5(
        path=child_dir / "baseline_uncurated_terminal_low_floor_train_v0_12.hdf5",
        rows=baseline_rows,
        view_id="baseline_uncurated_terminal_low_floor_v0_12",
        authority_config=authority_config,
        schema_version=V12_MANIFEST_SCHEMA_VERSION,
        extra_hdf5_attrs={
            "policy_slice": V12_POLICY_SLICE_ID,
            "baseline_floor_suppression_config_sha256": config[
                "baseline_floor_suppression_config_sha256"
            ],
            "baseline_actual_failure_material_ratio": baseline_mix_report[
                "baseline_actual_failure_material_ratio"
            ],
        },
        extra_view_fields={
            "policy_slice": V12_POLICY_SLICE_ID,
            "baseline_floor_suppression_config_sha256": config[
                "baseline_floor_suppression_config_sha256"
            ],
            **baseline_mix_report,
        },
    )
    hyperparameters = dict(parent_policies["candidate"].get("hyperparameters") or {})
    hyperparameters.update(
        {
            "trainer_family": RESIDUAL_TRAINER_FAMILY,
            "baseline_floor_suppression_config_sha256": config[
                "baseline_floor_suppression_config_sha256"
            ],
            "baseline_failure_material_ratio_target": V12_BASELINE_FAILURE_MATERIAL_RATIO,
            "terminal_failure_window_rows": V12_FAILURE_TAIL_WINDOW_ROWS,
        }
    )
    candidate_base = {
        key: parent_policies["candidate"][key]
        for key in (
            "weights",
            "bias",
            "train_sample_count",
            "feature_schema",
            "feature_schema_version",
            "phase_schema",
            "action_schema",
        )
    }
    candidate_base["hyperparameters"] = hyperparameters
    baseline_base = fit_phase_conditioned_bc_policy(
        policy_id="baseline_uncurated_terminal_low_floor_mvp2e_v12_bc",
        train_rows=baseline_rows,
        hyperparameters=hyperparameters,
        feature_schema=FEATURE_SCHEMA_V07A,
        phase_schema=BEHAVIOR_STATE_PHASES,
        feature_schema_version=FEATURE_SCHEMA_V07A_VERSION,
    )
    candidate_policy = build_v12_policy_artifact_payload(
        parent_policy_artifact=parent_policies["candidate"],
        base_policy_artifact=candidate_base,
        dataset_view_role="candidate_curated",
        training_view=candidate_view,
        source_v11a_diagnosis_sha256=diagnosis_sha,
        baseline_floor_suppression_config_sha256=config[
            "baseline_floor_suppression_config_sha256"
        ],
    )
    baseline_policy = build_v12_policy_artifact_payload(
        parent_policy_artifact=parent_policies["baseline"],
        base_policy_artifact=baseline_base,
        dataset_view_role="baseline_uncurated_terminal_low_floor",
        training_view=baseline_view,
        source_v11a_diagnosis_sha256=diagnosis_sha,
        baseline_floor_suppression_config_sha256=config[
            "baseline_floor_suppression_config_sha256"
        ],
    )
    write_json(child_dir / "candidate_policy_artifact_v0_12.json", candidate_policy)
    write_json(child_dir / "baseline_policy_artifact_v0_12.json", baseline_policy)
    gate = derive_v12_baseline_floor_suppression_gate(
        candidate_policy=candidate_policy,
        baseline_policy=baseline_policy,
        candidate_rows_v11=candidate_rows_v11,
        candidate_rows_v12=candidate_rows_v12,
        baseline_rows=baseline_rows,
        baseline_mix_report=baseline_mix_report,
        source_v11a_diagnosis_sha256=diagnosis_sha,
        baseline_floor_suppression_config_sha256=config[
            "baseline_floor_suppression_config_sha256"
        ],
        failure_material_report=failure_material_report,
    )
    write_json(child_dir / "baseline_floor_suppression_gate_v0_12.json", gate)
    manifest = {
        "schema_version": V12_MANIFEST_SCHEMA_VERSION,
        "policy_slice": V12_POLICY_SLICE_ID,
        "slice_id": V12_SLICE_ID,
        "parent_policy_slice": V11_POLICY_SLICE_ID,
        "source_policy_slice": V11A_POLICY_SLICE_ID,
        "source_v11a_diagnosis_sha256": diagnosis_sha,
        "baseline_floor_suppression_config": config,
        "fresh_calibration_seed_range": [min(V12_FRESH_CALIBRATION_RANGE), max(V12_FRESH_CALIBRATION_RANGE)],
        "fresh_heldout_seed_range": [min(V12_FRESH_HELDOUT_RANGE), max(V12_FRESH_HELDOUT_RANGE)],
        "burned_heldout_seed_ranges": config["burned_heldout_seed_ranges"],
        "burned_calibration_seed_ranges": config["burned_calibration_seed_ranges"],
        "training_views": {"candidate": candidate_view, "baseline": baseline_view},
        "policy_artifacts": {
            "candidate": {**candidate_policy, "path": str(child_dir / "candidate_policy_artifact_v0_12.json")},
            "baseline": {**baseline_policy, "path": str(child_dir / "baseline_policy_artifact_v0_12.json")},
        },
        "baseline_floor_suppression_gate": gate,
        "failed_closed": gate.get("passed") is not True,
        "failure_reason": gate.get("failure_reason", ""),
        "calibration_opened": False,
        "heldout_opened": False,
        "fresh_calibration_35000_35029_accessed": False,
        "fresh_heldout_36000_36049_accessed": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "proof_authority": False,
        "non_claims": {
            "policy_uplift_proven": False,
            "real_robot_success": False,
            "physical_robot_readiness": False,
            "visual_policy_performance": False,
            "hmd_openxr_readiness": False,
        },
    }
    manifest["v0_12_baseline_floor_suppression_manifest_sha256"] = _sha256_payload_excluding(
        manifest,
        "v0_12_baseline_floor_suppression_manifest_sha256",
    )
    write_json(child_dir / "v0_12_baseline_floor_suppression_manifest.json", manifest)
    return manifest


def _v12_burned_seed_range_accessed(seed: int) -> bool:
    seed_int = int(seed)
    return (
        _v11_burned_seed_range_accessed(seed_int)
        or seed_int in V11_FRESH_CALIBRATION_RANGE
        or seed_int in V11_FRESH_HELDOUT_RANGE
    )


def build_v12_fresh_manifest(
    *,
    output_dir: Path,
    suppression_manifest: dict[str, Any],
) -> dict[str, Any]:
    gate = suppression_manifest.get("baseline_floor_suppression_gate", {})
    if gate.get("passed") is not True:
        raise ValueError("v0_12_baseline_floor_suppression_gate_not_passed")
    calibration_rows = [
        _scenario_row(split="calibration", seed=seed)
        for seed in V12_FRESH_CALIBRATION_RANGE
    ]
    heldout_rows = [_scenario_row(split="held_out", seed=seed) for seed in V12_FRESH_HELDOUT_RANGE]
    if any(_v12_burned_seed_range_accessed(int(row["seed"])) for row in calibration_rows):
        raise ValueError("v0_12_fresh_manifest_reuses_burned_calibration_seed_range")
    if any(_v12_burned_seed_range_accessed(int(row["seed"])) for row in heldout_rows):
        raise ValueError("v0_12_fresh_manifest_reuses_burned_heldout_seed_range")
    manifest = {
        "schema_version": V12_MANIFEST_SCHEMA_VERSION,
        "policy_slice": V12_POLICY_SLICE_ID,
        "slice_id": V12_SLICE_ID,
        "parent_policy_slice": V11_POLICY_SLICE_ID,
        "source_policy_slice": V11A_POLICY_SLICE_ID,
        "scenario_profile": "v0_12",
        "task_type": "connector_insertion",
        "success_metric": SUCCESS_METRIC,
        "success_authority": V06_ENV_NATIVE_SUCCESS_AUTHORITY,
        "source_v12_baseline_floor_suppression_manifest_sha256": suppression_manifest[
            "v0_12_baseline_floor_suppression_manifest_sha256"
        ],
        "source_v12_baseline_floor_suppression_gate_sha256": gate[
            "baseline_floor_suppression_gate_sha256"
        ],
        "baseline_floor_suppression_config_sha256": gate[
            "baseline_floor_suppression_config_sha256"
        ],
        "scenarios": calibration_rows + heldout_rows,
        "fresh_split_manifest": {
            "calibration": {
                "seed_range": [min(V12_FRESH_CALIBRATION_RANGE), max(V12_FRESH_CALIBRATION_RANGE)],
                "scenario_ids": [row["scenario_id"] for row in calibration_rows],
                "count": len(calibration_rows),
            },
            "held_out": {
                "seed_range": [min(V12_FRESH_HELDOUT_RANGE), max(V12_FRESH_HELDOUT_RANGE)],
                "scenario_ids": [row["scenario_id"] for row in heldout_rows],
                "count": len(heldout_rows),
            },
        },
        "burned_heldout_seed_ranges": suppression_manifest["burned_heldout_seed_ranges"],
        "burned_calibration_seed_ranges": suppression_manifest["burned_calibration_seed_ranges"],
        "fresh_calibration_33000_33029_accessed": True,
        "fresh_calibration_35000_35029_accessed": False,
        "fresh_heldout_34000_34049_accessed": False,
        "fresh_heldout_36000_36049_accessed": False,
        "calibration_opened": False,
        "heldout_opened": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    manifest["manifest_sha256"] = _sha256_payload_excluding(manifest, "manifest_sha256")
    return manifest


def _v12_runtime_manifest_for_split(*, fresh_manifest: dict[str, Any], split: str) -> dict[str, Any]:
    if split not in {"calibration", "held_out"}:
        raise ValueError("v0_12_runtime_manifest_unknown_split")
    rows = [
        {**row, "source_split": split, "semantic_eval_split": split, "split": "held_out"}
        for row in fresh_manifest.get("scenarios", [])
        if isinstance(row, dict) and row.get("split") == split
    ]
    if not rows:
        raise ValueError(f"v0_12_runtime_manifest_missing_{split}_rows")
    seeds = [int(row["seed"]) for row in rows]
    if split == "calibration":
        if seeds != list(V12_FRESH_CALIBRATION_RANGE):
            raise ValueError("v0_12_calibration_seed_range_mismatch")
        if any(_v12_burned_seed_range_accessed(seed) for seed in seeds):
            raise ValueError("v0_12_runtime_manifest_reuses_burned_calibration_seed_range")
    if split == "held_out":
        if seeds != list(V12_FRESH_HELDOUT_RANGE):
            raise ValueError("v0_12_heldout_seed_range_mismatch")
        if any(_v12_burned_seed_range_accessed(seed) for seed in seeds):
            raise ValueError("v0_12_runtime_manifest_reuses_burned_heldout_seed_range")
    manifest = {
        "schema_version": fresh_manifest["schema_version"],
        "policy_slice": V12_POLICY_SLICE_ID,
        "slice_id": V12_SLICE_ID,
        "parent_policy_slice": V11_POLICY_SLICE_ID,
        "scenario_profile": "v0_12",
        "runtime_split": split,
        "task_type": fresh_manifest["task_type"],
        "success_metric": fresh_manifest["success_metric"],
        "success_authority": fresh_manifest["success_authority"],
        "source_fresh_manifest_sha256": fresh_manifest["manifest_sha256"],
        "scenarios": rows,
        "burned_heldout_seed_ranges": fresh_manifest["burned_heldout_seed_ranges"],
        "burned_calibration_seed_ranges": fresh_manifest["burned_calibration_seed_ranges"],
        "fresh_calibration_35000_35029_accessed": True,
        "fresh_heldout_36000_36049_accessed": split == "held_out",
        "calibration_opened": True,
        "heldout_opened": split == "held_out",
        "proof_authority": split == "held_out",
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    manifest["manifest_sha256"] = _sha256_payload_excluding(manifest, "manifest_sha256")
    return manifest


def _load_v12_policy_artifacts(output_dir: Path) -> dict[str, dict[str, Any]]:
    child_dir = output_dir / V12_CHILD_OUTPUT_DIRNAME
    candidate_path = child_dir / "candidate_policy_artifact_v0_12.json"
    baseline_path = child_dir / "baseline_policy_artifact_v0_12.json"
    if not candidate_path.exists() or not baseline_path.exists():
        raise ValueError("missing_v0_12_policy_artifacts")
    baseline = read_json(baseline_path)
    candidate = read_json(candidate_path)
    reasons: list[str] = []
    for role, policy in (("baseline", baseline), ("candidate", candidate)):
        if policy.get("policy_slice") != V12_POLICY_SLICE_ID:
            reasons.append(f"{role}_policy_slice_mismatch")
        if policy.get("parent_policy_slice") != V11_POLICY_SLICE_ID:
            reasons.append(f"{role}_parent_policy_slice_mismatch")
        if policy.get("fresh_calibration_35000_35029_accessed") is not False:
            reasons.append(f"{role}_fresh_calibration_accessed_before_runtime")
        if policy.get("fresh_heldout_36000_36049_accessed") is not False:
            reasons.append(f"{role}_fresh_heldout_accessed_before_closure")
        expected_hash = _sha256_payload_excluding(policy, "policy_artifact_sha256")
        if policy.get("policy_artifact_sha256") != expected_hash:
            reasons.append(f"{role}_policy_hash_mismatch")
    equality_keys = (
        "selected_action_adapter_id",
        "trainer",
        "trainer_family",
        "policy_class",
        "feature_schema",
        "feature_schema_version",
        "phase_schema",
        "action_schema",
        "base_servo_config_sha256",
        "authority_filter_config_sha256",
        "final_post_adapter_authority_config_sha256",
        "final_post_adapter_xy_authority_config_sha256",
        "shared_hysteresis_authority_config_sha256",
        "capture_conditioned_progress_authority_config_sha256",
        "horizon_reserved_capture_authority_config_sha256",
        "deadline_precedence_horizon_authority_config_sha256",
        "early_centered_z_open_safe_entry_config_sha256",
        "baseline_floor_suppression_config_sha256",
    )
    for key in equality_keys:
        if baseline.get(key) != candidate.get(key):
            reasons.append(f"peer_{key}_mismatch")
    if reasons:
        raise ValueError("v0_12_policy_peer_fairness_failed: " + ",".join(reasons))
    return {
        "baseline": {**baseline, "path": str(baseline_path)},
        "candidate": {**candidate, "path": str(candidate_path)},
    }


def _write_v12_calibration_external_rollouts(
    *,
    output_dir: Path,
    baseline_rollouts: list[dict[str, Any]],
    candidate_rollouts: list[dict[str, Any]],
) -> dict[str, str]:
    rollout_dir = output_dir / "calibration_external_rollouts"
    rollout_dir.mkdir(parents=True, exist_ok=True)
    baseline_path = rollout_dir / "baseline_calibration_rollouts_v0_12.json"
    candidate_path = rollout_dir / "candidate_calibration_rollouts_v0_12.json"
    write_json(baseline_path, baseline_rollouts)
    write_json(candidate_path, candidate_rollouts)
    return {"baseline": str(baseline_path), "candidate": str(candidate_path)}


def derive_v12_calibration_presignal_gate(
    *,
    baseline_rollouts: list[dict[str, Any]],
    candidate_rollouts: list[dict[str, Any]],
    runtime_gate: dict[str, Any],
    runtime_metadata: dict[str, Any],
    trace_paths: dict[str, list[str]],
) -> dict[str, Any]:
    gate = derive_v07h_calibration_presignal_gate(
        baseline_rollouts=baseline_rollouts,
        candidate_rollouts=candidate_rollouts,
        runtime_gate=runtime_gate,
        runtime_metadata=runtime_metadata,
        trace_paths=trace_paths,
        output_dir=Path("."),
    )
    baseline_rate = float(gate["baseline_calibration_success_rate"])
    candidate_rate = float(gate["candidate_calibration_success_rate"])
    success_gap = round(candidate_rate - baseline_rate, 12)
    attribution = _v08d_attribution_preservation_metrics(trace_paths)
    failure_reason = ""
    if runtime_gate.get("passed") is not True or runtime_metadata.get("runtime_backend") != "isaac_runtime":
        failure_reason = "calibration_runtime_gate_not_passed"
    elif (
        int(gate["baseline_calibration_rollout_count"]) < V07H_CALIBRATION_ROLLOUTS_PER_POLICY
        or int(gate["candidate_calibration_rollout_count"]) < V07H_CALIBRATION_ROLLOUTS_PER_POLICY
    ):
        failure_reason = "calibration_rollout_count_below_minimum"
    elif baseline_rate > V12_BASELINE_FLOOR_SUCCESS_MAXIMUM:
        failure_reason = "baseline_calibration_success_floor_above_v0_12_maximum"
    elif candidate_rate < V12_CALIBRATION_SUCCESS_MINIMUM:
        failure_reason = "candidate_calibration_success_below_v0_12_minimum"
    elif candidate_rate <= baseline_rate:
        failure_reason = "candidate_calibration_not_above_baseline"
    elif success_gap < V12_CALIBRATION_UPLIFT_MINIMUM:
        failure_reason = "candidate_baseline_success_gap_below_v0_12_minimum"
    elif attribution["attribution_preservation_gate_passed"] is not True:
        failure_reason = "attribution_preservation_failed"
    passed = failure_reason == ""
    gate.update(
        {
            "schema_version": V12_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
            "policy_slice": V12_POLICY_SLICE_ID,
            "slice_id": V12_SLICE_ID,
            "parent_policy_slice": V11_POLICY_SLICE_ID,
            "passed": bool(passed),
            "failure_reason": failure_reason,
            "heldout_allowed": bool(passed),
            "candidate_baseline_success_gap": success_gap,
            "candidate_success_gap_minimum": V12_CALIBRATION_UPLIFT_MINIMUM,
            "candidate_calibration_success_minimum": V12_CALIBRATION_SUCCESS_MINIMUM,
            "baseline_calibration_success_floor_maximum": V12_BASELINE_FLOOR_SUCCESS_MAXIMUM,
            "attribution_preservation": attribution,
            "attribution_preservation_gate_passed": bool(
                attribution["attribution_preservation_gate_passed"]
            ),
            "fresh_calibration_35000_35029_accessed": True,
            "fresh_heldout_36000_36049_accessed": False,
            "source": "v0_12_baseline_floor_suppression_calibration_runtime",
            "mvp2_closed": False,
            "policy_uplift_proven": False,
        }
    )
    gate["calibration_presignal_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "calibration_presignal_gate_sha256",
    )
    return gate


def run_v12_baseline_floor_suppression_runtime(
    *,
    output_dir: Path,
    device: str = DEFAULT_ISAAC_DEVICE,
    headless: bool = True,
    isaac_task: str = DEFAULT_ISAAC_TASK,
    max_steps: int = int(SUCCESS_METRIC["max_steps"]),
    action_scale: float = 1.0,
    min_rollouts_per_policy: int = MIN_PROOF_ROLLOUTS_PER_POLICY,
    bootstrap_iterations: int = 2000,
    bootstrap_seed: int = 23,
    backend: Any | None = None,
) -> dict[str, Any]:
    child_dir = output_dir / V12_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    suppression_manifest = build_v12_baseline_floor_suppression_slice(output_dir=output_dir)
    if suppression_manifest["baseline_floor_suppression_gate"].get("passed") is not True:
        return suppression_manifest["baseline_floor_suppression_gate"]
    fresh_manifest = build_v12_fresh_manifest(
        output_dir=output_dir,
        suppression_manifest=suppression_manifest,
    )
    write_json(child_dir / "v0_12_fresh_manifest.json", fresh_manifest)
    policy_artifacts = _load_v12_policy_artifacts(output_dir)
    baseline_policy = policy_artifacts["baseline"]
    candidate_policy = policy_artifacts["candidate"]
    selected_adapter_id = str(candidate_policy["selected_action_adapter_id"])
    policy_class = str(candidate_policy["policy_class"])
    trainer = str(candidate_policy["trainer"])
    use_single_app_actual_backend = (
        backend is None
        and getattr(IsaacConnectorInsertionEvaluatorBackend, "__name__", "")
        == "IsaacConnectorInsertionEvaluatorBackend"
    )
    evaluator_backend = backend or IsaacConnectorInsertionEvaluatorBackend(
        task=isaac_task,
        device=device,
        headless=headless,
        action_scale=action_scale,
        max_steps=max_steps,
    )
    actual_env = None
    actual_simulation_app = None
    actual_torch = None
    if use_single_app_actual_backend:
        from isaaclab.app import AppLauncher

        app_launcher = AppLauncher(
            {
                "headless": headless,
                "device": device,
                "enable_cameras": False,
            }
        )
        actual_simulation_app = app_launcher.app

        import gymnasium as gym
        import torch as torch_module

        import isaaclab_tasks  # noqa: F401
        from isaaclab_tasks.utils import parse_env_cfg

        env_cfg = parse_env_cfg(isaac_task, device=device, num_envs=1)
        actual_env = gym.make(isaac_task, cfg=env_cfg).unwrapped
        actual_torch = torch_module

    def run_runtime_manifest(
        *,
        manifest: dict[str, Any],
        runtime_output_dir: Path,
        rollouts_per_policy: int,
    ) -> BackendResult:
        if actual_env is not None:
            return _run_v08a_manifest_with_existing_isaac(
                evaluator_backend=evaluator_backend,
                env=actual_env,
                simulation_app=actual_simulation_app,
                torch_module=actual_torch,
                manifest=manifest,
                output_dir=runtime_output_dir,
                min_rollouts_per_policy=rollouts_per_policy,
                policy_artifacts=policy_artifacts,
            )
        return evaluator_backend.run(
            manifest=manifest,
            output_dir=runtime_output_dir,
            min_rollouts_per_policy=rollouts_per_policy,
            deterministic_profile="candidate_positive",
            policy_artifacts=policy_artifacts,
        )

    calibration_manifest = _v12_runtime_manifest_for_split(
        fresh_manifest=fresh_manifest,
        split="calibration",
    )
    write_json(child_dir / "calibration_runtime_manifest_v0_12.json", calibration_manifest)
    calibration_result = run_runtime_manifest(
        manifest=calibration_manifest,
        runtime_output_dir=child_dir / "isaac_runtime_fresh_calibration_v0_12",
        rollouts_per_policy=V07H_CALIBRATION_ROLLOUTS_PER_POLICY,
    )
    calibration_rollout_paths = _write_v12_calibration_external_rollouts(
        output_dir=child_dir,
        baseline_rollouts=list(calibration_result.baseline_rollouts),
        candidate_rollouts=list(calibration_result.candidate_rollouts),
    )
    calibration_trace_paths = {
        "baseline": list(calibration_result.baseline_trace_paths),
        "candidate": list(calibration_result.candidate_trace_paths),
    }
    calibration_gate = derive_v12_calibration_presignal_gate(
        baseline_rollouts=list(calibration_result.baseline_rollouts),
        candidate_rollouts=list(calibration_result.candidate_rollouts),
        runtime_gate=dict(calibration_result.runtime_gate),
        runtime_metadata=dict(calibration_result.runtime_metadata),
        trace_paths=calibration_trace_paths,
    )
    calibration_gate["calibration_runtime_manifest_sha256"] = calibration_manifest["manifest_sha256"]
    calibration_gate["baseline_calibration_rollout_path"] = calibration_rollout_paths["baseline"]
    calibration_gate["candidate_calibration_rollout_path"] = calibration_rollout_paths["candidate"]
    calibration_gate["calibration_presignal_gate_sha256"] = _sha256_payload_excluding(
        calibration_gate,
        "calibration_presignal_gate_sha256",
    )
    write_json(child_dir / "calibration_presignal_gate_v0_12.json", calibration_gate)
    write_json(output_dir / "calibration_presignal_gate.json", calibration_gate)
    if calibration_gate.get("passed") is not True:
        calibration_gate["mvp2_closed"] = False
        calibration_gate["policy_uplift_proven"] = False
        if actual_env is not None:
            actual_env.close()
        return calibration_gate

    selection = _v08a_calibration_selection_report(output_dir)
    training_scenario_ids = _v08a_training_scenario_ids(output_dir)
    heldout_manifest = _v12_runtime_manifest_for_split(
        fresh_manifest=fresh_manifest,
        split="held_out",
    )
    write_json(child_dir / "heldout_runtime_manifest_v0_12.json", heldout_manifest)
    heldout_leakage_guard = validate_no_heldout_leakage(
        manifest=heldout_manifest,
        training_scenario_ids=training_scenario_ids,
        curation_tuning_scenario_ids=[],
        threshold_tuning_scenario_ids=[],
        hyperparameter_scenario_ids=[],
        calibration_selector_scenario_ids=[
            str(item) for item in selection.get("calibration_scenario_ids", [])
        ],
    )
    if heldout_leakage_guard["passed"] is not True:
        raise ValueError("v0_12_fresh_heldout_leakage_guard_failed")
    baseline_view = _existing_train_view(
        child_dir / "baseline_uncurated_terminal_low_floor_train_v0_12.hdf5",
        view_id="baseline_uncurated_terminal_low_floor_v0_12",
    )
    candidate_view = _existing_train_view(
        child_dir / "candidate_curated_train_v0_12.hdf5",
        view_id="candidate_curated_v0_12_baseline_floor_suppression",
    )
    bridge_dir = _write_learning_harness_bridge(
        output_dir=child_dir,
        manifest=heldout_manifest,
        baseline_view=baseline_view,
        candidate_view=candidate_view,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    heldout_rollouts_per_policy = max(
        int(min_rollouts_per_policy),
        STRONGER_PUBLIC_ROLLOUTS_PER_POLICY,
        len(V12_FRESH_HELDOUT_RANGE),
    )
    heldout_result = run_runtime_manifest(
        manifest=heldout_manifest,
        runtime_output_dir=child_dir / "isaac_runtime_fresh_heldout_v0_12",
        rollouts_per_policy=heldout_rollouts_per_policy,
    )
    runtime_gate = dict(heldout_result.runtime_gate)
    actual_rollouts_per_policy = min(
        len(heldout_result.baseline_rollouts),
        len(heldout_result.candidate_rollouts),
    )
    runtime_gate["actual_baseline_rollouts"] = len(heldout_result.baseline_rollouts)
    runtime_gate["actual_candidate_rollouts"] = len(heldout_result.candidate_rollouts)
    runtime_gate["actual_rollouts_per_policy"] = actual_rollouts_per_policy
    combined_rollouts = list(heldout_result.baseline_rollouts) + list(heldout_result.candidate_rollouts)
    if any(_v12_burned_seed_range_accessed(int(rollout.get("seed", -1))) for rollout in combined_rollouts):
        raise ValueError("v0_12_burned_seed_accessed")
    heldout_suite = _heldout_suite(heldout_manifest)
    baseline_rollouts_path = _write_external_rollout_json(
        output_dir=child_dir,
        role="baseline",
        policy_artifact=baseline_policy,
        train_view=baseline_view,
        heldout_suite=heldout_suite,
        backend_result=heldout_result,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    candidate_rollouts_path = _write_external_rollout_json(
        output_dir=child_dir,
        role="candidate",
        policy_artifact=candidate_policy,
        train_view=candidate_view,
        heldout_suite=heldout_suite,
        backend_result=heldout_result,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    learning_report = _run_learning_validator(
        output_dir=child_dir,
        bridge_dir=bridge_dir,
        baseline_rollouts_path=baseline_rollouts_path,
        candidate_rollouts_path=candidate_rollouts_path,
        min_rollouts_per_policy=MIN_PROOF_ROLLOUTS_PER_POLICY,
        bootstrap_iterations=bootstrap_iterations,
        bootstrap_seed=bootstrap_seed,
        policy_class=policy_class,
        trainer=trainer,
    )
    train_generation_runtime_gate, train_gate_sha256 = load_v07a2_parent_train_generation_gate(output_dir)
    closure = derive_mvp2c_closure(
        learning_report=learning_report,
        runtime_gate=runtime_gate,
        train_generation_runtime_gate=train_generation_runtime_gate,
        calibration_selection_report=selection,
        heldout_leakage_guard=heldout_leakage_guard,
        actual_rollouts_per_policy=actual_rollouts_per_policy,
    )
    confidence_interval_report = _bootstrap_uplift_ci(
        baseline_rollouts=list(heldout_result.baseline_rollouts),
        candidate_rollouts=list(heldout_result.candidate_rollouts),
        iterations=bootstrap_iterations,
        seed=bootstrap_seed,
    )
    gate = {
        "schema_version": V12_HELDOUT_CLOSURE_SCHEMA_VERSION,
        "policy_slice": V12_POLICY_SLICE_ID,
        "slice_id": V12_SLICE_ID,
        "parent_policy_slice": V11_POLICY_SLICE_ID,
        "source_fresh_manifest_sha256": fresh_manifest["manifest_sha256"],
        "baseline_floor_suppression_config_sha256": suppression_manifest[
            "baseline_floor_suppression_config"
        ]["baseline_floor_suppression_config_sha256"],
        "baseline_floor_suppression_gate_sha256": suppression_manifest[
            "baseline_floor_suppression_gate"
        ]["baseline_floor_suppression_gate_sha256"],
        "parent_train_generation_runtime_gate_sha256": train_gate_sha256,
        "fresh_calibration_presignal_gate_sha256": calibration_gate[
            "calibration_presignal_gate_sha256"
        ],
        "runtime_backend": heldout_result.runtime_backend,
        "proof_runtime": heldout_result.proof_runtime,
        "runtime_gate": runtime_gate,
        "actual_rollouts_per_policy": actual_rollouts_per_policy,
        "baseline_success_rate": learning_report.get("baseline_success_rate"),
        "candidate_success_rate": learning_report.get("candidate_success_rate"),
        "curated_vs_uncurated_uplift": learning_report.get("curated_vs_uncurated_uplift"),
        "learning_report_path": str(
            child_dir / "mvp2_learning_proven_policy_eval" / "mvp2_learning_proven_report.json"
        ),
        "baseline_external_rollouts": str(baseline_rollouts_path),
        "candidate_external_rollouts": str(candidate_rollouts_path),
        "confidence_interval_report": confidence_interval_report,
        "stronger_public_evidence_target_passed": _derive_public_evidence_target(
            actual_rollouts_per_policy=actual_rollouts_per_policy,
            confidence_interval_report=confidence_interval_report,
        ),
        "calibration_opened": True,
        "heldout_opened": True,
        "fresh_calibration_33000_33029_accessed": True,
        "fresh_heldout_34000_34049_accessed": False,
        "fresh_calibration_35000_35029_accessed": True,
        "fresh_heldout_36000_36049_accessed": True,
        "same_heldout_reuse_allowed_for_closure": False,
        "heldout_leakage_guard": heldout_leakage_guard,
        "calibration_selection_report_sha256": _sha256_file(output_dir / "calibration_selection_report.json"),
        "selected_action_adapter_id": selected_adapter_id,
        "same_adapter_used_for_baseline_and_candidate": True,
        "same_policy_class": baseline_policy.get("policy_class") == candidate_policy.get("policy_class"),
        "same_trainer": baseline_policy.get("trainer") == candidate_policy.get("trainer"),
        "same_feature_schema": baseline_policy.get("feature_schema") == candidate_policy.get("feature_schema"),
        "mvp2_closed": closure["mvp2_closed"],
        "mvp2c_close_minimum_passed": closure["mvp2c_close_minimum_passed"],
        "policy_uplift_proven": closure["learning_proven"],
        "proof_eligible": closure["proof_eligible"],
        "blockers": closure["blockers"] + list(learning_report.get("blockers") or []),
        "non_claims": {
            "deployable_real_robot_policy": False,
            "visual_policy_performance": False,
            "real_robot_success": False,
            "physical_robot_readiness": False,
            "universal_robot_support": False,
            "hmd_openxr_readiness": False,
        },
    }
    gate["heldout_closure_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "heldout_closure_gate_sha256",
    )
    write_json(child_dir / "heldout_closure_gate_v0_12.json", gate)
    write_json(output_dir / "heldout_closure_gate.json", gate)
    if actual_env is not None:
        actual_env.close()
    return gate


def _v12a_calibration_gate_path(output_dir: Path) -> Path:
    return output_dir / V12_CHILD_OUTPUT_DIRNAME / "calibration_presignal_gate_v0_12.json"


def _v12a_rollout_path(output_dir: Path, role: str) -> Path:
    return (
        output_dir
        / V12_CHILD_OUTPUT_DIRNAME
        / "calibration_external_rollouts"
        / f"{role}_calibration_rollouts_v0_12.json"
    )


def _v12a_trace_path_from_rollout(rollout: dict[str, Any], *, output_dir: Path) -> Path:
    ref = str(rollout.get("rollout_log_ref") or rollout.get("trace_path") or "")
    if not ref:
        raise ValueError("v0_12a_rollout_missing_trace_ref")
    path = Path(ref)
    candidates = [path] if path.is_absolute() else [
        path,
        ROOT / path,
        output_dir / path,
        output_dir / V12_CHILD_OUTPUT_DIRNAME / path,
    ]
    for candidate in candidates:
        if candidate.exists():
            return candidate
    raise ValueError(f"v0_12a_missing_trace:{ref}")


def _v12a_paired_outcomes(
    *,
    baseline_rollouts: list[dict[str, Any]],
    candidate_rollouts: list[dict[str, Any]],
) -> tuple[dict[str, int], dict[str, list[int]], list[dict[str, Any]]]:
    baseline_by_id = {str(row["scenario_id"]): row for row in baseline_rollouts}
    candidate_by_id = {str(row["scenario_id"]): row for row in candidate_rollouts}
    if set(baseline_by_id) != set(candidate_by_id):
        raise ValueError("v0_12a_calibration_scenario_mismatch")
    counts = {"B1_C1": 0, "B1_C0": 0, "B0_C1": 0, "B0_C0": 0}
    seed_lists = {key: [] for key in counts}
    rows: list[dict[str, Any]] = []
    for scenario_id in sorted(baseline_by_id, key=_scenario_seed):
        baseline = baseline_by_id[scenario_id]
        candidate = candidate_by_id[scenario_id]
        baseline_success = bool(baseline.get("success"))
        candidate_success = bool(candidate.get("success"))
        key = f"B{1 if baseline_success else 0}_C{1 if candidate_success else 0}"
        seed = _scenario_seed(scenario_id)
        counts[key] += 1
        seed_lists[key].append(seed)
        rows.append(
            {
                "scenario_id": scenario_id,
                "seed": seed,
                "baseline_success": baseline_success,
                "candidate_success": candidate_success,
                "paired_outcome": key,
                "baseline_env_native_max_consecutive_success_steps": baseline.get(
                    "env_native_max_consecutive_success_steps"
                ),
                "candidate_env_native_max_consecutive_success_steps": candidate.get(
                    "env_native_max_consecutive_success_steps"
                ),
                "baseline_failure_reason": baseline.get("failure_reason", ""),
                "candidate_failure_reason": candidate.get("failure_reason", ""),
                "baseline_rollout_log_ref": baseline.get("rollout_log_ref"),
                "candidate_rollout_log_ref": candidate.get("rollout_log_ref"),
            }
        )
    return counts, seed_lists, rows


def _v12a_action_vector_delta(left: dict[str, Any], right: dict[str, Any], key: str) -> float | None:
    left_diag = left.get("controller_action_diagnostics") or {}
    right_diag = right.get("controller_action_diagnostics") or {}
    left_value = left_diag.get(key, left.get(key))
    right_value = right_diag.get(key, right.get(key))
    if left_value is None or right_value is None:
        return None
    left_array = np.asarray(left_value, dtype=np.float64)
    right_array = np.asarray(right_value, dtype=np.float64)
    if left_array.shape != right_array.shape or left_array.size == 0:
        return None
    return round(float(np.linalg.norm(left_array - right_array)), 12)


def _v12a_delta_stats(values: list[float]) -> dict[str, Any]:
    if not values:
        return {
            "count": 0,
            "mean": None,
            "median": None,
            "p95": None,
            "max": None,
            "zero_fraction": None,
            "identical_fraction": None,
        }
    sorted_values = sorted(values)
    p95_index = min(len(sorted_values) - 1, math.ceil(0.95 * len(sorted_values)) - 1)
    zero_count = sum(1 for value in values if abs(value) <= 1e-9)
    return {
        "count": len(values),
        "mean": round(float(statistics.fmean(values)), 12),
        "median": round(float(statistics.median(values)), 12),
        "p95": round(float(sorted_values[p95_index]), 12),
        "max": round(float(max(values)), 12),
        "zero_fraction": round(zero_count / len(values), 12),
        "identical_fraction": round(zero_count / len(values), 12),
    }


def _v12a_paired_trace_rows(
    *,
    baseline_rollouts: list[dict[str, Any]],
    candidate_rollouts: list[dict[str, Any]],
    output_dir: Path,
) -> list[tuple[dict[str, Any], dict[str, Any]]]:
    candidate_by_id = {str(row["scenario_id"]): row for row in candidate_rollouts}
    paired_rows: list[tuple[dict[str, Any], dict[str, Any]]] = []
    for baseline_rollout in sorted(baseline_rollouts, key=lambda row: _scenario_seed(str(row["scenario_id"]))):
        scenario_id = str(baseline_rollout["scenario_id"])
        candidate_rollout = candidate_by_id[scenario_id]
        baseline_trace = read_json(
            _v12a_trace_path_from_rollout(baseline_rollout, output_dir=output_dir)
        )
        candidate_trace = read_json(
            _v12a_trace_path_from_rollout(candidate_rollout, output_dir=output_dir)
        )
        baseline_rows = {
            int(row.get("step", -1)): row for row in list(baseline_trace.get("trace") or [])
        }
        candidate_rows = {
            int(row.get("step", -1)): row for row in list(candidate_trace.get("trace") or [])
        }
        for step in sorted(set(baseline_rows) & set(candidate_rows)):
            paired_rows.append((baseline_rows[step], candidate_rows[step]))
    return paired_rows


def build_v12a_action_compression_report(
    paired_rows: list[tuple[dict[str, Any], dict[str, Any]]],
) -> dict[str, Any]:
    delta_keys = (
        "raw_action_before_authority",
        "raw_action_after_authority",
        "pre_controller_action_vector",
        "post_adapter_action_vector",
    )
    deltas = {key: [] for key in delta_keys}
    xy_authority_active = 0
    z_block_active = 0
    for baseline_row, candidate_row in paired_rows:
        for key in delta_keys:
            delta = _v12a_action_vector_delta(baseline_row, candidate_row, key)
            if delta is not None:
                deltas[key].append(delta)
        baseline_diag = baseline_row.get("controller_action_diagnostics") or {}
        candidate_diag = candidate_row.get("controller_action_diagnostics") or {}
        if baseline_diag.get("xy_authority_applied") is True or candidate_diag.get(
            "xy_authority_applied"
        ) is True:
            xy_authority_active += 1
        if baseline_diag.get("final_post_adapter_z_motion_allowed") is False or candidate_diag.get(
            "final_post_adapter_z_motion_allowed"
        ) is False:
            z_block_active += 1
    paired_row_count = len(paired_rows)
    raw_before_stats = _v12a_delta_stats(deltas["raw_action_before_authority"])
    post_adapter_stats = _v12a_delta_stats(deltas["post_adapter_action_vector"])
    raw_before_mean = raw_before_stats["mean"]
    post_adapter_mean = post_adapter_stats["mean"]
    post_adapter_delta_smaller = (
        raw_before_mean is not None
        and post_adapter_mean is not None
        and float(post_adapter_mean) < float(raw_before_mean)
    )
    report = {
        "schema_version": "rdf_mvp2e_v12a_action_compression_report_v0.1.0",
        "policy_slice": V12A_POLICY_SLICE_ID,
        "source_policy_slice": V12_POLICY_SLICE_ID,
        "paired_trace_row_count": paired_row_count,
        "delta_stats": {key: _v12a_delta_stats(values) for key, values in deltas.items()},
        "raw_action_before_authority_mean_delta": raw_before_mean,
        "post_adapter_action_mean_delta": post_adapter_mean,
        "post_adapter_identical_fraction": post_adapter_stats["identical_fraction"],
        "shared_xy_authority_active_fraction": (
            round(xy_authority_active / paired_row_count, 12) if paired_row_count else 0.0
        ),
        "final_post_adapter_z_block_active_fraction": (
            round(z_block_active / paired_row_count, 12) if paired_row_count else 0.0
        ),
        "post_adapter_delta_smaller_than_raw_delta": post_adapter_delta_smaller,
    }
    report["action_compression_report_sha256"] = _sha256_payload_excluding(
        report,
        "action_compression_report_sha256",
    )
    return report


def build_v12a_runtime_authority_dominance_diagnosis(*, output_dir: Path) -> dict[str, Any]:
    gate_path = _v12a_calibration_gate_path(output_dir)
    if not gate_path.exists():
        raise ValueError("missing_v0_12_calibration_presignal_gate")
    gate = read_json(gate_path)
    if gate.get("runtime_backend") != "isaac_runtime":
        raise ValueError("v0_12_calibration_not_actual_isaac_runtime")
    if gate.get("heldout_opened") is not False or gate.get("fresh_heldout_36000_36049_accessed") is not False:
        raise ValueError("v0_12a_heldout_claim_boundary_violation")

    baseline_rollouts = json.loads(
        _v12a_rollout_path(output_dir, "baseline").read_text(encoding="utf-8")
    )
    candidate_rollouts = json.loads(
        _v12a_rollout_path(output_dir, "candidate").read_text(encoding="utf-8")
    )
    if not isinstance(baseline_rollouts, list) or not isinstance(candidate_rollouts, list):
        raise ValueError("v0_12a_calibration_rollouts_must_be_lists")

    counts, seed_lists, paired_outcome_rows = _v12a_paired_outcomes(
        baseline_rollouts=baseline_rollouts,
        candidate_rollouts=candidate_rollouts,
    )
    paired_trace_rows = _v12a_paired_trace_rows(
        baseline_rollouts=baseline_rollouts,
        candidate_rollouts=candidate_rollouts,
        output_dir=output_dir,
    )
    action_compression_report = build_v12a_action_compression_report(paired_trace_rows)
    baseline_rate = float(gate["baseline_calibration_success_rate"])
    candidate_rate = float(gate["candidate_calibration_success_rate"])
    success_gap = round(candidate_rate - baseline_rate, 12)
    paired_outcome_divergence_count = counts["B1_C0"] + counts["B0_C1"]
    authority_active_fraction = max(
        float(action_compression_report["shared_xy_authority_active_fraction"]),
        float(action_compression_report["final_post_adapter_z_block_active_fraction"]),
    )
    post_adapter_identical_fraction = float(
        action_compression_report["post_adapter_identical_fraction"] or 0.0
    )
    dominance_supported = (
        baseline_rate > V12_BASELINE_FLOOR_SUCCESS_MAXIMUM
        and candidate_rate >= V12_CALIBRATION_SUCCESS_MINIMUM
        and success_gap < V12_CALIBRATION_UPLIFT_MINIMUM
        and paired_outcome_divergence_count <= 1
        and action_compression_report["post_adapter_delta_smaller_than_raw_delta"] is True
        and (post_adapter_identical_fraction >= 0.5 or authority_active_fraction >= 0.5)
    )
    primary_root_cause_class = (
        "RUNTIME_AUTHORITY_DOMINATES_LEARNED_RESIDUAL_OUTCOME"
        if dominance_supported
        else "UNCLASSIFIED_V12_CALIBRATION_FAILURE"
    )
    recommended_downstream_slice = (
        V12A_RECOMMENDED_DOWNSTREAM_SLICE if dominance_supported else None
    )

    child_dir = output_dir / V12A_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    write_json(child_dir / "v0_12a_paired_outcome_table.json", paired_outcome_rows)
    write_json(child_dir / "v0_12a_action_compression_report.json", action_compression_report)
    report = {
        "schema_version": V12A_DIAGNOSIS_SCHEMA_VERSION,
        "policy_slice": V12A_POLICY_SLICE_ID,
        "source_policy_slice": V12_POLICY_SLICE_ID,
        "slice_id": V12A_SLICE_ID,
        "runtime_backend": "offline_artifact_diagnosis",
        "source_v12_calibration_gate_sha256": _sha256_file(gate_path),
        "baseline_calibration_success_count": int(gate["baseline_calibration_success_count"]),
        "candidate_calibration_success_count": int(gate["candidate_calibration_success_count"]),
        "baseline_calibration_success_rate": baseline_rate,
        "candidate_calibration_success_rate": candidate_rate,
        "candidate_baseline_success_gap": success_gap,
        "baseline_success_floor_maximum": V12_BASELINE_FLOOR_SUCCESS_MAXIMUM,
        "candidate_success_minimum": V12_CALIBRATION_SUCCESS_MINIMUM,
        "candidate_success_gap_minimum": V12_CALIBRATION_UPLIFT_MINIMUM,
        "baseline_floor_exceeded": baseline_rate > V12_BASELINE_FLOOR_SUCCESS_MAXIMUM,
        "candidate_success_requirement_met": candidate_rate >= V12_CALIBRATION_SUCCESS_MINIMUM,
        "calibration_gap_requirement_met": success_gap >= V12_CALIBRATION_UPLIFT_MINIMUM,
        "paired_outcome_counts": counts,
        "paired_outcome_divergence_count": paired_outcome_divergence_count,
        "candidate_recovered_baseline_failure_seeds": seed_lists["B0_C1"],
        "candidate_degraded_baseline_success_seeds": seed_lists["B1_C0"],
        "joint_failure_seeds": seed_lists["B0_C0"],
        "joint_success_seeds": seed_lists["B1_C1"],
        "action_compression_report": action_compression_report,
        "action_compression_report_sha256": action_compression_report[
            "action_compression_report_sha256"
        ],
        "paired_outcome_table": "v0_12a_paired_outcome_table.json",
        "action_compression_report_path": "v0_12a_action_compression_report.json",
        "primary_root_cause_class": primary_root_cause_class,
        "recommended_downstream_slice": recommended_downstream_slice,
        "proof_authority": False,
        "calibration_opened": True,
        "heldout_opened": False,
        "fresh_calibration_35000_35029_accessed": True,
        "fresh_heldout_36000_36049_accessed": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "non_claims": {
            "deployable_real_robot_policy": False,
            "visual_policy_performance": False,
            "real_robot_success": False,
            "physical_robot_readiness": False,
            "hmd_openxr_readiness": False,
        },
    }
    report["v0_12a_diagnosis_sha256"] = _sha256_payload_excluding(
        report,
        "v0_12a_diagnosis_sha256",
    )
    write_json(child_dir / "v0_12a_runtime_authority_dominance_diagnosis.json", report)
    return report


def load_required_v12a_runtime_authority_dominance_diagnosis(
    output_dir: Path,
) -> tuple[dict[str, Any], str]:
    report_path = (
        output_dir
        / V12A_CHILD_OUTPUT_DIRNAME
        / "v0_12a_runtime_authority_dominance_diagnosis.json"
    )
    if not report_path.exists():
        raise ValueError("missing_v0_12a_runtime_authority_dominance_diagnosis")
    report = read_json(report_path)
    expected_hash = _sha256_payload_excluding(report, "v0_12a_diagnosis_sha256")
    if report.get("v0_12a_diagnosis_sha256") != expected_hash:
        raise ValueError("v0_12a_runtime_authority_dominance_diagnosis_hash_mismatch")
    if report.get("primary_root_cause_class") != "RUNTIME_AUTHORITY_DOMINATES_LEARNED_RESIDUAL_OUTCOME":
        raise ValueError("v0_12a_required_runtime_authority_dominance_not_present")
    if report.get("recommended_downstream_slice") != V12A_RECOMMENDED_DOWNSTREAM_SLICE:
        raise ValueError("v0_12a_downstream_slice_mismatch")
    if report.get("heldout_opened") is not False or report.get("fresh_heldout_36000_36049_accessed") is not False:
        raise ValueError("v0_12a_heldout_claim_boundary_violation")
    return report, expected_hash


def build_v13_policy_influence_authority_ceiling_config(
    *,
    source_v12a_diagnosis_sha256: str,
) -> dict[str, Any]:
    config = {
        "schema_version": V13_POLICY_INFLUENCE_CONFIG_SCHEMA_VERSION,
        "policy_slice": V13_POLICY_SLICE_ID,
        "slice_id": V13_SLICE_ID,
        "authority_id": "policy_influence_authority_ceiling_v0_13",
        "source_policy_slice": V12A_POLICY_SLICE_ID,
        "source_v12a_diagnosis_sha256": source_v12a_diagnosis_sha256,
        "source_root_cause_class": "RUNTIME_AUTHORITY_DOMINATES_LEARNED_RESIDUAL_OUTCOME",
        "state_feedback_gain_ceiling": V13_STATE_FEEDBACK_GAIN_CEILING,
        "xy_policy_action_scale": 1.0,
        "xy_action_clip": V13_XY_ACTION_CLIP,
        "z_action_clip": V13_Z_ACTION_CLIP,
        "z_progress_injection_enabled": False,
        "final_xy_state_feedback_replacement_enabled": False,
        "min_post_adapter_delta_retention_ratio": V13_MIN_POST_ADAPTER_DELTA_RETENTION_RATIO,
        "max_post_adapter_identical_fraction": V13_MAX_POST_ADAPTER_IDENTICAL_FRACTION,
        "same_config_for_baseline_and_candidate": True,
        "heldout_excluded": True,
        "fresh_calibration_seed_range": [min(V13_FRESH_CALIBRATION_RANGE), max(V13_FRESH_CALIBRATION_RANGE)],
        "fresh_heldout_seed_range": [min(V13_FRESH_HELDOUT_RANGE), max(V13_FRESH_HELDOUT_RANGE)],
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    config["policy_influence_authority_ceiling_config_sha256"] = _sha256_payload_excluding(
        config,
        "policy_influence_authority_ceiling_config_sha256",
    )
    return config


def _v13_array_from_diag(row: dict[str, Any], key: str) -> np.ndarray | None:
    diagnostics = row.get("controller_action_diagnostics") or {}
    value = diagnostics.get(key, row.get(key))
    if value is None:
        return None
    array = np.asarray(value, dtype=np.float64)
    if array.size == 0:
        return None
    if array.size < len(ACTION_SCHEMA):
        array = np.pad(array, (0, len(ACTION_SCHEMA) - array.size), constant_values=0.0)
    return array[: len(ACTION_SCHEMA)].copy()


def _v13_simulated_policy_influence_action(
    row: dict[str, Any],
    *,
    config: dict[str, Any],
) -> list[float] | None:
    raw = _v13_array_from_diag(row, "raw_action_after_authority")
    if raw is None:
        raw = _v13_array_from_diag(row, "raw_action_before_authority")
    if raw is None:
        return None
    action = raw.copy()
    xy_scale = float(config.get("xy_policy_action_scale", 1.0))
    xy_gain = float(config["state_feedback_gain_ceiling"])
    xy_clip = float(config["xy_action_clip"])
    z_clip = float(config["z_action_clip"])
    action[0] = action[0] * xy_scale - float(row.get("relative_x_m", 0.0)) * xy_gain
    action[1] = action[1] * xy_scale - float(row.get("relative_y_m", 0.0)) * xy_gain
    action[0:2] = np.clip(action[0:2], -xy_clip, xy_clip)
    action[2] = np.clip(action[2], -z_clip, z_clip)
    diagnostics = row.get("controller_action_diagnostics") or {}
    if diagnostics.get("final_post_adapter_z_motion_allowed") is False:
        action[2] = 0.0
    action[3:6] = 0.0
    if action.shape[0] > 6:
        action[6] = np.clip(action[6], -1.0, 1.0)
    return [round(float(value), 12) for value in np.clip(action, -1.0, 1.0)]


def build_v13_policy_influence_simulation_report(
    paired_rows: list[tuple[dict[str, Any], dict[str, Any]]],
    *,
    config: dict[str, Any],
) -> dict[str, Any]:
    raw_before_deltas: list[float] = []
    raw_after_deltas: list[float] = []
    simulated_post_deltas: list[float] = []
    for baseline_row, candidate_row in paired_rows:
        raw_before_delta = _v12a_action_vector_delta(
            baseline_row,
            candidate_row,
            "raw_action_before_authority",
        )
        if raw_before_delta is not None:
            raw_before_deltas.append(raw_before_delta)
        raw_after_delta = _v12a_action_vector_delta(
            baseline_row,
            candidate_row,
            "raw_action_after_authority",
        )
        if raw_after_delta is not None:
            raw_after_deltas.append(raw_after_delta)
        baseline_action = _v13_simulated_policy_influence_action(baseline_row, config=config)
        candidate_action = _v13_simulated_policy_influence_action(candidate_row, config=config)
        if baseline_action is not None and candidate_action is not None:
            simulated_post_deltas.append(
                round(
                    float(
                        np.linalg.norm(
                            np.asarray(baseline_action, dtype=np.float64)
                            - np.asarray(candidate_action, dtype=np.float64)
                        )
                    ),
                    12,
                )
            )
    raw_before_stats = _v12a_delta_stats(raw_before_deltas)
    simulated_stats = _v12a_delta_stats(simulated_post_deltas)
    raw_before_mean = raw_before_stats["mean"]
    simulated_mean = simulated_stats["mean"]
    retention_ratio = (
        round(float(simulated_mean) / float(raw_before_mean), 12)
        if raw_before_mean not in (None, 0) and simulated_mean is not None
        else None
    )
    report = {
        "schema_version": "rdf_mvp2e_v13_policy_influence_simulation_report_v0.1.0",
        "policy_slice": V13_POLICY_SLICE_ID,
        "source_policy_slice": V12A_POLICY_SLICE_ID,
        "paired_trace_row_count": len(paired_rows),
        "delta_stats": {
            "raw_action_before_authority": raw_before_stats,
            "raw_action_after_authority": _v12a_delta_stats(raw_after_deltas),
            "simulated_v13_post_adapter_action": simulated_stats,
        },
        "raw_action_before_authority_mean_delta": raw_before_mean,
        "simulated_v13_post_adapter_mean_delta": simulated_mean,
        "post_adapter_delta_retention_ratio": retention_ratio,
        "post_adapter_identical_fraction": simulated_stats["identical_fraction"],
        "state_feedback_gain_ceiling": config["state_feedback_gain_ceiling"],
        "z_progress_injection_enabled": config["z_progress_injection_enabled"],
        "final_xy_state_feedback_replacement_enabled": config[
            "final_xy_state_feedback_replacement_enabled"
        ],
    }
    report["policy_influence_simulation_report_sha256"] = _sha256_payload_excluding(
        report,
        "policy_influence_simulation_report_sha256",
    )
    return report


def _v13_scrub_inherited_authority_fields(payload: dict[str, Any]) -> None:
    for key in (
        "early_centered_z_open_safe_entry_authority_id",
        "early_centered_z_open_safe_entry_config",
        "early_centered_z_open_safe_entry_config_sha256",
        "same_early_centered_z_open_safe_entry_config_as_peer",
        "final_post_adapter_xy_authority_id",
        "final_post_adapter_xy_authority_config",
        "final_post_adapter_xy_authority_config_sha256",
        "same_xy_authority_config_as_peer",
        "capture_conditioned_progress_authority_id",
        "capture_conditioned_progress_authority_config",
        "capture_conditioned_progress_authority_config_sha256",
        "horizon_reserved_capture_authority_id",
        "horizon_reserved_capture_authority_config",
        "horizon_reserved_capture_authority_config_sha256",
        "deadline_precedence_horizon_authority_id",
        "deadline_precedence_horizon_authority_config",
        "deadline_precedence_horizon_authority_config_sha256",
    ):
        payload.pop(key, None)


def build_v13_policy_artifact_payload(
    *,
    parent_policy_artifact: dict[str, Any],
    dataset_view_role: str,
    source_v12a_diagnosis_sha256: str,
    policy_influence_config: dict[str, Any],
) -> dict[str, Any]:
    role = "candidate" if dataset_view_role.startswith("candidate") else "baseline"
    payload = {
        key: json.loads(json.dumps(value))
        for key, value in parent_policy_artifact.items()
        if key not in {"path", "policy_artifact_sha256"}
    }
    _v13_scrub_inherited_authority_fields(payload)
    selected_config = dict(payload.get("selected_action_adapter_config") or {})
    selected_config.pop("selected_action_adapter_config_sha256", None)
    selected_config.update(
        {
            "xy_source": "policy_plus_state_feedback",
            "xy_action_scale": 1.0,
            "xy_state_feedback_gain": V13_STATE_FEEDBACK_GAIN_CEILING,
            "xy_action_clip": V13_XY_ACTION_CLIP,
            "z_action_clip": V13_Z_ACTION_CLIP,
            "policy_influence_authority_ceiling_id": policy_influence_config["authority_id"],
            "z_progress_injection_enabled": False,
            "final_xy_state_feedback_replacement_enabled": False,
        }
    )
    selected_config_sha256 = _sha256_payload(selected_config)
    hyperparameters = dict(payload.get("hyperparameters") or {})
    hyperparameters.update(
        {
            "policy_influence_authority_ceiling_config_sha256": policy_influence_config[
                "policy_influence_authority_ceiling_config_sha256"
            ],
            "state_feedback_gain_ceiling": V13_STATE_FEEDBACK_GAIN_CEILING,
            "z_progress_injection_enabled": False,
            "final_xy_state_feedback_replacement_enabled": False,
        }
    )
    payload.update(
        {
            "schema_version": V13_POLICY_ARTIFACT_SCHEMA_VERSION,
            "policy_artifact_schema_version": V13_POLICY_ARTIFACT_SCHEMA_VERSION,
            "policy_id": f"{role}_mvp2e_v13_policy_influence_authority_ceiling_policy",
            "policy_slice": V13_POLICY_SLICE_ID,
            "slice_id": V13_SLICE_ID,
            "parent_policy_slice": V12_POLICY_SLICE_ID,
            "source_policy_slice": V12A_POLICY_SLICE_ID,
            "source_v12_policy_artifact_sha256": parent_policy_artifact.get(
                "policy_artifact_sha256"
            ),
            "source_v12a_diagnosis_sha256": source_v12a_diagnosis_sha256,
            "dataset_view_role": dataset_view_role,
            "selected_action_adapter_config": selected_config,
            "selected_action_adapter_config_sha256": selected_config_sha256,
            "policy_influence_authority_ceiling_id": policy_influence_config["authority_id"],
            "policy_influence_authority_ceiling_config": policy_influence_config,
            "policy_influence_authority_ceiling_config_sha256": policy_influence_config[
                "policy_influence_authority_ceiling_config_sha256"
            ],
            "z_progress_injection_enabled": False,
            "final_xy_state_feedback_replacement_enabled": False,
            "hyperparameters": hyperparameters,
            "fresh_calibration_37000_37029_accessed": False,
            "fresh_heldout_38000_38049_accessed": False,
            "heldout_opened": False,
            "mvp2_closed": False,
            "policy_uplift_proven": False,
            "proof_authority": False,
        }
    )
    payload["policy_artifact_sha256"] = _sha256_payload_excluding(payload, "policy_artifact_sha256")
    return payload


def derive_v13_policy_influence_authority_ceiling_gate(
    *,
    candidate_policy: dict[str, Any],
    baseline_policy: dict[str, Any],
    simulation_report: dict[str, Any],
    source_v12a_diagnosis_sha256: str,
    policy_influence_config: dict[str, Any],
) -> dict[str, Any]:
    equality_keys = (
        "selected_action_adapter_id",
        "trainer",
        "trainer_family",
        "policy_class",
        "feature_schema",
        "feature_schema_version",
        "phase_schema",
        "action_schema",
        "base_servo_config_sha256",
        "authority_filter_config_sha256",
        "final_post_adapter_authority_config_sha256",
        "shared_hysteresis_authority_config_sha256",
        "selected_action_adapter_config_sha256",
        "policy_influence_authority_ceiling_config_sha256",
    )
    peer_mismatches = [
        key for key in equality_keys if candidate_policy.get(key) != baseline_policy.get(key)
    ]
    retention_ratio = simulation_report.get("post_adapter_delta_retention_ratio")
    identical_fraction = simulation_report.get("post_adapter_identical_fraction")
    reasons: list[str] = []
    if peer_mismatches:
        reasons.append("peer_fairness_mismatch")
    if retention_ratio is None or float(retention_ratio) < V13_MIN_POST_ADAPTER_DELTA_RETENTION_RATIO:
        reasons.append("post_adapter_delta_retention_below_minimum")
    if identical_fraction is None or float(identical_fraction) > V13_MAX_POST_ADAPTER_IDENTICAL_FRACTION:
        reasons.append("post_adapter_identical_fraction_above_maximum")
    if policy_influence_config.get("z_progress_injection_enabled") is not False:
        reasons.append("z_progress_injection_not_disabled")
    if policy_influence_config.get("final_xy_state_feedback_replacement_enabled") is not False:
        reasons.append("final_xy_state_feedback_replacement_not_disabled")
    gate = {
        "schema_version": V13_POLICY_INFLUENCE_GATE_SCHEMA_VERSION,
        "policy_slice": V13_POLICY_SLICE_ID,
        "slice_id": V13_SLICE_ID,
        "parent_policy_slice": V12_POLICY_SLICE_ID,
        "source_policy_slice": V12A_POLICY_SLICE_ID,
        "source_v12a_diagnosis_sha256": source_v12a_diagnosis_sha256,
        "policy_influence_authority_ceiling_config_sha256": policy_influence_config[
            "policy_influence_authority_ceiling_config_sha256"
        ],
        "policy_influence_simulation_report": simulation_report,
        "policy_influence_simulation_report_sha256": simulation_report[
            "policy_influence_simulation_report_sha256"
        ],
        "state_feedback_gain_ceiling": V13_STATE_FEEDBACK_GAIN_CEILING,
        "post_adapter_delta_retention_ratio": retention_ratio,
        "post_adapter_delta_retention_ratio_minimum": V13_MIN_POST_ADAPTER_DELTA_RETENTION_RATIO,
        "post_adapter_identical_fraction": identical_fraction,
        "post_adapter_identical_fraction_maximum": V13_MAX_POST_ADAPTER_IDENTICAL_FRACTION,
        "same_policy_influence_authority_ceiling_config_as_peer": (
            candidate_policy.get("policy_influence_authority_ceiling_config_sha256")
            == baseline_policy.get("policy_influence_authority_ceiling_config_sha256")
        ),
        "peer_fairness_mismatch_keys": peer_mismatches,
        "z_progress_injection_enabled": False,
        "final_xy_state_feedback_replacement_enabled": False,
        "heldout_opened": False,
        "fresh_calibration_37000_37029_accessed": False,
        "fresh_heldout_38000_38049_accessed": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "passed": not reasons,
        "failure_reasons": reasons,
        "failure_reason": ",".join(reasons),
    }
    gate["policy_influence_authority_ceiling_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "policy_influence_authority_ceiling_gate_sha256",
    )
    return gate


def build_v13_policy_influence_authority_ceiling_slice(*, output_dir: Path) -> dict[str, Any]:
    diagnosis, diagnosis_sha = load_required_v12a_runtime_authority_dominance_diagnosis(
        output_dir
    )
    parent_policies = _load_v12_policy_artifacts(output_dir)
    baseline_rollouts = json.loads(
        _v12a_rollout_path(output_dir, "baseline").read_text(encoding="utf-8")
    )
    candidate_rollouts = json.loads(
        _v12a_rollout_path(output_dir, "candidate").read_text(encoding="utf-8")
    )
    paired_trace_rows = _v12a_paired_trace_rows(
        baseline_rollouts=baseline_rollouts,
        candidate_rollouts=candidate_rollouts,
        output_dir=output_dir,
    )
    child_dir = output_dir / V13_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    config = build_v13_policy_influence_authority_ceiling_config(
        source_v12a_diagnosis_sha256=diagnosis_sha,
    )
    simulation_report = build_v13_policy_influence_simulation_report(
        paired_trace_rows,
        config=config,
    )
    candidate_policy = build_v13_policy_artifact_payload(
        parent_policy_artifact=parent_policies["candidate"],
        dataset_view_role="candidate_curated",
        source_v12a_diagnosis_sha256=diagnosis_sha,
        policy_influence_config=config,
    )
    baseline_policy = build_v13_policy_artifact_payload(
        parent_policy_artifact=parent_policies["baseline"],
        dataset_view_role="baseline_uncurated_terminal_low_floor",
        source_v12a_diagnosis_sha256=diagnosis_sha,
        policy_influence_config=config,
    )
    gate = derive_v13_policy_influence_authority_ceiling_gate(
        candidate_policy=candidate_policy,
        baseline_policy=baseline_policy,
        simulation_report=simulation_report,
        source_v12a_diagnosis_sha256=diagnosis_sha,
        policy_influence_config=config,
    )
    write_json(child_dir / "v0_13_policy_influence_authority_ceiling_config.json", config)
    write_json(child_dir / "v0_13_policy_influence_simulation_report.json", simulation_report)
    write_json(child_dir / "candidate_policy_artifact_v0_13.json", candidate_policy)
    write_json(child_dir / "baseline_policy_artifact_v0_13.json", baseline_policy)
    write_json(child_dir / "policy_influence_authority_ceiling_gate_v0_13.json", gate)
    manifest = {
        "schema_version": V13_MANIFEST_SCHEMA_VERSION,
        "policy_slice": V13_POLICY_SLICE_ID,
        "slice_id": V13_SLICE_ID,
        "parent_policy_slice": V12_POLICY_SLICE_ID,
        "source_policy_slice": V12A_POLICY_SLICE_ID,
        "source_v12a_diagnosis_sha256": diagnosis_sha,
        "source_v12a_primary_root_cause_class": diagnosis["primary_root_cause_class"],
        "policy_influence_authority_ceiling_config": config,
        "policy_influence_authority_ceiling_gate": gate,
        "fresh_calibration_seed_range": [min(V13_FRESH_CALIBRATION_RANGE), max(V13_FRESH_CALIBRATION_RANGE)],
        "fresh_heldout_seed_range": [min(V13_FRESH_HELDOUT_RANGE), max(V13_FRESH_HELDOUT_RANGE)],
        "burned_heldout_seed_ranges": [
            [21000, 21049],
            [24000, 24049],
            [26000, 26049],
            [27000, 27049],
            [32000, 32049],
            [34000, 34049],
            [36000, 36049],
        ],
        "burned_calibration_seed_ranges": [
            [30000, 30029],
            [31000, 31029],
            [33000, 33029],
            [35000, 35029],
        ],
        "policy_artifacts": {
            "candidate": {**candidate_policy, "path": str(child_dir / "candidate_policy_artifact_v0_13.json")},
            "baseline": {**baseline_policy, "path": str(child_dir / "baseline_policy_artifact_v0_13.json")},
        },
        "failed_closed": gate.get("passed") is not True,
        "failure_reason": gate.get("failure_reason", ""),
        "calibration_opened": False,
        "heldout_opened": False,
        "fresh_calibration_37000_37029_accessed": False,
        "fresh_heldout_38000_38049_accessed": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "non_claims": {
            "policy_uplift_proven": False,
            "real_robot_success": False,
            "physical_robot_readiness": False,
            "visual_policy_performance": False,
            "hmd_openxr_readiness": False,
        },
    }
    manifest["v0_13_policy_influence_authority_ceiling_manifest_sha256"] = (
        _sha256_payload_excluding(
            manifest,
            "v0_13_policy_influence_authority_ceiling_manifest_sha256",
        )
    )
    write_json(child_dir / "v0_13_policy_influence_authority_ceiling_manifest.json", manifest)
    return manifest


def _v13_burned_seed_range_accessed(seed: int) -> bool:
    seed_int = int(seed)
    return (
        _v12_burned_seed_range_accessed(seed_int)
        or seed_int in V12_FRESH_CALIBRATION_RANGE
        or seed_int in V12_FRESH_HELDOUT_RANGE
    )


def build_v13_fresh_manifest(
    *,
    output_dir: Path,
    ceiling_manifest: dict[str, Any],
) -> dict[str, Any]:
    gate = ceiling_manifest.get("policy_influence_authority_ceiling_gate", {})
    if gate.get("passed") is not True:
        raise ValueError("v0_13_policy_influence_authority_ceiling_gate_not_passed")
    calibration_rows = [
        _scenario_row(split="calibration", seed=seed)
        for seed in V13_FRESH_CALIBRATION_RANGE
    ]
    heldout_rows = [_scenario_row(split="held_out", seed=seed) for seed in V13_FRESH_HELDOUT_RANGE]
    if any(_v13_burned_seed_range_accessed(int(row["seed"])) for row in calibration_rows):
        raise ValueError("v0_13_fresh_manifest_reuses_burned_calibration_seed_range")
    if any(_v13_burned_seed_range_accessed(int(row["seed"])) for row in heldout_rows):
        raise ValueError("v0_13_fresh_manifest_reuses_burned_heldout_seed_range")
    manifest = {
        "schema_version": V13_MANIFEST_SCHEMA_VERSION,
        "policy_slice": V13_POLICY_SLICE_ID,
        "slice_id": V13_SLICE_ID,
        "parent_policy_slice": V12_POLICY_SLICE_ID,
        "source_policy_slice": V12A_POLICY_SLICE_ID,
        "scenario_profile": "v0_13",
        "task_type": "connector_insertion",
        "success_metric": SUCCESS_METRIC,
        "success_authority": V06_ENV_NATIVE_SUCCESS_AUTHORITY,
        "source_v13_policy_influence_authority_ceiling_manifest_sha256": ceiling_manifest[
            "v0_13_policy_influence_authority_ceiling_manifest_sha256"
        ],
        "source_v13_policy_influence_authority_ceiling_gate_sha256": gate[
            "policy_influence_authority_ceiling_gate_sha256"
        ],
        "policy_influence_authority_ceiling_config_sha256": gate[
            "policy_influence_authority_ceiling_config_sha256"
        ],
        "scenarios": calibration_rows + heldout_rows,
        "fresh_split_manifest": {
            "calibration": {
                "seed_range": [min(V13_FRESH_CALIBRATION_RANGE), max(V13_FRESH_CALIBRATION_RANGE)],
                "scenario_ids": [row["scenario_id"] for row in calibration_rows],
                "count": len(calibration_rows),
            },
            "held_out": {
                "seed_range": [min(V13_FRESH_HELDOUT_RANGE), max(V13_FRESH_HELDOUT_RANGE)],
                "scenario_ids": [row["scenario_id"] for row in heldout_rows],
                "count": len(heldout_rows),
            },
        },
        "burned_heldout_seed_ranges": ceiling_manifest["burned_heldout_seed_ranges"],
        "burned_calibration_seed_ranges": ceiling_manifest["burned_calibration_seed_ranges"],
        "fresh_calibration_35000_35029_accessed": True,
        "fresh_heldout_36000_36049_accessed": False,
        "fresh_calibration_37000_37029_accessed": False,
        "fresh_heldout_38000_38049_accessed": False,
        "calibration_opened": False,
        "heldout_opened": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    manifest["manifest_sha256"] = _sha256_payload_excluding(manifest, "manifest_sha256")
    return manifest


def _v13_runtime_manifest_for_split(*, fresh_manifest: dict[str, Any], split: str) -> dict[str, Any]:
    if split not in {"calibration", "held_out"}:
        raise ValueError("v0_13_runtime_manifest_unknown_split")
    rows = [
        {**row, "source_split": split, "semantic_eval_split": split, "split": "held_out"}
        for row in fresh_manifest.get("scenarios", [])
        if isinstance(row, dict) and row.get("split") == split
    ]
    if not rows:
        raise ValueError(f"v0_13_runtime_manifest_missing_{split}_rows")
    seeds = [int(row["seed"]) for row in rows]
    if split == "calibration":
        if seeds != list(V13_FRESH_CALIBRATION_RANGE):
            raise ValueError("v0_13_calibration_seed_range_mismatch")
        if any(_v13_burned_seed_range_accessed(seed) for seed in seeds):
            raise ValueError("v0_13_runtime_manifest_reuses_burned_calibration_seed_range")
    if split == "held_out":
        if seeds != list(V13_FRESH_HELDOUT_RANGE):
            raise ValueError("v0_13_heldout_seed_range_mismatch")
        if any(_v13_burned_seed_range_accessed(seed) for seed in seeds):
            raise ValueError("v0_13_runtime_manifest_reuses_burned_heldout_seed_range")
    manifest = {
        "schema_version": fresh_manifest["schema_version"],
        "policy_slice": V13_POLICY_SLICE_ID,
        "slice_id": V13_SLICE_ID,
        "parent_policy_slice": V12_POLICY_SLICE_ID,
        "scenario_profile": "v0_13",
        "runtime_split": split,
        "task_type": fresh_manifest["task_type"],
        "success_metric": fresh_manifest["success_metric"],
        "success_authority": fresh_manifest["success_authority"],
        "source_fresh_manifest_sha256": fresh_manifest["manifest_sha256"],
        "scenarios": rows,
        "burned_heldout_seed_ranges": fresh_manifest["burned_heldout_seed_ranges"],
        "burned_calibration_seed_ranges": fresh_manifest["burned_calibration_seed_ranges"],
        "fresh_calibration_37000_37029_accessed": True,
        "fresh_heldout_38000_38049_accessed": split == "held_out",
        "calibration_opened": True,
        "heldout_opened": split == "held_out",
        "proof_authority": split == "held_out",
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    manifest["manifest_sha256"] = _sha256_payload_excluding(manifest, "manifest_sha256")
    return manifest


def _load_v13_policy_artifacts(output_dir: Path) -> dict[str, dict[str, Any]]:
    child_dir = output_dir / V13_CHILD_OUTPUT_DIRNAME
    candidate_path = child_dir / "candidate_policy_artifact_v0_13.json"
    baseline_path = child_dir / "baseline_policy_artifact_v0_13.json"
    if not candidate_path.exists() or not baseline_path.exists():
        raise ValueError("missing_v0_13_policy_artifacts")
    baseline = read_json(baseline_path)
    candidate = read_json(candidate_path)
    reasons: list[str] = []
    for role, policy in (("baseline", baseline), ("candidate", candidate)):
        if policy.get("policy_slice") != V13_POLICY_SLICE_ID:
            reasons.append(f"{role}_policy_slice_mismatch")
        if policy.get("parent_policy_slice") != V12_POLICY_SLICE_ID:
            reasons.append(f"{role}_parent_policy_slice_mismatch")
        if policy.get("source_policy_slice") != V12A_POLICY_SLICE_ID:
            reasons.append(f"{role}_source_policy_slice_mismatch")
        if policy.get("fresh_calibration_37000_37029_accessed") is not False:
            reasons.append(f"{role}_fresh_calibration_accessed_before_runtime")
        if policy.get("fresh_heldout_38000_38049_accessed") is not False:
            reasons.append(f"{role}_fresh_heldout_accessed_before_closure")
        expected_hash = _sha256_payload_excluding(policy, "policy_artifact_sha256")
        if policy.get("policy_artifact_sha256") != expected_hash:
            reasons.append(f"{role}_policy_hash_mismatch")
        config = policy.get("policy_influence_authority_ceiling_config")
        if not isinstance(config, dict):
            reasons.append(f"{role}_policy_influence_config_missing")
        else:
            expected_config_hash = _sha256_payload_excluding(
                config,
                "policy_influence_authority_ceiling_config_sha256",
            )
            if (
                config.get("policy_influence_authority_ceiling_config_sha256")
                != expected_config_hash
                or policy.get("policy_influence_authority_ceiling_config_sha256")
                != expected_config_hash
            ):
                reasons.append(f"{role}_policy_influence_config_hash_mismatch")
    equality_keys = (
        "selected_action_adapter_id",
        "trainer",
        "trainer_family",
        "policy_class",
        "feature_schema",
        "feature_schema_version",
        "phase_schema",
        "action_schema",
        "base_servo_config_sha256",
        "authority_filter_config_sha256",
        "final_post_adapter_authority_config_sha256",
        "shared_hysteresis_authority_config_sha256",
        "selected_action_adapter_config_sha256",
        "policy_influence_authority_ceiling_config_sha256",
    )
    for key in equality_keys:
        if baseline.get(key) != candidate.get(key):
            reasons.append(f"peer_{key}_mismatch")
    if reasons:
        raise ValueError("v0_13_policy_peer_fairness_failed: " + ",".join(reasons))
    return {
        "baseline": {**baseline, "path": str(baseline_path)},
        "candidate": {**candidate, "path": str(candidate_path)},
    }


def _write_v13_calibration_external_rollouts(
    *,
    output_dir: Path,
    baseline_rollouts: list[dict[str, Any]],
    candidate_rollouts: list[dict[str, Any]],
) -> dict[str, str]:
    rollout_dir = output_dir / "calibration_external_rollouts"
    rollout_dir.mkdir(parents=True, exist_ok=True)
    baseline_path = rollout_dir / "baseline_calibration_rollouts_v0_13.json"
    candidate_path = rollout_dir / "candidate_calibration_rollouts_v0_13.json"
    write_json(baseline_path, baseline_rollouts)
    write_json(candidate_path, candidate_rollouts)
    return {"baseline": str(baseline_path), "candidate": str(candidate_path)}


def _v13_policy_influence_runtime_report(
    *,
    baseline_rollouts: list[dict[str, Any]],
    candidate_rollouts: list[dict[str, Any]],
    output_dir: Path,
) -> dict[str, Any]:
    paired_rows = _v12a_paired_trace_rows(
        baseline_rollouts=baseline_rollouts,
        candidate_rollouts=candidate_rollouts,
        output_dir=output_dir,
    )
    compression = build_v12a_action_compression_report(paired_rows)
    raw_mean = compression["raw_action_before_authority_mean_delta"]
    post_mean = compression["post_adapter_action_mean_delta"]
    retention_ratio = (
        round(float(post_mean) / float(raw_mean), 12)
        if raw_mean not in (None, 0) and post_mean is not None
        else None
    )
    report = {
        "schema_version": "rdf_mvp2e_v13_policy_influence_runtime_report_v0.1.0",
        "policy_slice": V13_POLICY_SLICE_ID,
        "paired_trace_row_count": compression["paired_trace_row_count"],
        "action_compression_report": compression,
        "post_adapter_delta_retention_ratio": retention_ratio,
        "post_adapter_identical_fraction": compression["post_adapter_identical_fraction"],
        "policy_influence_preservation_passed": bool(
            retention_ratio is not None
            and retention_ratio >= V13_MIN_POST_ADAPTER_DELTA_RETENTION_RATIO
            and float(compression["post_adapter_identical_fraction"] or 1.0)
            <= V13_MAX_POST_ADAPTER_IDENTICAL_FRACTION
        ),
    }
    report["policy_influence_runtime_report_sha256"] = _sha256_payload_excluding(
        report,
        "policy_influence_runtime_report_sha256",
    )
    return report


def derive_v13_calibration_presignal_gate(
    *,
    baseline_rollouts: list[dict[str, Any]],
    candidate_rollouts: list[dict[str, Any]],
    runtime_gate: dict[str, Any],
    runtime_metadata: dict[str, Any],
    trace_paths: dict[str, list[str]],
    output_dir: Path,
) -> dict[str, Any]:
    gate = derive_v07h_calibration_presignal_gate(
        baseline_rollouts=baseline_rollouts,
        candidate_rollouts=candidate_rollouts,
        runtime_gate=runtime_gate,
        runtime_metadata=runtime_metadata,
        trace_paths=trace_paths,
        output_dir=Path("."),
    )
    baseline_rate = float(gate["baseline_calibration_success_rate"])
    candidate_rate = float(gate["candidate_calibration_success_rate"])
    success_gap = round(candidate_rate - baseline_rate, 12)
    influence = _v13_policy_influence_runtime_report(
        baseline_rollouts=baseline_rollouts,
        candidate_rollouts=candidate_rollouts,
        output_dir=output_dir,
    )
    failure_reason = ""
    if runtime_gate.get("passed") is not True or runtime_metadata.get("runtime_backend") != "isaac_runtime":
        failure_reason = "calibration_runtime_gate_not_passed"
    elif (
        int(gate["baseline_calibration_rollout_count"]) < V07H_CALIBRATION_ROLLOUTS_PER_POLICY
        or int(gate["candidate_calibration_rollout_count"]) < V07H_CALIBRATION_ROLLOUTS_PER_POLICY
    ):
        failure_reason = "calibration_rollout_count_below_minimum"
    elif baseline_rate > V13_BASELINE_FLOOR_SUCCESS_MAXIMUM:
        failure_reason = "baseline_calibration_success_floor_above_v0_13_maximum"
    elif candidate_rate < V13_CALIBRATION_SUCCESS_MINIMUM:
        failure_reason = "candidate_calibration_success_below_v0_13_minimum"
    elif candidate_rate <= baseline_rate:
        failure_reason = "candidate_calibration_not_above_baseline"
    elif success_gap < V13_CALIBRATION_UPLIFT_MINIMUM:
        failure_reason = "candidate_baseline_success_gap_below_v0_13_minimum"
    elif influence["policy_influence_preservation_passed"] is not True:
        failure_reason = "policy_influence_preservation_failed"
    passed = failure_reason == ""
    gate.update(
        {
            "schema_version": V13_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
            "policy_slice": V13_POLICY_SLICE_ID,
            "slice_id": V13_SLICE_ID,
            "parent_policy_slice": V12_POLICY_SLICE_ID,
            "passed": bool(passed),
            "failure_reason": failure_reason,
            "heldout_allowed": bool(passed),
            "candidate_baseline_success_gap": success_gap,
            "candidate_success_gap_minimum": V13_CALIBRATION_UPLIFT_MINIMUM,
            "candidate_calibration_success_minimum": V13_CALIBRATION_SUCCESS_MINIMUM,
            "baseline_calibration_success_floor_maximum": V13_BASELINE_FLOOR_SUCCESS_MAXIMUM,
            "policy_influence_runtime_report": influence,
            "policy_influence_preservation_passed": bool(
                influence["policy_influence_preservation_passed"]
            ),
            "fresh_calibration_37000_37029_accessed": True,
            "fresh_heldout_38000_38049_accessed": False,
            "source": "v0_13_policy_influence_authority_ceiling_calibration_runtime",
            "mvp2_closed": False,
            "policy_uplift_proven": False,
        }
    )
    gate["calibration_presignal_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "calibration_presignal_gate_sha256",
    )
    return gate


def run_v13_policy_influence_authority_ceiling_runtime(
    *,
    output_dir: Path,
    device: str = DEFAULT_ISAAC_DEVICE,
    headless: bool = True,
    isaac_task: str = DEFAULT_ISAAC_TASK,
    max_steps: int = int(SUCCESS_METRIC["max_steps"]),
    action_scale: float = 1.0,
    min_rollouts_per_policy: int = MIN_PROOF_ROLLOUTS_PER_POLICY,
    bootstrap_iterations: int = 2000,
    bootstrap_seed: int = 23,
    backend: Any | None = None,
) -> dict[str, Any]:
    child_dir = output_dir / V13_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    ceiling_manifest = build_v13_policy_influence_authority_ceiling_slice(output_dir=output_dir)
    if ceiling_manifest["policy_influence_authority_ceiling_gate"].get("passed") is not True:
        return ceiling_manifest["policy_influence_authority_ceiling_gate"]
    fresh_manifest = build_v13_fresh_manifest(
        output_dir=output_dir,
        ceiling_manifest=ceiling_manifest,
    )
    write_json(child_dir / "v0_13_fresh_manifest.json", fresh_manifest)
    policy_artifacts = _load_v13_policy_artifacts(output_dir)
    baseline_policy = policy_artifacts["baseline"]
    candidate_policy = policy_artifacts["candidate"]
    selected_adapter_id = str(candidate_policy["selected_action_adapter_id"])
    policy_class = str(candidate_policy["policy_class"])
    trainer = str(candidate_policy["trainer"])
    use_single_app_actual_backend = (
        backend is None
        and getattr(IsaacConnectorInsertionEvaluatorBackend, "__name__", "")
        == "IsaacConnectorInsertionEvaluatorBackend"
    )
    evaluator_backend = backend or IsaacConnectorInsertionEvaluatorBackend(
        task=isaac_task,
        device=device,
        headless=headless,
        action_scale=action_scale,
        max_steps=max_steps,
    )
    actual_env = None
    actual_simulation_app = None
    actual_torch = None
    if use_single_app_actual_backend:
        from isaaclab.app import AppLauncher

        app_launcher = AppLauncher(
            {
                "headless": headless,
                "device": device,
                "enable_cameras": False,
            }
        )
        actual_simulation_app = app_launcher.app

        import gymnasium as gym
        import torch as torch_module

        import isaaclab_tasks  # noqa: F401
        from isaaclab_tasks.utils import parse_env_cfg

        env_cfg = parse_env_cfg(isaac_task, device=device, num_envs=1)
        actual_env = gym.make(isaac_task, cfg=env_cfg).unwrapped
        actual_torch = torch_module

    def run_runtime_manifest(
        *,
        manifest: dict[str, Any],
        runtime_output_dir: Path,
        rollouts_per_policy: int,
    ) -> BackendResult:
        if actual_env is not None:
            return _run_v08a_manifest_with_existing_isaac(
                evaluator_backend=evaluator_backend,
                env=actual_env,
                simulation_app=actual_simulation_app,
                torch_module=actual_torch,
                manifest=manifest,
                output_dir=runtime_output_dir,
                min_rollouts_per_policy=rollouts_per_policy,
                policy_artifacts=policy_artifacts,
            )
        return evaluator_backend.run(
            manifest=manifest,
            output_dir=runtime_output_dir,
            min_rollouts_per_policy=rollouts_per_policy,
            deterministic_profile="candidate_positive",
            policy_artifacts=policy_artifacts,
        )

    calibration_manifest = _v13_runtime_manifest_for_split(
        fresh_manifest=fresh_manifest,
        split="calibration",
    )
    write_json(child_dir / "calibration_runtime_manifest_v0_13.json", calibration_manifest)
    calibration_result = run_runtime_manifest(
        manifest=calibration_manifest,
        runtime_output_dir=child_dir / "isaac_runtime_fresh_calibration_v0_13",
        rollouts_per_policy=V07H_CALIBRATION_ROLLOUTS_PER_POLICY,
    )
    calibration_rollout_paths = _write_v13_calibration_external_rollouts(
        output_dir=child_dir,
        baseline_rollouts=list(calibration_result.baseline_rollouts),
        candidate_rollouts=list(calibration_result.candidate_rollouts),
    )
    calibration_trace_paths = {
        "baseline": list(calibration_result.baseline_trace_paths),
        "candidate": list(calibration_result.candidate_trace_paths),
    }
    calibration_gate = derive_v13_calibration_presignal_gate(
        baseline_rollouts=list(calibration_result.baseline_rollouts),
        candidate_rollouts=list(calibration_result.candidate_rollouts),
        runtime_gate=dict(calibration_result.runtime_gate),
        runtime_metadata=dict(calibration_result.runtime_metadata),
        trace_paths=calibration_trace_paths,
        output_dir=output_dir,
    )
    calibration_gate["calibration_runtime_manifest_sha256"] = calibration_manifest["manifest_sha256"]
    calibration_gate["baseline_calibration_rollout_path"] = calibration_rollout_paths["baseline"]
    calibration_gate["candidate_calibration_rollout_path"] = calibration_rollout_paths["candidate"]
    calibration_gate["calibration_presignal_gate_sha256"] = _sha256_payload_excluding(
        calibration_gate,
        "calibration_presignal_gate_sha256",
    )
    write_json(child_dir / "calibration_presignal_gate_v0_13.json", calibration_gate)
    write_json(output_dir / "calibration_presignal_gate.json", calibration_gate)
    if calibration_gate.get("passed") is not True:
        calibration_gate["mvp2_closed"] = False
        calibration_gate["policy_uplift_proven"] = False
        if actual_env is not None:
            actual_env.close()
        return calibration_gate

    selection = _v08a_calibration_selection_report(output_dir)
    training_scenario_ids = _v08a_training_scenario_ids(output_dir)
    heldout_manifest = _v13_runtime_manifest_for_split(
        fresh_manifest=fresh_manifest,
        split="held_out",
    )
    write_json(child_dir / "heldout_runtime_manifest_v0_13.json", heldout_manifest)
    heldout_leakage_guard = validate_no_heldout_leakage(
        manifest=heldout_manifest,
        training_scenario_ids=training_scenario_ids,
        curation_tuning_scenario_ids=[],
        threshold_tuning_scenario_ids=[],
        hyperparameter_scenario_ids=[],
        calibration_selector_scenario_ids=[
            str(item) for item in selection.get("calibration_scenario_ids", [])
        ],
    )
    if heldout_leakage_guard["passed"] is not True:
        raise ValueError("v0_13_fresh_heldout_leakage_guard_failed")
    parent_child_dir = output_dir / V12_CHILD_OUTPUT_DIRNAME
    baseline_view = _existing_train_view(
        parent_child_dir / "baseline_uncurated_terminal_low_floor_train_v0_12.hdf5",
        view_id="baseline_uncurated_terminal_low_floor_v0_12",
    )
    candidate_view = _existing_train_view(
        parent_child_dir / "candidate_curated_train_v0_12.hdf5",
        view_id="candidate_curated_v0_12_baseline_floor_suppression",
    )
    bridge_dir = _write_learning_harness_bridge(
        output_dir=child_dir,
        manifest=heldout_manifest,
        baseline_view=baseline_view,
        candidate_view=candidate_view,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    heldout_rollouts_per_policy = max(
        int(min_rollouts_per_policy),
        STRONGER_PUBLIC_ROLLOUTS_PER_POLICY,
        len(V13_FRESH_HELDOUT_RANGE),
    )
    heldout_result = run_runtime_manifest(
        manifest=heldout_manifest,
        runtime_output_dir=child_dir / "isaac_runtime_fresh_heldout_v0_13",
        rollouts_per_policy=heldout_rollouts_per_policy,
    )
    runtime_gate = dict(heldout_result.runtime_gate)
    actual_rollouts_per_policy = min(
        len(heldout_result.baseline_rollouts),
        len(heldout_result.candidate_rollouts),
    )
    runtime_gate["actual_baseline_rollouts"] = len(heldout_result.baseline_rollouts)
    runtime_gate["actual_candidate_rollouts"] = len(heldout_result.candidate_rollouts)
    runtime_gate["actual_rollouts_per_policy"] = actual_rollouts_per_policy
    combined_rollouts = list(heldout_result.baseline_rollouts) + list(heldout_result.candidate_rollouts)
    if any(_v13_burned_seed_range_accessed(int(rollout.get("seed", -1))) for rollout in combined_rollouts):
        raise ValueError("v0_13_burned_seed_accessed")
    heldout_suite = _heldout_suite(heldout_manifest)
    baseline_rollouts_path = _write_external_rollout_json(
        output_dir=child_dir,
        role="baseline",
        policy_artifact=baseline_policy,
        train_view=baseline_view,
        heldout_suite=heldout_suite,
        backend_result=heldout_result,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    candidate_rollouts_path = _write_external_rollout_json(
        output_dir=child_dir,
        role="candidate",
        policy_artifact=candidate_policy,
        train_view=candidate_view,
        heldout_suite=heldout_suite,
        backend_result=heldout_result,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    learning_report = _run_learning_validator(
        output_dir=child_dir,
        bridge_dir=bridge_dir,
        baseline_rollouts_path=baseline_rollouts_path,
        candidate_rollouts_path=candidate_rollouts_path,
        min_rollouts_per_policy=MIN_PROOF_ROLLOUTS_PER_POLICY,
        bootstrap_iterations=bootstrap_iterations,
        bootstrap_seed=bootstrap_seed,
        policy_class=policy_class,
        trainer=trainer,
    )
    train_generation_runtime_gate, train_gate_sha256 = load_v07a2_parent_train_generation_gate(output_dir)
    closure = derive_mvp2c_closure(
        learning_report=learning_report,
        runtime_gate=runtime_gate,
        train_generation_runtime_gate=train_generation_runtime_gate,
        calibration_selection_report=selection,
        heldout_leakage_guard=heldout_leakage_guard,
        actual_rollouts_per_policy=actual_rollouts_per_policy,
    )
    confidence_interval_report = _bootstrap_uplift_ci(
        baseline_rollouts=list(heldout_result.baseline_rollouts),
        candidate_rollouts=list(heldout_result.candidate_rollouts),
        iterations=bootstrap_iterations,
        seed=bootstrap_seed,
    )
    gate = {
        "schema_version": V13_HELDOUT_CLOSURE_SCHEMA_VERSION,
        "policy_slice": V13_POLICY_SLICE_ID,
        "slice_id": V13_SLICE_ID,
        "parent_policy_slice": V12_POLICY_SLICE_ID,
        "source_fresh_manifest_sha256": fresh_manifest["manifest_sha256"],
        "policy_influence_authority_ceiling_config_sha256": ceiling_manifest[
            "policy_influence_authority_ceiling_config"
        ]["policy_influence_authority_ceiling_config_sha256"],
        "policy_influence_authority_ceiling_gate_sha256": ceiling_manifest[
            "policy_influence_authority_ceiling_gate"
        ]["policy_influence_authority_ceiling_gate_sha256"],
        "parent_train_generation_runtime_gate_sha256": train_gate_sha256,
        "fresh_calibration_presignal_gate_sha256": calibration_gate[
            "calibration_presignal_gate_sha256"
        ],
        "runtime_backend": heldout_result.runtime_backend,
        "proof_runtime": heldout_result.proof_runtime,
        "runtime_gate": runtime_gate,
        "actual_rollouts_per_policy": actual_rollouts_per_policy,
        "baseline_success_rate": learning_report.get("baseline_success_rate"),
        "candidate_success_rate": learning_report.get("candidate_success_rate"),
        "curated_vs_uncurated_uplift": learning_report.get("curated_vs_uncurated_uplift"),
        "learning_report_path": str(
            child_dir / "mvp2_learning_proven_policy_eval" / "mvp2_learning_proven_report.json"
        ),
        "baseline_external_rollouts": str(baseline_rollouts_path),
        "candidate_external_rollouts": str(candidate_rollouts_path),
        "confidence_interval_report": confidence_interval_report,
        "stronger_public_evidence_target_passed": _derive_public_evidence_target(
            actual_rollouts_per_policy=actual_rollouts_per_policy,
            confidence_interval_report=confidence_interval_report,
        ),
        "calibration_opened": True,
        "heldout_opened": True,
        "fresh_calibration_37000_37029_accessed": True,
        "fresh_heldout_38000_38049_accessed": True,
        "same_heldout_reuse_allowed_for_closure": False,
        "heldout_leakage_guard": heldout_leakage_guard,
        "calibration_selection_report_sha256": _sha256_file(output_dir / "calibration_selection_report.json"),
        "selected_action_adapter_id": selected_adapter_id,
        "same_adapter_used_for_baseline_and_candidate": True,
        "same_policy_class": baseline_policy.get("policy_class") == candidate_policy.get("policy_class"),
        "same_trainer": baseline_policy.get("trainer") == candidate_policy.get("trainer"),
        "same_feature_schema": baseline_policy.get("feature_schema") == candidate_policy.get("feature_schema"),
        "mvp2_closed": closure["mvp2_closed"],
        "mvp2c_close_minimum_passed": closure["mvp2c_close_minimum_passed"],
        "policy_uplift_proven": closure["learning_proven"],
        "proof_eligible": closure["proof_eligible"],
        "blockers": closure["blockers"] + list(learning_report.get("blockers") or []),
        "non_claims": {
            "deployable_real_robot_policy": False,
            "visual_policy_performance": False,
            "real_robot_success": False,
            "physical_robot_readiness": False,
            "universal_robot_support": False,
            "hmd_openxr_readiness": False,
        },
    }
    gate["heldout_closure_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "heldout_closure_gate_sha256",
    )
    write_json(child_dir / "heldout_closure_gate_v0_13.json", gate)
    write_json(output_dir / "heldout_closure_gate.json", gate)
    if actual_env is not None:
        actual_env.close()
    return gate


def _v14_source_summary_from_row(row: dict[str, Any]) -> dict[str, Any]:
    path_value = row.get("runtime_trace_path") or row.get("source_trace_path")
    summary = {
        "path": str(path_value) if path_value else "",
        "success": row.get("source_trace_summary_success"),
        "env_native_rollout_success": row.get("source_trace_summary_env_native_rollout_success"),
        "failure_reason": row.get("source_trace_summary_failure_reason"),
    }
    if path_value and (
        summary["success"] is None
        or summary["env_native_rollout_success"] is None
        or summary["failure_reason"] is None
    ):
        path = Path(str(path_value))
        if path.exists():
            payload = read_json(path)
            payload_summary = payload.get("summary") or {}
            payload_success = bool(payload_summary.get("success"))
            summary.update(
                {
                    "success": payload_success,
                    "env_native_rollout_success": bool(
                        payload_summary.get("env_native_rollout_success", payload_success)
                    ),
                    "failure_reason": str(payload_summary.get("failure_reason") or ""),
                }
            )
    return summary


def derive_v14_source_provenance_report(
    baseline_rows: list[dict[str, Any]],
    *,
    candidate_rows: list[dict[str, Any]],
) -> dict[str, Any]:
    reasons: list[str] = []
    failure_rows = [row for row in baseline_rows if row.get("accepted") is False]
    for row in failure_rows:
        summary = _v14_source_summary_from_row(row)
        if row.get("source_trace_role") != "train_generation_failed_attempt":
            reasons.append("failure_row_source_trace_role_mismatch")
            break
        if summary["success"] is True or summary["env_native_rollout_success"] is True:
            reasons.append("failure_row_source_trace_summary_success_true")
            break
        if not str(summary.get("failure_reason") or ""):
            reasons.append("failure_row_missing_source_failure_reason")
            break
    if _v08k_any_calibration_or_heldout_training_rows(candidate_rows + baseline_rows):
        reasons.append("calibration_or_heldout_rows_used_for_training")
    report = {
        "schema_version": "rdf_mvp2e_v14_source_provenance_report_v0.1.0",
        "policy_slice": V14_POLICY_SLICE_ID,
        "failure_row_count": len(failure_rows),
        "candidate_row_count": len(candidate_rows),
        "passed": not reasons,
        "failure_reasons": reasons,
        "failure_reason": ",".join(reasons),
    }
    report["source_provenance_report_sha256"] = _sha256_payload_excluding(
        report,
        "source_provenance_report_sha256",
    )
    return report


def _v14_failure_source_key(row: dict[str, Any]) -> str:
    source_key = (
        row.get("uncurated_low_floor_source_row_sha256")
        or row.get("source_row_sha256")
        or f"{row.get('runtime_trace_path') or row.get('source_trace_path')}:{row.get('step')}"
    )
    return str(source_key)


def build_v14_row_balanced_baseline_rows(
    *,
    success_rows: list[dict[str, Any]],
    failure_rows: list[dict[str, Any]],
) -> tuple[list[dict[str, Any]], dict[str, Any]]:
    if not success_rows:
        raise ValueError("v0_14_success_rows_missing")
    if not failure_rows:
        raise ValueError("v0_14_failure_rows_missing")

    grouped: dict[str, list[dict[str, Any]]] = {}
    seen_source_rows: set[str] = set()
    duplicate_source_rows = 0
    for source_row in failure_rows:
        trace_key = str(source_row.get("runtime_trace_path") or source_row.get("source_trace_path") or "")
        if not trace_key:
            raise ValueError("v0_14_failure_row_missing_source_trace")
        source_key = _v14_failure_source_key(source_row)
        if source_key in seen_source_rows:
            duplicate_source_rows += 1
            continue
        seen_source_rows.add(source_key)
        row = _v09_deepcopy_row(source_row)
        row["uncurated_row_balance_source_row_sha256"] = source_key
        grouped.setdefault(trace_key, []).append(row)

    if not grouped:
        raise ValueError("v0_14_unique_failure_rows_missing")

    capped_by_trace: dict[str, list[dict[str, Any]]] = {}
    capped_failure_rows_per_trace: dict[str, int] = {}
    for trace_key, rows in sorted(grouped.items()):
        rows_sorted = sorted(rows, key=lambda item: int(item.get("step", 0)))
        selected = rows_sorted[-V14_MAX_ROWS_PER_FAILURE_SOURCE_TRACE:]
        capped_by_trace[trace_key] = selected
        capped_failure_rows_per_trace[trace_key] = len(selected)

    capped_count = sum(len(rows) for rows in capped_by_trace.values())
    target_pair_count = min(len(success_rows), capped_count)
    if target_pair_count <= 0:
        raise ValueError("v0_14_row_balance_target_missing")

    selected_failure_rows: list[dict[str, Any]] = []
    per_trace_selected: Counter[str] = Counter()
    index_by_trace = {trace_key: 0 for trace_key in capped_by_trace}
    trace_order = sorted(capped_by_trace)
    while len(selected_failure_rows) < target_pair_count:
        progressed = False
        for trace_key in trace_order:
            rows = capped_by_trace[trace_key]
            index = index_by_trace[trace_key]
            if index >= len(rows):
                continue
            row = _v09_deepcopy_row(rows[index])
            row.update(
                {
                    "proof_role": "v0_14_row_balanced_uncurated_failure_material",
                    "uncurated_row_balance_policy_slice": V14_POLICY_SLICE_ID,
                    "uncurated_row_balance_is_failure_material": True,
                    "uncurated_row_balance_duplicate_allowed": False,
                    "uncurated_row_balance_source_row_sha256": _v14_failure_source_key(rows[index]),
                }
            )
            selected_failure_rows.append(row)
            per_trace_selected[trace_key] += 1
            index_by_trace[trace_key] += 1
            progressed = True
            if len(selected_failure_rows) >= target_pair_count:
                break
        if not progressed:
            break

    baseline_success_rows = [_v09_deepcopy_row(row) for row in success_rows[:target_pair_count]]
    for row in baseline_success_rows:
        row.update(
            {
                "uncurated_row_balance_policy_slice": V14_POLICY_SLICE_ID,
                "uncurated_row_balance_is_failure_material": False,
                "uncurated_row_balance_duplicate_allowed": False,
            }
        )
    baseline_rows = baseline_success_rows + selected_failure_rows
    ratio = len(selected_failure_rows) / len(baseline_rows)
    report = {
        "success_row_count": len(success_rows),
        "selected_success_row_count": len(baseline_success_rows),
        "source_failure_row_count": len(failure_rows),
        "duplicate_source_failure_row_count": duplicate_source_rows,
        "unique_source_failure_row_count": len(seen_source_rows),
        "source_failure_trace_count": len(grouped),
        "selected_failure_row_count": len(selected_failure_rows),
        "baseline_actual_failure_material_ratio": round(ratio, 12),
        "baseline_failure_material_ratio_target": V14_BASELINE_FAILURE_MATERIAL_RATIO,
        "baseline_failure_ratio_min": V14_BASELINE_FAILURE_RATIO_MIN,
        "baseline_failure_ratio_max": V14_BASELINE_FAILURE_RATIO_MAX,
        "max_rows_per_failure_source_trace": V14_MAX_ROWS_PER_FAILURE_SOURCE_TRACE,
        "max_failure_to_success_row_ratio": V14_MAX_FAILURE_TO_SUCCESS_ROW_RATIO,
        "duplicate_failure_rows_allowed": False,
        "selected_failure_rows_per_trace": dict(sorted(per_trace_selected.items())),
        "capped_failure_rows_per_trace": dict(sorted(capped_failure_rows_per_trace.items())),
        "failure_material_selection": "row_balanced_near_miss_terminal_failure_rows",
    }
    return baseline_rows, report


def build_v14_policy_artifact_payload(
    *,
    parent_policy_artifact: dict[str, Any],
    base_policy_artifact: dict[str, Any],
    dataset_view_role: str,
    training_view: dict[str, Any],
    row_balance_gate_sha256: str,
    source_v13_manifest_sha256: str,
) -> dict[str, Any]:
    role = "candidate" if dataset_view_role.startswith("candidate") else "baseline"
    payload = {
        key: json.loads(json.dumps(value))
        for key, value in parent_policy_artifact.items()
        if key not in {"path", "policy_artifact_sha256"}
    }
    for key in (
        "weights",
        "bias",
        "train_sample_count",
        "hyperparameters",
        "feature_schema",
        "feature_schema_version",
        "phase_schema",
        "action_schema",
    ):
        payload[key] = base_policy_artifact[key]
    hyperparameters = dict(payload.get("hyperparameters") or {})
    hyperparameters.update(
        {
            "comparator_provenance_row_balance_gate_sha256": row_balance_gate_sha256,
            "baseline_failure_material_ratio_target": V14_BASELINE_FAILURE_MATERIAL_RATIO,
            "max_rows_per_failure_source_trace": V14_MAX_ROWS_PER_FAILURE_SOURCE_TRACE,
        }
    )
    payload.update(
        {
            "schema_version": V14_POLICY_ARTIFACT_SCHEMA_VERSION,
            "policy_artifact_schema_version": V14_POLICY_ARTIFACT_SCHEMA_VERSION,
            "policy_id": f"{role}_mvp2e_v14_comparator_provenance_row_balance_policy",
            "policy_slice": V14_POLICY_SLICE_ID,
            "slice_id": V14_SLICE_ID,
            "parent_policy_slice": V13_POLICY_SLICE_ID,
            "source_policy_slice": V13_POLICY_SLICE_ID,
            "source_v13_policy_artifact_sha256": parent_policy_artifact.get("policy_artifact_sha256"),
            "source_v13_manifest_sha256": source_v13_manifest_sha256,
            "dataset_view_role": dataset_view_role,
            "hyperparameters": hyperparameters,
            "training_view_sha256": training_view["sha256"],
            "training_view_path": training_view["path"],
            "comparator_provenance_row_balance_gate_sha256": row_balance_gate_sha256,
            "fresh_calibration_39000_39029_accessed": False,
            "fresh_heldout_40000_40049_accessed": False,
            "heldout_opened": False,
            "mvp2_closed": False,
            "policy_uplift_proven": False,
            "proof_authority": False,
        }
    )
    payload["policy_artifact_sha256"] = _sha256_payload_excluding(payload, "policy_artifact_sha256")
    return payload


def derive_v14_comparator_provenance_row_balance_gate(
    *,
    candidate_policy: dict[str, Any],
    baseline_policy: dict[str, Any],
    row_balance_report: dict[str, Any],
    provenance_report: dict[str, Any],
    source_v13_manifest_sha256: str,
) -> dict[str, Any]:
    equality_keys = (
        "selected_action_adapter_id",
        "trainer",
        "trainer_family",
        "policy_class",
        "feature_schema",
        "feature_schema_version",
        "phase_schema",
        "action_schema",
        "base_servo_config_sha256",
        "authority_filter_config_sha256",
        "final_post_adapter_authority_config_sha256",
        "shared_hysteresis_authority_config_sha256",
        "selected_action_adapter_config_sha256",
        "policy_influence_authority_ceiling_config_sha256",
    )
    peer_mismatches = [
        key for key in equality_keys if candidate_policy.get(key) != baseline_policy.get(key)
    ]
    ratio = float(row_balance_report.get("baseline_actual_failure_material_ratio", 0.0))
    success_count = int(row_balance_report.get("selected_success_row_count", 0))
    failure_count = int(row_balance_report.get("selected_failure_row_count", 0))
    failure_to_success = round(failure_count / success_count, 12) if success_count else float("inf")
    reasons: list[str] = []
    if peer_mismatches:
        reasons.append("peer_fairness_mismatch")
    if provenance_report.get("passed") is not True:
        reasons.append("source_provenance_failed")
    if ratio < V14_BASELINE_FAILURE_RATIO_MIN or ratio > V14_BASELINE_FAILURE_RATIO_MAX:
        reasons.append("baseline_failure_material_ratio_out_of_bounds")
    if failure_to_success > V14_MAX_FAILURE_TO_SUCCESS_ROW_RATIO:
        reasons.append("failure_to_success_row_ratio_above_maximum")
    if row_balance_report.get("duplicate_failure_rows_allowed") is not False:
        reasons.append("duplicate_failure_rows_not_disabled")
    gate = {
        "schema_version": V14_GATE_SCHEMA_VERSION,
        "policy_slice": V14_POLICY_SLICE_ID,
        "slice_id": V14_SLICE_ID,
        "parent_policy_slice": V13_POLICY_SLICE_ID,
        "source_v13_manifest_sha256": source_v13_manifest_sha256,
        "row_balance_report": row_balance_report,
        "source_provenance_report": provenance_report,
        "source_provenance_report_sha256": provenance_report["source_provenance_report_sha256"],
        "baseline_actual_failure_material_ratio": ratio,
        "baseline_failure_material_ratio_target": V14_BASELINE_FAILURE_MATERIAL_RATIO,
        "failure_to_success_row_ratio": failure_to_success,
        "max_failure_to_success_row_ratio": V14_MAX_FAILURE_TO_SUCCESS_ROW_RATIO,
        "max_rows_per_failure_source_trace": V14_MAX_ROWS_PER_FAILURE_SOURCE_TRACE,
        "duplicate_failure_rows_allowed": False,
        "same_policy_influence_authority_ceiling_config_as_peer": (
            candidate_policy.get("policy_influence_authority_ceiling_config_sha256")
            == baseline_policy.get("policy_influence_authority_ceiling_config_sha256")
        ),
        "peer_fairness_mismatch_keys": peer_mismatches,
        "fresh_calibration_39000_39029_accessed": False,
        "fresh_heldout_40000_40049_accessed": False,
        "heldout_opened": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "passed": not reasons,
        "failure_reasons": reasons,
        "failure_reason": ",".join(reasons),
    }
    gate["comparator_provenance_row_balance_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "comparator_provenance_row_balance_gate_sha256",
    )
    return gate


def build_v14_comparator_provenance_row_balance_slice(*, output_dir: Path) -> dict[str, Any]:
    v13_child_dir = output_dir / V13_CHILD_OUTPUT_DIRNAME
    v13_manifest_path = v13_child_dir / "v0_13_policy_influence_authority_ceiling_manifest.json"
    if not v13_manifest_path.exists():
        build_v13_policy_influence_authority_ceiling_slice(output_dir=output_dir)
    v13_manifest = read_json(v13_manifest_path)
    v13_gate = v13_manifest.get("policy_influence_authority_ceiling_gate", {})
    if v13_gate.get("passed") is not True:
        raise ValueError("v0_13_policy_influence_authority_ceiling_gate_not_passed")
    source_v13_manifest_sha = _sha256_payload_excluding(
        v13_manifest,
        "v0_13_policy_influence_authority_ceiling_manifest_sha256",
    )
    parent_policies = _load_v13_policy_artifacts(output_dir)
    source_dir = output_dir / V12_CHILD_OUTPUT_DIRNAME
    candidate_rows = _rows_from_hdf5_metadata(source_dir / "candidate_curated_train_v0_12.hdf5")
    v12_baseline_rows = _rows_from_hdf5_metadata(
        source_dir / "baseline_uncurated_terminal_low_floor_train_v0_12.hdf5"
    )
    success_rows = [_v09_deepcopy_row(row) for row in candidate_rows if row.get("accepted") is not False]
    failure_rows = [_v09_deepcopy_row(row) for row in v12_baseline_rows if row.get("accepted") is False]
    baseline_rows, row_balance_report = build_v14_row_balanced_baseline_rows(
        success_rows=success_rows,
        failure_rows=failure_rows,
    )
    candidate_rows_v14 = [_v09_deepcopy_row(row) for row in candidate_rows]
    provenance_report = derive_v14_source_provenance_report(
        baseline_rows,
        candidate_rows=candidate_rows_v14,
    )
    child_dir = output_dir / V14_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    authority_config = dict(parent_policies["candidate"].get("authority_filter_config") or {})
    if not authority_config:
        authority_config = _v09_source_authority_config(output_dir, parent_policies["candidate"])
    validate_v07c_action_authority_config_contract(authority_config)
    candidate_view = write_v07c_residual_train_view_hdf5(
        path=child_dir / "candidate_curated_train_v0_14.hdf5",
        rows=candidate_rows_v14,
        view_id="candidate_curated_v0_14_comparator_provenance_row_balance",
        authority_config=authority_config,
        schema_version=V14_MANIFEST_SCHEMA_VERSION,
        extra_hdf5_attrs={
            "policy_slice": V14_POLICY_SLICE_ID,
            "candidate_rows_unchanged_from_v13": True,
        },
        extra_view_fields={
            "policy_slice": V14_POLICY_SLICE_ID,
            "candidate_rows_unchanged_from_v13": True,
        },
    )
    baseline_view = write_v07c_residual_train_view_hdf5(
        path=child_dir / "baseline_uncurated_row_balanced_train_v0_14.hdf5",
        rows=baseline_rows,
        view_id="baseline_uncurated_row_balanced_v0_14",
        authority_config=authority_config,
        schema_version=V14_MANIFEST_SCHEMA_VERSION,
        extra_hdf5_attrs={
            "policy_slice": V14_POLICY_SLICE_ID,
            "baseline_actual_failure_material_ratio": row_balance_report[
                "baseline_actual_failure_material_ratio"
            ],
        },
        extra_view_fields={
            "policy_slice": V14_POLICY_SLICE_ID,
            **row_balance_report,
        },
    )
    candidate_base = {
        key: parent_policies["candidate"][key]
        for key in (
            "weights",
            "bias",
            "train_sample_count",
            "feature_schema",
            "feature_schema_version",
            "phase_schema",
            "action_schema",
        )
    }
    candidate_base["hyperparameters"] = dict(parent_policies["candidate"].get("hyperparameters") or {})
    baseline_hyperparameters = dict(parent_policies["baseline"].get("hyperparameters") or {})
    baseline_hyperparameters.update(
        {
            "trainer_family": RESIDUAL_TRAINER_FAMILY,
            "baseline_failure_material_ratio_target": V14_BASELINE_FAILURE_MATERIAL_RATIO,
            "max_rows_per_failure_source_trace": V14_MAX_ROWS_PER_FAILURE_SOURCE_TRACE,
            "duplicate_failure_rows_allowed": False,
        }
    )
    baseline_base = fit_phase_conditioned_bc_policy(
        policy_id="baseline_uncurated_row_balanced_mvp2e_v14_bc",
        train_rows=baseline_rows,
        hyperparameters=baseline_hyperparameters,
        feature_schema=FEATURE_SCHEMA_V07A,
        phase_schema=BEHAVIOR_STATE_PHASES,
        feature_schema_version=FEATURE_SCHEMA_V07A_VERSION,
    )
    provisional_gate = {
        "comparator_provenance_row_balance_gate_sha256": "pending",
    }
    candidate_policy = build_v14_policy_artifact_payload(
        parent_policy_artifact=parent_policies["candidate"],
        base_policy_artifact=candidate_base,
        dataset_view_role="candidate_curated",
        training_view=candidate_view,
        row_balance_gate_sha256=provisional_gate["comparator_provenance_row_balance_gate_sha256"],
        source_v13_manifest_sha256=source_v13_manifest_sha,
    )
    baseline_policy = build_v14_policy_artifact_payload(
        parent_policy_artifact=parent_policies["baseline"],
        base_policy_artifact=baseline_base,
        dataset_view_role="baseline_uncurated_row_balanced",
        training_view=baseline_view,
        row_balance_gate_sha256=provisional_gate["comparator_provenance_row_balance_gate_sha256"],
        source_v13_manifest_sha256=source_v13_manifest_sha,
    )
    gate = derive_v14_comparator_provenance_row_balance_gate(
        candidate_policy=candidate_policy,
        baseline_policy=baseline_policy,
        row_balance_report=row_balance_report,
        provenance_report=provenance_report,
        source_v13_manifest_sha256=source_v13_manifest_sha,
    )
    for policy in (candidate_policy, baseline_policy):
        hyperparameters = dict(policy.get("hyperparameters") or {})
        hyperparameters["comparator_provenance_row_balance_gate_sha256"] = gate[
            "comparator_provenance_row_balance_gate_sha256"
        ]
        policy["hyperparameters"] = hyperparameters
        policy["comparator_provenance_row_balance_gate_sha256"] = gate[
            "comparator_provenance_row_balance_gate_sha256"
        ]
        policy["policy_artifact_sha256"] = _sha256_payload_excluding(policy, "policy_artifact_sha256")
    write_json(child_dir / "candidate_policy_artifact_v0_14.json", candidate_policy)
    write_json(child_dir / "baseline_policy_artifact_v0_14.json", baseline_policy)
    write_json(child_dir / "v0_14_source_provenance_report.json", provenance_report)
    write_json(child_dir / "v0_14_row_balance_report.json", row_balance_report)
    write_json(child_dir / "v0_14_comparator_provenance_row_balance_gate.json", gate)
    manifest = {
        "schema_version": V14_MANIFEST_SCHEMA_VERSION,
        "policy_slice": V14_POLICY_SLICE_ID,
        "slice_id": V14_SLICE_ID,
        "parent_policy_slice": V13_POLICY_SLICE_ID,
        "source_policy_slice": V13_POLICY_SLICE_ID,
        "source_v13_manifest_sha256": source_v13_manifest_sha,
        "comparator_provenance_row_balance_gate": gate,
        "source_provenance_report": provenance_report,
        "row_balance_report": row_balance_report,
        "fresh_calibration_seed_range": [min(V14_FRESH_CALIBRATION_RANGE), max(V14_FRESH_CALIBRATION_RANGE)],
        "fresh_heldout_seed_range": [min(V14_FRESH_HELDOUT_RANGE), max(V14_FRESH_HELDOUT_RANGE)],
        "burned_heldout_seed_ranges": [
            *v13_manifest["burned_heldout_seed_ranges"],
            [38000, 38049],
        ],
        "burned_calibration_seed_ranges": [
            *v13_manifest["burned_calibration_seed_ranges"],
            [37000, 37029],
        ],
        "training_views": {"candidate": candidate_view, "baseline": baseline_view},
        "policy_artifacts": {
            "candidate": {**candidate_policy, "path": str(child_dir / "candidate_policy_artifact_v0_14.json")},
            "baseline": {**baseline_policy, "path": str(child_dir / "baseline_policy_artifact_v0_14.json")},
        },
        "failed_closed": gate.get("passed") is not True,
        "failure_reason": gate.get("failure_reason", ""),
        "calibration_opened": False,
        "heldout_opened": False,
        "fresh_calibration_39000_39029_accessed": False,
        "fresh_heldout_40000_40049_accessed": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
        "non_claims": {
            "policy_uplift_proven": False,
            "real_robot_success": False,
            "physical_robot_readiness": False,
            "visual_policy_performance": False,
            "hmd_openxr_readiness": False,
        },
    }
    manifest["v0_14_comparator_provenance_row_balance_manifest_sha256"] = (
        _sha256_payload_excluding(
            manifest,
            "v0_14_comparator_provenance_row_balance_manifest_sha256",
        )
    )
    write_json(child_dir / "v0_14_comparator_provenance_row_balance_manifest.json", manifest)
    return manifest


def _v14_burned_seed_range_accessed(seed: int) -> bool:
    seed_int = int(seed)
    return (
        _v13_burned_seed_range_accessed(seed_int)
        or seed_int in V13_FRESH_CALIBRATION_RANGE
        or seed_int in V13_FRESH_HELDOUT_RANGE
    )


def _v14_spent_heldout_range_record() -> dict[str, Any]:
    return {
        "range": V14_SPENT_HELDOUT_RANGE_LABEL,
        "status": V14_SPENT_HELDOUT_STATUS,
        "future_tuning_allowed": False,
        "future_closure_reuse_allowed": False,
        "reason": "Used by the v0_14 actual Isaac held-out closure gate.",
    }


def _v14_closure_gate_marks_heldout_spent(gate: dict[str, Any]) -> bool:
    if gate.get("policy_slice") != V14_POLICY_SLICE_ID:
        return False
    if gate.get("schema_version") != V14_HELDOUT_CLOSURE_SCHEMA_VERSION:
        return False
    for item in gate.get("spent_heldout_ranges") or []:
        if not isinstance(item, dict):
            continue
        if item.get("range") != V14_SPENT_HELDOUT_RANGE_LABEL:
            continue
        if item.get("status") == V14_SPENT_HELDOUT_STATUS:
            return True
    return (
        gate.get("fresh_heldout_40000_40049_accessed") is True
        and gate.get("same_heldout_reuse_allowed_for_closure") is False
    )


def assert_v14_spent_heldout_not_reopened(output_dir: Path) -> None:
    child_gate_path = output_dir / V14_CHILD_OUTPUT_DIRNAME / "heldout_closure_gate_v0_14.json"
    root_gate_path = output_dir / "heldout_closure_gate.json"
    for gate_path in (child_gate_path, root_gate_path):
        if not gate_path.exists():
            continue
        gate = read_json(gate_path)
        if _v14_closure_gate_marks_heldout_spent(gate):
            raise ValueError(
                "v0_14_heldout_40000_40049_already_spent_audit_only:"
                f"{gate_path}"
            )


def build_v14_fresh_manifest(
    *,
    output_dir: Path,
    comparator_manifest: dict[str, Any],
) -> dict[str, Any]:
    gate = comparator_manifest.get("comparator_provenance_row_balance_gate", {})
    if gate.get("passed") is not True:
        raise ValueError("v0_14_comparator_provenance_row_balance_gate_not_passed")
    calibration_rows = [
        _scenario_row(split="calibration", seed=seed)
        for seed in V14_FRESH_CALIBRATION_RANGE
    ]
    heldout_rows = [_scenario_row(split="held_out", seed=seed) for seed in V14_FRESH_HELDOUT_RANGE]
    if any(_v14_burned_seed_range_accessed(int(row["seed"])) for row in calibration_rows):
        raise ValueError("v0_14_fresh_manifest_reuses_burned_calibration_seed_range")
    if any(_v14_burned_seed_range_accessed(int(row["seed"])) for row in heldout_rows):
        raise ValueError("v0_14_fresh_manifest_reuses_burned_heldout_seed_range")
    manifest = {
        "schema_version": V14_MANIFEST_SCHEMA_VERSION,
        "policy_slice": V14_POLICY_SLICE_ID,
        "slice_id": V14_SLICE_ID,
        "parent_policy_slice": V13_POLICY_SLICE_ID,
        "source_policy_slice": V13_POLICY_SLICE_ID,
        "scenario_profile": "v0_14",
        "task_type": "connector_insertion",
        "success_metric": SUCCESS_METRIC,
        "success_authority": V06_ENV_NATIVE_SUCCESS_AUTHORITY,
        "source_v14_comparator_provenance_row_balance_manifest_sha256": comparator_manifest[
            "v0_14_comparator_provenance_row_balance_manifest_sha256"
        ],
        "source_v14_comparator_provenance_row_balance_gate_sha256": gate[
            "comparator_provenance_row_balance_gate_sha256"
        ],
        "scenarios": calibration_rows + heldout_rows,
        "fresh_split_manifest": {
            "calibration": {
                "seed_range": [min(V14_FRESH_CALIBRATION_RANGE), max(V14_FRESH_CALIBRATION_RANGE)],
                "scenario_ids": [row["scenario_id"] for row in calibration_rows],
                "count": len(calibration_rows),
            },
            "held_out": {
                "seed_range": [min(V14_FRESH_HELDOUT_RANGE), max(V14_FRESH_HELDOUT_RANGE)],
                "scenario_ids": [row["scenario_id"] for row in heldout_rows],
                "count": len(heldout_rows),
            },
        },
        "burned_heldout_seed_ranges": comparator_manifest["burned_heldout_seed_ranges"],
        "burned_calibration_seed_ranges": comparator_manifest["burned_calibration_seed_ranges"],
        "fresh_calibration_39000_39029_accessed": False,
        "fresh_heldout_40000_40049_accessed": False,
        "calibration_opened": False,
        "heldout_opened": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    manifest["manifest_sha256"] = _sha256_payload_excluding(manifest, "manifest_sha256")
    return manifest


def _v14_runtime_manifest_for_split(*, fresh_manifest: dict[str, Any], split: str) -> dict[str, Any]:
    if split not in {"calibration", "held_out"}:
        raise ValueError("v0_14_runtime_manifest_unknown_split")
    rows = [
        {**row, "source_split": split, "semantic_eval_split": split, "split": "held_out"}
        for row in fresh_manifest.get("scenarios", [])
        if isinstance(row, dict) and row.get("split") == split
    ]
    if not rows:
        raise ValueError(f"v0_14_runtime_manifest_missing_{split}_rows")
    seeds = [int(row["seed"]) for row in rows]
    if split == "calibration":
        if seeds != list(V14_FRESH_CALIBRATION_RANGE):
            raise ValueError("v0_14_calibration_seed_range_mismatch")
        if any(_v14_burned_seed_range_accessed(seed) for seed in seeds):
            raise ValueError("v0_14_runtime_manifest_reuses_burned_calibration_seed_range")
    if split == "held_out":
        if seeds != list(V14_FRESH_HELDOUT_RANGE):
            raise ValueError("v0_14_heldout_seed_range_mismatch")
        if any(_v14_burned_seed_range_accessed(seed) for seed in seeds):
            raise ValueError("v0_14_runtime_manifest_reuses_burned_heldout_seed_range")
    manifest = {
        "schema_version": fresh_manifest["schema_version"],
        "policy_slice": V14_POLICY_SLICE_ID,
        "slice_id": V14_SLICE_ID,
        "parent_policy_slice": V13_POLICY_SLICE_ID,
        "scenario_profile": "v0_14",
        "runtime_split": split,
        "task_type": fresh_manifest["task_type"],
        "success_metric": fresh_manifest["success_metric"],
        "success_authority": fresh_manifest["success_authority"],
        "source_fresh_manifest_sha256": fresh_manifest["manifest_sha256"],
        "scenarios": rows,
        "burned_heldout_seed_ranges": fresh_manifest["burned_heldout_seed_ranges"],
        "burned_calibration_seed_ranges": fresh_manifest["burned_calibration_seed_ranges"],
        "fresh_calibration_39000_39029_accessed": True,
        "fresh_heldout_40000_40049_accessed": split == "held_out",
        "calibration_opened": True,
        "heldout_opened": split == "held_out",
        "proof_authority": split == "held_out",
        "mvp2_closed": False,
        "policy_uplift_proven": False,
    }
    manifest["manifest_sha256"] = _sha256_payload_excluding(manifest, "manifest_sha256")
    return manifest


def _load_v14_policy_artifacts(output_dir: Path) -> dict[str, dict[str, Any]]:
    child_dir = output_dir / V14_CHILD_OUTPUT_DIRNAME
    candidate_path = child_dir / "candidate_policy_artifact_v0_14.json"
    baseline_path = child_dir / "baseline_policy_artifact_v0_14.json"
    if not candidate_path.exists() or not baseline_path.exists():
        raise ValueError("missing_v0_14_policy_artifacts")
    baseline = read_json(baseline_path)
    candidate = read_json(candidate_path)
    reasons: list[str] = []
    for role, policy in (("baseline", baseline), ("candidate", candidate)):
        if policy.get("policy_slice") != V14_POLICY_SLICE_ID:
            reasons.append(f"{role}_policy_slice_mismatch")
        if policy.get("parent_policy_slice") != V13_POLICY_SLICE_ID:
            reasons.append(f"{role}_parent_policy_slice_mismatch")
        if policy.get("fresh_calibration_39000_39029_accessed") is not False:
            reasons.append(f"{role}_fresh_calibration_accessed_before_runtime")
        if policy.get("fresh_heldout_40000_40049_accessed") is not False:
            reasons.append(f"{role}_fresh_heldout_accessed_before_closure")
        expected_hash = _sha256_payload_excluding(policy, "policy_artifact_sha256")
        if policy.get("policy_artifact_sha256") != expected_hash:
            reasons.append(f"{role}_policy_hash_mismatch")
        config = policy.get("policy_influence_authority_ceiling_config")
        if not isinstance(config, dict):
            reasons.append(f"{role}_policy_influence_config_missing")
        else:
            expected_config_hash = _sha256_payload_excluding(
                config,
                "policy_influence_authority_ceiling_config_sha256",
            )
            if (
                config.get("policy_influence_authority_ceiling_config_sha256")
                != expected_config_hash
                or policy.get("policy_influence_authority_ceiling_config_sha256")
                != expected_config_hash
            ):
                reasons.append(f"{role}_policy_influence_config_hash_mismatch")
    equality_keys = (
        "selected_action_adapter_id",
        "trainer",
        "trainer_family",
        "policy_class",
        "feature_schema",
        "feature_schema_version",
        "phase_schema",
        "action_schema",
        "base_servo_config_sha256",
        "authority_filter_config_sha256",
        "final_post_adapter_authority_config_sha256",
        "shared_hysteresis_authority_config_sha256",
        "selected_action_adapter_config_sha256",
        "policy_influence_authority_ceiling_config_sha256",
    )
    for key in equality_keys:
        if baseline.get(key) != candidate.get(key):
            reasons.append(f"peer_{key}_mismatch")
    if reasons:
        raise ValueError("v0_14_policy_peer_fairness_failed: " + ",".join(reasons))
    return {
        "baseline": {**baseline, "path": str(baseline_path)},
        "candidate": {**candidate, "path": str(candidate_path)},
    }


def _write_v14_calibration_external_rollouts(
    *,
    output_dir: Path,
    baseline_rollouts: list[dict[str, Any]],
    candidate_rollouts: list[dict[str, Any]],
) -> dict[str, str]:
    rollout_dir = output_dir / "calibration_external_rollouts"
    rollout_dir.mkdir(parents=True, exist_ok=True)
    baseline_path = rollout_dir / "baseline_calibration_rollouts_v0_14.json"
    candidate_path = rollout_dir / "candidate_calibration_rollouts_v0_14.json"
    write_json(baseline_path, baseline_rollouts)
    write_json(candidate_path, candidate_rollouts)
    return {"baseline": str(baseline_path), "candidate": str(candidate_path)}


def _v14_policy_influence_runtime_report(
    *,
    baseline_rollouts: list[dict[str, Any]],
    candidate_rollouts: list[dict[str, Any]],
    output_dir: Path,
) -> dict[str, Any]:
    report = _v13_policy_influence_runtime_report(
        baseline_rollouts=baseline_rollouts,
        candidate_rollouts=candidate_rollouts,
        output_dir=output_dir,
    )
    report.pop("policy_influence_runtime_report_sha256", None)
    report.update(
        {
            "schema_version": "rdf_mvp2e_v14_policy_influence_runtime_report_v0.1.0",
            "policy_slice": V14_POLICY_SLICE_ID,
            "source_policy_slice": V13_POLICY_SLICE_ID,
        }
    )
    report["policy_influence_runtime_report_sha256"] = _sha256_payload_excluding(
        report,
        "policy_influence_runtime_report_sha256",
    )
    return report


def derive_v14_calibration_presignal_gate(
    *,
    baseline_rollouts: list[dict[str, Any]],
    candidate_rollouts: list[dict[str, Any]],
    runtime_gate: dict[str, Any],
    runtime_metadata: dict[str, Any],
    trace_paths: dict[str, list[str]],
    output_dir: Path,
) -> dict[str, Any]:
    gate = derive_v07h_calibration_presignal_gate(
        baseline_rollouts=baseline_rollouts,
        candidate_rollouts=candidate_rollouts,
        runtime_gate=runtime_gate,
        runtime_metadata=runtime_metadata,
        trace_paths=trace_paths,
        output_dir=Path("."),
    )
    baseline_rate = float(gate["baseline_calibration_success_rate"])
    candidate_rate = float(gate["candidate_calibration_success_rate"])
    success_gap = round(candidate_rate - baseline_rate, 12)
    influence = _v14_policy_influence_runtime_report(
        baseline_rollouts=baseline_rollouts,
        candidate_rollouts=candidate_rollouts,
        output_dir=output_dir,
    )
    failure_reason = ""
    if runtime_gate.get("passed") is not True or runtime_metadata.get("runtime_backend") != "isaac_runtime":
        failure_reason = "calibration_runtime_gate_not_passed"
    elif (
        int(gate["baseline_calibration_rollout_count"]) < V07H_CALIBRATION_ROLLOUTS_PER_POLICY
        or int(gate["candidate_calibration_rollout_count"]) < V07H_CALIBRATION_ROLLOUTS_PER_POLICY
    ):
        failure_reason = "calibration_rollout_count_below_minimum"
    elif baseline_rate > V14_BASELINE_FLOOR_SUCCESS_MAXIMUM:
        failure_reason = "baseline_calibration_success_floor_above_v0_14_maximum"
    elif candidate_rate < V14_CALIBRATION_SUCCESS_MINIMUM:
        failure_reason = "candidate_calibration_success_below_v0_14_minimum"
    elif candidate_rate <= baseline_rate:
        failure_reason = "candidate_calibration_not_above_baseline"
    elif success_gap < V14_CALIBRATION_UPLIFT_MINIMUM:
        failure_reason = "candidate_baseline_success_gap_below_v0_14_minimum"
    elif influence["policy_influence_preservation_passed"] is not True:
        failure_reason = "policy_influence_preservation_failed"
    passed = failure_reason == ""
    gate.update(
        {
            "schema_version": V14_CALIBRATION_PRESIGNAL_SCHEMA_VERSION,
            "policy_slice": V14_POLICY_SLICE_ID,
            "slice_id": V14_SLICE_ID,
            "parent_policy_slice": V13_POLICY_SLICE_ID,
            "passed": bool(passed),
            "failure_reason": failure_reason,
            "heldout_allowed": bool(passed),
            "candidate_baseline_success_gap": success_gap,
            "candidate_success_gap_minimum": V14_CALIBRATION_UPLIFT_MINIMUM,
            "candidate_calibration_success_minimum": V14_CALIBRATION_SUCCESS_MINIMUM,
            "baseline_calibration_success_floor_maximum": V14_BASELINE_FLOOR_SUCCESS_MAXIMUM,
            "policy_influence_runtime_report": influence,
            "policy_influence_preservation_passed": bool(
                influence["policy_influence_preservation_passed"]
            ),
            "fresh_calibration_39000_39029_accessed": True,
            "fresh_heldout_40000_40049_accessed": False,
            "source": "v0_14_comparator_provenance_row_balance_calibration_runtime",
            "mvp2_closed": False,
            "policy_uplift_proven": False,
        }
    )
    gate["calibration_presignal_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "calibration_presignal_gate_sha256",
    )
    return gate


def run_v14_comparator_provenance_row_balance_runtime(
    *,
    output_dir: Path,
    device: str = DEFAULT_ISAAC_DEVICE,
    headless: bool = True,
    isaac_task: str = DEFAULT_ISAAC_TASK,
    max_steps: int = int(SUCCESS_METRIC["max_steps"]),
    action_scale: float = 1.0,
    min_rollouts_per_policy: int = MIN_PROOF_ROLLOUTS_PER_POLICY,
    bootstrap_iterations: int = 2000,
    bootstrap_seed: int = 23,
    backend: Any | None = None,
) -> dict[str, Any]:
    assert_v14_spent_heldout_not_reopened(output_dir)
    child_dir = output_dir / V14_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    comparator_manifest = build_v14_comparator_provenance_row_balance_slice(output_dir=output_dir)
    if comparator_manifest["comparator_provenance_row_balance_gate"].get("passed") is not True:
        return comparator_manifest["comparator_provenance_row_balance_gate"]
    fresh_manifest = build_v14_fresh_manifest(
        output_dir=output_dir,
        comparator_manifest=comparator_manifest,
    )
    write_json(child_dir / "v0_14_fresh_manifest.json", fresh_manifest)
    policy_artifacts = _load_v14_policy_artifacts(output_dir)
    baseline_policy = policy_artifacts["baseline"]
    candidate_policy = policy_artifacts["candidate"]
    selected_adapter_id = str(candidate_policy["selected_action_adapter_id"])
    policy_class = str(candidate_policy["policy_class"])
    trainer = str(candidate_policy["trainer"])
    use_single_app_actual_backend = (
        backend is None
        and getattr(IsaacConnectorInsertionEvaluatorBackend, "__name__", "")
        == "IsaacConnectorInsertionEvaluatorBackend"
    )
    evaluator_backend = backend or IsaacConnectorInsertionEvaluatorBackend(
        task=isaac_task,
        device=device,
        headless=headless,
        action_scale=action_scale,
        max_steps=max_steps,
    )
    actual_env = None
    actual_simulation_app = None
    actual_torch = None
    if use_single_app_actual_backend:
        from isaaclab.app import AppLauncher

        app_launcher = AppLauncher(
            {
                "headless": headless,
                "device": device,
                "enable_cameras": False,
            }
        )
        actual_simulation_app = app_launcher.app

        import gymnasium as gym
        import torch as torch_module

        import isaaclab_tasks  # noqa: F401
        from isaaclab_tasks.utils import parse_env_cfg

        env_cfg = parse_env_cfg(isaac_task, device=device, num_envs=1)
        actual_env = gym.make(isaac_task, cfg=env_cfg).unwrapped
        actual_torch = torch_module

    def run_runtime_manifest(
        *,
        manifest: dict[str, Any],
        runtime_output_dir: Path,
        rollouts_per_policy: int,
    ) -> BackendResult:
        if actual_env is not None:
            return _run_v08a_manifest_with_existing_isaac(
                evaluator_backend=evaluator_backend,
                env=actual_env,
                simulation_app=actual_simulation_app,
                torch_module=actual_torch,
                manifest=manifest,
                output_dir=runtime_output_dir,
                min_rollouts_per_policy=rollouts_per_policy,
                policy_artifacts=policy_artifacts,
            )
        return evaluator_backend.run(
            manifest=manifest,
            output_dir=runtime_output_dir,
            min_rollouts_per_policy=rollouts_per_policy,
            deterministic_profile="candidate_positive",
            policy_artifacts=policy_artifacts,
        )

    calibration_manifest = _v14_runtime_manifest_for_split(
        fresh_manifest=fresh_manifest,
        split="calibration",
    )
    write_json(child_dir / "calibration_runtime_manifest_v0_14.json", calibration_manifest)
    calibration_result = run_runtime_manifest(
        manifest=calibration_manifest,
        runtime_output_dir=child_dir / "isaac_runtime_fresh_calibration_v0_14",
        rollouts_per_policy=V07H_CALIBRATION_ROLLOUTS_PER_POLICY,
    )
    calibration_rollout_paths = _write_v14_calibration_external_rollouts(
        output_dir=child_dir,
        baseline_rollouts=list(calibration_result.baseline_rollouts),
        candidate_rollouts=list(calibration_result.candidate_rollouts),
    )
    calibration_trace_paths = {
        "baseline": list(calibration_result.baseline_trace_paths),
        "candidate": list(calibration_result.candidate_trace_paths),
    }
    calibration_gate = derive_v14_calibration_presignal_gate(
        baseline_rollouts=list(calibration_result.baseline_rollouts),
        candidate_rollouts=list(calibration_result.candidate_rollouts),
        runtime_gate=dict(calibration_result.runtime_gate),
        runtime_metadata=dict(calibration_result.runtime_metadata),
        trace_paths=calibration_trace_paths,
        output_dir=output_dir,
    )
    calibration_gate["calibration_runtime_manifest_sha256"] = calibration_manifest["manifest_sha256"]
    calibration_gate["baseline_calibration_rollout_path"] = calibration_rollout_paths["baseline"]
    calibration_gate["candidate_calibration_rollout_path"] = calibration_rollout_paths["candidate"]
    calibration_gate["calibration_presignal_gate_sha256"] = _sha256_payload_excluding(
        calibration_gate,
        "calibration_presignal_gate_sha256",
    )
    write_json(child_dir / "calibration_presignal_gate_v0_14.json", calibration_gate)
    write_json(output_dir / "calibration_presignal_gate.json", calibration_gate)
    if calibration_gate.get("passed") is not True:
        calibration_gate["mvp2_closed"] = False
        calibration_gate["policy_uplift_proven"] = False
        if actual_env is not None:
            actual_env.close()
        return calibration_gate

    selection = _v08a_calibration_selection_report(output_dir)
    training_scenario_ids = _v08a_training_scenario_ids(output_dir)
    heldout_manifest = _v14_runtime_manifest_for_split(
        fresh_manifest=fresh_manifest,
        split="held_out",
    )
    write_json(child_dir / "heldout_runtime_manifest_v0_14.json", heldout_manifest)
    heldout_leakage_guard = validate_no_heldout_leakage(
        manifest=heldout_manifest,
        training_scenario_ids=training_scenario_ids,
        curation_tuning_scenario_ids=[],
        threshold_tuning_scenario_ids=[],
        hyperparameter_scenario_ids=[],
        calibration_selector_scenario_ids=[
            str(item) for item in selection.get("calibration_scenario_ids", [])
        ],
    )
    if heldout_leakage_guard["passed"] is not True:
        raise ValueError("v0_14_fresh_heldout_leakage_guard_failed")
    baseline_view = _existing_train_view(
        child_dir / "baseline_uncurated_row_balanced_train_v0_14.hdf5",
        view_id="baseline_uncurated_row_balanced_v0_14",
    )
    candidate_view = _existing_train_view(
        child_dir / "candidate_curated_train_v0_14.hdf5",
        view_id="candidate_curated_v0_14_comparator_provenance_row_balance",
    )
    bridge_dir = _write_learning_harness_bridge(
        output_dir=child_dir,
        manifest=heldout_manifest,
        baseline_view=baseline_view,
        candidate_view=candidate_view,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    heldout_rollouts_per_policy = max(
        int(min_rollouts_per_policy),
        STRONGER_PUBLIC_ROLLOUTS_PER_POLICY,
        len(V14_FRESH_HELDOUT_RANGE),
    )
    heldout_result = run_runtime_manifest(
        manifest=heldout_manifest,
        runtime_output_dir=child_dir / "isaac_runtime_fresh_heldout_v0_14",
        rollouts_per_policy=heldout_rollouts_per_policy,
    )
    runtime_gate = dict(heldout_result.runtime_gate)
    actual_rollouts_per_policy = min(
        len(heldout_result.baseline_rollouts),
        len(heldout_result.candidate_rollouts),
    )
    runtime_gate["actual_baseline_rollouts"] = len(heldout_result.baseline_rollouts)
    runtime_gate["actual_candidate_rollouts"] = len(heldout_result.candidate_rollouts)
    runtime_gate["actual_rollouts_per_policy"] = actual_rollouts_per_policy
    combined_rollouts = list(heldout_result.baseline_rollouts) + list(heldout_result.candidate_rollouts)
    if any(_v14_burned_seed_range_accessed(int(rollout.get("seed", -1))) for rollout in combined_rollouts):
        raise ValueError("v0_14_burned_seed_accessed")
    heldout_suite = _heldout_suite(heldout_manifest)
    baseline_rollouts_path = _write_external_rollout_json(
        output_dir=child_dir,
        role="baseline",
        policy_artifact=baseline_policy,
        train_view=baseline_view,
        heldout_suite=heldout_suite,
        backend_result=heldout_result,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    candidate_rollouts_path = _write_external_rollout_json(
        output_dir=child_dir,
        role="candidate",
        policy_artifact=candidate_policy,
        train_view=candidate_view,
        heldout_suite=heldout_suite,
        backend_result=heldout_result,
        selected_adapter_id=selected_adapter_id,
        policy_class=policy_class,
        trainer=trainer,
    )
    learning_report = _run_learning_validator(
        output_dir=child_dir,
        bridge_dir=bridge_dir,
        baseline_rollouts_path=baseline_rollouts_path,
        candidate_rollouts_path=candidate_rollouts_path,
        min_rollouts_per_policy=MIN_PROOF_ROLLOUTS_PER_POLICY,
        bootstrap_iterations=bootstrap_iterations,
        bootstrap_seed=bootstrap_seed,
        policy_class=policy_class,
        trainer=trainer,
    )
    train_generation_runtime_gate, train_gate_sha256 = load_v07a2_parent_train_generation_gate(output_dir)
    closure = derive_mvp2c_closure(
        learning_report=learning_report,
        runtime_gate=runtime_gate,
        train_generation_runtime_gate=train_generation_runtime_gate,
        calibration_selection_report=selection,
        heldout_leakage_guard=heldout_leakage_guard,
        actual_rollouts_per_policy=actual_rollouts_per_policy,
    )
    confidence_interval_report = _bootstrap_uplift_ci(
        baseline_rollouts=list(heldout_result.baseline_rollouts),
        candidate_rollouts=list(heldout_result.candidate_rollouts),
        iterations=bootstrap_iterations,
        seed=bootstrap_seed,
    )
    gate = {
        "schema_version": V14_HELDOUT_CLOSURE_SCHEMA_VERSION,
        "policy_slice": V14_POLICY_SLICE_ID,
        "slice_id": V14_SLICE_ID,
        "parent_policy_slice": V13_POLICY_SLICE_ID,
        "source_fresh_manifest_sha256": fresh_manifest["manifest_sha256"],
        "comparator_provenance_row_balance_gate_sha256": comparator_manifest[
            "comparator_provenance_row_balance_gate"
        ]["comparator_provenance_row_balance_gate_sha256"],
        "parent_train_generation_runtime_gate_sha256": train_gate_sha256,
        "fresh_calibration_presignal_gate_sha256": calibration_gate[
            "calibration_presignal_gate_sha256"
        ],
        "runtime_backend": heldout_result.runtime_backend,
        "proof_runtime": heldout_result.proof_runtime,
        "runtime_gate": runtime_gate,
        "actual_rollouts_per_policy": actual_rollouts_per_policy,
        "baseline_success_rate": learning_report.get("baseline_success_rate"),
        "candidate_success_rate": learning_report.get("candidate_success_rate"),
        "curated_vs_uncurated_uplift": learning_report.get("curated_vs_uncurated_uplift"),
        "learning_report_path": str(
            child_dir / "mvp2_learning_proven_policy_eval" / "mvp2_learning_proven_report.json"
        ),
        "baseline_external_rollouts": str(baseline_rollouts_path),
        "candidate_external_rollouts": str(candidate_rollouts_path),
        "confidence_interval_report": confidence_interval_report,
        "stronger_public_evidence_target_passed": _derive_public_evidence_target(
            actual_rollouts_per_policy=actual_rollouts_per_policy,
            confidence_interval_report=confidence_interval_report,
        ),
        "calibration_opened": True,
        "heldout_opened": True,
        "fresh_calibration_39000_39029_accessed": True,
        "fresh_heldout_40000_40049_accessed": True,
        "same_heldout_reuse_allowed_for_closure": False,
        "spent_heldout_ranges": [_v14_spent_heldout_range_record()],
        "heldout_leakage_guard": heldout_leakage_guard,
        "calibration_selection_report_sha256": _sha256_file(output_dir / "calibration_selection_report.json"),
        "selected_action_adapter_id": selected_adapter_id,
        "same_adapter_used_for_baseline_and_candidate": True,
        "same_policy_class": baseline_policy.get("policy_class") == candidate_policy.get("policy_class"),
        "same_trainer": baseline_policy.get("trainer") == candidate_policy.get("trainer"),
        "same_feature_schema": baseline_policy.get("feature_schema") == candidate_policy.get("feature_schema"),
        "mvp2_closed": closure["mvp2_closed"],
        "mvp2c_close_minimum_passed": closure["mvp2c_close_minimum_passed"],
        "policy_uplift_proven": closure["learning_proven"],
        "proof_eligible": closure["proof_eligible"],
        "blockers": closure["blockers"] + list(learning_report.get("blockers") or []),
        "non_claims": {
            "deployable_real_robot_policy": False,
            "visual_policy_performance": False,
            "real_robot_success": False,
            "physical_robot_readiness": False,
            "universal_robot_support": False,
            "hmd_openxr_readiness": False,
        },
    }
    gate["heldout_closure_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "heldout_closure_gate_sha256",
    )
    write_json(child_dir / "heldout_closure_gate_v0_14.json", gate)
    write_json(output_dir / "heldout_closure_gate.json", gate)
    if actual_env is not None:
        actual_env.close()
    return gate


def load_v07a2_parent_train_generation_gate(parent_dir: Path) -> tuple[dict[str, Any], str]:
    gate_path = parent_dir / "train_generation_runtime_gate.json"
    if not gate_path.exists():
        raise ValueError("missing_train_generation_runtime_gate")
    gate = read_json(gate_path)
    if gate.get("passed") is not True:
        raise ValueError("train_generation_runtime_gate_not_passed")
    if gate.get("runtime_backend") != "isaac_runtime":
        raise ValueError("train_generation_runtime_gate_not_isaac_runtime")
    if gate.get("actual_train_generation_evidence") is not True:
        raise ValueError("train_generation_runtime_gate_not_actual_evidence")
    if int(gate.get("generated_success_count", 0)) < V06_TRAIN_GATE_SUCCESS_MINIMUM:
        raise ValueError("train_generation_success_count_too_low")
    return gate, _sha256_file(gate_path)


def _seed_from_trace_payload_or_path(payload: dict[str, Any], path: Path) -> int:
    scenario = payload.get("scenario") if isinstance(payload.get("scenario"), dict) else {}
    seed_value = scenario.get("seed")
    if seed_value is not None:
        try:
            return int(seed_value)
        except (TypeError, ValueError) as exc:
            raise ValueError("trace_scenario_seed_invalid") from exc
    scenario_id = str(scenario.get("scenario_id") or path.name)
    match = re.search(r"(?:train_success|train_failure|held_out|calibration)_(\d+)", scenario_id)
    if match is None:
        match = re.search(r"_(\d{4,6})(?:_|\\.)", path.name)
    if match is None:
        raise ValueError("trace_scenario_seed_missing")
    return int(match.group(1))


def _scenario_id_from_trace_payload_or_path(payload: dict[str, Any], path: Path) -> str:
    scenario = payload.get("scenario") if isinstance(payload.get("scenario"), dict) else {}
    scenario_id = scenario.get("scenario_id")
    if scenario_id:
        return str(scenario_id)
    try:
        return _scenario_id_from_trace_filename(path.name)
    except ValueError:
        seed = _seed_from_trace_payload_or_path(payload, path)
        return f"train_success_{seed}"


def _protected_heldout_seed_range_accessed(seed: int) -> bool:
    start, end = V07A2_PROTECTED_HELDOUT_SEED_RANGE
    return start <= int(seed) <= end


def _path_has_legacy_heldout_label(path: Path) -> bool:
    return any("heldout" in part.lower() or "held_out" in part.lower() for part in path.parts)


def trace_row_to_v07a2_train_row(
    row: dict[str, Any],
    *,
    source_trace_path: Path,
    source_trace_sha256: str,
    trajectory_id: str,
    source_trace_role: str,
    accepted: bool,
) -> dict[str, Any]:
    if "normalized_action" not in row:
        raise ValueError("normalized_action_missing")
    raw_action = row["normalized_action"]
    if not isinstance(raw_action, list):
        raise ValueError("normalized_action_invalid")
    if len(raw_action) < 6:
        raise ValueError("normalized_action_schema_too_short")
    step = int(row["step"])
    env_native_success_mask = _env_native_success_mask_from_row(row)
    insertion_depth_m = _required_v07a1_metric(row, "insertion_depth_m")
    lateral_error_m = _required_v07a1_metric(row, "lateral_error_m")
    relative_x_m = _required_v07a1_metric(row, "relative_x_m")
    relative_y_m = _required_v07a1_metric(row, "relative_y_m")
    orientation_error_deg = _required_v07a1_metric(row, "orientation_error_deg")
    behavior_state_phase = derive_v07a2_behavior_state_phase_from_metrics(
        {
            "env_native_success_mask": env_native_success_mask,
            "lateral_error_m": lateral_error_m,
            "insertion_depth_m": insertion_depth_m,
        }
    )
    original_phase = str(row.get("phase") or "")
    return {
        "trajectory_id": trajectory_id,
        "step": step,
        "timestamp_s": round(float(row.get("timestamp_s", step * 0.05)), 6),
        "phase": original_phase,
        "original_metric_phase": original_phase,
        "original_depth_phase": original_phase,
        "behavior_state_phase": behavior_state_phase,
        "phase_label_source": V07A2_BEHAVIOR_PHASE_LABEL_SOURCE,
        "behavior_phase_rule_version": V07A2_BEHAVIOR_PHASE_RULE_VERSION,
        "behavior_phase_lateral_gate_m": V07A_BEHAVIOR_PHASE_LATERAL_GATE_M,
        "feature_schema_version": FEATURE_SCHEMA_V07A_VERSION,
        "env_native_success": env_native_success_mask,
        "env_native_success_mask": env_native_success_mask,
        "insertion_depth_m": insertion_depth_m,
        "relative_x_m": relative_x_m,
        "relative_y_m": relative_y_m,
        "lateral_error_m": lateral_error_m,
        "orientation_error_deg": orientation_error_deg,
        "normalized_action": _action_with_schema_length(raw_action),
        "accepted": bool(accepted),
        "source_trace_role": source_trace_role,
        "source_trace_path": str(source_trace_path),
        "runtime_trace_path": str(source_trace_path),
        "source_trace_sha256": source_trace_sha256,
        "runtime_trace_sha256": source_trace_sha256,
        "policy_slice": V07A2_POLICY_SLICE_ID,
        "heldout_21000_21049_accessed": False,
    }


def _post_reset_cutoff_step(payload: dict[str, Any]) -> int | None:
    for key in ("env_reset_boundary_steps", "reset_boundary_steps"):
        value = payload.get(key)
        if isinstance(value, list) and value:
            return int(min(value))
    return None


def _prepare_v07a2_trace_native_rows(
    *,
    parent_gate: dict[str, Any],
    trace_paths: list[str],
    source_trace_role: str,
    accepted_from_summary: bool,
) -> tuple[list[dict[str, Any]], dict[str, Any]]:
    allowed = {str(path) for path in parent_gate.get("generated_trace_paths") or []}
    rows: list[dict[str, Any]] = []
    trace_hashes: dict[str, str] = {}
    source_paths: list[str] = []
    seeds: list[int] = []
    legacy_heldout_path_label_detected = False
    post_reset_rows_excluded = 0
    failure_type_counts: dict[str, int] = {}
    max_consecutive_hold_by_trace: dict[str, int] = {}
    hold_rows_by_trace: dict[str, int] = {}
    for raw_path in trace_paths:
        path = Path(str(raw_path))
        if str(path) not in allowed:
            raise ValueError("trace_path_not_in_parent_gate")
        if not path.exists():
            raise ValueError("runtime_trace_unreadable")
        legacy_heldout_path_label_detected = legacy_heldout_path_label_detected or _path_has_legacy_heldout_label(path)
        payload = read_json(path)
        seed = _seed_from_trace_payload_or_path(payload, path)
        if _protected_heldout_seed_range_accessed(seed):
            raise ValueError("protected_heldout_seed_range_access")
        seeds.append(seed)
        trajectory_id = _scenario_id_from_trace_payload_or_path(payload, path)
        trace = payload.get("trace")
        if not isinstance(trace, list) or not trace:
            raise ValueError("runtime_trace_invalid")
        trace_sha = _sha256_file(path)
        trace_hashes[str(path)] = trace_sha
        source_paths.append(str(path))
        summary = payload.get("summary") if isinstance(payload.get("summary"), dict) else {}
        accepted = bool(summary.get("success") is True) if not accepted_from_summary else bool(accepted_from_summary)
        reason = str(summary.get("failure_reason") or ("success" if accepted else "trace_failed_env_native_window_missing"))
        failure_type_counts[reason] = failure_type_counts.get(reason, 0) + (0 if accepted else 1)
        reset_cutoff = _post_reset_cutoff_step(payload)
        previous_step = -1
        consecutive_hold = 0
        max_consecutive_hold = 0
        hold_count = 0
        for trace_row in trace:
            if not isinstance(trace_row, dict):
                raise ValueError("runtime_trace_invalid")
            try:
                step = int(trace_row["step"])
            except (KeyError, TypeError, ValueError) as exc:
                raise ValueError("runtime_trace_step_invalid") from exc
            if step <= previous_step:
                raise ValueError("runtime_trace_step_not_strictly_increasing")
            previous_step = step
            if reset_cutoff is not None and step >= reset_cutoff:
                post_reset_rows_excluded += 1
                continue
            converted = trace_row_to_v07a2_train_row(
                trace_row,
                source_trace_path=path,
                source_trace_sha256=trace_sha,
                trajectory_id=trajectory_id,
                source_trace_role=source_trace_role,
                accepted=accepted,
            )
            rows.append(converted)
            if converted["behavior_state_phase"] == "HOLD":
                hold_count += 1
                consecutive_hold += 1
                max_consecutive_hold = max(max_consecutive_hold, consecutive_hold)
            else:
                consecutive_hold = 0
        hold_rows_by_trace[str(path)] = hold_count
        max_consecutive_hold_by_trace[str(path)] = max_consecutive_hold
    report = {
        "source_trace_role": source_trace_role,
        "source_trace_paths": source_paths,
        "source_trace_count": len(source_paths),
        "source_trace_sha256_by_path": trace_hashes,
        "scenario_seeds": seeds,
        "row_count": len(rows),
        "hold_rows": sum(1 for row in rows if row.get("behavior_state_phase") == "HOLD"),
        "hold_rows_by_trace": hold_rows_by_trace,
        "max_consecutive_hold_by_trace": max_consecutive_hold_by_trace,
        "post_reset_rows_excluded": post_reset_rows_excluded,
        "failure_type_counts": failure_type_counts,
        "legacy_heldout_path_label_detected": legacy_heldout_path_label_detected,
        "legacy_heldout_path_label_interpretation": (
            "directory_name_only_not_protected_seed_split" if legacy_heldout_path_label_detected else ""
        ),
        "protected_heldout_seed_range": list(V07A2_PROTECTED_HELDOUT_SEED_RANGE),
        "protected_heldout_seed_range_accessed": False,
        "heldout_21000_21049_accessed": False,
    }
    return rows, report


def prepare_v07a2_candidate_rows(*, parent_gate: dict[str, Any]) -> tuple[list[dict[str, Any]], dict[str, Any]]:
    return _prepare_v07a2_trace_native_rows(
        parent_gate=parent_gate,
        trace_paths=[str(path) for path in parent_gate.get("generated_success_trace_paths") or []],
        source_trace_role="candidate_success",
        accepted_from_summary=True,
    )


def prepare_v07a2_baseline_rows(*, parent_gate: dict[str, Any]) -> tuple[list[dict[str, Any]], dict[str, Any]]:
    generated_count = int(parent_gate.get("generated_rollout_count", 0) or 0)
    success_count = int(parent_gate.get("generated_success_count", 0) or 0)
    rows, report = _prepare_v07a2_trace_native_rows(
        parent_gate=parent_gate,
        trace_paths=[str(path) for path in parent_gate.get("generated_trace_paths") or []],
        source_trace_role="baseline_uncurated",
        accepted_from_summary=False,
    )
    denominator = max(generated_count, 1)
    report.update(
        {
            "baseline_view_semantics": "baseline_uncurated_all_attempts_from_parent_gate",
            "baseline_noise_mix_ratio": round((generated_count - success_count) / denominator, 6),
            "accepted_count_in_baseline_view": success_count,
            "failure_or_noisy_count_in_baseline_view": max(generated_count - success_count, 0),
            "failure_type_distribution": report.get("failure_type_counts", {}),
        }
    )
    return rows, report


def _seed_from_v07b_row(row: dict[str, Any]) -> int | None:
    for key in ("trajectory_id", "scenario_id", "source_trace_path", "runtime_trace_path"):
        value = row.get(key)
        if value is None:
            continue
        match = re.search(r"(?:train_success|train_failure|held_out|calibration)_(\d+)", str(value))
        if match is not None:
            return int(match.group(1))
    return None


def _metric_row_for_base_servo(row: dict[str, Any]) -> dict[str, Any]:
    return {
        "phase": row.get("phase"),
        "insertion_depth_m": row.get("insertion_depth_m", 0.0),
        "relative_x_m": row.get("relative_x_m", 0.0),
        "relative_y_m": row.get("relative_y_m", 0.0),
        "lateral_error_m": row.get("lateral_error_m", 0.0),
        "orientation_error_deg": row.get("orientation_error_deg", 0.0),
    }


def trace_row_to_v07b_residual_train_row(
    row: dict[str, Any],
    *,
    residual_servo_config: dict[str, Any],
    proof_role: str = "trace_native_residual_train",
) -> dict[str, Any]:
    validate_v07b_residual_servo_config_contract(residual_servo_config)
    seed = _seed_from_v07b_row(row)
    if seed is not None and _protected_heldout_seed_range_accessed(seed):
        raise ValueError("protected_heldout_seed_range_access")
    actual = np.asarray(_action_with_schema_length(row.get("normalized_action", [])), dtype=np.float64)
    base = _weak_base_servo_action(
        metric_row=_metric_row_for_base_servo(row),
        config=dict(residual_servo_config["base_servo_config"]),
    )
    residual = np.round(actual - base, 10)
    return {
        **row,
        "normalized_action": residual.tolist(),
        "actual_trace_action": np.round(actual, 10).tolist(),
        "base_servo_action": np.round(base, 10).tolist(),
        "base_servo_id": V07B_BASE_SERVO_ID,
        "base_servo_config_sha256": residual_servo_config["base_servo_config_sha256"],
        "residual_servo_config_sha256": residual_servo_config["v0_7b_residual_servo_config_sha256"],
        "residual_target_definition": V07B_RESIDUAL_TARGET_DEFINITION,
        "policy_slice": V07B_POLICY_SLICE_ID,
        "parent_policy_slice": V07A2_POLICY_SLICE_ID,
        "proof_role": proof_role,
        "heldout_21000_21049_accessed": False,
    }


def residualized_rows_for_v07b(
    rows: list[dict[str, Any]],
    *,
    residual_servo_config: dict[str, Any],
    proof_role: str = "trace_native_residual_train",
) -> list[dict[str, Any]]:
    return [
        trace_row_to_v07b_residual_train_row(row, residual_servo_config=residual_servo_config, proof_role=proof_role)
        for row in rows
    ]


def prepare_v07b_candidate_rows(
    *,
    parent_gate: dict[str, Any],
    residual_servo_config: dict[str, Any],
) -> tuple[list[dict[str, Any]], dict[str, Any]]:
    rows, report = prepare_v07a2_candidate_rows(parent_gate=parent_gate)
    return residualized_rows_for_v07b(rows, residual_servo_config=residual_servo_config), {
        **report,
        "residualized_for_policy_slice": V07B_POLICY_SLICE_ID,
        "residual_target_definition": V07B_RESIDUAL_TARGET_DEFINITION,
    }


def prepare_v07b_baseline_rows(
    *,
    parent_gate: dict[str, Any],
    residual_servo_config: dict[str, Any],
) -> tuple[list[dict[str, Any]], dict[str, Any]]:
    rows, report = prepare_v07a2_baseline_rows(parent_gate=parent_gate)
    return residualized_rows_for_v07b(rows, residual_servo_config=residual_servo_config), {
        **report,
        "residualized_for_policy_slice": V07B_POLICY_SLICE_ID,
        "residual_target_definition": V07B_RESIDUAL_TARGET_DEFINITION,
    }


def _validate_v07b_recovery_induction_source(payload: dict[str, Any]) -> None:
    if payload.get("schema_version") != V07B_SHARED_RECOVERY_INDUCTION_SCHEMA_VERSION:
        raise ValueError("recovery_overlay_labeler_unavailable")
    if [int(seed) for seed in payload.get("source_seeds", [])] != list(V07B_RECOVERY_SOURCE_SEEDS):
        raise ValueError("recovery_overlay_labeler_unavailable")
    if payload.get("state_induction_policy") not in {
        "shared_frozen_base_servo",
        "shared_pre_registered_zero_residual_policy",
    }:
        raise ValueError("recovery_overlay_labeler_unavailable")
    if payload.get("source_policy_slice") != "none":
        raise ValueError("recovery_overlay_labeler_unavailable")
    if payload.get("policy_specific_source") is not False:
        raise ValueError("recovery_overlay_labeler_unavailable")
    if payload.get("shared_overlay_for_both_views") is not True:
        raise ValueError("recovery_overlay_labeler_unavailable")
    if payload.get("proof_authority") is not False:
        raise ValueError("recovery_overlay_labeler_unavailable")


def _v07b_recovery_trace_entries(source_payload: dict[str, Any], source_path: Path) -> list[dict[str, Any]]:
    entries = source_payload.get("traces")
    if isinstance(entries, list) and entries:
        return [entry for entry in entries if isinstance(entry, dict)]
    trace_paths = source_payload.get("trace_paths")
    if isinstance(trace_paths, list):
        loaded: list[dict[str, Any]] = []
        for raw_path in trace_paths:
            path = Path(str(raw_path))
            if not path.is_absolute():
                path = source_path.parent / path
            payload = read_json(path)
            loaded.append(payload)
        return loaded
    return []


def build_v07b_shared_recovery_induction_manifest(source_manifest: dict[str, Any]) -> dict[str, Any]:
    rows_by_seed = {
        int(row["seed"]): row
        for row in source_manifest.get("scenarios", [])
        if isinstance(row, dict) and row.get("split") == "train_success" and "seed" in row
    }
    scenarios: list[dict[str, Any]] = []
    for seed in V07B_RECOVERY_SOURCE_SEEDS:
        if int(seed) not in rows_by_seed:
            raise ValueError("recovery_overlay_source_seed_missing")
        row = dict(rows_by_seed[int(seed)])
        row["source_split"] = row.get("split")
        row["split"] = "held_out"
        row["proof_role"] = "v0_7b_shared_train_recovery_induction"
        scenarios.append(row)
    manifest = {
        "schema_version": "rdf_mvp2e_v07b_shared_recovery_induction_manifest_v0.1.0",
        "source_manifest_sha256": source_manifest["manifest_sha256"],
        "scenario_profile": source_manifest.get("scenario_profile"),
        "task_type": source_manifest.get("task_type", "connector_insertion"),
        "success_metric": dict(source_manifest.get("success_metric") or SUCCESS_METRIC),
        "success_authority": source_manifest.get("success_authority"),
        "selected_seed_ids": list(V07B_RECOVERY_SOURCE_SEEDS),
        "source_policy_slice": "none",
        "state_induction_policy": "shared_frozen_base_servo",
        "heldout_21000_21049_accessed": False,
        "proof_authority": False,
        "scenarios": scenarios,
    }
    manifest["manifest_sha256"] = _sha256_payload(manifest)
    return manifest


def build_v07b_shared_base_servo_recovery_policy_artifact(
    *,
    residual_servo_config: dict[str, Any],
    selected_adapter: dict[str, Any],
) -> dict[str, Any]:
    validate_v07b_residual_servo_config_contract(residual_servo_config)
    selected_adapter_config = selected_adapter.get("selected_adapter_config")
    if not isinstance(selected_adapter_config, dict):
        raise ValueError("recovery_overlay_labeler_unavailable")
    selected_adapter_id = str(selected_adapter.get("selected_adapter_id") or "")
    if not selected_adapter_id:
        raise ValueError("recovery_overlay_labeler_unavailable")
    payload: dict[str, Any] = {
        "policy_artifact_schema_version": "rdf_mvp2e_v07b_shared_base_servo_policy_artifact_v0.1.0",
        "policy_id": "shared_frozen_base_servo_v0_7b_recovery_induction",
        "policy_slice": V07B_POLICY_SLICE_ID,
        "source_policy_slice": "none",
        "state_induction_policy": "shared_frozen_base_servo",
        "policy_specific_source": False,
        "shared_overlay_for_both_views": True,
        "policy_class": RESIDUAL_POLICY_CLASS,
        "trainer": RESIDUAL_TRAINER,
        "trainer_family": RESIDUAL_TRAINER_FAMILY,
        "feature_schema": list(FEATURE_SCHEMA_V07A),
        "feature_schema_version": FEATURE_SCHEMA_V07A_VERSION,
        "phase_schema": list(BEHAVIOR_STATE_PHASES),
        "behavior_state_phase_input": True,
        "behavior_phase_rule_version": V07A2_BEHAVIOR_PHASE_RULE_VERSION,
        "phase_label_source": V07A2_BEHAVIOR_PHASE_LABEL_SOURCE,
        "weights": [[0.0] * len(ACTION_SCHEMA) for _ in FEATURE_SCHEMA_V07A],
        "bias": [0.0] * len(ACTION_SCHEMA),
        "base_servo_plus_learned_residual": True,
        "base_servo_id": V07B_BASE_SERVO_ID,
        "base_servo_config": dict(residual_servo_config["base_servo_config"]),
        "base_servo_config_sha256": residual_servo_config["base_servo_config_sha256"],
        "residual_servo_config_sha256": residual_servo_config["v0_7b_residual_servo_config_sha256"],
        "residual_target_definition": V07B_RESIDUAL_TARGET_DEFINITION,
        "selected_action_adapter_id": selected_adapter_id,
        "selected_action_adapter_config": dict(selected_adapter_config),
        "selected_action_adapter_config_sha256": _sha256_payload(selected_adapter_config),
        "proof_authority": False,
        "heldout_21000_21049_accessed": False,
        "buyer_facing_limitation": V07A_BUYER_FACING_LIMITATION,
    }
    payload["policy_artifact_sha256"] = _sha256_payload_excluding(payload, "policy_artifact_sha256")
    return payload


def _sample_v07b_recovery_rows(trace: list[dict[str, Any]], *, max_rows: int) -> list[dict[str, Any]]:
    if len(trace) <= max_rows:
        return [row for row in trace if isinstance(row, dict)]
    if max_rows <= 1:
        return [trace[0]]
    indices = sorted({round(index * (len(trace) - 1) / (max_rows - 1)) for index in range(max_rows)})
    return [trace[index] for index in indices if isinstance(trace[index], dict)]


def _v07b_expert_recovery_action_from_state(
    row: dict[str, Any],
    *,
    parent_controller_repair_config: dict[str, Any],
) -> list[float]:
    phase = str(row.get("behavior_state_phase") or derive_v07a2_behavior_state_phase_from_metrics(
        {
            "env_native_success_mask": bool(row.get("env_native_success_mask", row.get("env_native_success", False))),
            "lateral_error_m": float(row.get("lateral_error_m", 0.0)),
            "insertion_depth_m": float(row.get("insertion_depth_m", 0.0)),
        }
    )).upper()
    xy_gain = float(parent_controller_repair_config.get("xy_state_feedback_gain", V06I_XY_STATE_FEEDBACK_GAIN))
    xy_clip = float(parent_controller_repair_config.get("xy_action_clip", V06I_XY_ACTION_CLIP))
    z_clip = float(parent_controller_repair_config.get("z_action_clip", V06H_Z_ACTION_CLIP))
    action = np.zeros(len(ACTION_SCHEMA), dtype=np.float64)
    action[0] = np.clip(-float(row.get("relative_x_m", 0.0)) * xy_gain, -xy_clip, xy_clip)
    action[1] = np.clip(-float(row.get("relative_y_m", 0.0)) * xy_gain, -xy_clip, xy_clip)
    if phase == "DESCEND":
        action[2] = -z_clip
    elif phase == "HOLD":
        hold_action = parent_controller_repair_config.get("stable_hold_action")
        if isinstance(hold_action, list) and len(hold_action) >= len(ACTION_SCHEMA):
            action = np.asarray(_action_with_schema_length(hold_action), dtype=np.float64)
        else:
            action[2] = 0.0
    if len(ACTION_SCHEMA) > 6:
        action[6] = 1.0
    return np.round(action, 10).tolist()


def build_v07b_train_recovery_overlay(
    *,
    source_path: Path,
    residual_servo_config: dict[str, Any],
    parent_controller_repair_config: dict[str, Any],
) -> dict[str, Any]:
    validate_v07b_residual_servo_config_contract(residual_servo_config)
    if not source_path.exists():
        raise ValueError("recovery_overlay_source_unavailable")
    if not isinstance(parent_controller_repair_config, dict) or not parent_controller_repair_config:
        raise ValueError("recovery_overlay_labeler_unavailable")
    source_payload = read_json(source_path)
    _validate_v07b_recovery_induction_source(source_payload)
    trace_entries = _v07b_recovery_trace_entries(source_payload, source_path)
    if source_payload.get("passed") is not True or not trace_entries:
        raise ValueError("recovery_overlay_source_unavailable")
    rows: list[dict[str, Any]] = []
    for entry in trace_entries:
        scenario = entry.get("scenario") if isinstance(entry.get("scenario"), dict) else {}
        seed = entry.get("seed") or entry.get("scenario_seed") or scenario.get("seed")
        if seed is not None and _protected_heldout_seed_range_accessed(int(seed)):
            raise ValueError("protected_heldout_seed_range_access")
        scenario_id = entry.get("scenario_id") or scenario.get("scenario_id") or f"train_recovery_{seed}"
        trace = entry.get("trace")
        if not isinstance(trace, list):
            continue
        for row in _sample_v07b_recovery_rows(trace, max_rows=V07B_RECOVERY_MAX_ROWS_PER_TRACE):
            if len(rows) >= V07B_RECOVERY_MAX_TOTAL_ROWS:
                break
            expert_action = _v07b_expert_recovery_action_from_state(
                row,
                parent_controller_repair_config=parent_controller_repair_config,
            )
            prepared = {
                **row,
                "trajectory_id": str(scenario_id),
                "normalized_action": expert_action,
                "accepted": False,
                "proof_role": "train_closed_loop_recovery_correction",
                "source_trace_role": "shared_train_recovery_overlay",
            }
            rows.append(
                trace_row_to_v07b_residual_train_row(
                    prepared,
                    residual_servo_config=residual_servo_config,
                    proof_role="train_closed_loop_recovery_correction",
                )
            )
    if not rows:
        raise ValueError("recovery_overlay_source_unavailable")
    manifest = {
        "schema_version": "rdf_mvp2e_v07b_train_recovery_overlay_v0.1.0",
        "source_path": str(source_path),
        "source_sha256": _sha256_file(source_path),
        "source_seeds": list(V07B_RECOVERY_SOURCE_SEEDS),
        "state_induction_policy": source_payload.get("state_induction_policy"),
        "source_policy_slice": "none",
        "policy_specific_source": False,
        "shared_overlay_for_both_views": True,
        "proof_authority": False,
        "max_rows_per_trace": V07B_RECOVERY_MAX_ROWS_PER_TRACE,
        "max_total_rows": V07B_RECOVERY_MAX_TOTAL_ROWS,
        "row_count": len(rows),
        "calibration_recovery_rows_in_train_view": False,
        "heldout_21000_21049_accessed": False,
    }
    manifest["train_recovery_overlay_sha256"] = _sha256_payload_excluding(
        manifest,
        "train_recovery_overlay_sha256",
    )
    return {"rows": rows, "manifest": manifest}


def _v07b_residual_fit_metric_block(
    rows: list[dict[str, Any]],
    predictions: list[list[float]],
    *,
    metric_role: str,
) -> dict[str, Any]:
    phase_counts = _behavior_phase_counts(rows)
    if len(rows) != len(predictions) or any(phase_counts[phase] <= 0 for phase in BEHAVIOR_STATE_PHASES):
        return {
            "metric_role": metric_role,
            "phase_row_counts": phase_counts,
            "required_phase_missing": True,
            "metric_status": "required_phase_missing",
        }
    residual_xy_mae_values: list[float] = []
    residual_z_mae_values: list[float] = []
    residual_rmse_values: list[float] = []
    reconstructed_xy_mae_values: list[float] = []
    reconstructed_z_mae_values: list[float] = []
    reconstructed_rmse_values: list[float] = []
    for phase in BEHAVIOR_STATE_PHASES:
        pairs = _phase_rows_with_predictions(rows, predictions, phase)
        expert_residual = np.asarray([row["normalized_action"] for row, _ in pairs], dtype=np.float64)
        pred_residual = np.asarray([prediction for _, prediction in pairs], dtype=np.float64)
        base = np.asarray([row["base_servo_action"] for row, _ in pairs], dtype=np.float64)
        actual = np.asarray([row["actual_trace_action"] for row, _ in pairs], dtype=np.float64)
        reconstructed = base + pred_residual
        residual_xy_mae_values.append(float(np.mean(np.abs(pred_residual[:, :2] - expert_residual[:, :2]))))
        residual_z_mae_values.append(float(np.mean(np.abs(pred_residual[:, 2] - expert_residual[:, 2]))))
        residual_rmse_values.append(float(np.sqrt(np.mean((pred_residual - expert_residual) ** 2))))
        reconstructed_xy_mae_values.append(float(np.mean(np.abs(reconstructed[:, :2] - actual[:, :2]))))
        reconstructed_z_mae_values.append(float(np.mean(np.abs(reconstructed[:, 2] - actual[:, 2]))))
        reconstructed_rmse_values.append(float(np.sqrt(np.mean((reconstructed - actual) ** 2))))
    align_pairs = _phase_rows_with_predictions(rows, predictions, "ALIGN")
    descend_pairs = _phase_rows_with_predictions(rows, predictions, "DESCEND")
    hold_pairs = _phase_rows_with_predictions(rows, predictions, "HOLD")

    def reconstructed_z(row: dict[str, Any], pred: list[float]) -> float:
        return float(np.asarray(row["base_servo_action"], dtype=np.float64)[2] + np.asarray(pred, dtype=np.float64)[2])

    align_negative_rate = sum(1 for row, pred in align_pairs if reconstructed_z(row, pred) <= -0.08) / len(align_pairs)
    descend_negative_rate = sum(
        1 for row, pred in descend_pairs if reconstructed_z(row, pred) <= -0.08
    ) / len(descend_pairs)
    descend_sign_agreement = sum(
        1
        for row, pred in descend_pairs
        if _sign_bucket(reconstructed_z(row, pred)) == _sign_bucket(float(row["actual_trace_action"][2]))
    ) / len(descend_pairs)
    hold_abs_z_mean = statistics.mean(abs(reconstructed_z(row, pred)) for row, pred in hold_pairs)
    return {
        "metric_role": metric_role,
        "phase_row_counts": phase_counts,
        "required_phase_missing": False,
        "metric_status": "computed",
        "candidate_residual_xy_mae_max": round(max(residual_xy_mae_values), 6),
        "candidate_residual_z_mae_max": round(max(residual_z_mae_values), 6),
        "candidate_residual_action_rmse_max": round(max(residual_rmse_values), 6),
        "candidate_reconstructed_action_xy_mae_max": round(max(reconstructed_xy_mae_values), 6),
        "candidate_reconstructed_action_z_mae_max": round(max(reconstructed_z_mae_values), 6),
        "candidate_reconstructed_action_rmse_max": round(max(reconstructed_rmse_values), 6),
        "candidate_align_reconstructed_negative_z_rate": round(align_negative_rate, 6),
        "candidate_descend_reconstructed_negative_z_rate": round(descend_negative_rate, 6),
        "candidate_descend_reconstructed_z_sign_agreement": round(descend_sign_agreement, 6),
        "candidate_hold_reconstructed_abs_z_mean": round(float(hold_abs_z_mean), 6),
    }


def derive_v07b_offline_residual_fit_gate(
    *,
    candidate_rows: list[dict[str, Any]],
    candidate_predictions: list[list[float]],
    candidate_policy_artifact_sha256: str,
    residual_servo_config_sha256: str,
    baseline_rows: list[dict[str, Any]] | None = None,
    baseline_predictions: list[list[float]] | None = None,
    baseline_policy_artifact_sha256: str | None = None,
) -> dict[str, Any]:
    baseline_rows = baseline_rows or []
    baseline_predictions = baseline_predictions or []
    candidate_metrics = _v07b_residual_fit_metric_block(
        candidate_rows,
        candidate_predictions,
        metric_role="candidate_gate",
    )
    baseline_metrics = _v07b_residual_fit_metric_block(
        baseline_rows,
        baseline_predictions,
        metric_role="baseline_report_only",
    )
    gate: dict[str, Any] = {
        "schema_version": V07B_OFFLINE_RESIDUAL_FIT_GATE_SCHEMA_VERSION,
        "policy_slice": V07B_POLICY_SLICE_ID,
        "slice_id": V07B_SLICE_ID,
        "behavior_phase_rule_version": V07A2_BEHAVIOR_PHASE_RULE_VERSION,
        "residual_target_definition": V07B_RESIDUAL_TARGET_DEFINITION,
        "residual_servo_config_sha256": residual_servo_config_sha256,
        "candidate_policy_artifact_sha256": candidate_policy_artifact_sha256,
        "baseline_policy_artifact_sha256": baseline_policy_artifact_sha256,
        "thresholds": dict(V07B_OFFLINE_RESIDUAL_FIT_THRESHOLDS),
        "baseline_report_only": True,
        "baseline_same_metrics_report_only": baseline_metrics,
        "phase_e_candidate_expressibility_unblocked": False,
        "future_ab_ready": False,
        "heldout_21000_21049_accessed": False,
        "proof_authority": False,
        "buyer_facing_limitation": V07A_BUYER_FACING_LIMITATION,
    }
    if candidate_metrics.get("required_phase_missing") is True:
        gate.update({"passed": False, "candidate_gate_passed": False, "failure_reason": "required_phase_missing"})
        gate["offline_residual_fit_gate_sha256"] = _sha256_payload_excluding(
            gate,
            "offline_residual_fit_gate_sha256",
        )
        return gate
    gate.update(candidate_metrics)
    thresholds = V07B_OFFLINE_RESIDUAL_FIT_THRESHOLDS
    passed = (
        gate["candidate_residual_xy_mae_max"] <= thresholds["candidate_residual_xy_mae_max"]
        and gate["candidate_residual_z_mae_max"] <= thresholds["candidate_residual_z_mae_max"]
        and gate["candidate_residual_action_rmse_max"] <= thresholds["candidate_residual_action_rmse_max"]
        and gate["candidate_reconstructed_action_xy_mae_max"]
        <= thresholds["candidate_reconstructed_action_xy_mae_max"]
        and gate["candidate_reconstructed_action_z_mae_max"] <= thresholds["candidate_reconstructed_action_z_mae_max"]
        and gate["candidate_reconstructed_action_rmse_max"]
        <= thresholds["candidate_reconstructed_action_rmse_max"]
        and gate["candidate_align_reconstructed_negative_z_rate"]
        <= thresholds["candidate_align_reconstructed_negative_z_rate_max"]
        and gate["candidate_descend_reconstructed_negative_z_rate"]
        >= thresholds["candidate_descend_reconstructed_negative_z_rate_min"]
        and gate["candidate_descend_reconstructed_z_sign_agreement"]
        >= thresholds["candidate_descend_reconstructed_z_sign_agreement_min"]
        and gate["candidate_hold_reconstructed_abs_z_mean"]
        <= thresholds["candidate_hold_reconstructed_abs_z_mean_max"]
    )
    gate["candidate_gate_passed"] = bool(passed)
    gate["passed"] = bool(passed)
    gate["phase_e_candidate_expressibility_unblocked"] = bool(passed)
    gate["failure_reason"] = "" if passed else "offline_residual_fit_failed"
    gate["future_calibration_blocked_reason"] = None if passed else "candidate_offline_residual_fit_failed"
    gate["future_ab_ready"] = bool(passed and baseline_policy_artifact_sha256)
    gate["offline_residual_fit_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "offline_residual_fit_gate_sha256",
    )
    return gate


def write_v07b_residual_train_view_hdf5(
    *,
    path: Path,
    rows: list[dict[str, Any]],
    view_id: str,
    residual_servo_config: dict[str, Any],
) -> dict[str, Any]:
    validate_v07b_residual_servo_config_contract(residual_servo_config)
    features, targets = _features_targets(rows, feature_schema=FEATURE_SCHEMA_V07A)
    string_dtype = h5py.string_dtype(encoding="utf-8")
    metadata = np.asarray([stable_json(row) for row in rows], dtype=object)
    path.parent.mkdir(parents=True, exist_ok=True)
    with h5py.File(path, "w") as h5:
        h5.attrs["schema_version"] = V07B_MANIFEST_SCHEMA_VERSION
        h5.attrs["view_id"] = view_id
        h5.attrs["feature_schema"] = stable_json(FEATURE_SCHEMA_V07A)
        h5.attrs["feature_schema_version"] = FEATURE_SCHEMA_V07A_VERSION
        h5.attrs["phase_schema"] = stable_json(list(BEHAVIOR_STATE_PHASES))
        h5.attrs["action_schema"] = stable_json(ACTION_SCHEMA)
        h5.attrs["residual_target_definition"] = V07B_RESIDUAL_TARGET_DEFINITION
        h5.attrs["base_servo_id"] = V07B_BASE_SERVO_ID
        h5.attrs["residual_servo_config_sha256"] = residual_servo_config[
            "v0_7b_residual_servo_config_sha256"
        ]
        h5.create_dataset("features", data=features)
        h5.create_dataset("actions", data=targets)
        h5.create_dataset("metadata_json", data=metadata, dtype=string_dtype)
    return {
        "schema_version": V07B_MANIFEST_SCHEMA_VERSION,
        "view_id": view_id,
        "path": str(path),
        "sha256": _sha256_file(path),
        "trajectory_count": len({str(row.get("trajectory_id")) for row in rows}),
        "transition_count": len(rows),
        "feature_schema": list(FEATURE_SCHEMA_V07A),
        "phase_schema": list(BEHAVIOR_STATE_PHASES),
        "residual_target_definition": V07B_RESIDUAL_TARGET_DEFINITION,
        "base_servo_id": V07B_BASE_SERVO_ID,
        "residual_servo_config_sha256": residual_servo_config["v0_7b_residual_servo_config_sha256"],
        "includes_rejected_material": any(row.get("accepted") is False for row in rows),
        "recovery_overlay_rows": sum(
            1 for row in rows if row.get("proof_role") == "train_closed_loop_recovery_correction"
        ),
    }


def build_v07b_policy_artifact_payload(
    *,
    base_policy_artifact: dict[str, Any],
    residual_servo_config: dict[str, Any],
    dataset_view_role: str,
    same_peer_contract: bool,
) -> dict[str, Any]:
    validate_v07b_residual_servo_config_contract(residual_servo_config)
    payload = dict(base_policy_artifact)
    payload.update(
        {
            "policy_artifact_schema_version": V07B_POLICY_ARTIFACT_SCHEMA_VERSION,
            "policy_slice": V07B_POLICY_SLICE_ID,
            "slice_id": V07B_SLICE_ID,
            "dataset_view_role": dataset_view_role,
            "policy_class": RESIDUAL_POLICY_CLASS,
            "trainer": RESIDUAL_TRAINER,
            "trainer_family": RESIDUAL_TRAINER_FAMILY,
            "behavior_phase_rule_version": V07A2_BEHAVIOR_PHASE_RULE_VERSION,
            "behavior_state_phase_input": True,
            "phase_label_source": V07A2_BEHAVIOR_PHASE_LABEL_SOURCE,
            "feature_schema_version": FEATURE_SCHEMA_V07A_VERSION,
            "base_servo_plus_learned_residual": True,
            "base_servo_id": V07B_BASE_SERVO_ID,
            "base_servo_config": dict(residual_servo_config["base_servo_config"]),
            "base_servo_config_sha256": residual_servo_config["base_servo_config_sha256"],
            "residual_servo_config_sha256": residual_servo_config["v0_7b_residual_servo_config_sha256"],
            "residual_target_definition": V07B_RESIDUAL_TARGET_DEFINITION,
            "same_base_servo_as_peer": same_peer_contract,
            "same_feature_schema_as_peer": same_peer_contract,
            "same_trainer_hyperparameters_as_peer": same_peer_contract,
            "same_selected_action_adapter_as_peer": same_peer_contract,
            "proof_authority": False,
            "heldout_21000_21049_accessed": False,
            "buyer_facing_limitation": V07A_BUYER_FACING_LIMITATION,
        }
    )
    payload["policy_artifact_sha256"] = _sha256_payload_excluding(payload, "policy_artifact_sha256")
    return payload


def _write_v07b_fail_closed_manifest(
    *,
    child_dir: Path,
    residual_servo_config: dict[str, Any],
    failure_reason: str,
    offline_gate: dict[str, Any] | None = None,
) -> dict[str, Any]:
    manifest = {
        "schema_version": V07B_MANIFEST_SCHEMA_VERSION,
        "slice_id": V07B_SLICE_ID,
        "policy_slice": V07B_POLICY_SLICE_ID,
        "parent_policy_slice": V07A2_POLICY_SLICE_ID,
        "residual_servo_config": residual_servo_config,
        "v0_7b_residual_servo_config_sha256": residual_servo_config["v0_7b_residual_servo_config_sha256"],
        "training_views": {},
        "policy_artifacts": {},
        "offline_residual_fit_gate": offline_gate or {
            "schema_version": V07B_OFFLINE_RESIDUAL_FIT_GATE_SCHEMA_VERSION,
            "passed": False,
            "failure_reason": failure_reason,
            "heldout_21000_21049_accessed": False,
            "proof_authority": False,
        },
        "failed_closed": True,
        "failure_reason": failure_reason,
        "heldout_opened": False,
        "heldout_21000_21049_accessed": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "buyer_facing_limitation": V07A_BUYER_FACING_LIMITATION,
    }
    manifest["v0_7b_residual_servo_manifest_sha256"] = _sha256_payload_excluding(
        manifest,
        "v0_7b_residual_servo_manifest_sha256",
    )
    write_json(child_dir / "v0_7b_residual_servo_manifest.json", manifest)
    return manifest


def build_v07b_residual_servo_slice(*, output_dir: Path) -> dict[str, Any]:
    parent_dir = output_dir
    child_dir = output_dir / V07B_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    v07a2_child = output_dir / V07A2_CHILD_OUTPUT_DIRNAME
    trace_config_path = v07a2_child / "v0_7a_2_trace_native_config.json"
    if trace_config_path.exists():
        trace_native_config = read_json(trace_config_path)
        validate_v07a2_trace_native_config_contract(trace_native_config)
    else:
        trace_native_config = build_v07a2_trace_native_train_view_slice(output_dir=output_dir).get(
            "trace_native_config",
            {},
        )
        validate_v07a2_trace_native_config_contract(trace_native_config)
    residual_servo_config = build_v07b_residual_servo_config(
        output_dir=child_dir,
        parent_config_sha256=trace_native_config["v0_7a_2_trace_native_config_sha256"],
    )
    parent_gate, _parent_gate_sha = load_v07a2_parent_train_generation_gate(parent_dir)
    candidate_rows, candidate_report = prepare_v07b_candidate_rows(
        parent_gate=parent_gate,
        residual_servo_config=residual_servo_config,
    )
    baseline_rows, baseline_report = prepare_v07b_baseline_rows(
        parent_gate=parent_gate,
        residual_servo_config=residual_servo_config,
    )
    recovery_source_path = child_dir / "shared_train_recovery_induction_v0_7b.json"
    controller_config_path = parent_dir / "controller_repair_config.json"
    try:
        overlay = build_v07b_train_recovery_overlay(
            source_path=recovery_source_path,
            residual_servo_config=residual_servo_config,
            parent_controller_repair_config=read_json(controller_config_path),
        )
    except ValueError as exc:
        reason = str(exc)
        write_json(
            child_dir / "offline_residual_fit_gate_v0_7b.json",
            {
                "schema_version": V07B_OFFLINE_RESIDUAL_FIT_GATE_SCHEMA_VERSION,
                "policy_slice": V07B_POLICY_SLICE_ID,
                "slice_id": V07B_SLICE_ID,
                "passed": False,
                "candidate_gate_passed": False,
                "phase_e_candidate_expressibility_unblocked": False,
                "failure_reason": reason,
                "future_calibration_blocked_reason": reason,
                "heldout_21000_21049_accessed": False,
                "proof_authority": False,
            },
        )
        return _write_v07b_fail_closed_manifest(
            child_dir=child_dir,
            residual_servo_config=residual_servo_config,
            failure_reason=reason,
        )
    recovery_rows = overlay["rows"]
    candidate_rows = candidate_rows + recovery_rows
    baseline_rows = baseline_rows + [dict(row) for row in recovery_rows]
    candidate_view = write_v07b_residual_train_view_hdf5(
        path=child_dir / "candidate_curated_train_v0_7b.hdf5",
        rows=candidate_rows,
        view_id="candidate_curated_v0_7b_residual_servo",
        residual_servo_config=residual_servo_config,
    )
    baseline_view = write_v07b_residual_train_view_hdf5(
        path=child_dir / "baseline_uncurated_train_v0_7b.hdf5",
        rows=baseline_rows,
        view_id="baseline_uncurated_v0_7b_residual_servo",
        residual_servo_config=residual_servo_config,
    )
    selection = read_json(parent_dir / "selected_action_adapter.json")
    selected_adapter_config = dict(selection["selected_adapter_config"])
    hyperparameters = {
        "ridge_lambda": 1e-3,
        "phase_input_shared": True,
        "feature_standardization": "none_deterministic_domain_units",
        "selected_action_adapter_id": selection["selected_adapter_id"],
        "selected_action_adapter_config_sha256": _sha256_payload(selected_adapter_config),
        "trainer_family": RESIDUAL_TRAINER_FAMILY,
        "base_servo_config_sha256": residual_servo_config["base_servo_config_sha256"],
        "residual_target_definition": V07B_RESIDUAL_TARGET_DEFINITION,
    }
    candidate_base = fit_phase_conditioned_bc_policy(
        policy_id="candidate_curated_mvp2e_v07b_residual_servo_bc",
        train_rows=candidate_rows,
        hyperparameters=hyperparameters,
        feature_schema=FEATURE_SCHEMA_V07A,
        phase_schema=BEHAVIOR_STATE_PHASES,
        feature_schema_version=FEATURE_SCHEMA_V07A_VERSION,
    )
    baseline_base = fit_phase_conditioned_bc_policy(
        policy_id="baseline_uncurated_mvp2e_v07b_residual_servo_bc",
        train_rows=baseline_rows,
        hyperparameters=hyperparameters,
        feature_schema=FEATURE_SCHEMA_V07A,
        phase_schema=BEHAVIOR_STATE_PHASES,
        feature_schema_version=FEATURE_SCHEMA_V07A_VERSION,
    )
    for payload in (candidate_base, baseline_base):
        payload["selected_action_adapter_id"] = selection["selected_adapter_id"]
        payload["selected_action_adapter_config"] = selected_adapter_config
        payload["selected_action_adapter_config_sha256"] = _sha256_payload(selected_adapter_config)
    candidate_policy = build_v07b_policy_artifact_payload(
        base_policy_artifact=candidate_base,
        residual_servo_config=residual_servo_config,
        dataset_view_role="candidate_curated",
        same_peer_contract=True,
    )
    baseline_policy = build_v07b_policy_artifact_payload(
        base_policy_artifact=baseline_base,
        residual_servo_config=residual_servo_config,
        dataset_view_role="baseline_uncurated",
        same_peer_contract=True,
    )
    candidate_policy_path = child_dir / "candidate_policy_artifact_v0_7b.json"
    baseline_policy_path = child_dir / "baseline_policy_artifact_v0_7b.json"
    write_json(candidate_policy_path, candidate_policy)
    write_json(baseline_policy_path, baseline_policy)
    candidate_predictions = predict_actions_for_rows(candidate_policy, candidate_rows)
    baseline_predictions = predict_actions_for_rows(baseline_policy, baseline_rows)
    offline_gate = derive_v07b_offline_residual_fit_gate(
        candidate_rows=candidate_rows,
        candidate_predictions=candidate_predictions,
        candidate_policy_artifact_sha256=candidate_policy["policy_artifact_sha256"],
        residual_servo_config_sha256=residual_servo_config["v0_7b_residual_servo_config_sha256"],
        baseline_rows=baseline_rows,
        baseline_predictions=baseline_predictions,
        baseline_policy_artifact_sha256=baseline_policy["policy_artifact_sha256"],
    )
    write_json(child_dir / "offline_residual_fit_gate_v0_7b.json", offline_gate)
    manifest = {
        "schema_version": V07B_MANIFEST_SCHEMA_VERSION,
        "slice_id": V07B_SLICE_ID,
        "policy_slice": V07B_POLICY_SLICE_ID,
        "parent_policy_slice": V07A2_POLICY_SLICE_ID,
        "residual_servo_config": residual_servo_config,
        "v0_7b_residual_servo_config_sha256": residual_servo_config["v0_7b_residual_servo_config_sha256"],
        "candidate_prepare_report": candidate_report,
        "baseline_report": baseline_report,
        "recovery_overlay_manifest": overlay["manifest"],
        "training_views": {"candidate": candidate_view, "baseline": baseline_view},
        "policy_artifacts": {
            "candidate": {**candidate_policy, "path": str(candidate_policy_path)},
            "baseline": {**baseline_policy, "path": str(baseline_policy_path)},
        },
        "offline_residual_fit_gate": offline_gate,
        "failed_closed": offline_gate.get("passed") is not True,
        "failure_reason": "" if offline_gate.get("passed") is True else offline_gate.get("failure_reason"),
        "heldout_opened": False,
        "heldout_21000_21049_accessed": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "buyer_facing_limitation": V07A_BUYER_FACING_LIMITATION,
    }
    manifest["v0_7b_residual_servo_manifest_sha256"] = _sha256_payload_excluding(
        manifest,
        "v0_7b_residual_servo_manifest_sha256",
    )
    write_json(child_dir / "v0_7b_residual_servo_manifest.json", manifest)
    return manifest


def _rows_from_hdf5_metadata(path: Path) -> list[dict[str, Any]]:
    if not path.exists():
        raise ValueError(f"missing_hdf5_view:{path}")
    with h5py.File(path, "r") as h5:
        metadata = h5["metadata_json"][()]
    rows: list[dict[str, Any]] = []
    for item in metadata:
        if isinstance(item, bytes):
            item = item.decode("utf-8")
        payload = json.loads(str(item))
        if not isinstance(payload, dict):
            raise ValueError("metadata_row_invalid")
        rows.append(payload)
    return rows


def write_v07c_residual_train_view_hdf5(
    *,
    path: Path,
    rows: list[dict[str, Any]],
    view_id: str,
    authority_config: dict[str, Any],
    schema_version: str = V07C_MANIFEST_SCHEMA_VERSION,
    extra_hdf5_attrs: dict[str, Any] | None = None,
    extra_view_fields: dict[str, Any] | None = None,
) -> dict[str, Any]:
    validate_v07c_action_authority_config_contract(authority_config)
    features, targets = _features_targets(rows, feature_schema=FEATURE_SCHEMA_V07A)
    string_dtype = h5py.string_dtype(encoding="utf-8")
    metadata = np.asarray([stable_json(row) for row in rows], dtype=object)
    path.parent.mkdir(parents=True, exist_ok=True)
    with h5py.File(path, "w") as h5:
        h5.attrs["schema_version"] = schema_version
        h5.attrs["view_id"] = view_id
        h5.attrs["feature_schema"] = stable_json(FEATURE_SCHEMA_V07A)
        h5.attrs["feature_schema_version"] = FEATURE_SCHEMA_V07A_VERSION
        h5.attrs["phase_schema"] = stable_json(list(BEHAVIOR_STATE_PHASES))
        h5.attrs["action_schema"] = stable_json(ACTION_SCHEMA)
        h5.attrs["residual_target_definition"] = V07B_RESIDUAL_TARGET_DEFINITION
        h5.attrs["base_servo_id"] = V07B_BASE_SERVO_ID
        h5.attrs["authority_filter_id"] = V07C_AUTHORITY_FILTER_ID
        h5.attrs["authority_filter_config_sha256"] = authority_config["authority_filter_config_sha256"]
        for key, value in (extra_hdf5_attrs or {}).items():
            h5.attrs[key] = stable_json(value) if isinstance(value, (dict, list, tuple)) else value
        h5.create_dataset("features", data=features)
        h5.create_dataset("actions", data=targets)
        h5.create_dataset("metadata_json", data=metadata, dtype=string_dtype)
    view = {
        "schema_version": schema_version,
        "view_id": view_id,
        "path": str(path),
        "sha256": _sha256_file(path),
        "trajectory_count": len({str(row.get("trajectory_id")) for row in rows}),
        "transition_count": len(rows),
        "feature_schema": list(FEATURE_SCHEMA_V07A),
        "phase_schema": list(BEHAVIOR_STATE_PHASES),
        "residual_target_definition": V07B_RESIDUAL_TARGET_DEFINITION,
        "base_servo_id": V07B_BASE_SERVO_ID,
        "authority_filter_id": V07C_AUTHORITY_FILTER_ID,
        "authority_filter_config_sha256": authority_config["authority_filter_config_sha256"],
        "includes_rejected_material": any(row.get("accepted") is False for row in rows),
        "recovery_overlay_rows": sum(
            1 for row in rows if row.get("proof_role") == "train_closed_loop_recovery_correction"
        ),
    }
    view.update(extra_view_fields or {})
    return view


def build_v07c_policy_artifact_payload(
    *,
    base_policy_artifact: dict[str, Any],
    authority_config: dict[str, Any],
    dataset_view_role: str,
) -> dict[str, Any]:
    validate_v07c_action_authority_config_contract(authority_config)
    payload = dict(base_policy_artifact)
    payload.update(
        {
            "policy_artifact_schema_version": V07C_POLICY_ARTIFACT_SCHEMA_VERSION,
            "policy_slice": V07C_POLICY_SLICE_ID,
            "slice_id": V07C_SLICE_ID,
            "dataset_view_role": dataset_view_role,
            "policy_class": RESIDUAL_POLICY_CLASS,
            "trainer": RESIDUAL_TRAINER,
            "trainer_family": RESIDUAL_TRAINER_FAMILY,
            "behavior_phase_rule_version": V07A2_BEHAVIOR_PHASE_RULE_VERSION,
            "behavior_state_phase_input": True,
            "feature_schema_version": FEATURE_SCHEMA_V07A_VERSION,
            "base_servo_plus_learned_residual": True,
            "base_servo_id": V07B_BASE_SERVO_ID,
            "residual_target_definition": V07B_RESIDUAL_TARGET_DEFINITION,
            "authority_filter_id": V07C_AUTHORITY_FILTER_ID,
            "authority_filter_config": dict(authority_config),
            "authority_filter_config_sha256": authority_config["authority_filter_config_sha256"],
            "same_base_servo_as_peer": True,
            "same_feature_schema_as_peer": True,
            "same_trainer_hyperparameters_as_peer": True,
            "same_selected_action_adapter_as_peer": True,
            "same_authority_filter_as_peer": True,
            "proof_authority": False,
            "heldout_21000_21049_accessed": False,
            "buyer_facing_limitation": V07A_BUYER_FACING_LIMITATION,
        }
    )
    payload["policy_artifact_sha256"] = _sha256_payload_excluding(payload, "policy_artifact_sha256")
    return payload


def build_v07c_residual_action_authority_slice(*, output_dir: Path) -> dict[str, Any]:
    parent_dir = output_dir
    v07b_dir = output_dir / V07B_CHILD_OUTPUT_DIRNAME
    v07b_manifest_path = v07b_dir / "v0_7b_residual_servo_manifest.json"
    if not v07b_manifest_path.exists():
        build_v07b_residual_servo_slice(output_dir=output_dir)
    v07b_manifest = read_json(v07b_manifest_path)
    if v07b_manifest.get("failed_closed") is True:
        raise ValueError("v0_7b_source_failed_closed")
    child_dir = output_dir / V07C_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    residual_servo_config = v07b_manifest["residual_servo_config"]
    selection = read_json(parent_dir / "selected_action_adapter.json")
    authority_config = build_v07c_action_authority_config(
        output_dir=child_dir,
        residual_servo_config=residual_servo_config,
        selected_action_adapter_id=selection["selected_adapter_id"],
    )
    candidate_rows = _rows_from_hdf5_metadata(v07b_dir / "candidate_curated_train_v0_7b.hdf5")
    baseline_rows = _rows_from_hdf5_metadata(v07b_dir / "baseline_uncurated_train_v0_7b.hdf5")
    candidate_view = write_v07c_residual_train_view_hdf5(
        path=child_dir / "candidate_curated_train_v0_7c.hdf5",
        rows=candidate_rows,
        view_id="candidate_curated_v0_7c_residual_action_authority",
        authority_config=authority_config,
    )
    baseline_view = write_v07c_residual_train_view_hdf5(
        path=child_dir / "baseline_uncurated_train_v0_7c.hdf5",
        rows=baseline_rows,
        view_id="baseline_uncurated_v0_7c_residual_action_authority",
        authority_config=authority_config,
    )
    candidate_v07b = read_json(v07b_dir / "candidate_policy_artifact_v0_7b.json")
    baseline_v07b = read_json(v07b_dir / "baseline_policy_artifact_v0_7b.json")
    candidate_policy = build_v07c_policy_artifact_payload(
        base_policy_artifact={**candidate_v07b, "policy_id": "candidate_curated_mvp2e_v07c_residual_action_authority_bc"},
        authority_config=authority_config,
        dataset_view_role="candidate_curated",
    )
    baseline_policy = build_v07c_policy_artifact_payload(
        base_policy_artifact={**baseline_v07b, "policy_id": "baseline_uncurated_mvp2e_v07c_residual_action_authority_bc"},
        authority_config=authority_config,
        dataset_view_role="baseline_uncurated",
    )
    candidate_policy_path = child_dir / "candidate_policy_artifact_v0_7c.json"
    baseline_policy_path = child_dir / "baseline_policy_artifact_v0_7c.json"
    write_json(candidate_policy_path, candidate_policy)
    write_json(baseline_policy_path, baseline_policy)
    candidate_predictions = predict_actions_for_rows(candidate_policy, candidate_rows)
    baseline_predictions = predict_actions_for_rows(baseline_policy, baseline_rows)
    residual_gate = dict(v07b_manifest.get("offline_residual_fit_gate") or {})
    residual_gate.update(
        {
            "schema_version": V07B_OFFLINE_RESIDUAL_FIT_GATE_SCHEMA_VERSION,
            "policy_slice": V07C_POLICY_SLICE_ID,
            "slice_id": V07C_SLICE_ID,
            "inherited_from_policy_slice": V07B_POLICY_SLICE_ID,
            "authority_filter_config_sha256": authority_config["authority_filter_config_sha256"],
            "heldout_21000_21049_accessed": False,
        }
    )
    residual_gate["offline_residual_fit_gate_sha256"] = _sha256_payload_excluding(
        residual_gate,
        "offline_residual_fit_gate_sha256",
    )
    write_json(child_dir / "offline_residual_fit_gate_v0_7c.json", residual_gate)
    authority_gate = derive_v07c_offline_action_authority_gate(
        candidate_rows=candidate_rows,
        baseline_rows=baseline_rows,
        candidate_policy_artifact=candidate_policy,
        baseline_policy_artifact=baseline_policy,
        candidate_predictions=candidate_predictions,
        baseline_predictions=baseline_predictions,
        authority_config=authority_config,
    )
    write_json(child_dir / "offline_action_authority_gate_v0_7c.json", authority_gate)
    recovery_source_path = v07b_dir / "shared_train_recovery_induction_v0_7b.json"
    manifest = {
        "schema_version": V07C_MANIFEST_SCHEMA_VERSION,
        "slice_id": V07C_SLICE_ID,
        "policy_slice": V07C_POLICY_SLICE_ID,
        "parent_policy_slice": V07B_POLICY_SLICE_ID,
        "v0_7b_manifest_sha256": _sha256_file(v07b_manifest_path),
        "source_v0_7b_recovery_sha256": _sha256_file(recovery_source_path) if recovery_source_path.exists() else None,
        "authority_filter_config": authority_config,
        "authority_filter_config_sha256": authority_config["authority_filter_config_sha256"],
        "training_views": {"candidate": candidate_view, "baseline": baseline_view},
        "policy_artifacts": {
            "candidate": {**candidate_policy, "path": str(candidate_policy_path)},
            "baseline": {**baseline_policy, "path": str(baseline_policy_path)},
        },
        "offline_residual_fit_gate_v0_7c": residual_gate,
        "offline_action_authority_gate_v0_7c": authority_gate,
        "failed_closed": not (residual_gate.get("passed") is True and authority_gate.get("passed") is True),
        "failure_reason": "" if residual_gate.get("passed") is True and authority_gate.get("passed") is True else (
            authority_gate.get("failure_reason") or residual_gate.get("failure_reason")
        ),
        "heldout_opened": False,
        "heldout_21000_21049_accessed": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "buyer_facing_limitation": V07A_BUYER_FACING_LIMITATION,
    }
    manifest["v0_7c_residual_action_authority_manifest_sha256"] = _sha256_payload_excluding(
        manifest,
        "v0_7c_residual_action_authority_manifest_sha256",
    )
    write_json(child_dir / "v0_7c_residual_action_authority_manifest.json", manifest)
    return manifest


def load_required_v07d_parent_harness_report(*, output_dir: Path) -> dict[str, Any]:
    report_path = _mvp2e_harness_dir(output_dir) / "mvp2e_harness_report.json"
    if not report_path.exists():
        raise ValueError("missing_v0_7c_classified_harness_report")
    report = read_json(report_path)
    if (
        report.get("schema_version") != MVP2E_HARNESS_REPORT_SCHEMA_VERSION
        or report.get("policy_slice_under_test") != V07C_POLICY_SLICE_ID
        or report.get("root_cause_status") != "classified"
        or report.get("primary_root_cause_class") != "ACTION_AUTHORITY_POST_ADAPTER_Z_LEAK"
        or report.get("recommended_downstream_slice") != "v0_7d_action_authority_post_adapter_z_gate"
        or report.get("protected_heldout_21000_21049_accessed") is not False
        or report.get("calibration_opened") is not False
        or report.get("heldout_opened") is not False
        or report.get("mvp2_closed") is not False
    ):
        raise ValueError("invalid_v0_7c_classified_harness_report")
    return report


def build_v07d_action_authority_post_adapter_z_gate_slice(*, output_dir: Path) -> dict[str, Any]:
    v07c_dir = output_dir / V07C_CHILD_OUTPUT_DIRNAME
    v07c_manifest_path = v07c_dir / "v0_7c_residual_action_authority_manifest.json"
    if not v07c_manifest_path.exists():
        raise ValueError("missing_v0_7c_parent_manifest")
    parent_harness_report = load_required_v07d_parent_harness_report(output_dir=output_dir)
    v07c_manifest = read_json(v07c_manifest_path)
    child_dir = output_dir / V07D_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    authority_config = dict(v07c_manifest["authority_filter_config"])
    final_authority_config = build_v07d_final_action_authority_config(
        output_dir=child_dir,
        inherited_authority_filter_config_sha256=authority_config["authority_filter_config_sha256"],
        selected_action_adapter_id=authority_config["selected_action_adapter_id"],
    )
    candidate_rows = _rows_from_hdf5_metadata(v07c_dir / "candidate_curated_train_v0_7c.hdf5")
    baseline_rows = _rows_from_hdf5_metadata(v07c_dir / "baseline_uncurated_train_v0_7c.hdf5")
    candidate_view = write_v07c_residual_train_view_hdf5(
        path=child_dir / "candidate_curated_train_v0_7d.hdf5",
        rows=candidate_rows,
        view_id="candidate_curated_v0_7d_action_authority_post_adapter_z_gate",
        authority_config=authority_config,
        schema_version=V07D_MANIFEST_SCHEMA_VERSION,
        extra_hdf5_attrs={
            "policy_slice": V07D_POLICY_SLICE_ID,
            "final_post_adapter_authority_id": V07D_FINAL_POST_ADAPTER_AUTHORITY_ID,
            "final_post_adapter_authority_config_sha256": final_authority_config[
                "final_post_adapter_authority_config_sha256"
            ],
            "stable_hold_authority": "env_native_success_mask",
        },
        extra_view_fields={
            "policy_slice": V07D_POLICY_SLICE_ID,
            "final_post_adapter_authority_id": V07D_FINAL_POST_ADAPTER_AUTHORITY_ID,
            "final_post_adapter_authority_config_sha256": final_authority_config[
                "final_post_adapter_authority_config_sha256"
            ],
            "stable_hold_authority": "env_native_success_mask",
        },
    )
    baseline_view = write_v07c_residual_train_view_hdf5(
        path=child_dir / "baseline_uncurated_train_v0_7d.hdf5",
        rows=baseline_rows,
        view_id="baseline_uncurated_v0_7d_action_authority_post_adapter_z_gate",
        authority_config=authority_config,
        schema_version=V07D_MANIFEST_SCHEMA_VERSION,
        extra_hdf5_attrs={
            "policy_slice": V07D_POLICY_SLICE_ID,
            "final_post_adapter_authority_id": V07D_FINAL_POST_ADAPTER_AUTHORITY_ID,
            "final_post_adapter_authority_config_sha256": final_authority_config[
                "final_post_adapter_authority_config_sha256"
            ],
            "stable_hold_authority": "env_native_success_mask",
        },
        extra_view_fields={
            "policy_slice": V07D_POLICY_SLICE_ID,
            "final_post_adapter_authority_id": V07D_FINAL_POST_ADAPTER_AUTHORITY_ID,
            "final_post_adapter_authority_config_sha256": final_authority_config[
                "final_post_adapter_authority_config_sha256"
            ],
            "stable_hold_authority": "env_native_success_mask",
        },
    )
    candidate_v07c = read_json(v07c_dir / "candidate_policy_artifact_v0_7c.json")
    baseline_v07c = read_json(v07c_dir / "baseline_policy_artifact_v0_7c.json")
    candidate_policy = build_v07d_policy_artifact_payload(
        base_policy_artifact={**candidate_v07c, "policy_id": "candidate_curated_mvp2e_v07d_action_authority_bc"},
        final_authority_config=final_authority_config,
        dataset_view_role="candidate_curated",
    )
    baseline_policy = build_v07d_policy_artifact_payload(
        base_policy_artifact={**baseline_v07c, "policy_id": "baseline_uncurated_mvp2e_v07d_action_authority_bc"},
        final_authority_config=final_authority_config,
        dataset_view_role="baseline_uncurated",
    )
    candidate_policy_path = child_dir / "candidate_policy_artifact_v0_7d.json"
    baseline_policy_path = child_dir / "baseline_policy_artifact_v0_7d.json"
    write_json(candidate_policy_path, candidate_policy)
    write_json(baseline_policy_path, baseline_policy)
    candidate_predictions = predict_actions_for_rows(candidate_policy, candidate_rows)
    baseline_predictions = predict_actions_for_rows(baseline_policy, baseline_rows)
    offline_gate = derive_v07d_offline_final_action_authority_gate(
        candidate_rows=candidate_rows,
        baseline_rows=baseline_rows,
        candidate_policy_artifact=candidate_policy,
        baseline_policy_artifact=baseline_policy,
        candidate_predictions=candidate_predictions,
        baseline_predictions=baseline_predictions,
        final_authority_config=final_authority_config,
    )
    write_json(child_dir / "offline_final_action_authority_gate_v0_7d.json", offline_gate)
    manifest = {
        "schema_version": V07D_MANIFEST_SCHEMA_VERSION,
        "slice_id": V07D_SLICE_ID,
        "policy_slice": V07D_POLICY_SLICE_ID,
        "parent_policy_slice": V07C_POLICY_SLICE_ID,
        "v0_7c_manifest_sha256": _sha256_file(v07c_manifest_path),
        "v0_7c_harness_report_sha256": _sha256_payload_excluding(
            parent_harness_report,
            "mvp2e_harness_report_sha256",
        ),
        "v0_7c_harness_report_path": str(_mvp2e_harness_dir(output_dir) / "mvp2e_harness_report.json"),
        "final_post_adapter_authority_config": final_authority_config,
        "final_post_adapter_authority_config_sha256": final_authority_config[
            "final_post_adapter_authority_config_sha256"
        ],
        "stable_hold_authority": "env_native_success_mask",
        "selected_action_adapter_lineage": "inherited_unchanged_from_v0_7c",
        "training_views": {"candidate": candidate_view, "baseline": baseline_view},
        "policy_artifacts": {
            "candidate": {**candidate_policy, "path": str(candidate_policy_path)},
            "baseline": {**baseline_policy, "path": str(baseline_policy_path)},
        },
        "offline_final_action_authority_gate_v0_7d": offline_gate,
        "failed_closed": offline_gate.get("passed") is not True,
        "failure_reason": "" if offline_gate.get("passed") is True else offline_gate.get("failure_reason"),
        "heldout_opened": False,
        "heldout_21000_21049_accessed": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "buyer_facing_limitation": V07A_BUYER_FACING_LIMITATION,
    }
    manifest["v0_7d_action_authority_manifest_sha256"] = _sha256_payload_excluding(
        manifest,
        "v0_7d_action_authority_manifest_sha256",
    )
    write_json(child_dir / "v0_7d_action_authority_manifest.json", manifest)
    return manifest


def build_v07e_shared_hysteresis_parity_repair_slice(
    *,
    output_dir: Path,
    counterfactual_windows: list[dict[str, Any]] | None = None,
) -> dict[str, Any]:
    v07d_dir = output_dir / V07D_CHILD_OUTPUT_DIRNAME
    v07d_manifest_path = v07d_dir / "v0_7d_action_authority_manifest.json"
    if not v07d_manifest_path.exists():
        raise ValueError("missing_v0_7d_parent_manifest")
    v07d_manifest = read_json(v07d_manifest_path)
    if v07d_manifest.get("policy_slice") != V07D_POLICY_SLICE_ID:
        raise ValueError("invalid_v0_7d_parent_manifest")
    if v07d_manifest.get("heldout_21000_21049_accessed") is not False:
        raise ValueError("v0_7e_parent_heldout_access_detected")
    child_dir = output_dir / V07E_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)

    final_authority_config = dict(v07d_manifest["final_post_adapter_authority_config"])
    validate_v07d_final_action_authority_config_contract(final_authority_config)
    candidate_rows = _rows_from_hdf5_metadata(v07d_dir / "candidate_curated_train_v0_7d.hdf5")
    baseline_rows = _rows_from_hdf5_metadata(v07d_dir / "baseline_uncurated_train_v0_7d.hdf5")
    candidate_v07d = read_json(v07d_dir / "candidate_policy_artifact_v0_7d.json")
    baseline_v07d = read_json(v07d_dir / "baseline_policy_artifact_v0_7d.json")
    inherited_authority_config = dict(candidate_v07d["authority_filter_config"])

    hysteresis_config = build_v07e_hysteresis_authority_config(
        output_dir=child_dir,
        parent_final_post_adapter_authority_config_sha256=final_authority_config[
            "final_post_adapter_authority_config_sha256"
        ],
    )
    candidate_view = write_v07c_residual_train_view_hdf5(
        path=child_dir / "candidate_curated_train_v0_7e.hdf5",
        rows=candidate_rows,
        view_id="candidate_curated_v0_7e_shared_hysteresis_parity_repair",
        authority_config=inherited_authority_config,
        schema_version=V07E_MANIFEST_SCHEMA_VERSION,
        extra_hdf5_attrs={
            "policy_slice": V07E_POLICY_SLICE_ID,
            "parent_policy_slice": V07D_POLICY_SLICE_ID,
            "shared_hysteresis_authority_id": V07E_SHARED_HYSTERESIS_AUTHORITY_ID,
            "shared_hysteresis_authority_config_sha256": hysteresis_config[
                "shared_hysteresis_authority_config_sha256"
            ],
            "final_post_adapter_authority_config_sha256": final_authority_config[
                "final_post_adapter_authority_config_sha256"
            ],
        },
        extra_view_fields={
            "policy_slice": V07E_POLICY_SLICE_ID,
            "parent_policy_slice": V07D_POLICY_SLICE_ID,
            "shared_hysteresis_authority_id": V07E_SHARED_HYSTERESIS_AUTHORITY_ID,
            "shared_hysteresis_authority_config_sha256": hysteresis_config[
                "shared_hysteresis_authority_config_sha256"
            ],
            "final_post_adapter_authority_config_sha256": final_authority_config[
                "final_post_adapter_authority_config_sha256"
            ],
        },
    )
    baseline_view = write_v07c_residual_train_view_hdf5(
        path=child_dir / "baseline_uncurated_train_v0_7e.hdf5",
        rows=baseline_rows,
        view_id="baseline_uncurated_v0_7e_shared_hysteresis_parity_repair",
        authority_config=inherited_authority_config,
        schema_version=V07E_MANIFEST_SCHEMA_VERSION,
        extra_hdf5_attrs={
            "policy_slice": V07E_POLICY_SLICE_ID,
            "parent_policy_slice": V07D_POLICY_SLICE_ID,
            "shared_hysteresis_authority_id": V07E_SHARED_HYSTERESIS_AUTHORITY_ID,
            "shared_hysteresis_authority_config_sha256": hysteresis_config[
                "shared_hysteresis_authority_config_sha256"
            ],
            "final_post_adapter_authority_config_sha256": final_authority_config[
                "final_post_adapter_authority_config_sha256"
            ],
        },
        extra_view_fields={
            "policy_slice": V07E_POLICY_SLICE_ID,
            "parent_policy_slice": V07D_POLICY_SLICE_ID,
            "shared_hysteresis_authority_id": V07E_SHARED_HYSTERESIS_AUTHORITY_ID,
            "shared_hysteresis_authority_config_sha256": hysteresis_config[
                "shared_hysteresis_authority_config_sha256"
            ],
            "final_post_adapter_authority_config_sha256": final_authority_config[
                "final_post_adapter_authority_config_sha256"
            ],
        },
    )

    candidate_policy = build_v07e_policy_artifact_payload(
        base_policy_artifact={**candidate_v07d, "policy_id": "candidate_curated_mvp2e_v07e_shared_hysteresis_bc"},
        hysteresis_config=hysteresis_config,
        dataset_view_role="candidate_curated",
    )
    baseline_policy = build_v07e_policy_artifact_payload(
        base_policy_artifact={**baseline_v07d, "policy_id": "baseline_uncurated_mvp2e_v07e_shared_hysteresis_bc"},
        hysteresis_config=hysteresis_config,
        dataset_view_role="baseline_uncurated",
    )
    candidate_policy_path = child_dir / "candidate_policy_artifact_v0_7e.json"
    baseline_policy_path = child_dir / "baseline_policy_artifact_v0_7e.json"
    write_json(candidate_policy_path, candidate_policy)
    write_json(baseline_policy_path, baseline_policy)

    counterfactual_windows = (
        list(counterfactual_windows)
        if counterfactual_windows is not None
        else _load_v07e_counterfactual_windows_from_autoresearch()
    )
    hysteresis_gate = derive_v07e_offline_hysteresis_parity_gate(
        counterfactual_windows=counterfactual_windows,
        hysteresis_config=hysteresis_config,
    )
    write_json(child_dir / "offline_hysteresis_parity_gate_v0_7e.json", hysteresis_gate)

    candidate_predictions = predict_actions_for_rows(candidate_policy, candidate_rows)
    baseline_predictions = predict_actions_for_rows(baseline_policy, baseline_rows)
    candidate_final_actions, candidate_align_rows = _v07e_final_actions_for_rows(
        rows=candidate_rows,
        predictions=candidate_predictions,
        policy_artifact=candidate_policy,
    )
    baseline_final_actions, baseline_align_rows = _v07e_final_actions_for_rows(
        rows=baseline_rows,
        predictions=baseline_predictions,
        policy_artifact=baseline_policy,
    )
    attribution_gate = derive_v07e_attribution_preservation_gate(
        candidate_final_actions=candidate_final_actions,
        baseline_final_actions=baseline_final_actions,
        hysteresis_config=hysteresis_config,
        candidate_policy_artifact=candidate_policy,
        baseline_policy_artifact=baseline_policy,
    )
    write_json(child_dir / "attribution_preservation_gate_v0_7e.json", attribution_gate)

    final_gate = derive_v07e_final_action_authority_regression_gate(
        final_align_rows=[*candidate_align_rows, *baseline_align_rows],
        hysteresis_gate=hysteresis_gate,
        attribution_gate=attribution_gate,
        hysteresis_config=hysteresis_config,
    )
    write_json(child_dir / "final_action_authority_regression_gate_v0_7e.json", final_gate)

    all_gates_passed = (
        hysteresis_gate.get("passed") is True
        and attribution_gate.get("passed") is True
        and final_gate.get("passed") is True
    )
    manifest = {
        "schema_version": V07E_MANIFEST_SCHEMA_VERSION,
        "slice_id": V07E_SLICE_ID,
        "policy_slice": V07E_POLICY_SLICE_ID,
        "parent_policy_slice": V07D_POLICY_SLICE_ID,
        "v0_7d_action_authority_manifest_sha256": v07d_manifest.get(
            "v0_7d_action_authority_manifest_sha256"
        ),
        "v0_7d_action_authority_manifest_file_sha256": _sha256_file(v07d_manifest_path),
        "shared_hysteresis_authority_config": hysteresis_config,
        "shared_hysteresis_authority_config_sha256": hysteresis_config[
            "shared_hysteresis_authority_config_sha256"
        ],
        "final_post_adapter_authority_config_sha256": final_authority_config[
            "final_post_adapter_authority_config_sha256"
        ],
        "selected_action_adapter_lineage": "inherited_unchanged_from_v0_7d",
        "training_views": {"candidate": candidate_view, "baseline": baseline_view},
        "policy_artifacts": {
            "candidate": {**candidate_policy, "path": str(candidate_policy_path)},
            "baseline": {**baseline_policy, "path": str(baseline_policy_path)},
        },
        "offline_hysteresis_parity_gate_v0_7e": hysteresis_gate,
        "attribution_preservation_gate_v0_7e": attribution_gate,
        "final_action_authority_regression_gate_v0_7e": final_gate,
        "failed_closed": not all_gates_passed,
        "failure_reason": ""
        if all_gates_passed
        else (
            final_gate.get("failure_reason")
            or attribution_gate.get("failure_reason")
            or hysteresis_gate.get("failure_reason")
        ),
        "phase_e_candidate_expressibility_unblocked": bool(
            final_gate.get("phase_e_candidate_expressibility_unblocked") is True
        ),
        "future_ab_ready": False,
        "heldout_opened": False,
        "heldout_21000_21049_accessed": False,
        "calibration_opened": False,
        "policy_training_performed": False,
        "policy_uplift_proven": False,
        "proof_authority": False,
        "mvp2_closed": False,
        "buyer_facing_limitation": V07A_BUYER_FACING_LIMITATION,
    }
    manifest["v0_7e_shared_hysteresis_parity_manifest_sha256"] = _sha256_payload_excluding(
        manifest,
        "v0_7e_shared_hysteresis_parity_manifest_sha256",
    )
    write_json(child_dir / "v0_7e_shared_hysteresis_parity_manifest.json", manifest)
    return manifest


def run_v07b_shared_train_recovery_induction_runtime(
    *,
    output_dir: Path,
    device: str,
    headless: bool,
    isaac_task: str,
    max_steps: int,
    action_scale: float,
) -> dict[str, Any]:
    child_dir = output_dir / V07B_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)

    def write_artifact(payload: dict[str, Any]) -> dict[str, Any]:
        payload["shared_train_recovery_induction_sha256"] = _sha256_payload_excluding(
            payload,
            "shared_train_recovery_induction_sha256",
        )
        write_json(child_dir / "shared_train_recovery_induction_v0_7b.json", payload)
        return payload

    base_artifact: dict[str, Any] = {
        "schema_version": V07B_SHARED_RECOVERY_INDUCTION_SCHEMA_VERSION,
        "policy_slice": V07B_POLICY_SLICE_ID,
        "source_seeds": list(V07B_RECOVERY_SOURCE_SEEDS),
        "state_induction_policy": "shared_frozen_base_servo",
        "source_policy_slice": "none",
        "policy_specific_source": False,
        "shared_overlay_for_both_views": True,
        "proof_authority": False,
        "passed": False,
        "runtime_backend": "isaac_runtime_not_started",
        "reason": "shared_train_recovery_induction_requires_actual_isaac_runtime",
        "traces": [],
        "heldout_21000_21049_accessed": False,
    }

    scenario_manifest_path = output_dir / "scenario_manifest.json"
    selected_adapter_path = output_dir / "selected_action_adapter.json"
    if not scenario_manifest_path.exists() or not selected_adapter_path.exists():
        return write_artifact(
            {
                **base_artifact,
                "reason": "missing_scenario_manifest_or_selected_action_adapter",
            }
        )

    source_manifest = read_json(scenario_manifest_path)
    selected_adapter = read_json(selected_adapter_path)
    parent_config_path = output_dir / V07A2_CHILD_OUTPUT_DIRNAME / "v0_7a_2_trace_native_config.json"
    parent_config_sha256 = (
        _sha256_file(parent_config_path)
        if parent_config_path.exists()
        else "parent_v0_7a_2_trace_native_config_unavailable_recovery_induction_only"
    )
    try:
        residual_servo_config = build_v07b_residual_servo_config(
            output_dir=child_dir,
            parent_config_sha256=parent_config_sha256,
        )
        policy_artifact = build_v07b_shared_base_servo_recovery_policy_artifact(
            residual_servo_config=residual_servo_config,
            selected_adapter=selected_adapter,
        )
        recovery_manifest = build_v07b_shared_recovery_induction_manifest(source_manifest)
    except ValueError as exc:
        return write_artifact(
            {
                **base_artifact,
                "reason": str(exc),
            }
        )

    policy_path = child_dir / "shared_base_servo_policy_artifact_v0_7b.json"
    manifest_path = child_dir / "shared_train_recovery_induction_manifest_v0_7b.json"
    write_json(policy_path, policy_artifact)
    write_json(manifest_path, recovery_manifest)

    probe_result = IsaacConnectorInsertionEvaluatorBackend(
        task=isaac_task,
        device=device,
        headless=headless,
        action_scale=action_scale,
        max_steps=max_steps,
    ).run_single_policy_probe(
        manifest=recovery_manifest,
        output_dir=child_dir / "isaac_runtime_shared_train_recovery_induction_v0_7b",
        policy_artifact=policy_artifact,
        role="v0_7b_shared_train_recovery_induction",
        max_rollouts=len(V07B_RECOVERY_SOURCE_SEEDS),
        stop_after_first_success=False,
    )
    trace_paths = list(probe_result.baseline_trace_paths)
    passed = bool(
        probe_result.runtime_gate.get("passed") is True
        and probe_result.runtime_backend == "isaac_runtime"
        and len(trace_paths) == len(V07B_RECOVERY_SOURCE_SEEDS)
    )
    reason = "" if passed else str(probe_result.runtime_gate.get("reason") or "shared_train_recovery_induction_failed")
    return write_artifact(
        {
            **base_artifact,
            "passed": passed,
            "runtime_backend": probe_result.runtime_backend,
            "proof_runtime": "v0_7b_shared_train_recovery_induction",
            "reason": reason,
            "trace_paths": trace_paths,
            "trace_path_count": len(trace_paths),
            "rollouts": probe_result.baseline_rollouts,
            "rollout_count": len(probe_result.baseline_rollouts),
            "runtime_gate": probe_result.runtime_gate,
            "runtime_metadata": probe_result.runtime_metadata,
            "recovery_induction_manifest": str(manifest_path),
            "recovery_induction_manifest_sha256": recovery_manifest["manifest_sha256"],
            "shared_base_servo_policy_artifact": str(policy_path),
            "shared_base_servo_policy_artifact_sha256": policy_artifact["policy_artifact_sha256"],
            "residual_servo_config_sha256": residual_servo_config["v0_7b_residual_servo_config_sha256"],
            "heldout_21000_21049_accessed": False,
        }
    )


def _parent_payload_hash(name: str, payload: dict[str, Any]) -> str | None:
    if name == "repair_probe_gate":
        return str(payload.get("repair_probe_gate_sha256") or "")
    if name == "failed_expressibility_sanity_gate":
        return str(payload.get("expressibility_sanity_gate_sha256") or "")
    if name == "selected_action_adapter":
        return _sha256_payload(payload)
    if name in {"baseline_policy_artifact", "candidate_policy_artifact"}:
        return str(payload.get("policy_artifact_sha256") or "")
    return None


def _validate_v07a_parent_artifact_semantics(name: str, payload: dict[str, Any]) -> list[str]:
    issues: list[str] = []
    if name == "repair_probe_gate":
        if payload.get("green_light_for_40_run_gate") is not True:
            issues.append("repair_probe_gate_not_green")
        if payload.get("hard_stop") is True:
            issues.append("repair_probe_gate_hard_stop")
        if payload.get("runtime_backend") != "isaac_runtime":
            issues.append("repair_probe_gate_not_isaac_runtime")
        if payload.get("heldout_opened") is True or payload.get("heldout_21000_21049_accessed") is True:
            issues.append("repair_probe_gate_opened_heldout")
    elif name == "train_generation_runtime_gate":
        if payload.get("passed") is not True:
            issues.append("train_generation_gate_not_passed")
        if payload.get("runtime_backend") != "isaac_runtime":
            issues.append("train_generation_gate_not_isaac_runtime")
        if int(payload.get("generated_rollout_count", 0)) != V06_TRAIN_GATE_ATTEMPT_COUNT:
            issues.append("train_generation_gate_rollout_count_mismatch")
        if int(payload.get("generated_success_count", 0)) < V06_TRAIN_GATE_SUCCESS_MINIMUM:
            issues.append("train_generation_gate_success_count_too_low")
        if payload.get("heldout_opened") is True or payload.get("heldout_21000_21049_accessed") is True:
            issues.append("train_generation_gate_opened_heldout")
    elif name == "failed_expressibility_sanity_gate":
        if payload.get("passed") is not False:
            issues.append("parent_expressibility_was_not_failed")
        if int(payload.get("success_count", 0)) != 0:
            issues.append("parent_expressibility_success_count_not_zero")
        if payload.get("runtime_backend") != "isaac_runtime":
            issues.append("parent_expressibility_not_isaac_runtime")
        if payload.get("heldout_opened") is True or payload.get("heldout_21000_21049_accessed") is True:
            issues.append("parent_expressibility_opened_heldout")
    elif name in {"baseline_policy_artifact", "candidate_policy_artifact"}:
        if not payload.get("policy_artifact_sha256"):
            issues.append(f"{name}_missing_policy_artifact_sha256")
    elif name == "selected_action_adapter":
        if payload.get("calibration_only_selection_passed") is not True:
            issues.append("selected_action_adapter_not_calibration_passed")
        if payload.get("selector_score_pre_registered") is not True:
            issues.append("selected_action_adapter_selector_not_pre_registered")
        if payload.get("same_adapter_used_for_baseline_and_candidate") is not True:
            issues.append("selected_action_adapter_not_shared")
        if payload.get("heldout_excluded") is not True:
            issues.append("selected_action_adapter_heldout_not_excluded")
        if payload.get("selected_adapter_frozen_before_heldout") is not True:
            issues.append("selected_action_adapter_not_frozen_before_heldout")
        if not payload.get("selected_adapter_id"):
            issues.append("selected_action_adapter_missing_id")
        if not payload.get("selected_adapter_config_sha256"):
            issues.append("selected_action_adapter_missing_config_sha256")
        if not payload.get("selected_adapter_sha256"):
            issues.append("selected_action_adapter_missing_sha256")
    return issues


def validate_v07a_parent_artifact_hashes(
    artifact_paths: dict[str, Path],
    expected_hashes: dict[str, str],
) -> dict[str, Any]:
    mismatched: list[str] = []
    semantic_issues: list[str] = []
    observed: dict[str, str | None] = {}
    for name, path in artifact_paths.items():
        file_key = f"parent_{name}_file_sha256"
        payload_key = f"parent_{name}_payload_sha256"
        if not path.exists():
            observed[file_key] = None
            mismatched.append(file_key)
            continue
        observed[file_key] = _sha256_file(path)
        if expected_hashes.get(file_key) and observed[file_key] != expected_hashes[file_key]:
            mismatched.append(file_key)
        if path.suffix == ".json":
            payload = read_json(path)
            semantic_issues.extend(_validate_v07a_parent_artifact_semantics(name, payload))
            payload_hash = _parent_payload_hash(name, payload)
            if payload_hash is not None:
                observed[payload_key] = payload_hash
                if expected_hashes.get(payload_key) and payload_hash != expected_hashes[payload_key]:
                    mismatched.append(payload_key)
    return {
        "passed": not mismatched and not semantic_issues,
        "mismatched_hashes": sorted(set(mismatched)),
        "semantic_issues": sorted(set(semantic_issues)),
        "observed_hashes": observed,
    }


