def validate_v07a1_relabel_config_contract(config: dict[str, Any]) -> None:
    if config.get("schema_version") != V07A1_RELABEL_CONFIG_SCHEMA_VERSION:
        raise ValueError("v0_7a_1_relabel_config_required")
    if config.get("slice_id") != V07A1_SLICE_ID:
        raise ValueError("v0_7a_1_relabel_config_required")
    if config.get("behavior_phase_rule_version") != V07A1_BEHAVIOR_PHASE_RULE_VERSION:
        raise ValueError("v0_7a_1_relabel_config_required")
    if "seat_depth_threshold_m" in config or "seat_depth_threshold_source" in config:
        raise ValueError("v0_7a_1_geometry_seat_threshold_forbidden")
    if config.get("relabel_config_sha256") != config.get("v0_7a_1_relabel_config_sha256"):
        raise ValueError("v0_7a_1_relabel_config_hash_mismatch")
    expected_hash = _sha256_payload_excluding(config, "v0_7a_1_relabel_config_sha256", "relabel_config_sha256")
    if config.get("relabel_config_sha256") != expected_hash:
        raise ValueError("v0_7a_1_relabel_config_hash_mismatch")


def build_v07a1_candidate_policy_artifact_payload(
    *,
    relabel_config: dict[str, Any],
    policy_artifact_sha256: str,
    baseline_policy_artifact_available: bool,
    base_policy_artifact: dict[str, Any] | None = None,
) -> dict[str, Any]:
    validate_v07a1_relabel_config_contract(relabel_config)
    payload = dict(base_policy_artifact or {})
    payload.update(
        {
            "policy_artifact_schema_version": V07A1_POLICY_ARTIFACT_SCHEMA_VERSION,
            "policy_slice": V07A1_POLICY_SLICE_ID,
            "slice_id": V07A1_SLICE_ID,
            "behavior_phase_rule_version": V07A1_BEHAVIOR_PHASE_RULE_VERSION,
            "behavior_state_phase_input": True,
            "phase_label_source": V07A1_BEHAVIOR_PHASE_LABEL_SOURCE,
            "feature_schema_version": FEATURE_SCHEMA_V07A_VERSION,
            "relabel_config_sha256": relabel_config["relabel_config_sha256"],
            "v0_7a_1_relabel_config_sha256": relabel_config["v0_7a_1_relabel_config_sha256"],
            "phase_e_candidate_only_diagnostic": True,
            "baseline_policy_artifact_available": bool(baseline_policy_artifact_available),
            "future_ab_ready": False,
            "future_ab_ready_source": "offline_train_fit_gate",
            "proof_authority": False,
            "heldout_21000_21049_accessed": False,
            "buyer_facing_limitation": V07A_BUYER_FACING_LIMITATION,
        }
    )
    payload["policy_artifact_sha256"] = policy_artifact_sha256
    return payload


def _v07a1_parent_file_hash_key(relative_path: str) -> str:
    normalized = relative_path.replace("/", "_").replace(".", "_")
    return f"parent_{normalized}_file_sha256"


def _v07a1_parent_payload_hash_key(relative_path: str) -> str:
    normalized = relative_path.replace("/", "_").replace(".", "_")
    return f"parent_{normalized}_payload_sha256"


def _v07a1_gate_heldout_opened(payload: dict[str, Any]) -> bool:
    return bool(payload.get("heldout_opened") is True or payload.get("heldout_21000_21049_accessed") is True)


def validate_v07a1_parent_proof_chain(parent_root: Path) -> dict[str, Any]:
    missing = [
        relative_path
        for relative_path in V07A1_PARENT_PROOF_CHAIN_REQUIRED_FILES
        if not (parent_root / relative_path).exists()
    ]
    if missing:
        if any(relative_path.startswith("v0_7a_behavior_state_phase_relabel/") for relative_path in missing):
            raise ValueError("parent_v0_7a_fail_closed_evidence_missing")
        raise ValueError(f"parent_proof_chain_file_missing:{missing[0]}")

    train_gate = read_json(parent_root / "train_generation_runtime_gate.json")
    if train_gate.get("passed") is not True:
        raise ValueError("parent_train_generation_runtime_gate_not_passed")
    if int(train_gate.get("generated_success_count", 0)) < V06_TRAIN_GATE_SUCCESS_MINIMUM:
        raise ValueError("parent_train_generation_success_count_too_low")
    if not isinstance(train_gate.get("generated_trace_paths"), list) or not train_gate["generated_trace_paths"]:
        raise ValueError("parent_train_generation_trace_paths_missing")
    if _v07a1_gate_heldout_opened(train_gate):
        raise ValueError("parent_heldout_opened")

    repair_gate = read_json(parent_root / "repair_probe_gate.json")
    if repair_gate.get("green_light_for_40_run_gate") is not True or repair_gate.get("hard_stop") is True:
        raise ValueError("parent_repair_probe_gate_not_green")
    if _v07a1_gate_heldout_opened(repair_gate):
        raise ValueError("parent_heldout_opened")

    selected_adapter = read_json(parent_root / "selected_action_adapter.json")
    selected_issues = _validate_v07a_parent_artifact_semantics("selected_action_adapter", selected_adapter)
    if selected_issues:
        raise ValueError(f"parent_selected_action_adapter_invalid:{selected_issues[0]}")

    v07a_offline = read_json(parent_root / "v0_7a_behavior_state_phase_relabel" / "offline_train_fit_gate.json")
    if v07a_offline.get("passed") is not False or v07a_offline.get("failure_reason") != "required_phase_missing":
        raise ValueError("parent_v0_7a_fail_closed_evidence_missing")
    if _v07a1_gate_heldout_opened(v07a_offline):
        raise ValueError("parent_heldout_opened")

    v07a_expressibility = read_json(
        parent_root / "v0_7a_behavior_state_phase_relabel" / "expressibility_sanity_gate_v0_7a.json"
    )
    if v07a_expressibility.get("passed") is not False:
        raise ValueError("parent_v0_7a_fail_closed_evidence_missing")
    if v07a_expressibility.get("runtime_backend") == "isaac_runtime":
        raise ValueError("parent_v0_7a_expressibility_unexpectedly_ran_isaac")
    if _v07a1_gate_heldout_opened(v07a_expressibility):
        raise ValueError("parent_heldout_opened")

    observed_hashes: dict[str, str] = {}
    for relative_path in V07A1_PARENT_PROOF_CHAIN_REQUIRED_FILES:
        path = parent_root / relative_path
        observed_hashes[_v07a1_parent_file_hash_key(relative_path)] = _sha256_file(path)
        if path.suffix == ".json":
            observed_hashes[_v07a1_parent_payload_hash_key(relative_path)] = _sha256_payload(read_json(path))

    return {
        "schema_version": "rdf_mvp2e_v07a1_parent_proof_chain_verdict_v0.1.0",
        "passed": True,
        "parent_root": str(parent_root),
        "required_files": list(V07A1_PARENT_PROOF_CHAIN_REQUIRED_FILES),
        "observed_hashes": observed_hashes,
        "train_generation_runtime_gate": {
            "passed": True,
            "generated_success_count": int(train_gate.get("generated_success_count", 0)),
            "generated_trace_path_count": len(train_gate.get("generated_trace_paths") or []),
        },
        "v0_7a_fail_closed_evidence": {
            "offline_train_fit_gate_passed": bool(v07a_offline.get("passed")),
            "offline_train_fit_failure_reason": v07a_offline.get("failure_reason"),
            "expressibility_runtime_backend": v07a_expressibility.get("runtime_backend"),
            "expressibility_reason": v07a_expressibility.get("reason"),
        },
        "selected_action_adapter": {
            "selected_adapter_id": selected_adapter.get("selected_adapter_id"),
            "selected_adapter_config_sha256": selected_adapter.get("selected_adapter_config_sha256"),
            "selected_adapter_sha256": selected_adapter.get("selected_adapter_sha256"),
        },
        "heldout_21000_21049_accessed": False,
        "proof_authority": False,
    }


