def run_v07b_expressibility_sanity_runtime(
    *,
    output_dir: Path,
    manifest: dict[str, Any],
    device: str,
    headless: bool,
    isaac_task: str,
    max_steps: int,
    action_scale: float,
) -> dict[str, Any]:
    child_dir = output_dir / V07B_CHILD_OUTPUT_DIRNAME
    child_dir.mkdir(parents=True, exist_ok=True)
    gate_path = child_dir / "offline_residual_fit_gate_v0_7b.json"
    gate_output_path = child_dir / "expressibility_sanity_gate_v0_7b.json"

    def fail_closed(reason: str, offline_gate: dict[str, Any] | None = None) -> dict[str, Any]:
        gate: dict[str, Any] = {
            "schema_version": "rdf_mvp2e_v07b_expressibility_sanity_gate_v0.1.0",
            "policy_slice": V07B_POLICY_SLICE_ID,
            "slice_id": V07B_SLICE_ID,
            "passed": False,
            "runtime_backend": "isaac_runtime_not_started",
            "proof_runtime": "isaac_candidate_policy_train_split_expressibility_sanity",
            "reason": reason,
            "heldout_opened": False,
            "heldout_21000_21049_accessed": False,
            "proof_authority": False,
        }
        if isinstance(offline_gate, dict):
            gate["offline_residual_fit_gate_sha256"] = offline_gate.get("offline_residual_fit_gate_sha256")
        write_json(gate_output_path, gate)
        return gate

    if not gate_path.exists():
        return fail_closed("missing_passed_v0_7b_offline_residual_fit_gate")
    offline_gate = read_json(gate_path)
    if (
        offline_gate.get("passed") is not True
        or offline_gate.get("candidate_gate_passed") is not True
        or offline_gate.get("phase_e_candidate_expressibility_unblocked") is not True
    ):
        return fail_closed("missing_passed_v0_7b_offline_residual_fit_gate", offline_gate)

    policy_path = child_dir / "candidate_policy_artifact_v0_7b.json"
    if not policy_path.exists():
        return fail_closed("missing_v0_7b_candidate_policy_artifact", offline_gate)
    policy_artifact = read_json(policy_path)
    base_servo_config = policy_artifact.get("base_servo_config")
    policy_valid = (
        policy_artifact.get("policy_slice") == V07B_POLICY_SLICE_ID
        and policy_artifact.get("trainer_family") == RESIDUAL_TRAINER_FAMILY
        and policy_artifact.get("base_servo_id") == V07B_BASE_SERVO_ID
        and isinstance(base_servo_config, dict)
        and policy_artifact.get("base_servo_config_sha256") == _sha256_payload(base_servo_config)
        and policy_artifact.get("residual_target_definition") == V07B_RESIDUAL_TARGET_DEFINITION
        and policy_artifact.get("behavior_phase_rule_version") == V07A2_BEHAVIOR_PHASE_RULE_VERSION
    )
    if not policy_valid:
        return fail_closed("invalid_v0_7b_candidate_policy_artifact", offline_gate)

    train_gate_status = resolve_existing_v06_train_generation_runtime_gate(output_dir=output_dir)
    if train_gate_status.get("reuse_allowed") is not True or not isinstance(train_gate_status.get("gate"), dict):
        return fail_closed(
            str(train_gate_status.get("reason", "missing_passed_v0_6_train_generation_gate")),
            offline_gate,
        )

    probe_manifest = build_v06_expressibility_sanity_manifest(
        manifest=manifest,
        train_generation_runtime_gate=train_gate_status["gate"],
    )
    write_json(child_dir / "expressibility_sanity_manifest_v0_7b.json", probe_manifest)
    probe_result = IsaacConnectorInsertionEvaluatorBackend(
        task=isaac_task,
        device=device,
        headless=headless,
        action_scale=action_scale,
        max_steps=max_steps,
    ).run_single_policy_probe(
        manifest=probe_manifest,
        output_dir=child_dir / "isaac_runtime_expressibility_sanity_v0_7b",
        policy_artifact=policy_artifact,
        role="v0_7b_expressibility_sanity",
        max_rollouts=V06_EXPRESSIBILITY_SANITY_SEED_COUNT,
        stop_after_first_success=False,
    )
    gate = derive_v06_expressibility_sanity_gate_from_probe_result(probe_result)
    gate["schema_version"] = "rdf_mvp2e_v07b_expressibility_sanity_gate_v0.1.0"
    gate["policy_slice"] = V07B_POLICY_SLICE_ID
    gate["slice_id"] = V07B_SLICE_ID
    gate["behavior_phase_rule_version"] = V07A2_BEHAVIOR_PHASE_RULE_VERSION
    gate["base_servo_id"] = V07B_BASE_SERVO_ID
    gate["residual_target_definition"] = V07B_RESIDUAL_TARGET_DEFINITION
    gate["offline_residual_fit_gate_sha256"] = offline_gate["offline_residual_fit_gate_sha256"]
    gate["manifest_sha256"] = probe_manifest["manifest_sha256"]
    gate["heldout_21000_21049_accessed"] = False
    gate["proof_authority"] = False
    gate["expressibility_sanity_gate_sha256"] = _sha256_payload_excluding(
        gate,
        "expressibility_sanity_gate_sha256",
    )
    write_json(gate_output_path, gate)
    return gate


